      SUBROUTINE MATI50(X,N,Y)
!
!     THIS PROGRAM COMPUTES THE INVERSE OF A SINGLE PRECISION SYMMETRIC
!     MATRIX WHOSE ORDER DOES NOT EXCEED 50
!     THE MODIFIED NO-SQUARE-ROOT CHOLESKI DECOMPOSITION IS USED
!     N IS THE ORDER OF THE SYMMETRIC MATRIX--N DOES NOT EXCEED 50
!     THE INPUT MATRIX IS THE LOWER LEFT TRIANGLE OF ARRAY X
!     OR, IF AVAILABLE, ALL OF THE ARRAY X
!     OUTPUT MATRIX--Y.
!     NOTE--THE DIMENSIONS OF X AND Y MUST BE THE SAME
!           IN THE CALLING ROUTINE AS IN THIS SUBROUTINE.
!           THEY HAVE BEEN SET HEREIN TO 50 BY 50,
!           AND HENCE THE 50 IN THE NAME OF THIS SUBROUTINE (MATI50).
!     NOTE--MATI50 IS IDENTICAL TO MATI25 AND MATINV
!           EXCEPT FOR THE DIMENSIONS.
!
!     REFERENCE--
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--THESIS
!     UPDATED         --AUGUST    1976.
!     UPDATED         --MARCH     1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!CCCC DOUBLE PRECISION SUM
!
      DIMENSION X(50,50)
      DIMENSION Y(50,50)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MATI'
      ISUBN2='50  '
!
!CCC  IF(N-1)115,106,115
      IF(N-1.NE.0)GO TO 115
      Y(1,1)=1.0D0/X(1,1)
      GO TO 111
!
!     WE KNOW THAT A = L TIMES D TIMES L TRANSPOSE     WHERE L IS A
!     LOWER TRIANGULAR MATRIX AND D IS A DIAGONAL MATRIX
!     THE DIAGONAL ELEMENTS OF L ARE ALL ONES, THEREFORE WE SAVE SPACE
!     AND OVERWRITE THIS DIAGONAL WITH THE DIAGONAL ELEMENTS OF D
!     FIND L AND D
!
  115 Y(1,1)=X(1,1)
      DO 20 I=2,N
      Y(I,1)=X(I,1)/X(1,1)
      DO 30 J=2,I
      SUM=0.
      JM1=J-1
      DO 40 K=1,JM1
      SUM=SUM+Y(K,K)*Y(I,K)*Y(J,K)
   40 CONTINUE
      Y(I,J)=X(I,J)-SUM
!CCCC IF(J-I)41,30,41
      IF(J-I.EQ.0)GO TO 30
      Y(I,J)=Y(I,J)/Y(J,J)
   30 CONTINUE
   20 CONTINUE
!
!     FIND L INVERSE AND STORE IT IN THE UPPER RIGHT TRIANGLE OF L
!
      DO 60 I=2,N
      IM1=I-1
      DO 70 J=1,IM1
      JJ=I-J
      SUM=0.
      JJP1=JJ+1
      DO 80 K=JJP1,I
!CCCC IF(K-I)64,65,64
      IF(K-I.NE.0)GO TO 64
      SUM=SUM+Y(K,JJ)
      GO TO 80
   64 SUM=SUM+Y(K,I)*Y(K,JJ)
   80 CONTINUE
      Y(JJ,I)=-SUM
   70 CONTINUE
   60 CONTINUE
!
!     FIND A INVERSE=L INVERSE TRANSPOSE TIMES D INVERSE TIMES L INVERSE
!     STORE THIS IN THE LOWER LEFT TRIANGLE OF L
!
      DO 100 I=1,N
      DO 110 J=1,I
      SUM=0.
      DO 120 K=I,N
!CCCC IF(K-I)91,92,91
      IF(K-I.EQ.0)GO TO 92
      CONTINUE
!CCCC IF(K-J)93,94,93
      IF(K-J.EQ.0)GO TO 94
      SUM=SUM+Y(I,K)*Y(J,K)/Y(K,K)
      GO TO 120
   94 SUM=SUM+Y(I,K)/Y(K,K)
      GO TO 120
   92 CONTINUE
!CCCC IF(K-J)95,96,95
      IF(K-J.EQ.0)GO TO 96
      SUM=SUM+Y(J,K)/Y(K,K)
      GO TO 120
   96 SUM=SUM+1.0D0/Y(K,K)
  120 CONTINUE
      Y(I,J)=SUM
  110 CONTINUE
  100 CONTINUE
!
!     FILL IN THE UPPER RIGHT TRIANGLE OF THE INVERSE MATRIX
!     THIS IS NEEDED ONLY BECAUSE OF THE BLUE SUBROUTINE WHICH FOLLOWS
!
      NM1=N-1
      DO 10 I=1,NM1
      JMIN=I+1
      DO 21 J=JMIN,N
      Y(I,J)=Y(J,I)
   21 CONTINUE
   10 CONTINUE
  111 RETURN
      END SUBROUTINE MATI50
      SUBROUTINE MATSCA(AMAT,AMAT2,MAXROM,MAXCOM,NR1,NC1,Y1,Y2,Y3,   &
      IMATSC,ICASE,IWRITE,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE SCALES A MATRIX BY
!              EITHER A SD, RANGE, MEAN, OR Z-SCORE.
!     INPUT  ARGUMENTS--AMAT   = THE SINGLE PRECISION MATRIX
!                     --MAXROM = THE INTEGER ROW DIMENSION OF AMAT
!                     --MAXCOM = THE INTEGER COUMN DIMENSION OF AMAT
!                     --NR1    = THE INTEGER NUMBER OF ROWS OF AMAT
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS OF AMAT
!     OUTPUT ARGUMENTS--AMAT2    = THE SINGLE PRECISION VALUE OF THE
!                                SCALED MATRIX.
!     OUTPUT--SCALED MATRIX.
!     NOTE--THIS ROUTINE ASSUMES THE ERROR CHECKING (FOR EQUAL
!           ROWS AND COLUMNS, MATCHING DIMENSIONS FOR X AND AMAT)
!           IS DONE BT THE CALLING SUBROUTINE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.6
!     ORIGINAL VERSION--JUNE      1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IMATSC
      CHARACTER*4 ICASE
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION AMAT(MAXROM,MAXCOM)
      DIMENSION AMAT2(MAXROM,MAXCOM)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MATS'
      ISUBN2='CA  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF MATSCA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NR1,NC1
   53 FORMAT('NR1, NC1 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)ICASE
   54 FORMAT('ICASE = ',A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               ********************************
!               **  SCALE THE MATRIX           *
!               ********************************
!
      IWRITE='OFF'
!
      IF(IMATSC.EQ.'NONE')THEN
        DO 110 J=1,NC1
          DO 120 I=1,NR1
            AMAT2(I,J)=AMAT(I,J)
 120      CONTINUE
 110    CONTINUE
        GO TO 9000
      ENDIF
!
      IF(IMATSC.EQ.'MEAN')THEN
        IF(ICASE.EQ.'ROW ')THEN
          DO 210 I=1,NR1
            DO 215 J=1,NC1
              Y1(J)=AMAT(I,J)
 215        CONTINUE
            CALL MEAN(Y1,NC1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y2(I)=ASTAT
 210      CONTINUE
          DO 220 I=1,NR1
            DO 225 J=1,NC1
              AMAT2(I,J)=AMAT(I,J)/Y2(I)
 225        CONTINUE
 220      CONTINUE
        ELSE
          DO 230 J=1,NC1
            DO 235 I=1,NR1
              Y1(I)=AMAT(I,J)
 235        CONTINUE
            CALL MEAN(Y1,NR1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y2(J)=ASTAT
 230      CONTINUE
          DO 240 J=1,NC1
            DO 245 I=1,NR1
              AMAT2(I,J)=AMAT(I,J)/Y2(J)
 245        CONTINUE
 240      CONTINUE
        ENDIF
      ENDIF
!
      IF(IMATSC.EQ.'RANG')THEN
        IF(ICASE.EQ.'ROW ')THEN
          DO 310 I=1,NR1
            DO 315 J=1,NC1
              Y1(J)=AMAT(I,J)
 315        CONTINUE
            CALL RANGDP(Y1,NC1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y2(I)=ASTAT
 310      CONTINUE
          DO 320 I=1,NR1
            DO 325 J=1,NC1
              AMAT2(I,J)=AMAT(I,J)/Y2(I)
 325        CONTINUE
 320      CONTINUE
        ELSE
          DO 330 J=1,NC1
            DO 335 I=1,NR1
              Y1(I)=AMAT(I,J)
 335        CONTINUE
            CALL RANGDP(Y1,NR1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y2(J)=ASTAT
 330      CONTINUE
          DO 340 J=1,NC1
            DO 345 I=1,NR1
              AMAT2(I,J)=AMAT(I,J)/Y2(J)
 345        CONTINUE
 340      CONTINUE
        ENDIF
      ENDIF
!
      IF(IMATSC.EQ.'Z-SC')THEN
        IF(ICASE.EQ.'ROW ')THEN
          DO 410 I=1,NR1
            DO 415 J=1,NC1
              Y1(J)=AMAT(I,J)
 415        CONTINUE
            CALL SD(Y1,NC1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y2(I)=ASTAT
            CALL MEAN(Y1,NC1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y3(I)=ASTAT
 410      CONTINUE
          DO 420 I=1,NR1
            DO 425 J=1,NC1
              AMAT2(I,J)=(AMAT(I,J)-Y3(I))/Y2(I)
 425        CONTINUE
 420      CONTINUE
        ELSE
          DO 430 J=1,NC1
            DO 435 I=1,NR1
              Y1(I)=AMAT(I,J)
 435        CONTINUE
            CALL SD(Y1,NR1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y2(J)=ASTAT
            CALL MEAN(Y1,NR1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y3(J)=ASTAT
 430      CONTINUE
          DO 440 J=1,NC1
            DO 445 I=1,NR1
              AMAT2(I,J)=(AMAT(I,J)-Y3(J))/Y2(J)
 445        CONTINUE
 440      CONTINUE
        ENDIF
      ENDIF
!
      IF(IMATSC.EQ.'SD  ')THEN
        IF(ICASE.EQ.'ROW ')THEN
          DO 510 I=1,NR1
            DO 515 J=1,NC1
              Y1(J)=AMAT(I,J)
 515        CONTINUE
            CALL SD(Y1,NC1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y3(I)=ASTAT
 510      CONTINUE
          DO 520 I=1,NR1
            DO 525 J=1,NC1
              AMAT2(I,J)=AMAT(I,J)/Y2(I)
 525        CONTINUE
 520      CONTINUE
        ELSE
          DO 530 J=1,NC1
            DO 535 I=1,NR1
              Y1(I)=AMAT(I,J)
 535        CONTINUE
            CALL SD(Y1,NR1,IWRITE,ASTAT,IBUGA3,IERROR)
            Y3(J)=ASTAT
 530      CONTINUE
          DO 540 J=1,NC1
            DO 545 I=1,NR1
              AMAT2(I,J)=AMAT(I,J)/Y2(J)
 545        CONTINUE
 540      CONTINUE
        ENDIF
      ENDIF
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)
  811 FORMAT('THE EUCLIDEN DISTANCE MATRIX HAS BEEN CALCULATED.')
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF MATSCA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IMATSC
 9015 FORMAT('IMATSC = ',A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE MATSCA
      SUBROUTINE MATMPI (X,WORK,S,E,V,N,M,NX,MX,K,IFLAG)
!
!-----------------------------------------------------------------------
!   MATMPI   WRITTEN BY CHARLES P. REEVE, STATISTICAL ENGINEERING
!            DIVISION, NATIONAL BUREAU OF STANDARDS, GAITHERSBURG,
!            MARYLAND  20899
!
!   FOR: COMPUTING THE MOORE-PENROSE PSEUDO-INVERSE OF AN NXM MATRIX
!        X WHERE N >= M.  THE TRANSPOSE OF THE INVERSE IS RETURNED IN
!        THE ORIGINAL MATRIX.  A LINPACK ROUTINE IS USED TO PERFORM
!        A SINGULAR VALUE DECOMPOSITION OF X FROM WHICH THE INVERSE
!        X+ IS COMPUTED.  IF X IS OF FULL RANK THEN X+ = INV(X'X)*X'.
!
!   NOTE: RNDERR IS A MACHINE DEPENDENT CONSTANT WHICH IS THE MACHINE
!         ROUNDING ERROR (OR A LITTLE LARGER).  IT IS USED TO DETERMINE
!         WHEN A SINGULAR VALUE IS ZERO (IN CASES WHERE THE USER HAS
!         REQUESTED AUTOMATIC DETERMINATION OF RANK BY INPUTTING K=0).
!         SEE DISCUSSION OF THIS POINT ON PAGE 11.2 OF REFERENCE 1.
!
!   SUBPROGRAMS CALLED: SSVDC (LINPACK)
!
!   CURRENT VERSION COMPLETED DECEMBER 14, 1989
!
!   REFERENCES:
!
!   1) DONGARRA, J.J., MOLER, C.B., BUNCH, J.R., AND STEWART, G.W.,
!      "LINPACK USERS' GUIDE", SIAM, PHILADELPHIA, 1979, CH. 11.
!
!   2) LAWSON, CHARLES L. AND HANSON, RICHARD J., "SOLVING LEAST
!      SQUARES PROBLEMS", PRENTICE-HALL, INC., CH. 7.
!-----------------------------------------------------------------------
!   DEFINITION OF PASSED PARAMETERS:
!
!    * X(NX,*) = MATRIX (SIZE N BY M) WHOSE PSEUDO-INVERSE IS TO BE
!                COMPUTED.  THE SECOND DIMENSION OF X, DEFINED IN THE
!                CALLING PROGRAM, MUST BE >=M. [REAL]
!
!      WORK(*) = VECTOR (LENGTH N) USED AS WORKSPACE [REAL]
!
!         S(*) = VECTOR (LENGTH M) OF SINGULAR VALUES IN DESCENDING
!                ORDER ON RETURN, PROVIDED INFO=0 ON RETURN [REAL]
!
!         E(*) = VECTOR (LENGTH M) OF ZEROS ON RETURN, PROVIDED INFO=0
!                ON RETURN [REAL]
!
!      V(MX,*) = MATRIX (SIZE M BY M) USED FOR INTERMEDIATE
!                COMPUTATIONS [REAL]
!
!          * N = NUMBER OF ROWS IN MATRIX X [INTEGER]
!
!          * M = NUMBER OF COLUMNS IN MATRIX X (M<=N) [INTEGER]
!
!         * NX = LEADING DIMENSION OF MATRIX X (NX>=N) [INTEGER]
!
!         * MX = LEADING DIMENSION OF MATRIX V (MX>=M) [INTEGER]
!
!          * K = ON INPUT: K>0 INDICATES KNOWN RANK OF MATRIX X.
!                          K=0 INDICATES RANK SHOULD BE AUTOMATICALLY
!                              DETERMINED BY PROGRAM.
!                ON OUTPUT: = UNCHANGED IF K>0 ON INPUT.
!                           = COMPUTED RANK OF X IF K=0 ON INPUT.
!
!        IFLAG = ERROR INDICATOR ON OUTPUT [INTEGER]  INTERPRETATION:
!                1 -> N>NX OR M>MX.
!                2 -> N<M.
!                3 -> INFO<>0 RETURNED FROM SSVDC (SINGULAR VALUES WERE
!                     NOT COMPUTED CORRECTLY, THUS MOORE-PENROSE
!                     PSEUDO-INVERSE NOT COMPUTED).
!                4 -> K<0 ON INPUT.
!
!   * INDICATES PARAMETERS REQUIRING INPUT VALUES
!-----------------------------------------------------------------------
!
      DIMENSION X(NX,*),WORK(*),S(*),E(*),V(MX,*)
!
      DATA RNDERR / 1.0E-14 /
!
      CUTOFF = 0.0
      IFLAG = 0
      IF (N.GT.NX.OR.M.GT.MX) THEN
         IFLAG = 1
         RETURN
!
      ENDIF
      IF (N.LT.M) THEN
         IFLAG = 2
         RETURN
!
      ENDIF
      IF (K.LT.0) THEN
         IFLAG = 4
         RETURN
!
      ENDIF
      IF (K.EQ.0) THEN
!
!--- COMPUTE LARGEST ELEMENT OF X (IN ABSOLUTE VALUE)
!
         XMAX = 0.0
         DO 20 I = 1, N
            DO 10 J = 1, M
               XMAX = AMAX1(XMAX,ABS(X(I,J)))
   10       CONTINUE
   20    CONTINUE
!
!--- COMPUTE CUTOFF POINT FOR A SINGULAR VALUE BEING ZERO
!
         CUTOFF = 10.0*RNDERR*XMAX
      ENDIF
!
!--- PERFORM SINGULAR VALUE FACTORIZATION USING LINPACK
!
      CALL SSVDC (X,NX,N,M,S,E,X,NX,V,MX,WORK,21,INFO)
!
!--- CHECK WHETHER SINGULAR VALUES HAVE BEEN COMPUTED CORRECTLY
!
      IF (INFO.NE.0) THEN
         IFLAG = 3
         RETURN
!
      ENDIF
      IF (K.EQ.0) THEN
!
!--- DETERMINE NUMBER OF NONZERO SINGULAR VALUES
!
         K = 0
         DO 30 J = 1, M
            IF (ABS(S(J)).GT.CUTOFF) THEN
               K = K+1
            ELSE
               GO TO 40
!
            ENDIF
   30    CONTINUE
      ENDIF
!
!--- COMPUTE THE MOORE-PENROSE PSEUDO-INVERSE OF X (TRANSPOSED)
!
   40 DO 60 J = 1, M
         DO 50 L = 1, K
            V(J,L) = V(J,L)/S(L)
   50    CONTINUE
   60 CONTINUE
      DO 100 I = 1, N
         DO 80 J = 1, M
            T = 0.0
            DO 70 L = 1, K
               T = T+V(J,L)*X(I,L)
   70       CONTINUE
            E(J) = T
   80    CONTINUE
         DO 90 J = 1, M
            X(I,J) = E(J)
   90    CONTINUE
  100 CONTINUE
      RETURN
!
      END SUBROUTINE MATMPI 
      SUBROUTINE MAXIM(X,N,IWRITE,XMAX,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE MAXIMUM
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMAX   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE MAXIMUM.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE MAXIMUM.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--DAVID, ORDER STATISTICS, 1970, PAGE 7.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY  1988.  (SUPPRESS SOME DIAGNOSTIC MESSAGES)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MAXI'
      ISUBN2='M   '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF MAXIM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ***********************
!               **  COMPUTE MAXIMUM  **
!               ***********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN MAXIM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE MAXIMUM IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN MAXIM--',
!CCCC1'THE 2ND INPUT ARGUMENT (N) HAS THE VALUE 1')
!CCCC CALL DPWRST('XXX','BUG ')
      XMAX=X(1)
      GO TO 800
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN MAXIM--',
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      XMAX=HOLD
      GO TO 800
  139 CONTINUE
!
!               ****************************
!               **  STEP 2--              **
!               **  COMPUTE THE MAXIMUM.  **
!               ****************************
!
      XMAX=X(1)
      DO 200 I=2,N
      IF(X(I).GT.XMAX)XMAX=X(I)
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XMAX
  811 FORMAT('THE MAXIMUM OF THE ',I8,' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF MAXIM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XMAX
 9015 FORMAT('XMAX = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE MAXIM
      SUBROUTINE MAXIND(X,N,IWRITE,PSTAMV,XIND,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE INDEX WHERE THE
!              SAMPLE MAXIMUM OF THE DATA IN THE INPUT VECTOR X
!              OCCURS.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XIND   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED INDEX OF THE SAMPLE MAXIMUM.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE INDEX OF THE MAXIMUM.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.2
!     ORIGINAL VERSION--FEBRUARY  2009.
!     UPDATED         --APRIL     2010. SKIP "MISSING VALUES"
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MINI'
      ISUBN2='ND  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'XIND')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MAXIND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************
!               **  COMPUTE MAXIMUM  **
!               ***********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN INDEX MAXIMUM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS FOR THE ',   &
               'RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE MUST BE 1 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
               '.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XIND=1.0
        GO TO 800
      ENDIF
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE INDEX OF THE MAXIMUM.  **
!               *****************************************
!
      XMAX=CPUMIN
      XIND=1
      DO 200 I=1,N
        IF(X(I).NE.PSTAMV .AND. X(I).GT.XMAX)THEN
          XMAX=X(I)
          XIND=REAL(I)
        ENDIF
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XIND
  811   FORMAT('THE INDEX FOR THE MAXIMUM VALUE OF THE ',I8,   &
               ' OBSERVATIONS = ',F12.0)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'XIND')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MAXIND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N
 9013   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XMAX,XIND
 9015   FORMAT('XMAX,XIND = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE MAXIND
      SUBROUTINE MAXCDF(X,CDF)
!CCCC SUBROUTINE MAXCDF(X,SIGMA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE MAXWELL DISTRIBUTION
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND
!              HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!                 F(X) = 2*IG(3/2,0.5*(1/SIGMA**2)*X**2)/SQRT(PI)
!              WITH IG DENOTING THE IMCOMPLETE GAMMA FUNCTION.
!              SIGMA IS A SCALE PARAMETER, SO WE CAN SET IT TO 1.
!     INPUT  ARGUMENTS--X     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE CUMULATIVE DISTRIBUTION
!                               FUNCTION IS TO BE EVALUATED.
!                               X SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--CDF   = THE SINGLE PRECISION CUMULATIVE
!                               DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE MAXWELL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DGAMI, DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, P. 453.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!     UPDATED         --FEBRUARY  2008. TREAT MAXWELL AS A SCALE
!                                       PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DGAMI
!
      EXTERNAL DGAMI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
!CCCC IF(X.LT.0.0)THEN
!CCCC   WRITE(ICOUT,8)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,48)X
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   CDF=0.0
!CCCC   GO TO 9000
!CCCC ENDIF
!CCCC IF(SIGMA.LE.0.0)THEN
!CCCC   WRITE(ICOUT,18)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,48)SIGMA
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   CDF=0.0
!CCCC   GO TO 9000
!CCCC ENDIF
!CCC8 FORMAT('***** ERROR: VALUE OF THE FIRST ARGUMENT TO MAXCDF ',
!CCCC1       'IS NEGATIVE.')
!CC18 FORMAT('***** ERROR: VALUE OF THE SECOND ARGUMENT TO MAXCDF ',
!CCCC1       'IS NON-POSITIVE.')
!CC48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      IF(X.LE.0.0)THEN
        CDF=0.0
      ELSE
        DX=DBLE(X)
!CCCC   DS=DBLE(SIGMA)**2
        DS=1.0D0
        IF(DX.GE.DSQRT(D1MACH(2)))THEN
          CDF=1.0
          GO TO 9000
        ENDIF
!
        DTERM3=2.0D0/DSQRT(DPI)
        DTERM1=1.5D0
        DTERM2=0.5D0*DX*DX/DS
        DCDF=DTERM3*DGAMI(DTERM1,DTERM2)
        CDF=REAL(DCDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MAXCDF
      SUBROUTINE MAXCD2(DX,DCDF)
!CCCC SUBROUTINE MAXCD2(DX,DSIGMA,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE MAXWELL DISTRIBUTION
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND
!              HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!                 F(X) = 2*IG(3/2,0.5*(1/SIGMA**2)*X**2)/SQRT(PI)
!              WITH IG DENOTING THE IMCOMPLETE GAMMA FUNCTION.
!     NOTE--THIS IS A COPY OF MAXCDF USED BY MAXPPF ROUTINE
!           TO OBTAIN HIGHER ACCURACY IN NUMERICAL INVERSION
!     INPUT  ARGUMENTS--X     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE CUMULATIVE DISTRIBUTION
!                               FUNCTION IS TO BE EVALUATED.
!                               X SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--CDF   = THE SINGLE PRECISION CUMULATIVE
!                               DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE MAXWELL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DGAMI, DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, P. 453.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!     UPDATED         --FEBRUARY  2008. TREAT SIGMA AS A SCALE
!                                       PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DGAMI
!
      EXTERNAL DGAMI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
!CCCC IF(X.LT.0.0)THEN
!CCCC   WRITE(ICOUT,8)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,48)X
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   CDF=0.0
!CCCC   GO TO 9000
!CCCC ENDIF
!CCCC IF(DSIGMA.LE.0.0D0)THEN
!CCCC   WRITE(ICOUT,18)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,48)SIGMA
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   DCDF=0.0D0
!CCCC   GO TO 9000
!CCCC ENDIF
!CCC8 FORMAT('***** ERROR: VALUE OF THE FIRST ARGUMENT TO MAXCDF ',
!CCCC1       'IS NEGATIVE.')
!CC18 FORMAT('***** ERROR: VALUE OF THE SECOND ARGUMENT TO MAXCDF ',
!CCCC1       'IS NON-POSITIVE.')
!CC48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      IF(DX.LE.0.0D0)THEN
        DCDF=0.0D0
      ELSE
        DS=1.0D0
!CCCC   DS=DSIGMA**2
        IF(DX.GE.DSQRT(D1MACH(2)))THEN
          DCDF=1.0D0
          GO TO 9000
        ENDIF
!
        DTERM3=2.0D0/DSQRT(DPI)
        DTERM1=1.5D0
        DTERM2=0.5D0*DX*DX/DS
        DCDF=DTERM3*DGAMI(DTERM1,DTERM2)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MAXCD2
      subroutine maxofq
!
!     NOTE: This subroutine used in computing the consensus mean
!           using the Iyer and Wang generalized tolerance interval
!           approach.
!
!           Modified for Dataplot 3/2006.
!
!           Modified for Dataplot 4/2021.
!
!           1) Allow maximum of 1,000 labs
!
      implicit none
!
      integer kk
!cccc double precision aa, ybar, cc, bb(100), yy(100)
      double precision aa, ybar, cc, bb(1000), yy(1000)
      common /cmn1/ kk
      common /cmn2/ aa, ybar, cc, bb, yy
!
      integer i
      double precision sx2, sx1, s1b
!
      sx2 = 0.0d0
      sx1 = 0.0d0
      s1b = 0.0d0
!
      do 10 i = 1, kk
         sx2 = sx2 + yy(i)**2/bb(i)
         sx1 = sx1 + yy(i)/bb(i)
         s1b = s1b + 1.0d0/bb(i)
   10 continue
!
      aa = sx2 - 2.0d0*ybar*sx1 + ybar**2 * s1b -   &
          (sx1 - ybar*s1b)**2/s1b
!
      return
      end
      SUBROUTINE MAXLI1(Y,N,ICASPL,   &
                        ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE MAXWELL DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 10.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MAXL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF MAXLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'1MAX')ALOC=0.0
!
!     THE LOG-LIKELIHOOD FUNCTION IS
!
!     (-N/2)*LOG(2) -3*N*LOG(S) - N*LOGGAMMA(1.5) +
!     2*SUM[i=1][N][LOG(Y(i) - U) -
!     (1/(2*S**2)*SUM[i=1][N][Y(i) - U]
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTERM1=(-DN/2.0D0)*DLOG(2.0D0) - 3.0D0*DN*DLOG(DS)
      DTERM2=1.0D0/(2.0D0*DS*DS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + DLOG(DX-DU)
        DSUM2=DSUM2 + (DX-DU)
 1000 CONTINUE
      DLIK=DTERM1 + 2.0D0*DSUM1 - DTERM2*DSUM2
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'1MAX')DNP=1.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF MAXLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE MAXLI1
      SUBROUTINE MAXML1(Y,N,ICASPL,   &
                        DTEMP1,   &
                        XMEAN,XSD,XMIN,XMAX,   &
                        ALOCML,SCALML,SCALSE,   &
                        ALOCMO,SCALMO,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE MAXWELL DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLMX WILL GENERATE THE OUTPUT
!              FOR THE MAXWELL MLE COMMAND).
!
!              THE CODE IS SET-UP TO HANDLE EITHER 1-PARAMETER OR
!              2-PARAMETER CASE.  CURRENTLY, THE 2-PARAMETER CASE ONLY
!              SUPPORTS MOMENT ESTIMATES.
!
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 10.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLMX),
!                                       SUPPORT 2-PARAMETER CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DP
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DVAR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!
!RAYL DOUBLE PRECISION DXSTRT
!RAYL DOUBLE PRECISION DXLOW
!RAYL DOUBLE PRECISION DXUP
!RAYL DOUBLE PRECISION XLOWSV
!RAYL DOUBLE PRECISION XUPSV
!
      DOUBLE PRECISION DGAMMA
      EXTERNAL DGAMMA
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
!
      DOUBLE PRECISION RAYFUN
      EXTERNAL RAYFUN
!
      INTEGER IN
      DOUBLE PRECISION DXBAR
      COMMON/RAYCOM/DXBAR,IN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI/ 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MAXM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF MAXML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),DTEMP1(I)
   57     FORMAT('I,Y(I),DTEMP1(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR MAXWELL MLE ESTIMATE              **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='MAXWELL'
      IFLAG=0
      IF(ICASPL.EQ.'1')IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      ALOCMO=CPUMIN
      SCALMO=CPUMIN
      ALOCML=CPUMIN
      SCALML=CPUMIN
      ALOCMM=CPUMIN
      SCALMM=CPUMIN
      SCALSE=CPUMIN
      SCA2SE=CPUMIN
!
      IF(ICASPL.EQ.'1')THEN
!
!       ONE-PARAMETER MODEL
!
!       MAXIMUM LIKELIHOOD ESTIMATE OF SIGMA:
!
!       SIGMAHAT = SUM[i=1 to N][SQRT(X(i)**2/(3*N)]
!
!       FORMULA FOR STANDARD ERROR GIVEN ON PAGE 201 OF
!       COHEN AND WHITTEN.
!
        DP=3.0D0
        DN=DBLE(N)
        DSUM1=0.0D0
        DO 1010 I=1,N
          DX=DBLE(Y(I))
          DSUM1=DSUM1 + DX*DX/(DP*DN)
 1010   CONTINUE
        DSUM1=DSQRT(DSUM1)
        SCALML=REAL(DSUM1)
        DTERM1=DSUM1**2/(2.0D0*DN*DP)
        DTERM2=2.0D0*DN*DP
!
!       USE LOG GAMMA FUNCTION IN CASE N GETS LARGE
!
!CCCC   DTERM3=DGAMMA((DN*DP+1.0D0)/2.0D0)
!CCCC   DTERM4=DGAMMA(DN*DP/2.0D0)
        DTERM3=DLNGAM((DN*DP+1.0D0)/2.0D0)
        DTERM4=DLNGAM(DN*DP/2.0D0)
        DTERM5=2.0D0*(DLOG(2.0D0) + DTERM3 - DTERM4)
        DTERM5=DEXP(DTERM5)
!
        DVAR=DTERM1*(DTERM2 - DTERM5)
        SCALSE=REAL(DSQRT(DVAR))
!
        DTERM1=DGAMMA(DP/2.0D0)
        DTERM2=DGAMMA((DP+1.0D0)/2.0D0)
        DTERM3=DTERM1/DSQRT(2.0D0*DTERM2)
        SCALMO=XMEAN*REAL(DTERM3)
      ELSE
!
!       MOMENT ESTIMATES ARE:
!
!       SIGMAHAT = S*SQRT(PI/(3*PI-8))
!       UHAT = XBAR - 2*SIGMAHAT**2*SQRT(2/PI)
!
        DTERM1=DSQRT(DPI/(3.0D0*DPI-8.0D0))
        DTERM2=DBLE(XSD)*DTERM1
        SCALMO=REAL(DTERM2)
        DTERM2=DSQRT(2.0D0/DPI)
        ALOCMO=XMEAN - 2.0*SCALMO*REAL(DTERM2)
!
!       MAXIMUM LIKELIHOOD ESTIMATES ARE:
!
!RAYL   DXBAR=DBLE(XMEAN)
!RAYL   IN=N
!RAYL   DO2010I=1,N
!RAYL     DTEMP1(I)=DBLE(Y(I))
!2010   CONTINUE
!
!RAYL   DXSTRT=DBLE(ALOCMM)
!RAYL   DAE=2.0*0.000001D0*DXSTRT
!RAYL   DRE=DAE
!RAYL   IFLAG=0
!RAYL   IF(DXSTRT.GE.0.0D0)THEN
!RAYL     DXLOW=DXSTRT/3.0D0
!RAYL   ELSE
!RAYL     DXLOW=DXSTRT*3.0D0
!RAYL   ENDIF
!RAYL   DXUP=DBLE(XMIN)
!RAYL   ITBRAC=0
!4105   CONTINUE
!RAYL   XLOWSV=DXLOW
!RAYL   XUPSV=DXUP
!RAYL   CALL DFZER2(RAYFUN,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
!
!RAYL   IF(IFLAG.EQ.4 .AND. ITBRAC.LE.100)THEN
!RAYL     IF(DXLOW.GE.0.0D0)THEN
!RAYL       DXLOW=XLOWSV/2.0D0
!RAYL     ELSE
!RAYL       DXLOW=XLOWSV*2.0D0
!RAYL     ENDIF
!RAYL     ITBRAC=ITBRAC+1
!RAYL     GO TO 4105
!RAYL   ENDIF
!
!RAYL   IF(IFLAG.EQ.2)THEN
!
!         NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC     WRITE(ICOUT,999)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     WRITE(ICOUT,111)
!C111     FORMAT('***** WARNING FROM MAXWELL MAXIMUM ',
!CCCC1           'LIKELIHOOD--')
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     WRITE(ICOUT,113)
!C113     FORMAT('      ESTIMATE OF MU MAY NOT BE COMPUTED TO ',
!CCCC1           'DESIRED TOLERANCE.')
!CCCC     CALL DPWRST('XXX','BUG ')
!RAYL   ELSEIF(IFLAG.EQ.3)THEN
!RAYL     WRITE(ICOUT,999)
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL     WRITE(ICOUT,121)
!C121     FORMAT('***** WARNING FROM MAXWELL MAXIMUM LIKELIHOOD--')
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL     WRITE(ICOUT,123)
!C123     FORMAT('      ESTIMATE OF MU MAY BE NEAR A SINGULAR POINT.')
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL   ELSEIF(IFLAG.EQ.4)THEN
!RAYL     WRITE(ICOUT,999)
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL     WRITE(ICOUT,131)
!C131     FORMAT('***** ERROR FROM MAXWELL MAXIMUM LIKELIHOOD--')
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL     WRITE(ICOUT,133)
!C133     FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL   ELSEIF(IFLAG.EQ.5)THEN
!RAYL     WRITE(ICOUT,999)
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL     WRITE(ICOUT,121)
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL     WRITE(ICOUT,143)
!C143     FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
!RAYL     CALL DPWRST('XXX','BUG ')
!RAYL   ENDIF
!
!RAYL   ALOCML=REAL(DXLOW)
!RAYL   DSUM1=0.0D0
!RAYL   DO2030I=1,N
!RAYL     DX=DBLE(Y(I)) - DXLOW
!RAYL     DSUM1=DSUM1 + DX**2
!2030   CONTINUE
!RAYL   SCALML=REAL(DSUM1/(2.0D0*DP))
!
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF MAXML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,6G15.7)
        CALL DPWRST('XXX','WRIT')
        IF(ICASPL.EQ.'1')THEN
          WRITE(ICOUT,9056)SCALMM,SCALSE
 9056     FORMAT('SCALMM,SCALSE = ',2G15.7)
          CALL DPWRST('XXX','WRIT')
        ELSE
          WRITE(ICOUT,9058)ALOCMO,SCALMO
 9058     FORMAT('ALOCML,SCALML = ',2G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE MAXML1
      SUBROUTINE MAXPDF(X,PDF)
!CCCC SUBROUTINE MAXPDF(X,SIGMA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE MAXWELL DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND
!              HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = SQRT(2/PI)*(1/SIGMA**2)**(3/2)*X**2*
!                        EXP(-(X**2)/(2*SIGMA**2))
!     INPUT  ARGUMENTS--X     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE PROBABILITY DENSITY
!                               FUNCTION IS TO BE EVALUATED.
!                               X SHOULD BE NON-NEGATIVE.
!                     --SIGMA = THE SINGLE PRECISION VALUE WHICH
!                               DEFINES THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF   = THE SINGLE PRECISION PROBABILITY
!                               DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE MAXWELL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, P. 453.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!     UPDATED         --FEBRUARY  2008. TREAT SIGMA AS A SCALE
!                                       PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,8)
    8   FORMAT('***** ERROR: THE VALUE OF THE FIRST ARGUMENT TO ',   &
               'MAXPDF IS NEGATIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)X
   48   FORMAT('      THE VALUE OF THE ARGUMENT IS: ',G15.7,'.')
        CALL DPWRST('XXX','WRIT')
        PDF=0.0
        GO TO 9000
      ENDIF
!CCCC IF(SIGMA.LE.0.0)THEN
!CCCC   WRITE(ICOUT,18)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,48)SIGMA
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   PDF=0.0
!CCCC   GO TO 9000
!CCCC ENDIF
!CC18 FORMAT('***** ERROR: VALUE OF THE SECOND ARGUMENT TO MAXPDF ',
!CCCC1       'IS NON-POSITIVE.')
!
      IF(X.EQ.0.0)THEN
        PDF=0.0
      ELSE
        DX=DBLE(X)
!CCCCC  DS=DBLE(SIGMA)
        DS=1.0D0
        IF(DX.GE.DSQRT(D1MACH(2)))THEN
          PDF=0.0
          GO TO 9000
        ENDIF
!
        DTERM1=DLOG(DSQRT(2.0D0/DPI))
        DTERM2=1.5D0*DLOG(1.0D0/DS**2)
        DTERM3=2.0D0*DLOG(DX)
        DTERM4=-(DX*DX)/(2.0D0*DS**2)
        DPDF=DTERM1 + DTERM2 + DTERM3 + DTERM4
        DPDF=DEXP(DPDF)
        PDF=REAL(DPDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MAXPDF
      SUBROUTINE MAXPPF(P,PPF)
!CCCC SUBROUTINE MAXPPF(P,SIGMA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE MAXWELL DISTRIBUTION
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND
!              HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!                 F(X) = 2*IG(3/2,0.5*(1/SIGMA)*X**2)/SQRT(PI)
!              WITH IG DENOTING THE IMCOMPLETE GAMMA FUNCTION.
!              DATAPLOT COMPUTES THE PERCENT POINT FUNCTION BY
!              NUMERICALLY INVERTING THE CUMULATIVE DISTRIBUTION
!              FUNCTION.
!     INPUT  ARGUMENTS--P     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE PERCENT POINT
!                               FUNCTION IS TO BE EVALUATED.
!                               P SHOULD BE IN THE INTERVAL (0,1].
!     OUTPUT ARGUMENTS--PPF   = THE SINGLE PRECISION PERCENT POINT
!                               FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE MAXWELL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--MAXCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, P. 453.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!     UPDATED         --OCTOBER   2006. UPDATE TO DOUBLE PRECISION
!     UPDATED         --FEBRUARY  2008. TREAT SIGMA AS A SCALE
!                                       PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DP
      DOUBLE PRECISION EPS
      DOUBLE PRECISION SIG
      DOUBLE PRECISION ZERO
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
      DOUBLE PRECISION XL
      DOUBLE PRECISION XR
      DOUBLE PRECISION XINC
      DOUBLE PRECISION CDFL
      DOUBLE PRECISION CDFR
      DOUBLE PRECISION FXL
      DOUBLE PRECISION FXR
      DOUBLE PRECISION FCS
      DOUBLE PRECISION P1
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DGAMMA
      EXTERNAL DGAMMA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
      DATA EPS /0.000001D0/
      DATA SIG /1.0E-7/
      DATA ZERO /0.0D0/
      DATA MAXIT /3000/
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      PPF=0.0
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,8)
    8   FORMAT('***** ERROR: VALUE OF THE FIRST ARGUMENT TO MAXPPF ',   &
               'IS OUTSIDE THE [0,1) INTERVAL.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)P
   48   FORMAT('      THE VALUE OF THE ARGUMENT IS: ',G15.7,'.')
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
!CCCC IF(SIGMA.LE.0.0)THEN
!CCCC   WRITE(ICOUT,18)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,48)SIGMA
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   PDF=0.0
!CCCC   GO TO 9000
!CCCC ENDIF
!CC18 FORMAT('***** ERROR: VALUE OF THE SECOND ARGUMENT TO MAXPDF ',
!CCCC1       'IS NON-POSITIVE.')
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9000
      ENDIF
!
!  FIND BRACKETING INTERVAL.
!
!  1) LOWER LIMIT = 0
!  2) MEAN = 2*SQRT(2*SIGMA/PI)
!     SD = SQRT(SIGMA**2*(3*PI-8)/PI)
!  3) START RIGHT LIMIT AT MEAN, INCREMENT IN UNITS OF
!     ONE STANDARD DEVIATION
!
!CCCC DSIGMA=DBLE(SIGMA)
      DSIGMA=1.0D0
      DP=DBLE(P)
      DMEAN=2.0D0*DSQRT(2.0D0*DSIGMA/DPI)
      DSD=DSIGMA**2*(3.0D0*DPI - 8.0D0)/DPI
      DSD=DSQRT(DSD)
!
      XL=0.0D0
      XR=DMEAN
      XINC=DSD
      ICOUNT=0
      MAXCNT=1000
!
   91 CONTINUE
      IF(XL.LE.0.0D0)XL=0.0D0
      IF(XR.LE.0.0D0)XR=XL+XINC
!CCCC CALL MAXCD2(XL,DSIGMA,CDFL)
!CCCC CALL MAXCD2(XR,DSIGMA,CDFR)
      CALL MAXCD2(XL,CDFL)
      CALL MAXCD2(XR,CDFR)
      IF(CDFL.LT.DP .AND. CDFR.LT.DP)THEN
        XL=XR
        XR=XL+XINC
      ELSEIF(CDFL.GT.DP .AND. CDFR.GT.DP)THEN
        XL=XL-XINC
        IF(XL.LT.0.0D0)XL=0.0D0
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
   96 FORMAT('***** ERROR--MAXPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL.')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -DP
      FXR = 1.0D0 - DP
  105 CONTINUE
      DX = (XL+XR)*0.5D0
!CCCC CALL MAXCD2(DX,DSIGMA,DCDF)
      CALL MAXCD2(DX,DCDF)
      P1=DCDF
      PPF=REAL(DX)
      FCS = P1 - DP
      IF(FCS*FXL.GT.ZERO)THEN
        XL = DX
        FXL = FCS
      ELSE
        XR = DX
        FXR = FCS
      ENDIF
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9000
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--MAXPPF ROUTINE DID NOT CONVERGE.')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MAXPPF
      SUBROUTINE MAXRAN(N,ISEED,X)
!CCCC SUBROUTINE MAXRAN(N,SIGMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE MAXWELL DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 F(X) = SQRT(2/PI)*(1/SIGMA)**(3/2)X**2*
!                        EXP(-X**2/(2*SIGMA))
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE MAXWELL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, MAXPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).
!                "CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME 1",
!                SECOND EDITION, WILEY, P. 453.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRMAXMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!     UPDATED         --FEBRUARY  2008. TREAT SIGMA AS A SCALE
!                                       PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--FOR THE MAXWELL DISTRIBUTION, THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
    6   FORMAT('      REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('      THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     USE PERCENT POINT TRANSFORMATION METHOD.
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        ATEMP=X(I)
!CCCC   CALL MAXPPF(ATEMP,SIGMA,PPF)
        CALL MAXPPF(ATEMP,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE MAXRAN
      SUBROUTINE MCLCDF(X,ALPHA,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE MCLEISH
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE CUMULATIVE DISTRIBUTION
!                                 FUNCTION IS TO BE EVALUATED.
!                     --ALPHA   = THE FIRST SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF     = THE DOUBLE PRECISION CUMULATIVE
!                                 DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE FOR THE MCLEISH
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAG.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION X
      DOUBLE PRECISION DX
      DOUBLE PRECISION DA
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION MCLFUN
      EXTERNAL MCLFUN
!
      DOUBLE PRECISION DALPHA
      COMMON/MCLCOM/DALPHA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        CDF=0.0D0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (ALPHA)',   &
             ' IN MCLCDF ROUTINE IS NON-POSITIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(X.EQ.0.0D0)THEN
        DCDF=0.5D0
        GO TO 9000
      ELSEIF(X.LT.0.0D0)THEN
        ICASE=0
        DX=-X
      ELSE
        ICASE=1
        DX=X
      ENDIF
!
      INF=+1
      IKEY=3
      EPSABS=0.0D0
      EPSREL=1.0D-7
      DA=0.0D0
      IER=0
      DCDF=0.0D0
      DALPHA=ALPHA
!
      CALL DQAG(MCLFUN,DA,DX,EPSABS,EPSREL,IKEY,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
!
      IF(ICASE.EQ.1)THEN
        DCDF=0.5D0 + DCDF
      ELSE
        DCDF=0.50D0 - DCDF
      ENDIF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM MCLCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM MCLCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM MCLCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM MCLCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM MCLCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM MCLCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MCLCDF
      DOUBLE PRECISION FUNCTION MCLFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE MCLEISH
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL REAL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 MCLPDF(X,ALPHA) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                   (ABS(X)/2)**(ALPHA-1/2)*
!                                   K(X,ALPHA-1/2)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!              THE MCLPDF ROUTINE IS CALLED TO COMPUTE THE
!              PROBABILITY DENSITY.  DEFINE AS FUNCTION TO BE USED FOR
!              INTEGRATION CODE CALLED BY MCLCDF.  THIS ROUTINE USES
!              DOUBLE PRECISION ARITHMETIC.
!     INPUT  ARGUMENTS--DX      = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--MCLFUN  = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE MCLEISH
!             DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--MCLPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      COMMON/MCLCOM/DALPHA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL MCLPDF(DX,DALPHA,DTERM)
      MCLFUN=DTERM
!
      RETURN
      END FUNCTION MCLFUN
