      SUBROUTINE MCLPDF(X,ALPHA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE MCLEISH BESSEL K-FUNCTION
!              DISTRIBUTION.  IT HAS SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS SYMMETRIC AND IS DEFINED
!              FOR ALL REAL X AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 MCLPDF(X,ALPHA) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                   (ABS(X)/2)**(ALPHA-1/2)*
!                                   K(X,ALPHA-1/2)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!     NOTE--ARGUMENTS TO THIS ROUTINE ARE IN DOUBLE PRECISION.
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!                                 X SHOULD BE POSITIVE
!                     --ALPHA    = THE FIRST SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF     = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE MCLEISH DISTRIBUTION
!             WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DBESK.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 WILEY, 1994, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION DX
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION PDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DORD
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
!
      DOUBLE PRECISION DTEMP1(1000)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (ALPHA)',   &
             ' IN MCLPDF ROUTINE IS NON-POSITIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE DENSITY FUNCTION.  FOR **
!               **  BETTER NUMERICAL STABILITY,        **
!               **  COMPUTE LOGARIGHMS.                **
!               *****************************************
!
!
!  COMPUTE BESSEL FUNCTION FIRST.  IF THIS IS 0, SET PDF TO
!  0 AND RETURN.
!
      DEPS=1.0D-12
      IF(ALPHA.GT.25.0)DEPS=1.0D-10
      DX=X
      DX=DABS(DX)
      IF(DX.EQ.0.0D0)DX=DEPS
      DORD=DABS(ALPHA-0.5D0)
      IARG1=1
      ISCALE=1
      CALL DBESK(DX,DORD,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM3=DTEMP1(IARG1)
      IF(DTERM3.LE.0.0D0)THEN
        PDF=0.0D0
        GO TO 9000
      ENDIF
      DTERM3=DLOG(DTERM3)
!
      DTERM1=0.5D0*DLOG(DPI) + DLNGAM(ALPHA)
      DTERM2=(ALPHA-0.5D0)*DLOG(DX/2.0D0)
      DTERM4 = -DTERM1+DTERM2+DTERM3
      PDF=DEXP(DTERM4)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MCLPDF
      SUBROUTINE MCLPPF(P,ALPHA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE MCLEISH DISTRIBUTION.  IT HAS
!              SHAPE PARAMETERS ALPHA.  THIS DISTRIBUTION IS DEFINED
!              FOR ALL REAL X AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 MCLPDF(X,ALPHA) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                   (ABS(X)/2)**(ALPHA-1/2)*
!                                   K(X,ALPHA-1/2)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY NUMERICALLY
!              INVERTING THE MCLEISH CUMULATIVE
!              DISTRIBUTION FUNCTION (WHICH IN TURN IS COMPUTED BY
!              NUMERICAL INTEGRATION OF THE PROBABILITYT DENSITY.
!
!     INPUT  ARGUMENTS--P       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PERCENT POINT
!                                 FUNCTION IS TO BE EVALUATED.
!                                 0 < P < 1
!                     --ALPHA   = THE FIRST SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF     = THE SINGLE PRECISION PERCENT POINT
!                                 FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE MCLEISH
!             DISTRIBUTION WITH SHAPE PARAMETER = ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION PTEMPL
      DOUBLE PRECISION PTEMPU
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION PPF
      DOUBLE PRECISION DINC
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION RE
      DOUBLE PRECISION AE
!
      DOUBLE PRECISION MCLFU2
      EXTERNAL MCLFU2
!
      DOUBLE PRECISION DP
      COMMON/MC2COM/DP
!
      DOUBLE PRECISION DALPHA
      COMMON/MCLCOM/DALPHA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      IF(P.LE.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)P
        CALL DPWRST('XXX','WRIT')
        PPF=0.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR: VALUE OF INPUT ARGUMENT (P) IN ',   &
             'MCLPPF ROUTINE')
   14 FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        PPF=0.0D0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (ALPHA)',   &
             ' IN MCLPPF ROUTINE IS NON-POSITIVE.')
!
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      IF(P.EQ.0.5D0)THEN
        PPF=0.0D0
        GO TO 9000
      ENDIF
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE PERCENT POINT FUNCTION.**
!               *****************************************
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH -10 AND +10,
!          INCREMENT BY 10.
!
      XLOW=-10.0D0
      XUP2=10.0D0
      CALL MCLCDF(XLOW,ALPHA,PTEMPL)
      CALL MCLCDF(XUP2,ALPHA,PTEMPU)
      DINC=10.0D0
!
      MAXIT=1000
      NIT=0
!
  200 CONTINUE
      IF(NIT.GT.MAXIT)THEN
        PPF=0.0D0
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      CALL MCLCDF(XLOW,ALPHA,PTEMPL)
      CALL MCLCDF(XUP2,ALPHA,PTEMPU)
      IF(PTEMPL.LE.P .AND. P.LE.PTEMPU)THEN
        XUP=XUP2
        GO TO 300
      ELSEIF(P.GT.PTEMPU)THEN
        XLOW=XUP2
        XUP2=XUP2 + DINC
        NIT=NIT+1
        GO TO 200
      ELSEIF(P.LT.PTEMPL)THEN
        XUP2=XLOW
        XLOW=XLOW - DINC
        NIT=NIT+1
        GO TO 200
      ENDIF
!
  300 CONTINUE
      AE=1.D-7
      RE=1.D-7
      DALPHA=ALPHA
      DP=P
      CALL DFZERO(MCLFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM MCLPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM MCLPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM MCLPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM MCLPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MCLPPF
      SUBROUTINE MCLRAN(N,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE MCLEISH DISTRIBUTION WITH SHAPE
!              PARAMETER = ALPHA.  THIS DISTRIBUTION IS DEFINED
!              FOR ALL X AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 MCLPDF(X,ALPHA) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                   (ABS(X)/2)**(ALPHA-1/2)*
!                                   K(X,ALPHA-1/2)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!              TO GENERATE RANDOM NUMBERS, USE THE RELATIONSHIP
!
!                    Y = SQRT(G)*Z
!
!              WITH G DENOTING A GAMMA RANDOM VARIABLE WITH SHAPE
!              ALPHA AND SCALE PARAMETER 2 AND Z A STANDARD NORMAL
!              RANDOM VARIABLE.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SHAPE PARAMETER FOR THE
!                                MCLEISH DISTRIBUTION
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE MCLEISH DISTRIBUTION
!             WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, NORRAN, GAMRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 WILEY, 1994, PP. 50-51.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
    5 FORMAT('***** ERROR--FOR THE MCLEISH DISTRIBUTION, THE REQUESTED')
    6 FORMAT('      NUMBER OF RANDOM NUMBERS WAS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!CC48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!     MCLEISH IS DISTRIBUTION OF SQRT(G)*Z WHERE G IS A GAMMA
!     DISTRIBUTION WITH SHAPE PARAMETER ALPHA AND SCALE PARAMETER 2
!     T IS A STANDARD NORMAL DISTRIBUTION.
!
      CALL GAMRAN(N,ALPHA,ISEED,X)
      NTEMP=1
      DO 100 I=1,N
        G1=SQRT(2.0*X(I))
        CALL NORRAN(NTEMP,ISEED,Y)
        G2=Y(1)
        X(I)=G1*G2
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE MCLRAN
      SUBROUTINE MEAN(X,N,IWRITE,XMEAN,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE MEAN
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE MEAN = (SUM OF THE OBSERVATIONS)/N.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMEAN  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE MEAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE MEAN.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 2, EDITION 1, 1961, PAGE 4.
!               --MOOD AND GRABLE, INTRODUCTION TO THE THEORY
!                 OF STATISTICS, EDITION 2, 1963, PAGE 146.
!               --DIXON AND MASSEY, INTRODUCTION TO STATISTICAL
!                 ANALYSIS, EDITION 2, 1957, PAGE 14.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JULY      1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MEAN'
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MEAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************
!               **  COMPUTE MEAN  **
!               ********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN MEAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        XMEAN=X(1)
        GO TO 800
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XMEAN=HOLD
      GO TO 800
  139 CONTINUE
!
!               *************************
!               **  STEP 2--           **
!               **  COMPUTE THE MEAN.  **
!               *************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
        DSUM=DSUM+DBLE(X(I))
  200 CONTINUE
      XMEAN=REAL(DSUM/DN)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XMEAN
  811   FORMAT('THE MEAN OF THE ',I8,' OBSERVATIONS = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MEAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,XMEAN
 9012   FORMAT('IERROR,XMEAN = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE MEAN
      SUBROUTINE MEDIAN(X,N,IWRITE,XTEMP,MAXNXT,XMED,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE MEDIAN
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE MEDIAN = THAT VALUE SUCH THAT HALF THE
!              DATA SET IS BELOW IT AND HALF ABOVE IT.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMED   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE MEDIAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE MEDIAN.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGE 326.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 2, EDITION 1, 1961, PAGE 49.
!               --DAVID, ORDER STATISTICS, 1970, PAGE 139.
!               --SNEDECOR AND COCHRAN, STATISTICAL METHODS,
!                 EDITION 6, 1967, PAGE 123.
!               --DIXON AND MASSEY, INTRODUCTION TO STATISTICAL
!                 ANALYSIS, EDITION 2, 1957, PAGE 70.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1976.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY  1988.  (COMMENTED OUT INPUT ERROR MESSAGES)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MEDI'
      ISUBN2='AN  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MEDIAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************
!               **  COMPUTE MEDIAN  **
!               **********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN MEDIAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE IS LESS THAN 1 OR GREATER THAN ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XMED=X(1)
        GO TO 800
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XMED=HOLD
      GO TO 800
  139 CONTINUE
!
!               ***************************
!               **  STEP 2--             **
!               **  COMPUTE THE MEDIAN.  **
!               ***************************
!
      CALL SORT(X,N,XTEMP)
!
      IEVODD=N-(N/2)*2
      NMID=N/2
      NMIDP1=NMID+1
      IF(IEVODD.EQ.0)XMED=(XTEMP(NMID)+XTEMP(NMIDP1))/2.0
      IF(IEVODD.EQ.1)XMED=XTEMP(NMIDP1)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XMED
  811   FORMAT('THE MEDIAN OF THE ',I8,' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MEDIAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,N,XMED
 9012   FORMAT('IBUGA3,IERROR,N,XMED = ',2(A4,2X),I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE MEDIAN
      SUBROUTINE MIDMEA(X,N,IWRITE,XTEMP,MAXNXT,XMIDM,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE MIDMEAN = THE
!              SAMPLE 25% (ON EACH SIDE) TRIMMED MEAN OF THE DATA
!              IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMIDM  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE MIDMEAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE MIDMEAN.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--DAVID, ORDER STATISTICS, 1970, PAGES 129, 136.
!               --CROW AND SIDDIQUI, 'ROBUST ESTIMATION OF LOCATION',
!                 JOURNAL OF THE AMERICAN STATISTICAL ASSOCIATION,
!                 1967, PAGES 357, 387.
!               --FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY, 1969).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1976.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     2007. FIX BUG
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DK
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MIDM'
      ISUBN2='EA  '
      IERROR='NO'
      XMIDM=CPUMIN
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MIDMEA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************
!               **  COMPUTE MIDMEAN  **
!               ***********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN MIDMEAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XMIDM=X(1)
        GO TO 800
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XMIDM=HOLD
      GO TO 800
  139 CONTINUE
!
!               ****************************
!               **  STEP 2--              **
!               **  COMPUTE THE MIDMEAN.  **
!               ****************************
!
      CALL SORT(X,N,XTEMP)
!
      P1=0.25
      NP1=INT(P1*AN+0.0001)
      ISTART=NP1+1
!
      P2=0.25
      NP2=INT(P2*AN+0.0001)
      ISTOP=N-NP2
!
      DSUM=0.0
      K=0
      IF(ISTART.GT.ISTOP)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,252)
  252   FORMAT('      START INDEX IS HIGHER THAN STOP INDEX.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,253)ISTART,ISTOP
  253   FORMAT('      ISTART,ISTOP = ',2I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DO 200 I=ISTART,ISTOP
        K=K+1
!CCCC   MARCH 2007.  USE SORTED VALUE
!CCCC   DX=X(I)
        DX=XTEMP(I)
        DSUM=DSUM+DX
  200 CONTINUE
      DK=K
      XMIDM=DSUM/DK
      GO TO 290
!
  290 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        PERP1=100.0*P1
        PERP2=100.0*P2
        PERP3=100.0*(1.0-P1-P2)
        WRITE(ICOUT,811)PERP1,NP1
  811   FORMAT(8X,F10.4,' PERCENT (= ',I8,' OBSERVATIONS) ',   &
               'OF THE DATA WERE TRIMMED         FROM BELOW')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,812)PERP2,NP2
  812   FORMAT(8X,F10.4,' PERCENT (= ',I8,' OBSERVATIONS) ',   &
               'OF THE DATA WERE TRIMMED         FROM ABOVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,813)PERP3,K
  813   FORMAT(8X,F10.4,' PERCENT (= ',I8,' OBSERVATIONS) ',   &
               'OF THE DATA REMAIN IN MIDDLE AFTER TRIMMING')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,821)N,XMIDM
  821   FORMAT('THE MIDMEAN OF THE ',I8,' OBSERVATIONS = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MIDMEA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XMIDM
 9015   FORMAT('XMIDM = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE MIDMEA
      SUBROUTINE MIDRAN(X,N,IWRITE,XMIDR,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE MIDRANGE
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE MIDRANGE = (SAMPLE MIN + SAMPLE MAX)/2.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMIDR  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE MIDRANGE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE MIDRANGE.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGE 338.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 2, EDITION 1, 1961, PAGE 91.
!               --DAVID, ORDER STATISTICS, 1970, PAGE 97.
!               --DIXON AND MASSEY, INTRODUCTION TO STATISTICAL
!                 ANALYSIS, EDITION 2, 1957, PAGE 71.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MIDR'
      ISUBN2='AN  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF MIDRAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ************************
!               **  COMPUTE MIDRANGE  **
!               ************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN MIDRAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE MIDRANGE IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN MIDRAN--',
!CCCC1'THE 2ND INPUT ARGUMENT (N) HAS THE VALUE 1')
!CCCC CALL DPWRST('XXX','BUG ')
      XMIDR=X(1)
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN MIDRAN--',
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      XMIDR=HOLD
      GO TO 800
  139 CONTINUE
!
!               *****************************
!               **  STEP 2--               **
!               **  COMPUTE THE MIDRANGE.  **
!               *****************************
!
      XMIN=X(1)
      XMAX=X(1)
      DO 200 I=1,N
      IF(X(I).LT.XMIN)XMIN=X(I)
      IF(X(I).GT.XMAX)XMAX=X(I)
  200 CONTINUE
      XMIDR=(XMIN+XMAX)/2.0
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XMIDR
  811 FORMAT('THE MIDRANGE OF THE ',I8,' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF MIDRAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XMIDR
 9015 FORMAT('XMIDR = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE MIDRAN
      SUBROUTINE MIECDF(DX,DK,DTHETA,DCDF)
!CCCC SUBROUTINE MIECDF(X,AK,BETA,THETA,CDF)
!
!     NOTE 05/06/2008--THE FOLLOWING 3 CHANGES WERE MADE:
!
!                      1) RENAMED FROM KAPPDF TO MIEPDF TO DISTINGUISH
!                         FROM THE KAPPA DISTRIBUTION DEFINED BY
!                         HOSKING AND WALLIS.
!
!                      2) BETA IS ACTUALLY A SCALE PARAMETER, SO WE
!                         CAN ASSUME BETA = 1 FOR STANDARD FORM OF
!                         DISTRIBUTION.
!
!                      3) MAKE THE ARGUMENTS DOUBLE PRECISION.
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DENSITY
!              FUNCTION VALUE FOR THE MIELKE'S BETA-KAPPA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETERS K AND THETA.
!              THE CDF FOR THE DISTRIBUTION IS
!                  F(X;K,THETA) = {X**THETA/(1 + X**THETA)}**(K/THETA)  X > 0
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DK     = A POSITIVE SHAPE PARAMETER
!                     --DTHETA = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE MIELKE'S BETA-KAPPA
!             DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 2", SECOND EDITION, P. 351.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--96/1
!     ORIGINAL VERSION--JANUARY   1996.
!     UPDATED         --MAY       2008. RENAME ROUTINE
!     UPDATED         --MAY       2008. TREAT BETA AS SCALE PARAMETER
!     UPDATED         --MAY       2008. ARGUMENTS DOUBLE PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DCDF=0.0D0
      IF(DX.LE.0.0D0)THEN
!CCCC   WRITE(ICOUT,5)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)DX
!CCCC   CALL DPWRST('XXX','BUG ')
        GO TO 9999
!CCC5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO MIECDF IS ',
!CCCC1         'NON-POSITIVE')
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO MIECDF IS ',   &
               'NON-POSITIVE')
      ELSEIF(DTHETA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DTHETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   35 FORMAT('***** ERROR--THE THIRD ARGUMENT TO MIECDF IS ',   &
             'NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DTERM1=DTHETA*DLOG(DX) - DLOG(1.0D0+DX**DTHETA)
      DTERM2=(DK/DTHETA)*DTERM1
      DCDF=DEXP(DTERM2)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE MIECDF
      SUBROUTINE MIEPDF(DX,DK,DTHETA,DPDF)
!CCCC SUBROUTINE MIEPDF(X,AK,BETA,THETA,PDF)
!
!     NOTE 05/06/2008--THE FOLLOWING 3 CHANGES WERE MADE:
!
!                      1) RENAMED FROM KAPPDF TO MIEPDF TO DISTINGUISH
!                         FROM THE KAPPA DISTRIBUTION DEFINED BY
!                         HOSKING AND WALLIS.
!
!                      2) BETA IS ACTUALLY A SCALE PARAMETER, SO WE
!                         CAN ASSUME BETA = 1 FOR STANDARD FORM OF
!                         DISTRIBUTION.
!
!                      3) MAKE THE ARGUMENTS DOUBLE PRECISION.
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE MIELKE'S BETA-KAPPA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETERS K AND THETA.
!              THE PDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!
!                 f(X;K,THETA) = K*X**(K-1)/[1+X**THETA]**(1+(K/THETA))
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DK     = A POSITIVE SHAPE PARAMETER
!                     --DTHETA = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE MIELKE'S BETA-KAPPA
!             DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 2, SECOND EDITION, P. 351.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--96/1
!     ORIGINAL VERSION--JANUARY   1996.
!     UPDATED         --MAY       2008. RENAME ROUTINE
!     UPDATED         --MAY       2008. TREAT BETA AS SCALE PARAMETER
!     UPDATED         --MAY       2008. MAKE ARGUMENTS DOUBLE PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPDF=0.0D0
      IF(DX.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO MIEPDF IS ',   &
               'NON-POSITIVE')
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO MIEPDF IS ',   &
               'NON-POSITIVE')
      ELSEIF(DTHETA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DTHETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   35 FORMAT('***** ERROR--THE THIRD ARGUMENT TO MIEPDF IS ',   &
             'NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DTERM1=DLOG(DK) + (DK-1.0D0)*DLOG(DX)
      DTERM2=(1.0D0 + (DK/DTHETA))*DLOG(1.0D0 + DX**DTHETA)
      DTERM3=DTERM1-DTERM2
      DPDF=DEXP(DTERM3)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE MIEPDF
      SUBROUTINE MIEPPF(DP,DK,DTHETA,DPPF)
!CCCC SUBROUTINE MIEPPF(P,AK,BETA,THETA,PPF)
!
!     NOTE 05/06/2008--THE FOLLOWING 2 CHANGES WERE MADE:
!
!                      1) RENAMED FROM KAPPPF TO MIEPPF TO DISTINGUISH
!                         FROM THE KAPPA DISTRIBUTION DEFINED BY
!                         HOSKING AND WALLIS.
!
!                      2) BETA IS ACTUALLY A SCALE PARAMETER, SO WE
!                         CAN ASSUME BETA = 1 FOR STANDARD FORM OF
!                         DISTRIBUTION.
!
!                      3) MAKE ARGUMENTS DOUBLE PRECISION
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE MIELKE'S BETA-KAPPA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETERS K AND THETA.
!              THE PPF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  G(P;K.THETA) = [P**(THETA/K)/(1-P**(THETA/K))]**(1/THETA)
!                                 0 < P < 1
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE AT WHICH THE
!                                PERCENT POINT FUNCTION IS TO BE EVALUATED.
!                     --AK     = A POSITIVE SHAPE PARAMETER
!                     --THETA  = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE PPF FOR
!             THE MIELKE'S BETA-KAPPA DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 < P < 1, THETA, K > 0.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 2", SECOND EDITION, P. 351.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!     UPDATED         --MAY       2008. RENAME ROUTINE
!     UPDATED         --MAY       2008. TREAT BETA AS SCALE PARAMETER
!     UPDATED         --MAY       2008. MAKE ARGUMENTS DOUBLE PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO MIEPPF IS ',   &
               'OUTSIDE THE (0,1) INTERVAL')
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO MIEPPF IS ',   &
               'NON-POSITIVE')
      ELSEIF(DTHETA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DTHETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   35 FORMAT('***** ERROR--THE THIRD ARGUMENT TO MIEPPF IS ',   &
             'NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DTERM2=(1.0D0/DTHETA)
      DTERM3=DP**(DTHETA/DK)
      DTERM4=DLOG(-DTERM3/(DTERM3-1.0D0))
      DTERM5=DTERM2*DTERM4
      DPPF=DEXP(DTERM5)
!
!CCCC DTERM1=(DTHETA/DK)*DLOG(DP) - DLOG(1.0D0 - DP**(DTHETA/DK))
!CCCC DTERM2=(DK/DTHETA)*DTERM1
!CCCC DPPF=DEXP(DTERM2)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE MIEPPF
      SUBROUTINE MIERAN(N,AK,THETA,ISEED,X)
!
!     NOTE 05/06/2008--THE FOLLOWING 2 CHANGES WERE MADE:
!
!                      1) RENAMED FROM KAPRAN TO MIERAN TO DISTINGUISH
!                         FROM THE KAPPA DISTRIBUTION DEFINED BY
!                         HOSKING AND WALLIS.
!
!                      2) BETA IS ACTUALLY A SCALE PARAMETER, SO WE
!                         CAN ASSUME BETA = 1 FOR STANDARD FORM OF
!                         DISTRIBUTION.
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE MIELKE'S BETA-KAPPA DISTRIBUTION
!              WITH SHAPE PARAMETERs = K AND THETA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --K      = THE SINGLE PRECISION VALUE OF THE
!                                K SHAPE PARAMETER.
!                     --THETA  = THE SINGLE PRECISION VALUE OF THE
!                                THETA SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE MIELKE'S BETA-KAPPA DISTRIBUTION
!             WITH SHAPE PARAMETERS K AND THETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ANU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2003.7
!     ORIGINAL VERSION--JULY      2003.
!     UPDATED         --MAY       2008. RENAME ROUTINE
!     UPDATED         --MAY       2008. TREAT BETA AS SCALE PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF MIELKE ',   &
             'BETA-KAPPA RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      IF(AK.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AK
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   15 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER (K) FOR ',   &
      'THE  MIELKE BETA-KAPPA RANDOM NUMBERS IS NON-POSITIVE')
      IF(THETA.LE.0.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   35 FORMAT('***** ERROR--THE THIRD SHAPE PARAMETER (THETA) ',   &
      'FOR THE  MIELKE BETA-KAPPA RANDOM NUMBERS IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N MIELKE'S BETA-KAPPA DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
!CCCC   CALL KAPPPF(X(I),AK,BETA,THETA,XTEMP)
        CALL MIEPPF(DBLE(X(I)),DBLE(AK),DBLE(THETA),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE MIERAN
      SUBROUTINE MINIM(X,N,IWRITE,XMIN,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE MINIMUM
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMIN   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE MINIMUM.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE MINIMUM.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--DAVID, ORDER STATISTICS, 1970, PAGE 7.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY  1988. (SUPPRESS SOME DIAGNOSTIC MESSAGES)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MINI'
      ISUBN2='M   '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF MINIM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ***********************
!               **  COMPUTE MINIMUM  **
!               ***********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN MINIM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE MINIMUM IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN MINIM--',
!CCCC1'THE 2ND INPUT ARGUMENT (N) HAS THE VALUE 1')
!CCCC CALL DPWRST('XXX','BUG ')
      XMIN=X(1)
      GO TO 800
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN MINIM--',
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      XMIN=HOLD
      GO TO 800
  139 CONTINUE
!
!               ****************************
!               **  STEP 2--              **
!               **  COMPUTE THE MINIMUM.  **
!               ****************************
!
      XMIN=X(1)
      DO 200 I=2,N
      IF(X(I).LT.XMIN)XMIN=X(I)
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XMIN
  811 FORMAT('THE MINIMUM OF THE ',I8,' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF MINIM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XMIN
 9015 FORMAT('XMIN = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE MINIM
      SUBROUTINE MININD(X,N,IWRITE,PSTAMV,XIND,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE INDEX WHERE THE
!              SAMPLE MINIMUM OF THE DATA IN THE INPUT VECTOR X
!              OCCURS.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XIND   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED INDEX OF THE SAMPLE MINIMUM.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE INDEX OF THE MINIMUM.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.2
!     ORIGINAL VERSION--FEBRUARY  2009.
!     UPDATED         --APRIL     2010. SKIP "MISSING VALUES"
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MINI'
      ISUBN2='ND  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NIND')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MININD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************
!               **  COMPUTE MINIMUM  **
!               ***********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN INDEX MINIMUM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS FOR THE ',   &
               'RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE MUST BE 1 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
               '.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XIND=1.0
        GO TO 800
      ENDIF
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE INDEX OF THE MINIMUM.  **
!               *****************************************
!
      XMIN=CPUMAX
      XIND=1.0
      DO 200 I=1,N
        IF(X(I).NE.PSTAMV .AND. X(I).LT.XMIN)THEN
          XMIN=X(I)
          XIND=REAL(I)
        ENDIF
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XIND
  811   FORMAT('THE INDEX FOR THE MINIMUM VALUE OF THE ',I8,   &
               ' OBSERVATIONS = ',F12.0)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NIND')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MININD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N
 9013   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XMIN,XIND
 9015   FORMAT('XMIN,XIND = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE MININD
      subroutine mixtur(a, k, m, c, x, n,   &
          alpha, mean, sd, tol, nobvs,   &
          newalp,newmea,newsd,dt,nt,vt,g,f,   &
          kmax,mmax,   &
          logl, icount, ifault)
!
!     Translation from Algol 60 by Alan Miller of AS 203.
!
!     ALGORITHM AS 203 APPL. STATIST. (1984) VOL.33, NO. 3
!
!     This algorithm calculates the maximum likelihood estimates of the
!     parameters of a mixture of normal or exponential or Poisson or
!     binomial distributions.   These parameters are the mixing
!     proportions, the means and (in the normal distribution case)
!     standard deviations.   It also calculates the log-likelihood
!     function and the number of iterations taken to satisfy the
!     tolerance value.
!
!     Users must provide their own routine `putout' which prints the
!     estimated parameter values after each iteration.   The form of
!     this routine is:
!        subroutine putout(k, alpha, mean, sd, logl)
!        integer k
!        real alpha(k), mean(k), sd(k), logl
!
!     Notes:
!     The original (Algol) variable names have been retained.   This
!     means that some variable names have more than 6 characters, such
!     as `counter', `newalp', etc.
!
!     NOTE: For Dataplot, variable names have been modified to be
!           six characters or less.
!
!     The authors treat the normal distribution as if it were a discrete
!     distribution.
!     In Fortran 77 it is necessary to give explicit dimensions to some
!     of the temporary arrays which are not passed as arguments.
!     Maximum values have been set for k and m (kmax and mmax) in the
!     parameter statement under `Local variables' below.
!
!     NOTE: For Dataplot, dimension in calling routine and pass
!           in to this routine.
!
      integer a, k, m, c, n(m), nobvs, icount, ifault
      real x(m), alpha(k), mean(k), sd(k), tol, logl
!cccc external putout
!
!     Local variables
!
      integer kmax, mmax, i, j
!cccc parameter (kmax = 20, mmax = 100)
      logical test
      real sumalp, part, oldlgl
      real zero, one, half
!
      real newalp(kmax)
      real newmea(kmax)
      real newsd(kmax)
      real dt(kmax)
      real nt(kmax)
      real vt(kmax)
!
      real g(mmax)
      real f(mmax, kmax)
!
      data zero /0.0/, one /1.0/, half /0.5/
!
      if (a .lt. 1 .or. a .gt. 4) then
        ifault = 1
        return
      else
        ifault = 0
      end if
                                                                                                                                  
      do 10 i = 1, m-1
        if (x(i) .gt. x(i+1)) then
          ifault = 5
          return
        end if
   10 continue
                                                                                                                                  
      if (nobvs .lt. 2 * m) then
        ifault = 6
        return
      end if
                                                                                                                                  
      do 20 i = 1, m
        if (n(i) .lt. 0) then
          ifault = 6
          return
        end if
        if (a .ne. 1) then
          if (x(i) .lt. zero) then
            ifault = 7
            return
          end if
        end if
   20 continue
                                                                                                                                  
      oldlgl = zero
      icount = 0
!
!     Start of iterative cycle
!
   30 icount = icount + 1
      do 40 j = 1, k
        if (alpha(j) .gt. one .or. alpha(j) .lt. zero) then
          ifault = 2
          return
        end if
        if (mean(j) .ge. x(m) .or. mean(j) .le. x(1)) then
          ifault = 3
          return
        end if
        if (a .eq. 1) then
          if (sd(j) .le. zero) then
            ifault = 4
            return
          end if
        end if
   40 continue
                                                                                                                                  
      do 60 i = 1, k-1
        do 50 j = i+1, k
          if (mean(i) .eq. mean(j)) then
            if (a .eq. 1) then
              if (sd(i) .eq. sd(j)) then
                ifault = 9
                return
              end if
            else
              ifault = 8
              return
            end if
          end if
   50   continue
   60 continue
                                                                                                                                  
      logl = zero
      do 80 i = 1, m
        g(i) = zero
        do 70 j = 1, k
!
!     a = 1 denotes normal mixture
!     a = 2 denotes exponential mixture
!     a = 3 denotes Poisson mixture
!     a = 4 denotes binomial mixture
!
          if (a .eq. 1) then
            f(i,j) = exp(-half*((x(i) - mean(j))/sd(j))**2) / sd(j)
          else if (a .eq. 2) then
            f(i,j) = exp(-x(i)/mean(j)) / mean(j)
          else if (a .eq. 3) then
            if (x(i) .eq. x(1)) then
              f(i,j) = exp(-mean(j)) * mean(j)**x(i)
            else
              f(i,j) = f(i-1,j) * mean(j)
            end if
          else
            if (x(i) .eq. x(1)) then
              f(i,j) = (one - mean(j) / x(m))**x(m) * (mean(j) /   &
                        (x(m) - mean(j)))**x(i)
            else
              f(i,j) = f(i-1,j) * (mean(j) / (x(m) - mean(j)))
            end if
          end if
          g(i) = g(i) + alpha(j) * f(i,j)
   70   continue
        logl = logl + n(i) * log(g(i))
   80 continue
!
!     Calculation of the probability densities of the sub-populations
!     which form the mixture, and the log-likelihood function.
!
      test = .false.
      sumalp = zero
      do 100 j = 1, k
        nt(j) = zero
        dt(j) = zero
        vt(j) = zero
        do 90 i = 1, m
          part = f(i,j) * n(i) / g(i)
          dt(j) = dt(j) + part
          nt(j) = nt(j) + part * x(i)
          if (a .eq. 1) vt(j) = vt(j) + part * (x(i) - mean(j))**2
   90   continue
!
!     Calculation of denominators and numerators of new estimates.
!
        newmea(j) = nt(j) / dt(j)
        if (j .ne. k) then
          newalp(j) = alpha(j) * dt(j) / nobvs
          sumalp = sumalp + newalp(j)
        else
          newalp(k) = one - sumalp
        end if
        if (a .eq. 1) newsd(j) = sqrt(vt(j) / dt(j))
!
!     Convergence test.
!
        if (abs(oldlgl - logl) .gt. tol) test = .true.
        oldlgl = logl
        alpha(j) = newalp(j)
        mean(j) = newmea(j)
        if (a .eq. 1) sd(j) = newsd(j)
  100 continue
!
      if (c .gt. 0) then
        if ((icount/c)*c .eq. icount) then
!cccc     call putout(k, alpha, mean, sd, logl)
        end if
      end if
                                                                                                                                  
      if (test) go to 30
      return
      end
      SUBROUTINE MLEGEV(X, N, PARA, VCOV, MONIT, IFAULT)
                                                                                                                                  
!        ALGORITHM AS215   APPL. STATIST. (1985) VOL. 34, NO. 3
!        Modifications in AS R76 (1989) have been incorporated.
!
!        MAXIMUM-LIKELIHOOD ESTIMATION OF GENERALIZED EXTREME-VALUE
!        DISTRIBUTION
!
      DOUBLE PRECISION PARA(3), VCOV(6), X(N)
      DOUBLE PRECISION A, ACCA, ACCG, ACCU, AI, AIGI, AN, D, DA, DAA,   &
        DAG, DELA, DELG, DELU, DG, DGG, DU, DUA, DUG, DUU, E, F, FOLD,   &
        G, GAI, GG, GI, GIPQ, GNORM, H, HALF, HE, HH, ONE, P, PA, PQ,   &
        PQG, PU, Q, QA, QU, R, RA, RATIO, RG, RU, SE, SH, SHE, SHH,   &
        SHHE, SMALL, SRF, STEPA, STEPG, STEPU, SY, SYE, SYHE, SYYE,   &
        TEMP1, TEMP2, U, VLNEG, XMAX, XMIN, Y, YE, Z, ZERO
      CHARACTER*8 ACTI1, ACTI2, ACTI3, ACTI4, ACTI5, ACTI6, ACTI7,   &
        ACTI8, ACTI9
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA ACTI1/'  NEWTON'/, ACTI2/'  ST.ASC'/, ACTI3/'  RESETK'/,   &
        ACTI4/'  SR.INF'/, ACTI5/'  SR.LIK'/, ACTI6/'  MAX.SR'/,   &
        ACTI7/'  MAX.EV'/, ACTI8/'  MAX.IT'/, ACTI9/'  CONVGD'/
      DATA ZERO /0.0D0/, HALF /0.5D0/, ONE/1.0D0/
!
!        ADDU,ACCA,ACCG ARE ACCURACY CRITERIA FOR TESTING CONVERGENCE
!        STEPU,STEPA,STEPG ARE MAXIMUM STEPLENGTHS FOR ITERATIONS
!        ACCU,ACCA,STEPU,STEPA ARE SCALED BY CURRENT VALUE OF A WHEN
!        USED IN PROGRAM
!
!CCCC DATA ACCU, ACCA, ACCG /3 * 1.0D-5/, STEPU, STEPA, STEPG /
      DATA ACCU /0.00001D0/
      DATA ACCA /0.00001D0/
      DATA ACCG /0.00001D0/
      DATA STEPU /0.5D0/
      DATA STEPA /0.25D0/
!CCCC DATA STEPG /0.01D0/
      DATA STEPG /0.2D0/
!
!        MAXIT IS MAX. NO. OF ITERATIONS
!        MAXEV IS MAX. NO. OF EVALUATIONS OF LIKELIHOOD FUNCTION
!        SRF IS STEPLENGTH REDUCTION FACTOR
!        MAXSR IS MAX. NO. OF STEPLENGTH REDUCTIONS PERMITTED PER
!        ITERATION
!
!CCCC DATA MAXIT /30/, MAXEV /50/, SRF /0.25D0/, MAXSR /30/
      DATA MAXIT /300/, MAXEV /500/, SRF /0.25D0/, MAXSR /300/
!
!        SMALL IS A SMALL NUMBER, USED TO ADJUST THE SHAPE PARAMETER TO
!        AVOID AN EXACT ZERO VALUE OR BORDERLINE INFEASIBILITY
!        ALNEG IS A LARGE NEGATIVE NUMBER, USED TO INITIALIZE
!        LOG-LIKELIHOOD
!
      DATA SMALL /1.D-3/, VLNEG /-1.D37/
!
      Z=0.0D0
      Y=0.0D0
      DAG=0.0D0
      DAA=0.0D0
      DA=0.0D0
      DELA=0.0D0
      DELG=0.0D0
      DELU=0.0D0
      DG=0.0D0
      DGG=0.0D0
      DU=0.0D0
      DUA=0.0D0
      DUG=0.0D0
      DUU=0.0D0
      ITYPE=0
!
!        FIND MIN AND MAX DATA VALUE
!
      DO 10 I = 1, 6
        VCOV(I) = ZERO
  10  CONTINUE
      IFAULT = 1
      IF (N .LE. 2) GO TO  170
      XMIN = X(1)
      XMAX = X(1)
      DO 20 I = 2, N
        IF (X(I) .LT. XMIN) XMIN = X(I)
        IF (X(I) .GT. XMAX) XMAX = X(I)
   20 CONTINUE
!
!       INITIALIZATION
!       U IS LOCATION PARAMETER
!       A IS SCALE PARAMETER
!       G IS SHAPE PARAMETER
!
      IF (MONIT .GT. 0) THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE (ICOUT, 6000)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE (ICOUT, 6003)
        CALL DPWRST('XXX','BUG ')
      ENDIF
  999 FORMAT(1X)
 6000 FORMAT(' MAXIMUM-LIKELIHOOD ESTIMATION OF GENERALIZED EXTREME',   &
        1X, 'VALUE DISTRIBUTION')
 6003 FORMAT(' ITER EVAL', 8X, 'XI', 5X, 'ALPHA',   &
        9X, 'K  ACTION', 6X, 'LOG-L', 7X, 'GNORM')
!
      IFAULT = 0
      NITER = 0
      NEVAL =0
      FOLD = VLNEG
      U = PARA(1)
      A = PARA(2)
      G = PARA(3)
      IF (G .EQ. ZERO) G = SMALL
      IF (Z .LE. ZERO) A = ONE
      AN = DBLE(FLOAT(N))
!
!        CHECK WHETHER ALL DATA POINTS LIE WITHIN THE RANGE OF THE GEV
!        DISTRIBUTION WITH THE INITIAL PARAMETERS - IF NOT, ADJUST THE
!        SHAPE PARAMETER SO AS TO BRING ALL POINTS WITHIN RANGE
!
      IF (G .GT. ZERO) GO TO  30
      IF (XMIN .GE. U) GO TO  40
      Z = A / (XMIN - U)
      IF (MONIT .GT. 0) THEN
        WRITE (ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI3
        CALL DPWRST('XXX','BUG ')
      ENDIF
 6010 FORMAT(1X, I4, I5, 3F10.4, 1X, A, F11.3, 1PD12.2)
!
      G = Z + SMALL
      IF (G .GE. ZERO) G = HALF * Z
      GO TO  40
   30 IF (XMAX .LE. U) GO TO  40
      Z = A / (XMAX - U)
      IF (G .LT. Z) GO TO  40
      IF(MONIT .GT. 0) THEN
        WRITE (ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI3
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      G = Z - SMALL
      IF (G .LE. ZERO) G = HALF * Z
!
!        START OF MAIN LOOP
!
   40 DO 140 NITER = 1, MAXIT
!
      NSR = 0
   50 IF (NEVAL .GE. MAXEV) GO TO  150
      NEVAL = NEVAL + 1
      AI = ONE / A
      GI = ONE /G
      GAI = G * AI
      AIGI = AI * GI
      GG = ONE - G
!
!       ACCUMULATE SUMS OF QUANTITIES OCCURRING IN LIKELIHOOD
!       DERIVATIVES
!
!       IN PRESCOTT AND WALDEN'S NOTATION:
!       Z IS 1 - K * (X(I)-U) / A
!       Y IS THE REDUCED VARIATE - (1/K) * LOG(Z)
!       E IS EXP(-Y)
!       H IS EXP(K*Y)
!
      SY = ZERO
      SE = ZERO
      SYE = ZERO
      SYYE = ZERO
      SH = ZERO
      SHE = ZERO
      SYHE = ZERO
      SHHE = ZERO
      SHH = ZERO
      DO 60 I = 1, N
        Z = ONE -GAI * (X(I) - U)
        Y = -GI * LOG(Z)
        E = EXP(-Y)
        H = ONE / Z
        YE = Y * E
        HE = H * E
        HH = H * H
        SY = SY + Y
        SY = SY + E
        SYE = SYE + YE
        SYYE = SYYE + Y * YE
        SH = SH + H
        SHE = SHE + HE
        SYHE = SYHE + Y * HE
        SHHE = SHHE + HH * E
        SHH = SHH + HH
   60 CONTINUE
!
!       F IS CURRENT VALUE OF LIKELIHOOD FUNCTIONN
!
      F = -AN * LOG(A) - GG * SY - SE
      IF (F .GT. FOLD) GO TO  90
!
!       LIKELIHOOD HAS NOT INCREASED - REDUCE STEPLENGTH AND TRY AGAIN
!
      IF (MONIT .GT. 0) THEN
        WRITE(ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI5, F
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF (NSR .EQ. MAXSR) GO TO  80
   70 NSR = NSR + 1
      U = U - DELU
      A = A - DELA
      G = G - DELG
      DELU = SRF * DELU
      DELA = SRF * DELA
      DELG = SRF * DELG
      U = U + DELU
      A = A + DELA
      G = G + DELG
      IF (A .GT. G * (XMIN - U) .AND. A .GT. G * (XMAX - U) .AND. G .NE.   &
        ZERO) GO TO 50
      IF (MONIT .GT. 0) THEN
        WRITE (ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI4
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF (NSR .LT. MAXSR) GO TO  70
!
!        MAX. NO. OF STEPLENGTH REDUCTIONS REACHED
!        IF CURRENT ITERATION IS NEWTON-RAPHSON, TRY STEEPEST ASCENT
!        INSTEAD.  IF CURRENT ITERATION IS STEEPEST ASCENT, GIVE UP.
!
   80 U = U - DELU
      A = A - DELA
      G = G - DELG
      IF (MONIT .GT. 0) THEN
        WRITE(ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI6
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF (ITYPE .EQ. 1) GO TO  100
      IFAULT = 4
      GO TO  160
!
!        P,Q,R, ARE AS DEFINED IN FLOOD STUDIES REPORT
!
   90 FOLD = F
      P = AN - SE
      Q = SHE - GG * SH
      R = AN - SY + SYE
      PQ = P + Q
      GIPQ = GI * PQ
!
!        FIRST DERIVATIVES OF LOG-LIKELIHOOD
!
      DU = -AI * Q
      DA = -AIGI * PQ
      DG = -GI * (R - GIPQ)
      IF (MONIT .GT. 0) GNORM = SQRT(DU * DU + DA * DA + DG * DG)
!
!        DERIVATIVES OF P,Q,R
!
      PU = -AI * SHE
      PA = GI * PU + AIGI * SE
      QU = GG * AI * (SHHE + G * SHH)
      RU = AI * (SH - SHE + SYHE)
      RA = GI * RU - AIGI * (AN - SE + SYE)
      RG = GI * (SY - SYE + SYYE - A * RA)
      QA = AI * Q + GI * (PU + QU)
      PQG = GIPQ + A * (RA - GI * (PA + QA))
!
!         MINUS SECOND DERIVATIVE OF LOG-LIKELIHOOD (HESSIAN MATRIX)
!
      DUU = AI * QU
      DUA = AIGI * (PU + QU)
      DAA = -AIGI * (AI * PQ - PA - QA)
      DUG = GI * (RU - GI * (PU + QU))
      DAG = -AIGI * (GIPQ - PQG)
      DGG = GI * (RG - GI * (PQG + R - GIPQ - GIPQ))
!
!         INVERT HESSIAN MATRIX
!
      DO 95 KK = 1, 3
        IF (DUU .LE. ZERO) GO TO 100
        D = ONE / DUU
        TEMP1 = -DUA * D
        IF (KK .GT. 2) TEMP1 = -TEMP1
        TEMP2 = -DUG * D
        IF (KK .GT. 1) TEMP2 = -TEMP2
        DUU = DAA + TEMP1 * DUA
        DUA = DAG + TEMP1 * DUG
        DAA = DGG + TEMP2 * DUG
        DUG = TEMP1
        DAG = TEMP2
        DGG = D
   95 CONTINUE
!
!        CALCULATE STEPLENGTHS
!
      ITYPE = 1
      IF (MONIT .GT. 0) THEN
        WRITE(ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI1, F, GNORM
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      DELU = DUU * DU + DUA * DA + DUG * DG
      DELA = DUA * DU + DAA * DA + DAG * DG
      DELG = DUG * DU + DAG * DA + DGG * DG
      RATIO = DMAX1(ABS(DELU) / (STEPU * A), ABS(DELA) / (STEPA * A),   &
        ABS(DELG) / STEPG)
      IF (RATIO .LT. ONE) GO TO  110
      RATIO = ONE / RATIO
      DELU = DELU * RATIO
      DELA = DELA * RATIO
      DELG = DELG * RATIO
      GO TO  110
!
!        HESSIAN IS NOT POSITIVE DEFINITE - MAKE A LARGE STEP IN THE
!        DIRECTION OF STEEPEST ASCENT
!
  100 ITYPE = 2
      IF (MONIT .GT. 0) THEN
        WRITE(ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI2, F, GNORM
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      D = ABS(VLNEG)
      TEMP1 = D
      IF (DU .NE. ZERO) TEMP1 = STEPU * A / ABS(DU)
      TEMP2 = D
      IF (DA .NE. ZERO) TEMP2 = STEPA * A / ABS(DA)
      Z = D
      IF (DG .NE. ZERO) Z = STEPG / ABS(DG)
      RATIO = MIN(TEMP1, TEMP2, Z)
      DELU = RATIO * DU
      DELA = RATIO * DA
      DELG = RATIO * DG
!
!        ADJUST PARAMETERS
!
  110 U = U + DELU
      A = A + DELA
      G = G + DELG
!
!        TEST FOR FEASIBILITY
!
      IF (A .GT. F * (XMIN - U) .AND. A .GT. G * (XMAX - U) .AND. G .NE.   &
        ZERO) GO TO  130
      DO 120 NSR = 1, MAXSR
        IF (MONIT .GT. 0) THEN
          WRITE(ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI4
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
        U = U - DELU
        A = A - DELA
        G = G - DELG
        DELU = SRF * DELU
        DELA = SRF * DELA
        DELG = SRF * DELG
        U = U + DELU
        A = A + DELA
        G = G + DELG
        IF (A .GT. G * (XMIN - U) .AND. A .GT. G * (XMAX - Y) .AND.   &
           G .NE. ZERO) GO TO  140
  120 CONTINUE
      GO TO  80
!
!        TEST FOR CONVERGENCE
!
  130 IF (ABS(DELU) .GT. ACCU * A) GO TO  140
      IF (ABS(DELA) .GT. ACCA * A) GO TO  140
      IF (ABS(DELG) .GT. ACCG) GO TO  140
      IF (MONIT .GT. 0) THEN
        WRITE(ICOUT, 6010) NITER, NEVAL, U, A, G, ACTI9
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      VCOV(1) = DUU
      VCOV(2) = DUA
      VCOV(3) = DAA
      VCOV(4) = DUG
      VCOV(5) = DAG
      VCOV(6) = DGG
      GO TO  160
!
!        END OF MAIN LOOP
!
  140 CONTINUE
!
!        ITERATIONS NOT CONVERGED - SET FAULT FLAG
!
      IFAULT = 2
      IF (MONIT .GT. 0) THEN
        WRITE(ICOUT, 6010) MAXIT, NEVAL, U, A, G, ACTI8
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO  160
  150 IFAULT = 3
      IF (MONIT .GT. 0) THEN
        WRITE(ICOUT, 6010) NITER, MAXEV, U, A, G, ACTI7
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
!        ITERATION FINISHED -COPY RESULTS INTO ARRAY PARA
!
  160 IF (MONIT .GT. 0) THEN
        WRITE(ICOUT, 6020)
        CALL DPWRST('XXX','BUG ')
      ENDIF
 6020 FORMAT('0')
!
      PARA(1) = U
      PARA(2) = A
      PARA(3) = G
      RETURN
!
  170 CONTINUE
      DO 180 I = 1, 3
        PARA(I) = ZERO
  180 CONTINUE
      RETURN
!
      END SUBROUTINE MLEGEV
      SUBROUTINE MMXCDF(X,BETA,GAMMA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE MINIMAX DISTRIBUTION
!              WITH SHAPE PARAMETERS BETA AND GAMMA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!
!                 f(X;GAMMA,BETA) = BETA*GAMMA*X**(BETA-1)*
!                                   (1-X**BETA)**(GAMMA-1)
!                                   0 < X < 1; GAMMA, BETA > 0
!
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --BETA   = THE DOUBLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                     --GAMMA  = THE DOUBLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE MINIMAX DISTRIBUTION
!             WITH SHAPE PARAMETERS BETA AND GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION JANUARY--2008.1
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=200)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION MMXFUN
      EXTERNAL MMXFUN
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DGAMMA
      COMMON/MMXCOM/DBETA,DGAMMA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      CDF=0.0D0
      IF(X.LE.0.0)GO TO 9000
      IF(X.GE.1.0)THEN
        CDF=1.0D0
        GO TO 9000
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR--THE SECOND ARGUMENT TO MMXCDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
  102   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE THIRD ARGUMENT TO MMXCDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      INF=+1
      EPSABS=1.0D-7
      EPSREL=1.0D-7
      IER=0
      IKEY=3
      CDF=0.0D0
!
      DA=1.0D-7
      DX=DBLE(X)
      DBETA=BETA
      DGAMMA=GAMMA
!
      CALL DQAG(MMXFUN,DA,DX,EPSABS,EPSREL,IKEY,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
      CDF=REAL(DCDF)
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM MMXCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM MMXCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM MMXCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM MMXCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM MMXCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM MMXCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MMXCDF
      DOUBLE PRECISION FUNCTION MMXFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE MINIMAX DISTRIBUTION
!              WITH SHAPE PARAMETERS GAMMA AND BETA.
!
!              THE MINIMAX PROBABILITY DENSITY FUNCTION IS:
!
!                  f(X;GAMMA,BETA) = BETA*GAMMA*X**(BETA-1)*
!                                    (1-X**BETA)**(GAMMA-1)
!                                    0 < X < 1; GAMMA, BETA > 0
!
!              IDENTICAL TO MMXPDF,
!              BUT DEFINE AS FUNCTION TO BE USED FOR INTEGRATION
!              CODE CALLED BY MMXCDF.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--MMXFUN  = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE MINIMAX DISTRIBUTION
!             WITH SHAPE PARAMETERS GAMMA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--2008/1
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      COMMON/MMXCOM/BETA,GAMMA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      TERM1=DLOG(GAMMA) + DLOG(BETA)
      TERM2=(BETA-1.0D0)*DLOG(DX)
      TERM3=(GAMMA-1.0D0)*DLOG(1.0D0 - DX**BETA)
      TERM4=TERM1+TERM2+TERM3
      PDF=DEXP(TERM4)
!
      MMXFUN=PDF
!
      RETURN
      END FUNCTION MMXFUN
      SUBROUTINE MMXPDF(X,BETA,GAMMA,PDF)
!
!     NOTE--THE MINIMAX PROBABILITY DENSITY FUNCTION IS:
!
!           f(X;GAMMA,BETA) = BETA*GAMMA*X**(BETA-1)*
!                             (1-X**BETA)**(GAMMA-1)
!                             0 < X < 1; GAMMA, BETA > 0
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!     VERSION NUMBER--2008/1
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0D0
!
      IF(X.LE.0.0D0 .OR. X.GE.1.0D0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE FIRST ARGUMENT TO MMXPDF IS ',   &
               'OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)X
  102   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR--THE SECOND ARGUMENT TO MMXPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE THIRD ARGUMENT TO MMXPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=DLOG(GAMMA) + DLOG(BETA)
      TERM2=(BETA-1.0D0)*DLOG(X)
      TERM3=(GAMMA-1.0D0)*DLOG(1.0D0 - X**BETA)
      TERM4=TERM1+TERM2+TERM3
      PDF=DEXP(TERM4)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MMXPDF
      SUBROUTINE MNKDIS(X,Y,N,P,IWRITE,STATVA,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE MINKOWSKI DISTANCE BETWEEN THE
!              TWO SETS OF DATA IN THE INPUT VECTORS X AND Y.  THE
!              SAMPLE MINKOWSKI DISTANCE WILL BE A SINGLE PRECISION VALUE
!              CALCULATED AS:
!
!                 D = {SUM[i=1 to N][(ABS|(X(i) - X(k))|**P]}**(1/P)
!
!              P = 1 IS EQUIVALENT TO THE MANHATTAN DISTANCE AND
!              P = 2 IS EQUIVALENT TO EUCLIDEAN DISTANCE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS WHICH
!                                CONSTITUTE THE FIRST SET OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS WHICH
!                                CONSTITUTE THE SECOND SET OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTORS X AND Y.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE COSINE DISTANCE
!                                BETWEEN THE TWO SETS OF DATA IN THE
!                                INPUT VECTORS X AND Y.  THIS SINGLE
!                                PRECISION VALUE WILL BE BETWEEN 0.0
!                                AND 1.0 (INCLUSIVELY).
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE MINKOWSKI DISTANCE BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ABS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XXX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/08
!     ORIGINAL VERSION--AUGUST    2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MNKD'
      ISUBN2='IS  '
      IERROR='NO'
      STATVA=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'KDIS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MNKDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,P
   52   FORMAT('IBUGA3,ISUBRO,N,P = ',2(A4,2X),I8,F7.2)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN MINKOWSKI DISTANCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLES IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE MINKOWSKI DISTANCE.           **
!               ************************************************
!
      STATVA=0.0
      DO 200 I=1,N
        STATVA=STATVA + ABS(X(I) - Y(I))**P
  200 CONTINUE
      STATVA=STATVA**(1.0/P)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,P,STATVA
  811   FORMAT('THE MINKOWSKI DISTANCE OF THE ',I8,   &
                 ' OBSERVATIONS WITH P OF ',F7.1,' = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'KDIS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MNKDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,STATVA
 9012   FORMAT('IERROR,STATVA = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE MNKDIS
      SUBROUTINE MOM(G, D, A, FAULT)
!
!        ALGORITHM AS 99.3  APPL. STATIST. (1976) VOL.25, P.180
!
!        EVALUATES FIRST SIX MOMENTS OF A JOHNSON
!        SB DISTRIBUTION, USING GOODWIN METHOD
!
      REAL A(6), B(6), C(6), G, D, ZZ, VV, RTTWO, RRTPI, W, E, R,   &
        H, T, U, Y, X, V, F, Z, S, P, Q, AA, AB, EXPA, EXPB,   &
        ZERO, QUART, HALF, P75, ONE, TWO, THREE, ZABS, ZEXP
      LOGICAL L, FAULT
!
      DATA ZZ, VV, LIMIT /1.0E-5, 1.0E-8, 500/
!
!        RTTWO IS SQRT(2.0)
!        RRTPI IS RECIPROCAL OF SQRT(PI)
!        EXPA IS A VALUE SUCH THAT EXP(EXPA) DOES NOT QUITE
!          CAUSE OVERFLOW
!        EXPB IS A VALUE SUCH THAT 1.0 + EXP(-EXPB) MAY BE
!          TAKEN TO BE 1.0
!
      DATA     RTTWO,        RRTPI, EXPA, EXPB   &
        /1.414213562, 0.5641895835, 80.0, 23.7/
      DATA ZERO, QUART, HALF,  P75, ONE, TWO, THREE   &
           /0.0,  0.25,  0.5, 0.75, 1.0, 2.0,   3.0/
!
      ZABS(X) = ABS(X)
      ZEXP(X) = EXP(X)
!
      S=0.0
      FAULT = .FALSE.
      DO 10 I = 1, 6
        C(I) = ZERO
   10 CONTINUE
      W = G / D
!
!        TRIAL VALUE OF H
!
      IF (W .GT. EXPA) GO TO  140
      E = ZEXP(W) + ONE
      R = RTTWO / D
      H = P75
      IF (D .LT. THREE) H = QUART * D
      K = 1
      GO TO  40
!
!        START OF OUTER LOOP
!
   20 K = K + 1
      IF (K .GT. LIMIT) GO TO  140
      DO 30 I = 1, 6
        C(I) = A(I)
   30 CONTINUE
!
!        NO CONVERGENCE YET - TRY SMALLER H
!
      H = HALF * H
   40 T = W
      U = T
      Y = H * H
      X = TWO * Y
      A(1) = ONE / E
      DO 50 I = 2, 6
        A(I) = A(I - 1) / E
   50 CONTINUE
      V = Y
      F = R * H
      M = 0
!
!        START OF INNER LOOP
!        TO EVALUATE INFINITE SERIES
!
   60 M = M + 1
      IF (M .GT. LIMIT) GO TO  140
      DO 70 I = 1, 6
         B(I) = A(I)
   70 CONTINUE
      U = U - F
      Z = ONE
      IF (U .GT. -EXPB) Z = ZEXP(U) + Z
      T = T + F
      L = T .GT. EXPB
      IF (.NOT. L) S = ZEXP(T) + ONE
      P = ZEXP(-V)
      Q = P
      DO 90 I = 1, 6
      AA = A(I)
      P = P / Z
      AB = AA
      AA = AA + P
      IF (AA .EQ. AB) GO TO  100
      IF (L) GO TO  80
      Q = Q / S
      AB = AA
      AA = AA + Q
      L = AA .EQ. AB
   80 A(I) = AA
   90 CONTINUE
  100 Y = Y + X
      V = V + Y
      DO 110 I = 1, 6
         IF (A(I) .EQ. ZERO) GO TO  140
         IF (ZABS((A(I) - B(I)) / A(I)) .GT. VV) GO TO  60
  110 CONTINUE
!
!        END OF INNER LOOP
!
      V = RRTPI * H
      DO 120 I = 1, 6
         A(I) = V * A(I)
  120 CONTINUE
      DO 130 I = 1, 6
         IF (A(I) .EQ. ZERO) GO TO  140
         IF (ZABS((A(I) - C(I)) / A(I)) .GT. ZZ) GO TO  20
  130 CONTINUE
!
!        END OF OUTER LOOP
!
      RETURN
  140 FAULT =.TRUE.
      RETURN
      END SUBROUTINE MOM
      SUBROUTINE MOMENT(X, Y, N, R, W)
!
!        ALGORITHM AS 258.3  APPL.STATIST. (1990), VOL.39, NO.3
!
!        For k=0,...,n,  computes the integral from x to
!        infinity of the quantity
!
!                 R(k+1) = ( t - y )**k z(t) dt,
!            where
!                 z(t) = 1/sqrt(2 pi) exp( -t**2 / 2 ) .
!
      INTEGER N
      DOUBLE PRECISION X, Y, R( * ), W( * )
      INTEGER I, K
      DOUBLE PRECISION ALNORM
      DOUBLE PRECISION XMY, SQR2PI, FACT(19)
      EXTERNAL ALNORM
      DATA SQR2PI / 2.506628274631000502415765D0 /
      DATA FACT / 2 * 1.D0, 2.D0, 6.D0, 24.D0, 120.D0, 720.D0, 5040.D0,   &
           40320.D0, 362880.D0, 3628800.D0, 39916800.D0, 479001600.D0,   &
           6227020800.D0, 87178291200.D0, 1307674368000.D0,   &
           20922789888000.D0, 355687428096000.D0, 6402373705728000.D0 /
!
!        Compute first term of R.
!
      W(1) = EXP(-X * X / 2.0) / SQR2PI
      W(2) = ALNORM(-X, .FALSE.)
      R(1) = W(2)
      IF (N .GT. 0) THEN
         DO 10 I = 1, N
            W(I + 2) = (W(I) - X * W(I + 1)) / I
            R(I + 1) = W(I + 2) * FACT(I + 1)
   10    CONTINUE
!
!        If X=Y, then R is already computed.
!
         IF (X .NE. Y) THEN
!
!        Compute R.
!
            DO 30 K = 0, N
               R(K + 1) = W(2) / FACT(K + 1)
               XMY = X - Y
               DO 20 I = 1, K
                  R(K + 1) = R(K + 1) * XMY + W(I + 2) / FACT(K - I + 1)
   20          CONTINUE
               R(K + 1) = R(K + 1) * FACT(K + 1)
   30       CONTINUE
         END IF
      END IF
      RETURN
      END SUBROUTINE MOMENT
      SUBROUTINE MOVSTA(Y1,Y2,Y3,N,NUMV,ICASS7,ISTARA,MAXNXT,   &
                        ISEED,IQUAME,IQUASE,PSTAMV,   &
                        IMOVEP,IMOVDI,IFILT,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        YOUT,NOUT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--COMPUTE A "MOVING" STATISTIC.  ALTHOUGH THIS IS TYPICALLY
!              USED FOR A LOCATION STATISTIC, IN CAN BE USED FOR ANY
!              SUPPORTED STATISTIC.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/10
!     ORIGINAL VERSION--OCTOBER     2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*4 ICASC2
      CHARACTER*4 ICASS7
      CHARACTER*4 ISTARA
      CHARACTER*4 IQUAME
      CHARACTER*4 IQUASE
      CHARACTER*4 IMOVDI
      CHARACTER*4 IMOVEP
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION YOUT(*)
!
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MOVS'
      ISUBN2='TA  '
      IBELOW=0
      IABOVE=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'VSTA')THEN
        WRITE(ICOUT,70)
   70   FORMAT('AT THE BEGINNING OF MOVSTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)ICASCT,ICASC2,ICASS7,IMOVDI,IMOVEP
   71   FORMAT('ICASCT,ICASC2,ICASS7,IMOVDI,IMOVEP = ',   &
               4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)IQUAME,IQUASE,PSTAMV,N,IFILT
   72   FORMAT('IQUAME,IQUASE,PSTAMV,N,IFILT = ',2(A4,2X),G15.7,2I8)
        CALL DPWRST('XXX','BUG ')
        DO 75 I=1,N
          WRITE(ICOUT,73)I,Y1(I),Y2(I),Y3(I)
   73     FORMAT('I,Y1(I),Y2(I),Y3(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
      ENDIF
!
      IF(IFILT.LT.1)THEN
        IFILT=3
      ENDIF
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.IFILT)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN MOVING <STAT> COMMAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN THE ',   &
               'FILTER WIDTH.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,36)IFILT
   36   FORMAT('      THE FILTER WIDTH           = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************************
!               **  STEP 1--                                        **
!               **  CASE 1: DIRECTION = CENTER                      **
!               ******************************************************
!
      NOUT=0
!
      IF(IMOVEP.EQ.'SYMM')THEN
        IF(IMOVDI.EQ.'LEFT')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
  111     FORMAT('      SYMMETRIC END POINT OPTION NOT SUPPORTED ',   &
                 '"LEFT" DIRECTION.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IMOVDI.EQ.'RIGH')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,121)
  121     FORMAT('      SYMMETRIC END POINT OPTION NOT SUPPORTED ',   &
                 '"RIGHT" DIRECTION.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      IF(IMOVDI.EQ.'CENT')THEN
        IBELOW=IFILT/2
        IABOVE=IFILT/2
      ELSEIF(IMOVDI.EQ.'LEFT')THEN
        IBELOW=0
        IABOVE=IFILT-1
      ELSEIF(IMOVDI.EQ.'RIGH')THEN
        IBELOW=IFILT-1
        IABOVE=0
      ENDIF
!
      IF(IMOVEP.EQ.'SKIP')THEN
        DO 1010 I=1,N
          NSTRT=I-IBELOW
          IF(NSTRT.LT.1)GO TO 1010
          NSTOP=I+IABOVE
          IF(NSTOP.GT.N)GO TO 1010
          NTEMP=NSTOP-NSTRT+1
          CALL CMPSTA(Y1(NSTRT),Y2(NSTRT),Y3(NSTRT),TEMP1,TEMP2,TEMP3,   &
                      TEMP4,TEMP5,   &
                      MAXNXT,NTEMP,NTEMP,NTEMP,NUMV,ICASS7,ISTARA,   &
                      ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                      DTEMP1,DTEMP2,DTEMP3,   &
                      STAT,   &
                      ISUBRO,IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          NOUT=NOUT+1
          YOUT(NOUT)=STAT
 1010   CONTINUE
      ELSEIF(IMOVEP.EQ.'SYMM')THEN
        DO 1020 I=1,N
          NSTRT=I-IBELOW
          IF(NSTRT.LT.1)NSTRT=1
          IBELOT=I-NSTRT
          NSTOP=I+IABOVE
          IF(NSTOP.GT.N)NSTOP=N
          IABOVT=NSTOP-I
          ITEMP=MIN(IABOVT,IBELOT)
          NSTRT=I-ITEMP
          NSTOP=I+ITEMP
          NTEMP=NSTOP-NSTRT+1
          CALL CMPSTA(Y1(NSTRT),Y2(NSTRT),Y3(NSTRT),TEMP1,TEMP2,TEMP3,   &
                      TEMP4,TEMP5,   &
                      MAXNXT,NTEMP,NTEMP,NTEMP,NUMV,ICASS7,ISTARA,   &
                      ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                      DTEMP1,DTEMP2,DTEMP3,   &
                      STAT,   &
                      ISUBRO,IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          NOUT=NOUT+1
          YOUT(NOUT)=STAT
 1020   CONTINUE
      ELSEIF(IMOVEP.EQ.'PART')THEN
        DO 1030 I=1,N
          NSTRT=I-IBELOW
          IF(NSTRT.LT.1)NSTRT=1
          NSTOP=I+IABOVE
          IF(NSTOP.GT.N)NSTOP=N
          NTEMP=NSTOP-NSTRT+1
          CALL CMPSTA(Y1(NSTRT),Y2(NSTRT),Y3(NSTRT),TEMP1,TEMP2,TEMP3,   &
                      TEMP4,TEMP5,   &
                      MAXNXT,NTEMP,NTEMP,NTEMP,NUMV,ICASS7,ISTARA,   &
                      ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                      DTEMP1,DTEMP2,DTEMP3,   &
                      STAT,   &
                      ISUBRO,IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          NOUT=NOUT+1
          YOUT(NOUT)=STAT
 1030   CONTINUE
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'VSTA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MOVSTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NOUT
 9013   FORMAT('NOUT = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(NOUT.GE.1)THEN
          DO 9021 I=1,NOUT
            WRITE(ICOUT,9023)I,YOUT(I)
 9023       FORMAT('I,YOUT(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9021     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE MOVSTA
      double precision function mpf(x, t, nlab, y)
      implicit double precision (a-h, o-z)
      dimension x(*), t(*)
!
!     -- Calculate the mean estimate
      wsum = 0.0d0
      xhat = 0.0d0
      do 10 i=1, nlab
         wght = 1.0d0/(t(i)+y)
         wsum = wsum +wght
         xhat = xhat +x(i)*wght
 10   continue
      xhat = xhat /wsum
!
!    -- Evaluate the function
      mpf = 0.0d0
      do 20 i=1, nlab
         mpf = mpf + 1.0d0/(t(i) +y) *(x(i) -xhat)**2
 20   continue
      return
      end
      double precision function mpfder(x, t, nlab, y, wsum)
      implicit double precision (a-h, o-z)
      dimension x(*), t(*)
!
!     -- Calculate the mean estimate
      wsum = 0.0d0
      xhat = 0.0d0
      do 10 i=1, nlab
         wght = 1.0d0/(t(i)+y)
         wsum = wsum + wght
         xhat = xhat + x(i)*wght
 10   continue
      xhat = xhat /wsum
!
!    -- Evaluate the function
      mpfder = 0.0d0
      do 20 i=1, nlab
         mpfder = mpfder + 1.0d0/(t(i) +y)**2 *(x(i) -xhat)**2
 20   continue
      return
      end
      subroutine mpinit (dat, n, ieq2, nlab, x, t)
!
!  Initialization for Mandel-Paule estimation
!
!  Routine supplied by Mark Vangel: 10/2000
!
!  2/2005: Modification by Alan Heckert.  If a lab has a single
!          observation, the within lab variance is zero and
!          code below blows up.  As an alternative, check for
!          this case and set the resulting variance to the
!          maximum variance of all the labs.
!
      implicit double precision (a-h, o-z)
      real dat
      dimension dat(*), n(*), x(*), t(*)
!
!     -- Calculate batch means and variances of these means
      ntot   = 0
      timax=0.0
      do 10 i=1, nlab
        x(i) = 0.0d0
        if (ieq2 .eq. 1) then
           ntot  = ntot +n(1)
           ni    = n(1)
           n(i)  = ni
        else
           ntot  = ntot +n(i)
           ni = n(i)
        end if
        do 20 j=ntot-ni+1, ntot
          x(i) = x(i) + dat(j)
 20     continue
        x(i)   = x(i)/dble(ni)
        t(i)   = 0.0d0
        do 30 j=ntot-ni+1, ntot
           t (i) = t(i) +(dat(j)-x(i))**2
 30     continue
        if(ni .eq. 1)then
          t(i) = -1.0
        else
          t(i) = t(i) /dble(((ni-1)*ni))
          if(t(i).gt.timax)timax=t(i)
        endif
 10   continue
!
      do 40 i=1, nlab
        if (t(i) .le. 0.0) t(i)=timax
 40   continue
!
      Return
      end
      subroutine mpintl(nlab,n,x,t,xm,s2b,w,maxit,dlik,ibuga3,ierror)
!
!  --Mandel-Paule Interlab subroutine
!  --This subroutine is driver routine for generating maximum
!  --likelihood estimates
!  --Code provided by Mark Vangel (10/2000)
!  --Adapted to Dataplot by Alan Heckert
!
      implicit double precision (a-h, o-z)
      double precision mplglk, mpwmea, mps2bf
      dimension n(*), t(*), w(*), x(*)
      character*4 ibuga3
      character*4 ierror
      dimension q(3), xl(3)
!
      common /mpcom/ t0, t1
!
!-----COMMON---------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      do 5 i=1,3
        q(i)=0.0d0
        xl(i)=0.0d0
  5   continue
!cccc tol    = 1.d-12
      tol    = 1.d-18
      iter   = 0
      dlik   = mplglk (nlab, n, x, t, xm, s2b, w, ibuga3)
 10   continue
!
      if(ibuga3.eq.'ON')then
         WRITE(ICOUT,999)
  999    FORMAT(1X)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1001)ITER,S2B,XM,DLIK
 1001    FORMAT('ITER,S2B,XM,DLIK=',I8,3G15.7)
         CALL DPWRST('XXX','BUG ')
      endif
!
      dlt    = 0.0d0
      iter   = iter +1
      mltwgt = 0
      do 20 i=1, nlab
        a    = s2b  /(x(i) - xm)**2
        b    = t(i) /(x(i) - xm)**2
        nitemp=abs(n(i))
        ss   = dble(nitemp*(nitemp-1))*t(i)
        if (a .eq. 0.0d0) then
          w(i)  = dble(nitemp)/((x(i)-xm)**2 +dble(nitemp-1)*t(i))
          q(1)  = w(i)
          nwght = 1
        else
          call mpweig(a, b, dble(nitemp-1), nwght, q, ibuga3, ierror)
          if(ierror.eq.'YES')return
        end if
        if (nwght .gt. 1) mltwgt = 1
        if (nwght .eq. 1) then
          wtmp = q(1)
          jwgt = 1
        else
          do 15 j=1,3
            xl(j) = dble(nitemp)*log(q(j)) -   &
            q(j)*(1.0d0/a +dble(nitemp-1)*t(i)/(1.0d0-q(j))) -   &
            dble(nitemp-1)*log(1.0d0-q(j))
 15       continue
          if (xl(2) .gt. xl(1) .and. xl(2) .gt. xl(3)) then
            wtmp = q(2)
            jwgt = 2
          else if (xl(3) .gt. xl(1) .and. xl(3) .gt. xl(2)) then
            wtmp = q(3)
            jwgt = 3
          else
            wtmp = q(1)
            jwgt = 1
          end if
        end if
        dtmp = abs(wtmp - w(i))
        if (dtmp .gt. dlt) dlt = dtmp
        w(i) = wtmp
        if(ibuga3.eq.'ON')then
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1011)XM,S2B,I,NWGHT,JWGT
 1011     FORMAT('XM,S2B,I,NWGHT,JWGT=',2G15.7,3I8)
          CALL DPWRST('XXX','BUG ')
        endif
 20   continue
!
      dlik  = mplglk (nlab, n, x, t, xm, s2b, w, ibuga3)
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1021)iter,t0 +(t1-t0)*xm,(t1-t0)**2*s2b, dlik
 1021   FORMAT('ITER,T0+(T1-T0)*XM,(T1-T0**2*S2B,DLIK=',I8,3G16.8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      s2b   = mps2bf(x, w, xm, nlab)
      xm    = mpwmea(x, w, nlab, ibuga3)
      if (dlt .gt. tol .and. iter .lt. maxit) go to 10
      if (iter .gt. maxit) then
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1041)
 1041   FORMAT('***** ERROR FROM MPINTL:: CONVERGENCE FAILED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
      return
      end
      double precision function mplglk   &
          (nlab, n, x, t, xm, s2b, w, ibuga3)
!
!  --log-likelihood function used by CONSESUS MEANS code
!  --provided by Mark Vangel (10/2000)
!
      implicit double precision (a-h, o-z)
      character*4 ibuga3
      dimension n(*), x(*), t(*), w(*)
!
!-----COMMON---------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      mplglk = 0.0d0
      if (s2b .gt. 0.0d0) then
        do 10 i=1, nlab
          nitemp=abs(n(i))
          prtlik = dble(nitemp)*log(w(i)/s2b) -   &
                   (w(i)/s2b)*((x(i)-xm)**2 +   &
                   dble(nitemp-1)*t(i)/(1.0d0-w(i))) -   &
                   dble(nitemp-1)*log(1.0d0 - w(i))
          mplglk = mplglk + prtlik
          IF(IBUGA3.EQ.'ON')THEN
            WRITE(ICOUT,999)
  999       FORMAT(1X)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,101)PRTLIK
 101   FORMAT('***** FROM MPLGLK (s2b > 0): PRTLIK = ',G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
 10     continue
      else
        do 20 i=1, nlab
          nitemp=abs(n(i))
          prtlik = -w(i) *((x(i)-xm)**2 + dble(nitemp-1)*t(i)) +   &
                   dble(nitemp)*log(w(i))
          mplglk = mplglk + prtlik
          IF(IBUGA3.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,103)PRTLIK
 103   FORMAT('***** FROM MPLGLK (s2b <= 0): PRTLIK = ',G15.7)
          ENDIF
 20     continue
      end if
!
      return
      end
      subroutine mppoly(x, fx)
!
! --Compute cubic polynomial function for root finder in
! --Consensus Means code.
! --Code provided by Mark Vangel
!
      implicit double precision (a-h, o-z)
      double precision c(0:3)
      common /mpfnc/ c
!
      fx = c(0)+x*(c(1)+x*(c(2)+x*c(3)))
!
      return
      end
      subroutine mpprep (nlab, x, t, t0, t1)
!
!     Mark Vangel, NIST, Nov 1995
!
!     Added to Dataplot: 10/2000
!
!     Scale the sufficient statistics so that the
!     means are in [0,1].
!
      implicit double precision (a-h, o-z)
      dimension x(*), t(*)
!
      t0 = x(1)
      t1 = x(1)
      do 10 j=1, nlab
         if (x(j) .lt. t0) t0 = x(j)
         if (x(j) .gt. t1) t1 = x(j)
 10   continue
      do 20 j=1, nlab
         x(j) = (x(j)-t0)/(t1-t0)
         t(j) = t(j)/(t1-t0)**2
 20   continue
      return
      end
      subroutine mproot   &
       (x, t, nlab, tol, rhs, root, maxit, niter, ier)
      implicit double precision (a-h, o-z)
      double precision mpf, mpfder
      dimension x(*), t(*)
!
!-----COMMON---------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
!
!     -- If root is negative or nonexistent, set it to
!        zero.
!
      y  = 0.0d0
      f0 = mpf(x, t, nlab, y)
      if (f0 .lt. rhs) then
         root = 0.0d0
         ier  = 1
         return
      end if
!
!    -- Loop until convergence
      niter = 0
 30   continue
         niter = niter +1
         fd = mpfder(x, t, nlab, y, wsum)
         ynew = y +(mpf(x, t, nlab, y)-rhs)/fd
         if (abs (ynew-y) .le. tol .and.   &
                  niter   .le. maxit) then
            root = ynew
            ier  = 0
            return
         else if (niter .gt. maxit) then
            root = ynew
            WRITE(ICOUT,999)
  999       FORMAT(1X)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1001)
 1001       FORMAT('***** ERROR: FAILURE IN MPROOT: YNEW = ',G15.7)
            CALL DPWRST('XXX','BUG ')
            DO 1010 I=1,NLAB
            WRITE(ICOUT,1011)
 1011       FORMAT('      I,T(I) = ',I8,G15.7)
 1010       CONTINUE
            ier  = 2
            return
         else
           y = ynew
           go to 30
         end if
         return
      end
      double precision function mps2bf (x, w, xbar, nlab)
!
!  --Code for consensus mean
!  --Provided by Mark Vangel
!
      implicit double precision (a-h, o-z)
      dimension x(*), w(*)
      mps2bf = 0.0d0
      wsum   = 0.0d0
      do 10 i=1, nlab
         mps2bf = mps2bf + w(i)**2 *(x(i) -xbar)**2
         wsum   = wsum + w(i)
 10   continue
      if (wsum .ne. 0.0d0) then
         mps2bf = mps2bf /wsum
      else
         mps2bf = 0.0d0
      end if
      return
      end
      subroutine mpsub (nlab, n, x, t, xmp, s2bmp, imanpa, ibuga3)
!
!  Initialization for Mandel-Paule estimation
!
!  Routine supplied by Mark Vangel: 10/2000
!
      implicit double precision (a-h, o-z)
!cccc double precision mprhs
      double precision mpxbar
      dimension x(*), n(*), t(*)
      character*4 imanpa
      character*4 ibuga3
!
!-----COMMON---------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      maxit = 1000
!cccc tol   = 1.d-7
      tol   = 1.d-15
!
!    -- Initialize with Mandel-Paule
      s2b = 0.d0
!CCCC USE NLAB FOR MANDEL-PAULE, NLAB-1 FOR MODIFIED MANDEL-PAULE
      if(imanpa.eq.'MODI')then
        xrhs=dble(nlab)
      else
        xrhs=dble(nlab-1)
      endif
!CCCC xrhs = mprhs (x, t, t, n, nlab)
      call mproot   &
       (x, t, nlab, tol, xrhs, s2b, maxit, niter, ier)
      xmp  = mpxbar   (x, t, s2b, nlab)
      s2bmp  = s2b
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1001)
 1001   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1011)
 1011   FORMAT('FROM ROUTINE MPSUB')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1021)XRHS,XMP,S2BMP,N(1)
 1021   FORMAT('RHS,XMP,S2BMP,N(1) = ',3G15.7,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      return
      end
      double precision function mpwmea (x, w, nlab, ibuga3)
!
! --Compute a weighted mean for the consensus means code
! --provided by Mark Vangel.
!
      implicit double precision (a-h, o-z)
      dimension w(*), x(*)
      character*4 ibuga3
!
!-----COMMON---------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      dtemp = 0.0d0
      wsum  = 0.0d0
      do 10 i=1, nlab
         dtemp = dtemp + x(i)*w(i)
         wsum  = wsum  + w(i)
 10   continue
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        DO 1010 I=1,NLAB
          WRITE(ICOUT,1001)I,X(I),W(I)
 1001     FORMAT('***** MPWMEA: I,X(I),W(I)=',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 1010   CONTINUE
      ENDIF
      mpwmea = dtemp/wsum
      return
      end
      subroutine mpweig (a, b, gnu, nwght, w, ibuga3, ierror)
      implicit double precision (a-h, o-z)
!
!     Concensus Means Code
!     Mark Vangel, NIST, Oct. 1995
!
!         Find weight by solving cubic equation.
!
      character*4 ibuga3
      character*4 ierror
      real dwarf, precis
      double precision w(*)
      double precision c(0:3)
      common /mpfnc/ c
      external mppoly
!
!-----COMMON---------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
!
      IERROR='NO'
      c(3)   = 1.0d0
      c(2)   = 1.0d0 - a
      c(1)   = gnu *(a+b)
      c(0)   = gnu *b
      precis = 1.e-14
      dwarf  = 1.e-14
      x0     = -1.0d0
      x1     =  0.0d0
      ndeg   = 11
      zero=0.0d0
!
      call mpzero(mppoly, x0, x1, ndeg, precis, dwarf, zero, ier)
      nwght  = 1
      w(1)   = zero + 1.0d0
      disc   = (1.0d0-a+zero)**2 +4.0d0*b*gnu/zero
      if (disc .gt. 0.0d0) then
            z1   = zero
            disc = sqrt(disc)
            z2   = (-(1.0d0-a+zero) +disc)/2.0d0
            z3   = (-(1.0d0-a+zero) -disc)/2.0d0
            if ((-1.0d0 .le. z2 .and. z2 .le. 0.0d0) .or.   &
               ((-1.0d0 .le. z3 .and. z3 .le. 0.0d0))) then
                nwght = 3
                w(2) = z2 +1.0d0
                w(3) = z3 +1.0d0
            end if
      end if
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1001)W(1),W(2),W(3)
 1001   FORMAT('FROM MPWEIG: W = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      if (ier .ne. 0) then
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1011)IER
 1011   FORMAT('FROM MPWEIG: IER = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1021)A,B,GNU
 1021   FORMAT('FROM MPWEIG: A,B,GNU = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1026)W(1),W(2),W(3)
 1026   FORMAT('FROM MPWEIG: W = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
      end if
      if (nwght .eq. 3) then
!CCCC   write(ICOUT,1031) W(1),W(2),W(3)
!1031   FORMAT('FROM MPWEIG (NWGHT=3): W = ',3G15.7)
!CCCC   CALL DPWRST('XXX','BUG ')
      endif
      return
      end
      double precision function mpxbar (x, t, s2b, nlab)
      implicit double precision (a-h, o-z)
      dimension x(*), t(*)
!
      mpxbar = 0.0d0
      wsum = 0.0d0
      do 10 i=1, nlab
         wi   = 1.0d0/(s2b+t(i))
         wsum = wsum + wi
         mpxbar = mpxbar + x(i)*wi
 10   continue
      mpxbar = mpxbar /wsum
!
      return
      end
      SUBROUTINE MPZERO(EVF,A,B,NDEG,PRECIS,DWARF,ZERO,IER)
!-----------------------------------------------------------------------
!
!   PURPOSE              - FIND A ZERO OF A FUNCTION WHICH CHANGES
!                            SIGN IN A GIVEN INTERVAL BY LARKIN'S
!                            METHOD OF RATIONAL INTERPOLATION.
!
!   PRECISION            - DOUBLE.
!
!   ARGUMENTS    EVF     - AN EXTERNAL SUBROUTINE EVF(X,FX) WITH
!                            DOUBLE PRECISION ARBUMENTS X,FX WHICH
!                            COMPUTES F(X) FOR ANY X IN THE INTERVAL
!                            (A,B) INCLUSIVE. (INPUT)
!                            EVF MUST APPEAR IN AN EXTERNAL STATEMENT
!                            IN THE CALLING PROGRAM.
!                A,B     - DOUBLE PRECISION BOUNDARY POINTS.
!                            (INPUT/OUTPUT)
!                          ON INPUT, F(A) AND F(B) SHOULD HAVE OPPOSITE
!                            SIGNS UNLESS ONE EQUALS 0.
!                          ON OUTPUT, BOTH A AND B ARE ALTERED BUT F(A)
!                            AND F(B) REMAIN OPPOSITELY SIGNED UNLESS
!                            ONE EQUALS 0. IF NEITHER F(A) NOR F(B)
!                            EQUALS 0, THEN
!                              ABS(A-B) .LE. 4*PRECIS*ABS(A)+2*DWARF.
!                NDEG    - MAXIMUM TOTAL DEGREE OF RATIONAL INTER-
!                            POLATION. (INPUT)
!                            IF NDEG.LT.2 THEN 2 IS USED IN PLACE OF
!                            NDEG. IF NDEG.GT.11 THEN 11 IS USED IN
!                            PLACE OF NDEG.
!                PRECIS  - REAL RELATIVE CONVERGENCE PARAMETER. (INPUT)
!                            PRECIS SHOULD BE AT LEAST MACHINE PRE-
!                            CISION, I.E. 1+PRECIS.GT.1 IN DOUBLE
!                            PRECISION ARITHMETIC.
!                DWARF   - REAL ABSOLUTE CONVERGENCE PARAMETER. (INPUT)
!                            DWARF SHOULD BE AT LEAST AS LARGE AS THE
!                            SMALLEST POSITIVE NORMALIZED REAL NUMBER
!                            REPRESENTABLE IN THE COMPUTER.
!                ZERO    - DOUBLE PRECISION APPROXIMATE ZERO OF F(X).
!                            (OUTPUT)
!                            ZERO EQUALS WHICHEVER OF OUTPUT A OR B HAS
!                            SMALLER F MAGNITUDE.
!                IER     - ERROR INDICATOR. (OUTPUT)
!                            NO ERROR: IER=0 .
!                            TERMINAL ERROR:
!                              IER=129 INDICATES THAT F HAS THE SAME
!                              SIGN ON INPUT A AND B.
!
!-----------------------------------------------------------------------
!
!                                 SPECIFICATIONS FOR ARGUMENTS.
!
      INTEGER NDEG,IER
      REAL PRECIS,DWARF
      DOUBLE PRECISION A,B,ZERO
!
!                                 SPECIFICATIONS FOR LOCAL VARIABLES.
!
      INTEGER MAXDEG,NN,N,NLAST,I,J
      REAL TOL,C,D,E,D0,D1
      DOUBLE PRECISION X(11),U(11),X0,F0,F1,F2,Z,FZ,H,HLAST,R,S,T
      DATA MAXDEG/11/
!
!     REMARK:  IN THIS SUBROUTINE THE MAXIMUM ALLOWABLE DEGREE OF
!                RATIONAL INTERPOLATION HAS BEEN ARBITRARILY SET AT 11.
!                (SEE DESCRIPTION OF NDEG.) TO INCREASE THE MAXIMUM
!                ALLOWABLE DEGREE TO M:
!                  1. DIMENSION X AND U AT M (RATHER THAN 11),
!                  2. INITIALIZE MAXDEG AT M (RATHER THAN 11),
!                IN THE ABOVE LINES OF CODE.
!
!                                 FIRST EXECUTABLE STATEMENT.
!
      X0 = A
      X(1) = B
      CALL EVF(A,F0)
      CALL EVF(B,F1)
      IF (F0.EQ.0. .OR. F1.EQ.0.) GO TO 120
      IF (F0.GT.0. .AND. F1.GT.0.) GO TO 140
      IF (F0.LT.0. .AND. F1.LT.0.) GO TO 140
      NN = NDEG
      N = NN
      IF (NN.LT.2) NN = 2
      IF (NN.GT.MAXDEG) NN = MAXDEG
      R = X(1) - X0
      E = 0.0
      D = 0.0
      C = 0.0
      F2 = F0
!
!                                 MAIN LOOP.
!
   10 CONTINUE
      TOL = 2.*PRECIS*DABS(X0) + DWARF
      IF (DABS(R).LE.2.*TOL) GO TO 120
      U(1) = R* (F0/ (F0-F1))
      IF (E.LT.TOL .OR. DABS(F0).GE.DABS(F2)) GO TO 60
!
!                                 INTERPOLATE.
!
      H = U(1)
      HLAST = H
      NLAST = 1
      S = R
      DO 30 I = 2,N
          S = S + U(I) - U(I-1)
          T = X(I) - X0 - S
          IF (T.EQ.0.) GO TO 40
          U(I) = H* (S/T)
          H = H + U(I)
          D1 = DABS(U(I))
          IF (I.EQ.2) GO TO 20
          IF (D1.GE.D0) GO TO 40
          T = H/R
          IF (T.LE.0. .OR. T.GE.1.) GO TO 40
   20     HLAST = H
          NLAST = I
          D0 = D1
   30 CONTINUE
   40 Z = X0 + HLAST
      D0 = DABS(HLAST)
      D1 = DABS(Z-X(1))
      C = E
      E = D
      D = AMIN1(D0,D1)
      IF (D.GE.0.5*C) GO TO 60
      IF (D.GE.TOL) GO TO 70
      IF (D0.LT.TOL) GO TO 50
      IF (R.LT.0.) TOL = -TOL
      Z = X(1) - TOL
      GO TO 70
                                                                                                                                  
   50 IF (R.LT.0.) TOL = -TOL
      Z = X0 + TOL
      GO TO 70
!
!                                 END INTERPOLATE.
!
   60 CONTINUE
!
!                                 BISECT.
!
      H = .5*R
      Z = X0 + H
      NLAST = 1
      D = DABS(H)
      E = D
!
!                                 END BISECT.
!
   70 CONTINUE
!
!                                 EVALUATE AND ORGANIZE.
!
      CALL EVF(Z,FZ)
      IF (FZ.NE.0.) GO TO 80
      X0 = Z
      F0 = FZ
      GO TO 120
                                                                                                                                  
   80 N = MIN0(NLAST+1,NN)
      J = N + 1
      DO 90 I = 2,N
          J = J - 1
          X(J) = X(J-1)
          U(J) = U(J-1)
   90 CONTINUE
      IF (FZ.GT.0. .AND. F1.GT.0.) GO TO 100
      IF (FZ.LT.0. .AND. F1.LT.0.) GO TO 100
      X(2) = X0
      F2 = F0
      U(2) = U(2) - R
      GO TO 110
                                                                                                                                  
  100 X(1) = X0
      F2 = F1
      F1 = F0
  110 CONTINUE
      X0 = Z
      F0 = FZ
      R = X(1) - X0
!
!                                 END EVALUATE AND ORGANIZE.
!
      GO TO 10
!
!                                 END MAIN LOOP.
!
  120 CONTINUE
!
!                                 RETURN WITHOUT ERROR.
!
      IER = 0
      A = X0
      B = X(1)
      IF (DABS(F1).LT.DABS(F0)) GO TO 130
      ZERO = A
      RETURN
                                                                                                                                  
  130 ZERO = B
      RETURN
                                                                                                                                  
  140 CONTINUE
!
!                                 RETURN WITH ERROR.
!
      IER = 129
      RETURN
      END SUBROUTINE MPZERO
      SUBROUTINE MSCORE(X,N,IWRITE,XSCORE,TEMP1,MAXNXT,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE MOOD SCORES
!              OF THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X, AND
!              PUTS THE RESULTING N SCORES INTO THE SINGLE PRECISION
!              VECTOR XSCORE.
!
!              THE MOOD SCORES ARE DEFINED AS
!
!                 M(X(i)) = (R(i) - (N+1)/2)**2
!
!              WITH R(i) DENOTING THE RANK OF THE i-TH OBSERVATION.
!              THE MOOD SCORE IS THE SQUARE OF THE DIFFERENCE BETWEEN
!              THE OBSERVED RANK AND THE AVERAGE RANK.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SCORED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XEOS   = THE SINGLE PRECISION VECTOR INTO WHICH
!                                THE SCORES FROM X WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XSCORE CONTAINING THE MOOD
!             SCORES IN THE SINGLE PRECISION VECTOR X.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANK
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE FIRST AND THIRD ARGUMENTS IN THE CALLING SEQUENCE MAY
!              BE IDENTICAL; THAT IS, AN 'IN PLACE' SCORING IS
!              PERMITTED.
!     REFERENCES--HIGGINS (2004), "INTRODUCTION TO MODERN NONPARAMETRIC
!                 STATISTICS", DUXBURY ADVANCED SERIES, P. 50.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023.06
!     ORIGINAL VERSION--JUNE      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XSCORE(*)
      DIMENSION TEMP1(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MSCO'
      ISUBN2='RE  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,IBUGA3,ISUBRO
   53   FORMAT('N,IBUGA3,ISUBRO = ',I8,2(2X,A4))
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN MOOD SCORES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('      THE NUMBER OF OBSERVATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  GENERATE THE MOOD   SCORES            **
!               ********************************************
!
        CALL RANK(X,N,IWRITE,XSCORE,TEMP1,MAXNXT,IBUGA3,IERROR)
        TERM1=(REAL(N)+1.0)/2.0
        DO 211 K=1,N
          XSCORE(K)=(XSCORE(K) - TERM1)**2
  211   CONTINUE
!
!
!               ******************************
!               **  STEP 4--                **
!               **  WRITE OUT A FEW LINES   **
!               **  OF SUMMARY INFORMATION  **
!               **  ABOUT THE CODING.       **
!               ******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IINDX=1
        WRITE(ICOUT,912)IINDX,XSCORE(IINDX)
  912   FORMAT('THE MOOD SCORE OF ROW ',I10,' = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IINDX=N
        WRITE(ICOUT,912)IINDX,XSCORE(IINDX)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,X(I),XSCORE(I)
 9016     FORMAT('I,X(I),XSCORE(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE MSCORE
        INTEGER FUNCTION MSTA1(X,MP)
!
!       ===================================================
!       Purpose: Determine the starting point for backward
!                recurrence such that the magnitude of
!                Jn(x) at that point is about 10^(-MP)
!       Input :  x     --- Argument of Jn(x)
!                MP    --- Value of magnitude
!       Output:  MSTA1 --- Starting point
!       ===================================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
        A0=DABS(X)
        N0=INT(1.1*A0)+1
        F0=ENVJ(N0,A0)-MP
        N1=N0+5
        F1=ENVJ(N1,A0)-MP
        DO 10 IT=1,20
           AN1=DBLE(N1)
           AN0=DBLE(N0)
           NN=INT(AN1-(AN1-AN0)/(1.0D0-F0/F1))
           F=ENVJ(NN,A0)-MP
           IF(ABS(NN-N1).LT.1) GO TO 20
           N0=N1
           F0=F1
           N1=NN
           F1=F
 10     CONTINUE
 20     MSTA1=NN
        RETURN
        END
      INTEGER FUNCTION MSTA2(X,N,MP)
!
!       ===================================================
!       Purpose: Determine the starting point for backward
!                recurrence such that all Jn(x) has MP
!                significant digits
!       Input :  x  --- Argument of Jn(x)
!                n  --- Order of Jn(x)
!                MP --- Significant digit
!       Output:  MSTA2 --- Starting point
!       ===================================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
        A0=DABS(X)
        HMP=0.5D0*MP
        EJN=ENVJ(N,A0)
        IF (EJN.LE.HMP) THEN
           OBJ=MP
           N0=INT(1.1*A0)
        ELSE
           OBJ=HMP+EJN
           N0=N
        ENDIF
        F0=ENVJ(N0,A0)-OBJ
        N1=N0+5
        F1=ENVJ(N1,A0)-OBJ
        DO 10 IT=1,20
           AN1=DBLE(N1)
           AN0=DBLE(N0)
           NN=INT(AN1-(AN1-AN0)/(1.0D0-F0/F1))
           F=ENVJ(NN,A0)-OBJ
           IF (ABS(NN-N1).LT.1) GO TO 20
           N0=N1
           F0=F1
           N1=NN
           F1=F
10      CONTINUE
20      MSTA2=NN+10
        RETURN
        END
      SUBROUTINE MULRAN(n,p,ncat,ix,iseed,ierror)
!**********************************************************************
!
!            SUBROUTINE GENMUL( N, P, NCAT, IX )
!     GENerate an observation from the MULtinomial distribution
!
!
!                              Arguments
!
!
!     N --> Number of events that will be classified into one of
!           the categories 1..NCAT
!                         INTEGER N
!
!     P --> Vector of probabilities.  P(i) is the probability that
!           an event will be classified into category i.  Thus, P(i)
!           must be [0,1]. Only the first NCAT-1 P(i) must be defined
!           since P(NCAT) is 1.0 minus the sum of the first
!           NCAT-1 P(i).
!                         REAL P(NCAT-1)
!
!     NCAT --> Number of categories.  Length of P and IX.
!                         INTEGER NCAT
!
!     IX <-- Observation from multinomial distribution.  All IX(i)
!            will be nonnegative and their sum will be N.
!                         INTEGER IX(NCAT)
!
!
!                              Method
!
!
!     Algorithm from page 559 of
!
!     Devroye, Luc
!
!     Non-Uniform Random Variate Generation.  Springer-Verlag,
!     New York, 1986.
!
!     DATAPLOT NOTE: CODE FROM RANLIB LIBRARY OF BROWN AND LAVATO.
!                    Department of Biomathematics, Box 237
!                    The University of Texas, M.D. Anderson Cancer Center
!                    1515 Holcombe Boulevard
!                    Houston, TX      77030
!
!                    FOLLOWING CHANGES:
!                    1) RENAMED FROM GENMUL TO MULRAN
!                    2) REPLACE THEIR IGBNM ROUTINE WITH DATAPLOT BINRAN
!                    3) I/O CHANGED AND ERROR FLAG ADDED.
!
!**********************************************************************
!     .. Scalar Arguments ..
      INTEGER n,ncat
!     ..
!     .. Array Arguments ..
      REAL p(*)
      INTEGER ix(*)
!     ..
!     .. Local Scalars ..
      REAL prob,ptot,sum
      INTEGER i,icat,ntot
!     ..
!     .. External Functions ..
!CCCC INTEGER ignbin
!CCCC EXTERNAL ignbin
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs
!     ..
!     .. Executable Statements ..
!
!---------------------------------------------------------------------
!
      REAL XTEMP(1)
!
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!     Check Arguments
!
      IF (n.LT.0) THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1001)N
 1001   FORMAT('***** ERROR IN MULRAN: N IS NOT POSITIVE, VALUE = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9999
      ENDIF
      IF (ncat.LE.1) THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1003)NCAT
 1003   FORMAT('***** ERROR IN MULRAN: NUMBER OF CATEGORIES IS <= 1, ',   &
               'VALUE = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9999
      ENDIF
      ptot = 0.0
      DO 10,i = 1,ncat - 1
          IF (p(i).LT.0.0 .or. p(i).gt.1.0) THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1011)i,p(i)
 1011   FORMAT('***** ERROR IN MULRAN: FOR CATEGORY ',I8,' P(I) IS ',   &
               'NOT IN THE INTERVAL (0,1).  THE VALUE = ',G15.7)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9999
          ENDIF
          ptot = ptot + p(i)
   10 CONTINUE
      IF (ptot.GT.0.999999) THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1021)
 1021   FORMAT('***** ERROR IN MULRAN: SUM OF PROBABILITIES IS ',   &
               'GREATER THAN 1.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9999
      ENDIF
!
!     Initialize variables
!
      ntot = n
      sum = 1.0
      DO 20,i = 1,ncat
          ix(i) = 0
   20 CONTINUE
                                                                                                                                  
!     Generate the observation
      NPAR=1
      DO 30,icat = 1,ncat - 1
          prob = p(icat)/sum
!CCCC     ix(icat) = ignbin(ntot,prob)
          CALL BINRAN(NPAR,PROB,NTOT,ISEED,XTEMP)
          IX(ICAT) = INT(XTEMP(1)+0.1)
          ntot = ntot - ix(icat)
          IF (ntot.LE.0) go to 9999
          sum = sum - p(icat)
   30 CONTINUE
      ix(ncat) = ntot
!
!     Finished
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE MULRAN
      SUBROUTINE MUTCDF(X,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE MUTH DISTRIBUTION
!              WITH SHAPE PARAMETER BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!
!              F(X;BETA) = 1 - EXP[-(1/BETA)*(EXP(BETA*X) - 1) + BETA*X]
!                          0 <= BETA <= 1; X > 0
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --BETA   = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --MUTH (1977), "RELIABILITY MODELS WITH POSITIVE MEMORY
!                DERIVED FROM THE MEAN RESIDUAL LIFE FUNCTION", IN
!                "THE THEORY AND APPLICATIONS OF RELIABILITY",
!                EDS. TSOKOS AND SHIMI, NEW YORK: ACADEMIC PRESS, INC.,
!                PP. 401-435.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
      IF(X.LE.0.0D0)THEN
        CDF=0.0D0
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0 .OR. BETA.GT.1.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO MUTCDF IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(BETA.LE.0.0D0)THEN
        CDF=1.0D0 - DEXP(-X)
      ELSE
        TERM1=DEXP(BETA*X)
        TERM3=-(1.0D0/BETA)*(TERM1 - 1.0D0)
        CDF=1.0D0 - EXP(TERM3 + BETA*X)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MUTCDF
      SUBROUTINE MUTCHA(X,BETA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE MUTH DISTRIBUTION
!              WITH SHAPE PARAMETER BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE CUMULATIVE HAZARD FUNCTION
!
!              H(X;BETA) = (1/BETA)*(EXP(BETA*X) - 1) - BETA*X
!                          0 <= BETA <= 1; X > 0
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --BETA   = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--HAZ    = THE DOUBLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE HAZARD FUNCTION VALUE HAZ.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --MUTH (1977), "RELIABILITY MODELS WITH POSITIVE MEMORY
!                DERIVED FROM THE MEAN RESIDUAL LIFE FUNCTION", IN
!                "THE THEORY AND APPLICATIONS OF RELIABILITY",
!                EDS. TSOKOS AND SHIMI, NEW YORK: ACADEMIC PRESS, INC.,
!                PP. 401-435.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0D0
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0 .OR. BETA.GT.1.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO MUTCHAZ IS ',   &
             'NON-POSITIVE.')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO MUTCHAZ IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(BETA.LE.0.0D0)THEN
        HAZ=X
      ELSE
        HAZ=(1.0D0/BETA)*(DEXP(BETA*X) - 1.0D0) - BETA*X
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MUTCHA
      SUBROUTINE MUTHAZ(X,BETA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE MUTH DISTRIBUTION
!              WITH SHAPE PARAMETER BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE HAZARD FUNCTION
!
!              h(X;BETA) = EXP(BETA*X) - BETA
!                          0 <= BETA <= 1; X > 0
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --BETA   = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--HAZ    = THE DOUBLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION HAZARD FUNCTION VALUE HAZ.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --MUTH (1977), "RELIABILITY MODELS WITH POSITIVE MEMORY
!                DERIVED FROM THE MEAN RESIDUAL LIFE FUNCTION", IN
!                "THE THEORY AND APPLICATIONS OF RELIABILITY",
!                EDS. TSOKOS AND SHIMI, NEW YORK: ACADEMIC PRESS, INC.,
!                PP. 401-435.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0D0
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0 .OR. BETA.GT.1.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO MUTHAZ IS ',   &
             'NON-POSITIVE.')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO MUTHAZ IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(BETA.LE.0.0D0)THEN
        HAZ=1.0D0
      ELSE
        HAZ=DEXP(BETA*X) - BETA
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MUTHAZ
      SUBROUTINE MUTPDF(X,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE MUTH DISTRIBUTION
!              WITH SHAPE PARAMETER BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!
!              f(X;BETA) = (EXP(BETA*X) - BETA)*
!                          EXP[-(1/BETA)*(EXP(BETA*X) - 1) + BETA*X]
!
!                          0 <= BETA <= 1; X > 0
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --BETA   = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --MUTH (1977), "RELIABILITY MODELS WITH POSITIVE MEMORY
!                DERIVED FROM THE MEAN RESIDUAL LIFE FUNCTION", IN
!                "THE THEORY AND APPLICATIONS OF RELIABILITY",
!                EDS. TSOKOS AND SHIMI, NEW YORK: ACADEMIC PRESS, INC.,
!                PP. 401-435.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0D0
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0 .OR. BETA.GT.1.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO MUTPDF IS ',   &
             'NON-POSITIVE.')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO MUTPDF IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(BETA.LE.0.0D0)THEN
        PDF=DEXP(-X)
      ELSE
        TERM1=DEXP(BETA*X)
        TERM3=-(1.0D0/BETA)*(TERM1 - 1.0D0)
        PDF=(TERM1 - BETA)*EXP(TERM3 + BETA*X)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MUTPDF
      SUBROUTINE MUTPPF(P,BETA,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE MUTH
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --BETA   = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 < P < 1
!     OTHER DATAPAC   SUBROUTINES NEEDED--MUTCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --MUTH (1977), "RELIABILITY MODELS WITH POSITIVE MEMORY
!                DERIVED FROM THE MEAN RESIDUAL LIFE FUNCTION", IN
!                "THE THEORY AND APPLICATIONS OF RELIABILITY",
!                EDS. TSOKOS AND SHIMI, NEW YORK: ACADEMIC PRESS, INC.,
!                PP. 401-435.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/1
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.00000001D0/
      DATA SIG /1.0D-8/
      DATA ZERO /0.0D0/
      DATA MAXIT /5000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
      IF(P.LE.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO MUTPPF IS OUTSIDE ',   &
               'THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0 .OR. BETA.GT.1.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO MUTPPF IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(BETA.LE.0.0D0)THEN
        PPF=-DLOG(1.0D0 - P)
        GO TO 9000
      ENDIF
!
!  FIND BRACKETING INTERVAL.  THIS IS A RELATIVELY SHORT-TAILED
!  DISTRIBUTION WITH A RESTRICTED VALUE OF THE SHAPE PARAMETER.
!  SO JUST USE 10 AS THE UPPER BOUND (AND INCREMENT IN STEPS
!  OF 10).
!
      XL=0.0D0
      XR=5.0D0
      XINC=10.0D0
      ICOUNT=0
      MAXCNT=10000
!
   91 CONTINUE
      IF(XL.LE.0.0D0)THEN
        CDFL=0.0D0
      ELSE
        CALL MUTCDF(XL,BETA,CDFL)
      ENDIF
      IF(XR.LE.0.0D0)XR=XL+XINC
      CALL MUTCDF(XR,BETA,CDFR)
!
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
        XR=XL+XINC
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
        IF(XL.LT.0.0D0)XL=0.0D0
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
   96 FORMAT('***** ERROR--MUTPPF UNABLE TO FIND BRACKETING INTERVAL.')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -P
      FXR = 1.0D0 - P
  105 CONTINUE
      X = (XL+XR)*0.5D0
      CALL MUTCDF(X,BETA,DCDF)
      P1=DCDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9000
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
  130 FORMAT('***** ERROR--MUTPPF ROUTINE DID NOT CONVERGE.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MUTPPF
      SUBROUTINE MUTRAN(N,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE MUTH DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = BETA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE MUTH DISTRIBUTION
!             WITH SHAPE PARAMETER VALUE = BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 <= BETA <= N
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, MUTPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --MUTH (1977), "RELIABILITY MODELS WITH POSITIVE MEMORY
!                DERIVED FROM THE MEAN RESIDUAL LIFE FUNCTION", IN
!                "THE THEORY AND APPLICATIONS OF RELIABILITY",
!                EDS. TSOKOS AND SHIMI, NEW YORK: ACADEMIC PRESS, INC.,
!                PP. 401-435.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.1
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0 .OR. BETA.GT.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF MUTH RANDOM ',   &
             'NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO MUTRAN IS ',   &
             'OUTSIDE THE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N MUTH DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL MUTPPF(DBLE(X(I)),DBLE(BETA),DTEMP)
        X(I)=REAL(DTEMP)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE MUTRAN
      SUBROUTINE MVMLTL(NR,N,A,X,Y)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! COMPUTE Y=LX
! WHERE L IS A LOWER TRIANGULAR MATRIX STORED IN A
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(N,N)       --> LOWER TRIANGULAR (N*N) MATRIX
! X(N)         --> OPERAND VECTOR
! Y(N)        <--  RESULT VECTOR
!
! NOTE
! ----
! X AND Y CANNOT SHARE STORAGE
!
      DIMENSION A(NR,1),X(N),Y(N)
      DO 30 I=1,N
        SUM=0.
        DO 10 J=1,I
          SUM=SUM+A(I,J)*X(J)
   10   CONTINUE
        Y(I)=SUM
   30 CONTINUE
      RETURN
      END SUBROUTINE MVMLTL
      SUBROUTINE MVMLTS(NR,N,A,X,Y)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! COMPUTE Y=AX
! WHERE "A" IS A SYMMETRIC (N*N) MATRIX STORED IN ITS LOWER
! TRIANGULAR PART AND X,Y ARE N-VECTORS
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(N,N)       --> SYMMETRIC (N*N) MATRIX STORED IN
!                  LOWER TRIANGULAR PART AND DIAGONAL
! X(N)         --> OPERAND VECTOR
! Y(N)        <--  RESULT VECTOR
!
! NOTE
! ----
! X AND Y CANNOT SHARE STORAGE.
!
      DIMENSION A(NR,1),X(N),Y(N)
      DO 30 I=1,N
        SUM=0.
        DO 10 J=1,I
          SUM=SUM+A(I,J)*X(J)
   10   CONTINUE
        IF(I.EQ.N) GO TO 25
        IP1=I+1
        DO 20 J=IP1,N
          SUM=SUM+A(J,I)*X(J)
   20   CONTINUE
   25   Y(I)=SUM
   30 CONTINUE
      RETURN
      END SUBROUTINE MVMLTS
      SUBROUTINE MVMLTU(NR,N,A,X,Y)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! COMPUTE Y=(L+)X
! WHERE L IS A LOWER TRIANGULAR MATRIX STORED IN A
! (L-TRANSPOSE (L+) IS TAKEN IMPLICITLY)
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(NR,1)       --> LOWER TRIANGULAR (N*N) MATRIX
! X(N)         --> OPERAND VECTOR
! Y(N)        <--  RESULT VECTOR
!
! NOTE
! ----
! X AND Y CANNOT SHARE STORAGE
!
      DIMENSION A(NR,1),X(N),Y(N)
      DO 30 I=1,N
        SUM=0.
        DO 10 J=I,N
          SUM=SUM+A(J,I)*X(J)
   10   CONTINUE
        Y(I)=SUM
   30 CONTINUE
      RETURN
      END SUBROUTINE MVMLTU
      DOUBLE PRECISION FUNCTION MVNFNC(N, W)
!
!     Integrand subroutine
!
      INTEGER N, INFIN(*), INFIS
      DOUBLE PRECISION W(*), LOWER(*), UPPER(*), CORREL(*), ONE
      INTEGER NL, IJ, I, J
      PARAMETER ( NL = 100, ONE = 1.0D0 )
      DOUBLE PRECISION COV((NL*(NL+1))/2), A(NL), B(NL), Y(NL), BVN
      INTEGER INFI(NL)
      DOUBLE PRECISION PROD, D1, E1, DI, EI, SUM, PHINV, D, E, MVNNIT
      SAVE D1, E1, A, B, INFI, COV
!
      INCLUDE 'DPCOP2.INC'
!
      BMIN=DBLE(CPUMIN)
!
      DI = D1
      EI = E1
      PROD = E1 - D1
      IJ = 1
      DO 100 I = 1,N
         Y(I) = PHINV( DI + W(I)*(EI-DI) )
         SUM = 0.0D0
         DO 200 J = 1,I
            IJ = IJ + 1
            SUM = SUM + COV(IJ)*Y(J)
  200    CONTINUE
         IJ = IJ + 1
         IF ( COV(IJ) .GT. 0.0D0 ) THEN
            CALL LIMITS( A(I+1)-SUM, B(I+1)-SUM, INFI(I+1), DI, EI )
         ELSE
            DI = ( 1.0D0 + SIGN( ONE, A(I+1)-SUM ) )/2.0D0
            EI = ( 1.0D0 + SIGN( ONE, B(I+1)-SUM ) )/2.0D0
         ENDIF
         PROD = PROD*(EI-DI)
 100  CONTINUE
      MVNFNC = PROD
      RETURN
!
!     Entry point for intialization.
!
      ENTRY MVNNIT(N, CORREL, LOWER, UPPER, INFIN, INFIS, D, E)
      MVNNIT = 0
!
!     Initialization and computation of covariance Cholesky factor.
!
      CALL NCVSRT(N, LOWER,UPPER,CORREL,INFIN,Y, INFIS,A,B,INFI,COV,D,E)
      D1 = D
      E1 = E
      IF ( N - INFIS .EQ. 2 ) THEN
         D = SQRT( 1.0D0 + COV(2)**2 )
         A(2) = A(2)/D
         B(2) = B(2)/D
         E = BVN( A, B, INFI, COV(2)/D )
         D = 0.0D0
         INFIS = INFIS + 1
      END IF
!
      RETURN
      END FUNCTION MVNFNC
      SUBROUTINE MVTLMS( NU, A, B, INFIN, LOWER, UPPER )
      DOUBLE PRECISION A, B, LOWER, UPPER, STUDNT
      INTEGER NU, INFIN
!
      INCLUDE 'DPCOP2.INC'
!
      LOWER = 0.0D0
      UPPER = 1.0D0
      IF ( INFIN .GE. 0 ) THEN
         IF ( INFIN .NE. 0 ) LOWER = STUDNT( NU, A )
         IF ( INFIN .NE. 1 ) UPPER = STUDNT( NU, B )
      ENDIF
!
      RETURN
      END SUBROUTINE MVTLMS
      SUBROUTINE MVTSRT( N, NU, LOWER, UPPER, CORREL, INFIN, Y, INFIS,   &
                         A, B, INFI, COV, D, E )
!
!     Sort limits
!
      INTEGER N, NU, INFI(*), INFIN(*), INFIS
      DOUBLE PRECISION   &
           A(*), B(*), COV(*), LOWER(*), UPPER(*), CORREL(*), Y(*), D, E
      INTEGER I, J, K, IJ, II, JMIN
      DOUBLE PRECISION SUMSQ, ZERO, TWO, PI, CVDIAG
      DOUBLE PRECISION AI, BI, SUM, YL, YU, YD
      DOUBLE PRECISION AMIN, BMIN, DMIN, EMIN, CON, CONODD, CONEVN
      PARAMETER ( ZERO = 0, TWO = 2, PI = 3.14159265358979323844 )
!
      INCLUDE 'DPCOP2.INC'
!
      AMIN=DBLE(CPUMAX)
      AMAX=DBLE(CPUMIN)
      BMIN=DBLE(CPUMAX)
      IJ = 0
      II = 0
      INFIS = 0
!
      DO 100 I = 1, N
         INFI(I) = INFIN(I)
         IF ( INFI(I) .LT. 0 ) THEN
            INFIS = INFIS + 1
         ELSE
            A(I) = 0.0D0
            B(I) = 0.0D0
            IF ( INFI(I) .NE. 0 ) A(I) = LOWER(I)
            IF ( INFI(I) .NE. 1 ) B(I) = UPPER(I)
         ENDIF
         DO 200 J = 1,I-1
            IJ = IJ + 1
            II = II + 1
            COV(IJ) = CORREL(II)
  200    CONTINUE
         IJ = IJ + 1
         COV(IJ) = 1
  100 CONTINUE
      CONODD = 1.0D0/PI
      CONEVN = 1.0D0/TWO
      DO 300 I = 1, NU - 1
         IF ( MOD(I,2) .EQ. 0 ) THEN
            IF ( I .GT. 2 ) CONEVN = CONEVN*DBLE(I-1)/DBLE(I-2)
         ELSE
            IF ( I .GT. 2 ) CONODD = CONODD*DBLE(I-1)/DBLE(I-2)
         ENDIF
  300 CONTINUE
!
!     First move any doubly infinite limits to innermost positions
!
      IF ( INFIS .LT. N ) THEN
         DO 400 I = N, N-INFIS+1, -1
            IF ( INFI(I) .GE. 0 ) THEN
               DO 500 J = 1, I-1
                  IF ( INFI(J) .LT. 0 ) THEN
                     CALL RCSWAP( J, I, A, B, INFI, N, COV )
                     GO TO  400
                  ENDIF
  500          CONTINUE
            ENDIF
  400    CONTINUE
!
!     Sort remaining limits and determine Cholesky decomposition
!
         II = 0
         YD = 1.0D0
         DO 900 I = 1, N-INFIS
!
!     Determine the integration limits for variable with minimum
!      expected probability and interchange that variable with Ith.
!
            EMIN = 1
            DMIN = 0
            JMIN = I
            CVDIAG = 0
            IJ = II
            DO 600 J = I, N-INFIS
               SUM = 0
               SUMSQ = 0
               DO 650 K = 1, I-1
                  SUM = SUM + COV(IJ+K)*Y(K)
                  SUMSQ = SUMSQ + COV(IJ+K)**2
  650          CONTINUE
               IJ = IJ + J
               SUMSQ = SQRT( MAX( COV(IJ)-SUMSQ, ZERO ) )
               IF ( SUMSQ .GT. 0 ) THEN
                  AI = YD*( A(J) - SUM )/SUMSQ
                  BI = YD*( B(J) - SUM )/SUMSQ
                  CALL MVTLMS( NU+J-1, AI, BI, INFI(J), D, E )
                  IF ( EMIN - DMIN .GE. E - D ) THEN
                     JMIN = J
                     AMIN = AI
                     BMIN = BI
                     DMIN = D
                     EMIN = E
                     CVDIAG = SUMSQ
                  ENDIF
               ENDIF
  600       CONTINUE
            IF ( JMIN .NE. I ) CALL RCSWAP( I, JMIN, A,B, INFI, N,COV )
!
!     Compute Ith column of Cholesky factor.
!
            IJ = II + I
            COV(IJ) = CVDIAG
            DO 700 J = I+1, N-INFIS
               IF ( CVDIAG .GT. 0.0D0 ) THEN
                  SUM = COV(IJ+I)
                  DO 750 K = 1, I-1
                     SUM = SUM - COV(II+K)*COV(IJ+K)
  750             CONTINUE
                  COV(IJ+I) = SUM/CVDIAG
               ELSE
                  COV(IJ+I) = 0.0D0
               ENDIF
               IJ = IJ + J
 700        CONTINUE
!
!     Compute expected value for Ith integration variable and
!     scale Ith covariance matrix row and limits.
!
            IF ( MOD(NU+I-1,2) .EQ. 0 ) THEN
               IF ( NU+I-3 .GT. 0 ) CONEVN =   &
                                    CONEVN*DBLE(NU+I-2)/DBLE(NU+I-3)
               CON = CONEVN
            ELSE
               IF ( NU+I-3 .GT. 0 ) CONODD =   &
                                    CONODD*DBLE(NU+I-2)/DBLE(NU+I-3)
               CON = CONODD
            ENDIF
            IF ( CVDIAG .GT. 0.0D0 ) THEN
               YL = 0.0D0
               YU = 0.0D0
               IF ( INFI(I) .NE. 0 .AND. NU+I-2 .GT. 0 )   &
                    YL = -CON*DBLE(NU+I-1)/DBLE(NU+I-2)   &
                    /( 1.0D0 + AMIN**2/DBLE(NU+I-1) )**((NU+I-2)/TWO)
               IF ( INFI(I) .NE. 1 .AND. NU+I-2 .GT. 0 )   &
                    YU = -CON*DBLE(NU+I-1)/DBLE(NU+I-2)   &
                    /( 1.0D0 + BMIN**2/(NU+I-1) )**( (NU+I-2)/TWO )
               Y(I) = ( YU - YL )/( EMIN - DMIN )/YD
               DO 800 J = 1,I
                  II = II + 1
                  COV(II) = COV(II)/CVDIAG
  800          CONTINUE
               IF ( INFI(I) .NE. 0 ) A(I) = A(I)/CVDIAG
               IF ( INFI(I) .NE. 1 ) B(I) = B(I)/CVDIAG
            ELSE
               Y(I) = 0.0D0
               II = II + I
            ENDIF
            YD = YD/SQRT( 1 + ( Y(I)*YD + 1 )*( Y(I)*YD - 1 )/(NU+I) )
  900    CONTINUE
         CALL MVTLMS( NU, A(1), B(1), INFI(1), D, E)
      ENDIF
!
      RETURN
      END SUBROUTINE MVTSRT
      SUBROUTINE NBCDF(X,P,AN,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X FOR
!              THE NEGATIVE BINOMIAL DISTRIBUTION WITH DOUBLE
!              PRECISION 'BERNOULLI PROBABILITY' PARAMETER = P,
!              AND DOUBLE PRECISION 'NUMBER OF SUCCESSES IN
!              BERNOULLI TRIALS' PARAMETER = N.  THE NEGATIVE
!              BINOMIAL DISTRIBUTION USED HEREIN HAS MEAN = N*(1-P)/P
!              AND STANDARD DEVIATION = SQRT(N*(1-P)/(P*P))).
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE
!              INTEGER X--X = 0, 1, 2, ... .  THIS DISTRIBUTION HAS
!              THE PROBABILITY MASS FUNCTION
!
!                  p(X;P,N) = C(N+X-1,N) * P**N * (1-P)**X.
!
!              WHERE C(N+X-1,N) IS THE COMBINATORIAL FUNCTION
!              EQUALING THE NUMBER OF COMBINATIONS OF N+X-1 ITEMS
!              TAKEN N AT A TIME.  THE NEGATIVE BINOMIAL DISTRIBUTION
!              IS THE DISTRIBUTION OF THE NUMBER OF FAILURES BEFORE
!              OBTAINING N SUCCESSES IN AN INDEFINITE SEQUENCE OF
!              BERNOULLI (0,1) CTRIALS WHERE THE PROBABILITY OF
!              SUCCESS IN A SINGLE TRIAL = P.
!
!              THE NEGATIVE BINOMIAL CAN BE EXTENDED TO THE
!              CASE WHERE N IS POSITIVE REAL NUMBER (I.E., NOT
!              RESTRICTED TO AN INTEGER).  IN THAT CASE, THE
!              PROBABILITY FUNCTION IS:
!
!              F(X) = P**N * (1-P)**X * GAMMA(N+X)/(GAMMA(N)*X!)
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.  X
!                                SHOULD BE A NON-NEGATIVE INTEGER.
!                     --P      = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER
!                                FOR THE NEGATIVE BINOMIAL
!                                DISTRIBUTION.  0 <= P < 1.
!                     --N      = THE DOUBLE PRECISION VALUE OF THE
!                                'NUMBER OF SUCCESSES IN BERNOULLI
!                                TRIALS' PARAMETER.  N > 0.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE NEGATIVE BINOMIAL
!             DISTRIBUTION WITH PARAMETERS P AND N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE AND INTEGRAL-VALUED.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY) AND
!                   1.0 (EXCLUSIVELY).
!                 --N SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DBETAI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DATAN, LNGAMM.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 945, FORMULAE 26.5.24 AND
!                 26.5.28, AND PAGE 929.
!               --JOHNSON, KOTZ, AND KEMP, "DISCRETE UNIVARIATE
!                 DISTRIBUTIONS", SECOND EDITION, 1992.
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION, 2001.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGES 130-131.
!               --WILLIAMSON AND BRETHERTON, TABLES OF
!                 THE NEGATIVE BINOMIAL PROBABILITY
!                 DISTRIBUTION, 1963.
!               --OWEN, HANDBOOK OF STATISTICAL
!                 TABLES, 1962, PAGE 304.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     2004. EXTEND TO NON-INTEGER VALUES
!                                       FOR N
!     UPDATED         --MARCH     2009. CONVERT TO DOUBLE PRECISION
!     UPDATED         --MARCH     2009. USE DBETAI EVEN FOR INTEGER
!                                       VALUES OF N
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION P
      DOUBLE PRECISION AN
      DOUBLE PRECISION CDF
      DOUBLE PRECISION DBETAI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA EPS/0.0000001D0/
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0D0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0D0.OR.P.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO NBCDF IS OUTSIDE ',   &
      'THE ALLOWABLE (0,1) INTERVAL')
!
      IF(X.LT.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO NBCDF IS NEGATIVE.')
!
      IF(AN.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AN
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE THIRD ARGUMENT TO NBCDF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IX=INT(X+EPS)
      CDF=1.0D0 - DBETAI(DBLE(1.0-P),DBLE(IX+1),DBLE(AN))
!
 9000 CONTINUE
      RETURN
!
      END SUBROUTINE NBCDF
      INTEGER FUNCTION NBPK(M,J)
!CCCC INTEGER FUNCTION NBP_K(M,J)
      NBPK=0
      IF (M.LT.J) THEN
          NBPK=0
      ELSE
          IF (J.EQ.1) NBPK=M
          IF (J.EQ.2) NBPK=(M*(M-1))/2
          IF (J.EQ.3) NBPK=(M*(M-1)*(M-2))/6
      ENDIF
      RETURN
      END FUNCTION NBPK
      INTEGER FUNCTION NBPNCE(M,J)
!CCCC CHANGE TO 6-CHARACTER NAME
!CCCC INTEGER FUNCTION NBP_NCEIL(M,J)
      IF (MOD(M,J).EQ.0) THEN
         NBPNCE=INT(dble(M)/J)
      ELSE
         NBPNCE=NINT(dble(M)/J+0.5)
      ENDIF
      RETURN
      END FUNCTION NBPNCE
      DOUBLE PRECISION FUNCTION NBFUN(DK,DX)
!
!     PURPOSE--DPMLNB CALLS DFZER2 TO FIND A ROOT FOR THE FOLLOWING
!              FUNCTION:
!
!                 LN(KHAT) - LN(XBAR + KHAT) - PSI(KHAT) +
!                 (1/N)*SUM[i=1 to N][PSI(X(I) + KHAT)] = 0
!
!              WITH
!
!                  KHAT     = CURRENT ESTIMATE FOR K
!                  N        = SAMPLE SIZE
!                  XBAR     = SAMPLE MEAN
!                  PSI      = PSI FUNCTION
!
!     INPUT  ARGUMENTS--DK  = THE DOUBLE PRECISION VALUE THAT
!                             SPECIFIES THE K SHAPE PARAMETER FOR
!                             THE NEGATIVE BINOMIAL DISTRIBUTION.
!     OUTPUT--THE DOUBLE PRECISION FUNCTION VALUE NBFUN.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DPSI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KARL BURY (1999). "STATISTICAL DISTRIBUTIONS IN
!                 ENGINEERING", CAMBRIDGE UNIVERSITY PRESS, P. 91.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DK
      DOUBLE PRECISION DX(*)
!
      DOUBLE PRECISION DXBAR
      COMMON/NBCOM/DXBAR,N
!
      EXTERNAL DPSI
      DOUBLE PRECISION DPSI
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DLOG(DK) - DLOG(DXBAR + DK) - DPSI(DK)
      DSUM1=0.0D0
      DO 100 I=1,N
        DTERM2=DX(I) + DK
        DSUM1=DSUM1 + DPSI(DTERM2)
  100 CONTINUE
      NBFUN=DTERM1 + DSUM1/DBLE(N)
!
      RETURN
      END FUNCTION NBFUN
      DOUBLE PRECISION FUNCTION NBFUN2(DK,DX)
!
!     PURPOSE--DPMLNB CALLS DFZER2 TO FIND A ROOT FOR THE FOLLOWING
!              FUNCTION:
!
!                 LN(KHAT) - LN(XBAR + KHAT) - PSI(KHAT) +
!                 (1/N)*SUM[i=1 to N][PSI(X(I) + KHAT)] = 0
!
!              WITH
!
!                  KHAT     = CURRENT ESTIMATE FOR K
!                  N        = SAMPLE SIZE
!                  XBAR     = SAMPLE MEAN
!                  PSI      = PSI FUNCTION
!
!               THIS VERSION IS MODIFIED FOR THE CASE WHERE THE
!               DATA IS GROUPED.
!
!     INPUT  ARGUMENTS--DK  = THE DOUBLE PRECISION VALUE THAT
!                             SPECIFIES THE K SHAPE PARAMETER FOR
!                             THE NEGATIVE BINOMIAL DISTRIBUTION.
!     OUTPUT--THE DOUBLE PRECISION FUNCTION VALUE NBFUN.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DPSI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KARL BURY (1999). "STATISTICAL DISTRIBUTIONS IN
!                 ENGINEERING", CAMBRIDGE UNIVERSITY PRESS, P. 91.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.3
!     ORIGINAL VERSION--MARCH     2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DK
      DOUBLE PRECISION DX(*)
!
      DOUBLE PRECISION DXBAR
      COMMON/NBCOM2/DXBAR,N,IINDX
!
      EXTERNAL DPSI
      DOUBLE PRECISION DPSI
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DFREQ
      DOUBLE PRECISION DVAL
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DLOG(DK) - DLOG(DXBAR + DK) - DPSI(DK)
      DSUM1=0.0D0
      DO 100 I=1,N
        DVAL=DX(I)
        DFREQ=DX(I+IINDX)
        DTERM2=DVAL + DK
        DSUM1=DSUM1 + DFREQ*DPSI(DTERM2)
  100 CONTINUE
      NBFUN2=DTERM1 + DSUM1/DBLE(N)
!
      RETURN
      END FUNCTION NBFUN2
      SUBROUTINE NBLIK1(Y,N,P,AK,   &
      ALIK,AIC,AICC,BIC,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE NEGATIVE BINOMIAL DISTRIBUTION.  THE DATA IS
!              ASSUMED TO BE IN "RAW" FORM.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.  SPECIFICALLY, THE SAMPLE SIZE AND THE
!              PRESENCE OF NON-NEGATIVE VALUES.  ALSO, IT IS ASSUMED
!              THAT THE CALLING PROGRAM HAS ALREADY ROUNDED THE RESPONSE
!              TO THE NEAREST INTEGER.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/3
!     ORIGINAL VERSION--MARCH     2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DK
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DXBAR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DLNGAM
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NBLI'
      ISUBN2='K1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NBLIK1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,P,AK
   55   FORMAT('N,P,AK = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NEGATIVE BINOMIAL MLE ESTIMATE  **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     LIKELIHOOD FUNCTION IS:
!
!     SUM[i=1 to N][LOG(GAMMA(Y(i) + K)] - N*LOG(GAMMA(R)) -
!     SUM[i=1 to N][LOG(GAMMA(Y(i)+ 1)] - N*K*LOG(P) +
!     N*XBAR*LOG(1-P)
!
      CALL MEAN(Y,N,IWRITE,XMEAN,IBUGA3,IERROR)
      DXBAR=DBLE(XMEAN)
      DN=DBLE(N)
      DP=DBLE(P)
      DK=DBLE(AK)
      DTERM1=-DN*DLNGAM(DK)+DN*DK*LOG(DP)+DN*DXBAR*LOG(1.0D0-DP)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + DLNGAM(DX+DK)
        DSUM2=DSUM2 + DLNGAM(DX+1.0D0)
 1000 CONTINUE
!
      DLIK=DSUM1 - DSUM2 + DTERM1
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NBLIK1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)DSUM1,DSUM2
 9012   FORMAT('DSUM1,DSUM2 = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DTERM1,DTERM2,DTERM3
 9013   FORMAT('DTERM1,DTERM2,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NBLIK1
      SUBROUTINE NBLIK2(Y,X,N,P,AK,   &
      ALIK,AIC,AICC,BIC,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE NEGATIVE BINOMIAL DISTRIBUTION.  THE DATA IS
!              ASSUMED TO BE IN "BINNED" FORM.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.  SPECIFICALLY, THE SAMPLE SIZE AND THE
!              PRESENCE OF NON-NEGATIVE VALUES.  ALSO, IT IS ASSUMED
!              THAT THE CALLING PROGRAM HAS ALREADY ROUNDED THE RESPONSE
!              TO THE NEAREST INTEGER.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/3
!     ORIGINAL VERSION--MARCH     2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DFREQ
      DOUBLE PRECISION DP
      DOUBLE PRECISION DK
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DXBAR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DLNGAM
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NBLI'
      ISUBN2='K2  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NBLIK2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,P,AK
   55   FORMAT('N,P,AK = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,X(I),Y(I)
   57     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NEGATIVE BINOMIAL MLE ESTIMATE  **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     LIKELIHOOD FUNCTION IS:
!
!     SUM[i=1 to N][LOG(GAMMA(Y(i) + K)] - N*LOG(GAMMA(R)) -
!     SUM[i=1 to N][LOG(GAMMA(Y(i)+ 1)] - N*K*LOG(P) +
!     N*XBAR*LOG(1-P)
!
      CALL WEMEAN(X,Y,N,IWRITE,XMEAN,IBUGA3,IERROR)
      DXBAR=DBLE(XMEAN)
      NTOT=0
      DO 1000 I=1,N
        NTOT=INT(Y(I))+NTOT
 1000 CONTINUE
      DN=DBLE(NTOT)
      DP=DBLE(P)
      DK=DBLE(AK)
      DTERM1=-DN*DLNGAM(DK)+DN*DK*LOG(DP)+DN*DXBAR*LOG(1.0D0-DP)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 1010 I=1,N
        DX=DBLE(X(I))
        DFREQ=DBLE(Y(I))
        DSUM1=DSUM1 + DFREQ*DLNGAM(DX+DK)
        DSUM2=DSUM2 + DFREQ*DLNGAM(DX+1.0D0)
 1010 CONTINUE
!
      DLIK=DSUM1 - DSUM2 + DTERM1
      ALIK=REAL(DLIK)
      NP=2
      DNP=DBLE(NP)
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NBLIK2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)DSUM1,DSUM2
 9012   FORMAT('DSUM1,DSUM2 = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DTERM1,DTERM2,DTERM3
 9013   FORMAT('DTERM1,DTERM2,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NBLIK2
      SUBROUTINE NBML1(Y,N,XMEAN,XVAR,PSV,AKSV,   &
      XTEMP,DTEMP,ITEMP,MAXNXT,   &
      ALOWP1,AUPPP1,ALOWK1,AUPPK1,ALPHA,NUMALP,NUMOUT,   &
      AKML,PML,PMLBC,PSE,AKSE,COVSE,IERFLG,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE NEGATIVE BINOMIAL DISTRIBUTION FOR THE CASE WHERE
!              P AND K ARE BOTH UNKNOWN.  THE DATA IS ASSUMED TO BE IN
!              "RAW" FORM.  YOU CAN OPTIONALLY SPECIFY STARTING VALUES
!              (IN PSV AND KSV).  THE MOMENT ESTIMATES WILL BE USED IF
!              STARTING VALUES ARE NOT SPECIFIED.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.  SPECIFICALLY, THE SAMPLE SIZE AND THE
!              PRESENCE OF NON-NEGATIVE VALUES.  ALSO, IT IS ASSUMED
!              THAT THE CALLING PROGRAM HAS ALREADY ROUNDED THE RESPONSE
!              TO THE NEAREST INTEGER.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!              --JOHNSON, KEMP, AND KOTZ.  "UNIVARIATE DISCRETE
!                DISTRIBUTIONS", THIRD EDITION, WILEY, 2005, CHAPTER 5.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/3
!     ORIGINAL VERSION--MARCH     2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPNBML)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION ALOWP1(*)
      DIMENSION AUPPP1(*)
      DIMENSION ALOWK1(*)
      DIMENSION AUPPK1(*)
      DIMENSION ALPHA(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      EXTERNAL NBFUN
      DOUBLE PRECISION NBFUN
!
      DOUBLE PRECISION DXBAR
      COMMON/NBCOM/DXBAR,NSAMP
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION XLOWSV
      DOUBLE PRECISION XUPSV
      DOUBLE PRECISION DINC
!
      DOUBLE PRECISION TRIGAM
!
      INTEGER IFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XTEMP(*)
      DOUBLE PRECISION DTEMP(*)
      INTEGER ITEMP(*)
!
      REAL FISH(2,2)
      REAL COV(2,2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NBML'
      ISUBN2='1   '
      IERROR='NO'
!
      AKML=-99.0
      PML=-99.0
      PMLBC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NBML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,XMEAN,XVAR,AKSV,PSV
   55   FORMAT('N,XMEAN,XVAR,AKSV,PSV = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NEGATIVE BINOMIAL MLE ESTIMATE  **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
      IF(XVAR.LE.0.0)THEN
        IERFLG=1
        GO TO 9000
      ELSE
        ARATIO=XMEAN/XVAR
        AMXRAT=0.97
        IF(ARATIO.GT.AMXRAT)THEN
          IERFLG=1
          GO TO 9000
        ENDIF
      ENDIF
!
!     IF STARTING VALUES DO NOT EXIST, COMPUTE METHOD OF
!     MOMENT ESTIMATORS
!
      AKMOM=XMEAN*XMEAN/(XVAR - XMEAN)
      IF(AKSV.EQ.CPUMIN)THEN
        AKSV=AKMOM
      ENDIF
      PMOM=XMEAN/XVAR
      IF(PSV.EQ.CPUMIN)THEN
        PKSV=PMOM
      ENDIF
!
!     NOW COMPUTE MAXIMUM LIKELIHOOD ESTIMATES FOR K
!     ASSUMED UNKNOWN CASE.
!
      DXBAR=DBLE(XMEAN)
      NSAMP=N
!
      DXSTRT=DBLE(AKSV)
      DINC=MAX(DXSTRT/25.0D0,1.0D0)
      DINC=2.0D0
      DAE=0.000001D0
      DRE=DAE
      IFLAG=0
      DXLOW=MAX(DXSTRT - DINC,0.00001D0)
      DXUP=DXSTRT + DINC
      ITBRAC=0
      DO 3104 I=1,N
        DTEMP(I)=DBLE(Y(I))
 3104 CONTINUE
!
 3105 CONTINUE
      XLOWSV=DXLOW
      XUPSV=DXUP
      CALL DFZER2(NBFUN,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
!
      IF(IFLAG.EQ.4 .AND. ITBRAC.LE.200)THEN
        DXLOW=MAX(0.00001D0,XLOWSV-DINC)
        DXUP=XUPSV+DINC
        ITBRAC=ITBRAC+1
        GO TO 3105
      ENDIF
!
      IERFLG=IFLAG
!
      AKML=REAL(DXLOW)
      PML=AKML/(XMEAN + AKML)
      IF(AKML.GT.1.0)THEN
        PMLBC=(AKML-1.0)/(XMEAN + AKML - 1.0)
      ELSE
        PMLBC=0.0
      ENDIF
!
!     COMPUTE LOCAL FISHER INFORMATION MATRIX
!
      AN=REAL(N)
      FISH(1,1)=AN*AKML/(PML*PML*(1.0-PML))
      FISH(2,1)=-AN/PML
      FISH(1,2)=FISH(2,1)
      DN=DBLE(N)
      DTERM1=DN*TRIGAM(DBLE(AKML),IFAULT)
      DSUM1=0.0D0
      DO 3200 I=1,N
        DSUM1=DSUM1 + TRIGAM(DBLE(Y(I)+DBLE(AKML)),IFAULT)
 3200 CONTINUE
      FISH(2,2)=REAL(DTERM1 - DSUM1)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3211)
 3211   FORMAT('****** NBML1: AFTER COMPUTE FISHER INFORMATION MATRIX')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3214)DSUM1,DTERM1
 3214   FORMAT('DSUM1,DTERM1 = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3215)FISH(1,1),FISH(2,1),FISH(2,2)
 3215   FORMAT('FISH(1,1),FISH(2,1),FISH(2,2) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      NDIM=2
      CALL SGECO(FISH,NDIM,NDIM,ITEMP,RCOND,XTEMP)
      IJOB=1
      CALL SGEDI(FISH,NDIM,NDIM,ITEMP,XTEMP,XTEMP(MAXNXT/2),IJOB)
      DO 3230 J=1,NDIM
        DO 3240 I=1,NDIM
          COV(I,J)=FISH(I,J)
 3240   CONTINUE
 3230 CONTINUE
      PSE=0.0
      IF(COV(1,1).GE.0.0)PSE=SQRT(COV(1,1))
      AKSE=0.0
      IF(COV(2,2).GE.0.0)AKSE=SQRT(COV(2,2))
      COVSE=0.0
      IF(COV(2,1).GE.0.0)COVSE=SQRT(COV(2,1))
!
      DO 3260 I=1,NUMALP
!
        ALP=ALPHA(I)
        P1=ALP/2.0
        P2=1.0-(ALP/2.0)
        CALL NORPPF(P1,APPF1)
        CALL NORPPF(P2,APPF2)
        ALOWP1(I)=PML + APPF1*PSE
        IF(ALOWP1(I).LT.0.0)ALOWP1(I)=0.0
        AUPPP1(I)=PML + APPF2*PSE
        IF(AUPPP1(I).GE.1.0)AUPPP1(I)=1.0
        ALOWK1(I)=AKML + APPF1*AKSE
        IF(ALOWK1(I).LT.0.0)ALOWK1(I)=0.0
        AUPPK1(I)=AKML + APPF2*AKSE
!
 3260 CONTINUE
      NUMOUT=NUMALP
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NBML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)PML,PMLBC,AKML
 9013   FORMAT('PML,PMLBC,AKML = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NBML1
      SUBROUTINE NBML2(N,XMEAN,XVAR,AK,   &
      ALOWP1,AUPPP1,ALPHA,NUMALP,NUMOUT,   &
      PML,PMLBC,PMLBCV,IERFLG,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE NEGATIVE BINOMIAL DISTRIBUTION FOR THE CASE WHERE
!              K IS ASSUMED KNOWN.  THE DATA IS ASSUMED TO BE IN
!              "RAW" FORM.  CONFIDENCE LIMITS FOR P WILL BE RETURNED IF
!              NUMALP >= 1.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.  SPECIFICALLY, THE SAMPLE SIZE AND THE
!              PRESENCE OF NON-NEGATIVE VALUES.  ALSO, IT IS ASSUMED
!              THAT THE CALLING PROGRAM HAS ALREADY ROUNDED THE RESPONSE
!              TO THE NEAREST INTEGER.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!              --JOHNSON, KEMP, AND KOTZ.  "UNIVARIATE DISCRETE
!                DISTRIBUTIONS", THIRD EDITION, WILEY, 2005, CHAPTER 5.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/3
!     ORIGINAL VERSION--MARCH     2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPNBML)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION ALOWP1(*)
      DIMENSION AUPPP1(*)
      DIMENSION ALPHA(*)
!
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NBML'
      ISUBN2='1   '
      IERROR='NO'
!
      AKML=-99.0
      PML=-99.0
      PMLBC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NBML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,XMEAN,XVAR
   55   FORMAT('N,XMEAN,XVAR = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NEGATIVE BINOMIAL MLE ESTIMATE  **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
      PMLBC=0.0
      PMLBCV=0.0
      PML=AK/(XMEAN+AK)
!
      IF(PML.LT.0.0 .OR. PML.GT.1.0)THEN
        IERFLG=1
        GO TO 9000
      ENDIF
!
      IF(AK.GE.2.0)THEN
        PMLBC=(AK-1.0)/(XMEAN+AK-1.0)
        PMLBCV=(1.0/REAL(N))*PMLBC*PMLBC*(1.0-PMLBC)/   &
               (AK-1.0-PMLBC)
      ENDIF
!
      AN=REAL(N)
      IF(AK.GE.2.0 .AND. NUMALP.GE.1)THEN
        DO 2160 I=1,NUMALP
!
          ALP=ALPHA(I)
          P1=ALP/2.0
          P2=1.0-(ALP/2.0)
          CALL NBPPF(DBLE(P1),DBLE(PMLBC),DBLE(AN*AK),DTEMP)
          SL=DTEMP
          CALL NBPPF(DBLE(P2),DBLE(PMLBC),DBLE(AN*AK),DTEMP)
          SU=DTEMP
          TERM1=AK - 1.0
          ALOWP1(I)=TERM1/((SU/AN)+TERM1)
          IF(ALOWP1(I).LE.0.0)ALOWP1(I)=0.0
          AUPPP1(I)=TERM1/((SL/AN)+TERM1)
          IF(AUPPP1(I).GE.1.0)AUPPP1(I)=1.0
 2160   CONTINUE
        NUMOUT=NUMALP
      ELSE
        NUMOUT=0
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NBML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)PML,PMLBC,PMLBCV
 9013   FORMAT('PML,PMLBC,PMLBCV = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        IF(AK.GE.2.0 .AND. NUMALP.GE.1)THEN
          DO 9160 I=1,NUMALP
            WRITE(ICOUT,9063)I,ALPHA(I),ALOWP1(I),AUPPP1(I)
 9063       FORMAT('I,ALPHA(I),ALOWP1(I),AUPPP1(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','WRIT')
 9160     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE NBML2
      SUBROUTINE NBML3(Y,X,N,XMEAN,XVAR,PSV,AKSV,   &
      XTEMP,DTEMP,ITEMP,MAXNXT,   &
      ALOWP1,AUPPP1,ALOWK1,AUPPK1,ALPHA,NUMALP,NUMOUT,   &
      AKML,PML,PMLBC,PSE,AKSE,COVSE,IERFLG,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE NEGATIVE BINOMIAL DISTRIBUTION FOR THE CASE WHERE
!              P AND K ARE BOTH UNKNOWN.  THE DATA IS ASSUMED TO BE IN
!              "BINNED" FORM.  THE BINNING IS ASSUMED TO BE OF THE
!              TYPE X(I),F(I) WHERE X(I) IS THE DATA VALUE AND
!              F(I) IS THE FREQUENCY.
!
!              YOU CAN OPTIONALLY SPECIFY STARTING VALUES
!              (IN PSV AND KSV).  THE MOMENT ESTIMATES WILL BE USED IF
!              STARTING VALUES ARE NOT SPECIFIED.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.  SPECIFICALLY, THE SAMPLE SIZE AND THE
!              PRESENCE OF NON-NEGATIVE VALUES.  ALSO, IT IS ASSUMED
!              THAT THE CALLING PROGRAM HAS ALREADY ROUNDED THE RESPONSE
!              TO THE NEAREST INTEGER.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!              --JOHNSON, KEMP, AND KOTZ.  "UNIVARIATE DISCRETE
!                DISTRIBUTIONS", THIRD EDITION, WILEY, 2005, CHAPTER 5.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/3
!     ORIGINAL VERSION--MARCH     2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION ALOWP1(*)
      DIMENSION AUPPP1(*)
      DIMENSION ALOWK1(*)
      DIMENSION AUPPK1(*)
      DIMENSION ALPHA(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      EXTERNAL NBFUN2
      DOUBLE PRECISION NBFUN2
!
      DOUBLE PRECISION DXBAR
      COMMON/NBCOM2/DXBAR,NSAMP,IINDX
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION XLOWSV
      DOUBLE PRECISION XUPSV
      DOUBLE PRECISION DINC
!
      DOUBLE PRECISION TRIGAM
      DOUBLE PRECISION DVAL
      DOUBLE PRECISION DFREQ
!
      INTEGER IFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DOUBLE PRECISION DTEMP(*)
      INTEGER          ITEMP(*)
!
      REAL FISH(2,2)
      REAL COV(2,2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NBML'
      ISUBN2='3   '
      IERROR='NO'
!
      AKML=-99.0
      PML=-99.0
      PMLBC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NBML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,XMEAN,XVAR,AKSV,PSV
   55   FORMAT('N,XMEAN,XVAR,AKSV,PSV = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,X(I),Y(I)
   57     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NEGATIVE BINOMIAL MLE ESTIMATE  **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
      IF(XVAR.LE.0.0)THEN
        IERFLG=1
        GO TO 9000
      ELSE
        ARATIO=XMEAN/XVAR
        AMXRAT=0.97
        IF(ARATIO.GT.AMXRAT)THEN
          IERFLG=1
          GO TO 9000
        ENDIF
      ENDIF
!
!     IF STARTING VALUES DO NOT EXIST, COMPUTE METHOD OF
!     MOMENT ESTIMATORS
!
      AKMOM=XMEAN*XMEAN/(XVAR - XMEAN)
      IF(AKSV.EQ.CPUMIN)THEN
        AKSV=AKMOM
      ENDIF
      PMOM=XMEAN/XVAR
      IF(PSV.EQ.CPUMIN)THEN
        PKSV=PMOM
      ENDIF
!
!     NOW COMPUTE MAXIMUM LIKELIHOOD ESTIMATES FOR K
!     ASSUMED UNKNOWN CASE.
!
      DXBAR=DBLE(XMEAN)
      IINDX=MAXNXT/2
      IF(N.LE.IINDX)THEN
        IWD=0
        NSAMP=0
        DO 2110 I=1,N
          DTEMP(I)=X(I)
          DTEMP(IINDX+I)=Y(I)
          NSAMP=NSAMP+INT(Y(I)+0.1)
 2110   CONTINUE
      ELSE
        IERFLG=99
        GO TO 9000
      ENDIF
!
      DXSTRT=DBLE(AKSV)
      DINC=MAX(1.0D0,DXSTRT/25.0D0)
      DAE=0.000001D0
      DRE=DAE
      IFLAG=0
      DXLOW=MAX(DXSTRT - DINC,0.00001D0)
      DXUP=DXSTRT + DINC
      ITBRAC=0
!
 3105 CONTINUE
      XLOWSV=DXLOW
      XUPSV=DXUP
      CALL DFZER2(NBFUN2,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
!
      IF(IFLAG.EQ.4 .AND. ITBRAC.LE.200)THEN
        DXLOW=MAX(0.00001D0,XLOWSV-DINC)
        DXUP=XUPSV+DINC
        ITBRAC=ITBRAC+1
        GO TO 3105
      ENDIF
!
      IERFLG=IFLAG
!
      AKML=REAL(DXLOW)
      PML=AKML/(XMEAN + AKML)
      IF(AKML.GT.1.0)THEN
        PMLBC=(AKML-1.0)/(XMEAN + AKML - 1.0)
      ELSE
        PMLBC=0.0
      ENDIF
!
!     COMPUTE LOCAL FISHER INFORMATION MATRIX
!
      AN=REAL(NSAMP)
      FISH(1,1)=AN*AKML/(PML*PML*(1.0-PML))
      FISH(2,1)=-AN/PML
      FISH(1,2)=FISH(2,1)
      DN=DBLE(NSAMP)
      DTERM1=DN*TRIGAM(DBLE(AKML),IFAULT)
      DSUM1=0.0D0
      DO 3200 I=1,N
        DVAL=DBLE(X(I))
        DFREQ=DBLE(Y(I))
        DSUM1=DSUM1 + DFREQ*TRIGAM(DVAL+DBLE(AKML),IFAULT)
 3200 CONTINUE
      FISH(2,2)=REAL(DTERM1 - DSUM1)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3211)
 3211   FORMAT('****** NBML1: AFTER COMPUTE FISHER INFORMATION MATRIX')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3214)DSUM1,DTERM1
 3214   FORMAT('DSUM1,DTERM1 = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3215)FISH(1,1),FISH(2,1),FISH(2,2)
 3215   FORMAT('FISH(1,1),FISH(2,1),FISH(2,2) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      NDIM=2
      CALL SGECO(FISH,NDIM,NDIM,ITEMP,RCOND,XTEMP)
      IJOB=1
      CALL SGEDI(FISH,NDIM,NDIM,ITEMP,XTEMP,XTEMP(MAXNXT/2),IJOB)
      DO 3230 J=1,NDIM
        DO 3240 I=1,NDIM
          COV(I,J)=FISH(I,J)
 3240   CONTINUE
 3230 CONTINUE
      PSE=0.0
      IF(COV(1,1).GE.0.0)PSE=SQRT(COV(1,1))
      AKSE=0.0
      IF(COV(2,2).GE.0.0)AKSE=SQRT(COV(2,2))
      COVSE=0.0
      IF(COV(2,1).GE.0.0)COVSE=SQRT(COV(2,1))
!
      DO 3260 I=1,NUMALP
!
        ALP=ALPHA(I)
        P1=ALP/2.0
        P2=1.0-(ALP/2.0)
        CALL NORPPF(P1,APPF1)
        CALL NORPPF(P2,APPF2)
        ALOWP1(I)=PML + APPF1*PSE
        IF(ALOWP1(I).LT.0.0)ALOWP1(I)=0.0
        AUPPP1(I)=PML + APPF2*PSE
        IF(AUPPP1(I).GE.1.0)AUPPP1(I)=1.0
        ALOWK1(I)=AKML + APPF1*AKSE
        IF(ALOWK1(I).LT.0.0)ALOWK1(I)=0.0
        AUPPK1(I)=AKML + APPF2*AKSE
!
 3260 CONTINUE
      NUMOUT=NUMALP
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'BML3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NBML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)PML,PMLBC,AKML
 9013   FORMAT('PML,PMLBC,AKML = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NBML3
      SUBROUTINE NBPDF(X,P,AN,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X FOR
!              THE NEGATIVE BINOMIAL DISTRIBUTION WITH DOUBLE
!              PRECISION 'BERNOULLI PROBABILITY' PARAMETER = P,
!              AND DOUBLE PRECISION 'NUMBER OF SUCCESSES IN
!              BERNOULLI TRIALS' PARAMETER = N.  THE NEGATIVE
!              BINOMIAL DISTRIBUTION USED HEREIN HAS MEAN = N*(1-P)/P
!              AND STANDARD DEVIATION = SQRT(N*(1-P)/(P*P))).
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE
!              INTEGER X--X = 0, 1, 2, ... .  THIS DISTRIBUTION HAS
!              THE PROBABILITY MASS FUNCTION
!
!                  p(X;P,N) = C(N+X-1,N) * P**N * (1-P)**X.
!
!              WHERE C(N+X-1,N) IS THE COMBINATORIAL FUNCTION
!              EQUALING THE NUMBER OF COMBINATIONS OF N+X-1 ITEMS
!              TAKEN N AT A TIME.  THE NEGATIVE BINOMIAL DISTRIBUTION
!              IS THE DISTRIBUTION OF THE NUMBER OF FAILURES BEFORE
!              OBTAINING N SUCCESSES IN AN INDEFINITE SEQUENCE OF
!              BERNOULLI (0,1) CTRIALS WHERE THE PROBABILITY OF
!              SUCCESS IN A SINGLE TRIAL = P.
!
!              THE NEGATIVE BINOMIAL CAN BE EXTENDED TO THE
!              CASE WHERE N IS POSITIVE REAL NUMBER (I.E., NOT
!              RESTRICTED TO AN INTEGER).  IN THAT CASE, THE
!              PROBABILITY FUNCTION IS:
!
!              F(X) = P**N * (1-P)**X * GAMMA(N+X)/(GAMMA(N)*X!)
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.  X
!                                SHOULD BE A NON-NEGATIVE INTEGER.
!                     --P      = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER
!                                FOR THE NEGATIVE BINOMIAL
!                                DISTRIBUTION.  0 <= P < 1.
!                     --N      = THE DOUBLE PRECISION VALUE OF THE
!                                'NUMBER OF SUCCESSES IN BERNOULLI
!                                TRIALS' PARAMETER.  N > 0.
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY MASS
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS FUNCTION VALUE
!             PDF FOR THE NEGATIVE BINOMIAL DISTRIBUTION WITH
!             PARAMETERS P AND N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE AND INTEGRAL-VALUED.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY) AND
!                   1.0 (INCLUSIVELY).
!                 --N SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BINRAW.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 945, FORMULAE 26.5.24 AND
!                 26.5.28, AND PAGE 929.
!               --JOHNSON, KOTZ, AND KEMP, "DISCRETE UNIVARIATE
!                 DISTRIBUTIONS", SECOND EDITION, 1992.
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION, 2001.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGES 130-131.
!               --WILLIAMSON AND BRETHERTON, TABLES OF
!                 THE NEGATIVE BINOMIAL PROBABILITY
!                 DISTRIBUTION, 1963.
!               --OWEN, HANDBOOK OF STATISTICAL
!                 TABLES, 1962, PAGE 304.
!               --CATHERINE LOADER (2000), "FAST AND ACCURATE COMPUTATION
!                 OF BINOMIAL PROBABILITIES", BELL LABS?
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/3
!     ORIGINAL VERSION--MARCH     2004.
!     UPDATED         --MARCH     2009. USE CATHERINE LOADER ALGORITHM
!                                       (THIS IS IMPLEMENTED IN THE
!                                       BINRAW ROUTINE, WHICH IS A
!                                       FORTRAN IMPLEMENTATION OF THE
!                                       ORIGINAL C CODES OF LOADER)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA EPS/0.0000001D0/
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0D0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0D0.OR.P.GT.1.0D0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO NBPDF IS OUTSIDE ',   &
               'THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0D0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO NBPDF IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AN.LT.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE THIRD ARGUMENT TO NBPDF IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AN
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      IX=INT(X+EPS)
      Q=1.0D0 - P
      ILOG=0
!
      CALL BINRAW(AN,P,Q,DBLE(IX)+AN,ANS,ILOG)
      DP=AN/(AN+X)
      IF(ILOG.EQ.1)THEN
        PDF=LOG(DP)+ANS
      ELSE
        PDF=DP*ANS
      ENDIF
!
 9000 CONTINUE
      RETURN
!
      END SUBROUTINE NBPDF
      SUBROUTINE NBPPF(P,PPAR,AN,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION VALUE
!              AT THE DOUBLE PRECISION VALUE P FOR THE NEGATIVE BINOMIAL
!              DISTRIBUTION WITH DOUBLE PRECISION 'BERNOULLI PROBABILITY'
!              PARAMETER = PPAR, AND DOUBLE PRECISION 'NUMBER OF
!              SUCCESSES IN BERNOULLI TRIALS' PARAMETER = N.  THE
!              NEGATIVE BINOMIAL DISTRIBUTION USED HEREIN HAS
!              MEAN = N*(1-PPAR)/PPAR AND STANDARD DEVIATION =
!              SQRT(N*(1-PPAR)/(PPAR*PPAR))).  THIS DISTRIBUTION IS DEFINED
!              FOR ALL NON-NEGATIVE INTEGER X--X = 0, 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY MASS FUNCTION
!
!                  p(X;P,N) = C(N+X-1,N) * P**N * (1-P)**X.
!
!              WHERE C(N+X-1,N) IS THE COMBINATORIAL FUNCTION
!              EQUALING THE NUMBER OF COMBINATIONS OF N+X-1 ITEMS
!              TAKEN N AT A TIME.  THE NEGATIVE BINOMIAL DISTRIBUTION
!              IS THE DISTRIBUTION OF THE NUMBER OF FAILURES BEFORE
!              OBTAINING N SUCCESSES IN AN INDEFINITE SEQUENCE OF
!              BERNOULLI (0,1) CTRIALS WHERE THE PROBABILITY OF
!              SUCCESS IN A SINGLE TRIAL = P.
!
!              THE NEGATIVE BINOMIAL CAN BE EXTENDED TO THE
!              CASE WHERE N IS POSITIVE REAL NUMBER (I.E., NOT
!              RESTRICTED TO AN INTEGER).  IN THAT CASE, THE
!              PROBABILITY FUNCTION IS:
!
!              F(X) = P**N * (1-P)**X * GAMMA(N+X)/(GAMMA(N)*X!)
!
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE (BETWEEN
!                                0.0 (INCLUSIVELY) AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT FUNCTION IS
!                                TO BE EVALUATED.
!                     --PPAR   = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER.
!                     --AN     = THE DOUBLE PRECISION VALUE OF THE
!                                'NUMBER OF SUCCESSES IN BERNOULLI
!                                TRIALS' PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE PPF
!             FOR THE NEGATIVE BINOMIAL DISTRIBUTION WITH PARAMETERS
!             PPAR AND AN.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--PPAR SHOULD BE BETWEEN 0.0 (EXCLUSIVELY) AND
!                   1.0 (EXCLUSIVELY).
!                 --AN SHOULD BE A POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPPF, NBCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT, EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION AND DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT FROM THIS DISCRETE
!              DISTRIBUTION PERCENT POINT FUNCTION SUBROUTINE MUST
!              NECESSARILY BE A DISCRETE INTEGER VALUE, THE OUTPUT
!              VARIABLE PPF IS DOUBLE PRECISION IN MODE.
!     REFERENCES--JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 122-142,
!                 ESPECIALLY PAGE 127, FORMULA 22.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 92-95.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGES 130-131.
!               --WILLIAMSON AND BRETHERTON, TABLES OF
!                 THE NEGATIVE BINOMIAL PROBABILITY
!                 DISTRIBUTION, 1963.
!               --OWEN, HANDBOOK OF STATISTICAL
!                 TABLES, 1962, PAGE 304.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     2004. EXTENDED TO SUPPORT
!                                       NON-INTEGER VALUES FOR N
!     UPDATED         --MARCH     2009. CONVERT TO DOUBLE PRECISION
!     UPDATED         --MARCH     2009. IMPROVED INITIAL APPROXIMATION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
      IF(P.LT.0.0D0.OR.P.GE.1.0D0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST TO NBPPF IS OUTSIDE ',   &
               'THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(PPAR.LE.0.0D0.OR.PPAR.GT.1.0D0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO NBPPF IS OUTSIDE ',   &
               'THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PPAR
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AN.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO NBPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AN
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      N=INT(AN+0.000001D0)
      DPPAR=PPAR
      PPF=0.0D0
      IX0=0
      IX1=0
      IX2=0
      P0=0.0D0
      P1=0.0D0
      P2=0.0D0
!
!     TREAT CERTAIN SPECIAL CASES IMMEDIATELY--
!     1) P = 0.0
!     2) P = 0.5 AND PPAR = 0.5
!     3) PPF = 0
!     4) PPAR = 0
!
      IF(P.EQ.0.0D0)THEN
        PPF=0.0D0
        GO TO 9000
      ELSEIF(PPAR.EQ.1.0D0)THEN
        PPF=0.0D0
        GO TO 9000
      ELSEIF(P.EQ.0.5D0.AND.PPAR.EQ.0.5D0)THEN
        PPF=DBLE(N-1)
        GO TO 9000
      ELSE
        PF0=PPAR**AN
        IF(P.LE.PF0)THEN
          PPF=0.0D0
          GO TO 9000
        ENDIF
      ENDIF
!
!     DETERMINE AN INITIAL APPROXIMATION TO THE NEGATIVE BINOMIAL
!     PERCENT POINT BY USE OF THE HYPERBOLIC ARCSIN
!     TRANSFORMATION OF THE NEGATIVE BINOMIAL
!     TO APPROXIMATE NORMALITY.
!     (SEE JOHNSON AND KOTZ, DISCRETE DISTRIBUTIONS,
!     PAGE 127, FORMULA 22).
!
      AMEAN=AN*(1.0D0-PPAR)/PPAR
      SD=SQRT(AN*(1.0D0-PPAR)/(PPAR*PPAR))
      ARG=SQRT((AMEAN+0.375D0)/(AN-0.75D0))
      ARCSH=LOG(ARG+SQRT(ARG*ARG+1.0D0))
      YMEAN=(SQRT(AN-0.5D0))*ARCSH
      YSD=0.5D0
      CALL NODPPF(P,ZPPF)
      YPPF=YMEAN+ZPPF*YSD
      ARG=YPPF/SQRT(AN-0.5D0)
      E=EXP(ARG)
      SINH=(E-1.0D0/E)/2.0D0
      X2=-0.375D0+(AN-0.75D0)*SINH*SINH
      X2=X2+0.5D0
      IX2=INT(X2)
!
!     CHECK AND MODIFY (IF NECESSARY) THIS INITIAL
!     ESTIMATE OF THE PERCENT POINT
!     TO ASSURE THAT IT BE NON-NEGATIVE.
!
      IF(IX2.LT.0)IX2=0
!
!     DETERMINE UPPER AND LOWER BOUNDS ON THE DESIRED
!     PERCENT POINT BY ITERATING OUT (BOTH BELOW AND ABOVE)
!     FROM THE ORIGINAL APPROXIMATION AT STEPS
!     OF 1 STANDARD DEVIATION.
!     THE RESULTING BOUNDS WILL BE AT MOST
!     1 STANDARD DEVIATION APART.
!
      IX0=0
      IX1=INT(10.0D0**7 + 0.01D0)
      ISD=INT(SD+1.0D0)
      X2=DBLE(IX2)
      CALL NBCDF(X2,PPAR,AN,P2)
!
      IF(P2.LT.P)GO TO 210
      GO TO 250
!
  210 CONTINUE
      IX0=IX2
      I=1
  215 CONTINUE
      IX2=IX0+ISD
      IF(IX2.GE.IX1)GO TO 275
      X2=IX2
      CALL NBCDF(X2,PPAR,AN,P2)
      IF(P2.GE.P)GO TO 230
      IX0=IX2
      I=I+1
      IF(I.LE.1000000)GO TO 215
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,222)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  230 IX1=IX2
      GO TO 275
!
  250 CONTINUE
      IX1=IX2
      I=1
  255 CONTINUE
      IX2=IX1-ISD
      IF(IX2.LE.IX0)GO TO 275
      X2=IX2
      CALL NBCDF(X2,PPAR,AN,P2)
      IF(P2.LT.P)GO TO 270
      IX1=IX2
      I=I+1
      IF(I.LE.1000000)GO TO 255
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,262)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  270 IX0=IX2
!
  275 IF(IX0.EQ.IX1)GO TO 280
      GO TO 295
  280 IF(IX0.EQ.0)GO TO 285
      IF(IX0.EQ.N)GO TO 290
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,282)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  285 IX1=IX1+1
      GO TO 295
  290 IX0=IX0-1
  295 CONTINUE
!
!     COMPUTE NEGATIVE BINOMIAL PROBABILITIES FOR THE
!     DERIVED LOWER AND UPPER BOUNDS.
!
      X0=IX0
      X1=IX1
      CALL NBCDF(X0,PPAR,AN,P0)
      CALL NBCDF(X1,PPAR,AN,P1)
!
!     CHECK THE PROBABILITIES FOR PROPER ORDERING
!
      IF(P0.LT.P.AND.P.LE.P1)GO TO 490
      IF(P0.EQ.P)GO TO 410
      IF(P1.EQ.P)GO TO 420
      IF(P0.GT.P1)GO TO 430
      IF(P0.GT.P)GO TO 440
      IF(P1.LT.P)GO TO 450
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,401)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  410 PPF=IX0
      GO TO 9000
  420 PPF=IX1
      GO TO 9000
  430 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,431)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  440 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,441)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  450 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,451)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  490 CONTINUE
!
!     THE STOPPING CRITERION IS THAT THE LOWER BOUND
!     AND UPPER BOUND ARE EXACTLY 1 UNIT APART.
!     CHECK TO SEE IF IX1 = IX0 + 1;
!     IF SO, THE ITERATIONS ARE COMPLETE;
!     IF NOT, THEN BISECT, COMPUTE PROBABILIIES,
!     CHECK PROBABILITIES, AND CONTINUE ITERATING
!     UNTIL IX1 = IX0 + 1.
!
  300 IX0P1=IX0+1
      IF(IX1.EQ.IX0P1)GO TO 690
      IX2=(IX0+IX1)/2
      IF(IX2.EQ.IX0)GO TO 610
      IF(IX2.EQ.IX1)GO TO 620
      X2=IX2
      CALL NBCDF(X2,PPAR,AN,P2)
      IF(P0.LT.P2.AND.P2.LT.P1)GO TO 630
      IF(P2.LE.P0)GO TO 640
      IF(P2.GE.P1)GO TO 650
  610 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,611)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  620 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,611)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  630 IF(P2.LE.P)GO TO 635
      IX1=IX2
      P1=P2
      GO TO 300
  635 IX0=IX2
      P0=P2
      GO TO 300
  640 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,641)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  650 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,651)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  690 PPF=IX1
      IF(P0.EQ.P)PPF=IX0
      GO TO 9000
!
  950 WRITE(ICOUT,240)IX0,P0
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,241)IX1,P1
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,242)IX2,P2
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,244)P
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,245)PPAR,N
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
  222 FORMAT('NO UPPER BOUND FOUND AFTER 10**7 ITERATIONS')
  240 FORMAT('IX0  = ',I8,10X,'P0 = ',F14.7)
  241 FORMAT('IX1  = ',I8,10X,'P1 = ',F14.7)
  242 FORMAT('IX2  = ',I8,10X,'P2 = ',F14.7)
  244 FORMAT('P    = ',F14.7)
  245 FORMAT('PPAR = ',F14.7,10X,'N  = ',I8)
  249 FORMAT('***** INTERNAL ERROR IN NBPPF  SUBROUTINE *****')
  262 FORMAT('NO LOWER BOUND FOUND AFTER 10**7 ITERATIONS')
  282 FORMAT('LOWER AND UPPER BOUND IDENTICAL')
  401 FORMAT('IMPOSSIBLE BRANCH CONDITION ENCOUNTERED')
  431 FORMAT('LOWER BOUND PROBABILITY (P0) GREATER THAN ',   &
       'UPPER BOUND PROBABILITY (P1)')
  441 FORMAT('LOWER BOUND PROBABILITY (P0) GREATER THAN ',   &
       21HINPUT PROBABILITY (P))
  451 FORMAT('UPPER BOUND PROBABILITY (P1) LESS    THAN ',   &
       'INPUT PROBABILITY (P)')
  611 FORMAT('BISECTION VALUE (X2) = LOWER BOUND (X0)')
!C621 FORMAT('BISECTION VALUE (X2) = UPPER BOUND (X1)')
  641 FORMAT('BISECTION VALUE PROBABILITY (P2) ',   &
       'LESS THAN LOWER BOUND PROBABILITY (P0)')
  651 FORMAT('BISECTION VALUE PROBABILITY (P2) ',   &
       'GREATER THAN UPPER BOUND PROBABILITY (P1)')
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NBPPF
      SUBROUTINE NBRAN(N,P,AK,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE NEGATIVE BINOMIAL DISTRIBUTION
!              WITH SINGLE PRECISION 'BERNOULLI PROBABILITY'
!              PARAMETER = P,
!              AND INTEGER 'NUMBER OF SUCCESSES IN BERNOULLI TRIALS'
!              PARAMETER = K.
!              THE NEGATIVE BINOMIAL DISTRIBUTION USED
!              HEREIN HAS MEAN = K*(1-P)/P
!              AND STANDARD DEVIATION = SQRT(K*(1-P)/(P*P))).
!              THIS DISTRIBUTION IS DEFINED FOR
!              ALL NON-NEGATIVE INTEGER X--X = 0, 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = C(K+X-1,K) * P**K * (1-P)**X.
!              WHERE C(K+X-1,K) IS THE COMBINATORIAL FUNCTION
!              EQUALING THE NUMBER OF COMBINATIONS OF K+X-1 ITEMS
!              TAKEN K AT A TIME.
!              THE NEGATIVE BINOMIAL DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF FAILURES
!              BEFORE OBTAINING K SUCCESSES IN AN
!              INDEFINITE SEQUENCE OF BERNOULLI (0,1)
!              TRIALS WHERE THE PROBABILITY OF SUCCESS
!              IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE 'BERNOULLI PROBABILITY'
!                                PARAMETER FOR THE NEGATIVE BINOMIAL
!                                DISTRIBUTION.
!                                P SHOULD BE BETWEEN
!                                0.0 (EXCLUSIVELY) AND
!                                1.0 (EXCLUSIVELY).
!                     --K      = THE INTEGER VALUE
!                                OF THE 'NUMBER OF SUCCESSES
!                                IN BERNOULLI TRIALS' PARAMETER.
!                                K SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE NEGATIVE BINOMIAL DISTRIBUTION
!             WITH 'BERNOULLI PROBABILITY' PARAMETER = P
!             AND 'NUMBER OF SUCCESSES IN BERNOULLI TRIALS'
!             PARAMETER = K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!                 --K SHOULD BE A POSITIVE INTEGER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, BINRAN, GEORAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE RANDOM NUMBER
!              GENERATOR MUST NECESSARILY BE A
!              SEQUENCE OF ***INTEGER*** VALUES,
!              THE OUTPUT VECTOR X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VECTORS FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 95.
!               --JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 122-142.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGES 130-131.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     2004. SUPPORT FOR NON-INTEGER K
!     UPDATED         --MARCH     2004. ALGORITHM FOR MODERATE TO
!                                       LARGE K APPEARS WRONG (STARTS
!                                       AT X>=K, I.E., BASED ON
!                                       ALTERNATIVE DEFINITION OF
!                                       NEGATIVE BINOMIAL.
!                                       REPLACE CURRENT ALGORITHM
!                                       WITH CODE FROM ALAN MILLER
!                                       BASED ON J. DAGPUNAR,
!                                       "PRINCIPLES OF RANDOM VARIATE
!                                       GENERATION", CLARENDON PRESS,
!                                       OXFORD, 1988.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL X(*)
!
!OLD  DIMENSION B(2)
!OLD  DIMENSION G(2)
!
      REAL H
      REAL Q
      REAL XTEMP
      REAL ST
      REAL AK
      REAL ULN
      REAL V
      REAL R(1)
      REAL S
      REAL Y
      REAL G
      INTEGER K
      INTEGER I
      INTEGER NTEMP
      INTEGER NUNI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE NUMBER OF REQUESTED NEGATIVE ',   &
               'BINOMIAL RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER FOR THE ',   &
               'NEGATIVE BINOMIAL IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AK.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER FOR THE ',   &
               'NEGATIVE BINOMIAL IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)K
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
!
!
!     REPLACE FOLLOWING ALGORITHM WITH ONE THAT CAN ACCOMODATE
!     REAL VALUES FOR K.
!
!     CHECK ON THE MAGNITUDE OF P,
!     AND BRANCH TO THE FASTER
!     GENERATION METHOD ACCORDINGLY.
!
!OLD  IF(P.LT.0.1)GO TO 450
!
!     IF P IS MODERATE OR LARGE,
!     GENERATE N NEGATIVE BINOMIAL NUMBERS
!     USING THE FACT THAT THE
!     WAITING TIME FOR K SUCCESSES IN
!     BERNOULLI TRIALS HAS A
!     NEGATIVE BINOMIAL DISTRIBUTION.
!
!OLD  DO100I=1,N
!OLD  ISUM=0
!OLD  J=1
!O150 CALL BINRAN(1,P,1,ISEED,B)
!OLD  IB=B(1)+0.5
!OLD  ISUM=ISUM+IB
!OLD  IF(ISUM.EQ.K)GO TO 250
!OLD  J=J+1
!OLD  GO TO 150
!O250 X(I)=J
!O100 CONTINUE
!OLD  RETURN
!
!     IF P IS SMALL,
!     GENERATE N NEGATIVE BINOMIAL NUMBERS
!     BY USING THE FACT THAT THE SUM
!     OF GEOMETRIC VARIATES IS A
!     NEGATIVE BINOMIAL VARIATE.
!
!O450 DO500I=1,N
!OLD  ISUM=0
!OLD  DO600J=1,K
!OLD  CALL GEORAN(1,P,ISEED,G)
!OLD  IG=G(1)+0.5
!OLD  ISUM=ISUM+IG
!O600 CONTINUE
!OLD  X(I)=ISUM
!O500 CONTINUE
!
!     THIS ALGORITHM REVERSES THE ROLE OF P AND Q AS
!     USED IN DATAPLOT.
!
      NUNI=1
      Q=P
      P2=1.0-Q
      H=0.7
!
      DO 600 I=1,N
!
        XTEMP=0.0
        ST=AK
!
        IF(P2.GT.H)THEN
          V=1.0/LOG(P2)
          K=INT(ST + 0.0000001)
          DO 610 ITEMP=1,K
  620       CONTINUE
            CALL UNIRAN(NUNI,ISEED,R)
            IF(R(1).LE.0.0)GO TO 620
            NTEMP=INT(V*LOG(R(1)))
            XTEMP=XTEMP+NTEMP
  610     CONTINUE
          ST=ST-K
        ENDIF
!
        S=0.0
        ULN=-LOG(R1MACH(1))
        IF(ST.GT.-ULN/LOG(Q))THEN
          WRITE(ICOUT,691)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,692)P2,AK
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
        Y=Q**ST
        G=ST
        CALL UNIRAN(NUNI,ISEED,R)
  630   CONTINUE
        IF(Y.LE.R(1))THEN
          R(1)=R(1)-Y
          S=S+1.0
          Y=Y*P2*G/S
          G=G+1.0
          GO TO 630
        ENDIF
        X(I)=XTEMP+S
  600 CONTINUE
!
  691 FORMAT('***** ERROR IN NEGATIVE BINOMIAL RANDOM NUMBERS--')
  692 FORMAT('      THE VALUE OF P (',F10.5,') IS TOO LARGE FOR THE ',   &
             'VALUE OF K (',F10.5,')')
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NBRAN
      SUBROUTINE NCBCDF(XSNGL, ASNGL, BSNGL, LAMBDS, CDF)
!
!     ALGORITHM AS226 APPL. STATIST. (1987) VOL. 36, NO. 2
!     Incorporates modification AS R84 from AS vol. 39, pp311-2, 1990
!
!     Returns the cumulative probability of X for the non-central beta
!     distribution with parameters A, B and non-centrality LAMBDA
!
!     Auxiliary routines required: DLNGAM - log-gamma function (ACM
!     291 or AS 245), and BETAIN - incomplete-beta function (AS 63)
!
      REAL  XSNGL, ASNGL, BSNGL, LAMBDS, CDF
      DOUBLE PRECISION A, AX, B, BETA, C, ERRBD, ERRMAX, GX, HALF,   &
                       LAMBDA, ONE, Q, SUMQ, TEMP, X, XJ, ZERO
      DOUBLE PRECISION BETANC, A0, X0, UALPHA
      DOUBLE PRECISION DLNGAM
      DOUBLE PRECISION DLBETA
      DOUBLE PRECISION DBETAI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!
!     Change ERRMAX and ITRMAX if desired ...
!     MAY 2004. Increase error criterion and number of iterations
!               (to get more accuracy for PDF function)
!
!CCCC DATA ERRMAX, ITRMAX /1.0D-6, 100/, UALPHA /5.0D0/
      DATA ERRMAX, ITRMAX /1.0D-8, 300/, UALPHA /5.0D0/
      DATA ZERO, HALF, ONE /0.0D0, 0.5D0, 1.0D0/
!
      A=DBLE(ASNGL)
      B=DBLE(BSNGL)
      LAMBDA=DBLE(LAMBDS)
      X=DBLE(XSNGL)
      CDF=0.0
!
      IF(A.LE.0.0 .OR. B.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)A
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)B
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(X.LT.0.D0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(X.GT.1.D0)THEN
        WRITE(ICOUT,401)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,402)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(LAMBDA.LT.0.D0)THEN
        WRITE(ICOUT,501)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,503)LAMBDS
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('***** ERROR--EITHER THE ALPHA OR BETA IS NON-POSITIVE.')
  103 FORMAT('      THE VALUE OF ALPHA IS ',E15.7)
  104 FORMAT('      THE VALUE OF BETA IS ',E15.7,'       ******')
  301 FORMAT('***** ERROR--THE INPUT ARGUMENT IS NON-POSITIVE.')
  302 FORMAT('      IT HAS THE VALUE ',G15.7)
  401 FORMAT('***** ERROR--THE INPUT ARGUMENT IS GREATER THAN 1.')
  402 FORMAT('      IT HAS THE VALUE ',G15.7)
  501 FORMAT('***** ERROR--THE NON-CENTRALITY PARAMETER IS NEGATIVE.')
  503 FORMAT('      THE VALUE OF LAMBDA IS ',G15.7)
!
      BETANC = X
      CDF=REAL(BETANC)
!
      IF (X .EQ. ZERO .OR. X .EQ. ONE) GO TO 9999
!
      C = LAMBDA * HALF
!
!     Initialize the series ...
!
      X0 = INT(MAX(C - UALPHA*SQRT(C), ZERO))
      A0 = A + X0
!CCCC BETA = DLNGAM(A0) + DLNGAM(B) -  DLNGAM(A0+B)
      BETA = DLBETA(A0,B)
      TEMP = DBETAI(X, A0, B)
      GX = EXP(A0 * LOG(X) + B * LOG(ONE - X) - BETA - LOG(A0))
      IF (A0 .GT. A) THEN
        Q = EXP(-C + X0*LOG(C) - DLNGAM(X0 + ONE))
      ELSE
        Q = EXP(-C)
      END IF
      XJ = ZERO
      AX = Q * TEMP
      SUMQ = ONE - Q
      BETANC = AX
!
!     Recur over subsequent terms until convergence is achieved...
!
   10 XJ = XJ + ONE
      TEMP = TEMP - GX
      GX = X * (A + B + XJ - ONE) * GX / (A + XJ)
      Q = Q * C / XJ
      SUMQ = SUMQ - Q
      AX = TEMP * Q
      BETANC = BETANC + AX
!
!     Check for convergence and act accordingly...
!
      ERRBD = (TEMP - GX) * SUMQ
      IF ((INT(XJ) .LT. ITRMAX) .AND. (ERRBD .GT. ERRMAX)) GO TO 10
      IF (ERRBD .GT. ERRMAX) THEN
        WRITE(ICOUT,701)
        CALL DPWRST('XXX','BUG ')
        CDF=REAL(BETANC)
        GO TO 9999
      ELSE
        CDF=REAL(BETANC)
        GO TO 9999
      ENDIF
  701 FORMAT('***** WARNING--THE BETCDF ROUTINE DID NOT CONVERGE.  ***')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCBCDF
      REAL FUNCTION NCBFU3(X)
!
!     PURPOSE--NCBPDF CALLS DIFF TO FIND A NUMERICAL DERIVATIVE
!              FOR THE NON-CENTRAL CUMULATIVE DISTRIBUTION FUNCTION.
!              NCBFU3 IS A FUNCTION THAT CALL NCBCDF.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE DERIVATIVE
!                                IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION FUNCTION VALUE NCBFU3.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NCBCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--APRIL     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL ALPHA
      REAL BETA
      REAL ALAMB
      COMMON/NCBCOM/ALPHA,BETA,ALAMB
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL NCBCDF(X,ALPHA,BETA,ALAMB,CDF)
      NCBFU3=CDF
!
      RETURN
      END FUNCTION NCBFU3
      SUBROUTINE NCBPDF(X, A, B, LAMBDA, PDF)
!
!     PURPOSE--PROBABILITY DENSITY FUNCTION FOR THE NON-CENTRAL
!              BETA DISTRIBUTION.  THE PROBABILITY DENSITY FUNCTION
!              IS COMPUTED BY COMPUTING THE NUMERICAL DERIVATIVE OF
!              THE CUMULATIVE DISTRIBUTION FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --LAMBDS = THE NON-CENTRALITY PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DIFF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--LENTH, "COMPUTING NONCENTRAL BETA PROBABILITIES",
!                 APPLIED STATISTICS, VOL. 39, NO. 2, 1987,
!                 PP. 241-244.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/4
!     ORIGINAL VERSION--APRIL     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL  X
      REAL  A
      REAL  B
      REAL  LAMBDA
      REAL  PDF
!
      REAL NCBFU3
      EXTERNAL NCBFU3
      REAL ALPHA
      REAL BETA
      REAL ALAMB
      COMMON/NCBCOM/ALPHA,BETA,ALAMB
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      PDF=0.0
!
      IF(A.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(B.LE.0.0)THEN
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)B
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(LAMBDA.LT.0.0)THEN
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)LAMBDA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(X.LT.0.0 .OR. X.GT.1.0)THEN
        WRITE(ICOUT,105)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER FOR THE ',   &
             'NON-CENTRAL BETA PDF IS NON-POSITIVE.')
  102 FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER FOR THE ',   &
             'NON-CENTRAL BETA PDF IS NON-POSITIVE.')
  103 FORMAT('***** ERROR--THE NON-CENTRALITY PARAMETER FOR THE ',   &
             'NON-CENTRAL BETA PDF IS NEGATIVE.')
  104 FORMAT('      THE VALUE OF THE PARAMETER IS ',G15.7)
  105 FORMAT('***** ERROR--THE INPUT ARGUMENT FOR THE NON-CENTRAL ',   &
             'BETA PDF IS OUTSIDE THE (0,1) INTERVAL')
!
!  USE NON-CENTRAL F PDF FUNCTION
!
!  NOTE: THIS RELATIONSHIP APPLIES TO CDF FUNCTION, NOT CLEAR
!        THAT IT APPLIES TO PDF (DO NOT GET CONSISTENT ANSWERS).
!
!CCCC DF2=2.0*B
!CCCC DF2=2.0*B
!CCCC XTEMP=X*DF2/(DF1 - X*DF1)
!CCCC CALL NCFPDF(XTEMP,DF1,DF2,ALAMB,PDF)
!CCCC GO TO 9999
!
!  FIND NUMERIC DERIVATIVE OF CDF ROUTINE
!
      IFAIL=0
      IORD=1
      EPS=0.001
      ACCUR=0.0
      IFAIL=0
      X0 = X
      XMIN=0.0
      XMAX=1.0
      ALPHA=A
      BETA=B
      ALAMB=LAMBDA
!
      CALL DIFF(IORD,X0,XMIN,XMAX,NCBFU3,EPS,ACCUR,PDF,ERROR,IFAIL)
!
      IF(IFAIL.EQ.1)THEN
  999     FORMAT(1X)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,301)
  301   FORMAT('***** WARNING IN NUMERICAL DERIVATIVE FOR NCBPDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)
  303   FORMAT('      THE ESTIMATED ERROR IN THE RESULT EXCEEDS THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,305)
  305   FORMAT('      REQUESTED ERROR, BUT THE MOST ACCURATE RESULT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,307)
  307   FORMAT('      POSSIBLE HAS BEEN RETURNED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFAIL.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,311)
  311   FORMAT('***** ERROR IN NUMERICAL DERIVATIVE FOR NCBPDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,313)
  313   FORMAT('      ERROR IN THE INPUT TO THE DIFF ROUTINE.')
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ELSEIF(IFAIL.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,321)
  321   FORMAT('***** ERROR IN NUMERICAL DERIVATIVE FOR NCBPDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,323)
  323   FORMAT('      THE INTERVAL FOR DIFFERENTIATION, (',G15.7,   &
               ',',G15.7,')')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,325)
  325   FORMAT('      IS TOO SMALL.')
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
!
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCBPDF
      SUBROUTINE NCBPPF(P,ALPHA,BETA,LAMBDA,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE NON-CENTRAL BETA
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JULY      1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!CCCC DOUBLE PRECISION DCDF
!CCCC DOUBLE PRECISION DALPHA
!CCCC DOUBLE PRECISION DBETA
!CCCC DOUBLE PRECISION DX
!CCCC DOUBLE PRECISION DBETAI
      REAL LAMBDA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.0001/
      DATA SIG /1.0E-5/
      DATA ZERO /0./
      DATA MAXIT /100/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GT.1.0)GO TO 50
      IF(ALPHA.LE.0.0)GO TO 55
      IF(BETA.LE.0.0)GO TO 60
      IF(LAMBDA.LT.0.0)GO TO 70
      GO TO 90
   50 WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      RETURN
   55 WRITE(ICOUT,11)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)ALPHA
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      RETURN
   60 WRITE(ICOUT,25)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)BETA
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      GO TO 9999
   70 WRITE(ICOUT,35)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)LAMBDA
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      GO TO 9999
!
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
             'NCBPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
             'NCBPPF IS NON-POSITIVE')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
             ' NCBPPF IS NON-POSITIVE')
   35 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO ',   &
             'NCBPPF SUBROUTINE IS NEGATIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
   90 CONTINUE
!
      A = ALPHA
      B = BETA
!
      IERR=0
      IC = 0
      AB = A/B
      XL = 0.0
      XR = 1.0
      FXL = -P
      FXR = 1.0 - P
!CCCC INVALID P EXPLICITLY CHECKED FOR EARLIER.
      IF(FXL*FXR .GT. ZERO)GO TO 50
!
!  BISECTION METHOD
!
  105 CONTINUE
      X = (XL+XR)*0.5
      CALL NCBCDF(X,ALPHA,BETA,LAMBDA,CDF)
      P1=CDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** FATAL ERROR--NCBPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCBPPF
      SUBROUTINE NCBRAN(N,ALPHA,BETA,ALAMB,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE NON-CENTRAL BETA DISTRIBUTION WITH SHAPE
!              PARAMETERS ALPHA AND BETA AND NON-CENTRALITY
!              PARAMETER LAMBDA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST  SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                     --ALAMB  = THE SINGLE PRECISION VALUE OF THE
!                                NON-CENTRALITY PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE NON-CENTRAL BETA DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ALPHA, BETA, AND ALAMB.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA AND BETA  SHOULD BE POSITIVE.
!                 --ALAMB  SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NCCRAN, CHSRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS VOLUME 2", SECOND EDITION,
!                 1994, PAGES 502-503.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.5
!     ORIGINAL VERSION--MAY       2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF NON-CENTRAL BETA ',   &
      ' RANDOM NUMBERS IS NON-POSITIVE.')
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   16 FORMAT('***** ERROR--THE SHAPE PARAMETER ALPHA FOR THE ',   &
      'NON-CENTRAL BETA RANDOM NUMBERS IS NON-POSITIVE.')
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,26)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   26 FORMAT('***** ERROR--THE SHAPE PARAMETER BETA FOR THE ',   &
      'NON-CENTRAL BETA RANDOM NUMBERS IS NON-POSITIVE.')
      IF(ALAMB.LT.0.0)THEN
        WRITE(ICOUT,36)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAMB
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   36 FORMAT('***** ERROR--THE NON-CENTRALITY PARAMETER LAMBDA FOR ',   &
      'THE NON-CENTRAL BETA RANDOM NUMBERS IS NEGATIVE.')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     USE THE CENTRAL AND NON-CENTRAL CHI-SQUARE RANDOM NUMBER
!     ROUTINE TO GENERATE NON-CENTRAL BETA RANDOM NUMBERS.
!
!     NCB = NCCHISQ(NU1,LAMBDA)/(NCCHISQ(NU1,LAMBDA)+CHISQUARE(NU2))
!
      ANU1=ALPHA
      ANU2=BETA
      NTEMP=1
      DO 100 I=1,N
        CALL NCCRAN(NTEMP,ANU1,ALAMB,ISEED,XTEMP)
        TERM1=XTEMP(1)
        CALL CHSRAN(NTEMP,ANU2,ISEED,XTEMP)
        TERM2=XTEMP(1)
        X(I)=TERM1/(TERM1+TERM2)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NCBRAN
      SUBROUTINE NCVSRT( N, LOWER, UPPER, CORREL, INFIN, Y, INFIS,   &
                         A, B, INFI, COV, D, E )
!
!     Subroutine to sort integration limits.
!
      INTEGER N, INFI(*), INFIN(*), INFIS
      DOUBLE PRECISION   &
           A(*), B(*), COV(*), LOWER(*), UPPER(*), CORREL(*), Y(*), D, E
      INTEGER I, J, K, IJ, II, JMIN
      DOUBLE PRECISION SUMSQ, ZERO
      PARAMETER ( ZERO = 0 )
      DOUBLE PRECISION AJ, BJ, SUM, SQTWPI
      DOUBLE PRECISION CVDIAG, AMIN, BMIN, DMIN, EMIN, YL, YU
      PARAMETER ( SQTWPI = 2.50662827463100050240 )
!
      INCLUDE 'DPCOP2.INC'
!
      IJ = 0
      II = 0
      INFIS = 0
      AMIN=DBLE(CPUMIN)
      BMIN=DBLE(CPUMIN)
!
      DO 100 I = 1,N
         INFI(I) = INFIN(I)
         IF ( INFI(I) .LT. 0 ) THEN
            INFIS = INFIS + 1
         ELSE
            A(I) = 0
            B(I) = 0
            IF ( INFI(I) .NE. 0 ) A(I) = LOWER(I)
            IF ( INFI(I) .NE. 1 ) B(I) = UPPER(I)
         ENDIF
         DO 200 J = 1,I-1
            IJ = IJ + 1
            II = II + 1
            COV(IJ) = CORREL(II)
  200    CONTINUE
         IJ = IJ + 1
         COV(IJ) = 1
  100 CONTINUE
!
!     First move any doubly infinite limits to innermost positions
!
      IF ( INFIS .LT. N ) THEN
         DO 300 I = N,N-INFIS+1,-1
            IF ( INFI(I) .GE. 0 ) THEN
               DO 400 J = 1,I-1
                  IF ( INFI(J) .LT. 0 ) THEN
                     CALL RCSWAP(J, I, A, B, INFI, N, COV)
                     GO TO 300
                  ENDIF
 400           CONTINUE
            ENDIF
 300     CONTINUE
!
!     Sort remaining limits and determine Cholesky decomposition
!
         II = 0
         DO 500 I = 1,N-INFIS
!
!     Determine the integration limits for variable with minimum
!      expected probability and interchange that variable with Ith.
!
            EMIN = 1
            DMIN = 0
            JMIN = I
            CVDIAG = 0
            IJ = II
            DO 600 J = I, N-INFIS
               SUM = 0
               SUMSQ = 0
               DO 700 K = 1, I-1
                  SUM = SUM + COV(IJ+K)*Y(K)
                  SUMSQ = SUMSQ + COV(IJ+K)**2
  700          CONTINUE
               IJ = IJ + J
               SUMSQ = SQRT( MAX( COV(IJ)-SUMSQ, ZERO ) )
               IF ( SUMSQ .GT. 0 ) THEN
                  IF ( INFI(J) .NE. 0 ) AJ = ( A(J) - SUM )/SUMSQ
                  IF ( INFI(J) .NE. 1 ) BJ = ( B(J) - SUM )/SUMSQ
                  CALL LIMITS( AJ, BJ, INFI(J), D, E )
                  IF ( EMIN - DMIN .GE. E - D ) THEN
                     JMIN = J
                     IF ( INFI(J) .NE. 0 ) AMIN = AJ
                     IF ( INFI(J) .NE. 1 ) BMIN = BJ
                     DMIN = D
                     EMIN = E
                     CVDIAG = SUMSQ
                  ENDIF
               ENDIF
  600       CONTINUE
            IF ( JMIN .NE. I) CALL RCSWAP(I, JMIN, A, B, INFI, N, COV)
!
!     Compute Ith column of Cholesky factor.
!
            IJ = II + I
            COV(IJ) = CVDIAG
            DO 800 J = I+1, N-INFIS
               IF ( CVDIAG .GT. 0 ) THEN
                  SUM = COV(IJ+I)
                  DO 900 K = 1, I-1
                     SUM = SUM - COV(II+K)*COV(IJ+K)
  900             CONTINUE
                  COV(IJ+I) = SUM/CVDIAG
               ELSE
                  COV(IJ+I) = 0
               ENDIF
               IJ = IJ + J
  800       CONTINUE
!
!     Compute expected value for Ith integration variable and
!     scale Ith covariance matrix row and limits.
!
            IF ( CVDIAG .GT. 0 ) THEN
               IF ( EMIN .GT. DMIN + 1D-8 ) THEN
                  YL = 0
                  YU = 0
                  IF ( INFI(I) .NE. 0 ) YL = -EXP( -AMIN**2/2 )/SQTWPI
                  IF ( INFI(I) .NE. 1 ) YU = -EXP( -BMIN**2/2 )/SQTWPI
                  Y(I) = ( YU - YL )/( EMIN - DMIN )
               ELSE
                  IF ( INFI(I) .EQ. 0 ) Y(I) = BMIN
                  IF ( INFI(I) .EQ. 1 ) Y(I) = AMIN
                  IF ( INFI(I) .EQ. 2 ) Y(I) = ( AMIN + BMIN )/2
               END IF
               DO 910 J = 1,I
                  II = II + 1
                  COV(II) = COV(II)/CVDIAG
  910          CONTINUE
               IF ( INFI(I) .NE. 0 ) A(I) = A(I)/CVDIAG
               IF ( INFI(I) .NE. 1 ) B(I) = B(I)/CVDIAG
            ELSE
               Y(I) = 0
               II = II + I
            ENDIF
  500    CONTINUE
         CALL LIMITS( A(1), B(1), INFI(1), D, E)
      ENDIF
!
      RETURN
      END SUBROUTINE NCVSRT
      SUBROUTINE NCCCDF(X, DF, FL, CDF)
! UKC NETLIB DISTRIBUTION COPYRIGHT 1990 RSS
!
!
!<<<<<  Acquired in machine-readable form from 'Applied Statistics'
!<<<<<  algorithms editor, January 1983.
!
!
!        ALGORITHM AS 170  APPL. STATIST. (1981) VOL.30, NO.3
!
!        The non-central chi-squared distribution.
!
!     Auxiliary routines required: GAMMDS = AS147, ALOGAM = CACM 291.
!     See AS245 for an alternative to ALOGAM.
!
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DGAMIP
      DOUBLE PRECISION DARG1
!
      INCLUDE 'DPCOP2.INC'
!
!        TEST FOR ADMISSIBILITY OF ARGUMENTS
!
      IF (DF.LE.0.0) THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF (FL.LT.0.0)THEN
        WRITE(ICOUT,401)
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('***** ERROR--THE DEGREES OF FREEDOM PARAMETER FOR NCCCDF '   &
            ,'IS NON-POSITIVE. ****')
  301 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO NCCCDF IS ')
  302 FORMAT('      NON-POSITIVE.  IT HAS THE VALUE ',E15.7)
  401 FORMAT('***** ERROR--THE NON-CENTRALITY PARAMETER TO NCCCDF ',   &
             'IS NEGATIVE. ****')
!
!
      CDF = 0.0
      IF(X.EQ.0.0)GO TO 9999
      DF2 = 0.5*DF
      X2 = 0.5*X
!CCCC FXP = GAMMDS(X2,DF2,IFAULT)
      DARG1=DGAMIP(DBLE(DF2),DBLE(X2))
      FXP=REAL(DARG1)
      CALL NCCCHI(X2,DF2,FL,FXP,CDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCCCDF
      SUBROUTINE NCCCHI(X, DF, FL, FXC, CHI)
!
!        ALGORITHM AS 170.2  APPL. STATIST. (1981) VOL.30, NO.3
!
!        (ROUTINE USED BY NCCCDF AND NCCNCP)
      PARAMETER (ACC2 = 1.0E-8)
      DOUBLE PRECISION DGAMIP
      DOUBLE PRECISION DARG1
!
      CHI = FXC
      DF1 = DF
      FL2 = 0.5*FL
      C = 1.0
      T = 0.0
    1 CONTINUE
      T = T+1.0
      C = C*FL2/T
      DF1 = DF1+1.0
!CCCC TERM = C*GAMMDS(X, DF1, IFAULT)
      DARG1=DGAMIP(DBLE(DF1),DBLE(X))
      TERM = C*REAL(DARG1)
      CHI = CHI+TERM
      IF (TERM.GE.ACC2) GO TO 1
      CHI = CHI*EXP(-FL2)
!
      RETURN
      END SUBROUTINE NCCCHI
      SUBROUTINE NCCPDF(X, V, FL, PDF)
! UKC NETLIB DISTRIBUTION COPYRIGHT 1990 RSS
!
!
!        The non-central chi-squared probability density function.
!        USE THE FOLLOWING FORMULA ON PAGE 436 OF 2ND ED OF
!        VOL. 2 OF JOHNSON AND KOTZ.
!        F(X)=EXP(-(L+X)/2)*(1/2)*(X/V)**((V-2)/4)*I((V-2)/2)(SQRT(L*X))
!        WHERE I IS THE MODIFIED BESSEL FUNCTION.
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
!
      DOUBLE PRECISION DX, DL, DV, DPDF
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
      DOUBLE PRECISION DLNGAM
!
      DOUBLE PRECISION DTEMP1(1)
      REAL TEMP1(1)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!        TEST FOR ADMISSIBILITY OF ARGUMENTS
!
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF (V.LE.0.0) THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)V
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF (FL.LT.0.0)THEN
        WRITE(ICOUT,401)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)FL
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('***** ERROR IN NCCPDF--THE SECOND INPUT ARGUMENT ',   &
      'IS NON-POSITIVE')
  301 FORMAT('***** ERROR IN NCCPDF--THE FIRST INPUT ARGUMENT ',   &
      'IS NON-POSITIVE')
  401 FORMAT('***** ERROR IN NCCPDF--THE THIRD INPUT ARGUMENT ',   &
      'IS NON-POSITIVE')
   46 FORMAT('      THE ARGUMENT HAS THE VALUE ',E15.6)
!
!
      PDF = 0.0
      DX=DBLE(X)
      DL=DBLE(FL)
      DV=DBLE(V)
!
      IF(FL.EQ.0.0)THEN
        DTERM1=((DV-2.0D0)/2.0D0)*DLOG(DX)
        DTERM2=-DX/2.0D0
        DTERM3=(DV/2.0D0)*DLOG(2.0D0)
        DTERM4=DLNGAM(DV/2.0D0)
        DPDF=DEXP(DTERM1+DTERM2-DTERM3-DTERM4)
        PDF=REAL(DPDF)
        GO TO 9999
      ENDIF
!
      IF(DV.LT.2.0D0)GO TO 1000
!
      DTERM1=DSQRT(DL*DX)
      IF(DTERM1.LE.DLOG(D1MACH(2)))THEN
        DTERM2=-(DL+DX)/2.0D0+DLOG(0.5D0)+   &
               ((DV-2.0D0)/4.0D0)*DLOG(DX/DL)
        IARG1=1
        ISCALE=1
        DTERM5=(DV-2.0D0)/2.0D0
        CALL DBESI(DTERM1,DTERM5,ISCALE,IARG1,DTEMP1,NZERO)
        DTERM3=DTEMP1(1)
        DTERM3=DLOG(DTERM3)
        DTERM4=DTERM2+DTERM3
        IF(DTERM4.LE.-80.D0)THEN
          PDF=0.0
        ELSEIF(DTERM4.GE.80.D0)THEN
          WRITE(ICOUT,601)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,47)X
          CALL DPWRST('XXX','BUG ')
          PDF=LOG(R1MACH(2))
        ELSE
          DPDF=DEXP(DTERM4)
          PDF=SNGL(DPDF)
        ENDIF
      ELSE
        WRITE(ICOUT,501)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9999
  601 FORMAT('***** ERROR IN NCCPDF--OVERFLOW IN CALCULATION OF PDF' ,   &
      ' VALUE, PDF SET TO LOG OF LARGEST NUMBER.')
  501 FORMAT('***** ERROR IN NCCPDF--ARGUMENT TO LARGE FOR DBESI ',   &
      'ROUTINE, PDF SET TO 0')
   47 FORMAT('      THE ARGUMENT HAS THE VALUE ',E15.6)
!
!  CASE FOR V < 2 REQUIRE NEGATIVE ORDER OF MODIFIED BESSEL FUNCTION.
!  USE I(-v) = I(v) + (2/PI)*SIN(V*PI)*K(v)
!
 1000 CONTINUE
      DTERM1=DSQRT(DL*DX)
      IF(DTERM1.LE.DLOG(D1MACH(2)))THEN
        DTERM2=-(DL+DX)/2.0D0+DLOG(0.5D0)+   &
               ((DV-2.0D0)/4.0D0)*DLOG(DX/DL)
        IARG1=1
        ISCALE=1
        DTERM5=(DV-2.0D0)/2.0D0
        CALL DBESI(DTERM1,DABS(DTERM5),ISCALE,IARG1,DTEMP1,NZERO)
        DTERM3=DTEMP1(1)
        CALL BESK(SNGL(DTERM1),SNGL(DABS(DTERM5)),ISCALE,IARG1,TEMP1,   &
                  NZERO)
        TERM3=TEMP1(1)
        DTERM3=DTERM3+(2.0D0/DPI)*DSIN(DABS(DTERM5)*DPI)*DBLE(TERM3)
        DTERM3=DLOG(DTERM3)
        DTERM4=DTERM2+DTERM3
        IF(DTERM4.LE.-80.D0)THEN
          PDF=0.0
        ELSEIF(DTERM4.GE.80.D0)THEN
          WRITE(ICOUT,601)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,47)X
          CALL DPWRST('XXX','BUG ')
          PDF=LOG(R1MACH(2))
        ELSE
          DPDF=DEXP(DTERM4)
          PDF=SNGL(DPDF)
        ENDIF
      ELSE
        WRITE(ICOUT,501)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9999
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCCPDF
      SUBROUTINE NCCNCP(X, DF, FX, FL)
!
!        ALGORITHM AS 170.1  APPL.STATIST. (1981) VOL.30, NO.3
!
!        DEFINE ACCURACY AND INITIALIZE
!
!        N SHOULD BE SPECIFIED SUCH THAT ACC IS GREATER THAN
!        OR EQUAL TO (AU-AL)/2**N
!
      PARAMETER (ACC = 1.0E-6, N = 30)
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DGAMIP
      DOUBLE PRECISION DARG1
!
      INCLUDE 'DPCOP2.INC'
!
      AL = 0.0
      AINC = 80.0
      AU = 80.0
!
!        TEST FOR ADMISSIBILITY OF ARGUMENTS
!
      IF (DF.LE.0.0) THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF (FX.LE.0.0)THEN
        WRITE(ICOUT,401)
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('***** FATAL DIAGNOSTIC--THE DEGREES OF FREEDOM PARAMETER',   &
             ' IS NON-POSITIVE. ****')
  301 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT IS ')
  302 FORMAT('      NON-POSITIVE.  IT HAS THE VALUE ',E15.7)
  401 FORMAT('***** FATAL DIAGNOSTIC--THE CDF PARAMETER IS NEGATIVE.')
!
      DF2 = 0.5*DF
      X2 = 0.5*X
!CCCC FX1 = GAMMDS(X2,DF2,IFAULT)
      DARG1=DGAMIP(DBLE(DF2),DBLE(X2))
      FX1 = REAL(DARG1)
    1 CONTINUE
!CCC1 APROX = CHI(X2,DF2,AU,FX1)
      CALL NCCCHI (X2,DF2,AU,FX1,APROX)
      IF (FX.GT.APROX) GO TO  2
      IF (FX.LT.APROX) AL = AU
      AU = AU+AINC
      GO TO 1
!
    2 CONTINUE
      DO 3 J = 1,N
        FL = 0.5*(AL+AU)
!CCCC   APROX = CHI(X2, DF2, FL, FX1)
        CALL NCCCHI (X2,DF2,FL,FX1,APROX)
        IF (ABS(FX-APROX).LT.ACC) GO TO 9999
        IF (FX.LT.APROX) AL = FL
        IF (FX.GE.APROX) AU = FL
    3 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCCNCP
      SUBROUTINE NCCPPF(P,NU,DELTA,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE NON-CENTRAL CHI-SQUARE
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/9
!     ORIGINAL VERSION--SEPTEMBER 1994.
!     UPDATE          --MAY       2004. SOME UPDATES TO SPEED
!                                 CONVERGENCE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL NU
      DOUBLE PRECISION DGAMIP
      DOUBLE PRECISION DARG1
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA EPS /0.0001/
!CCCC DATA SIG /1.0E-5/
      DATA ZERO /0./
      DATA MAXIT /500/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO NCCPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(NU.LE.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO NCCPPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)NU
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DELTA.LT.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE THIRD ARGUMENT TO NCCPPF ',   &
               'IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DELTA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!  SPECIAL CASE.  FOR INTEGER NU AND DELTA = 0, USE CENTRAL CHI-SQUARE
!  ROUTINE.
!
      IF(DELTA.EQ.0.0)THEN
        NUINT=INT(NU+0.1)
        ANUINT=REAL(NUINT)
        IF(ABS(NU-ANUINT).LE.0.00001 .AND. NUINT.GE.1)THEN
          CALL CHSPPF(P,NUINT,PPF)
          GO TO 9999
        ENDIF
      ENDIF
!
!  FIND BRACKETING INTERVAL.  USE CORRESPONDING CENTRAL CHI-SQUARE
!  AS INITIAL GUESS, INCREMENTS OF 1 STANDARD DEVIATION AROUND IT
!  (SD = SQRT(2*(NU+2*DELTA))
!  AFTER SUCCESSFULLY FIND BRACKETING INTERVAL, THEN SWITCH TO
!  MORE EFFICIENT BISECTION METHOD.
!
!  5/2004. BETTER BRACKETING INTERVAL.  BASE ON MEAN, SD, AND VALUE OF P.
!          ALSO, FOR LOW VALUES OF NU AND MORE EXTREME VALUES OF P,
!          LOOSEN THE CONVERGENCE CRITIERION.  LEFT INVERVAL IS 0 (OR
!          0 + EPS)
!
      EPS=0.0001
      SIG=1.0E-5
!CCCC IF(NU.GE.20.0)THEN
!CCCC   EPS=0.0001
!CCCC   SIG=1.0E-5
!CCCC   IF(P.GT.0.95 .OR. P.LT.0.05)THEN
!CCCC     EPS=0.0001
!CCCC     SIG=1.0E-4
!CCCC   ENDIF
!CCCC ELSE
!CCCC   IF(P.GT.0.99 .OR. P.LT.0.01)THEN
!CCCC     EPS=0.0001
!CCCC     SIG=1.0E-5
!CCCC   ENDIF
!CCCC ENDIF
!
!CCCC NUINT=NU+0.5
!CCCC CALL CHSPPF(P,NUINT,XL)
      AMEAN=NU+DELTA
      SD=SQRT(2.0*(NU+2.0*DELTA))
      XINC=SD
!
      XL=0.0
      IF(P.LE.0.25)THEN
        XL=0.0
      ELSEIF(P.GT.0.25 .AND. P.LE.0.75)THEN
        XL=AMEAN
      ELSEIF(P.GT.0.75 .AND. P.LE.0.95)THEN
        XL=AMEAN+SD
      ELSE
        XL=AMEAN+2.0*SD
      ENDIF
!
      ICOUNT=0
      MAXCNT=100
!
   91 CONTINUE
      XR=XL+XINC
      IF(XL.LE.0.0)XL=0.0
      IF(XR.LE.0.0)XR=XL+XINC
!
      DF2 = 0.5*NU
      FL=DELTA
      IF(XL.LE.0.0000001)THEN
        CDFL=0.0
      ELSE
        X2 = 0.5*XL
        DARG1=DGAMIP(DBLE(DF2),DBLE(X2))
        FXP=REAL(DARG1)
        CALL NCCCHI(X2,DF2,FL,FXP,CDFL)
      ENDIF
      X2 = 0.5*XR
      DARG1=DGAMIP(DBLE(DF2),DBLE(X2))
      FXP=REAL(DARG1)
      CALL NCCCHI(X2,DF2,FL,FXP,CDFR)
!
!CCCC CALL NCCCDF(XL,NU,DELTA,CDFL)
!CCCC CALL NCCCDF(XR,NU,DELTA,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** FATAL ERROR--NCCPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL. *****')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -P
      FXR = 1.0 - P
  105 CONTINUE
      X = (XL+XR)*0.5
!
      IF(X.LE.0.0000001)THEN
        CDF=0.0
      ELSE
        X2 = 0.5*X
        DARG1=DGAMIP(DBLE(DF2),DBLE(X2))
        FXP=REAL(DARG1)
        CALL NCCCHI(X2,DF2,FL,FXP,CDF)
      ENDIF
!CCCC CALL NCCCDF(X,NU,DELTA,CDF)
      P1=CDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--NCCPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCCPPF
      SUBROUTINE NCCRAN(N,ANU,ALAMB,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE NON-CENTRAL CHI-SQUARED DISTRIBUTION
!              WITH DEGREES OF FREEDOM PARAMETER NU AND
!              NON-CENTRALITY PARAMETER LAMBDA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ANU    = THE DEGREES OF FREEDOM PARAMETER
!                     --ALAMB  = THE NON-CENTRALITY PARAMETER
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE NON-CENTRAL CHI-SQUARED DISTRIBUTION
!             WITH SHAPE PARAMETERS NU AND LANBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ANU SHOULD BE POSITIVE.
!                 --ALAMB SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORRAN, GAMRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/5
!     ORIGINAL VERSION--MAY       2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!CCCC DIMENSION XTEMP(1)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF NON-CENTRAL ',   &
               'CHI-SQUARE RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ANU.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE DEGREES OF FREEDOM PARAMETER FOR ',   &
               'NON-CENTRAL CHI-SQUARE RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)ANU
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALAMB.LT.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE NON-CENTRALITY PARAMETER FOR ',   &
               'NON-CENTRAL CHI-SQUARE RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)ALAMB
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
   48 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      IF(ALAMB.EQ.0.0)THEN
        CALL CHSRAN(N,ANU,ISEED,X)
      ELSE
        IF(ANU.LE.1.0)THEN
          CALL UNIRAN(N,ISEED,X)
          DO 1367 II=1,N
            ATEMP=X(II)
            CALL NCCPPF(ATEMP,ANU,ALAMB,PPF)
            X(II)=PPF
 1367     CONTINUE
        ELSE
!CCCC     NOTE: 5/2004.  USING PERCENT POINT METHOD SEEMS TO
!CCCC           GENERATE BETTER RANDOM NUMBERS THAN THE SUM OF
!CCCC           NORMALS METHOD.  IT IS SLOWER, BUT IT SEEMS TO
!CCCC           BE MORE ACCURATE.  ALSO, IT CAN HANDLE NON-INTEGER
!CCCC           VALUES OF NU.
!
          CALL UNIRAN(N,ISEED,X)
          DO 1369 II=1,N
            ATEMP=X(II)
            CALL NCCPPF(ATEMP,ANU,ALAMB,PPF)
            X(II)=PPF
 1369     CONTINUE
!CCCC     NUINT=INT(NU+0.5)
!CCCC     IF(NUINT.LT.1)NUINT=1
!CCCC     NTEMP=1
!CCCC     DO1365II=1,N
!CCCC       ASUM=0.0
!CCCC       DO1366J=1,NUINT
!CCCC         CALL NORRAN(NTEMP,ISEED,XTEMP)
!CCCC         ASUM=ASUM + (XTEMP(1) + (ALAMB/REAL(NUINT)))**2
!1365       CONTINUE
!CCCC       X(II)=ASUM
!1365     CONTINUE
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NCCRAN
      SUBROUTINE NCFCDF(X,NU1,NU2,LAMBDA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE NON-CENTRAL F DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM
!              PARAMETERS = NU1 AND NU2.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU1    = THE INTEGER DEGREES OF FREEDOM
!                                FOR THE NUMERATOR OF THE F RATIO.
!                                NU1 SHOULD BE POSITIVE.
!                     --NU2    = THE INTEGER DEGREES OF FREEDOM
!                                FOR THE DENOMINATOR OF THE F RATIO.
!                                NU2 SHOULD BE POSITIVE.
!                     --LAMBDA   NON-NEGATIVE NON-CENTRALITY PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE NON-CENTRAL F DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETERS = NU1 AND NU2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --NU1 SHOULD BE A POSITIVE INTEGER VARIABLE.
!                 --NU2 SHOULD BE A POSITIVE INTEGER VARIABLE.
!                 --LAMBDA SHOULD BE GREATER THAN OR EQUAL TO 0.
!     OTHER           SUBROUTINES NEEDED--NCBCDF,CHSCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DATAN.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ALGORITHM --USES THE NON-CENTRAL BETA DISTRIBUTION.
!     REFERENCES--"COMPUTING NON-CENTRAL BETA PROBABILITIES"
!                 RUSSELL LENTH, ALGORITHM AS 226 FROM APPLIED
!                 STATISTICS JOURNAL.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--94/9
!     ORIGINAL VERSION--SEPTEMBER 1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL NU1
      REAL NU2
      REAL LAMBDA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(NU1.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO NCFCDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(NU2.LE.0.0)THEN
        WRITE(ICOUT,23)
   23   FORMAT('***** ERROR--THE THIRD ARGUMENT TO NCFCDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO NCFCDF ',   &
               'IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(LAMBDA.LT.0.0)THEN
        WRITE(ICOUT,24)
   24   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO NCFCDF ',   &
               'IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
      TERM1=NU1*0.5
      TERM2=NU2*0.5
      TERM3=NU1*X/(NU1*X+NU2)
      CALL NCBCDF(TERM3,TERM1,TERM2,LAMBDA,CDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NCFCDF
      REAL FUNCTION NCFFU3(X)
!
!     PURPOSE--NCFPDF CALLS DIFF TO FIND A NUMERICAL DERIVATIVE
!              FOR THE NON-CENTRAL CUMULATIVE DISTRIBUTION FUNCTION.
!              NCFFU3 IS A FUNCTION THAT CALL NCFCDF.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE DERIVATIVE
!                                IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION FUNCTION VALUE NCFFU3.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NCBCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.5
!     ORIGINAL VERSION--MAY       2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL ANU1
      REAL ANU2
      REAL ALAMB
      COMMON/NCFCOM/ANU1,ANU2,ALAMB
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  NOTE: NCFCDF CALLS NCBCDF.  PERFORM THE NEEDED PARAMETER TRANSLATION
!        AND CALL NCBCDF (I.E., SAVE A SUBROUTINE CALL).
!
!CCCC CALL NCFCDF(X,ANU1,ANU2,,ALAMB,CDF)
      TERM1=ANU1*0.5
      TERM2=ANU2*0.5
      TERM3=ANU1*X/(ANU1*X+ANU2)
      CALL NCBCDF(TERM3,TERM1,TERM2,ALAMB,CDF)
      NCFFU3=CDF
!
      RETURN
      END FUNCTION NCFFU3
      SUBROUTINE NCFPDF(X,NU1,NU2,LAMBDA,PDF)
!
!     PURPOSE--PROBABILITY DENSITY FUNCTION FOR THE NON-CENTRAL
!              T DISTRIBUTION.  THE PROBABILITY DENSITY FUNCTION
!              IS COMPUTED BY COMPUTING THE NUMERICAL DERIVATIVE OF
!              THE CUMULATIVE DISTRIBUTION FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ANU    = THE DEGREES OF FREEDOM SHAPE PARAMETER
!                     --DELTA  = THE FIRST NON-CENTRALITY SHAPE PARAMETER
!                     --LAMBDA = THE SECOND NON-CENTRALITY PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DIFF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/5
!     ORIGINAL VERSION--MAY       2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL  X
      REAL  NU1
      REAL  NU2
      REAL  LAMBDA
      REAL  PDF
!
      REAL NCFFU3
      EXTERNAL NCFFU3
      REAL ANU1
      REAL ANU2
      REAL ALAMB
      COMMON/NCFCOM/ANU1,ANU2,ALAMB
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      PDF=0.0
!
      IF(NU1.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)NU1
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('**** ERROR--THE FIRST DEGREES OF FREEDOM PARAMETER')
  102 FORMAT('     FOR NCFPDF IS NON-POSITIVE.  IT HAS THE VALUE ',   &
             E15.7)
!
      IF(NU2.LE.0.0)THEN
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)NU2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  103 FORMAT('**** ERROR--THE SECOND DEGREES OF FREEDOM PARAMETER')
  104 FORMAT('     FOR NCFPDF IS NON-POSITIVE.  IT HAS THE VALUE ',   &
             E15.7)
!
      IF(ALAMB.LT.0.0)THEN
        WRITE(ICOUT,303)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,304)ALAMB
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  303 FORMAT('**** ERROR--THE NON-CENTRALITY PARAMETER IS NEGATIVE.')
  304 FORMAT('     IT HAS THE VALUE ',E15.7)
!
!  FIND NUMERIC DERIVATIVE OF CDF ROUTINE
!
      IORD=1
      EPS=0.0001
      ACCUR=0.0
      IFAIL=0
      X0 = X
      XMIN=MAX(X0 - 50.0,0.0)
      XMAX=X0 + 50.0
      ANU1=NU1
      ANU2=NU2
      ALAMB=LAMBDA
!
      CALL DIFF(IORD,X0,XMIN,XMAX,NCFFU3,EPS,ACCUR,PDF,ERROR,IFAIL)
!
      IF(IFAIL.EQ.1)THEN
  999     FORMAT(1X)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,401)
  401   FORMAT('***** WARNING IN NUMERICAL DERIVATIVE FOR NCFPDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,403)
  403   FORMAT('      THE ESTIMATED ERROR IN THE RESULT EXCEEDS THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,405)
  405   FORMAT('      REQUESTED ERROR, BUT THE MOST ACCURATE RESULT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,407)
  407   FORMAT('      POSSIBLE HAS BEEN RETURNED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFAIL.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,411)
  411   FORMAT('***** ERROR IN NUMERICAL DERIVATIVE FOR NCFPDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,413)
  413   FORMAT('      ERROR IN THE INPUT TO THE DIFF ROUTINE.')
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ELSEIF(IFAIL.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,421)
  421   FORMAT('***** ERROR IN NUMERICAL DERIVATIVE FOR NCFPDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,423)
  423   FORMAT('      THE INTERVAL FOR DIFFERENTIATION, (',G15.7,   &
               ',',G15.7,')')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,425)
  425   FORMAT('      IS TOO SMALL.')
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCFPDF
      SUBROUTINE NCFPPF(P,NU1,NU2,DELTA,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE NON-CENTRAL F
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/9
!     ORIGINAL VERSION--SEPTEMBER 1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL NU1
      REAL NU2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.0001/
      DATA SIG /1.0E-5/
      DATA ZERO /0./
      DATA MAXIT /500/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO NCFPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(NU1.LT.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO NCFPPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)NU1
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(NU2.LT.0.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO NCFPPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)NU2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DELTA.LT.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO NCFPPF ',   &
               'IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DELTA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!  FIND BRACKETING INTERVAL.  USE CORRESPONDING CENTRAL F
!  AS INITIAL GUESS, INCREMENTS OF 100 AROUND IT.
!  AFTER SUCCESSFULLY FIND BRACKETING INTERVAL, THEN SWITCH TO
!  MORE EFFICIENT BISECTION METHOD.
!
      XINC=50.0
      NU1INT=INT(NU1+0.5)
      NU2INT=INT(NU2+0.5)
      CALL FPPF(P,NU1INT,NU2INT,XL)
      ICOUNT=0
      MAXCNT=10000
!
   91 CONTINUE
      XR=XL+XINC
      IF(XL.LE.0.0)XL=0.0
      IF(XR.LE.0.0)XR=XL+1.0
      CALL NCFCDF(XL,NU1,NU2,DELTA,CDFL)
      CALL NCFCDF(XR,NU1,NU2,DELTA,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** FATAL ERROR--NCFPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL. *****')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -P
      FXR = 1.0 - P
  105 CONTINUE
      X = (XL+XR)*0.5
      CALL NCFCDF(X,NU1,NU2,DELTA,CDF)
      P1=CDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--NCFPPF ROUTINE DID NOT CONVERGE.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCFPPF
      SUBROUTINE NCFRAN(N,ANU1,ANU2,ALAMB1,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE NON-CENTRAL F DISTRIBUTION WITH SHAPE
!              PARAMETERS ANU1 AND ANU2 AND NON-CENTRALITY
!              PARAMETER LAMBDA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ANU1   = THE SINGLE PRECISION VALUE OF THE
!                                FIRST  SHAPE PARAMETER.
!                     --ANU2   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                     --ALAMB1  = THE SINGLE PRECISION VALUE OF THE
!                                NON-CENTRALITY PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE NON-CENTRAL F DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ANU1, ANU2, AND ALAMB1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ANU1 AND ANU2  SHOULD BE POSITIVE.
!                 --ALAMB1  SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORRAN, CHSRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS VOLUME 2", SECOND EDITION,
!                 1994, PAGES 502-503.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.5
!     ORIGINAL VERSION--MAY       2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF NON-CENTRAL F ',   &
      ' RANDOM NUMBERS IS NON-POSITIVE.')
      IF(ANU1.LE.0.0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ANU1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   16 FORMAT('***** ERROR--THE SHAPE PARAMETER NU1 FOR THE ',   &
      'NON-CENTRAL F RANDOM NUMBERS IS NON-POSITIVE.')
      IF(ANU2.LE.0.0)THEN
        WRITE(ICOUT,26)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ANU2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   26 FORMAT('***** ERROR--THE SHAPE PARAMETER NU2 FOR THE ',   &
      'NON-CENTRAL F RANDOM NUMBERS IS NON-POSITIVE.')
      IF(ALAMB1.LT.0.0)THEN
        WRITE(ICOUT,36)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAMB1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   36 FORMAT('***** ERROR--THE NON-CENTRALITY PARAMETER LAMBDA FOR ',   &
      'THE NON-CENTRAL F RANDOM NUMBERS IS NEGATIVE.')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!  IF DEGREES OF FREEDOM ARE LESS THAN 1, THEN USE PERCENT
!  POINT METHOD (PROBABLY NOT MOST EFFICIENT METHOD, BUT LEAVE
!  UNTIL FIND A BETTER ALGORITHM).
!
      ALAMB2=0.0
!
      IF(ANU1.LE.1.0 .OR. ANU2.LE.1.0)THEN
        CALL UNIRAN(N,ISEED,X)
        DO 1378 II=1,N
          ATEMP=X(II)
          CALL NCFPPF(ATEMP,ANU1,ANU2,ALAMB1,PPF)
          X(II)=PPF
 1378   CONTINUE
      ELSE
        NTEMP=1
        DO 100 II=1,N
          CALL NORRAN(NTEMP,ISEED,XTEMP)
          X1=(XTEMP(1) + SQRT(ALAMB1))**2
          IF(ANU1.GT.1.0)THEN
            CALL CHSRAN(NTEMP,ANU1-1.0,ISEED,XTEMP)
            X1=X1+XTEMP(1)
          ENDIF
          CALL NORRAN(NTEMP,ISEED,XTEMP)
          X2=(XTEMP(1) + SQRT(ALAMB2))**2
          IF(ANU2.GT.1.0)THEN
            CALL CHSRAN(NTEMP,ANU2-1.0,ISEED,XTEMP)
            X2=X2+XTEMP(1)
          ENDIF
          X(II)=ANU2*X1/(ANU1*X2)
  100   CONTINUE
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NCFRAN
      SUBROUTINE NCTCDF(T2, DF2, DELTA2, CDF)
!
!     ALGORITHM AS 243  APPL. STATIST. (1989), VOL.38, NO. 1
!
!     Cumulative probability at T of the non-central t-distribution
!     with DF degrees of freedom (may be fractional) and non-centrality
!     parameter DELTA.
!
!     Note - requires the following auxiliary routines
!     ALOGAM (X)                         - ACM 291 or AS 245
!     BETAIN (X, A, B, ALBETA, IFAULT)   - AS 63 (updated in ASR 19)
!     ALNORM (X, UPPER)                  - AS 66
!
      REAL T2, DF2, DELTA2
!CCCC DOUBLE PRECISION A, DLBETA, ALNRPI, B, DEL, DELTA, DF, EN, ERRBD
      DOUBLE PRECISION A, DLBETA, B, DEL, DELTA, DF, EN, ERRBD
      DOUBLE PRECISION ERRMAX, GEVEN, GODD, HALF, ITRMAX, LAMBDA, ONE
      DOUBLE PRECISION P, Q, R2PI, RXB, S, T, TT, TWO, X, XEVEN, XODD
      DOUBLE PRECISION ZERO, DBETAI, TNC, DCDF, DCCDF
      LOGICAL NEGDEL
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!
!     Note - ITRMAX and ERRMAX may be changed to suit one's needs.
!
      DATA ITRMAX/500.1D0/, ERRMAX/1.D-06/
!
!     Constants - R2PI = 1/ {GAMMA(1.5) * SQRT(2)} = SQRT(2 / PI)
!                 ALNRPI = LN(SQRT(PI))
!
      DATA ZERO/0.D0/
      DATA HALF/0.5D0/
      DATA ONE/1.0D0/
      DATA TWO/2.0D0/
      DATA R2PI/0.79788456080286535588D0/
!CCCC DATA ALNRPI/0.57236 49429 24700 08707D0/
!
      T=DBLE(T2)
      DF=DBLE(DF2)
      DELTA=DBLE(DELTA2)
      TNC=0.0D0
!
      IF(DF.LE.ZERO)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE DEGREES OF FREEDOM PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)DF2
  102   FORMAT('      IT HAS THE VALUE ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      TNC = ZERO
!
      TT = T
      DEL = DELTA
      NEGDEL = .FALSE.
      IF (T .GE. ZERO) GO TO 1
      NEGDEL = .TRUE.
      TT = -TT
      DEL = -DEL
    1 CONTINUE
!
!     Initialize twin series (Guenther, J. Statist. Computn. Simuln.
!     vol.6, 199, 1978).
!
      EN = ONE
      X = T * T / (T* T + DF)
      IF (X .LE. ZERO) GO TO 20
      LAMBDA = DEL * DEL
      P = HALF * DEXP(-HALF * LAMBDA)
      Q = R2PI * P * DEL
      S = HALF - P
      A = HALF
      B = HALF * DF
      RXB = (ONE - X) ** B
!CCCC ALBETA = ALNRPI + ALOGAM(B, IFAULT) - ALOGAM(A + B, IFAULT)
!CCCC XODD = BETAIN(X, A, B, ALBETA, IFAULT)
      ALBETA=DLBETA(A,B)
      XODD = DBETAI(X,A,B)
!
      GODD = TWO * RXB * EXP(A * LOG(X) - ALBETA)
      XEVEN = ONE - RXB
      GEVEN = B * X * RXB
      TNC = P * XODD + Q * XEVEN
!
!     Repeat until convergence
!
   10 A = A + ONE
      XODD = XODD - GODD
      XEVEN = XEVEN - GEVEN
      GODD = GODD * X * (A + B - ONE) / A
      GEVEN = GEVEN * X * (A + B - HALF) / (A + HALF)
      P = P * LAMBDA / (TWO * EN)
      Q = Q * LAMBDA / (TWO * EN + ONE)
      S = S - P
      EN = EN + ONE
      TNC = TNC + P * XODD + Q * XEVEN
      ERRBD = TWO * S * (XODD - GODD)
      IF (ERRBD .GT. ERRMAX .AND. EN .LE. ITRMAX) GO TO 10
!
!CCCC APRIL 1995.  IF NO CONVERGENCE, CALL DOUBLY NON-CENTRAL T
!CCCC ROUTINE.
!
   20 CONTINUE
      IF (EN .GT. ITRMAX) THEN
!CCCC   WRITE(ICOUT,701)
!CCCC   CALL DPWRST('XXX','BUG ')
        ALAMB=0.0
        IF(DELTA2.GE.100.0)THEN
          CALL CUMTNC(DBLE(T2),DBLE(DF2),DBLE(DELTA2),DCDF,DCCDF)
          CDF=REAL(DCDF)
        ELSE
          CALL DNTCDF(T2,DF2,DELTA2,ALAMB,CDF)
        ENDIF
        RETURN
      ENDIF
!C701 FORMAT('*** WARNING--THE NCTCDF ROUTINE DID NOT CONVERGE.')
!
!CCCC TNC = TNC + ALNORM(DEL, .TRUE.)
      ARG1=REAL(DEL)
      CALL NORCDF(ARG1,ARG2)
      TNC = TNC + DBLE(1.0-ARG2)
      IF (NEGDEL) TNC = ONE - TNC
!
 9999 CONTINUE
      CDF=REAL(TNC)
      RETURN
      END SUBROUTINE NCTCDF
      SUBROUTINE NCTCD2(T2, DF2, DELTA2, CDF)
!
!     This is a copy of NCTCDF.  Distinction is that this version
!     returns a double precision result (used by the NCTPDF
!     routine) and inputs double precision arguments.
!
!     ALGORITHM AS 243  APPL. STATIST. (1989), VOL.38, NO. 1
!
!     Cumulative probability at T of the non-central t-distribution
!     with DF degrees of freedom (may be fractional) and non-centrality
!     parameter DELTA.
!
!     Note - requires the following auxiliary routines
!     ALOGAM (X)                         - ACM 291 or AS 245
!     BETAIN (X, A, B, ALBETA, IFAULT)   - AS 63 (updated in ASR 19)
!     ALNORM (X, UPPER)                  - AS 66
!
      DOUBLE PRECISION T2, DF2, DELTA2, ARG2, CDF, CCDF
!CCCC DOUBLE PRECISION A, DLBETA, ALNRPI, B, DEL, DELTA, DF, EN, ERRBD
      DOUBLE PRECISION A, DLBETA, B, DEL, DELTA, DF, EN, ERRBD
      DOUBLE PRECISION ERRMAX, GEVEN, GODD, HALF, ITRMAX, LAMBDA, ONE
      DOUBLE PRECISION P, Q, R2PI, RXB, S, T, TT, TWO, X, XEVEN, XODD
      DOUBLE PRECISION ZERO, DBETAI, TNC
      LOGICAL NEGDEL
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!     Note - ITRMAX and ERRMAX may be changed to suit one's needs.
!
      DATA ITRMAX/1000.1D0/, ERRMAX/1.D-08/
!
!     Constants - R2PI = 1/ {GAMMA(1.5) * SQRT(2)} = SQRT(2 / PI)
!                 ALNRPI = LN(SQRT(PI))
!
      DATA ZERO/0.D0/
      DATA HALF/0.5D0/
      DATA ONE/1.0D0/
      DATA TWO/2.0D0/
      DATA R2PI/0.79788456080286535588D0/
!CCC  DATA ALNRPI/0.57236 49429 24700 08707D0/
!
      T=T2
      DF=DF2
      DELTA=DELTA2
      TNC=0.0D0
!
      IF(DF.LE.ZERO)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE DEGREES OF FREEDOM PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)DF2
  102   FORMAT('      IT HAS THE VALUE ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      TNC = ZERO
!
      TT = T
      DEL = DELTA
      NEGDEL = .FALSE.
      IF (T .GE. ZERO) GO TO 1
      NEGDEL = .TRUE.
      TT = -TT
      DEL = -DEL
    1 CONTINUE
!
!     Initialize twin series (Guenther, J. Statist. Computn. Simuln.
!     vol.6, 199, 1978).
!
      EN = ONE
      X = T * T / (T* T + DF)
      IF (X .LE. ZERO) GO TO 20
      LAMBDA = DEL * DEL
      P = HALF * DEXP(-HALF * LAMBDA)
      Q = R2PI * P * DEL
      S = HALF - P
      A = HALF
      B = HALF * DF
      RXB = (ONE - X) ** B
!CCCC ALBETA = ALNRPI + ALOGAM(B, IFAULT) - ALOGAM(A + B, IFAULT)
!CCCC XODD = BETAIN(X, A, B, ALBETA, IFAULT)
      ALBETA=DLBETA(A,B)
      XODD = DBETAI(X,A,B)
!
      GODD = TWO * RXB * EXP(A * LOG(X) - ALBETA)
      XEVEN = ONE - RXB
      GEVEN = B * X * RXB
      TNC = P * XODD + Q * XEVEN
!
!     Repeat until convergence
!
   10 A = A + ONE
      XODD = XODD - GODD
      XEVEN = XEVEN - GEVEN
      GODD = GODD * X * (A + B - ONE) / A
      GEVEN = GEVEN * X * (A + B - HALF) / (A + HALF)
      P = P * LAMBDA / (TWO * EN)
      Q = Q * LAMBDA / (TWO * EN + ONE)
      S = S - P
      EN = EN + ONE
      TNC = TNC + P * XODD + Q * XEVEN
      ERRBD = TWO * S * (XODD - GODD)
      IF (ERRBD .GT. ERRMAX .AND. EN .LE. ITRMAX) GO TO 10
!
!CCCC APRIL 1995.  IF NO CONVERGENCE, CALL DOUBLY NON-CENTRAL T
!CCCC ROUTINE.
!
   20 CONTINUE
      IF (EN .GT. ITRMAX) THEN
!CCCC   WRITE(ICOUT,701)
!CCCC   CALL DPWRST('XXX','BUG ')
        ALAMB=0.0
        IF(DELTA2.GE.100.0)THEN
          CALL CUMTNC(T2,DF2,DELTA2,CDF,CCDF)
        ELSE
          CALL DNTCDF(REAL(T2),REAL(DF2),REAL(DELTA2),ALAMB,CDF2)
          CDF=DBLE(CDF2)
        ENDIF
        RETURN
      ENDIF
!C701 FORMAT('*** WARNING--THE NCTCD2 ROUTINE DID NOT CONVERGE. ')
!
!CCCC TNC = TNC + ALNORM(DEL, .TRUE.)
      ARG1=REAL(DEL)
      CALL NODCDF(DEL,ARG2)
      TNC = TNC + (1.0D0-ARG2)
      IF (NEGDEL) TNC = ONE - TNC
      GO TO 9999
!
 9999 CONTINUE
      CDF=TNC
      RETURN
      END SUBROUTINE NCTCD2
      SUBROUTINE NCTPDF(T, DF, DELTA, PDF)
!
!     COMPUTE NON-CENTRAL PDF BASED ON NON-CENTRAL CDF.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDF1
      DOUBLE PRECISION DPDF2
!
      INCLUDE 'DPCOP2.INC'
!
!     T = 0 IS A SPECIAL CASE.
!
!CCCC EPS=0.000001
      EPS=1.0E-8
      IF(ABS(T).LE.EPS)THEN
!
!  THIS ALGORITHM DOES NOT RETURN A CORRECT RESULT.  AS TEMPORARY
!  FIX, COMPUTE FOR +EPS AND -EPS, THEN AVERAGE RESULT.
!
!CCCC   TX=EPS
!CCCC   TERM1=DF/TX
!CCCC   DF2=DF+2.0
!CCCC   TX2=SQRT((DF+2.0)/DF)*TX
!CCCC   CALL NCTCDF(TX2,DF2,DELTA,TERM2)
!CCCC   CALL NCTCDF(TX,DF,DELTA,TERM3)
!CCCC   PDF=TERM1*(TERM2-TERM3)
!
        TTEMP=EPS
        DTERM1=DBLE(DF/TTEMP)
        DF2=DF+2.0
        T2=SQRT((DF+2.0)/DF)*TTEMP
        CALL NCTCD2(DBLE(T2),DBLE(DF2),DBLE(DELTA),DTERM2)
        CALL NCTCD2(DBLE(TTEMP),DBLE(DF),DBLE(DELTA),DTERM3)
        DPDF1=DTERM1*(DTERM2-DTERM3)
!
        TTEMP=-EPS
        DTERM1=DBLE(DF/TTEMP)
        DF2=DF+2.0
        T2=SQRT((DF+2.0)/DF)*TTEMP
        CALL NCTCD2(DBLE(T2),DBLE(DF2),DBLE(DELTA),DTERM2)
        CALL NCTCD2(DBLE(TTEMP),DBLE(DF),DBLE(DELTA),DTERM3)
        DPDF2=DTERM1*(DTERM2-DTERM3)
!
        DPDF=(DPDF1+DPDF2)/2.0D0
        PDF=REAL(DPDF)
      ELSE
        DTERM1=DBLE(DF/T)
        DF2=DF+2.0
        T2=SQRT((DF+2.0)/DF)*T
        CALL NCTCD2(DBLE(T2),DBLE(DF2),DBLE(DELTA),DTERM2)
        CALL NCTCD2(DBLE(T),DBLE(DF),DBLE(DELTA),DTERM3)
        DPDF=DTERM1*(DTERM2-DTERM3)
        PDF=REAL(DPDF)
      ENDIF
!
      RETURN
      END SUBROUTINE NCTPDF
      SUBROUTINE NCTPPF(P,NU,DELTA,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE NON-CENTRAL T
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/9
!     ORIGINAL VERSION--SEPTEMBER 1994.
!     UPDATED         --OCTOBER   2006. CALL LIST TO TPPF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL NU
      DOUBLE PRECISION DLNGAM
      DOUBLE PRECISION ANU
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DDELTA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!CCCC DOUBLE PRECISION FCT
!CCCC DOUBLE PRECISION C0
!CCCC DOUBLE PRECISION C1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA EPS /0.0001/
!CCCC DATA SIG /1.0E-5/
      DATA ZERO /0./
      DATA MAXIT /500/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
               'NCTPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(NU.LT.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'NCTPPF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)NU
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DELTA.LT.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
               'NCTPPF IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DELTA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!  DELTA = 0 AND NU INTEGER, USE CENTRAL T
!
      IF(DELTA.EQ.0.0)THEN
        NUINT=INT(NU+0.1)
        ANUINT=REAL(NUINT)
        IF(ABS(NU-ANUINT).LE.0.000001)THEN
          CALL TPPF(P,REAL(NUINT),PPF)
          GO TO 9999
        ENDIF
      ENDIF
!
!  FIND BRACKETING INTERVAL.
!
!  1) CORRESPONDING CENTRAL T IS A LOWER BOUND
!  2) BASE INCREMENT ON SD OF NON-CENTRAL T:
!
!         (DELTA**2 + 1)*N/(N-2) -
!          DELTA**2*N*[GAMMA(0.5*(N-1))]**2/{2*[GAMMA(0.5*N)]**2}
!
!     IF NU <= 2, THEN BASE SD ON NU = 3 AND MULTIPLY BY A
!     SCALE FACTOR (AND SET MAX ITERATIONS HIGHER).
!
!  AFTER SUCCESSFULLY FIND BRACKETING INTERVAL, THEN SWITCH TO
!  MORE EFFICIENT BISECTION METHOD.
!
      EPS=0.0000001
      SIG=1.0E-7
!CCCC IF(NU.LT.3.0)THEN
!CCCC   IF(P.GT.0.90 .OR. P.LT.0.10)THEN
!CCCC     EPS=0.0001
!CCCC     SIG=1.0E-4
!CCCC   ENDIF
!CCCC ENDIF
!CCCC IF(ABS(DELTA).GE.10.0)THEN
!CCCC     EPS=0.0001
!CCCC     SIG=1.0E-4
!CCCC ENDIF
!
      NUINT=INT(NU+0.5)
      CALL TPPF(P,REAL(NUINT),XL)
!CCCC XINC=50.0
      ANU=DBLE(NUINT)
      IF(ANU.LE.2.5D0)ANU=3.0D0
!
      DDELTA=DBLE(DELTA)
      DTERM1=ANU*(DDELTA**2 + 1.0D0)/(ANU-2.0D0)
      DTERM2=2.0D0*DLOG(DDELTA) + DLOG(ANU) - DLOG(2.0D0)
      DTERM3=2.0D0*DLNGAM(0.5D0*(ANU-1.0D0)) - 2.0D0*DLNGAM(0.5D0*ANU)
      DTERM4=DTERM2 + DTERM3
      DTERM5=DEXP(DTERM4)
      DSD=DTERM1 - DTERM5
      IF(DSD.GE.0.0D0)THEN
        SD=REAL(DSQRT(DSD))
      ELSE
        SD=10.0
      ENDIF
      IF(NU.GE.2.5)THEN
        XINC=SD
      ELSEIF(NU.GE.1.5)THEN
        XINC=5.0*SD
      ELSE
        XINC=10.0*SD
      ENDIF
      IF(XINC.LT.1.0)XINC=1.0
!
      ICOUNT=0
      MAXCNT=200
      IF(NU.LT.3.0)MAXCNT=500
!
   91 CONTINUE
      XR=XL+XINC
      CALL NCTCDF(XL,NU,DELTA,CDFL)
      CALL NCTCDF(XR,NU,DELTA,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** ERROR--NCTPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL.')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -P
      FXR = 1.0 - P
  105 CONTINUE
      X = (XL+XR)*0.5
      CALL NCTCDF(X,NU,DELTA,CDF)
      P1=CDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** FATAL ERROR--NCTPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NCTPPF
      SUBROUTINE NCTRAN(N,ANU,DELTA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE STUDENT'S NON-CENTRAL T DISTRIBUTION
!              WITH DEGREES OF FREEDOM PARAMETER NU AND
!              NON-CENTRALITY PARAMETER DELTA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --NU     = THE INTEGER DEGREES OF FREEDOM
!                                PARAMETER.
!                     --DELTA  = THE REAL NON-CENTRALITY PARAMETER DELTA.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE STUDENT'S NON-CENTRAL T DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU AND
!             NON-CENTRALITY PARAMETER DELTA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORNCTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORNCTRAN (1977)
!     REFERENCES--MOOD AND GRABLE, INTRODUCTION TO THE
!                 THEORY OF STATISTICS, 1963, PAGE 233.
!               --JOHNSON, KOTZ, AND BALAKRISHNAN, CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 2, SECOND EDITION,
!                 1994, CHAPTER 31.
!               --HASTINGS, EVANS, AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION, WILEY, 2001,
!                 PP. 184-186.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!     UPDATED         --MAY       2004. SUPPORT FOR REAL VALUES OF NU
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL DELTA
      REAL ANU
      DIMENSION X(*)
      DIMENSION Y(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!CCCC DATA PI/3.14159265359/
!CCCC DATA EPS/0.00001/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO NCTRAN ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ANU.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO NCTRAN ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)ANU
   48   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N STUDENT'S NON-CENTRAL T RANDOM NUMBERS
!     USING THE DEFINITION THAT A STUDENT'S NON-CENTRAL T VARIATE
!     WITH NU DEGREES OF FREEDOM AND NON-CENTRALITY PARAMETER
!     DELTA EQUALS A NORMAL VARIATE WITH LOCATION PARAMETER DELTA
!     DIVIDED BY A STANDARDIZED CHI VARIATE
!     (WHERE THE LATTER EQUALS SQRT(CHI-SQUARED/NU).
!     FIRST GENERATE A NORMAL RANDOM NUMBER WITH LOCATION PARAMETER
!     DELTA, THEN GENERATE A STANDARDIZED CHI RANDOM NUMBER,
!     THEN FORM THE RATIO OF THE FIRST DIVIDED BY
!     THE SECOND.
!
      CALL NORRAN(N,ISEED,X)
      NTEMP=1
!
      DO 100 I=1,N
!
        X(I)=X(I) + DELTA
        CALL CHSRAN(NTEMP,ANU,ISEED,Y)
        X(I)=X(I)/SQRT(Y(1)/ANU)
!
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NCTRAN
      SUBROUTINE NEARNE(Y1,X1,N,Y2,D2,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE THE NEAREST NEIGHBOR FOR THE
!              2-D CASE.  THIS USES A BRUTE FORCE ALGORITHM.
!              THE OUTPOUT VECTOR IS THE INDEX OF THE NEAREST
!              NEIGHBOR.
!
!     INPUT  ARGUMENTS--X1 (REAL)
!                     --Y1 (REAL)
!     OUTPUT ARGUMENTS--Y2 (REAL)
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/8
!     ORIGINAL VERSION--AUGUST     2013
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL X1(*)
      REAL Y1(*)
      REAL Y2(*)
      REAL D2(*)
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION DISTM
      DOUBLE PRECISION DDIST
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DY1
      DOUBLE PRECISION DY2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ARNE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF NEARNE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X1(I),Y1(I)
   56     FORMAT('I,X1(I),Y1(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1151)
 1151   FORMAT('***** ERROR IN NEAREST NEIGHBOR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1152)
 1152   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IS LESS THAN ',   &
               'ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1154)N
 1154   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        Y2(1)=1.0
        D2(1)=0.0
      ELSEIF(N.EQ.2)THEN
        Y2(1)=2.0
        Y2(2)=1.0
        TERM1=(X1(1) - X1(2))**2
        TERM2=(Y1(1) - Y1(2))**2
        D2(1)=SQRT(TERM1 + TERM2)
        D2(2)=D2(1)
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE NEAREST NEIGHBORS             **
!               ************************************************
!
      DO 2000 K=1,N
        DISTM=DBLE(CPUMAX)
        IINDX=-1
        DO 2100 L=1,N
          IF(L.EQ.K)GO TO 2100
          DX1=DBLE(X1(K))
          DX2=DBLE(X1(L))
          DY1=DBLE(Y1(K))
          DY2=DBLE(Y1(L))
          DDIST=DSQRT((DX1 - DX2)**2 + (DY1 - DY2)**2)
          IF(DDIST.LT.DISTM)THEN
            IINDX=L
            DISTM=DDIST
          ENDIF
 2100   CONTINUE
        Y2(K)=REAL(IINDX)
        D2(K)=REAL(DISTM)
 2000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ARNE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF NEARNE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR
 9013   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9021 I=1,N
          WRITE(ICOUT,9022)I,Y2(I),D2(I)
 9022     FORMAT('I,Y2(I),D2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9021   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE NEARNE
      SUBROUTINE NEARN2(X1,Y1,N1,X2,Y2,N2,ICASE,MAXOBV,   &
                        AIINDX,TEMPX,TEMPY,TEMPD,TEMPZ,   &
                        Y3,X3,D3,TAG1,TAG2,N3,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS IS A SLIGHTLY MODIFIED VERSION OF NEARNE.  THE
!              NEARNE ROUTINE TAKES A LIST OF (X,Y) COORDINATE PAIRS
!              AND FINDS THE NEAREST NEIGHBOR OF EACH POINT.  THIS
!              ROUTINE TAKES TWO LISTS OF (X,Y) COORDINATE PAIRS.
!              FOR EACH ROW OF THE FIRST LIST, THE SECOND LIST IS
!              SEARCHED TO FIND THE NEAREST NEIGHBOR.  THERE ARE
!              TWO ALTERNATIVES.  IN THE FIRST ALTERNATIVE, ONLY
!              THE SINGLE NEAREST NEIGBOR IS RETURNED.  FOR THE
!              SECOND ALTERNATIVE, WE RETURN A SORTED LIST OF
!              NEAREST NEIGBORS.  THIS CAN BE HELPFUL IF YOU NEED
!              THE "SECOND" NEAREST NEIGHBOR OR THE "THIRD" NEAREST
!              NEIGHBOR, AND SO ON.
!
!     INPUT  ARGUMENTS--X1 (REAL)
!                     --Y1 (REAL)
!     OUTPUT ARGUMENTS--Y2 (REAL)
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/9
!     ORIGINAL VERSION--SEPTEMBER  2013
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL X1(*)
      REAL Y1(*)
      REAL X2(*)
      REAL Y2(*)
      REAL X3(*)
      REAL Y3(*)
      REAL D3(*)
      REAL TAG1(*)
      REAL TAG2(*)
      REAL TEMPX(*)
      REAL TEMPY(*)
      REAL TEMPD(*)
      REAL TEMPZ(*)
      REAL AIINDX(*)
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION DISTM
      DOUBLE PRECISION DDIST
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DY1
      DOUBLE PRECISION DY2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ARN2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF NEARN2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,N2
   52   FORMAT('IBUGA3,ISUBRO,N1,N2 = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,X1(I),Y1(I)
   56     FORMAT('I,X1(I),Y1(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,X2(I),Y2(I)
   66     FORMAT('I,X2(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N1.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1151)
 1151   FORMAT('***** ERROR IN NEAREST NEIGHBOR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1152)
 1152   FORMAT('      THE NUMBER OF OBSERVATIONS FOR (X1,Y1) ',   &
               'IS LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1154)N1
 1154   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N2.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1151)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1162)
 1162   FORMAT('      THE NUMBER OF OBSERVATIONS FOR (X2,Y2) ',   &
               'IS LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1154)N2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  CASE ONE: FIND THE SINGLE NEAREST NEIGHBOR **
!               *************************************************
!
      IF(ICASE.EQ.1)THEN
        DO 2010 J=1,N2
          DX1=DBLE(X2(J))
          DY1=DBLE(Y2(J))
          DISTM=DBLE(CPUMAX)
          DO 2020 K=1,N1
            DX2=DBLE(X1(K))
            DY2=DBLE(Y1(K))
            DDIST=DSQRT((DX1 - DX2)**2 + (DY1 - DY2)**2)
            IF(DDIST.LT.DISTM)THEN
              DISTM=DDIST
              X3(J)=X1(K)
              Y3(J)=Y1(K)
              D3(J)=REAL(DDIST)
            ENDIF
 2020     CONTINUE
 2010   CONTINUE
        N3=N2
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  CASE TWO: RETURN SORTED LIST OF DISTANCES  **
!               *************************************************
!
      ELSEIF(ICASE.EQ.2)THEN
        IF(N1*N2.GT.MAXOBV)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1151)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3052)MAXOBV
 3052     FORMAT('      THE NUMBER OF OUTPUT ROWS EXCEEDS THE ',   &
                 'MAXIMUM ALLOWED (',I8,')')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        ICNT=0
        DO 3010 J=1,N2
          DX1=DBLE(X2(J))
          DY1=DBLE(Y2(J))
!
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ARN2')THEN
            WRITE(ICOUT,3011)J,DX1,DY1
 3011       FORMAT('J,DX1,DX2 = ',I8,2G15.7)
           CALL DPWRST('XXX','BUG ')
          ENDIF
!
          DO 3020 K=1,N1
            DX2=DBLE(X1(K))
            DY2=DBLE(Y1(K))
            DDIST=DSQRT((DX1 - DX2)**2 + (DY1 - DY2)**2)
            TEMPX(K)=X1(K)
            TEMPY(K)=Y1(K)
            TEMPD(K)=REAL(DDIST)
            AIINDX(K)=REAL(K)
 3020     CONTINUE
!
!         NOW SORT THE DATA
!
          CALL SORTI(TEMPD,N1,TEMPZ,AIINDX)
          DO 3030 K=1,N1
            ICNT=ICNT+1
            IINDX=INT(AIINDX(K)+0.1)
            D3(ICNT)=TEMPD(K)
            X3(ICNT)=TEMPX(IINDX)
            Y3(ICNT)=TEMPY(IINDX)
            TAG1(ICNT)=REAL(J)
            TAG2(ICNT)=REAL(K)
 3030     CONTINUE
 3010   CONTINUE
        N3=ICNT
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ARN2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF NEARN2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N3
 9013   FORMAT('IERROR,N3 = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9021 I=1,N3
          WRITE(ICOUT,9022)I,X3(I),Y3(I),D3(I)
 9022     FORMAT('I,X3(I),Y3(I),D3(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9021   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE NEARN2
      SUBROUTINE NEARN3(Y1,X1,N,Y2,X2,DIST,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--GIVEN THE POINT (X2,Y2), RETURN THE DISTANCE FROM
!              THAT POINT TO EACH POINT IN THE ARRAY (X1,Y1).
!              SORT THESE DISTANCES.
!
!     INPUT  ARGUMENTS--X1 (REAL ARRAY)
!                     --Y1 (REAL ARRAY)
!                     --N  (INTEGER)
!                     --X2 (REAL SCALAR)
!                     --Y2 (REAL SCALAR)
!     OUTPUT ARGUMENTS--DIST (REAL ARRAY)
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/01
!     ORIGINAL VERSION--JANUARY    2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL X1(*)
      REAL Y1(*)
      REAL DIST(*)
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION DDIST
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DY1
      DOUBLE PRECISION DY2
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ARN3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF NEARN3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,X2,Y2
   52   FORMAT('IBUGA3,ISUBRO,N,X2,Y2 = ',2(A4,2X),I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X1(I),Y1(I)
   56     FORMAT('I,X1(I),Y1(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1151)
 1151   FORMAT('***** ERROR IN NEAREST NEIGHBOR DISTANCES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1152)
 1152   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IS LESS THAN ',   &
               'ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1154)N
 1154   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE DISTANCES                     **
!               ************************************************
!
!     DELETE "ZERO" DISTANCES
!
      DEPS=1.0D-15
      DX2=DBLE(X2)
      DY2=DBLE(Y2)
      ICNT=0
      DO 2000 K=1,N
        DX1=DBLE(X1(K))
        DY1=DBLE(Y1(K))
        DDIST=DSQRT((DX1 - DX2)**2 + (DY1 - DY2)**2)
        IF(DABS(DDIST).GT.DEPS)THEN
          ICNT=ICNT+1
          DIST(ICNT)=REAL(DDIST)
        ENDIF
 2000 CONTINUE
!
!     NOW SORT THE DISTANCES
!
      CALL SORT(DIST,ICNT,DIST)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ARN3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF NEARN3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR
 9013   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9021 I=1,N
          WRITE(ICOUT,9022)I,DIST(I)
 9022     FORMAT('I,DIST(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
 9021   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE NEARN3
      SUBROUTINE NEIGH(IT,NN,XS,N,I1,I2,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--FOR THE IT-TH HORIZONTAL ORDERED DATA POINT XS(IT),
!              DETERMINE THE INDICES I1 AND I2 WHICH DEFINE
!              THE NN NEAREST NEIGHBORS OF XS(IT).
!     NOTE--XS(IT) IS CONSIDERED A NEIGHBOR OF ITSELF.
!     REFERENCE--CHAMBERS, ET AL.  GRAPHICAL METHODS FOR DATA ANALYSIS.
!                WADSWORTH, 1983, PAGES 94-98, 121-122.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/2
!     ORIGINAL VERSION--FEBRUARY   1988
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION XS(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EIGH'
      ISUBN2='H   '
!
      I1=(-999)
      I2=(-999)
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'EIGH')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF NEIGH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBRO,IBUGA3,IERROR
   52 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IT,NN,N
   53 FORMAT('IT,NN,N = ',3I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)I1,I2
   54 FORMAT('I1,I2 = ',2I8)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.GE.1)GO TO 119
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN NEIGH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT FULL SAMPLE SIZE,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      FOR WHICH LOWESS NEIGHBORHOODS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      ARE TO BE COMPUTED, MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)N
  116 FORMAT('      THE FULL SAMPLE SIZE N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  119 CONTINUE
!
      IF(IT.GE.1)GO TO 129
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** ERROR IN NEIGH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,122)
  122 FORMAT('      THE INPUT TARGET OBSERVATION INDEX')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,123)
  123 FORMAT('      FOR WHICH A LOWESS IS TO BE CARRIED OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,124)N
  124 FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVE).')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,125)
  125 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,126)IT
  126 FORMAT('      THE TARGET OBSERVATION INDEX IT = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  129 CONTINUE
!
      IF(NN.GE.1)GO TO 139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,131)
  131 FORMAT('***** ERROR IN NEIGH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,132)
  132 FORMAT('      THE INPUT NEIGHBORHOOD SIZE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,133)
  133 FORMAT('      FOR WHICH A LOWESS IS TO BE CARRIED OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,134)N
  134 FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVE).')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,135)
  135 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)NN
  136 FORMAT('      THE NEIGHBORHOOD SIZE NN = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  139 CONTINUE
!
!               ***********************************************
!               **  STEP 11--                                **
!               **  COMPUTE THE INDICES OF THE NEIGHBORHOOD  **
!               ***********************************************
!
      I1=IT
      I2=IT
      NNI=1
!
      IF(NN.LE.1)GO TO 1190
      DO 1100 I=2,NN
!
      IF(I1.LE.1)GO TO 1110
      IF(I2.GE.N)GO TO 1120
      GO TO 1130
!
 1110 CONTINUE
      I2=I2+1
      NNI=NNI+1
      GO TO 1100
!
 1120 CONTINUE
      I1=I1-1
      NNI=NNI+1
      GO TO 1100
!
 1130 CONTINUE
      I1M1=I1-1
      I2P1=I2+1
      DEL1=ABS(XS(IT)-XS(I1M1))
      DEL2=ABS(XS(I2P1)-XS(IT))
      IF(DEL1.LT.DEL2)I1=I1M1
      IF(DEL1.GE.DEL2)I2=I2P1
      NNI=NNI+1
      GO TO 1100
!
 1100 CONTINUE
 1190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'EIGH')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF NEIGH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ISUBRO,IBUGA3,IERROR
 9012 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IT,NN,N
 9013 FORMAT('IT,NN,N = ',3I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)I1,I2
 9014 FORMAT('I1,I2 = ',2I8)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE NEIGH
      SUBROUTINE NEXT (RCOMBO, R, N, INIT)
!
!        ALGORITHM AS 304.7 APPL.STATIST. (1996), VOL.45, NO.3
!
!        Accepts some R-combination of the first N integers and then
!        computes the next R-combination in the lexicographic
!        ordering of the N! / (R! * (N - R)!) such R-combinations.
!        Returns the first R-combination if the initialization
!        indicator is .true. and then resets the indicator.
!
!        DATAPLOT NOTE: THIS IS A UTILITY ROUTINE USED BY
!                       FISHER TWO SAMPLE RANDOMIZATION TEST
!
      INTEGER R, N, RCOMBO(R)
      LOGICAL INIT
!
      INTEGER I, J, D
!
      IF (INIT) THEN
         DO 10 I = 1, R
            RCOMBO(I) = I
   10    CONTINUE
         INIT = .FALSE.
      ELSE
         D = N - R
         J = R
!
!        The counter J is not prevented from going out of bounds
!        which will happen if there is no next R-combination
!
   20    IF (RCOMBO(J) .LT. D + J) GO TO  30
         J = J - 1
         GO TO  20
   30    RCOMBO(J) = RCOMBO(J) + 1
         DO 40 I = J + 1, R
            RCOMBO(I) = RCOMBO(I - 1) + 1
   40    CONTINUE
      END IF
!
      RETURN
      END SUBROUTINE NEXT 
      SUBROUTINE NMXCDF(X,U1,SD1,U2,SD2,P,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE MIXTUURE NORMAL (GAUSSIAN)
!              DISTRIBUTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODCDF.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS, 2ND. ED.--1, 1994, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--98.5
!     ORIGINAL VERSION--MAY       1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DARG1
      DOUBLE PRECISION DCDF1
      DOUBLE PRECISION DCDF2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(SD1.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
  101 FORMAT('*****ERROR FROM NMXCDF--FIRST SCALE PARAMETER IS ',   &
             'NOT POSITVE.')
      IF(SD2.LE.0.0)THEN
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
  103 FORMAT('*****ERROR FROM NMXCDF--SECOND SCALE PARAMETER IS ',   &
             'NOT POSITIVE.')
!
      DARG1=DBLE((X-U1)/SD1)
      CALL NODCDF(DARG1,DCDF1)
      DARG1=DBLE((X-U2)/SD2)
      CALL NODCDF(DARG1,DCDF2)
!
      CDF=REAL(DBLE(P)*DCDF1 + DBLE(1.0-P)*DCDF2)
!
 9000 CONTINUE
!
      RETURN
      END SUBROUTINE NMXCDF
      SUBROUTINE NMDCDF(X,U1,SD1,U2,SD2,P,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE MIXTUURE NORMAL (GAUSSIAN)
!              DISTRIBUTION.  SAME AS NMXCDF EXCEPT THAT THE
!              CDF RETURNED IS DOUBLE PRECISION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODCDF.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS, 2ND. ED.--1, 1994, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--98.5
!     ORIGINAL VERSION--MAY       1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DARG1
      DOUBLE PRECISION DCDF1
      DOUBLE PRECISION DCDF2
      DOUBLE PRECISION CDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(SD1.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
  101 FORMAT('*****ERROR FROM NMXCDF--FIRST SCALE PARAMETER IS ',   &
             'NOT POSITVE.')
      IF(SD2.LE.0.0)THEN
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
  103 FORMAT('*****ERROR FROM NMXCDF--SECOND SCALE PARAMETER IS ',   &
             'NOT POSITIVE.')
!
      DARG1=DBLE((X-U1)/SD1)
      CALL NODCDF(DARG1,DCDF1)
      DARG1=DBLE((X-U2)/SD2)
      CALL NODCDF(DARG1,DCDF2)
!
      CDF=DBLE(P)*DCDF1 + DBLE(1.0-P)*DCDF2
!
 9000 CONTINUE
!
      RETURN
      END SUBROUTINE NMDCDF
      SUBROUTINE NMXML1(Y,X,N,NVAR,Y2,X2,N2,   &
                        TEMP1,TEMP2,TEMP3,WORK,ITEMP1,MAXNXT,   &
                        CLLIMI,CLWIDT,NCOMP,IHSTCW,   &
                        ALPHA,XMEAN,XSD,KMAX,NTOT2,ALOGL,   &
                        AMEAN,ASD,AMIN,AMAX,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD
!              ESTIMATES FOR THE NORMAL MIXTURE DISTRIBUTION
!              IT USES APPLIED STATISTICS ALGORITHM 203 TO
!              PERFORM THE MAXIMUM LIKELIHOOD ESTIMATION.
!
!              THERE ARE TWO CASES:
!
!              1) ONE VARIABLE CASE: Y IS RAW DATA
!                 A) CALL DPBIN TO BIN DATA
!                 B) IF USER HAS SPECIFIED CLASS LIMITS OR WIDTH,
!                    PASS TO DPBIN.
!              2) TWO VARIABLE CASE: Y IS FREQUENCY, X IS CLASS
!                 MID-POINT.
!
!              NCOMP DEFINES NUMBER OF NORMAL DISTRIBUTIONS BEING
!              FIT.  MAXIMUM OF 20 ALLOWED.
!
!              EXTRACTED FROM DPMLNM IN ORDER TO MAKE IT EASIER TO
!              USE BY OTHER COMMANDS (E.G., GOODNESS OF FIT, BOOTSTRAP).
!     EXAMPLE--NORMAL MIXTURE MAXIMUM LIKELIHOOD Y
!            --NORMAL MIXTURE MAXIMUM LIKELIHOOD Y X
!     REFERENCE--"MAXIMUM LIKELIHOOD ESTIMATION OF MIXTURES OF
!                DISTRIBUTIONS", M. AGHA AND T. IBRAHIM,
!                APPLIED STATISTICS, 1984, VOLUME 33, NO. 3,
!                PP. 327-329.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/3
!     ORIGINAL VERSION--MARCH     2011. EXTRACTED FROM DPMLNM
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IHSTCW
      CHARACTER*4 IHSTO2
      CHARACTER*4 IRELAT
      CHARACTER*4 IRHSTG
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      PARAMETER (MMAX=200)
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION CLLIMI(*)
      DIMENSION CLWIDT(*)
      INTEGER   ITEMP1(*)
!
      REAL TOL
!
      REAL ALPHA(*)
      REAL XMEAN(*)
      REAL XSD(*)
!
!     FOR STORAGE EFFICIENCY, USE SINGLE "WORK" ARRAY FOR FOLLOWING.
!     TO AVOID CONFUSION, LEAVE ALPHA, XMEAN, AND XSD AS DISTINCT
!     ARRAYS (THESE TAKE A MINIMAL AMOUNT OF STORAGE, SINCE THESE
!     REFERENCED IN THIS ROUTINE, KEEP CLARITY IN CODE)
!
      DIMENSION WORK(*)
!
!CCCC REAL NEWALP(KMAX)
!CCCC REAL NEWMEA(KMAX)
!CCCC REAL NEWSD(KMAX)
!CCCC REAL DT(KMAX)
!CCCC REAL NT(KMAX)
!CCCC REAL VT(KMAX)
!CCCC REAL G(MMAX)
!CCCC REAL F(MMAX,KMAX)
!
!CCCC EQUIVALENCE(NEWALP(1), WORK(1))
!CCCC EQUIVALENCE(NEWMEA(1), WORK(KMAX + 1))
!CCCC EQUIVALENCE(NEWSD(1),  WORK(2*KMAX + 1))
!CCCC EQUIVALENCE(DT(1),     WORK(3*KMAX + 1))
!CCCC EQUIVALENCE(NT(1),     WORK(4*KMAX + 1))
!CCCC EQUIVALENCE(VT(1),     WORK(5*KMAX + 1))
!CCCC EQUIVALENCE(G(1),      WORK(6*KMAX + 1))
!CCCC EQUIVALENCE(F(1,1),    WORK(7*KMAX + 1))
!
!-----COMMON--------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT---------------------------------------------------
!
      ISUBN1='NMXM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NMXML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IHSTCW,IHSTO2,IRELAT,IRHSTG
   52   FORMAT('IBUGA3,ISUBRO,IHSTCW,IHSTO2,IRELAT,IRHSTG = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)N,NCOMP,NVAR,KMAX,MAXNXT
   53   FORMAT('N,NCOMP,NVAR,KMAX,MAXNXT = ',5I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)CLWIDT(1),CLLIMI(1),CLLIMI(2)
   54   FORMAT('CLWIDT(1),CLLIMI(1),CLLIMI(2) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'XML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NCOMP.LT.2 .OR. NCOMP.GT.KMAX)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN NORMAL MIXTURE MAXIMUM LIKELIHOOD ',   &
               'ESTIMATION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1123)
 1123   FORMAT('      THE SPECIFIED NUMBER OF COMPONENT ',   &
               'DISTRIBUTIONS IS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1125)KMAX
 1125   FORMAT('      LESS THAN 2 OR GREATER THAN ',I8,'.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1127)NCOMP
 1127   FORMAT('      NUMBER OF COMPONENTS = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      NPERC=0
      NMIN=5
      IF(NVAR.EQ.1)THEN
        CALL CKDIST(Y,N,NMIN,TEMP2,NPERC,ISUBRO,IBUGA3,IERROR)
      ELSEIF(NVAR.EQ.2)THEN
        CALL CKDIS2(Y,X,TEMP1,N,MAXNXT,NMIN,TEMP2,NPERC,NTOT2,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(NVAR.EQ.1)THEN
        CALL SORT(Y,N,TEMP2)
        DO 1160 I=1,N
          Y(I)=TEMP2(I)
 1160   CONTINUE
      ELSEIF(NVAR.EQ.2)THEN
        CALL SORTC(X,Y,N,TEMP1,TEMP2)
        DO 1210 I=1,N
          X(I)=TEMP1(I)
          Y(I)=TEMP2(I)
 1210   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1301)N
 1301   FORMAT('AFTER SORT, N = ',I8)
        CALL DPWRST('XXX','WRIT')
        DO 1310 I=1,MIN(N,100)
          WRITE(ICOUT,1311)I,X(I),Y(I)
 1311     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
 1310   CONTINUE
      ENDIF
!
!               *****************************************
!               **  STEP 21--                          **
!               **  CARRY OUT CALCULATIONS             **
!               **  FOR NORMAL MIXTURE MLE ESTIMATION  **
!               *****************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'XML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
      IWRITE='OFF'
      TOL=1.0E-6
      IA = 1
      K = NCOMP
      IC = 0
!
      IF(NVAR.EQ.1)THEN
        NTOT2=N
        CALL MEAN(Y,N,IWRITE,AMEAN,IBUGA3,IERROR)
        CALL SD(Y,N,IWRITE,ASD,IBUGA3,IERROR)
        AMIN=Y(1)
        AMAX=Y(N)
        IRELAT='OFF'
        IRHSTG='PERC'
        CLWID=CLWIDT(1)
        IHSTO2='ON'
        CALL DPBIN(Y,N,IRELAT,CLWID,CLLIMI(1),CLLIMI(2),IRHSTG,   &
                   TEMP3,MAXNXT,IHSTCW,IHSTO2,   &
                   Y2,X2,N2,IBUGA3,IERROR)
!
        M=N2
        DO 2210 I=1,N2
          ITEMP1(I)=INT(Y2(I)+0.5)
 2210   CONTINUE
!
      ELSE
        M=N
        DO 2310 I=1,M
          ITEMP1(I)=INT(Y(I)+0.5)
          X2(I)=X(I)
 2310   CONTINUE
        DELTA=X2(2) - X2(1)
        AMIN=X2(1) - (DELTA/2.0)
        AMAX=X2(M) + (DELTA/2.0)
        DSUM1=0.0D0
        NTOT=0
        DO 2220 I=1,M
          NTOT=NTOT + ITEMP1(I)
          DSUM1= DSUM1 + DBLE(ITEMP1(I))*DBLE(X2(I))
 2220   CONTINUE
        AMEAN=REAL(DSUM1/DBLE(NTOT2))
        DSUM1=0.0D0
        DO 2230 I=1,M
          TERM1=X2(I) - AMEAN
          DSUM1= DSUM1 + DBLE(ITEMP1(I))*(DBLE(TERM1)**2)
 2230   CONTINUE
        ASD=REAL(DSUM1/DBLE(NTOT2))
      ENDIF
!
      ACOMP=REAL(NCOMP)
      PTEMP=1.0/ACOMP
      DO 2410 I=1,NCOMP
        ALPHA(I)=PTEMP
        XSD(I)=ASD
        XMEAN(I)=AMIN + REAL(I)*PTEMP*(AMAX-AMIN)
 2410 CONTINUE
      XMEAN(NCOMP)=XMEAN(NCOMP) - 0.5*PTEMP*(AMAX-AMIN)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        DO 2412 I=1,N2
          WRITE(ICOUT,2411)I,X2(I),ITEMP1(I)
 2411     FORMAT('I,X2(I),ITEMP1(I) = ',I8,G15.7,I8)
          CALL DPWRST('XXX','WRIT')
 2412   CONTINUE
      ENDIF
!
      CALL MIXTUR(IA,K,M,IC,X2,ITEMP1,   &
                  ALPHA,XMEAN,XSD,TOL,NTOT2,   &
                  WORK(1),WORK(KMAX+1),WORK(2*KMAX+1),WORK(3*KMAX+1),   &
                  WORK(4*KMAX+1),WORK(5*KMAX+1),WORK(6*KMAX+1),   &
                  WORK(7*KMAX+1),   &
                  KMAX,MMAX,   &
                  ALOGL,ICOUNT,IFAULT)
!
      IF(IFAULT.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2013)
 2013   FORMAT('     AN INVALID  CHOICE FOR DISTRIBUTION WAS MADE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2015)
 2015   FORMAT('     VALUE OF IA = ',I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(IFAULT.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2023)
 2023   FORMAT('     A MIXING PARAMETER OUTSIDE THE (0,1] ',   &
               'INTERVAL WAS SPECIFIED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(IFAULT.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2033)
 2033   FORMAT('     MEAN IS OUTSIDE THE RANGE OF THE DATA.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(IFAULT.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2043)
 2043   FORMAT('     A NON-POSITIVE STANDARD DEVIATION WAS ',   &
               'SPECIFIED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(IFAULT.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2053)
 2053   FORMAT('     INPUT DATA WAS NOT SORTED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(IFAULT.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2063)
 2063   FORMAT('     A NEGATIVE FREQUENCY WAS SPECIFIED OR THE ')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2065)
 2065   FORMAT('     TOTAL FREQUENCY IS LESS THAN 2 TIMES THE ',   &
               'NUMBER OF CLASSES.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(IFAULT.EQ.7)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2073)
 2073   FORMAT('     NEGATIVE FREQUENCY SPECIFIED FOR NON-NORMAL ',   &
               'DISTRIBUTION.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(IFAULT.EQ.8)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2083)
 2083   FORMAT('     EQUAL MEANS SPECIFIED FOR NON-NORMAL ',   &
               'DISTRIBUTION.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(IFAULT.EQ.9)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2093)
 2093   FORMAT('     ALL MEANS AND ALL STANDARD DEVIATIONS ',   &
               'WERE SPECIFIED EQUAL.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(IFAULT.GT.0)THEN
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF NMXML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)N
 9015   FORMAT('N = ',I8)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NMXML1
      SUBROUTINE NMXPPF(P,U1,SD1,U2,SD2,PMIX,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE NORMAL MIXTURE
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/5
!     ORIGINAL VERSION--MAY       1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION FXL
      DOUBLE PRECISION FXR
      DOUBLE PRECISION XLD
      DOUBLE PRECISION XRD
      DOUBLE PRECISION P1
      DOUBLE PRECISION X
      DOUBLE PRECISION PPFD
      DOUBLE PRECISION FCS
      DOUBLE PRECISION XRML
      DOUBLE PRECISION SIG
      DOUBLE PRECISION EPS
      DOUBLE PRECISION ZERO
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.00001D0/
      DATA SIG /1.0D-6/
      DATA ZERO /0.D0/
      DATA MAXIT /20000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO NMXPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD1.LE.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE FIRST SCALE PARAMETER TO ',   &
               'NMXPPF IS LESS THAN OR EQUAL TO 0.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD1
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD2.LE.0.0)THEN
        WRITE(ICOUT,13)
   13   FORMAT('***** ERROR--THE SECOND SCALE PARAMETER TO ',   &
               'NMXPPF IS LESS THAN OR EQUAL TO 0.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(PMIX.LT.0.0 .OR. PMIX.GT.1.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE MIXING PARAMETER TO ',   &
               'NMXPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PMIX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!  FIND BRACKETING INTERVAL.
!
      XMEAN=PMIX*U1 + (1.0-PMIX)*U2
      XVAR=PMIX*SD1*SD1 + (1.0-PMIX)*SD2*SD2 +   &
           PMIX*(1.0-PMIX)*(U1-U2)*(U1-U2)
      XSD=SQRT(XVAR)
!
      ICOUNT=0
      MAXCNT=100
!
      XL=XMEAN
      XINC=XSD
!
   91 CONTINUE
      XR=XL+XINC
      CALL NMXCDF(XL,U1,SD1,U2,SD2,PMIX,CDFL)
      CALL NMXCDF(XR,U1,SD1,U2,SD2,PMIX,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** ERROR--NMXPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL.')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      XLD=DBLE(XL)
      XRD=DBLE(XR)
      IC = 0
      FXL = DBLE(-P)
      FXR = DBLE(1.0 - P)
  105 CONTINUE
      X = (XLD+XRD)*0.5D0
      CALL NMDCDF(REAL(X),U1,SD1,U2,SD2,PMIX,DCDF)
      P1=DCDF
      PPFD=X
      PPF=REAL(PPFD)
      FCS = P1 - DBLE(P)
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XRD = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XLD = X
      FXL = FCS
  115 CONTINUE
      XRML = XRD - XLD
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--NMXPPF ROUTINE DID NOT CONVERGE.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NMXPPF
      SUBROUTINE NMXRAN(N,U1,SD1,U2,SD2,P,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE THE NORMAL (GAUSSIAN) MIXTURE
!              DISTRIBUTION.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE NORMAL MIXTURE DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     METHOD--1) CALCULATE UNIFORM RAND NUMBER.
!             2) IF LESS THAN OR EQUAL TO P, CALCULATE RAND NUMBER
!                FROM NORMAL WITH U1, SD1
!             3) IF GREATER THAN P, CALCULATE RAND NUMBER
!                FROM NORMAL WITH U2, SD2
!     REFERENCES--FOWLKES, "SOME METHODS FOR STUDYING THE MIXTURE
!                 OF TWO NORMAL (LOGNORMAL) DSITRIBUTIONS',
!                 JOURNAL OF THE AMERICAN STATISTICAL ASSOCIATION,
!                 SEPTEMBER, 1979.  PAGES 561-575.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--98.5
!     ORIGINAL VERSION--MAY       1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'NMXRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
      CALL UNIRAN(N,ISEED,X)
!
      NTEMP=1
      DO 200 I=1,N
        CALL NORRAN(NTEMP,ISEED,Y)
        IF(X(I).LE.P)THEN
          X(I)=U1 + SD1*Y(1)
        ELSE
          X(I)=U2 + SD2*Y(1)
        ENDIF
  200 CONTINUE
!
      RETURN
      END SUBROUTINE NMXRAN
      SUBROUTINE NORADA(X,N,IDIST,IWRITE,MAXOBV,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                        DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                        MINMAX,IGEPDF,IDFTTY,IWEIGL,AL,   &
                        STATVA,SHAPE1,SHAPE2,ALOC,SCALE,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE ANDERSON-DARLING STATISTIC
!              FOR VARIOUS DISTRIBUTIONS.  PARAMETERS ARE ESTIMATED
!              USING MAXIMUM LIKELIHOOD.  ALTERNATIVELY, RETURN THE
!              PARAMETER ESTIMATES OR THE CDF/P-VALUE.
!
!              THIS ROUTINE IS PROVIDED TO ALLOW A-D STATISTICS TO BE
!              TABULATED/PLOTTED IN THE 20+ COMMANDS THAT WORK WITH
!              BUILT-IN STATISTICS.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED ANDERSON-DARLING STATISTIC.
!     OUTPUT--VALUE OF THE ANDERSON-DARLING STATISTIC.
!     PRINTING--NO.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2015.2
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--FEBRUARY  2015.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*20 IDIST
      CHARACTER*4 IWRITE
      CHARACTER*4 IGEPDF
      CHARACTER*4 IDFTTY
      CHARACTER*4 IWEIGL
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
!
      CHARACTER*4 IADEDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 IGAUDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 ICENSO
      CHARACTER*4 IEXPBC
      CHARACTER*4 IWEIBC
      CHARACTER*4 ICENTY
      CHARACTER*4 IHSTCW
      CHARACTER*4 IHSTOU
      CHARACTER*4 IRELAT
      CHARACTER*4 IRHSTG
!
      CHARACTER*4 IDFTSV
!
      DOUBLE PRECISION DM
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      INTEGER ITEMP1(*)
!
      REAL CLWIDT(2)
      REAL CLLIMI(4)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!CCCC DATA PI/3.14159265359/
!
      ISUBN1='NORA'
      ISUBN2='DA  '
      IERROR='NO'
      IUPPER=MAXOBV
!
      ALOC=0.0
      SCALE=1.0
      SHAPE1=CPUMIN
      SHAPE2=CPUMIN
      SHAPE3=CPUMIN
      SHAPE4=CPUMIN
      SHAPE5=CPUMIN
      SHAPE6=CPUMIN
      SHAPE7=CPUMIN
      A=CPUMIN
      B=CPUMIN
      YLOWLM=CPUMIN
      YUPPLM=CPUMIN
!
      IADEDF='NULL'
      IMAKDF='NULL'
      IBEIDF='NULL'
      ILGADF='NULL'
      ISKNDF='NULL'
      IGLDDF='NULL'
      IBGEDF='NULL'
      IGETDF='NULL'
      ICONDF='NULL'
      IGOMDF='NULL'
      IKATDF='NULL'
      IGIGDF='NULL'
      IGEODF='NULL'
      IGAUDF='NULL'
      ICENSO='OFF'
      IEXPBC='NULL'
      IWEIBC='NULL'
      ICENTY='NULL'
      IDFTSV=IDFTTY
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RPPC')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF NORADA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IDIST,IBUGA3,ISUBRO,N,MAXOBV
   52   FORMAT('IDIST,IBUGA3,ISUBRO,N,MAXOBV = ',A16,2X,2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ************************************************
!               **  COMPUTE NORMAL                            **
!               **  PROBABILITY PLOT CORRELATION COEFFICIENT  **
!               ************************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!
      IF(N.LE.5 .OR. N.GE.MAXOBV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN NORMAL ANDERSON-DARLING--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE RESPONSE VARIABLE HAS FEWER THAN FIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)MAXNYW
  113   FORMAT('      OR MORE THAN ',I8,' OBSERVATIONS.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      IERROR='YES'
      GO TO 9000
  139 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  LOOP THROUGHT THE VARIOUS DISTRIBUTIONS.   **
!               *************************************************
!
      IWRITE='OFF'
!
!     SUPPORTED DISTRIBUTIONS:
!
!       LOCATION/SCALE DISTRIBUTIONS:
!       1. NORMAL
!       2. EXPONENTIAL
!       3. DOUBLE EXPONENTIAL
!       4. GUMBEL
!       5. LOGISTIC
!       6. UNIFORM
!       7. MAXWELL
!       8. RAYLEIGH
!
!       SCALE/ONE SHAPE PARAMETER DISTRIBUTIONS:
!       1. WEIBULL
!       2. LOGNORMAL
!       3. GAMMA
!       4. FATIGUE LIFE
!       5. BURR TYPE 10
!       6. LOGISTIC EXPONENTIAL
!       7. GEOMETRIC EXTREME EXPONENTIAL
!       8. FRECHET
!       9. INVERTED GAMMA
!
      IF(IDIST.EQ.'NORMAL')THEN
        ICASPL='NORM'
        CALL MEAN(X,N,IWRITE,ALOC,IBUGA3,IERROR)
        CALL SD(X,N,IWRITE,SCALE,IBUGA3,IERROR)
      ELSEIF(IDIST.EQ.'EXPONENTIAL')THEN
        ICASPL='EXPO'
        CALL MEAN(X,N,IWRITE,XMEAN,IBUGA3,IERROR)
        CALL MINIM(X,N,IWRITE,ALOC,IBUGA3,IERROR)
        SCALE=XMEAN-ALOC
      ELSEIF(IDIST.EQ.'DOUBLE EXPONENTIAL')THEN
        ICASPL='DEXP'
        CALL MEDIAN(X,N,IWRITE,TEMP1,MAXOBV,ALOC,IBUGA3,IERROR)
        XMED=ALOC
        DN=DBLE(N)
        DSUM=0.0D0
        DO 210 I=1,N
          DSUM=DSUM + DBLE(ABS(X(I) - XMED))
  210   CONTINUE
        SCALE=REAL(DSUM/DN)
!CCCC ELSEIF(IDIST.EQ.'UNIFORM')THEN
!
!       FOR UNIFORM, OBTAIN LOCATION/SCALE ESTIMATES USING
!       PPCC METHOD.
!
!CCCC   ICASPL='UNIF'
!CCCC   CALL UNIMED(N,TEMP1)
!CCCC   CALL SORT(X,N,X)
!CCCC   DO220J=1,N
!CCCC     CALL UNIPPF(TEMP1(J),TEMP2(J))
!C220   CONTINUE
!CCCC   CALL LINFI2(X,TEMP2,N,ALOC,SCALE,ISUBRO,IBUGA3,IERROR)
!CCCC   A=ALOC
!CCCC   B=ALOC + SCALE
!CCCC   YLOWLM=A
!CCCC   YUPPLM=B
!
      ELSEIF(IDIST.EQ.'GUMBEL' .OR. IDIST.EQ.'MAXWELL' .OR.   &
             IDIST.EQ.'RAYLEIGH' .OR. IDIST.EQ.'UNIFORM' .OR.   &
             IDIST.EQ.'LOGISTIC')THEN
        IF(IDIST.EQ.'GUMBEL')ICASPL='EV1 '
        IF(IDIST.EQ.'MAXWELL')ICASPL='MAXW'
        IF(IDIST.EQ.'RAYLEIGH')ICASPL='RAYL'
        IF(IDIST.EQ.'UNIFORM')ICASPL='UNIF'
        IF(IDIST.EQ.'LOGISTIC')ICASPL='LOGI'
        IF(IDIST.EQ.'UNIFORM')THEN
          IDFTTY='MOME'
        ENDIF
        IFLAGD=1
        CALL DPML1(X,X,N,ICASPL,IFLAGD,IFLAG9,   &
                   TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP5,   &
                   DTEMP1,DTEMP2,DTEMP3,ITEMP1,MAXOBV,   &
                   ALOC,SCALE,ALOWLI,AUPPLI,   &
                   SH1,SH2,SH3,SH4,   &
                   SH5,SH6,SH7,   &
                   YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                   IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                   ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                   IGEODF,IBGEDF,IGAUDF,   &
                   ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                   CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                   IBUGA3,ISUBRO,IERROR)
        IF(IDIST.EQ.'UNIFORM')THEN
          A=ALOC
          B=ALOC + SCALE
          YLOWLM=A
          YUPPLM=B
        ENDIF
      ELSEIF(IDIST.EQ.'GAMMA' .OR.   &
             IDIST.EQ.'WEIBULL' .OR.   &
             IDIST.EQ.'LOGNORMAL' .OR.   &
             IDIST.EQ.'FRECHET' .OR.   &
             IDIST.EQ.'BURR TYPE 10' .OR.   &
             IDIST.EQ.'INVERTED GAMMA' .OR.   &
             IDIST.EQ.'GEOMETRIC EXTR EXPO' .OR.   &
             IDIST.EQ.'LOGISTIC EXPONENTIAL' .OR.   &
             IDIST.EQ.'FATIGUE LIFE'   &
            )THEN
        IF(IDIST.EQ.'GAMMA')ICASPL='GAMM'
        IF(IDIST.EQ.'LOGNORMAL')ICASPL='LOGN'
        IF(IDIST.EQ.'WEIBULL')ICASPL='WEIB'
        IF(IDIST.EQ.'FRECHET')ICASPL='EV2'
        IF(IDIST.EQ.'BURR TYPE 10')ICASPL='BU10'
        IF(IDIST.EQ.'INVERTED GAMMA')ICASPL='IGAM'
        IF(IDIST.EQ.'GEOMETRIC EXTR EXPO')ICASPL='GEEX'
        IF(IDIST.EQ.'LOGISTIC EXPONENTIAL')ICASPL='LEXP'
        IF(IDIST.EQ.'FATIGUE LIFE')ICASPL='FATL'
        IFLAGD=1
        CALL DPML1(X,X,N,ICASPL,IFLAGD,IFLAG9,   &
                   TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP5,   &
                   DTEMP1,DTEMP2,DTEMP3,ITEMP1,MAXOBV,   &
                   ALOC,SCALE,ALOWLI,AUPPLI,   &
                   SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                   SHAPE5,SHAPE6,SHAPE7,   &
                   YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                   IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                   ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                   IGEODF,IBGEDF,IGAUDF,   &
                   ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                   CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                   IBUGA3,ISUBRO,IERROR)
        ALOC=0.0
!
!       FOR WEIBULL, CHECK IF "GAUGE LENGTH" OPTION IS ON.  IF SO,
!       THEN ADJUST ESTIMATE OF THE SCALE PARAMETER.
!
        IF(IDIST.EQ.'WEIBULL')ICASPL='WEIB'
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,399)IDIST
  399   FORMAT('      NO MATCH FOR DISTRIBUTION: ',A20)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      ICASP2='AD  '
      CALL DPGOF9(X,N,ICASPL,ICASP2,   &
                  TEMP1,TEMP2,TEMP3,N2,   &
                  YLOWLM,YUPPLM,A,B,MINMAX,   &
                  SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                  SHAPE5,SHAPE6,SHAPE7,   &
                  IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                  ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                  IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                  MAXOBV,   &
                  ALOC,SCALE,   &
                  STATVA,DM,   &
                  IBUGA3,ISUBRO,IERROR,IERRFL)
!
!       FOR WEIBULL, CHECK IF "GAUGE LENGTH" OPTION IS ON.  IF SO,
!       THEN ADJUST ESTIMATE OF THE SCALE PARAMETER.  NOTE THAT THIS
!       IS NOT NEEDED FOR COMPUTING THE GOODNESS OF FIT STATISTIC, BUT
!       IT MAY BE HELPFUL IF THE SCALE PARAMETER IS BEING DISPLAYED.
!       ONLY DO THIS IF GAUGE LENGTH PARAMETER IS POSITIVE.
!
        IF(IDIST.EQ.'WEIBULL' .AND. IWEIGL.EQ.'ON')THEN
          IF(AL.GT.0.0)THEN
            SCALE=AL**(1.0/SHAPE1)*SCALE
          ENDIF
        ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,STATVA
  811   FORMAT('THE ANDERSON-DARLING STATISTIC OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IDFTTY=IDFTSV
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RPPC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF NORADA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)STATVA,ALOC,SCALE,SHAPE1
 9014   FORMAT('STATVA,ALOC,SCALE,SHAPE1 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE NORADA
      SUBROUTINE NORCDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/SQRT(2*PI))*EXP(-X*X/2).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 932, FORMULA 26.2.17.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 40-111.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA B1,B2,B3,B4,B5,P/.319381530,-0.356563782,1.781477937,   &
                            -1.821255978,1.330274429,.2316419/
!
!-----START POINT-----------------------------------------------------
!
      Z=X
      IF(X.LT.0.0)Z=-Z
      T=1.0/(1.0+P*Z)
      CDF=1.0-((0.39894228040143  )*EXP(-0.5*Z*Z))*(B1*T+B2*T**2+B3*T**3   &
      +B4*T**4+B5*T**5)
      IF(X.LT.0.0)CDF=1.0-CDF
!
      RETURN
      END SUBROUTINE NORCDF
      SUBROUTINE NORFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              CENSORED NORMAL MAXIMUM LIKELIHOOD EQUATIONS.
!
!                 SUM[i=1 to r][Z(I)] + SUM[j=1 to m][h(y(i)] = 0
!                 SUM[i=1 to r][Z(I)**2] + SUM[j=1 to m][y(i)*h(y(i)] - r = 0
!
!              WITH
!
!                 r = NUMBER OF FAILURE TIMES
!                 m = NUMBER OF CENSORED ITEMS
!
!                 Z(I) = (X(i) - muhat)/sigmahat
!                 Y(I) = (C(j) - muhat)/sigmahat
!
!                 h IS THE NORMAL HAZARD FUNCTION.
!
!              WITH C AND K DENOTING THE SHAPE PARAMETERS,
!              RESPECTIVELY.  THE muhat AND sigmahat PARAMETERS ARE
!              THE QUANTITIES BEING ESTIMATED.  USE THE MEAN AND
!              STANDARD DEVIATION OF THE FAILURE TIMES DATA AS
!              STARTING VALUES.
!
!              TO SIMPLIFY THE INTERFACE, SORT THE INPUT DATA
!              ARRAY, X, SO THAT THE r FAILURE TIMES COME FIRST
!              AND THEN THE M CENSOR TIMES.
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--NORMAL MAXIMUM LIKELIHOOD Y CENSOR
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/11
!     ORIGINAL VERSION--NOVEMBER  2003.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION MU
      DOUBLE PRECISION SIGMA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DCDF
!
!---------------------------------------------------------------------
!
      COMMON/NORCML/IR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      MU=X(1)
      SIGMA=X(2)
      DN=DBLE(NOBS)
      DR=DBLE(IR)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 200 I=1,IR
        DX=DBLE(XDATA(I))
        DX=(DX - MU)/SIGMA
        DSUM1=DSUM1 + DX
        DSUM2=DSUM2 + DX*DX
  200 CONTINUE
!
      DSUM3=0.0D0
      DSUM4=0.0D0
      IF(IR.LT.NOBS)THEN
        DO 300 I=IR+1,NOBS
          DX=DBLE(XDATA(I))
          DX=(DX - MU)/SIGMA
          CALL NODPDF(DX,DPDF)
          CALL NODCDF(DX,DCDF)
          DHAZ=DPDF/(1.0D0 - DCDF)
          DSUM3=DSUM3 + DHAZ
          DSUM4=DSUM4 + DX*DHAZ
  300   CONTINUE
      ENDIF
!
      FVEC(1)=DSUM1 + DSUM3
      FVEC(2)=DSUM2 + DSUM4 - DR
!
      RETURN
      END SUBROUTINE NORFUN 
      SUBROUTINE NORLI1(Y,N,ALOC,SCALE,   &
      ALIK,AIC,AICC,BIC,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE NORMAL DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DN
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NORL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NORLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     LOG-LIKELIHOOD FUNCTION IS:
!
!     -(N/2)*LOG(2*PI) - N*LOG(SIGMA) -
!     0.5*SUM[i=1 to N][((X(I)-MU)/SIGMA)**2]
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTERM1=-(DN/2.0D0)*DLOG(2.0D0*DPI) - DN*DLOG(DS)
      DSUM1=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + ((DX-DU)/DS)**2
 1000 CONTINUE
!
      DLIK=DTERM1 - 0.5D0*DSUM1
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NORLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NORLI1
      SUBROUTINE NORLI2(Y,X,N,IR,ALOC,SCALE,   &
      ALIK,AIC,AICC,BIC,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE NORMAL DISTRIBUTION.  THIS IS FOR RIGHT CENSORED
!              DATA WITH NO GROUPING.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DN
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NORL'
      ISUBN2='I1  '
!
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NORLI2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     LOG-LIKELIHOOD FUNCTION IS (WE ASSUME THE FAILURE TIMES
!     ARE IN OBSERVATIONS 1 TO R AND THE CENSORING TIMES ARE IN
!     OBSERVATIONS R+1 TO N):
!
!     -(R/2)*LOG(2*PI) - R*LOG(SIGMA) -
!     0.5*SUM[i=1 to R][((Y(I)-MU)/SIGMA)**2] +
!     SUM[i=R+1 to N][1 - NORCDF(Y(I),MU,SIGMA)]
!
      DR=DBLE(IR)
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTERM1=-(DR/2.0D0)*DLOG(2.0D0*DPI) - DR*DLOG(DS)
      DSUM1=0.0D0
      DO 1000 I=1,IR
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + ((DX-DU)/DS)**2
 1000 CONTINUE
!
      DSUM2=0.0D0
      IF(IR.LT.N)THEN
        DO 2000 I=IR+1,N
          DX=DBLE(Y(I))
          DX=(DX-DU)/DS
          CALL NODCDF(DX,DCDF)
          DSUM2=DSUM2 + (1.0D0 - DCDF)
 2000   CONTINUE
      ENDIF
!
      DLIK=DTERM1 - 0.5D0*DSUM1 + DSUM2
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIK2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NORLI2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3,DCDF
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3,DCDF = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NORLI2
      SUBROUTINE NORML1(Y,N,ICASE,   &
      ALOWLO,AUPPLO,ALOWSC,AUPPSC,ALPHA,NUMALP,NUMOUT,   &
      XMEAN,XSD,XVAR,XMIN,XMAX,XSDMEA,XSDSD,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE NORMAL DISTRIBUTION FOR THE RAW DATA CASE
!              (I.E., NO CENSORING AND NO GROUPING).  IT WILL ALSO
!              RETURN THE CONFIDENCE INTERVALS FOR THE LOCATION
!              AND SCALE PARAMETERS.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLN1 WILL GENERATE THE OUTPUT
!              FOR THE NORMAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!              --JOHNSON, KEMP, AND KOTZ.  "UNIVARIATE DISCRETE
!                DISTRIBUTIONS", THIRD EDITION, WILEY, 2005, CHAPTER 5.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLNO)
!     UPDATED         --OCTOBER   2009. ADD "ICASE":
!                                       0 => POINT ESTIMATE ONLY
!                                       1 => POINT ESTIMATE PLUS
!                                            UNCERTAINTY INTERVALS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION ALOWLO(*)
      DIMENSION AUPPLO(*)
      DIMENSION ALOWSC(*)
      DIMENSION AUPPSC(*)
      DIMENSION ALPHA(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
      INTEGER ICASE
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NORM'
      ISUBN2='L1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NORML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE
   52   FORMAT('IBUGA3,ISUBRO,ICASE = ',2(A4,2X),I5)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NORMAL MLE ESTIMATE             **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='NORMAL'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(ICASE.EQ.0)GO TO 9000
!
      AN=REAL(N)
      XSDMEA=XSD/SQRT(AN)
      XSDSD=XSD/SQRT(2.0*(AN-1.0))
!
      IDF=N-1
      ADF=REAL(IDF)
      DO 1010 I=1,NUMALP
!
        ALP=ALPHA(I)
        P1=ALP/2.0
        P2=1.0-(ALP/2.0)
!
        CALL TPPF(P1,REAL(IDF),TLOW)
        CALL TPPF(P2,REAL(IDF),TUPP)
        ALOWLO(I)=XMEAN + TLOW*XSDMEA
        AUPPLO(I)=XMEAN + TUPP*XSDMEA
!
        CALL CHSPPF(P1,IDF,APPF1)
        CALL CHSPPF(P2,IDF,APPF2)
        ALOWSC(I)=XSD*SQRT(ADF/APPF2)
        AUPPSC(I)=XSD*SQRT(ADF/APPF1)
!
 1010 CONTINUE
      NUMOUT=NUMALP
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NORML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,XMEAN,XSD,XSDMEA,XSDSD
   55   FORMAT('N,XMEAN,XSD,XSDMEA,XSDSD = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NORML1
      SUBROUTINE NORML2(Y,X,N,IR,   &
                        XTEMP,DTEMP1,ITEMP,MAXNXT,IOUNI2,   &
                        ALOWLO,AUPPLO,ALOWSC,AUPPSC,ALPHA,NUMALP,NUMOUT,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XSDMEA,XSDSD,XCOV,COV,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE NORMAL DISTRIBUTION FOR THE UNGROUPED,
!              MULTIPLY RIGHT CENSORED DATA CASE.  IT WILL ALSO
!              RETURN THE CONFIDENCE INTERVALS FOR THE LOCATION
!              AND SCALE PARAMETERS.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLN2 WILL GENERATE THE OUTPUT
!              FOR THE NORMAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!              --CLIFFORD COHEN, "TRUNCATED AND CENSORED SAMPLES:
!                THEORY AND APPLICATIONS", DEKKER, 1991.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLNO)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION ALOWLO(*)
      DIMENSION AUPPLO(*)
      DIMENSION ALOWSC(*)
      DIMENSION AUPPSC(*)
      DIMENSION ALPHA(*)
!
      DIMENSION FISH(2,2)
      DIMENSION COV(2,2)
!
      COMMON/NORCML/IR2
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      EXTERNAL NORFUN
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DX
      DOUBLE PRECISION MU
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION SIGMA
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
      DOUBLE PRECISION DSUM6
      DOUBLE PRECISION DPPF1
      DOUBLE PRECISION DPPF2
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DIMENSION ITEMP(*)
      DOUBLE PRECISION DTEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NORM'
      ISUBN2='L1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NORML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NORMAL MLE ESTIMATE             **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='NORMAL'
      CALL CKCENS(X,XTEMP,N,IDIST,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      CALL SORTC(Y,X,N,Y,X)
      IR=0
      DO 2120 I=1,N
        IF(X(I).EQ.1.0)IR=IR+1
 2120 CONTINUE
!
      IFLAG=0
      CALL SUMRAW(Y,IR,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IR2=IR
      XPAR(1)=DBLE(XMEAN)
      XPAR(2)=DBLE(XSD)
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(NORFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      XMEAN=REAL(XPAR(1))
      XSD=REAL(XPAR(2))
!
!  NOW COMPUTE THE FISHER INFORMATION MATRIX, INVERT TO GET THE
!  PARAMETER VARIANCE-COVARIANCE MATRIX.
!
      MU=DBLE(XMEAN)
      SIGMA=DBLE(XSD)
      DN=DBLE(N)
      DR=DBLE(IR)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 4150 I=1,IR
        DX=(DBLE(Y(I)) - MU)/SIGMA
        DSUM1=DSUM1 + DX
        DSUM2=DSUM2 + DX*DX
 4150 CONTINUE
!
      DSUM3=0.0D0
      DSUM4=0.0D0
      DSUM5=0.0D0
      DSUM6=0.0D0
      IF(IR.LT.N)THEN
        DO 4180 I=IR+1,N
          DX=(DBLE(Y(I)) - MU)/SIGMA
          CALL NODPDF(DX,DPDF)
          CALL NODCDF(DX,DCDF)
          DHAZ=DPDF/(1.0D0 - DCDF)
          DSUM3=DSUM3 + DHAZ*(DHAZ - DX)
          DSUM4=DSUM4 + DHAZ*(1.0D0 + DX*(DHAZ - DX))
          DSUM5=DSUM5 + DX*DHAZ
          DSUM6=DSUM6 + DX*DX*DHAZ*(DHAZ - DX)
 4180   CONTINUE
      ENDIF
      XVAR=XSD*XSD
      FISH(1,1)=(1.0/XVAR)*REAL(DR + DSUM3)
      FISH(1,2)=(1.0/XVAR)*REAL(2.0D0*DSUM1 + DSUM4)
      FISH(2,1)=FISH(1,2)
      FISH(2,2)=(1.0/XVAR)*REAL(3.0D0*DSUM2+2.0D0*DSUM5+DSUM6-DR)
!
      NDIM=2
      CALL SGECO(FISH,NDIM,NDIM,ITEMP,RCOND,XTEMP)
      IJOB=1
      CALL SGEDI(FISH,NDIM,NDIM,ITEMP,XTEMP,XTEMP(MAXNXT/2),IJOB)
      DO 4210 J=1,NDIM
        DO 4215 I=1,NDIM
          COV(I,J)=FISH(I,J)
 4215   CONTINUE
 4210 CONTINUE
      DO 4219 I=1,NDIM
        WRITE(IOUNI2,'(2E15.7)')(COV(I,J),J=1,NDIM)
 4219 CONTINUE
!
      XSDMEA=SQRT(COV(1,1))
      XSDSD=SQRT(COV(2,2))
      XCOV=COV(1,2)
!
      IDF=N-1
      ADF=REAL(IDF)
      DO 1010 I=1,NUMALP
!
        ALP=ALPHA(I)
        P1=ALP/2.0
        P2=1.0-(ALP/2.0)
!
        CALL NODPPF(DBLE(P1),DPPF1)
        CALL NODPPF(DBLE(P2),DPPF2)
        ALOWLO(I)=0.0
        AUPPLO(I)=0.0
        ALOWSC(I)=0.0
        AUPPSC(I)=0.0
!
        IF(COV(1,1).GE.0.0)THEN
          ALOWLO(I)=XMEAN + REAL(DPPF1)*SQRT(COV(1,1))
          AUPPLO(I)=XMEAN + REAL(DPPF2)*SQRT(COV(1,1))
        ENDIF
        IF(COV(2,2).GE.0.0)THEN
          ALOWSC(I)=XMEAN + REAL(DPPF1)*SQRT(COV(2,2))
          AUPPSC(I)=XMEAN + REAL(DPPF2)*SQRT(COV(2,2))
        ENDIF
!
 1010 CONTINUE
      NUMOUT=NUMALP
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NORML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,XMEAN,XSD,XSDMEA,XSDSD
   55   FORMAT('N,XMEAN,XSD,XSDMEA,XSDSD = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE NORML2
      SUBROUTINE NORPDF(X,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/SQRT(2*PI))*EXP(-X*X/2).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 931, FORMULA 26.2.1.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DENSITYS--1, 1970, PAGES 40-111.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265/
!
!-----START POINT-----------------------------------------------------
!
      CONST=1/SQRT(2.0*PI)
      TERM=EXP(-0.5*X**2)
      PDF=CONST*TERM
!
      RETURN
      END SUBROUTINE NORPDF
      SUBROUTINE NORPE1(Y,N,NPERC,XMEAN,XSD,IOUNI1,IDTYPR,   &
                        QP,XQPHAT,XQPSE,XQPLCL,XQPUCL,   &
                        ALPHAP,NUMALP,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES PERCENTILES AND ASSOCIATED
!              CONIDENCE INTERVALS (BASED ON THE ML ESTIMATES) FOR
!              THE NORMAL DISTRIBUTION FOR THE RAW DATA CASE
!              (I.E., NO CENSORING AND NO GROUPING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLN1 WILL GENERATE THE OUTPUT
!              FOR THE NORMAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLNO)
!     UPDATED         --MARCH     2014. SUPPORT ONE-SIDED INTERVALS
!                                       (IDTYPR)
!     UPDATED         --FEBRUARY  2017. INCLUDE STANDARD ERROR (XQPSE)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION QP(*)
      DIMENSION XQPHAT(*)
      DIMENSION XQPSE(*)
      DIMENSION XQPLCL(*)
      DIMENSION XQPUCL(*)
!
      DOUBLE PRECISION DPPF
!
      CHARACTER*4 IDTYPR
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NORP'
      ISUBN2='E1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RPE1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NORPE1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IDTYPR
   52   FORMAT('IBUGA3,ISUBRO,IDTYPR = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)N,NPERC,NUMALP
   53   FORMAT('N,NPERC,NUMALP = ',3I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NORMAL PERCENTILES              **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RPE1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NPERC.GE.1)THEN
!
!       2014/03: ONE-SIDED INTERVALS FOR PERCENTILES ARE EQUIVALENT TO
!                ONE-SIDED TOLERANCE INTERVALS.  SO IT MAY SOMETIMES
!                BE DESIRABLE TO COMPUTE ONE-SIDED INTERVALS.
!
        AN=REAL(N)
        C1=XSD/SQRT(AN)
        ANU=REAL(N-1)
        C4=XSD/SQRT(2.0*ANU)
        IF(IDTYPR.EQ.'LOWE')THEN
          ALPHL=ALPHAP
          ALPHU=1.0 - ALPHAP
        ELSEIF(IDTYPR.EQ.'UPPE')THEN
          ALPHL=ALPHAP
          ALPHU=1.0 - ALPHAP
        ELSE
          ALPHL=ALPHAP/2.0
          ALPHU=1.0 - ALPHAP/2.0
        ENDIF
!
        WRITE(IOUNI1,1001)
 1001   FORMAT(15X,'       POINT     ','     LOWER     ',   &
               '     UPPER')
        WRITE(IOUNI1,1002)
 1002   FORMAT('    PERCENTILE ','     ESTIMATE   ',   &
               'CONFIDENCE LIMIT ','CONFIDENCE LIMIT')
!
        DO 1110 I=1,NPERC
          QPTEMP=QP(I)/100.0
          CALL NODPPF(DBLE(QPTEMP),DPPF)
          XQPHAT(I)=XMEAN + XSD*REAL(DPPF)
          DELTA=REAL(DPPF)*SQRT(AN)
          TERM1=C1**2 + (REAL(DPPF)*C4)**2
          XQPSE(I)=SQRT(TERM1)
          IF(DELTA.LT.0.0)THEN
            DELTA2=-DELTA
            CALL NCTPPF(ALPHU,ANU,DELTA2,C2)
            C2=-C2
            CALL NCTPPF(ALPHL,ANU,DELTA2,C3)
            C3=-C3
          ELSE
            CALL NCTPPF(ALPHL,ANU,DELTA,C2)
            CALL NCTPPF(ALPHU,ANU,DELTA,C3)
          ENDIF
          ATEMP1=XMEAN + C1*C2
          ATEMP2=XMEAN + C1*C3
          IF(IDTYPR.EQ.'UPPE')THEN
            XQPLCL(I)=CPUMIN
          ELSE
            XQPLCL(I)=MIN(ATEMP1,ATEMP2)
          ENDIF
          IF(IDTYPR.EQ.'LOWE')THEN
            XQPUCL(I)=CPUMIN
          ELSE
            XQPUCL(I)=MAX(ATEMP1,ATEMP2)
          ENDIF
          WRITE(IOUNI1,'(4E15.7,2X,E15.7)')   &
               QP(I),XQPHAT(I),XQPSE(I),XQPLCL(I),XQPUCL(I)
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RPE1')THEN
            WRITE(ICOUT,1113)XMEAN,XSD,ANU,ALPHAP
 1113       FORMAT('XMEAN,XSD,ANU,ALPHAP = ',4G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1115)DELTA,C1,C2,C3
 1115       FORMAT('DELTA,C1,C2,C3 = ',4G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1117)ATEMP1,ATEMP2
 1117       FORMAT('ATEMP1,ATEMP2 = ',2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
 1110   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RPE1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NORPE1--')
        CALL DPWRST('XXX','WRIT')
        IF(NPERC.GT.1)THEN
          DO 9050 I=1,NPERC
            WRITE(ICOUT,9055)I,QP(I),XQPHAT(I),XQPSE(I),   &
                             XQPLCL(I),XQPUCL(I)
 9055       FORMAT('I,QP(I),XQPHAT(I),XQPSE(I),XQPLCL(I),XQPUCL(I) = ',   &
                   I8,5G15.7)
            CALL DPWRST('XXX','WRIT')
 9050     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE NORPE1
      SUBROUTINE NORPE2(Y,X,N,IR,NPERC,IDTYPR,   &
                        XMEAN,XSD,COV,IOUNI1,   &
                        QP,XQPHAT,XQPLCL,XQPUCL,   &
                        ALPHAP,NUMALP,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES PERCENTILES AND ASSOCIATED
!              CONIDENCE INTERVALS (BASED ON THE ML ESTIMATES) FOR
!              THE NORMAL DISTRIBUTION FOR THE MULTIPLY CENSORED
!              UNGROUPED DATA CASE.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLN1 WILL GENERATE THE OUTPUT
!              FOR THE NORMAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 10.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLNO)
!     UPDATED         --MARCH     2014. SUPPORT FOR ONE-SIDED PERCENTILES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION QP(*)
      DIMENSION XQPHAT(*)
      DIMENSION XQPLCL(*)
      DIMENSION XQPUCL(*)
!
      CHARACTER*4 IDTYPR
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION COV(2,2)
!
      DOUBLE PRECISION ZALPU
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION D(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NORP'
      ISUBN2='E2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RPE2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF NORPE2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IDTYPR
   52   FORMAT('IBUGA3,ISUBRO,IDTYPR = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)N,IR,NPERC,NUMALP,ALPHAP
   53   FORMAT('N,IR,NPERC,NUMALP,ALPHAP = ',4I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)XMEAN,XSD,COV(1,1),COV(2,2),COV(2,1)
   54   FORMAT('XMEAN,XSD,COV(1,1),COV(2,2),COV(2,1) = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS FOR          **
!               **  CENSORED NORMAL PERCENTILES         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RPE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NPERC.GE.1)THEN
!
        D(1)=1.0D0
        IF(IDTYPR.EQ.'LOWE')THEN
          ALPHL=ALPHAP
          ALPHU=1.0 - ALPHAP
        ELSEIF(IDTYPR.EQ.'UPPE')THEN
          ALPHL=ALPHAP
          ALPHU=1.0 - ALPHAP
        ELSE
          ALPHL=ALPHAP/2.0
          ALPHU=1.0 - ALPHAP/2.0
        ENDIF
        CALL NODPPF(DBLE(ALPHU),ZALPU)
!
        WRITE(IOUNI1,1001)
 1001   FORMAT(15X,'       POINT     ','     LOWER     ',   &
               '     UPPER')
        WRITE(IOUNI1,1002)
 1002   FORMAT('    PERCENTILE ','     ESTIMATE   ',   &
               'CONFIDENCE LIMIT ','CONFIDENCE LIMIT')
!
        DO 1010 I=1,NPERC
          QPTEMP=QP(I)/100.0
          CALL NODPPF(DBLE(QPTEMP),D(2))
          XQPHAT(I)=XMEAN + XSD*REAL(D(2))
          DSUM1=0.0D0
          DO 1020 II=1,2
            DO 1030 JJ=1,2
              DSUM1=DSUM1 + D(II)*D(JJ)*DBLE(COV(II,JJ))
 1030       CONTINUE
 1020     CONTINUE
          XQPSE=SQRT(REAL(DSUM1))
          ATEMP1=XQPHAT(I) - REAL(ZALPU)*XQPSE
          ATEMP2=XQPHAT(I) + REAL(ZALPU)*XQPSE
          XQPLCL(I)=MIN(ATEMP1,ATEMP2)
          XQPUCL(I)=MAX(ATEMP1,ATEMP2)
          IF(IDTYPR.EQ.'LOWE')XQPUCL(I)=CPUMIN
          IF(IDTYPR.EQ.'UPPE')XQPLCL(I)=CPUMIN
!
          WRITE(IOUNI1,'(3E15.7,2X,E15.7)')   &
               QP(I),XQPHAT(I),XQPLCL(I),XQPUCL(I)
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MLNO')THEN
            WRITE(ICOUT,1061)I,QP(I),XQPHAT(I)
 1061       FORMAT('I,QP(I),XQPHAT(I),ZALPU = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1065)ZALPU,DSUM1,XQPSE
 1065       FORMAT('ZALPU,DSUM1,XQPSE = ',3G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1067)ATEMP1,ATEMP2
 1067       FORMAT('ATEMP1,ATEMP2 = ',2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
 1010   CONTINUE
!
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RPE2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF NORPE2--')
        CALL DPWRST('XXX','WRIT')
        IF(NPERC.GT.1)THEN
          DO 9050 I=1,NPERC
            WRITE(ICOUT,9055)I,QP(I),XQPHAT(I),XQPLCL(I),XQPUCL(I)
 9055       FORMAT('I,QP(I),XQPHAT(I),XQPLCL(I),XQPUCL(I) = ',   &
                   I8,4G15.7)
            CALL DPWRST('XXX','WRIT')
 9050     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE NORPE2
      SUBROUTINE NORPCV(ALPHA,N,CV,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE RETURNS EITHER THE 0.01 OR THE
!              THE 0.05 PERCENT POINT OF THE PPCC STATISTIC FOR
!              THE NORMAL DISTRIBUTION FOR 3 <= N <= 1,000.  THESE
!              ARE THE CRITICAL VALUES COMPUTED BY JUDY DEVANEY
