      SUBROUTINE NORPPC(X,N,IDIST,ALAMB,ALAMB2,   &
                        IWRITE,Y,W,TEMP1,DTEMP1,MAXNYW,   &
                        MINMAX,IGEPDF,   &
                        PPCC,SHAPE,SHAPE2,ALOC,SCALE,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE NORMAL
!              PROBABILITY PLOT CORRELATION COEFFICIENT.
!              THE PROTOTYPE NORMAL DISTRIBUTION USED HEREIN
!              HAS MEAN = 0 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/SQRT(2*PI)) * EXP(-X*X/2).
!              AS USED HEREIN, A PROBABILITY PLOT FOR A DISTRIBUTION
!              IS A PLOT OF THE ORDERED OBSERVATIONS VERSUS
!              THE ORDER STATISTIC MEDIANS FOR THAT DISTRIBUTION.
!              THE NORMAL PROBABILITY PLOT IS USEFUL IN
!              GRAPHICALLY TESTING THE COMPOSITE (THAT IS,
!              LOCATION AND SCALE PARAMETERS NEED NOT BE SPECIFIED)
!              HYPOTHESIS THAT THE UNDERLYING DISTRIBUTION
!              FROM WHICH THE DATA HAVE BEEN RANDOMLY DRAWN
!              IS THE NORMAL DISTRIBUTION.
!              IF THE HYPOTHESIS IS TRUE, THE PROBABILITY PLOT
!              SHOULD BE NEAR-LINEAR.
!              A MEASURE OF SUCH LINEARITY IS GIVEN BY THE
!              CALCULATED PROBABILITY PLOT CORRELATION COEFFICIENT.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--PPCC   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED NORMAL PPCC.
!     OUTPUT--NONE.
!     PRINTING--YES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, UNIMED, NORPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FILLIBEN, 'TECHNIQUES FOR TAIL LENGTH ANALYSIS',
!                 PROCEEDINGS OF THE EIGHTEENTH CONFERENCE
!                 ON THE DESIGN OF EXPERIMENTS IN ARMY RESEARCH
!                 DEVELOPMENT AND TESTING (ABERDEEN, MARYLAND,
!                 OCTOBER, 1972), PAGES 425-450.
!               --FILLIBEN, 'THE PROBABILITY PLOT CORRELATION COEFFICIENT
!                 TEST FOR NORMALITY', TECHNOMETRICS, 1975, PAGES 111-117.
!               --RYAN AND JOINER, 'NORMAL PROBABILITY PLOTS AND TESTS
!                 FOR NORMALITY'  PENNSYLVANIA
!                 STATE UNIVERSITY REPORT.
!               --HAHN AND SHAPIRO, STATISTICAL METHODS IN ENGINEERING,
!                 1967, PAGES 260-308.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 40-111.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--JULY      1972.
!     UPDATED         --JULY      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       2011. INCORPORATE OTHER DISTRIBUTIONS
!     UPDATED         --JANUARY   2013. FOR WEIBULL AND TUKEY-LAMBDA, OPTION
!                                       TO ESTIMATE SHAPE PARAMETER
!     UPDATED         --FEBRUARY  2013. ADD LOGNORMAL
!     UPDATED         --FEBRUARY  2013. ADD GENERALIZED PARETO
!     UPDATED         --FEBRUARY  2013. ADD G AND H
!     UPDATED         --FEBRUARY  2013. ADD WALD, INVERTED WEIBULL
!     UPDATED         --FEBRUARY  2013. ADD GAMMA, FATIGUE LIFE
!     UPDATED         --MARCH     2013. ADD SINE
!     UPDATED         --FEBRUARY  2015. ADD G
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*20 IDIST
      CHARACTER*4 IWRITE
      CHARACTER*4 IGEPDF
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IWRISV
      CHARACTER*4 IWEIBC
      CHARACTER*4 IWEIFL
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DPPF
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION W(*)
      DIMENSION TEMP1(*)
!
      DOUBLE PRECISION DTEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA PI/3.14159265359/
!
      ISUBN1='NORP'
      ISUBN2='PC  '
      IERROR='NO'
      IUPPER=MAXNYW
!
      SUM1=0.0
      SUM2=0.0
      SUM3=0.0
      AN=N
      PPCC=0.0
      SHAPE=ALAMB
      WBAR=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RPPC')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF NORPPC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IDIST,IBUGA3,ISUBRO,N,MAXNYW
   52   FORMAT('IDIST,IBUGA3,ISUBRO,N,MAXNXT = ',A16,2X,2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ************************************************
!               **  COMPUTE NORMAL                            **
!               **  PROBABILITY PLOT CORRELATION COEFFICIENT  **
!               ************************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!
      IF(N.EQ.1)THEN
        GO TO 9000
      ELSEIF(N.LE.2 .OR. N.GE.MAXNYW)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN NORMAL PPCC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE RESPONSE VARIABLE HAS FEWER THAN TWO')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)MAXNYW
  113   FORMAT('      OR MORE THAN ',I8,' OBSERVATIONS.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      GO TO 9000
  139 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE NORMAL                         **
!               **  PROBABILITY PLOT CORRELATION COEFFICIENT.  **
!               *************************************************
!
      CALL SORT(X,N,Y)
      CALL UNIMED(N,W)
      IWRISV=IWRITE
      IWRITE='OFF'
      CALL MEAN(Y,N,IWRITE,YBAR,IBUGA3,IERROR)
      IWRITE=IWRISV
!
      IF(IDIST.EQ.'NORMAL')THEN
        DO 200 I=1,N
          CALL NORPPF(W(I),WOUT)
          W(I)=WOUT
  200   CONTINUE
        WBAR=0.0
      ELSEIF(IDIST.EQ.'CAUCHY')THEN
        DO 210 I=1,N
          ARG=PI*W(I)
          W(I)=-COS(ARG)/SIN(ARG)
  210   CONTINUE
      ELSEIF(IDIST.EQ.'TUKEY-LAMBDA')THEN
!
!       FOR TUKEY-LAMBDA, EITHER USED A FIXED VALUE FOR SHAPE OR
!       USE PPCC METHOD TO ESTIMATE.
!
        IF(ALAMB.EQ.CPUMIN)THEN
          SHAPST=-4.0
          SHAPIN=0.05
          NLOOP=161
          PPCC=-1.0
          DO 221 ILOOP=1,NLOOP
            CALL UNIMED(N,W)
            IF(-0.001.LT.SHAPST.AND.SHAPST.LT.0.001)THEN
              DO 225 I=1,N
                Q=W(I)
                W(I)=LOG(Q/(1.0-Q))
  225         CONTINUE
            ELSE
              DO 226 I=1,N
                Q=W(I)
                W(I)=(Q**SHAPST-(1.0-Q)**SHAPST)/SHAPST
  226         CONTINUE
            ENDIF
            IWRISV=IWRITE
            IWRITE='OFF'
            CALL MEAN(W,N,IWRITE,WBAR,IBUGA3,IERROR)
            IWRITE=IWRISV
!
            DSUM1=0.0D0
            DSUM2=0.0D0
            DSUM3=0.0D0
            DO 227 I=1,N
              DTERM1=DBLE(Y(I) - YBAR)
              DTERM2=DBLE(W(I) - WBAR)
              DSUM1=DSUM1 + DTERM1*DTERM1
              DSUM2=DSUM2 + DTERM1*DTERM2
              DSUM3=DSUM3 + DTERM2*DTERM2
  227       CONTINUE
            PPCCT=DSUM2/DSQRT(DSUM3*DSUM1)
            IF(PPCCT.GT.PPCC)THEN
              SHAPE=SHAPST
              SUMXY=REAL(DSUM2)
              SUMXX=REAL(DSUM3)
              SCALE=0.0
              IF(SUMXX.NE.0.0)SCALE=SUMXY/SUMXX
              ALOC=YBAR-SCALE*WBAR
              PPCC=PPCCT
            ENDIF
            SHAPST=SHAPST+SHAPIN
  221     CONTINUE
          GO TO 8000
!
        ELSE
          IF(-0.001.LT.ALAMB.AND.ALAMB.LT.0.001)THEN
            DO 228 I=1,N
              Q=W(I)
              W(I)=LOG(Q/(1.0-Q))
  228       CONTINUE
          ELSE
            DO 229 I=1,N
              Q=W(I)
              W(I)=(Q**ALAMB-(1.0-Q)**ALAMB)/ALAMB
  229       CONTINUE
          ENDIF
        ENDIF
      ELSEIF(IDIST.EQ.'LOGISTIC')THEN
        DO 230 I=1,N
          CALL LOGPPF(W(I),WOUT)
          W(I)=WOUT
  230   CONTINUE
      ELSEIF(IDIST.EQ.'DOUBLE EXPONENTIAL')THEN
        DO 235 I=1,N
          CALL DEXPPF(W(I),WOUT)
          W(I)=WOUT
  235   CONTINUE
      ELSEIF(IDIST.EQ.'COSINE')THEN
        DO 240 I=1,N
