          DO 335 ILOOP1=1,NLOOP1
            DO 338 ILOOP2=1,NLOOP2
              CALL UNIMED(N,W)
              DO 333 I=1,N
                CALL GHPPF(W(I),SHAPS1,SHAPS2,PPF,DBLE(AVAL1),DPPF)
                W(I)=REAL(DPPF)
  333         CONTINUE
              CALL MEAN(W,N,IWRITE,WBAR,IBUGA3,IERROR)
