  399   FORMAT('      NO MATCH FOR DISTRIBUTION: ',A20)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      SUM1=0.0
      SUM2=0.0
      DO 410 I=1,N
        SUM1=SUM1+Y(I)
        SUM2=SUM2+W(I)
  410 CONTINUE
      YBAR=SUM1/AN
      IF(WBAR.EQ.CPUMIN)WBAR=SUM2/AN
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DO 420 I=1,N
        DTERM1=DBLE(Y(I) - YBAR)
        DTERM2=DBLE(W(I) - WBAR)
        DSUM1=DSUM1 + DTERM1*DTERM1
        DSUM2=DSUM2 + DTERM1*DTERM2
        DSUM3=DSUM3 + DTERM2*DTERM2
  420 CONTINUE
      PPCC=REAL(DSUM2/DSQRT(DSUM3*DSUM1))
      SUMXY=REAL(DSUM2)
      SUMXX=REAL(DSUM3)
      SCALE=0.0
      IF(SUMXX.NE.0.0)SCALE=SUMXY/SUMXX
      ALOC=YBAR-SCALE*WBAR
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
 8000 CONTINUE
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)
  811   FORMAT('THE NORMAL PROBABILITY PLOT CORRELATION COEFFICIENT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,812)N,PPCC
  812   FORMAT('OF THE ',I8,' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RPPC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF NORPPC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)SUM1,SUM2,SUM3,PPCC,SHAPE
 9014   FORMAT('SUM1,SUM2,SUM3,PPCC,SHAPE = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE NORPPC
      SUBROUTINE NODCDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/SQRT(2*PI))*EXP(-X*X/2).
!              THIS IS THE DOUBLE PRECISION VERSION.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--ALNORM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 932, FORMULA 26.2.17.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 40-111.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97.8
!     ORIGINAL VERSION--AUGUST    1997.
!     UPDATED         --SEPTEMBER 2009. SWITCH FROM USING APPLIED
!                                       STATISTICS ALGORITHM ALNORM
!                                       TO ACM 715 ANORM ALGORITHM
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION CDF
!CCCC DOUBLE PRECISION ALNORM
      DOUBLE PRECISION ANORM
      LOGICAL UPPER
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(X.LT.0.0D0)THEN
        UPPER=.FALSE.
!CCCC   CDF=ALNORM(X,UPPER)
        CDF=ANORM(X)
      ELSEIF(X.GT.0.0D0)THEN
!CCCC   UPPER=.TRUE.
!CCCC   CDF=1.0D0 - ALNORM(X,UPPER)
        CDF=ANORM(X)
      ELSE
        CDF=0.5D0
      ENDIF
!
      RETURN
      END SUBROUTINE NODCDF
      SUBROUTINE NODPDF(Z, PDF)
!CCCC SUBROUTINE NODPDF(Z, P, Q, PDF)
!
!      Normal distribution probabilities accurate to 1.e-15.
!      Z = no. of standard deviations from the mean.
!      P, Q = probabilities to the left & right of Z.   P + Q = 1.
!       PDF = the probability density.
!
!       Based upon algorithm 5666 for the error function, from:
!       Hart, J.F. et al, 'Computer Approximations', Wiley 1968
!
!       Programmer: Alan Miller
!
!      Latest revision - 30 March 1986
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      DATA P0, P1, P2, P3, P4, P5, P6/220.2068679123761D0,   &
              221.2135961699311D0, 112.0792914978709D0,   &
              33.91286607838300D0, 6.373962203531650D0,   &
              .7003830644436881D0, .3526249659989109D-01/
      DATA Q0, Q1, Q2, Q3, Q4, Q5, Q6, Q7/440.4137358247522D0,   &
              793.8265125199484D0, 637.3336333788311D0,   &
              296.5642487796737D0, 86.78073220294608D0,   &
              16.06417757920695D0, 1.755667163182642D0,   &
              .8838834764831844D-1/,   &
              CUTOFF/7.071D0/, ROOT2PI/2.506628274631001D0/
!
      ZABS = ABS(Z)
!
!      |Z| > 37.
!
      IF (ZABS .GT. 37.D0) THEN
        PDF = 0.D0
        IF (Z .GT. 0.D0) THEN
          P = 1.D0
          Q = 0.D0
        ELSE
          P = 0.D0
          Q = 1.D0
        END IF
        RETURN
      END IF
!
!      |Z| <= 37.
!
      EXPNTL = EXP(-0.5D0*ZABS**2)
      PDF = EXPNTL/ROOT2PI
!
!      |Z| < CUTOFF = 10/sqrt(2).
!
      IF (ZABS .LT. CUTOFF) THEN
        P = EXPNTL*((((((P6*ZABS + P5)*ZABS + P4)*ZABS + P3)*ZABS +   &
              P2)*ZABS + P1)*ZABS + P0)/(((((((Q7*ZABS + Q6)*ZABS +   &
              Q5)*ZABS + Q4)*ZABS + Q3)*ZABS + Q2)*ZABS + Q1)*ZABS +   &
              Q0)
!
!      |Z| >= CUTOFF.
!
      ELSE
        P = PDF/(ZABS + 1.D0/(ZABS + 2.D0/(ZABS + 3.D0/(ZABS + 4.D0/   &
              (ZABS + 0.65D0)))))
      END IF
!
      IF (Z .LT. 0.D0) THEN
        Q = 1.D0 - P
      ELSE
        Q = P
        P = 1.D0 - Q
      END IF
      RETURN
      END SUBROUTINE NODPDF
      SUBROUTINE NODPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES
!              THE PERCENT POINT
!              FUNCTION VALUE FOR THE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/SQRT(2*PI))*EXP(-X*X/2).
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     NOTE--THIS ROUTINE IS IDENTICAL IN LOGIC TO NORPPF
!           EXCEPT NORPPF HAS INTERNAL CALUCLATIONS
!           IN SINGLE PRECISION,
!           WHILE NODPPF HAS INTERNAL CALUCLATIONS
!           IN DOUBLE PRECISION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!
!      ALGORITHM AS241  APPL. STATIST. (1988) VOL. 37, NO. 3
!
!      Produces the normal deviate Z corresponding to a given lower
!      tail area of P; Z is accurate to about 1 part in 10**16.
!
!      The hash sums below are the sums of the mantissas of the
!      coefficients.   They are included for use in checking
!      transcription.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95.7
!     ORIGINAL VERSION--JULY      1995.
!     UPDATED         --AUGUST    1997. REPLACE CURRENT ALGORITHM WITH
!                                       AS 241 (HAS HIGHER ACCURACY)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION PPF
      DOUBLE PRECISION ZERO, ONE, HALF, SPLIT1, SPLIT2, CONST1,   &
              CONST2, A0, A1,  A2, A3, A4, A5, A6, A7, B1, B2, B3,   &
                B4, B5, B6, B7,   &
              C0, C1, C2, C3, C4, C5, C6, C7,  D1, D2, D3, D4, D5,   &
              D6, D7, E0, E1, E2, E3, E4, E5, E6, E7, F1, F2, F3,   &
              F4, F5, F6, F7, Q, R
      PARAMETER (ZERO = 0.D0, ONE = 1.D0, HALF = 0.5D0,   &
              SPLIT1 = 0.425D0, SPLIT2 = 5.D0,   &
              CONST1 = 0.180625D0, CONST2 = 1.6D0)
!
      INCLUDE 'DPCOP2.INC'
!
!      Coefficients for P close to 0.5
!
      PARAMETER (A0 = 3.3871328727963666080D0,   &
                 A1 = 1.3314166789178437745D+2,   &
                 A2 = 1.9715909503065514427D+3,   &
                 A3 = 1.3731693765509461125D+4,   &
                 A4 = 4.5921953931549871457D+4,   &
                 A5 = 6.7265770927008700853D+4,   &
                 A6 = 3.3430575583588128105D+4,   &
                 A7 = 2.5090809287301226727D+3,   &
                 B1 = 4.2313330701600911252D+1,   &
                 B2 = 6.8718700749205790830D+2,   &
                 B3 = 5.3941960214247511077D+3,   &
                 B4 = 2.1213794301586595867D+4,   &
                 B5 = 3.9307895800092710610D+4,   &
                 B6 = 2.8729085735721942674D+4,   &
                 B7 = 5.2264952788528545610D+3)
!      HASH SUM AB    55.8831928806149014439
!
!      Coefficients for P not close to 0, 0.5 or 1.
!
      PARAMETER (C0 = 1.42343711074968357734D0,   &
                 C1 = 4.63033784615654529590D0,   &
                 C2 = 5.76949722146069140550D0,   &
                 C3 = 3.64784832476320460504D0,   &
                 C4 = 1.27045825245236838258D0,   &
                 C5 = 2.41780725177450611770D-1,   &
                 C6 = 2.27238449892691845833D-2,   &
                 C7 = 7.74545014278341407640D-4,   &
                 D1 = 2.05319162663775882187D0,   &
                 D2 = 1.67638483018380384940D0,   &
                 D3 = 6.89767334985100004550D-1,   &
                 D4 = 1.48103976427480074590D-1,   &
                 D5 = 1.51986665636164571966D-2,   &
                 D6 = 5.47593808499534494600D-4,   &
                 D7 = 1.05075007164441684324D-9)
!      HASH SUM CD    49.33206503301610289036
!
!      Coefficients for P near 0 or 1.
!
      PARAMETER (E0 = 6.65790464350110377720D0,   &
                 E1 = 5.46378491116411436990D0,   &
                 E2 = 1.78482653991729133580D0,   &
                 E3 = 2.96560571828504891230D-1,   &
                 E4 = 2.65321895265761230930D-2,   &
                 E5 = 1.24266094738807843860D-3,   &
                 E6 = 2.71155556874348757815D-5,   &
                 E7 = 2.01033439929228813265D-7,   &
                 F1 = 5.99832206555887937690D-1,   &
                 F2 = 1.36929880922735805310D-1,   &
                 F3 = 1.48753612908506148525D-2,   &
                 F4 = 7.86869131145613259100D-4,   &
                 F5 = 1.84631831751005468180D-5,   &
                 F6 = 1.42151175831644588870D-7,   &
                 F7 = 2.04426310338993978564D-15)
!      HASH SUM EF    47.52583317549289671629
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      PPF=0.0D0
      IF(P.LE.0.0D0.OR.P.GE.1.0D0)GO TO 50
      GO TO 90
   50 WRITE(ICOUT,1)
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO NODPPF ',   &
      'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',D15.7,'*****')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
   90 CONTINUE
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE PERCENT POINT FUNCTION VALUE  **
!               ************************************************
!
      IF(P.EQ.0.5D0)THEN
        PPF=0.0D0
        GO TO 9000
      ENDIF
!
      Q = P - HALF
      IF (ABS(Q) .LE. SPLIT1) THEN
        R = CONST1 - Q * Q
        PPF = Q * (((((((A7 * R + A6) * R + A5) * R + A4) * R + A3)   &
                * R + A2) * R + A1) * R + A0) /   &
                    (((((((B7 * R + B6) * R + B5) * R + B4) * R + B3)   &
                * R + B2) * R + B1) * R + ONE)
        RETURN
      ELSE
        IF (Q .LT. ZERO) THEN
          R = P
        ELSE
          R = ONE - P
        END IF
        IF (R .LE. ZERO) THEN
          WRITE(ICOUT,47)
          CALL DPWRST('XXX','BUG ')
          PPF = ZERO
          RETURN
        END IF
   47 FORMAT('***** INTERNAL ERROR FROM NODPPF ******')
        R = SQRT(-LOG(R))
        IF (R .LE. SPLIT2) THEN
          R = R - CONST2
          PPF = (((((((C7 * R + C6) * R + C5) * R + C4) * R + C3)   &
                * R + C2) * R + C1) * R + C0) /   &
                   (((((((D7 * R + D6) * R + D5) * R + D4) * R + D3)   &
                * R + D2) * R + D1) * R + ONE)
        ELSE
          R = R - SPLIT2
          PPF = (((((((E7 * R + E6) * R + E5) * R + E4) * R + E3)   &
                * R + E2) * R + E1) * R + E0) /   &
                   (((((((F7 * R + F6) * R + F5) * R + F4) * R + F3)   &
                * R + F2) * R + F1) * R + ONE)
        END IF
        IF (Q .LT. ZERO) PPF = - PPF
        RETURN
      END IF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NODPPF
      SUBROUTINE NORPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/SQRT(2*PI))*EXP(-X*X/2).
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT, LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--ODEH AND EVANS, THE PERCENTAGE POINTS
!                 OF THE NORMAL DISTRIBUTION, ALGORTIHM 70,
!                 APPLIED STATISTICS, 1974, PAGES 96-97.
!               --EVANS, ALGORITHMS FOR MINIMAL DEGREE
!                 POLYNOMIAL AND RATIONAL APPROXIMATION,
!                 M. SC. THESIS, 1972, UNIVERSITY
!                 OF VICTORIA, B. C., CANADA.
!               --HASTINGS, APPROXIMATIONS FOR DIGITAL
!                 COMPUTERS, 1955, PAGES 113, 191, 192.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 933, FORMULA 26.2.23.
!               --FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 40-111.
!               --THE KELLEY STATISTICAL TABLES, 1948.
!               --OWEN, HANDBOOK OF STATISTICAL TABLES,
!                 1962, PAGES 3-16.
!               --PEARSON AND HARTLEY, BIOMETRIKA TABLES
!                 FOR STATISTICIANS, VOLUME 1, 1954,
!                 PAGES 104-113.
!     COMMENTS--THE CODING AS PRESENTED BELOW
!               IS ESSENTIALLY IDENTICAL TO THAT
!               PRESENTED BY ODEH AND EVANS
!               AS ALGORTIHM 70 OF APPLIED STATISTICS.
!               THE PRESENT AUTHOR HAS MODIFIED THE
!               ORIGINAL ODEH AND EVANS CODE WITH ONLY
!               MINOR STYLISTIC CHANGES.
!             --AS POINTED OUT BY ODEH AND EVANS
!               IN APPLIED STATISTICS,
!               THEIR ALGORITHM REPRESENTES A
!               SUBSTANTIAL IMPROVEMENT OVER THE
!               PREVIOUSLY EMPLOYED
!               HASTINGS APPROXIMATION FOR THE
!               NORMAL PERCENT POINT FUNCTION--
!               THE ACCURACY OF APPROXIMATION
!               BEING IMPROVED FROM 4.5*(10**-4)
!               TO 1.5*(10**-8).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --OCTOBER   1976.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA P0,P1,P2,P3,P4   &
      /-.322232431088,-1.0,   &
       -.342242088547,-.204231210245E-1,   &
       -.453642210148E-4/
      DATA Q0,Q1,Q2,Q3,Q4   &
      /.993484626060E-1,.588581570495,   &
       .531103462366,.103537752850,   &
       .38560700634E-2/
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(P.LE.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 WRITE(ICOUT,1)
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'NORPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,'*****')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
   90 CONTINUE
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE PERCENT POINT FUNCTION VALUE  **
!               ************************************************
!
      IF(P.EQ.0.5)GO TO 120
      GO TO 129
  120 CONTINUE
      PPF=0.0
      GO TO 9000
  129 CONTINUE
!
      PHOLD=P
      R=P
      IF(PHOLD.GT.0.5)R=1.0-R
      T=SQRT(-2.0*LOG(R))
      ANUM=((((T*P4+P3)*T+P2)*T+P1)*T+P0)
      ADEN=((((T*Q4+Q3)*T+Q2)*T+Q1)*T+Q0)
      PPF=T+(ANUM/ADEN)
      IF(PHOLD.LT.0.5)PPF=-PPF
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NORPPF
      SUBROUTINE NORRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE THE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/SQRT(2*PI))*EXP(-X*X/2).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE NORMAL DISTRIBUTION
!             WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     METHOD--BOX-MULLER ALGORITHM.
!     REFERENCES--BOX AND MULLER, 'A NOTE ON THE GENERATION
!                 OF RANDOM NORMAL DEVIATES', JOURNAL OF THE
!                 ASSOCIATION FOR COMPUTING MACHINERY, 1958,
!                 PAGES 610-611.
!               --TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 33-34.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 39.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 40-111.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JULY      1976.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'NORRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!     THEN GENERATE 2 ADDITIONAL UNIFORM (0,1) RANDOM NUMBERS
!     (TO BE USED BELOW IN FORMING THE N-TH NORMAL
!     RANDOM NUMBER WHEN THE DESIRED SAMPLE SIZE N
!     HAPPENS TO BE ODD).
!
      CALL UNIRAN(N,ISEED,X)
      CALL UNIRAN(2,ISEED,Y)
!
!     GENERATE N NORMAL RANDOM NUMBERS
!     USING THE BOX-MULLER METHOD.
!
      DO 200 I=1,N,2
      IP1=I+1
      U1=X(I)
      IF(I.EQ.N)GO TO 210
      U2=X(IP1)
      GO TO 220
  210 U2=Y(2)
  220 ARG1=-2.0*LOG(U1)
      ARG2=2.0*PI*U2
      SQRT1=SQRT(ARG1)
      Z1=SQRT1*COS(ARG2)
      Z2=SQRT1*SIN(ARG2)
      X(I)=Z1
      IF(I.EQ.N)GO TO 200
      X(IP1)=Z2
  200 CONTINUE
!
      RETURN
      END SUBROUTINE NORRAN
      SUBROUTINE NORSF(P,SF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SPARSITY
!              FUNCTION VALUE FOR THE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/SQRT(2*PI))*EXP(-X*X/2).
!              NOTE THAT THE SPARSITY FUNCTION OF A DISTRIBUTION
!              IS THE DERIVATIVE OF THE PERCENT POINT FUNCTION,
!              AND ALSO IS THE RECIPROCAL OF THE PROBABILITY
!              DENSITY FUNCTION (BUT IN UNITS OF P RATHER THAN X).
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE SPARSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--SF     = THE SINGLE PRECISION
!                                SPARSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION SPARSITY
!             FUNCTION VALUE SF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 40-111.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION SF
      DOUBLE PRECISION PPF
      DOUBLE PRECISION PDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DATA C/.3989422804/
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST  ARGUMENT TO NORSF IS OUTSIDE THE')
    2 FORMAT('      THE ALLOWABLE (0,1) INTERVAL *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.7,' *****')
!
!-----START POINT-----------------------------------------------------
!
      CALL NODPPF(P,PPF)
      PDF=DBLE(C)*EXP(-(PPF*PPF)/2.0D0)
      IF(PDF.NE.0.0D0)THEN
        SF=1.0D0/PDF
      ELSE
        SF=DBLE(CPUMAX)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE NORSF
      SUBROUTINE NPV(X,Y,N,IWRITE,XIDTEM,STAT,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE NEGATIVE PREDICTIVE VALUE
!              BETWEEN TWO VARIABLES.
!
!              THIS IS NPVICALLY FOR THE 2X2 CASE.  THAT IS,
!              EACH VARIABLE HAS TWO MUTUALLY EXCLUSIVE
!              CHOICES CODED AS 1 (FOR SUCCESS) OR 0 (FOR
!              FAILURE).
!
!              A TYPICAL EXAMPLE WOULD BE WHERE VARIABLE ONE
!              DENOTES THE GROUND TRUTH AND A VALUE OF 1
!              INDICATES "PRESENT" AND A VALUE OF 0 INDICATES
!              "NOT PRESENT".  VARIABLE TWO REPRESENTS SOME TYPE
!              OF DETECTION DEVICE WHERE A VALUE OF 1 INDICATES
!              THE DEVICE DETECTED THE NPVIED OBJECT WHILE A
!              VALUE OF 0 INDICATES THAT THE OBJECT WAS NOT
!              DETECTED.  NEGATIVE PREDICTIVE VALUE IS THEN DEFINED AS
!              (TRUE NEGATIVE)/(TRUE NEGATIVE + FALSE NEGATIVE).
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED NEGATIVE PREDICTIVE VALUE
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE NEGATIVE PREDICTIVE VALUE BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NPV '
      ISUBN2='    '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF NPV--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE NEGATIVE PREDICTIVE VALUE')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        STAT=AN22/(AN12+AN22)
        GO TO 3000
      ENDIF
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2202 I=1,N
          X(I)=1.0
 2202   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2203 I=1,N
            IF(X(I).NE.1.0)X(I)=0.0
 2203     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2208 I=1,N
            IF(X(I).EQ.ATEMP1)X(I)=0.0
            IF(X(I).EQ.ATEMP2)X(I)=1.0
 2208     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2211)
 2211   FORMAT('      RESPONSE VARIABLE ONE SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2213)
 2213   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2215)NDIST
 2215   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
 1349 CONTINUE
!
      CALL DISTIN(Y,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,N
          Y(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,N
            IF(Y(I).NE.1.0)Y(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,N
            IF(Y(I).EQ.ATEMP1)Y(I)=0.0
            IF(Y(I).EQ.ATEMP2)Y(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2311)
 2311   FORMAT('      RESPONSE VARIABLE TWO SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2313)
 2313   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2315)NDIST
 2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      N11=0
      N12=0
      N21=0
      N22=0
      DO 2410 I=1,N
        IF(X(I).EQ.1.0 .AND. Y(I).EQ.1.0)THEN
          N11=N11+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.0.0)THEN
          N22=N22+1
        ELSEIF(X(I).EQ.1.0 .AND. Y(I).EQ.0.0)THEN
          N12=N12+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.1.0)THEN
          N21=N21+1
        ENDIF
 2410 CONTINUE
!
      STAT=REAL(N22)/REAL(N12+N22)
!
 3000 CONTINUE
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE NEGATIVE PREDICTIVE VALUE PROPORTION = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF NPV--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE NPV
      SUBROUTINE NRMLAG(X,AN,ALN)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE NORMALIZED LAGUERRE
!              POLYNOMIAL OF ORDER N.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION INPUT ARGUMENT
!                       AN     = THE SINGLE PRECISION VALUE FOR THE
!                                ORDER OF THE FUNCTION (SHOULD BE
!                                NON-NEGATIVE ORDER)
!     OUTPUT ARGUMENTS--ALN    = THE SINGLE PRECISION VALUE OF THE
!                                NORMALIZED LAGUERRE POLYNOMIAL.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SOME DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"HANDBOOK OF MATHEMATICAL FUNCTIONS, AMS 55",
!                 ABRAMOWITZ AND STEGUM.
!                 USE FOLLOWING RECURRENCE FORMULA:
!                    L(N+1) = (1+2*N-X)*L(N)-N**2*L(N-1)
!                 FIRST FEW TERMS ARE FROM TABLE 22.10 OF ABRAMOWITZ
!                 AND STEGUM.
!                 NORMALIZED LAGUERRE IS LAGUERRE SCALED BY N!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JULY       1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN, DN2
      DOUBLE PRECISION DLN, DLN1, DLN2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 1ST INPUT ARGUMENT ',   &
      'TO THE NRMLAG SUBROUTINE IS NEGATIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
      N=INT(AN+0.5)
      IF(N.LT.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    6 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 2ND INPUT ARGUMENT ',   &
      'TO THE NRMLAGRRE SUBROUTINE IS NEGATIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
      DX=DBLE(X)
      DN=DBLE(N)
!
      IF(N.LE.0)THEN
        ALN=1.0
      ELSEIF(N.EQ.1)THEN
        ALN=-X+1.0
      ELSEIF(N.EQ.2)THEN
        ALN=X**2 - 4.0*X + 2.0
      ELSEIF(N.EQ.3)THEN
        DLN=-DX**3 + 9.0D0*DX**2 -18.0D0*DX + 6.0D0
        ALN=REAL(DLN)
      ELSE
        DLN1=-DX**3 + 9.0D0*DX**2 -18.0D0*DX + 6.0D0
        DLN2=DX**2 - 4.0D0*DX + 2.0D0
        DO 1000 I=4,N
          DN2=DBLE(I)-1.0D0
          DLN=(1.0D0+2.0D0*DN2-DX)*DLN1 - DN2**2*DLN2
          DLN2=DLN1
          DLN1=DLN
 1000   CONTINUE
        ALN=REAL(DLN)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE NRMLAG
      subroutine nscor1 (s, n, n2, work, ifault)
!
!        Algorithm AS 177   Appl. Statist. (1982) Vol. 31, No. 2
!
!        Exact calculation of Normal Scores
!
      double precision s(n2), work(4,721)
!     double precision zero, one, c, scor, ai1, ani, an, h
!     data one/1.0d0/, zero/0.0d0/, h/0.025d0/, nstep/721/
      double precision zero, c, scor, ai1, ani, an, h
      data zero/0.0d0/, h/0.025d0/, nstep/721/
!
      ifault=3
      if (n2 .ne. n/2) return
      ifault=1
      if (n .le. 1) return
      ifault=0
      if (n .gt. 2000) ifault=2
!
      an=n
      c=log(an)
!
!        Accumulate ordinates for calculation of integral for rankits
!
      do 20 i=1, n2
        i1=i-1
        ni=n-i
        ai1=i1
        ani=ni
        scor=zero
        do 10 j=1,nstep
          scor=scor+exp(work(2,j) + ai1 * work(3,j) + ani * work(4,j)   &
               + c) * work(1,j)
   10   continue
        s(i)=scor * h
        c=c+log(ani/dble(i))
   20 continue
      return
      end
      subroutine nscor2(s,n,n2,ier)
!
!     algorithm as 177.3, applied statistics, v.31, 161-165, 1982.
!
!     calculates approximate expected values of normal order statistics.
!     claimed accuracy is 0.0001, though usually accurate to 5-6 dec.
!
!***  N.B. This routine is NOT in double precision ***
!
!     arguments:
!     s(n2)   = output, the first n2 expected values.
!     n       = input, the sample size.
!     n2      = input, the number of order statistics required; must
!                      be <= n/2.
!     ier     = output, error indicator
!                   = 0 if no error detected
!                   = 1 if n <= 1.
!                   = 2 if n > 2000, in which case the order statistics
!                          are still calculated, but may be inaccurate.
!                   = 3 if n2 > n/2 (n.b. this differs from the
!                          published algorithm which returns an error
!                          if n2 is not equal to n/2.)
!
!     calls ppnd = applied statistics algorithm 111.
!     An alternative is ppnd7 in algorithm AS 241.
!
      real s(n2), eps(4), dl1(4), dl2(4), gam(4), lam(4),   &
         bb, d, b1, an, ai, e1, e2, l1, correc, ppnd
      data eps/0.419885e0, 0.450536e0, 0.456936e0, 0.468488e0/,   &
       dl1/0.112063e0, 0.121770e0, 0.239299e0, 0.215159e0/,   &
       dl2/0.080122e0, 0.111348e0, -0.211867e0, -0.115049e0/,   &
       gam/0.474798e0, 0.469051e0, 0.208597e0, 0.259784e0/,   &
       lam/0.282765e0, 0.304856e0, 0.407708e0, 0.414093e0/,   &
       bb/-0.283833/, d/-0.106136/, b1/0.5641896/
!
!     input parameter checks.
!
      ier = 3
      if(n2.gt.n/2) return
      ier = 1
      if(n.le.1) return
      ier = 0
      if(n.gt.2000) ier = 2
      s(1) = b1
      if(n.eq.2) return
!
!     calculate normal tail areas for first 3 order statistics.
!
      an = n
      k = 3
      if(n2.lt.k) k = n2
      do 5 i = 1,k
        ai = i
        e1 = (ai - eps(i))/(an + gam(i))
        e2 = e1**lam(i)
        s(i) = e1 + e2*(dl1(i) + e2*dl2(i))/an - correc(i,n)
    5 continue
      if(n2.eq.k) go to 20
!
!     calculate normal areas for other cases.
!
      do 10 i = 4,n2
        ai = i
        l1 = lam(4) + bb/(ai + d)
        e1 = (ai - eps(4))/(an + gam(4))
        e2 = e1**l1
        s(i) = e1 + e2*(dl1(4) + e2*dl2(4))/an - correc(i,n)
   10 continue
!
!     convert tail areas to normal deviates.
!
   20 continue
      do 30 i = 1,n2
        s(i) = -ppnd(s(i),ier)
   30 continue
      return
      end
      subroutine nsinit(work)
!
!        Algorithm AS 177.1   Appl. Statist. (1982) Vol. 31, No. 2
!
      double precision work(4,721)
      double precision xstart, h, pi2, half, xx, alnorm
      data xstart/-9.0d0/, h/0.025d0/, pi2/-0.918938533d0/,   &
           half/0.5d0/,  nstep/721/
      xx=xstart
!
!        Set up arrays for calculation of integral
!
      do 10 i=1,nstep
        work(1,i)=xx
        work(2,i)=pi2 - xx * xx * half
        work(3,i)=log(alnorm(xx, .true.))
        work(4,i)=log(alnorm(xx, .false.))
        xx=xstart + dble(i) * h
   10 continue
      return
      end
      SUBROUTINE OCCPDF(X,B,C,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE CLASICAL OCCUPANCY
!              DISTRIBUTION ON THE INTERVAL (0,C).
!              THIS DISTRIBUTION HAS MEAN = (C-1)**B*C**(1-B)
!              AND STANDARD DEVIATION = (C-1)*(C-2)**B*C**(1-B) +
!                                       (C-1)**B*C**(1-B) -
!                                       (C-1)**(2*B)*C**(2-2*B)
!              THIS DISTRIBUTION HAS THE PROBABILITY
!              MASS FUNCTION:
!
!                P(X;C,B) = SUM[i=0 to C-X][(-1)**i*(X+i i)*
!                           (C  X+i)*((C-X-i)/C)**B
!                         = SUM[i=X to C][(-1)**(i-X)*C!*((C-i)/C)**B/
!                           (X!*(i-X)!(C-i)!
!                         = C!*S(B,C-X)/(X!*C**B)
!                         X = 0, 1, ..., C
!               WITH S DENOTING STERLING'S NUMBER OF THE SECOND
!               KIND.
!
!               GIVEN C CELLS AND B BALLS, THERE ARE C**B WAYS THE
!               BALLS CAN BE PLACED IN THE C CELLS (ASSUMMING
!               THAT ALL PLACEMENTS ARE EQUI-PROBABLE).  THE
!               CLASSICAL OCCUPANCY DISTRIBUTION IS THE DISTRIBUTION
!               OF THE NUMBER OF EMPTY CELLS.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                       C      = THE INTEGER VALUE THAT SPECIFIES
!                                THE FIRST SHAPE PARAMETER (THE
!                                NUMBER OF CELLS)
!                       B      = THE INTEGER VALUE THAT SPECIFIES
!                                THE SECOND SHAPE PARAMETER (THE
!                                NUMBER OF BALLS)
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND C, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS" SECOND EDITION,
!                 PAGES 414-416.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER B
      INTEGER C
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DB
      DOUBLE PRECISION DC
      DOUBLE PRECISION DPDF
!CCCC DOUBLE PRECISION DTERM1
!CCCC DOUBLE PRECISION DTERM2
!CCCC DOUBLE PRECISION DTERM3
!CCCC DOUBLE PRECISION DTERM4
!CCCC DOUBLE PRECISION DTERM5
!CCCC DOUBLE PRECISION DJ
!CCCC DOUBLE PRECISION DLNGAM
!CCCC DOUBLE PRECISION DSIGN
!CCCC DOUBLE PRECISION DSUM1
!CCCC DOUBLE PRECISION DSUM2
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
!
      IF(C.LT.1)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   12 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
             'OCCPDF IS LESS THAN 1.')
!
      IF(B.LT.1)THEN
        WRITE(ICOUT,22)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)B
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   22 FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
             'OCCPDF IS LESS THAN 1.')
!
      IX=INT(X+0.5)
      IF(IX.LT.0 .OR. IX.GT.C)THEN
        WRITE(ICOUT,2)C
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)IX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
             'OCCPDF IS OUTSIDE THE (0,',I8,') INTERVAL')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(IX)
      DB=DBLE(B)
      DC=DBLE(C)
      DPDF=0.0D0
!
!     NOTE: JOHNSON, KOTZ, AND KEMP PROVIDE 3 DIFFERENT
!           SUMMATION FORMULAS.  THESE SEEM ACCURATE UP TO
!           ABOUT N = 50.
!
!CCCC DO100J=IX,C
!CCCC   DJ=DBLE(J)
!CCCC   DSIGN=(-1.0D0)**(DJ-DX)
!CCCC   IF(J.EQ.C)THEN
!CCCC     CONTINUE
!CCCC   ELSE
!CCCC     DTERM1=DLNGAM(DC+1.0D0) - DLNGAM(DX+1.0D0) -
!CCCC1           DLNGAM(DJ-DX+1.0D0) - DLNGAM(DC-DJ+1.0D0) +
!CCCC1           DB*DLOG((DC-DJ)/DC)
!CCCC     DTERM1=DEXP(DTERM1)
!CCCC     DPDF=DPDF + DSIGN*DTERM1
!CCCC   ENDIF
!C100 CONTINUE
!CCCC PDF=REAL(DPDF)
!
!CCCC DTERM1=DLNGAM(DC+1.0D0) - DLNGAM(DX+1.0D0) - DLNGAM(DC-DX+1.0D0)
!
!CCCC DSUM1=0.0D0
!CCCC DO200J=0,C-IX,2
!CCCC   DJ=DBLE(J)
!CCCC   DTERM2=DLNGAM(DC-DX+1.0D0) - DLNGAM(DJ+1.0D0) -
!CCCC1         DLNGAM(DC-DX-DJ+1.0D0)
!CCCC   DTERM3=DB*DLOG(1.0D0 - (DX+DJ)/DC)
!CCCC   DTERM4=DEXP(DTERM2 + DTERM3)
!CCCC   DSUM1=DSUM1 + DTERM4
!C200 CONTINUE
!
!CCCC DSUM2=0.0D0
!CCCC DO400J=1,C-IX,2
!CCCC   DJ=DBLE(J)
!CCCC   DTERM2=DLNGAM(DC-DX+1.0D0) - DLNGAM(DJ+1.0D0) -
!CCCC1         DLNGAM(DC-DX-DJ+1.0D0)
!CCCC   DTERM3=DB*DLOG(1.0D0 - (DX+DJ)/DC)
!CCCC   DTERM4=DEXP(DTERM2 + DTERM3)
!CCCC   DSUM2=DSUM2 + DTERM4
!C400 CONTINUE
!
!CCCC DSUM1=DSUM1 - DSUM2
!CCCC DPDF=DEXP(DTERM1 + DLOG(DSUM1))
!CCCC PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE OCCPDF
      SUBROUTINE ODDDIS(Y,N,PSTAMV,IWRITE,XIDTEM,N11,N21,NOUT,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE IS A UITILITY ROUTINE USED BY
!              THE ODDS RATIO AND RELATED ROUTINES.  THE ODDS
!              RATIO ASSUMES THERE ARE TWO CHOICES THAT ARE
!              TYPICALLY CODED AS 1 (FOR SUCCESS) OR
!              0 (FOR FAILURE).   SINCE THE SAMPLES CAN BE
!              OF DIFFERENT SIZES, ALLOW FOR A MISSING VALUE
!              CODE (PSTAMV).
!
!              THIS ROUTINE DOES THE FOLLOWING:
!
!              1) STRIP OUT ANY MISSING VALUES.
!
!              2) DETERMINE HOW MANY DISTINCT VALUES THERE ARE
!                 IN Y.  SHOULD BE EITHER ONE OR TWO AFTER
!                 MISSING VALUES EXTRACTED.
!
!              3) COUNT UP NUMBER OF SUCCESSES (1's) AND
!                 FAILURES (0's).
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --PSTAMV = THE SINGLE PRECISION MISSING VALUE
!                                CODE.
!                     --IWRITE = CHARACTER VARIABLE SPECIFYING
!                                PRINT OPTION.
!                     --XIDTEM = TEMPORARY SINGLE PRECISION VECTOR.
!     OUTPUT ARGUMENTS--N11    = THE INTEGER VALUE CONTAINING THE
!                                NUMBER OF SUCCESSES.
!                     --N21    = THE INTEGER VALUE CONTAINING THE
!                                NUMBER OF FAILURES.
!                     --NOUT   = THE INTEGER VALUE CONTAINING THE
!                                NUMBER OF OBSERVATIONS AFTER
!                                MISSING VALUES STRIPPED OUT.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE ODDS RATIO BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DISTIN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/4
!     ORIGINAL VERSION--APRIL     2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='ODDD'
      ISUBN2='IS  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF ODDDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I)
   56     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE ODDDIS ROUTINE--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  STRIP OUT MISSING VALUES              **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICNT=0
      DO 1260 I=1,N
        IF(ABS(Y(I) - PSTAMV).GE.0.001)THEN
          ICNT=ICNT+1
          Y(ICNT)=Y(I)
        ENDIF
 1260 CONTINUE
      NOUT=ICNT
!
      IF(NOUT.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1281)
 1281   FORMAT('      AFTER REMOVING THE MISSING VALUES,')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1283)
 1283   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)NOUT
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DISTIN(Y,NOUT,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,NOUT
          Y(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,NOUT
            IF(Y(I).NE.1.0)Y(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,NOUT
            IF(Y(I).EQ.ATEMP1)Y(I)=0.0
            IF(Y(I).EQ.ATEMP2)Y(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2311)
 2311   FORMAT('      RESPONSE VARIABLE SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2313)
 2313   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2315)NDIST
 2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      N11=0
      N21=0
!
      DO 2410 I=1,NOUT
        IF(Y(I).EQ.1.0)THEN
          N11=N11+1
        ELSE
          N21=N21+1
        ENDIF
 2410 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF ODDDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,NOUT,N11,N21
 9013   FORMAT('N,NOUT,N11,N21 = ',5I10)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE ODDDIS
      SUBROUTINE ODDRAT(X,N1,Y,N2,PSTAMV,IWRITE,XIDTEM,STAT,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE ODDS RATIO
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!                     --PSTAMV = THE MISSING VALUE CODE
!     OUTPUT ARGUMENTS--ODDRAT = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED ODDS RATIO
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE ODDS RATIO BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--ODDDIS.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/4
!     ORIGINAL VERSION--APRIL     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='ODDR'
      ISUBN2='AT  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF ODDRAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N1,N2
   53   FORMAT('N1,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MAX(N1,N2)
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE BIAS CORRECTED ODDS RATIO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N1
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1213)
 1213   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N1.EQ.2 .AND. N2.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        GO TO 3000
      ENDIF
!
 1349 CONTINUE
!
      CALL ODDDIS(X,N1,PSTAMV,IWRITE,XIDTEM,N11,N21,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      CALL ODDDIS(Y,N2,PSTAMV,IWRITE,XIDTEM,N12,N22,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      AN11=REAL(N11)
      AN21=REAL(N21)
      AN12=REAL(N12)
      AN22=REAL(N22)
      GO TO 3000
!
!     COMPUTE THE BIAS CORRECTED LOG OF THE ODDS RATIO.
!
 3000 CONTINUE
      AN1=AN11+AN21
      AN2=AN12+AN22
      AN=AN1 + AN2
!
      P11=AN11/AN1
      P21=AN21/AN1
      P12=AN12/AN2
      P22=AN22/AN2
!
      STAT=(AN11+0.5)*(AN22+0.5)/((AN12+0.5)*(AN21+0.5))
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE BIAS CORRECTED ODDS RATIO = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF ODDRAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)P11,P12,P21,P22
 9014   FORMAT('P11,P12,P21,P22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE ODDRAT
      SUBROUTINE ODDRSE(X,N1,Y,N2,PSTAMV,IWRITE,XIDTEM,STAT,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE STANDARD ERROR OF THE
!              BIAS CORRECTED ODDS RATIO.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!                     --PSTAMV = THE MISSING VALUE CODE
!     OUTPUT ARGUMENTS--ODDRSE = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STANDARD ERROR OF THE
!                                ODDS RATIO (BIAS CORRECTED)
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE STANDARD ERROR OF THE ODDS RATIO BETWEEN
!             THE 2 SETS OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--ODDDIS.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/4
!     ORIGINAL VERSION--APRIL     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='ODDR'
      ISUBN2='SE  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF ODDRSE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N1,N2
   53   FORMAT('N1,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MAX(N1,N2)
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE BIAS CORRECTED ',   &
               'LOG ODDS RATIO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N1
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1213)
 1213   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N1.EQ.2 .AND. N2.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        GO TO 3000
      ENDIF
!
 1349 CONTINUE
!
      CALL ODDDIS(X,N1,PSTAMV,IWRITE,XIDTEM,N11,N21,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      CALL ODDDIS(Y,N2,PSTAMV,IWRITE,XIDTEM,N12,N22,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      AN11=REAL(N11)
      AN21=REAL(N21)
      AN12=REAL(N12)
      AN22=REAL(N22)
      GO TO 3000
!
!     COMPUTE THE BIAS CORRECTED LOG OF THE ODDS RATIO.
!
 3000 CONTINUE
      AN1=AN11+AN21
      AN2=AN12+AN22
      AN=AN1 + AN2
!
      P11=AN11/AN1
      P21=AN21/AN1
      P12=AN12/AN2
      P22=AN22/AN2
!
      ODDRATZ=(AN11+0.5)*(AN22+0.5)/((AN12+0.5)*(AN21+0.5))
      STAT=ODDRATZ*SQRT((1.0/(AN11+0.5)) + (1.0/(AN21+0.5)) +   &
               (1.0/(AN12+0.5)) + (1.0/(AN22+0.5)))
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE STANDARD ERROR OF THE BIAS CORRECTED ODDS ',   &
             'RATIO = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF ODDRSE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)P11,P12,P21,P22
 9014   FORMAT('P11,P12,P21,P22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE ODDRSE
      SUBROUTINE OGICDF(DX,DN,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE OGIVE DISTRIBUTION WITH SHAPE
!              PARAMETER N.  THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;N) = ((4*N-2)/(3*N-1))*X**N - ((N-1)/(3*N-1))*X**(2*N)
!                       0 <= X <= 1, N >= 0.5
!
!              WITH N DENOTING THE SHAPE PARAMETER.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DN     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE OGIVE DISTRIBUTION WITH SHAPE
!             PARAMETER N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND N: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!     UPDATED         --DECEMBER  2007. UPDATE FROM USING NUMERICAL
!                                       INTEGRATION TO USING EXPLICIT
!                                       FORMULA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
      IF(DX.LE.0.0D0)THEN
        GO TO 9000
      ELSEIF(DX.GE.1.0D0)THEN
        DCDF=1.0D0
        GO TO 9000
      ELSEIF(DN.LT.0.5D0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE SECOND ARGUMENT TO OGICDF IS ',   &
               'LESS THAN 0.5')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DN
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE CDF     FUNCTION  **
!               ************************************
!
      DTERM1=((4.0D0*DN - 2.0D0)/(3.0D0*DN - 1.0D0))*DX**DN
      DTERM2=((DN - 1.0D0)/(3.0D0*DN - 1.0D0))*DX**(2.0D0*DN)
      DCDF=DTERM1 - DTERM2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE OGICDF
      DOUBLE PRECISION FUNCTION OGIFU2(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE OGIVE DISTRIBUTION WITH
!              SHAPE PARAMETERS N.
!
!              DEFINE AS FUNCTION TO BE USED FOR INTEGRATION
!              CODE CALLED BY OGIPPF.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--OGIFU2  = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE OGIVE DISTRIBUTION WITH
!             SHAPE PARAMETER N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--OGIPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND N: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
!
      DOUBLE PRECISION DP
      COMMON/OG2COM/DP
!
      DOUBLE PRECISION DN
      COMMON/OGICOM/DN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL OGICDF(DX,DN,DCDF)
      OGIFU2=DP - DCDF
!
      RETURN
      END FUNCTION OGIFU2
      SUBROUTINE OGIPDF(X,N,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE OGIVE DISTRIBUTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!                  f(X;N) = N*X**(N-1)*{(4*N-2)/(3*N-1) -
!                           ((2*N-2)/(3*N-1))*X**N}
!                           0 <= X <= 1, N >= 0.5
!
!              WITH N DENOTING THE SHAPE PARAMETER.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --N      = THE SINGLE PRECISION SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND 1, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND N: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--SEPTEMBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION N
      DOUBLE PRECISION X
      DOUBLE PRECISION PDF
      DOUBLE PRECISION TERM1
      DOUBLE PRECISION TERM2
      DOUBLE PRECISION TERM3
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0D0
      IF((N.GT.0.5D0 .AND. N.LT.1.0D0) .AND.   &
          X.LE.0.0D0)THEN
        WRITE(ICOUT,2)
    2   FORMAT('***** ERROR--THE FIRST ARGUMENT TO OGIPDF IS ',   &
               'OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.LT.0.5D0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE SECOND ARGUMENT TO OGIPDF IS ',   &
               'LESS THAN 0.5')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)N
        GO TO 9000
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      IF(X.LE.0.0D0 .AND. N.EQ.0.5D0)THEN
        PDF=1.0D0
      ELSEIF(X.LE.0.0D0 .AND. N.EQ.1.0D0)THEN
        PDF=1.0D0
      ELSEIF(X.LE.0.0D0 .AND.   &
            (N.GT.0.5D0 .AND. N.LT.1.0D0))THEN
        TERM1=N
        TERM2=(4.0D0*N-2.0D0)/(3.0D0-1.0D0)
        TERM3=(2.0D0*N-2.0D0)/(3.0D0-1.0D0)
        PDF=TERM1*(TERM2-TERM3)
      ELSE
        TERM1=N*(X**(N-1.0D0))
        TERM2=(4.0D0*N-2.0D0)/(3.0D0*N-1.0D0)
        TERM3=((2.0D0*N-2.0D0)/(3.0D0*N-1.0D0))*X**N
        PDF=TERM1*(TERM2 - TERM3)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE OGIPDF
      SUBROUTINE OGIPPF(P,N,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE OGIVE DISTRIBUTION WITH
!              SHAPE PARAMETER N.  THIS DISTRIBUTION HAS
!              THE PROBABILITY DENSITY FUNCTION
!
!                  f(X;N) = N*X**(N-1)*{(4*N-2)/(3*N-1) -
!                           ((2*N-2)/(3*N-1))*X**N}
!                           0 <= X <= 1, N >= 0.5
!
!              WITH N DENOTING THE SHAPE PARAMETER.
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY NUMERICALLY
!              INVERTING THE OGIVE CUMULATIVE
!              DISTRIBUTION FUNCTION (WHICH IN TURN IS COMPUTED BY
!              NUMERICAL INTEGRATION OF THE PROBABILITYT DENSITY.
!
!     INPUT  ARGUMENTS--P       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PERCENT POINT
!                                 FUNCTION IS TO BE EVALUATED.
!                                 0 < P < 1
!                     --N       = THE FIRST SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF     = THE DOUBLE PRECISION PERCENT POINT
!                                 FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE OGIVE
!             DISTRIBUTION WITH SHAPE PARAMETER = N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND N: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION N
      DOUBLE PRECISION PPF
!
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION RE
      DOUBLE PRECISION AE
!
      DOUBLE PRECISION OGIFU2
      EXTERNAL OGIFU2
!
      DOUBLE PRECISION DP
      COMMON/OG2COM/DP
!
      DOUBLE PRECISION DN
      COMMON/OGICOM/DN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      PPF=0.0D0
      IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO OGIPPF IS ',   &
               'OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)P
   48   FORMAT('      THE VALUE OF THE ARGUMENT IS: ',G15.7,'.')
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ELSEIF(N.LT.0.5D0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE SECOND ARGUMENT TO OGIPDF IS ',   &
               'LESS THAN 0.5')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)N
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(P.EQ.0.0D0)THEN
        PPF=0.0D0
        GO TO 9000
      ELSEIF(P.EQ.1.0D0)THEN
        PPF=1.0D0
        GO TO 9000
      ENDIF
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE PERCENT POINT FUNCTION.**
!               *****************************************
!
      XLOW=0.0D0
      XUP=1.0D0
      XUP2=0.5D0
      AE=1.D-7
      RE=1.D-7
      DN=N
      DP=P
      CALL DFZERO(OGIFU2,XLOW,XUP,XUP2,RE,AE,IFLAG)
!
      PPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM OGIPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM OGIPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM OGIPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM OGIPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE OGIPPF
      SUBROUTINE OGIRAN(N,AN,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE OGIVE DISTRIBUTION WITH
!              SHAPE PARAMETER AN.
!
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!                  f(X;N) = N*X**(N-1)*{(4*N-2)/(3*N-1) -
!                           ((2*N-2)/(3*N-1))*X**N}
!                           0 <= X <= 1, N >= 0.5
!
!              WITH N DENOTING THE SHAPE PARAMETER.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --AN     = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER AN.
!                                AN SHOULD BE IN THE RANGE (0,1).
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE OGIVE DISTRIBUTION
!             WITH SHAPE PARAMETER AN.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, OGIPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND VAN DORP (2004), "BEYOND AN: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATIONS", WORLD SCIENTFIC
!                 PUBLISHING COMPANY, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'OGIVE RANDOM NUMBERS IS NON-POSITIVE')
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      ELSEIF(AN.LT.0.5)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)AN
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  201 FORMAT('***** ERROR--THE N SHAPE PARAMETER IS ',   &
             'LESS THAN 0.5')
  203 FORMAT('      THE VALUE OF N IS ',G15.7)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N OGIVE DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL OGIPPF(DBLE(X(I)),DBLE(AN),DTEMP)
        X(I)=REAL(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE OGIRAN
      subroutine onestp(y,n,np,ns,nt,nl,isdeg,itdeg,ildeg,nsjump,ntjump,   &
      nljump,ni,userw,rw,season,trend,work)
!
!  This routine is part of the Bill Cleveland seasonal loess
!  program.
!
      integer n,ni,np,ns,nt,nsjump,ntjump,nl,nljump,isdeg,itdeg,ildeg
      real y(n),rw(n),season(n),trend(n),work(n+2*np,5)
      logical userw
      do 23089 j = 1,ni
      do 23091 i = 1,n
      work(i,1) = y(i)-trend(i)
23091 continue
      call ss(work(1,1),n,np,ns,isdeg,nsjump,userw,rw,work(1,2),work(1,   &
      3),work(1,4),work(1,5),season)
      call fts(work(1,2),n+2*np,np,work(1,3),work(1,1))
      call ess(work(1,3),n,nl,ildeg,nljump,.false.,work(1,4),work(1,1),   &
      work(1,5))
      do 23093 i = 1,n
      season(i) = work(np+i,2)-work(i,1)
23093 continue
      do 23095 i = 1,n
      work(i,1) = y(i)-season(i)
23095 continue
      call ess(work(1,1),n,nt,itdeg,ntjump,userw,rw,trend,work(1,3))
23089 continue
      return
      end
      SUBROUTINE OPTCHK(N,X,TYPSIZ,SX,FSCALE,GRADTL,ITNLIM,NDIGIT,EPSM,   &
           DLT,METHOD,IEXP,IAGFLG,IAHFLG,STEPMX,MSG,IPRTMP)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! CHECK INPUT FOR REASONABLENESS
!
! PARAMETERS
! ----------
! N            --> DIMENSION OF PROBLEM
! X(N)         --> ON ENTRY, ESTIMATE TO ROOT OF FCN
! TYPSIZ(N)   <--> TYPICAL SIZE OF EACH COMPONENT OF X
! SX(N)       <--  DIAGONAL SCALING MATRIX FOR X
! FSCALE      <--> ESTIMATE OF SCALE OF OBJECTIVE FUNCTION FCN
! GRADTL       --> TOLERANCE AT WHICH GRADIENT CONSIDERED CLOSE
!                  ENOUGH TO ZERO TO TERMINATE ALGORITHM
! ITNLIM      <--> MAXIMUM NUMBER OF ALLOWABLE ITERATIONS
! NDIGIT      <--> NUMBER OF GOOD DIGITS IN OPTIMIZATION FUNCTION FCN
! EPSM         --> MACHINE EPSILON
! DLT         <--> TRUST REGION RADIUS
! METHOD      <--> ALGORITHM INDICATOR
! IEXP        <--> EXPENSE FLAG
! IAGFLG      <--> =1 IF ANALYTIC GRADIENT SUPPLIED
! IAHFLG      <--> =1 IF ANALYTIC HESSIAN SUPPLIED
! STEPMX      <--> MAXIMUM STEP SIZE
! MSG         <--> MESSAGE AND ERROR CODE
! IPR          --> DEVICE TO WHICH TO SEND OUTPUT
!
      DIMENSION X(N),TYPSIZ(N),SX(N)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      IF(IPRTMP.LT.0)IPRTMP=IPR
!
! CHECK THAT PARAMETERS ONLY TAKE ON ACCEPTABLE VALUES.
! IF NOT, SET THEM TO DEFAULT VALUES.
      IF(METHOD.LT.1 .OR. METHOD.GT.3) METHOD=1
      IF(IAGFLG.NE.1) IAGFLG=0
      IF(IAHFLG.NE.1) IAHFLG=0
      IF(IEXP.NE.0) IEXP=1
      IF(MOD(MSG/2,2).EQ.1 .AND. IAGFLG.EQ.0) GO TO 830
      IF(MOD(MSG/4,2).EQ.1 .AND. IAHFLG.EQ.0) GO TO 835
!
! CHECK DIMENSION OF PROBLEM
!
      IF(N.LE.0) GO TO 805
      IF(N.EQ.1 .AND. MOD(MSG,2).EQ.0) GO TO 810
!
! COMPUTE SCALE MATRIX
!
      DO 10 I=1,N
        IF(TYPSIZ(I).EQ.0.D0) TYPSIZ(I)=1.0D0
        IF(TYPSIZ(I).LT.0.D0) TYPSIZ(I)=-TYPSIZ(I)
        SX(I)=1.0D0/TYPSIZ(I)
   10 CONTINUE
!
! CHECK MAXIMUM STEP SIZE
!
      IF (STEPMX .GT. 0.0D0) GO TO 20
      STPSIZ = 0.0D0
      DO 15 I = 1, N
         STPSIZ = STPSIZ + X(I)*X(I)*SX(I)*SX(I)
   15 CONTINUE
      STPSIZ = SQRT(STPSIZ)
      STEPMX = MAX(1.0D3*STPSIZ, 1.0D3)
   20 CONTINUE
! CHECK FUNCTION SCALE
      IF(FSCALE.EQ.0.) FSCALE=1.0D0
      IF(FSCALE.LT.0.) FSCALE=-FSCALE
!
! CHECK GRADIENT TOLERANCE
      IF(GRADTL.LT.0.D0) GO TO 815
!
! CHECK ITERATION LIMIT
      IF(ITNLIM.LE.0) GO TO 820
!
! CHECK NUMBER OF DIGITS OF ACCURACY IN FUNCTION FCN
      IF(NDIGIT.EQ.0) GO TO 825
      IF(NDIGIT.LT.0) NDIGIT=INT(-LOG10(EPSM))
!
! CHECK TRUST REGION RADIUS
      IF(DLT.LE.0.) DLT=-1.0D0
      IF (DLT .GT. STEPMX) DLT = STEPMX
      RETURN
!
! ERROR EXITS
!
  805 WRITE(ICOUT,901) N
      CALL DPWRST('XXX','BUG ')
      MSG=-1
      GO TO 895
  810 WRITE(ICOUT,902)
      CALL DPWRST('XXX','BUG ')
      MSG=-2
      GO TO 895
  815 WRITE(ICOUT,903) GRADTL
      CALL DPWRST('XXX','BUG ')
      MSG=-3
      GO TO 895
  820 WRITE(ICOUT,904) ITNLIM
      CALL DPWRST('XXX','BUG ')
      MSG=-4
      GO TO 895
  825 WRITE(ICOUT,905) NDIGIT
      CALL DPWRST('XXX','BUG ')
      MSG=-5
      GO TO 895
  830 WRITE(ICOUT,906) MSG
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,916)IAGFLG
      CALL DPWRST('XXX','BUG ')
      MSG=-6
      GO TO 895
  835 WRITE(ICOUT,907) MSG
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,917)IAHFLG
      CALL DPWRST('XXX','BUG ')
      MSG=-7
  895 RETURN
  901 FORMAT('***** FROM OPTCHK    ILLEGAL DIMENSION, N =',I5)
  902 FORMAT(   &
      '***** FROM OPTCHK    +++ WARNING +++  THIS PACKAGE IS ',   &
      'INEFFICIENT FOR PROBLEMS OF SIZE N=1.')
  903 FORMAT(   &
      '***** FROM OPTCHK    ILLEGAL TOLERANCE.  GRADTL = ',E20.13)
  904 FORMAT(   &
      '***** FROM OPTCHK    ILLEGAL ITERATION LIMIT.  ITNLIM = ',I5)
  905 FORMAT(   &
      '***** FROM OPTCHK    MINIMIZATION FUNCTION HAS NO GOOD DIGITS.'   &
      ,'  NDIGIT = ',I5)
  906 FORMAT(   &
      '***** FROM OPTCHK    USER REQUESTS THAT ANALYTIC GRADIENT BE',   &
      ' ACCEPTED AS PROPERLY CODED (MSG =',I5)
  916 FORMAT(   &
      '                     BUT ANALYTIC GRADIENT NOT SUPPLIED',   &
      '(IAGFLG = ',I5,'.')
  907 FORMAT(   &
      '***** FROM OPTCHK    USER REQUESTS THAT ANALYTIC HESSIAN BE',   &
      ' ACCEPTED AS PROPERLY CODED (MSG =',I5)
  917 FORMAT(   &
      '                     BUT ANALYTIC HESSIAN NOT SUPPLIED',   &
      '(IAHFLG = ',I5,'.')
      END SUBROUTINE OPTCHK
      SUBROUTINE OPTDRV(NR,N,X,TYPSIZ,FSCALE,   &
                        METHOD,IEXP,MSG,NDIGIT,ITNLIM,IAGFLG,   &
                        IAHFLG,IPR2,   &
                        DLT,GRADTL,STEPMX,STEPTL,   &
                        XPLS,FPLS,GPLS,ITRMCD,   &
                        A,UDIAG,G,P,SX,WRK0,WRK1,WRK2,WRK3)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! DRIVER FOR NON-LINEAR OPTIMIZATION PROBLEM
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! X(N)         --> ON ENTRY: ESTIMATE TO A ROOT OF FCN
! FCN          --> NAME OF SUBROUTINE TO EVALUATE OPTIMIZATION FUNCTION
!                  MUST BE DECLARED EXTERNAL IN CALLING ROUTINE
!                            FCN: R(N) --> R(1)
! D1FCN        --> (OPTIONAL) NAME OF SUBROUTINE TO EVALUATE GRADIENT
!                  OF FCN.  MUST BE DECLARED EXTERNAL IN CALLING ROUTINE
! D2FCN        --> (OPTIONAL) NAME OF SUBROUTINE TO EVALUATE HESSIAN OF
!                  OF FCN.  MUST BE DECLARED EXTERNAL IN CALLING ROUTINE
! TYPSIZ(N)    --> TYPICAL SIZE FOR EACH COMPONENT OF X
! FSCALE       --> ESTIMATE OF SCALE OF OBJECTIVE FUNCTION
! METHOD       --> ALGORITHM TO USE TO SOLVE MINIMIZATION PROBLEM
!                    =1 LINE SEARCH
!                    =2 DOUBLE DOGLEG
!                    =3 MORE-HEBDON
! IEXP         --> =1 IF OPTIMIZATION FUNCTION FCN IS EXPENSIVE TO
!                  EVALUATE, =0 OTHERWISE.  IF SET THEN HESSIAN WILL
!                  BE EVALUATED BY SECANT UPDATE INSTEAD OF
!                  ANALYTICALLY OR BY FINITE DIFFERENCES
! MSG         <--> ON INPUT:  (.GT.0) MESSAGE TO INHIBIT CERTAIN
!                    AUTOMATIC CHECKS
!                  ON OUTPUT: (.LT.0) ERROR CODE; =0 NO ERROR
! NDIGIT       --> NUMBER OF GOOD DIGITS IN OPTIMIZATION FUNCTION FCN
! ITNLIM       --> MAXIMUM NUMBER OF ALLOWABLE ITERATIONS
! IAGFLG       --> =1 IF ANALYTIC GRADIENT SUPPLIED
! IAHFLG       --> =1 IF ANALYTIC HESSIAN SUPPLIED
! IPR          --> DEVICE TO WHICH TO SEND OUTPUT
! DLT          --> TRUST REGION RADIUS
! GRADTL       --> TOLERANCE AT WHICH GRADIENT CONSIDERED CLOSE
!                  ENOUGH TO ZERO TO TERMINATE ALGORITHM
! STEPMX       --> MAXIMUM ALLOWABLE STEP SIZE
! STEPTL       --> RELATIVE STEP SIZE AT WHICH SUCCESSIVE ITERATES
!                  CONSIDERED CLOSE ENOUGH TO TERMINATE ALGORITHM
! XPLS(N)     <--> ON EXIT:  XPLS IS LOCAL MINIMUM
! FPLS        <--> ON EXIT:  FUNCTION VALUE AT SOLUTION, XPLS
! GPLS(N)     <--> ON EXIT:  GRADIENT AT SOLUTION XPLS
! ITRMCD      <--  TERMINATION CODE
! A(N,N)       --> WORKSPACE FOR HESSIAN (OR ESTIMATE)
!                  AND ITS CHOLESKY DECOMPOSITION
! UDIAG(N)     --> WORKSPACE [FOR DIAGONAL OF HESSIAN]
! G(N)         --> WORKSPACE (FOR GRADIENT AT CURRENT ITERATE)
! P(N)         --> WORKSPACE FOR STEP
! SX(N)        --> WORKSPACE (FOR DIAGONAL SCALING MATRIX)
! WRK0(N)      --> WORKSPACE
! WRK1(N)      --> WORKSPACE
! WRK2(N)      --> WORKSPACE
! WRK3(N)      --> WORKSPACE
!
!
! INTERNAL VARIABLES
! ------------------
! ANALTL           TOLERANCE FOR COMPARISON OF ESTIMATED AND
!                  ANALYTICAL GRADIENTS AND HESSIANS
! EPSM             MACHINE EPSILON
! F                FUNCTION VALUE: FCN(X)
! ITNCNT           CURRENT ITERATION, K
! RNF              RELATIVE NOISE IN OPTIMIZATION FUNCTION FCN.
!                       NOISE=10.**(-NDIGIT)
!
      DIMENSION X(N),XPLS(N),G(N),GPLS(N),P(N)
      DIMENSION TYPSIZ(N),SX(N)
      DIMENSION A(NR,1),UDIAG(N)
      DIMENSION WRK0(N),WRK1(N),WRK2(N),WRK3(N)
      DIMENSION FHAT(1)
      DIMENSION WRKHAT(1)
      LOGICAL MXTAKE,NOUPDT
!DPLT EXTERNAL FCN,D1FCN,D2FCN
!DPLT EXTERNAL OPTFCN
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOF2.INC'
      REAL R1MACH
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
! INITIALIZATION
! --------------
      DO 10 I=1,N
        P(I)=0.D0
   10 CONTINUE
      ITNCNT=0
      IRETCD=-1
!CCCC EPSM=D1MACH(4)
      EPSM=R1MACH(4)
      AMUSAV = 0.0D0
      DLPSAV = 0.0D0
      DLTSAV = 0.0D0
      PHISAV = 0.0D0
      PHPSAV = 0.0D0
!
      CALL OPTCHK(N,X,TYPSIZ,SX,FSCALE,GRADTL,ITNLIM,NDIGIT,EPSM,   &
           DLT,METHOD,IEXP,IAGFLG,IAHFLG,STEPMX,MSG,IPR2)
      IF(MSG.LT.0) RETURN
      RNF=MAX(10.0D0**(-NDIGIT),EPSM)
      ANALTL=MAX(1.0D-2,SQRT(RNF))
!
      IF(MOD(MSG/8,2).EQ.1) GO TO 15
      WRITE(ICOUT,901)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,900) (TYPSIZ(I),I=1,MIN(N,5))
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,902)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,900) (SX(I),I=1,MIN(5,N))
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,903) FSCALE
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,904) NDIGIT
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,914) IAGFLG
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,916)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,924) IAHFLG
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,926)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,934) IEXP
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,936)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,944) METHOD
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,946)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,954) ITNLIM
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,964) EPSM
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,905) STEPMX
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,915) STEPTL
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,925) GRADTL
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,935) DLT
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,945) RNF
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,955) ANALTL
      CALL DPWRST('XXX','BUG ')
   15 CONTINUE
!
! EVALUATE FCN(X)
!
      CALL OPTFCN(N,X,FHAT)
      F=FHAT(1)
!
! EVALUATE ANALYTIC OR FINITE DIFFERENCE GRADIENT AND CHECK ANALYTIC
! GRADIENT, IF REQUESTED.
!
      IF (IAGFLG .EQ. 1) GO TO 20
!     IF (IAGFLG .EQ. 0)
!     THEN
!CCCC   CALL FSTOFD (1, 1, N, X, OPTFCN, F, G, SX, RNF, WRK, 1)
!CCCC   CALL FSTOFD (1, 1, N, X, F, G, SX, RNF, WRK, 1)
        CALL FSTOFD (1, 1, N, X, FHAT, G, SX, RNF, WRK1, 1)
        F=FHAT(1)
        GO TO 25
!
   20 CONTINUE
!DP20 CALL D1FCN (N, X, G)
!DPLT IF (MOD(MSG/2,2) .EQ. 1) GO TO 25
!     IF (MOD(MSG/2,2).EQ.0)
!     THEN
!DPLT   CALL GRDCHK (N, X, FCN, F, G, TYPSIZ, SX, FSCALE,
!DPLT1    RNF, ANALTL, WRK1, MSG, IPR)
!DPLT   IF (MSG .LT. 0) RETURN
   25 CONTINUE
!
      CALL OPTSTP(N,X,F,G,WRK1,ITNCNT,ICSCMX,   &
                  ITRMCD,GRADTL,STEPTL,SX,FSCALE,ITNLIM,IRETCD,MXTAKE,   &
                  IPR,MSG)
      IF(ITRMCD.NE.0) GO TO 700
!
      IF(IEXP.NE.1) GO TO 80
!
! IF OPTIMIZATION FUNCTION EXPENSIVE TO EVALUATE (IEXP=1), THEN
! HESSIAN WILL BE OBTAINED BY SECANT UPDATES.  GET INITIAL HESSIAN.
!
      CALL HSNINT(NR,N,A,SX,METHOD)
      GO TO 90
   80 CONTINUE
!
! EVALUATE ANALYTIC OR FINITE DIFFERENCE HESSIAN AND CHECK ANALYTIC
! HESSIAN IF REQUESTED (ONLY IF USER-SUPPLIED ANALYTIC HESSIAN
! ROUTINE D2FCN FILLS ONLY LOWER TRIANGULAR PART AND DIAGONAL OF A).
!
      IF (IAHFLG .EQ. 1) GO TO 82
!     IF (IAHFLG .EQ. 0)
!     THEN
!DPLT    IF (IAGFLG .EQ. 1) CALL FSTOFD (NR, N, N, X, D1FCN, G, A, SX,
!DPLT1      RNF, WRK1, 3)
!DPLT    IF (IAGFLG .NE. 1) CALL SNDOFD (NR, N, X, OPTFCN, F, A, SX,
         IF (IAGFLG .EQ. 1) CALL FSTOFD (NR, N, N, X, G, A, SX,   &
            RNF, WRK1, 3)
         IF (IAGFLG .NE. 1) CALL SNDOFD (NR, N, X, F, A, SX,   &
            RNF, WRK1, WRK2)
         GO TO 88
!
!     ELSE
   82    CONTINUE
!DP82    IF (MOD(MSG/4,2).EQ.0) GO TO 85
!        IF (MOD(MSG/4, 2) .EQ. 1)
!        THEN
!DPLT       CALL D2FCN (NR, N, X, A)
!DPLT       GO TO 88
!
!        ELSE
!DP85       CALL HESCHK (NR, N, X, FCN, D1FCN, D2FCN, F, G, A, TYPSIZ,
!DPLT1         SX, RNF, ANALTL, IAGFLG, UDIAG, WRK1, WRK2, MSG, IPR)
!
!           HESCHK EVALUATES D2FCN AND CHECKS IT AGAINST THE FINITE
!           DIFFERENCE HESSIAN WHICH IT CALCULATES BY CALLING FSTOFD
!           (IF IAGFLG .EQ. 1) OR SNDOFD (OTHERWISE).
!
!DPLT       IF (MSG .LT. 0) RETURN
   88 CONTINUE
!
   90 IF(MOD(MSG/8,2).EQ.0)   &
           CALL RESULT(NR,N,X,F,G,A,P,ITNCNT,1)
!
!
! ITERATION
! ---------
  100 ITNCNT=ITNCNT+1
!
! FIND PERTURBED LOCAL MODEL HESSIAN AND ITS LL+ DECOMPOSITION
! (SKIP THIS STEP IF LINE SEARCH OR DOGSTEP TECHNIQUES BEING USED WITH
! SECANT UPDATES.  CHOLESKY DECOMPOSITION L ALREADY OBTAINED FROM
! SECFAC.)
!
      IF(IEXP.EQ.1 .AND. METHOD.NE.3) GO TO 105
  103   CALL CHLHSN(NR,N,A,EPSM,SX,UDIAG)
  105 CONTINUE
!
! SOLVE FOR NEWTON STEP:  AP=-G
!
      DO 110 I=1,N
        WRK1(I)=-G(I)
  110 CONTINUE
      CALL LLTSLV(NR,N,A,P,WRK1)
!
! DECIDE WHETHER TO ACCEPT NEWTON STEP  XPLS=X + P
! OR TO CHOOSE XPLS BY A GLOBAL STRATEGY.
!
      IF (IAGFLG .NE. 0 .OR. METHOD .EQ. 1) GO TO 111
      DLTSAV = DLT
      IF (METHOD .EQ. 2) GO TO 111
      AMUSAV = AMU
      DLPSAV = DLTP
      PHISAV = PHIZ
      PHPSAV = PHIP0
  111 CONTINUE
      IF(METHOD.EQ.1)   &
           CALL LNSRCH(N,X,F,G,P,XPLS,FPLS,MXTAKE,IRETCD,   &
           STEPMX,STEPTL,SX,IPR2)
      IF(METHOD.EQ.2)   &
           CALL DOGDRV(NR,N,X,F,G,A,P,XPLS,FPLS,SX,STEPMX,   &
           STEPTL,DLT,IRETCD,MXTAKE,WRK0,WRK1,WRK2,WRK3,IPR2)
      IF(METHOD.EQ.3)   &
           CALL HOOKDR(NR,N,X,F,G,A,UDIAG,P,XPLS,FPLS,SX,STEPMX,   &
           STEPTL,DLT,IRETCD,MXTAKE,AMU,DLTP,PHIZ,PHIP0,WRK0,   &
           WRK1,WRK2,EPSM,ITNCNT,IPR2)
!
! IF COULD NOT FIND SATISFACTORY STEP AND FORWARD DIFFERENCE
! GRADIENT WAS USED, RETRY USING CENTRAL DIFFERENCE GRADIENT.
!
      IF (IRETCD .NE. 1 .OR. IAGFLG .NE. 0) GO TO 112
!     IF (IRETCD .EQ. 1 .AND. IAGFLG .EQ. 0)
!     THEN
!
!        SET IAGFLG FOR CENTRAL DIFFERENCES
!
         IAGFLG = -1
         WRITE(ICOUT,906) ITNCNT
         CALL DPWRST('XXX','BUG ')
!
!DPLT    CALL FSTOCD (N, X, OPTFCN, SX, RNF, G)
         CALL FSTOCD (N, X, SX, RNF, G)
         IF (METHOD .EQ. 1) GO TO 105
         DLT = DLTSAV
         IF (METHOD .EQ. 2) GO TO 105
         AMU = AMUSAV
         DLTP = DLPSAV
         PHIZ = PHISAV
         PHIP0 = PHPSAV
         GO TO 103
!     ENDIF
!
! CALCULATE STEP FOR OUTPUT
!
  112 CONTINUE
      DO 114 I = 1, N
         P(I) = XPLS(I) - X(I)
  114 CONTINUE
!
! CALCULATE GRADIENT AT XPLS
!
      IF (IAGFLG .EQ. (-1)) GO TO 116
      IF (IAGFLG .EQ. 0) GO TO 118
!
! ANALYTIC GRADIENT
!DPLT CALL D1FCN (N, XPLS, GPLS)
      GO TO 120
!
! CENTRAL DIFFERENCE GRADIENT
!D116 CALL FSTOCD (N, XPLS, OPTFCN, SX, RNF, GPLS)
  116 CALL FSTOCD (N, XPLS, SX, RNF, GPLS)
      GO TO 120
!
! FORWARD DIFFERENCE GRADIENT
!D118 CALL FSTOFD (1, 1, N, XPLS, OPTFCN, FPLS, GPLS, SX, RNF, WRK, 1)
!C118 CALL FSTOFD (1, 1, N, XPLS, FPLS, GPLS, SX, RNF, WRK, 1)
  118 CONTINUE
      CALL FSTOFD (1, 1, N, XPLS, FHAT, GPLS, SX, RNF, WRKHAT, 1)
      FPLS=FHAT(1)
  120 CONTINUE
!
! CHECK WHETHER STOPPING CRITERIA SATISFIED
!
      CALL OPTSTP(N,XPLS,FPLS,GPLS,X,ITNCNT,ICSCMX,   &
                  ITRMCD,GRADTL,STEPTL,SX,FSCALE,ITNLIM,IRETCD,MXTAKE,   &
                  IPR2,MSG)
      IF(ITRMCD.NE.0) GO TO 690
!
! EVALUATE HESSIAN AT XPLS
!
      IF(IEXP.EQ.0) GO TO 130
      IF(METHOD.EQ.3)   &
           CALL SECUNF(NR,N,X,G,A,UDIAG,XPLS,GPLS,EPSM,ITNCNT,RNF,   &
           IAGFLG,NOUPDT,WRK1,WRK2,WRK3)
      IF(METHOD.NE.3)   &
           CALL SECFAC(NR,N,X,G,A,XPLS,GPLS,EPSM,ITNCNT,RNF,IAGFLG,   &
           NOUPDT,WRK0,WRK1,WRK2,WRK3)
      GO TO 150
  130 IF(IAHFLG.EQ.1) GO TO 140
      IF(IAGFLG.NE.1)   &
           CALL SNDOFD(NR,N,XPLS,FPLS,A,SX,RNF,WRK1,WRK2)
      GO TO 150
  140 CONTINUE
!D140 CALL D2FCN(NR,N,XPLS,A)
  150 CONTINUE
      IF(MOD(MSG/16,2).EQ.1)   &
           CALL RESULT(NR,N,XPLS,FPLS,GPLS,A,P,ITNCNT,1)
!
! X <-- XPLS  AND  G <-- GPLS  AND  F <-- FPLS
!
      F=FPLS
      DO 160 I=1,N
        X(I)=XPLS(I)
        G(I)=GPLS(I)
  160 CONTINUE
      GO TO 100
!
! TERMINATION
! -----------
! RESET XPLS,FPLS,GPLS,  IF PREVIOUS ITERATE SOLUTION
!
  690 IF(ITRMCD.NE.3) GO TO 710
  700 CONTINUE
      FPLS=F
      DO 705 I=1,N
        XPLS(I)=X(I)
        GPLS(I)=G(I)
  705 CONTINUE
!
! PRINT RESULTS
!
  710 CONTINUE
      IF(MOD(MSG/8,2).EQ.0)   &
           CALL RESULT(NR,N,XPLS,FPLS,GPLS,A,P,ITNCNT,0)
      MSG=0
!DPLT
!CCCC WRITE HESSIAN TO FILE DPST2F.DAT.  BEFORE WRITING, MAKE
!CCCC UPPER DIAGONAL OF MATRIX EQUAL TO LOWER DIAGONAL.
!
      IOUNI2=IST2NU
      DO 9005 I=1,N
        DO 9007 J=1,N
          A(J,I)=A(I,J)
 9007   CONTINUE
 9005 CONTINUE
!
      IF(N.LE.10)THEN
      WRITE(IOUNI2,9011)ITNCNT
      DO 9010 I=1,N
        WRITE(IOUNI2,9013)(A(I,J),J=1,N)
 9010 CONTINUE
 9011 FORMAT(1X,'HESSIAN MATRIX AT ITERATION ',I5)
 9013 FORMAT(10(1X,E15.7))
      ELSE
      WRITE(IOUNI2,9011)ITNCNT
      DO 9020 I=1,N
        DO 9025 J=1,N
          WRITE(IOUNI2,9023)A(I,J)
 9025   CONTINUE
        WRITE(IOUNI2,9027)
 9020 CONTINUE
 9023 FORMAT(1X,E15.7)
 9027 FORMAT(1X)
      ENDIF
!
      RETURN
!
  900 FORMAT('***** FROM OPTDRV       ',5(E20.13,3X))
  901 FORMAT('***** FROM OPTDRV    TYPICAL X')
  902 FORMAT('***** FROM OPTDRV    DIAGONAL SCALING MATRIX FOR X')
  903 FORMAT('***** FROM OPTDRV    TYPICAL F = ',E20.13)
  904 FORMAT('***** FROM OPTDRV    NUMBER OF GOOD DIGITS IN OPTFCN = ',   &
      I5)
  914 FORMAT('                     GRADIENT FLAG  = ',I5,   &
      ' (=1 IF ')
  916 FORMAT('                     ANALYTIC GRADIENT SUPPLIED)')
  924 FORMAT('                     HESSIAN FLAG   = ',I5,   &
      ' (=1 IF ')
  926 FORMAT('                     ANALYTIC HESSIAN SUPPLIED)')
  934 FORMAT('                     EXPENSE FLAG   = ',I5,' (=1 IF ',   &
      'MINIMIZATION ')
  936 FORMAT('                     FUNCTION EXPENSIVE TO EVALUATE)')
  944 FORMAT('                     METHOD TO USE  = ',I5,' (=1,2,3 ',   &
      'FOR LINE SEARCH,')
  946 FORMAT('                     DOUBLE DOGLEG, MORE-HEBDON ',   &
      ' RESPECTIVELY)')
  954 FORMAT('                     ITERATION LIMIT = ',I5)
  964 FORMAT('                     MACHINE EPSILON = ',E20.13)
  905 FORMAT('***** FROM OPTDRV    MAXIMUM STEP SIZE    = ',E20.13)
  915 FORMAT('                     STEP TOLERANCE       = ',E20.13)
  925 FORMAT('                     GRADIENT TOLERANCE   = ',E20.13)
  935 FORMAT('                     TRUST REGION RADIUS  = ',E20.13)
  945 FORMAT('                     REL NOISE IN OPTFCN  = ',E20.13)
  955 FORMAT('                     ANAL-FD TOLERANCE    = ',E20.13)
  906 FORMAT('***** FROM OPTDRV    SHIFT FROM FORWARD TO CENTRAL ',   &
      'DIFFERENCES IN ITERATION ', I5)
      END SUBROUTINE OPTDRV
      SUBROUTINE OPTFCN(NTEMP, XTEMP, FHAT)
!
!     PURPOSE--AUXILLARY FUNCTION FOR THE UNCMIN ROUTINES.
!              IT COMPUTES THE FUNCTION BEING OPTIMIZED
!              AT THE VALUES OF THE N PARAMETERS GIVEN IN
!              X AND RETURNS THE FUNCTION VALUE IN F.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/2
!     ORIGINAL VERSION--FEBRUARY  1995.
!     UPDATED         --SEPTEMBER 2015. SUPPORT FOR FUNCTION BLOCKS
!     UPDATED         --SEPTEMBER 2015. SUPPORT FOR IOPTMM (SPECIFY
!                                       WHETHER MINIMIZING OR
!                                       MAXIMIMZING THE FUNCTION)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION XTEMP(*)
      DOUBLE PRECISION FHAT(*)
      DOUBLE PRECISION F
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOFB.INC'
      INCLUDE 'DPCOST.INC'
!
      COMMON/IFBL2/IFLGFB
!
      CHARACTER*8 IFBNAM
      CHARACTER*8 IFBANS
!
      CHARACTER*4 IFEESV
      COMMON/IFEED/IFEESV
!
      CHARACTER*4 ZMODEL
      CHARACTER*4 IPARN
      CHARACTER*4 IPARN2
      CHARACTER*4 IANGLU
      CHARACTER*4 IFTEXP
      CHARACTER*4 IFTORD
      CHARACTER*4 IFORSW
      CHARACTER*4 ITYPEH
      CHARACTER*4 IW21HO
      CHARACTER*4 IW22HO
      CHARACTER*4 IVARN
      CHARACTER*4 IVARN2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IH
      CHARACTER*4 IH2
!
!---------------------------------------------------------------------
!
      PARAMETER (IOPTCH=1000)
      PARAMETER (IOPTC2=100)
!
      DIMENSION PARAM(IOPTC2)
      DIMENSION IPARN(IOPTC2)
      DIMENSION IPARN2(IOPTC2)
      DIMENSION IVARN(IOPTC2)
      DIMENSION IVARN2(IOPTC2)
!
      DIMENSION ZMODEL(IOPTCH)
      DIMENSION ITYPEH(IOPTCH)
      DIMENSION IW21HO(IOPTCH)
      DIMENSION IW22HO(IOPTCH)
      DIMENSION W2HOLD(IOPTCH)
!
      DIMENSION ILOCV(IOPTC2)
!CCCC DIMENSION ILAB(IOPTC2)
!
      COMMON /OPTCMC/ IBUGA3, ITYPEH, IW21HO, IW22HO, IPARN, IPARN2,   &
                      IVARN, IVARN2, ZMODEL
      COMMON /OPTCMR/ PARAM, W2HOLD,   &
                      NUMCHA, NUMVAR, NWHOLD, NUMDV, ILOCV
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      IFOUND='NO'
      IBUGA3='OFF'
      IBUGCO='OFF'
      IBUGEV='OFF'
      ISUBRO='NULL'
      IFTEXP='+'
      IFTORD='DATA'
      IFORSW='E'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF OPTFCN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NUMCHA,NUMDV,NUMVAR,NTEMP,IFLGFB
   53   FORMAT('NUMCHA,NUMDV,NUMVAR,NTEMP,IFLGFB = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)(ZMODEL(J),J=1,MIN(NUMCHA,25))
   54   FORMAT('ZMODEL(I) = ',25A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMVAR
          WRITE(ICOUT,56)I,PARAM(I),IPARN(I),IPARN2(I)
   56     FORMAT('I,PARAM(I),IPARN(I),IPARN2(I) = ',I8,G15.7,A4,A4)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 59 I=1,NUMDV
          WRITE(ICOUT,61)I,IVARN(I),IVARN2(I)
   61     FORMAT('I, IVARN(I),IVARN2(I) = ',I8,2X,A4,A4)
          CALL DPWRST('XXX','BUG ')
   59   CONTINUE
      ENDIF
!
!               ***************************
!               **  STEP 3--             **
!               **  INITIALIZE PARAMETERS**
!               ***************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFBNAM=' '
      IFBANS=' '
      IFBCPT=0
      IF(IFLGFB.EQ.1)THEN
        IFBNAM=IFBNA1
        IFBANS=IFBAN1
        IFBCNT=IFBCN1
        IFBCPT=IFBCP1
      ELSEIF(IFLGFB.EQ.2)THEN
        IFBNAM=IFBNA2
        IFBANS=IFBAN2
        IFBCNT=IFBCN2
        IFBCPT=IFBCP2
      ELSEIF(IFLGFB.EQ.3)THEN
        IFBNAM=IFBNA3
        IFBANS=IFBAN3
        IFBCNT=IFBCN3
        IFBCPT=IFBCP3
      ENDIF
!
      IF(IFLGFB.LE.0)THEN
        DO 9100 K=1,NUMDV
          JLOC=ILOCV(K)
          PARAM(JLOC)=REAL(XTEMP(K))
 9100   CONTINUE
!
        IPASS=2
        IBUGCO=IBUGA3
        IBUGEV=IBUGA3
        CALL COMPIM(ZMODEL,NUMCHA,IPASS,PARAM,IPARN,IPARN2,NUMVAR,   &
                    IANGLU,ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,FX,   &
                    IBUGCO,IBUGEV,IERROR)
        IF(IOPTMM.EQ.'MAXI')FX=-FX
      ELSE
!
!       FUNCTION BLOCK CASE:
!
!       STEP 1: COMPUTE FUNCTION BLOCK (BUT FIRST SET CURRENT
!               VALUE OF DESIRED PARAMETER).
!
        DO 3301 JJ=1,IFBCPT
          IF(IFLGFB.EQ.1)THEN
            IH=IFBPL1(JJ)(1:4)
            IH2=IFBPL1(JJ)(5:8)
          ELSEIF(IFLGFB.EQ.2)THEN
            IH=IFBPL2(JJ)(1:4)
            IH2=IFBPL2(JJ)(5:8)
          ELSEIF(IFLGFB.EQ.3)THEN
            IH=IFBPL3(JJ)(1:4)
            IH2=IFBPL3(JJ)(5:8)
          ENDIF
          IF(IH.EQ.'    ')GO TO 3301
          DO 3305 II=1,NUMNAM
            IF(IH.EQ.IHNAME(II) .AND. IH2.EQ.IHNAM2(II) .AND.   &
               IUSE(II).EQ.'P')THEN
              VALUE(II)=REAL(XTEMP(JJ))
              IVALUE(II)=INT(XTEMP(JJ)+0.5D0)
              GO TO 3301
          ENDIF
 3305     CONTINUE
!
!         PARAMETER NAME NOT FOUND IN CURRENT LIST, SO NEED TO ADD
!         TO NAME LIST
!
          IF(NUMNAM.LT.MAXNAM)THEN
            NUMNAM=NUMNAM+1
            IHNAME(NUMNAM)=IH
            IHNAM2(NUMNAM)=IH2
            IUSE(NUMNAM)='P'
            VALUE(NUMNAM)=REAL(XTEMP(JJ))
            IVALUE(NUMNAM)=INT(XTEMP(JJ)+ 0.5)
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,3306)
 3306       FORMAT('***** ERROR IN MULTIVARIABLE OPTIMIZATION--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,3307)
 3307       FORMAT('      MAXIMUM NUMBER OF NAMES EXCEEDED.')
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 3301   CONTINUE
!
        IFEEDB='OFF'
        CALL DPFBEX(IFBNAM,IANGLU,ISEED,IFTEXP,IFTORD,IFORSW,   &
                    IBUGA3,IBUGA3,IBUGCO,IBUGEV,IBUGEV,   &
                    ISUBRO,IFOUND,IERROR)
        IFEEDB=IFEESV
!
!       STEP 2: RETRIEVE RESPONSE
!
        DO 3320 II=1,NUMNAM
          IF(IFBANS(1:4).EQ.IHNAME(II) .AND.   &
             IFBANS(5:8).EQ.IHNAM2(II))THEN
            IF(IUSE(II).EQ.'P')THEN
              FX=VALUE(II)
              GO TO 3329
            ELSEIF(IUSE(II).EQ.'V')THEN
              ICOLR=IVALUE(II)
              IJ=MAXN*(ICOLR-1)+1
              IF(ICOLR.LE.MAXCOL)FX=V(IJ)
              IF(ICOLR.EQ.MAXCP1)FX=PRED(1)
              IF(ICOLR.EQ.MAXCP2)FX=RES(1)
              IF(ICOLR.EQ.MAXCP3)FX=YPLOT(1)
              IF(ICOLR.EQ.MAXCP4)FX=XPLOT(1)
              IF(ICOLR.EQ.MAXCP5)FX=X2PLOT(1)
              IF(ICOLR.EQ.MAXCP6)FX=TAGPLO(1)
              GO TO 3329
            ENDIF
          ENDIF
 3320   CONTINUE
!
!       PARAMETER/VARIABLE NAME NOT FOUND
!
        WRITE(ICOUT,3306)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3321)
 3321   FORMAT('      EXPECTED PARAMETER/VARIABLE NOT FOUND IN ',   &
               'NAME TABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3323)IFBANS
 3323   FORMAT('      EXPECTED NAME = ',A8)
        CALL DPWRST('XXX','BUG ')
        FX=0.0
!
 3329   CONTINUE
        IF(IOPTMM.EQ.'MAXI')FX=-FX
!
      ENDIF
!
      F=DBLE(FX)
      FHAT(1)=F
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END      OF OPTFCN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9021)IERROR
 9021   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9101)FX
 9101   FORMAT('FX  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9102 KK=1,NUMDV
          WRITE(ICOUT,9103)KK,REAL(X(KK))
 9103     FORMAT('I,X(I) = ',I5,1X,G15.7)
          CALL DPWRST('XXX','BUG ')
 9102   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE OPTFCN
      SUBROUTINE OPTIF9(NR,N,X,TYPSIZ,FSCALE,   &
                        METHOD,IEXP,MSG,NDIGIT,ITNLIM,IAGFLG,   &
                        IAHFLG,IPR,   &
                        DLT,GRADTL,STEPMX,STEPTL,   &
                        XPLS,FPLS,GPLS,ITRMCD,A,WRK)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! PROVIDE COMPLETE INTERFACE TO MINIMIZATION PACKAGE.
! USER HAS FULL CONTROL OVER OPTIONS.
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! X(N)         --> ON ENTRY: ESTIMATE TO A ROOT OF FCN
! FCN          --> NAME OF SUBROUTINE TO EVALUATE OPTIMIZATION FUNCTION
!                  MUST BE DECLARED EXTERNAL IN CALLING ROUTINE
!                            FCN: R(N) --> R(1)
! D1FCN        --> (OPTIONAL) NAME OF SUBROUTINE TO EVALUATE GRADIENT
!                  OF FCN.  MUST BE DECLARED EXTERNAL IN CALLING ROUTINE
! D2FCN        --> (OPTIONAL) NAME OF SUBROUTINE TO EVALUATE HESSIAN OF
!                  OF FCN.  MUST BE DECLARED EXTERNAL IN CALLING ROUTINE
! TYPSIZ(N)    --> TYPICAL SIZE FOR EACH COMPONENT OF X
! FSCALE       --> ESTIMATE OF SCALE OF OBJECTIVE FUNCTION
! METHOD       --> ALGORITHM TO USE TO SOLVE MINIMIZATION PROBLEM
!                    =1 LINE SEARCH
!                    =2 DOUBLE DOGLEG
!                    =3 MORE-HEBDON
! IEXP         --> =1 IF OPTIMIZATION FUNCTION FCN IS EXPENSIVE TO
!                  EVALUATE, =0 OTHERWISE.  IF SET THEN HESSIAN WILL
!                  BE EVALUATED BY SECANT UPDATE INSTEAD OF
!                  ANALYTICALLY OR BY FINITE DIFFERENCES
! MSG         <--> ON INPUT:  (.GT.0) MESSAGE TO INHIBIT CERTAIN
!                    AUTOMATIC CHECKS
!                  ON OUTPUT: (.LT.0) ERROR CODE; =0 NO ERROR
! NDIGIT       --> NUMBER OF GOOD DIGITS IN OPTIMIZATION FUNCTION FCN
! ITNLIM       --> MAXIMUM NUMBER OF ALLOWABLE ITERATIONS
! IAGFLG       --> =1 IF ANALYTIC GRADIENT SUPPLIED
! IAHFLG       --> =1 IF ANALYTIC HESSIAN SUPPLIED
! IPR          --> DEVICE TO WHICH TO SEND OUTPUT
! DLT          --> TRUST REGION RADIUS
! GRADTL       --> TOLERANCE AT WHICH GRADIENT CONSIDERED CLOSE
!                  ENOUGH TO ZERO TO TERMINATE ALGORITHM
! STEPMX       --> MAXIMUM ALLOWABLE STEP SIZE
! STEPTL       --> RELATIVE STEP SIZE AT WHICH SUCCESSIVE ITERATES
!                  CONSIDERED CLOSE ENOUGH TO TERMINATE ALGORITHM
! XPLS(N)     <--> ON EXIT:  XPLS IS LOCAL MINIMUM
! FPLS        <--> ON EXIT:  FUNCTION VALUE AT SOLUTION, XPLS
! GPLS(N)     <--> ON EXIT:  GRADIENT AT SOLUTION XPLS
! ITRMCD      <--  TERMINATION CODE
! A(N,N)       --> WORKSPACE FOR HESSIAN (OR ESTIMATE)
!                  AND ITS CHOLESKY DECOMPOSITION
! WRK(N,8)     --> WORKSPACE
!
!CCCC MAY 1995.  DO DUMMY DECLARATIONS WITH "*".
!CCCC DIMENSION X(N),XPLS(N),GPLS(N),TYPSIZ(N)
!CCCC DIMENSION A(NR,1),WRK(NR,1)
      DIMENSION X(*),XPLS(*),GPLS(*),TYPSIZ(*)
      DIMENSION A(NR,*),WRK(NR,*)
!DPLT EXTERNAL FCN,D1FCN,D2FCN
!DPLT EXTERNAL OPTFCN
!
! EQUIVALENCE WRK(N,1) = UDIAG(N)
!             WRK(N,2) = G(N)
!             WRK(N,3) = P(N)
!             WRK(N,4) = SX(N)
!             WRK(N,5) = WRK0(N)
!             WRK(N,6) = WRK1(N)
!             WRK(N,7) = WRK2(N)
!             WRK(N,8) = WRK3(N)
!
!DPLT CALL OPTDRV(NR,N,X,FCN,D1FCN,D2FCN,TYPSIZ,FSCALE,
      CALL OPTDRV(NR,N,X,TYPSIZ,FSCALE,   &
                  METHOD,IEXP,MSG,NDIGIT,ITNLIM,IAGFLG,IAHFLG,IPR,   &
                  DLT,GRADTL,STEPMX,STEPTL,   &
                  XPLS,FPLS,GPLS,ITRMCD,   &
                  A,WRK(1,1),WRK(1,2),WRK(1,3),WRK(1,4),WRK(1,5),   &
           WRK(1,6),WRK(1,7),WRK(1,8))
      RETURN
      END SUBROUTINE OPTIF9
      SUBROUTINE OPTSTP(N,XPLS,FPLS,GPLS,X,ITNCNT,ICSCMX,   &
            ITRMCD,GRADTL,STEPTL,SX,FSCALE,ITNLIM,IRETCD,MXTAKE,   &
            IPRTMP,MSG)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! UNCONSTRAINED MINIMIZATION STOPPING CRITERIA
! --------------------------------------------
! FIND WHETHER THE ALGORITHM SHOULD TERMINATE, DUE TO ANY
! OF THE FOLLOWING:
! 1) PROBLEM SOLVED WITHIN USER TOLERANCE
! 2) CONVERGENCE WITHIN USER TOLERANCE
! 3) ITERATION LIMIT REACHED
! 4) DIVERGENCE OR TOO RESTRICTIVE MAXIMUM STEP (STEPMX) SUSPECTED
!
!
! PARAMETERS
! ----------
! N            --> DIMENSION OF PROBLEM
! XPLS(N)      --> NEW ITERATE X[K]
! FPLS         --> FUNCTION VALUE AT NEW ITERATE F(XPLS)
! GPLS(N)      --> GRADIENT AT NEW ITERATE, G(XPLS), OR APPROXIMATE
! X(N)         --> OLD ITERATE X[K-1]
! ITNCNT       --> CURRENT ITERATION K
! ICSCMX      <--> NUMBER CONSECUTIVE STEPS .GE. STEPMX
!                  [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! ITRMCD      <--  TERMINATION CODE
! GRADTL       --> TOLERANCE AT WHICH RELATIVE GRADIENT CONSIDERED CLOSE
!                  ENOUGH TO ZERO TO TERMINATE ALGORITHM
! STEPTL       --> RELATIVE STEP SIZE AT WHICH SUCCESSIVE ITERATES
!                  CONSIDERED CLOSE ENOUGH TO TERMINATE ALGORITHM
! SX(N)        --> DIAGONAL SCALING MATRIX FOR X
! FSCALE       --> ESTIMATE OF SCALE OF OBJECTIVE FUNCTION
! ITNLIM       --> MAXIMUM NUMBER OF ALLOWABLE ITERATIONS
! IRETCD       --> RETURN CODE
! MXTAKE       --> BOOLEAN FLAG INDICATING STEP OF MAXIMUM LENGTH USED
! IPR          --> DEVICE TO WHICH TO SEND OUTPUT
! MSG          --> IF MSG INCLUDES A TERM 8, SUPPRESS OUTPUT
!
!
      INTEGER N,ITNCNT,ICSCMX,ITRMCD,ITNLIM
      DIMENSION SX(N)
      DIMENSION XPLS(N),GPLS(N),X(N)
      LOGICAL MXTAKE
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      IF(IPRTMP.LT.0)IPRTMP=IPR
      ITRMCD=0
!
! LAST GLOBAL STEP FAILED TO LOCATE A POINT LOWER THAN X
      IF(IRETCD.NE.1) GO TO 50
!     IF(IRETCD.EQ.1)
!     THEN
        JTRMCD=3
        GO TO 600
!     ENDIF
   50 CONTINUE
!
! FIND DIRECTION IN WHICH RELATIVE GRADIENT MAXIMUM.
! CHECK WHETHER WITHIN TOLERANCE
!
      D=MAX(ABS(FPLS),FSCALE)
      RGX=0.0D0
      DO 100 I=1,N
        RELGRD=ABS(GPLS(I))*MAX(ABS(XPLS(I)),1.D0/SX(I))/D
        RGX=MAX(RGX,RELGRD)
  100 CONTINUE
      JTRMCD=1
      IF(RGX.LE.GRADTL) GO TO 600
!
      IF(ITNCNT.EQ.0) RETURN
!
! FIND DIRECTION IN WHICH RELATIVE STEPSIZE MAXIMUM
! CHECK WHETHER WITHIN TOLERANCE.
!
      RSX=0.0D0
      DO 120 I=1,N
        RELSTP=ABS(XPLS(I)-X(I))/MAX(ABS(XPLS(I)),1./SX(I))
        RSX=MAX(RSX,RELSTP)
  120 CONTINUE
      JTRMCD=2
      IF(RSX.LE.STEPTL) GO TO 600
!
! CHECK ITERATION LIMIT
!
      JTRMCD=4
      IF(ITNCNT.GE.ITNLIM) GO TO 600
!
! CHECK NUMBER OF CONSECUTIVE STEPS \ STEPMX
!
      IF(MXTAKE) GO TO 140
!     IF(.NOT.MXTAKE)
!     THEN
        ICSCMX=0
        RETURN
!     ELSE
  140   CONTINUE
        IF (MOD(MSG/8,2) .EQ. 0) WRITE(ICOUT,900)
        ICSCMX=ICSCMX+1
        IF(ICSCMX.LT.5) RETURN
        JTRMCD=5
!     ENDIF
!
!
! PRINT TERMINATION CODE
!
!CCCC DATAPLOT WILL PRINT THE ERROR MESSAGES FROM DPOPT3.
  600 ITRMCD=JTRMCD
      IF (MOD(MSG/8,2) .EQ. 0) GO TO(601,602,603,604,605), ITRMCD
      GO TO 700
  601 CONTINUE
!CCCC WRITE(ICOUT,901)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,911)
!CCCC CALL DPWRST('XXX','BUG ')
      GO TO 700
  602 CONTINUE
!CCCC WRITE(ICOUT,902)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,912)
!CCCC CALL DPWRST('XXX','BUG ')
      GO TO 700
  603 CONTINUE
!CCCC WRITE(ICOUT,903)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,913)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,923)
!CCCC CALL DPWRST('XXX','BUG ')
      GO TO 700
  604 CONTINUE
!CCCC WRITE(ICOUT,904)
!CCCC CALL DPWRST('XXX','BUG ')
      GO TO 700
  605 CONTINUE
!CCCC WRITE(ICOUT,905)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,915)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,915)
!CCCC CALL DPWRST('XXX','BUG ')
!
  700 RETURN
!
  900 FORMAT(   &
      '***** FROM OPTSTP    STEP OF MAXIMUM LENGTH (STEPMX) TAKEN')
!C901 FORMAT(
!CCCC+'***** FROM OPTSTP    RELATIVE GRADIENT CLOSE TO ZERO.')
!C911 FORMAT(
!CCCC+'                     CURRENT ITERATE IS PROBABLY SOLUTION.')
!C902 FORMAT(
!CCCC+'***** FROM OPTSTP    SUCCESSIVE ITERATES WITHIN TOLERANCE.')
!C912 FORMAT(
!CCCC+'                     CURRENT ITERATE IS PROBABLY SOLUTION.')
!C903 FORMAT(
!CCCC+'***** FROM OPTSTP    LAST GLOBAL STEP FAILED TO LOCATE A ',
!CCCC+'POINT LOWER THAN X.')
!C913 FORMAT(
!CCCC+'                     EITHER X IS AN APPROXIMATE LOCAL MINIMUM',
!CCCC+ ' OF THE FUNCTION,')
!C923 FORMAT(
!CCCC+'                     THE FUNCTION IS TOO NON-LINEAR FOR THIS ',
!CCCC+'ALGORITHM OR STEPTL IS TOO LARGE.')
!C904 FORMAT(
!CCCC+'***** FROM OPTSTP    ALGORITHM FAILED BECAUSE ITERATION LIMIT',
!CCCC+'  EXCEEDED.')
!C905 FORMAT(
!CCCC+'***** FROM OPTSTP    MAXIMUM STEP SIZE EXCEEDED 5 CONSECUTIVE',
!CCCC+'  TIMES.')
!C915 FORMAT(
!CCCC+'                     EITHER THE FUNCTION IS UNBOUNDED BELOW, ',
!CCCC+'BECOMES ASYMPTOTIC TO A FINITE VALUE FROM ABOVE IN SOME ')
!C925 FORMAT(
!CCCC+'                     DIRECTION, OR STEPMX IS TOO SMALL.')
      END SUBROUTINE OPTSTP
      SUBROUTINE ORTHES(NM,N,LOW,IGH,A,ORT)
!***BEGIN PROLOGUE  ORTHES
!***DATE WRITTEN   760101   (YYMMDD)
!***REVISION DATE  830518   (YYMMDD)
!***CATEGORY NO.  D4C1B2
!***KEYWORDS  EIGENVALUES,EIGENVECTORS,EISPACK
!***AUTHOR  SMITH, B. T., ET AL.
!***PURPOSE  Reduces real general matrix to upper Hessenberg form
!            orthogonal similarity transformations.
!***DESCRIPTION
!
!     This subroutine is a translation of the ALGOL procedure ORTHES,
!     NUM. MATH. 12, 349-368(1968) by Martin and Wilkinson.
!     HANDBOOK FOR AUTO. COMP., VOL.II-LINEAR ALGEBRA, 339-358(1971).
!
!     Given a REAL GENERAL matrix, this subroutine
!     reduces a submatrix situated in rows and columns
!     LOW through IGH to upper Hessenberg form by
!     orthogonal similarity transformations.
!
!     On INPUT
!
!        NM must be set to the row dimension of two-dimensional
!          array parameters as declared in the calling program
!          dimension statement.
!
!        N is the order of the matrix.
!
!        LOW and IGH are integers determined by the balancing
!          subroutine  BALANC.  If  BALANC  has not been used,
!          set LOW=1, IGH=N.
!
!        A contains the input matrix.
!
!     On OUTPUT
!
!        A contains the Hessenberg matrix.  Information about
!          the orthogonal transformations used in the reduction
!          is stored in the remaining triangle under the
!          Hessenberg matrix.
!
!        ORT contains further information about the transformations.
!          only elements LOW through IGH are used.
!
!     Questions and comments should be directed to B. S. Garbow,
!     APPLIED MATHEMATICS DIVISION, ARGONNE NATIONAL LABORATORY
!     ------------------------------------------------------------------
!***REFERENCES  B. T. SMITH, J. M. BOYLE, J. J. DONGARRA, B. S. GARBOW,
!                 Y. IKEBE, V. C. KLEMA, C. B. MOLER, *MATRIX EIGEN-
!                 SYSTEM ROUTINES - EISPACK GUIDE*, SPRINGER-VERLAG,
!                 1976.
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  ORTHES
!
      INTEGER I,J,M,N,II,JJ,LA,MP,NM,IGH,KP1,LOW
      REAL A(NM,N),ORT(IGH)
      REAL F,G,H,SCALE
!
!***FIRST EXECUTABLE STATEMENT  ORTHES
      LA = IGH - 1
      KP1 = LOW + 1
      IF (LA .LT. KP1) GO TO 200
!
      DO 180 M = KP1, LA
         H = 0.0E0
         ORT(M) = 0.0E0
         SCALE = 0.0E0
!     .......... SCALE COLUMN (ALGOL TOL THEN NOT NEEDED) ..........
         DO 90 I = M, IGH
            SCALE = SCALE + ABS(A(I,M-1))
   90    CONTINUE
!
         IF (SCALE .EQ. 0.0E0) GO TO 180
         MP = M + IGH
!     .......... FOR I=IGH STEP -1 UNTIL M DO -- ..........
         DO 100 II = M, IGH
            I = MP - II
            ORT(I) = A(I,M-1) / SCALE
            H = H + ORT(I) * ORT(I)
  100    CONTINUE
!
         G = -SIGN(SQRT(H),ORT(M))
         H = H - ORT(M) * G
         ORT(M) = ORT(M) - G
!     .......... FORM (I-(U*UT)/H) * A ..........
         DO 130 J = M, N
            F = 0.0E0
!     .......... FOR I=IGH STEP -1 UNTIL M DO -- ..........
            DO 110 II = M, IGH
               I = MP - II
               F = F + ORT(I) * A(I,J)
  110       CONTINUE
!
            F = F / H
!
            DO 120 I = M, IGH
               A(I,J) = A(I,J) - F * ORT(I)
  120       CONTINUE
!
  130    CONTINUE
!     .......... FORM (I-(U*UT)/H)*A*(I-(U*UT)/H) ..........
         DO 160 I = 1, IGH
            F = 0.0E0
!     .......... FOR J=IGH STEP -1 UNTIL M DO -- ..........
            DO 140 JJ = M, IGH
               J = MP - JJ
               F = F + ORT(J) * A(I,J)
  140       CONTINUE
!
            F = F / H
!
            DO 150 J = M, IGH
               A(I,J) = A(I,J) - F * ORT(J)
  150       CONTINUE
!
  160    CONTINUE
!
         ORT(M) = SCALE * ORT(M)
         A(M,M-1) = SCALE * G
  180 CONTINUE
!
  200 RETURN
      END SUBROUTINE ORTHES
      SUBROUTINE ORTRAN(NM,N,LOW,IGH,A,ORT,Z)
!***BEGIN PROLOGUE  ORTRAN
!***DATE WRITTEN   760101   (YYMMDD)
!***REVISION DATE  830518   (YYMMDD)
!***CATEGORY NO.  D4C4
!***KEYWORDS  EIGENVALUES,EIGENVECTORS,EISPACK
!***AUTHOR  SMITH, B. T., ET AL.
!***PURPOSE  Accumulates orthogonal similarity transformations in
!            reduction of real general matrix by ORTHES.
!***DESCRIPTION
!
!     This subroutine is a translation of the ALGOL procedure ORTRANS,
!     NUM. MATH. 16, 181-204(1970) by Peters and Wilkinson.
!     HANDBOOK FOR AUTO. COMP., VOL.II-LINEAR ALGEBRA, 372-395(1971).
!
!     This subroutine accumulates the orthogonal similarity
!     transformations used in the reduction of a REAL GENERAL
!     matrix to upper Hessenberg form by  ORTHES.
!
!     On INPUT
!
!        NM must be set to the row dimension of two-dimensional
!          array parameters as declared in the calling program
!          dimension statement.
!
!        N is the order of the matrix.
!
!        LOW and IGH are integers determined by the balancing
!          subroutine  BALANC.  If  BALANC  has not been used,
!          set LOW=1, IGH=N.
!
!        A contains information about the orthogonal trans-
!          formations used in the reduction by  ORTHES
!          in its strict lower triangle.
!
!        ORT contains further information about the trans-
!          formations used in the reduction by  ORTHES.
!          only elements LOW through IGH are USED.
!
!     On OUTPUT
!
!        Z contains the transformation matrix produced in the
!          reduction by  ORTHES.
!
!        ORT has been altered.
!
!     Questions and comments should be directed to B. S. Garbow,
!     APPLIED MATHEMATICS DIVISION, ARGONNE NATIONAL LABORATORY
!     ------------------------------------------------------------------
!***REFERENCES  B. T. SMITH, J. M. BOYLE, J. J. DONGARRA, B. S. GARBOW,
!                 Y. IKEBE, V. C. KLEMA, C. B. MOLER, *MATRIX EIGEN-
!                 SYSTEM ROUTINES - EISPACK GUIDE*, SPRINGER-VERLAG,
!                 1976.
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  ORTRAN
!
      INTEGER I,J,N,KL,MM,MP,NM,IGH,LOW,MP1
      REAL A(NM,IGH),ORT(IGH),Z(NM,N)
      REAL G
!
!     .......... INITIALIZE Z TO IDENTITY MATRIX ..........
!***FIRST EXECUTABLE STATEMENT  ORTRAN
      DO 80 I = 1, N
!
         DO 60 J = 1, N
            Z(I,J) = 0.0E0
   60    CONTINUE
!
         Z(I,I) = 1.0E0
   80 CONTINUE
!
      KL = IGH - LOW - 1
      IF (KL .LT. 1) GO TO 200
!     .......... FOR MP=IGH-1 STEP -1 UNTIL LOW+1 DO -- ..........
      DO 140 MM = 1, KL
         MP = IGH - MM
         IF (A(MP,MP-1) .EQ. 0.0E0) GO TO 140
         MP1 = MP + 1
!
         DO 100 I = MP1, IGH
            ORT(I) = A(I,MP-1)
  100    CONTINUE
!
         DO 130 J = MP, IGH
            G = 0.0E0
!
            DO 110 I = MP, IGH
               G = G + ORT(I) * Z(I,J)
  110       CONTINUE
!     .......... DIVISOR BELOW IS NEGATIVE OF H FORMED IN ORTHES.
!                DOUBLE DIVISION AVOIDS POSSIBLE UNDERFLOW ..........
            G = (G / ORT(MP)) / A(MP,MP-1)
!
            DO 120 I = MP, IGH
               Z(I,J) = Z(I,J) + G * ORT(I)
  120       CONTINUE
!
  130    CONTINUE
!
  140 CONTINUE
!
  200 RETURN
      END SUBROUTINE ORTRAN
      SUBROUTINE PA(X,N,XPT,DELTAE,IWRITE,PAOUT,   &
                    IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE "PERCENTAGE OF ALLOWED
!              DEVIATION" (OR PA) STATISTIC:
!
!                 Pa(i) = (D(i)/DELTAe))*100
!
!              WHERE
!
!                   D(i)    = X(i) - Xpt
!                             (Xpt IS A CONSENSUS OR ASSIGNED VALUE)
!                   DELTAe  = IS A PRE-DEFINED ALLOWANCE FOR
!                             MEASUREMENT ERROR
!
!              THE PA STATISTIC IS A PERFORMANCE SCORE DISCUSSED
!              IN THE ISO 13528 STANDARD (2015 SECOND EDITION).
!              VALUES OF PA <= -100 AND PA >= 100 INDICATE AN
!              "ACTION" SIGNAL.
!
!              NOTE THAT XPT AND DELTAE ARE NOT COMPUTED FROM THE
!              CURRENT DATA.  THE XPT IS CONSIDERED THE "TRUE" VALUE
!              (OR THE BEST GUESS OF THE TRUE VALUE).  THE ISO 13528
!              STANDARD DISCUSSES NUMEROUS WAYS OF DETERMINING THIS
!              VALUE.  THE DELTAE IS AN "ACCEPTABLE" ERROR.  THERE IS
!              NO STANDARD WAY FOR DETERMINING THIS.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --XPT    = THE SINGLE PRECISION VALUE CONTAINING
!                                THE ASSIGNED VALUE
!                     --DELTAE = THE SINGLE PRECISION VALUE CONTAINING
!                                THE PRE-DEFINED ALLOWABLE ERROR
!     OUTPUT ARGUMENTS--PAOUT  = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED PA VALUES.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE SAMPLE PA
!             VALUES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--ISO 13528, SECOND EDITION, STATISTICAL METHODS FOR USE
!                IN PROFICIENCY TESTING BY INTERLABORATORY COMPARISONS,
!                2015, PP. 25.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2016.2
!     ORIGINAL VERSION--FEBRUARY  2016.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION PAOUT(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PA  '
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PA  ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N,XPT,DELTAE
   52   FORMAT('IBUGA3,N,XPT,DELTAE = ',A4,2X,I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************
!               **  COMPUTE PA    **
!               ********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN PA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(DELTAE.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE ALLOWABE MEASUREMENT ERROR (DELTAE) IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)DELTAE
  127   FORMAT('      THE ALLOWABLE MEASUREMENT ERROR = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *************************
!               **  STEP 2--           **
!               **  COMPUTE THE PA     **
!               *************************
!
      DO 200 I=1,N
        PAOUT(I)=((X(I) - XPT)/DELTAE)*100.
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N
  811   FORMAT('THE NUMBER OF PA VALUES GENERATED = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PA  ')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF PA--')
        CALL DPWRST('XXX','BUG ')
        DO 9012 I=1,N
          WRITE(ICOUT,9015)I,X(I),PAOUT(I)
 9015     FORMAT('I,X(I),PAOUT(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9012   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE PA
      SUBROUTINE PAPCDF(DX,DTHETA,DP,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE DX
!              FOR THE POLYA-AEPPLI DISTRIBUTION
!              WITH DOUBLE PRECISION SHAPE PARAMETERS DTHETA AND
!              DP.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= 0.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;THETA,P) = EXP(-THETA)*(THETA*(1-P)/P)*P**X*
!                             CHU(X+1;2,THETA*(1-P)/P)
!                           = EXP(-THETA)*P**X*
!                             SUM[J=1 to X][(X-1  J-1)*
!                             (THETA*(1-P)/P)**J/J!
!                             X = 1, 2, ....
!
!              p(0;THETA,P) = EXP(-THETA)
!
!              CHU = THE CONFLUENT HYPERGEOMETRIC FUNTION 1F1.
!
!              JOHNSON, KOTZ, AND KEMP GIVE THE FOLLOWING
!              FORMULAS FOR X = 1, ..., 4 (ALPHA=THETA*(1-P)/P):
!
!
!              p(1;THETA,P) = EXP(-THETA)*
!              p(2;THETA,P) = EXP(-THETA)*ALPHA*P**2*(1+ALPHA/2)
!              p(2;THETA,P) = EXP(-THETA)*ALPHA*P**2*(1+ALPHA/2)
!              p(3;THETA,P) = EXP(-THETA)*ALPHA*P**3*
!                             (1+ALPHA+ALPHA**2/6)
!              p(4;THETA,P) = EXP(-THETA)*ALPHA*P**4*
!                             (1+3*ALPHA/2+ALPHA**2/2+ALPHA**3/24)
!
!              FOR THE CDF, WE USE THE FOLLOWING RECURRENCE
!              RELATION (FROM JOHNSON, KOTZ AND KEMP):
!
!              p(X+1) = (THETA*(1-P)/(X+1))*SUM[J=1 TO X]
!                       [(X+1-J)*P**(X-J)*p(X)]
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --DTHETA = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --DP     = THE DOUBLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE DCDF FOR THE POLYA-AEPPLI DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 < P < 1,  AND THETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM, DCHU.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 378-382.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DCDF=0.0D0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
               'PAPCDF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DTHETA.LE.0.0D0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'PAPCDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DTHETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      INTX=INT(DX+0.5D0)
      IF(INTX.LT.0)THEN
        DCDF=0.0D0
        GO TO 9999
      ENDIF
!
!
      DQ=1.0D0 - DP
      DALPHA=DTHETA*DQ/DP
      DX=DBLE(INTX)
!
      DPDFS2=DEXP(-DTHETA)
      IF(INTX.EQ.0)THEN
        DCDF=DPDFS2
        GO TO 9999
      ENDIF
      DTERM1=-DTHETA + DLOG(DALPHA) + DLOG(DP)
      DPDFS1=DEXP(DTERM1)
      IF(INTX.EQ.1)THEN
        DCDF=DPDFS1+DPDFS2
        GO TO 9999
      ENDIF
      DCDF=DPDFS1+DPDFS2
!
      DO 100 I=2,INTX
        IF(I.EQ.2)THEN
          DTERM1=-DTHETA + DLOG(DALPHA) + 2.0D0*DLOG(DP) +   &
                 DLOG(1.0D0 + DALPHA/2.0D0)
          DPDF=DEXP(DTERM1)
        ELSEIF(I.EQ.3)THEN
          DTERM1=-DTHETA + DLOG(DALPHA) + 3.0D0*DLOG(DP) +   &
                 DLOG(1.0D0 + DALPHA + DALPHA**2/6.0D0)
          DPDF=DEXP(DTERM1)
        ELSEIF(I.EQ.4)THEN
          DTERM1=-DTHETA + DLOG(DALPHA) + 4.0D0*DLOG(DP) +   &
                 DLOG(1.0D0 + 1.5D0*DALPHA + 0.5D0*DALPHA**2   &
                 + DALPHA**3/24.0D0)
          DPDF=DEXP(DTERM1)
        ELSE
          DTERM1=(1.0D0/DBLE(I))
          DTERM2=(DTHETA*DQ + 2.0D0*DP*DBLE(I-1))*DPDFS1
          DTERM3=DP**2*DBLE(I-2)*DPDFS2
          DPDF=DTERM1*(DTERM2 - DTERM3)
        ENDIF
        DCDF=DCDF + DPDF
        DPDFS2=DPDFS1
        DPDFS1=DPDF
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PAPCDF
      SUBROUTINE PAPFUN(N,XPAR,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              POLYA-AEPPLI MAXIMUM LIKELIHOOD EQUATIONS:
!
!                  XBAR - THETAHAT/(1-PHAT) = 0
!                  XBAR - SUM[J=1 to N][fj*(J-1)*P(J-1)/(N*P(J))} = 0
!
!              WITH THETAHAT AND PHAT DENOTING THE CURRENT ESTIMATES
!              OF THE SHAPE PARAMETERS AND WHERE P(J) = THE
!              POLYA-AEPPLI PDF USING THE ESTIMATED PARAMETERS.
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!
!     EXAMPLE--POLYA-AEPPLI MAXIMUM LIKELIHOOD Y
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 378-382.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DXM1
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPDF1
      DOUBLE PRECISION DPDF2
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DENOM
      DOUBLE PRECISION DSUM1
!
      DOUBLE PRECISION XBAR
      COMMON/PAPCOM/MAXNXT,NTOT,XBAR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DTHETA=XPAR(1)
      DP=XPAR(2)
      DN=DBLE(NTOT)
      FVEC(1)=XBAR - DTHETA/(1.0D0 - DP)
!
      IINDX=MAXNXT/2
      DSUM1=0.0D0
!
      DO 200 I=1,K
!
        DX=DBLE(Y(IINDX+I))
        DFREQ=Y(I)
!
        DXM1=DX-1.0D0
        CALL PAPPDF(DXM1,DTHETA,DP,DPDF1)
        CALL PAPPDF(DX,DTHETA,DP,DPDF2)
        DNUM=DFREQ*DXM1*DPDF1
        DENOM=DN*DPDF2
!
        IF(DENOM.NE.0.0D0)THEN
          DSUM1=DSUM1 + DNUM/DENOM
        ELSE
          DSUM1=DSUM1 + DBLE(CPUMAX)
        ENDIF
!
  200 CONTINUE
!
      FVEC(2)=XBAR - DSUM1
!
      RETURN
      END SUBROUTINE PAPFUN
      SUBROUTINE PAPPDF(DX,DTHETA,DP,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE DX
!              FOR THE POLYA-AEPPLI DISTRIBUTION
!              WITH DOUBLE PRECISION SHAPE PARAMETERS DTHETA AND
!              DP.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= 0.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;THETA,P) = EXP(-THETA)*(THETA*(1-P)/P)*P**X*
!                             CHU(X+1;2,THETA*(1-P)/P)
!                           = EXP(-THETA)*P**X*
!                             SUM[J=1 to X][(X-1  J-1)*
!                             (THETA*(1-P)/P)**J/J!
!                             X = 1, 2, ....
!
!              p(0;THETA,P) = EXP(-THETA)
!
!              CHU = THE CONFLUENT HYPERGEOMETRIC FUNTION 1F1.
!
!              JOHNSON, KOTZ, AND KEMP GIVE THE FOLLOWING
!              FORMULAS FOR X = 1, ..., 4 (ALPHA=THETA*(1-P)/P):
!
!
!              p(1;THETA,P) = EXP(-THETA)*
!              p(2;THETA,P) = EXP(-THETA)*ALPHA*P**2*(1+ALPHA/2)
!              p(2;THETA,P) = EXP(-THETA)*ALPHA*P**2*(1+ALPHA/2)
!              p(3;THETA,P) = EXP(-THETA)*ALPHA*P**3*
!                             (1+ALPHA+ALPHA**2/6)
!              p(4;THETA,P) = EXP(-THETA)*ALPHA*P**4*
!                             (1+3*ALPHA/2+ALPHA**2/2+ALPHA**3/24)
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --DTHETA = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --DP     = THE DOUBLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS FUNCTION VALUE
!             DPDF FOR THE POLYA-AEPPLI DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 < P < 1,  AND THETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM, DCHU.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 378-382.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DPDF=0.0D0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
!
      IF(DTHETA.LE.0.0D0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DTHETA
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
      INTX=INT(DX+0.5D0)
      IF(INTX.LT.0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
!
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PAPPDF ',   &
      'IS NEGATIVE')
   11 FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
      'PAPPDF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   12 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
      'PAPPDF IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      DQ=1.0D0 - DP
      DALPHA=DTHETA*DQ/DP
      DX=DBLE(INTX)
!
      IF(INTX.EQ.0)THEN
        DPDF=DEXP(-DTHETA)
      ELSEIF(INTX.EQ.1)THEN
        DTERM1=-DTHETA + DLOG(DALPHA) + DLOG(DP)
        DPDF=DEXP(DTERM1)
      ELSEIF(INTX.EQ.2)THEN
        DTERM1=-DTHETA + DLOG(DALPHA) + 2.0D0*DLOG(DP) +   &
                DLOG(1.0D0 + DALPHA/2.0D0)
        DPDF=DEXP(DTERM1)
      ELSEIF(INTX.EQ.3)THEN
        DTERM1=-DTHETA + DLOG(DALPHA) + 3.0D0*DLOG(DP) +   &
                DLOG(1.0D0 + DALPHA + DALPHA**2/6.0D0)
        DPDF=DEXP(DTERM1)
      ELSEIF(INTX.EQ.4)THEN
        DTERM1=-DTHETA + DLOG(DALPHA) + 4.0D0*DLOG(DP) +   &
                DLOG(1.0D0 + 1.5D0*DALPHA + 0.5D0*DALPHA**2   &
                + DALPHA**3/24.0D0)
        DPDF=DEXP(DTERM1)
      ELSE
!
!       THE CONFLUENT HYPERGEOMETRIC FORMULATION GIVEN IN
!       JOHNSON, KOTZ, AND KEMP DOES NOT SEEM TO BE
!       WORKING FOR REASONS THAT ARE NOT CLEAR TO ME.  SO FOR
!       NOW, USE THE SUMMATION FORMULA.  THIS IS LESS
!       EFFICIENT, BUT IT SEEMS TO PROVIDE ACCURATE ANSWERS.
!
!CCCC   DTWO=2.0D0
!CCCC   DTERM1=-DTHETA + DLOG(1.0D0-DP) + DLOG(DTHETA) - DLOG(DP)
!CCCC  1       + DX*DLOG(DP)
!CCCC   CALL CHM(DTWO,-DTHETA*(1.0D0-DP)/DP,1.0D0-DX,DTERM2,IERROR)
!CCCC   DTERM2=DLOG(DTERM2)
!CCCC   DPDF=DEXP(DTERM1 + DTERM2)
!CCCC   print *,'dterm1,dterm2,dpdf=',dterm1,dterm2,dpdf
!
        DTERM1=-DTHETA + DX*DLOG(DP)
        DSUM=0.0D0
        DO 100 J=1,INTX
          DJ=DBLE(J)
          DTERM2=DLNGAM(DX) - DLNGAM(DJ) - DLNGAM(DX-DJ+1.0D0)
          DTERM3=DJ*DLOG(DALPHA) - DLNGAM(DJ+1.0D0)
          DSUM=DSUM + DEXP(DTERM2 + DTERM3)
  100   CONTINUE
        DTERM4=DLOG(DSUM)
        DPDF=DEXP(DTERM1 + DTERM4)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PAPPDF
      SUBROUTINE PAPPPF(DX,DTHETA,DP,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE DX
!              FOR THE POLYA-AEPPLI DISTRIBUTION
!              WITH DOUBLE PRECISION SHAPE PARAMETERS DTHETA AND
!              DP.  THIS DISTRIBUTION IS DEFINED FOR 0 <= DX < 1.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;THETA,P) = EXP(-THETA)*(THETA*(1-P)/P)*P**X*
!                             CHU(X+1;2,THETA*(1-P)/P)
!                           = EXP(-THETA)*P**X*
!                             SUM[J=1 to X][(X-1  J-1)*
!                             (THETA*(1-P)/P)**J/J!
!                             X = 1, 2, ....
!
!              p(0;THETA,P) = EXP(-THETA)
!
!              CHU = THE CONFLUENT HYPERGEOMETRIC FUNTION 1F1.
!
!              JOHNSON, KOTZ, AND KEMP GIVE THE FOLLOWING
!              FORMULAS FOR X = 1, ..., 4 (ALPHA=THETA*(1-P)/P):
!
!
!              p(1;THETA,P) = EXP(-THETA)*
!              p(2;THETA,P) = EXP(-THETA)*ALPHA*P**2*(1+ALPHA/2)
!              p(2;THETA,P) = EXP(-THETA)*ALPHA*P**2*(1+ALPHA/2)
!              p(3;THETA,P) = EXP(-THETA)*ALPHA*P**3*
!                             (1+ALPHA+ALPHA**2/6)
!              p(4;THETA,P) = EXP(-THETA)*ALPHA*P**4*
!                             (1+3*ALPHA/2+ALPHA**2/2+ALPHA**3/24)
!
!              FOR THE CDF, WE USE THE FOLLOWING RECURRENCE
!              RELATION (FROM JOHNSON, KOTZ AND KEMP):
!
!              p(X+1) = (THETA*(1-P)/(X+1))*SUM[J=1 TO X]
!                       [(X+1-J)*P**(X-J)*p(X)]
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --DTHETA = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --DP     = THE DOUBLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE DPPF FOR THE POLYA-AEPPLI DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= X < P.
!                 --0 < P < 1,  AND THETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM, DCHU.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 378-382.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      REAL R1MACH
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DPPF=0.0D0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
               'PAPPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DTHETA.LE.0.0D0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'PAPPPF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DTHETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DX.LT.0.0D0 .OR. DX.GE.1.0D0)THEN
        WRITE(ICOUT,13)
   13   FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
               'PAPPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      IF(DX.LE.0.0D0)THEN
        DPPF=0.0D0
        GO TO 9999
      ENDIF
!
      DQ=1.0D0 - DP
      DALPHA=DTHETA*DQ/DP
      DEPS=1.0D-7
!
      DPDFS2=DEXP(-DTHETA)
      IF(DPDFS2.GE.DX-DEPS)THEN
        DPPF=0.0D0
        GO TO 9999
      ENDIF
      DTERM1=-DTHETA + DLOG(DALPHA) + DLOG(DP)
      DPDFS1=DEXP(DTERM1)
      DCDF=DPDFS1+DPDFS2
      IF(DCDF.GE.DX-DEPS)THEN
        DPPF=1.0D0
        GO TO 9999
      ENDIF
      I=1
!
  100 CONTINUE
!
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          DPPF=0.0
          GO TO 9999
        ENDIF
!
        IF(I.EQ.2)THEN
          DTERM1=-DTHETA + DLOG(DALPHA) + 2.0D0*DLOG(DP) +   &
                 DLOG(1.0D0 + DALPHA/2.0D0)
          DPDF=DEXP(DTERM1)
        ELSEIF(I.EQ.3)THEN
          DTERM1=-DTHETA + DLOG(DALPHA) + 3.0D0*DLOG(DP) +   &
                 DLOG(1.0D0 + DALPHA + DALPHA**2/6.0D0)
          DPDF=DEXP(DTERM1)
        ELSEIF(I.EQ.4)THEN
          DTERM1=-DTHETA + DLOG(DALPHA) + 4.0D0*DLOG(DP) +   &
                 DLOG(1.0D0 + 1.5D0*DALPHA + 0.5D0*DALPHA**2   &
                 + DALPHA**3/24.0D0)
          DPDF=DEXP(DTERM1)
        ELSE
          DTERM1=(1.0D0/DBLE(I))
          DTERM2=(DTHETA*DQ + 2.0D0*DP*DBLE(I-1))*DPDFS1
          DTERM3=DP**2*DBLE(I-2)*DPDFS2
          DPDF=DTERM1*(DTERM2 - DTERM3)
        ENDIF
        DCDF=DCDF + DPDF
        DPDFS2=DPDFS1
        DPDFS1=DPDF
        IF(DCDF.GE.DX-DEPS)THEN
          DPPF=DBLE(I)
          GO TO 9999
        ENDIF
      GO TO 100
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PAPPPF
      SUBROUTINE PAPRAN(N,THETA,P,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE POLYA-AEPPLI DISTRIBUTION
!              WITH SHAPE PARAMETERS THETA AND P.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= 0.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;THETA,P) = EXP(-THETA)*(THETA*(1-P)/P)*P**X*
!                             CHU(X+1;2,THETA*(1-P)/P)
!                           = EXP(-THETA)*P**X*
!                             SUM[J=1 to X][(X-1  J-1)*
!                             (THETA*(1-P)/P)**J/J!
!                             X = 1, 2, ....
!
!              p(0;THETA,P) = EXP(-THETA)
!
!              CHU = THE CONFLUENT HYPERGEOMETRIC FUNTION 1F1.
!
!              JOHNSON, KOTZ, AND KEMP GIVE THE FOLLOWING
!              FORMULAS FOR X = 1, ..., 4 (ALPHA=THETA*(1-P)/P):
!
!
!              p(1;THETA,P) = EXP(-THETA)*
!              p(2;THETA,P) = EXP(-THETA)*ALPHA*P**2*(1+ALPHA/2)
!              p(2;THETA,P) = EXP(-THETA)*ALPHA*P**2*(1+ALPHA/2)
!              p(3;THETA,P) = EXP(-THETA)*ALPHA*P**3*
!                             (1+ALPHA+ALPHA**2/6)
!              p(4;THETA,P) = EXP(-THETA)*ALPHA*P**4*
!                             (1+3*ALPHA/2+ALPHA**2/2+ALPHA**3/24)
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --THETA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE POLYA-AEPPLI DISTRIBUTION
!             WITH SHAPE PARAMETERS THETA AND P.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 < P < 1, THETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 378-382.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
!-------------------------------------------------------------------
!
      REAL THETA
      REAL P
      DIMENSION X(*)
!
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DP
      DOUBLE PRECISION DTEMP
      DOUBLE PRECISION DPPF
!
!-----COMMON--------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT---------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
      'POLYA-AEPPLI RANDOM NUMBERS IS NON-POSITIVE')
!
      IF(P.LE.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE P SHAPE PARAMETER FOR POLYA-AEPPLI ')
   12 FORMAT('      RANDOM NUMBERS IS OUTSIDE THE ALLOWABLE (0,1) ',   &
             'INTERVAL')
!
      IF(THETA.LE.0.0)THEN
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   21 FORMAT('***** ERROR--THE THETA SHAPE PARAMETER FOR ',   &
             'POLYA-AEPPLI')
   22 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
! 100 CONTINUE
!
      CALL UNIRAN(N,ISEED,X)
      DTHETA=DBLE(THETA)
      DP=DBLE(P)
!
      DO 100 I=1,N
        DTEMP=DBLE(X(I))
        CALL PAPPPF(DTEMP,DTHETA,DP,DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE PAPRAN
      SUBROUTINE PARALI (X1,Y1,X2,Y2,X3,Y3,   &
                         X4,Y4,   &
                         IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--GIVEN A LINE DEFINED BY THE TWO POINTS (X1,Y1) AND
!              (X2,Y2) AND THE POINT (X3,Y3), FIND THE LINE
!              PARALLEL TO THE FIRST LINE AND CONTAINING (X3,Y3).
!              THAT IS, FIND THE COORDINATES FOR A SECOND POINT
!              ON THIS PARALLEL LINE.  THIS IS BASICALLY A
!              UTILITY ROUTINE SINCE THE SECOND LINE NEEDS TO
!              CALL ROUTINES BASED ON THE LINE AS DEFINED BY
!              TWO POINTS (RATHER THAN ONE POINT AND THE SLOPE).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.10
!     ORIGINAL VERSION--OCTOBER   2012.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      REAL X1
      REAL Y1
      REAL X2
      REAL Y2
      REAL X3
      REAL Y3
      REAL X4
      REAL Y4
      REAL S
      REAL YINT
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RALI')THEN
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGININNING OF PARALI')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)X1,Y1,X2,Y2,X3,Y3
   53   FORMAT('X1,Y1,X2,Y2,X3,Y3 = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IERROR='NO'
      XADD=(X1+X2)/2.0
      IF(ABS(XADD).LT.1.0)XADD=1.0
      YADD=(Y1+Y2)/2.0
      IF(ABS(YADD).LT.1.0)YADD=1.0
!
      IF(Y1.EQ.Y2)THEN
        X4=X3+XADD
        Y4=Y3
      ELSEIF(X1.EQ.X2)THEN
        X4=X3
        Y4=Y3+YADD
      ELSE
        S=(Y2-Y1)/(X2-X1)
        YINT=Y3 - S*X3
        X4=X3+XADD
        Y4=S*X4 + YINT
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TLIN')THEN
        WRITE(ICOUT,9051)
 9051   FORMAT('AT THE END OF INTLIN')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9053)XOUT,YOUT
 9053   FORMAT('X3(I),Y3(I) = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PARALI 
      SUBROUTINE PARCHI(IHP,IHP2,IDIST,   &
      IPAR,ILOWLM,IUPPLM,LOWLTY,UPPLTY,   &
      ISUBN1,ISUBN2,IERROR)
!
!     PURPOSE--CHECK TO SEE IF A (INTEGER) PARAMETER IS IN
!              A SPECIFIED RANGE.  UTILITY ROUTINE FOR
!              PROBABILITY PLOT, LAHEY COMPILER HAD TROUBLE
!              COMPILING DPPP.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/8
!     ORIGINAL VERSION--AUGUST    1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
!
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 LOWLTY
      CHARACTER*4 UPPLTY
      CHARACTER*30 IDIST
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!               ************************************
!               **  STEP 1--                      **
!               **  CHECK FOR GAMMA DISTRIBUTION  **
!               **  PARAMETER GAMMA               **
!               ************************************
!
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IPAR=INT(VALUE(ILOCP)+0.5)
!
      IF(LOWLTY.EQ.'>   ')THEN
        IF(IPAR.GT.ILOWLM)GO TO 1590
      ELSEIF(LOWLTY.EQ.'>=  ')THEN
        IF(IPAR.GE.ILOWLM)GO TO 1590
      ENDIF
      WRITE(ICOUT,999)
  999 FORMAT(' ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1511)ISUBN1,ISUBN2
 1511 FORMAT('***** ERROR IN ',A4,A4,'--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1512)IHP,IHP2
 1512 FORMAT('      THE SPECIFIED SHAPE PARAMETER ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1513)IDIST
 1513 FORMAT('      FOR THE ',A30,' DISTRIBUTION')
      CALL DPWRST('XXX','BUG ')
      IF(LOWLTY.EQ.'>   ')THEN
        WRITE(ICOUT,1514)ILOWLM
 1514   FORMAT('      MUST BE STRICTLY LARGER THAN ',I10,';')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(LOWLTY.EQ.'>=  ')THEN
        WRITE(ICOUT,1524)ILOWLM
 1524   FORMAT('      MUST BE LARGER THAN OR EQUAL TO ',I10,';')
        CALL DPWRST('XXX','BUG ')
      ENDIF
