      SUBROUTINE PARCDF(X,GAMMA,A,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE PARETO
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA
!              AND LOCATION PARAMETER ALOC.
!              THE PARETO DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X GREATER THAN
!              OR EQUAL TO A,
!              AND HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!              F(X) = 1 - (A/X)**GAMMA
!
!              NOTE THAT ALTHOUGH A IS COMMONLY REFERRED TO AS A
!              LOCATION PARAMETER, IT IS NOT IN THE TECHNICAL
!              SENSE OF
!
!                 f(X;A) = f(X-A),0)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO ALOC.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                ALOC SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE PARETO
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA
!             AND LOCATION PARAMETER A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA AND A SHOULD BE POSITIVE.
!                 --X SHOULD BE GREATER THAN
!                   OR EQUAL TO A.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 233-249.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 102.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.A)THEN
        WRITE(ICOUT,4)A
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PARCDF IS LESS THAN ',   &
             'THE LOCATION PARAMETER ',G15.7)
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PARCDF (THE SHAPE ',   &
             'PARAMETER) IS NON-POSITIVE')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO PARCDF (THE ',   &
             'LOCATION PARAMETER) IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      CDF=1.0-(A/X)**GAMMA
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PARCDF
      DOUBLE PRECISION FUNCTION PARFUN(AHAT,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MODIFIED
!              MAXIMUM LIKELIHOOD ESTIMATE OF THE THRESHOLD PARAMETER
!              OF THE PARETO DISTRIBUTION.  THIS FUNCTION FINDS THE ROOT
!              OF THE EQUATION:
!
!              N*(XMIN - AHAT)/XMIN -
!              (1/N)*SUM[i=1 to N][LOG(X(i)/AHAT) = 0
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--PARETO MAXIMUM LIKELIHOOD Y
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 11.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY       2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION AHAT
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION DXBAR
      DOUBLE PRECISION DXMIN
      COMMON/PARCOM/DXBAR,DXMIN,N
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DN=DBLE(N)
      DTERM1=DN*(DXMIN - AHAT)/DXMIN
      DSUM1=0.0D0
      DO 100 I=1,N
        DX=X(I)/AHAT
        DSUM1=DSUM1 + DLOG(DX)
  100 CONTINUE
!
      PARFUN=DTERM1 - DSUM1/DN
!
      RETURN
      END FUNCTION PARFUN
      SUBROUTINE PARCHA(X,GAMMA,A,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE PARETO
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA
!              AND LOCATION PARAMETER = A.
!              THE PARETO DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X GREATER THAN
!              OR EQUAL TO A,
!              AND HAS THE CUMULATIVE HAZARD FUNCTION
!              H(X) = GAMMA*LOG(X/A)
!
!              NOTE THAT ALTHOUGH A IS COMMONLY REFERRED TO AS A
!              LOCATION PARAMETER, IT IS NOT IN THE TECHNICAL
!              SENSE OF
!
!                 f(X;A) = f(X-A),0)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO ALOC.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                ALOC SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION
!                                CUMULATIVE HAZARD FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE FOR THE PARETO
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA
!             AND LOCATION PARAMETER A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE GREATER THAN
!                   OR EQUAL TO A.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, CHAPTER 20
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 102.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      IF(X.LT.A)THEN
        WRITE(ICOUT,4)A
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PARCHAZ IS LESS THAN ',   &
             'THE LOCATION PARAMETER ',G15.7)
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PARCHAZ (THE SHAPE ',   &
             'PARAMETER) IS NON-POSITIVE')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO PARCHAZ (THE ',   &
             'LOCATION PARAMETER) IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      HAZ=GAMMA*LOG(X/A)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PARCHA
      SUBROUTINE PARHAZ(X,GAMMA,A,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE PARETO
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA
!              AND LOCATION PARAMETER = A.
!              THE PARETO DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X GREATER THAN
!              OR EQUAL TO A, AND HAS THE HAZARD FUNCTION
!              H(X) = GAMMA / X
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO ALOC.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
