      END SUBROUTINE PARHAZ
      SUBROUTINE PARLI1(Y,N,   &
                        THRESH,SHAPE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE PARETO DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 10.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PARL'
      ISUBN2='I1  '
!
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF PARLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SHAPE
   55   FORMAT('N,ALOC,SHAPE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     THE LOG-LIKELIHOOD FUNCTION IS (G IS THE SHAPE
!     PARAMETER AND A IS THE LOCATION PARAMETER, THE
!     PARETO TYPICALLY NOT USED WITH A SCALE PARAMETER).
!
!     N*LOG(G) + N*G*LOG(A) -
!     SUM[i=1 to N][(G+1)*LOG(X(i))]
!
      DN=DBLE(N)
      DG=DBLE(SHAPE)
      DA=DBLE(THRESH)
      DTERM1=DN*DLOG(DG) + DN*DG*DLOG(DA)
      DSUM1=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + (DG+1.0D0)*DLOG(DX)
 1000 CONTINUE
      DLIK=DTERM1 - DSUM1
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF PARLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE PARLI1
      SUBROUTINE PARML1(Y,N,   &
                        DTEMP1,   &
                        XMEAN,XSD,XMIN,XMAX,   &
                        AMOM,SHAPMO,   &
                        AMM,SHAPMM,   &
                        AML,SHAPML,AMLSE,SHAPSE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE PARETO DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).
!
!              THIS WILL RETURN MOMENT, MODIFIED MOMENT, AND MODIFIED
!              MAXIMUM LIKELIHOOD ESTIMATES.  THE MODIFIED MAXIMUM
!              LIKLIHOOD ESTIMATES USE THE MODIFIED MOMENT ESTIMATE
!              FOR THE THRESHOLD AND THEN THE STANDARD MAXIMUM LIKELIHOOD
!              ESTIMATE FOR THE SHAPE PARAMETER (THE STANDARD ML
!              ESTIMATES HAVE REGULARITY PROBLEMS WHEN THE THRESHOLD
!              PARAMETER IS UNKNOWN).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLPA WILL GENERATE THE OUTPUT
!              FOR THE PARETO MLE COMMAND).
!
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 11.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLPA)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
!
      DOUBLE PRECISION PARFUN
      EXTERNAL PARFUN
!
      INTEGER IN
      DOUBLE PRECISION DXBAR
      DOUBLE PRECISION DXMIN
      COMMON/PARCOM/DXBAR,DXMIN,IN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PARM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF PARML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR PARETO MLE ESTIMATE               **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='PARETO'
      IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     MOMENT ESTIMATES:
!
!       GAMMAHAT = 1 + SQRT(1 + (XBAR/S)**2)
!       AHAT     = XBAR*(GAMMAHAT - 1)/GAMMAHAT
!
      SHAPMO=1.0 + SQRT(1.0 + (XMEAN/XSD)**2)
      AMOM=XMEAN*(SHAPMO - 1.0)/SHAPMO
      IF(AMOM.GT.XMIN)THEN
        AMOM=CPUMIN
        SHAPMO=CPUMIN
      ENDIF
!
!     MODIFIED MOMENT ESTIMATES:
!
!        GAMMAHAT = (N*XBAR - XMIN)/(N*(XBAR - XMIN))
!        AHAT     = (N-1)*XMIN*XBAR/(N*XBAR - XMIN)
!
      AN=REAL(N)
      SHAPMM=(AN*XMEAN - XMIN)/(AN*(XMEAN - XMIN))
      AMM=(AN-1.0)*XMIN*XMEAN/(N*XMEAN - XMIN)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')THEN
        WRITE(ICOUT,1055)N,XMEAN,XSD,XMIN,XMAX
 1055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,6G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1057)AMOM,SHAPMO,AMM,SHAPMM
 1057   FORMAT('AMOM,SHAPMO,AMM,SHAPMM = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!     MODIFIED MAXIMUM LIKELIHOOD ESTIMATES:
!
!     ITERATIVELY SOLVE FOR THE THRESHOLD PARAMETER:
!
!        N*(XMIN - AHAT)/XMIN - (1/N)*SUM[i=1 to N][LOG(X(i)/AHAT) = 0
!
!     THEN
!
!        GAMMAHAT = N/SUM[i=1 to N][LOG(X(i)/AHAT)]
!
!
      DXBAR=DBLE(XMEAN)
      DXMIN=DBLE(XMIN)
      IN=N
      DO 2010 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 2010 CONTINUE
!
      DEPS=1.0D-12
      DXSTRT=DBLE(AMM)
      DAE=2.0*0.000001D0*DXSTRT
      DRE=DAE
      IFLAG=0
!CCCC DXLOW=0.0D0
!CCCC DXLOW=DEPS
      DXLOW=DXSTRT/2.0D0
      DXUP=DBLE(XMIN) - DEPS
      ITBRAC=0
      CALL DFZER2(PARFUN,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
!
      IF(IFLAG.EQ.2)THEN
!
!       NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM PARETO MAXIMUM ',
!CCCC1         'LIKELIHOOD--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      ESTIMATE OF THRESHOLD MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM PARETO MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ESTIMATE OF THRESHOLD MAY BE NEAR A ',   &
               'SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM PARETO MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      AML=REAL(DXLOW)
!
      DSUM=0.0D0
      DO 4110 I=1,N
        DTERM1=DBLE(LOG(Y(I)/DBLE(AML)))
        DSUM=DSUM + DTERM1
 4110 CONTINUE
      GAMMA=REAL(DSUM)/AN
      SHAPML=1.0/GAMMA
!
      AN=REAL(N)
      SHAPSE=CPUMIN
      AMLSE=CPUMIN
      IF(N.GT.3)THEN
        TERM1=(AN**2)*(SHAPML**2)/((AN-2.0)**2*(AN-3.0))
        SHAPSE=SQRT(TERM1)
      ENDIF
      IF(AN.GT.2.0/SHAPML)THEN
        AMLSE=(AML/(AN*SHAPML - 1.0))*SQRT(AN*SHAPML/(AN*SHAPML - 2.0))
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF PARML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9058)AML,SHAPML,AMLSE,SHAPSE
 9058   FORMAT('AML,SHAPML,AMLSE,SHAPSE = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE PARML1
      SUBROUTINE PARPDF(X,GAMMA,A,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE PARETO
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE PARETO DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X GREATER THAN
!              OR EQUAL TO A,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA*A**GAMMA/(X**(GAMMA+1))  X >= A.
!                                                    A, GAMMA > 0
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO ALOC.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                ALOC SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE PARETO
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA
!             AND LOCATION PARAMETER A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE GREATER THAN OR EQUAL TO A.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 233-249.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 102.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.A)THEN
        WRITE(ICOUT,4)A
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PARPDF IS LESS THAN ',   &
             'THE LOCATION PARAMETER ',G15.7)
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT (THE SHAPE PARAMETER) ',   &
             'TO PARPDF IS NON-POSITIVE')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO PARPDF (THE ',   &
             'LOCATION PARAMETER) IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      PDF=GAMMA*A**GAMMA/(X**(GAMMA+1.0))
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PARPDF
      SUBROUTINE PARPPF(P,GAMMA,A,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE PARETO
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA
!              AND LOCATION PARAMETER = A.
!              THE PARETO DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X GREATER THAN
!              OR EQUAL TO A,
!              AND HAS THE PERCENT POINT FUNCTION
!              G(P) = A*(1.0-P)**(-1.0/GAMMA)
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!
!              NOTE THAT ALTHOUGH A IS COMMONLY REFERRED TO AS A
!              LOCATION PARAMETER, IT IS NOT IN THE TECHNICAL
!              SENSE OF
!
!                 f(X;A) = f(X-A),0)
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                A SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE PARETO DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA AND A SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 233-249.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 102.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PARPPF IS OUTSIDE ',   &
             'THE ALLOWABLE [0,1) INTERVAL')
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PARPPF (THE SHAPE ',   &
             'PARAMETER) IS NON-POSITIVE')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO PARPPF (THE ',   &
             'LOCATION PARAMETER) IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      PPF=A*(1.0-P)**(-1.0/GAMMA)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PARPPF
      SUBROUTINE PARRAN(N,GAMMA,A,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE PARETO DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!              THE PROTOTYPE PARETO DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X GREATER THAN
!              OR EQUAL TO 1,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA*A**GAMMA/(X**(GAMMA+1)).
!
!              NOTE THAT ALTHOUGH A IS COMMONLY REFERRED TO AS A
!              LOCATION PARAMETER, IT IS NOT IN THE TECHNICAL
!              SENSE OF
!
!                 f(X;A) = f(X-A),0)
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                A SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE PARETO DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA
!             LOCATION PARAMETER VALUE = A
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA AND A SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 233-249.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 104.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,26)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF PARETO RANDOM ',   &
      'NUMBERS IS NON-POSITIVE ******')
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE PARPDF ',   &
             'SUBROUTINE')
   16 FORMAT('      (THE SHAPE PARAMETER) IS NON-POSITIVE *****')
   25 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE PARPDF ',   &
             'SUBROUTINE')
   26 FORMAT('      (THE LOCATION PARAMETER) IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N PARETO DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      X(I)=A*(1.0-X(I))**(-1.0/GAMMA)
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PARRAN
      SUBROUTINE PA2CDF(X,GAMMA,A,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE PARETO TYPE II
!              DISTRIBUTION WITH SINGLE PRECISION TAIL LENGTH
!              PARAMETER = GAMMA AND LOCATION PARAMETER = A.
!              THE PARETO DISTRIBUTION USED HEREIN IS DEFINED FOR
!              ALL X GREATER THAN OR EQUAL TO 0,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA*A**GAMMA/(X+A)**(GAMMA+1)
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!              F(X) = 1 - A**GAMMA/(X+A)**GAMMA
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO 1.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                A SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE PARETO
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA
!             AND LOCATION PARAMETER A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA AND A SHOULD BE POSITIVE.
!                 --X SHOULD BE GREATER THAN
!                   OR EQUAL TO 0.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, CHAPTER 20
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--CHAPTER 30
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DA
      DOUBLE PRECISION DG
      DOUBLE PRECISION DX
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE PA2CDF ',   &
             'SUBROUTINE IS NEGATIVE.')
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE PA2CDF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE PA2CDF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DA=DBLE(A)
      DG=DBLE(GAMMA)
      DX=DBLE(X)
      DCDF=1.0D0 - DA**DG/((DX+DA)**DG)
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PA2CDF
      SUBROUTINE PA2PDF(X,GAMMA,A,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE PARETO DISTRIBUTION OF THE
!              SECOND KIND WITH SINGLE PRECISION TAIL LENGTH
!              PARAMETER = GAMMA AND LOCATION PARAMETER A.
!              THE PARETO DISTRIBUTION USED HEREIN IS DEFINED FOR
!              ALL X GREATER THAN OR EQUAL TO 0,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA*A**GAMMA/(X+A)**(GAMMA+1)
!
!              NOTE THAT ALTHOUGH A IS COMMONLY REFERRED TO AS A
!              LOCATION PARAMETER, IT IS NOT IN THE TECHNICAL
!              SENSE OF
!
!                 f(X;A) = f(X-A),0)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO 1.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                A SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE PARETO
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA
!             AND LOCATION PARAMETER A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA AND A SHOULD BE POSITIVE.
!                 --X SHOULD BE GREATER THAN OR EQUAL TO 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, CHAPTER 20
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--CHAPTER 30
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE PA2PDF ',   &
             'SUBROUTINE IS NEGATIVE.')
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE PA2PDF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE PA2PDF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DG=DBLE(GAMMA)
      DA=DBLE(A)
      DTERM1=DLOG(DG) + DG*DLOG(DA) - (DG+1.0D0)*DLOG(DX+DA)
      DPDF=DEXP(DTERM1)
      PDF=SNGL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PA2PDF
      SUBROUTINE PA2PPF(P,GAMMA,A,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION
!              VALUE FOR THE PARETO DISTRIBUTION OF THE SECOND KIND
!              WITH SINGLE PRECISION TAIL LENGTH PARAMETER = GAMMA
!              AND LOCATION PARAMETER A.
!              THE PARETO DISTRIBUTION USED HEREIN IS DEFINED FOR
!              ALL X GREATER THAN OR EQUAL TO 0,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA*A**GAMMA/(X+A)**(GAMMA+1)
!
!              THE PERCENT POINT FUNCTION IS
!
!              G(P) = (A**GAMMA/(1-P))**(1/GAMMA) - A
!
!              NOTE THAT ALTHOUGH A IS COMMONLY REFERRED TO AS A
!              LOCATION PARAMETER, IT IS NOT IN THE TECHNICAL
!              SENSE OF
!
!                 f(X;A) = f(X-A),0)
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                A SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE PARETO DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA AND LOCATION
!             PARAMETER = A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA AND A SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, CHAPTER 20
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--CHAPTER 30
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DA
      DOUBLE PRECISION DG
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE PA2PPF ',   &
             'SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE PA2PPF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE PA2PPF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      IF(P.LE.0.0)THEN
        PPF=0.0
      ELSE
        DP=DBLE(P)
        DA=DBLE(A)
        DG=DBLE(GAMMA)
        DPPF=(DA**DG/(1.0D0-DP))**(1.0D0/DG) - DA
        PPF=REAL(DPPF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PA2PPF
      SUBROUTINE PA2RAN(N,GAMMA,A,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE PARETO DISTRIBUTION OF THE SECOND KIND
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA AND
!              LOCATION PARAMETER A.
!              THE PARETO DISTRIBUTION USED HEREIN IS DEFINED FOR
!              ALL X GREATER THAN OR EQUAL TO 0,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA*A**GAMMA/(X+A)**(GAMMA+1)
!
!              NOTE THAT ALTHOUGH A IS COMMONLY REFERRED TO AS A
!              LOCATION PARAMETER, IT IS NOT IN THE TECHNICAL
!              SENSE OF
!
!                 f(X;A) = f(X-A),0)
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE LOCATION PARAMETER.
!                                A SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE PARETO DISTRIBUTION OF THE SECOND KIND
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA AND
!             LOCATION PARAMETER A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --JOHNSON, KOTZ, AND BALAKRISHNAN, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994.
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2003.6
!     ORIGINAL VERSION--JUNE      2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE NUMBER OF REQUESTED PARETO SECOND ',   &
      'KIND RANDOM NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SHAPE PARAMETER FOR THE PARETO ',   &
      'SECOND KIND RANDOM NUMBERS IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE LOCATION PARAMETER FOR THE PARETO ',   &
      'SECOND KIND RANDOM NUMBERS IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N PARETO SECOND KIND DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL PA2PPF(X(I),GAMMA,A,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PA2RAN
      SUBROUTINE PASSB(NAC,IDO,IP,L1,IDL1,CC,C1,C2,CH,CH2,WA)
!***BEGIN PROLOGUE  PASSB
!***REFER TO  CFFTB
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSB
      DIMENSION       CH(IDO,L1,IP)          ,CC(IDO,IP,L1)          ,   &
                      C1(IDO,L1,IP)          ,WA(*)      ,C2(IDL1,IP),   &
                      CH2(IDL1,IP)
!***FIRST EXECUTABLE STATEMENT  PASSB
      IDOT = IDO/2
      IPP2 = IP+2
      IPPH = (IP+1)/2
      IDP = IP*IDO
!
      IF (IDO .LT. L1) GO TO 106
      DO 103 J=2,IPPH
         JC = IPP2-J
         DO 102 K=1,L1
!DIR$ IVDEP
            DO 101 I=1,IDO
               CH(I,K,J) = CC(I,J,K)+CC(I,JC,K)
               CH(I,K,JC) = CC(I,J,K)-CC(I,JC,K)
  101       CONTINUE
  102    CONTINUE
  103 CONTINUE
      DO 105 K=1,L1
!DIR$ IVDEP
         DO 104 I=1,IDO
            CH(I,K,1) = CC(I,1,K)
  104    CONTINUE
  105 CONTINUE
      GO TO 112
  106 DO 109 J=2,IPPH
         JC = IPP2-J
         DO 108 I=1,IDO
!DIR$ IVDEP
            DO 107 K=1,L1
               CH(I,K,J) = CC(I,J,K)+CC(I,JC,K)
               CH(I,K,JC) = CC(I,J,K)-CC(I,JC,K)
  107       CONTINUE
  108    CONTINUE
  109 CONTINUE
      DO 111 I=1,IDO
!DIR$ IVDEP
         DO 110 K=1,L1
            CH(I,K,1) = CC(I,1,K)
  110    CONTINUE
  111 CONTINUE
  112 IDL = 2-IDO
      INC = 0
      DO 116 L=2,IPPH
         LC = IPP2-L
         IDL = IDL+IDO
!DIR$ IVDEP
         DO 113 IK=1,IDL1
            C2(IK,L) = CH2(IK,1)+WA(IDL-1)*CH2(IK,2)
            C2(IK,LC) = WA(IDL)*CH2(IK,IP)
  113    CONTINUE
         IDLJ = IDL
         INC = INC+IDO
         DO 115 J=3,IPPH
            JC = IPP2-J
            IDLJ = IDLJ+INC
            IF (IDLJ .GT. IDP) IDLJ = IDLJ-IDP
            WAR = WA(IDLJ-1)
            WAI = WA(IDLJ)
!DIR$ IVDEP
            DO 114 IK=1,IDL1
               C2(IK,L) = C2(IK,L)+WAR*CH2(IK,J)
               C2(IK,LC) = C2(IK,LC)+WAI*CH2(IK,JC)
  114       CONTINUE
  115    CONTINUE
  116 CONTINUE
      DO 118 J=2,IPPH
!DIR$ IVDEP
         DO 117 IK=1,IDL1
            CH2(IK,1) = CH2(IK,1)+CH2(IK,J)
  117    CONTINUE
  118 CONTINUE
      DO 120 J=2,IPPH
         JC = IPP2-J
!DIR$ IVDEP
         DO 119 IK=2,IDL1,2
            CH2(IK-1,J) = C2(IK-1,J)-C2(IK,JC)
            CH2(IK-1,JC) = C2(IK-1,J)+C2(IK,JC)
            CH2(IK,J) = C2(IK,J)+C2(IK-1,JC)
            CH2(IK,JC) = C2(IK,J)-C2(IK-1,JC)
  119    CONTINUE
  120 CONTINUE
      NAC = 1
      IF (IDO .EQ. 2) RETURN
      NAC = 0
      DO 121 IK=1,IDL1
         C2(IK,1) = CH2(IK,1)
  121 CONTINUE
      DO 123 J=2,IP
!DIR$ IVDEP
         DO 122 K=1,L1
            C1(1,K,J) = CH(1,K,J)
            C1(2,K,J) = CH(2,K,J)
  122    CONTINUE
  123 CONTINUE
      IF (IDOT .GT. L1) GO TO 127
      IDIJ = 0
      DO 126 J=2,IP
         IDIJ = IDIJ+2
         DO 125 I=4,IDO,2
            IDIJ = IDIJ+2
!DIR$ IVDEP
            DO 124 K=1,L1
               C1(I-1,K,J) = WA(IDIJ-1)*CH(I-1,K,J)-WA(IDIJ)*CH(I,K,J)
               C1(I,K,J) = WA(IDIJ-1)*CH(I,K,J)+WA(IDIJ)*CH(I-1,K,J)
  124       CONTINUE
  125    CONTINUE
  126 CONTINUE
      RETURN
  127 IDJ = 2-IDO
      DO 130 J=2,IP
         IDJ = IDJ+IDO
         DO 129 K=1,L1
            IDIJ = IDJ
!DIR$ IVDEP
            DO 128 I=4,IDO,2
               IDIJ = IDIJ+2
               C1(I-1,K,J) = WA(IDIJ-1)*CH(I-1,K,J)-WA(IDIJ)*CH(I,K,J)
               C1(I,K,J) = WA(IDIJ-1)*CH(I,K,J)+WA(IDIJ)*CH(I-1,K,J)
  128       CONTINUE
  129    CONTINUE
  130 CONTINUE
      RETURN
      END SUBROUTINE PASSB
      SUBROUTINE PASSB2(IDO,L1,CC,CH,WA1)
!***BEGIN PROLOGUE  PASSB2
!***REFER TO  CFFTB
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSB2
      DIMENSION       CC(IDO,2,L1)           ,CH(IDO,L1,2)           ,   &
                      WA1(*)
!***FIRST EXECUTABLE STATEMENT  PASSB2
      IF (IDO .GT. 2) GO TO 102
      DO 101 K=1,L1
         CH(1,K,1) = CC(1,1,K)+CC(1,2,K)
         CH(1,K,2) = CC(1,1,K)-CC(1,2,K)
         CH(2,K,1) = CC(2,1,K)+CC(2,2,K)
         CH(2,K,2) = CC(2,1,K)-CC(2,2,K)
  101 CONTINUE
      RETURN
  102 IF(IDO/2.LT.L1) GO TO 105
      DO 104 K=1,L1
!DIR$ IVDEP
         DO 103 I=2,IDO,2
            CH(I-1,K,1) = CC(I-1,1,K)+CC(I-1,2,K)
            TR2 = CC(I-1,1,K)-CC(I-1,2,K)
            CH(I,K,1) = CC(I,1,K)+CC(I,2,K)
            TI2 = CC(I,1,K)-CC(I,2,K)
            CH(I,K,2) = WA1(I-1)*TI2+WA1(I)*TR2
            CH(I-1,K,2) = WA1(I-1)*TR2-WA1(I)*TI2
  103    CONTINUE
  104 CONTINUE
      RETURN
  105 DO 107 I=2,IDO,2
!DIR$ IVDEP
         DO 106 K=1,L1
            CH(I-1,K,1) = CC(I-1,1,K)+CC(I-1,2,K)
            TR2 = CC(I-1,1,K)-CC(I-1,2,K)
            CH(I,K,1) = CC(I,1,K)+CC(I,2,K)
            TI2 = CC(I,1,K)-CC(I,2,K)
            CH(I,K,2) = WA1(I-1)*TI2+WA1(I)*TR2
            CH(I-1,K,2) = WA1(I-1)*TR2-WA1(I)*TI2
  106    CONTINUE
  107 CONTINUE
      RETURN
      END SUBROUTINE PASSB2
      SUBROUTINE PASSB3(IDO,L1,CC,CH,WA1,WA2)
!***BEGIN PROLOGUE  PASSB3
!***REFER TO  CFFTB
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSB3
      DIMENSION       CC(IDO,3,L1)           ,CH(IDO,L1,3)           ,   &
                      WA1(*)     ,WA2(*)
!***FIRST EXECUTABLE STATEMENT  PASSB3
      TAUR = -.5
      TAUI = .5*SQRT(3.)
      IF (IDO .NE. 2) GO TO 102
      DO 101 K=1,L1
         TR2 = CC(1,2,K)+CC(1,3,K)
         CR2 = CC(1,1,K)+TAUR*TR2
         CH(1,K,1) = CC(1,1,K)+TR2
         TI2 = CC(2,2,K)+CC(2,3,K)
         CI2 = CC(2,1,K)+TAUR*TI2
         CH(2,K,1) = CC(2,1,K)+TI2
         CR3 = TAUI*(CC(1,2,K)-CC(1,3,K))
         CI3 = TAUI*(CC(2,2,K)-CC(2,3,K))
         CH(1,K,2) = CR2-CI3
         CH(1,K,3) = CR2+CI3
         CH(2,K,2) = CI2+CR3
         CH(2,K,3) = CI2-CR3
  101 CONTINUE
      RETURN
  102 IF(IDO/2.LT.L1) GO TO 105
      DO 104 K=1,L1
!DIR$ IVDEP
         DO 103 I=2,IDO,2
            TR2 = CC(I-1,2,K)+CC(I-1,3,K)
            CR2 = CC(I-1,1,K)+TAUR*TR2
            CH(I-1,K,1) = CC(I-1,1,K)+TR2
            TI2 = CC(I,2,K)+CC(I,3,K)
            CI2 = CC(I,1,K)+TAUR*TI2
            CH(I,K,1) = CC(I,1,K)+TI2
            CR3 = TAUI*(CC(I-1,2,K)-CC(I-1,3,K))
            CI3 = TAUI*(CC(I,2,K)-CC(I,3,K))
            DR2 = CR2-CI3
            DR3 = CR2+CI3
            DI2 = CI2+CR3
            DI3 = CI2-CR3
            CH(I,K,2) = WA1(I-1)*DI2+WA1(I)*DR2
            CH(I-1,K,2) = WA1(I-1)*DR2-WA1(I)*DI2
            CH(I,K,3) = WA2(I-1)*DI3+WA2(I)*DR3
            CH(I-1,K,3) = WA2(I-1)*DR3-WA2(I)*DI3
  103    CONTINUE
  104 CONTINUE
      RETURN
  105 DO 107 I=2,IDO,2
!DIR$ IVDEP
         DO 106 K=1,L1
            TR2 = CC(I-1,2,K)+CC(I-1,3,K)
            CR2 = CC(I-1,1,K)+TAUR*TR2
            CH(I-1,K,1) = CC(I-1,1,K)+TR2
            TI2 = CC(I,2,K)+CC(I,3,K)
            CI2 = CC(I,1,K)+TAUR*TI2
            CH(I,K,1) = CC(I,1,K)+TI2
            CR3 = TAUI*(CC(I-1,2,K)-CC(I-1,3,K))
            CI3 = TAUI*(CC(I,2,K)-CC(I,3,K))
            DR2 = CR2-CI3
            DR3 = CR2+CI3
            DI2 = CI2+CR3
            DI3 = CI2-CR3
            CH(I,K,2) = WA1(I-1)*DI2+WA1(I)*DR2
            CH(I-1,K,2) = WA1(I-1)*DR2-WA1(I)*DI2
            CH(I,K,3) = WA2(I-1)*DI3+WA2(I)*DR3
            CH(I-1,K,3) = WA2(I-1)*DR3-WA2(I)*DI3
  106    CONTINUE
  107 CONTINUE
      RETURN
      END SUBROUTINE PASSB3
      SUBROUTINE PASSB4(IDO,L1,CC,CH,WA1,WA2,WA3)
!***BEGIN PROLOGUE  PASSB4
!***REFER TO  CFFTB
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSB4
      DIMENSION       CC(IDO,4,L1)           ,CH(IDO,L1,4)           ,   &
                      WA1(*)     ,WA2(*)     ,WA3(*)
!***FIRST EXECUTABLE STATEMENT  PASSB4
      IF (IDO .NE. 2) GO TO 102
      DO 101 K=1,L1
         TI1 = CC(2,1,K)-CC(2,3,K)
         TI2 = CC(2,1,K)+CC(2,3,K)
         TR4 = CC(2,4,K)-CC(2,2,K)
         TI3 = CC(2,2,K)+CC(2,4,K)
         TR1 = CC(1,1,K)-CC(1,3,K)
         TR2 = CC(1,1,K)+CC(1,3,K)
         TI4 = CC(1,2,K)-CC(1,4,K)
         TR3 = CC(1,2,K)+CC(1,4,K)
         CH(1,K,1) = TR2+TR3
         CH(1,K,3) = TR2-TR3
         CH(2,K,1) = TI2+TI3
         CH(2,K,3) = TI2-TI3
         CH(1,K,2) = TR1+TR4
         CH(1,K,4) = TR1-TR4
         CH(2,K,2) = TI1+TI4
         CH(2,K,4) = TI1-TI4
  101 CONTINUE
      RETURN
  102 IF(IDO/2.LT.L1) GO TO 105
      DO 104 K=1,L1
!DIR$ IVDEP
         DO 103 I=2,IDO,2
            TI1 = CC(I,1,K)-CC(I,3,K)
            TI2 = CC(I,1,K)+CC(I,3,K)
            TI3 = CC(I,2,K)+CC(I,4,K)
            TR4 = CC(I,4,K)-CC(I,2,K)
            TR1 = CC(I-1,1,K)-CC(I-1,3,K)
            TR2 = CC(I-1,1,K)+CC(I-1,3,K)
            TI4 = CC(I-1,2,K)-CC(I-1,4,K)
            TR3 = CC(I-1,2,K)+CC(I-1,4,K)
            CH(I-1,K,1) = TR2+TR3
            CR3 = TR2-TR3
            CH(I,K,1) = TI2+TI3
            CI3 = TI2-TI3
            CR2 = TR1+TR4
            CR4 = TR1-TR4
            CI2 = TI1+TI4
            CI4 = TI1-TI4
            CH(I-1,K,2) = WA1(I-1)*CR2-WA1(I)*CI2
            CH(I,K,2) = WA1(I-1)*CI2+WA1(I)*CR2
            CH(I-1,K,3) = WA2(I-1)*CR3-WA2(I)*CI3
            CH(I,K,3) = WA2(I-1)*CI3+WA2(I)*CR3
            CH(I-1,K,4) = WA3(I-1)*CR4-WA3(I)*CI4
            CH(I,K,4) = WA3(I-1)*CI4+WA3(I)*CR4
  103    CONTINUE
  104 CONTINUE
      RETURN
  105 DO 107 I=2,IDO,2
!DIR$ IVDEP
         DO 106 K=1,L1
            TI1 = CC(I,1,K)-CC(I,3,K)
            TI2 = CC(I,1,K)+CC(I,3,K)
            TI3 = CC(I,2,K)+CC(I,4,K)
            TR4 = CC(I,4,K)-CC(I,2,K)
            TR1 = CC(I-1,1,K)-CC(I-1,3,K)
            TR2 = CC(I-1,1,K)+CC(I-1,3,K)
            TI4 = CC(I-1,2,K)-CC(I-1,4,K)
            TR3 = CC(I-1,2,K)+CC(I-1,4,K)
            CH(I-1,K,1) = TR2+TR3
            CR3 = TR2-TR3
            CH(I,K,1) = TI2+TI3
            CI3 = TI2-TI3
            CR2 = TR1+TR4
            CR4 = TR1-TR4
            CI2 = TI1+TI4
            CI4 = TI1-TI4
            CH(I-1,K,2) = WA1(I-1)*CR2-WA1(I)*CI2
            CH(I,K,2) = WA1(I-1)*CI2+WA1(I)*CR2
            CH(I-1,K,3) = WA2(I-1)*CR3-WA2(I)*CI3
            CH(I,K,3) = WA2(I-1)*CI3+WA2(I)*CR3
            CH(I-1,K,4) = WA3(I-1)*CR4-WA3(I)*CI4
            CH(I,K,4) = WA3(I-1)*CI4+WA3(I)*CR4
  106    CONTINUE
  107 CONTINUE
      RETURN
      END SUBROUTINE PASSB4
      SUBROUTINE PASSB5(IDO,L1,CC,CH,WA1,WA2,WA3,WA4)
!***BEGIN PROLOGUE  PASSB5
!***REFER TO  CFFTB
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSB5
      DIMENSION       CC(IDO,5,L1)           ,CH(IDO,L1,5)           ,   &
                      WA1(*)     ,WA2(*)     ,WA3(*)     ,WA4(*)
!***FIRST EXECUTABLE STATEMENT  PASSB5
      PI = 4.*ATAN(1.)
      TR11 = SIN(.1*PI)
      TI11 = SIN(.4*PI)
      TR12 = -SIN(.3*PI)
      TI12 = SIN(.2*PI)
      IF (IDO .NE. 2) GO TO 102
      DO 101 K=1,L1
         TI5 = CC(2,2,K)-CC(2,5,K)
         TI2 = CC(2,2,K)+CC(2,5,K)
         TI4 = CC(2,3,K)-CC(2,4,K)
         TI3 = CC(2,3,K)+CC(2,4,K)
         TR5 = CC(1,2,K)-CC(1,5,K)
         TR2 = CC(1,2,K)+CC(1,5,K)
         TR4 = CC(1,3,K)-CC(1,4,K)
         TR3 = CC(1,3,K)+CC(1,4,K)
         CH(1,K,1) = CC(1,1,K)+TR2+TR3
         CH(2,K,1) = CC(2,1,K)+TI2+TI3
         CR2 = CC(1,1,K)+TR11*TR2+TR12*TR3
         CI2 = CC(2,1,K)+TR11*TI2+TR12*TI3
         CR3 = CC(1,1,K)+TR12*TR2+TR11*TR3
         CI3 = CC(2,1,K)+TR12*TI2+TR11*TI3
         CR5 = TI11*TR5+TI12*TR4
         CI5 = TI11*TI5+TI12*TI4
         CR4 = TI12*TR5-TI11*TR4
         CI4 = TI12*TI5-TI11*TI4
         CH(1,K,2) = CR2-CI5
         CH(1,K,5) = CR2+CI5
         CH(2,K,2) = CI2+CR5
         CH(2,K,3) = CI3+CR4
         CH(1,K,3) = CR3-CI4
         CH(1,K,4) = CR3+CI4
         CH(2,K,4) = CI3-CR4
         CH(2,K,5) = CI2-CR5
  101 CONTINUE
      RETURN
  102 IF(IDO/2.LT.L1) GO TO 105
      DO 104 K=1,L1
!DIR$ IVDEP
         DO 103 I=2,IDO,2
            TI5 = CC(I,2,K)-CC(I,5,K)
            TI2 = CC(I,2,K)+CC(I,5,K)
            TI4 = CC(I,3,K)-CC(I,4,K)
            TI3 = CC(I,3,K)+CC(I,4,K)
            TR5 = CC(I-1,2,K)-CC(I-1,5,K)
            TR2 = CC(I-1,2,K)+CC(I-1,5,K)
            TR4 = CC(I-1,3,K)-CC(I-1,4,K)
            TR3 = CC(I-1,3,K)+CC(I-1,4,K)
            CH(I-1,K,1) = CC(I-1,1,K)+TR2+TR3
            CH(I,K,1) = CC(I,1,K)+TI2+TI3
            CR2 = CC(I-1,1,K)+TR11*TR2+TR12*TR3
            CI2 = CC(I,1,K)+TR11*TI2+TR12*TI3
            CR3 = CC(I-1,1,K)+TR12*TR2+TR11*TR3
            CI3 = CC(I,1,K)+TR12*TI2+TR11*TI3
            CR5 = TI11*TR5+TI12*TR4
            CI5 = TI11*TI5+TI12*TI4
            CR4 = TI12*TR5-TI11*TR4
            CI4 = TI12*TI5-TI11*TI4
            DR3 = CR3-CI4
            DR4 = CR3+CI4
            DI3 = CI3+CR4
            DI4 = CI3-CR4
            DR5 = CR2+CI5
            DR2 = CR2-CI5
            DI5 = CI2-CR5
            DI2 = CI2+CR5
            CH(I-1,K,2) = WA1(I-1)*DR2-WA1(I)*DI2
            CH(I,K,2) = WA1(I-1)*DI2+WA1(I)*DR2
            CH(I-1,K,3) = WA2(I-1)*DR3-WA2(I)*DI3
            CH(I,K,3) = WA2(I-1)*DI3+WA2(I)*DR3
            CH(I-1,K,4) = WA3(I-1)*DR4-WA3(I)*DI4
            CH(I,K,4) = WA3(I-1)*DI4+WA3(I)*DR4
            CH(I-1,K,5) = WA4(I-1)*DR5-WA4(I)*DI5
            CH(I,K,5) = WA4(I-1)*DI5+WA4(I)*DR5
  103    CONTINUE
  104 CONTINUE
      RETURN
  105 DO 107 I=2,IDO,2
!DIR$ IVDEP
         DO 106 K=1,L1
            TI5 = CC(I,2,K)-CC(I,5,K)
            TI2 = CC(I,2,K)+CC(I,5,K)
            TI4 = CC(I,3,K)-CC(I,4,K)
            TI3 = CC(I,3,K)+CC(I,4,K)
            TR5 = CC(I-1,2,K)-CC(I-1,5,K)
            TR2 = CC(I-1,2,K)+CC(I-1,5,K)
            TR4 = CC(I-1,3,K)-CC(I-1,4,K)
            TR3 = CC(I-1,3,K)+CC(I-1,4,K)
            CH(I-1,K,1) = CC(I-1,1,K)+TR2+TR3
            CH(I,K,1) = CC(I,1,K)+TI2+TI3
            CR2 = CC(I-1,1,K)+TR11*TR2+TR12*TR3
            CI2 = CC(I,1,K)+TR11*TI2+TR12*TI3
            CR3 = CC(I-1,1,K)+TR12*TR2+TR11*TR3
            CI3 = CC(I,1,K)+TR12*TI2+TR11*TI3
            CR5 = TI11*TR5+TI12*TR4
            CI5 = TI11*TI5+TI12*TI4
            CR4 = TI12*TR5-TI11*TR4
            CI4 = TI12*TI5-TI11*TI4
            DR3 = CR3-CI4
            DR4 = CR3+CI4
            DI3 = CI3+CR4
            DI4 = CI3-CR4
            DR5 = CR2+CI5
            DR2 = CR2-CI5
            DI5 = CI2-CR5
            DI2 = CI2+CR5
            CH(I-1,K,2) = WA1(I-1)*DR2-WA1(I)*DI2
            CH(I,K,2) = WA1(I-1)*DI2+WA1(I)*DR2
            CH(I-1,K,3) = WA2(I-1)*DR3-WA2(I)*DI3
            CH(I,K,3) = WA2(I-1)*DI3+WA2(I)*DR3
            CH(I-1,K,4) = WA3(I-1)*DR4-WA3(I)*DI4
            CH(I,K,4) = WA3(I-1)*DI4+WA3(I)*DR4
            CH(I-1,K,5) = WA4(I-1)*DR5-WA4(I)*DI5
            CH(I,K,5) = WA4(I-1)*DI5+WA4(I)*DR5
  106    CONTINUE
  107 CONTINUE
      RETURN
      END SUBROUTINE PASSB5
      SUBROUTINE PASSF(NAC,IDO,IP,L1,IDL1,CC,C1,C2,CH,CH2,WA)
!***BEGIN PROLOGUE  PASSF
!***REFER TO  CFFTF
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSF
      DIMENSION       CH(IDO,L1,IP)          ,CC(IDO,IP,L1)          ,   &
                      C1(IDO,L1,IP)          ,WA(*)      ,C2(IDL1,IP),   &
                      CH2(IDL1,IP)
!***FIRST EXECUTABLE STATEMENT  PASSF
      IDOT = IDO/2
      IPP2 = IP+2
      IPPH = (IP+1)/2
      IDP = IP*IDO
!
      IF (IDO .LT. L1) GO TO 106
      DO 103 J=2,IPPH
         JC = IPP2-J
         DO 102 K=1,L1
!DIR$ IVDEP
            DO 101 I=1,IDO
               CH(I,K,J) = CC(I,J,K)+CC(I,JC,K)
               CH(I,K,JC) = CC(I,J,K)-CC(I,JC,K)
  101       CONTINUE
  102    CONTINUE
  103 CONTINUE
      DO 105 K=1,L1
!DIR$ IVDEP
         DO 104 I=1,IDO
            CH(I,K,1) = CC(I,1,K)
  104    CONTINUE
  105 CONTINUE
      GO TO 112
  106 DO 109 J=2,IPPH
         JC = IPP2-J
         DO 108 I=1,IDO
!DIR$ IVDEP
            DO 107 K=1,L1
               CH(I,K,J) = CC(I,J,K)+CC(I,JC,K)
               CH(I,K,JC) = CC(I,J,K)-CC(I,JC,K)
  107       CONTINUE
  108    CONTINUE
  109 CONTINUE
      DO 111 I=1,IDO
!DIR$ IVDEP
         DO 110 K=1,L1
            CH(I,K,1) = CC(I,1,K)
  110    CONTINUE
  111 CONTINUE
  112 IDL = 2-IDO
      INC = 0
      DO 116 L=2,IPPH
         LC = IPP2-L
         IDL = IDL+IDO
!DIR$ IVDEP
         DO 113 IK=1,IDL1
            C2(IK,L) = CH2(IK,1)+WA(IDL-1)*CH2(IK,2)
            C2(IK,LC) = -WA(IDL)*CH2(IK,IP)
  113    CONTINUE
         IDLJ = IDL
         INC = INC+IDO
         DO 115 J=3,IPPH
            JC = IPP2-J
            IDLJ = IDLJ+INC
            IF (IDLJ .GT. IDP) IDLJ = IDLJ-IDP
            WAR = WA(IDLJ-1)
            WAI = WA(IDLJ)
!DIR$ IVDEP
            DO 114 IK=1,IDL1
               C2(IK,L) = C2(IK,L)+WAR*CH2(IK,J)
               C2(IK,LC) = C2(IK,LC)-WAI*CH2(IK,JC)
  114       CONTINUE
  115    CONTINUE
  116 CONTINUE
      DO 118 J=2,IPPH
!DIR$ IVDEP
         DO 117 IK=1,IDL1
            CH2(IK,1) = CH2(IK,1)+CH2(IK,J)
  117    CONTINUE
  118 CONTINUE
      DO 120 J=2,IPPH
         JC = IPP2-J
!DIR$ IVDEP
         DO 119 IK=2,IDL1,2
            CH2(IK-1,J) = C2(IK-1,J)-C2(IK,JC)
            CH2(IK-1,JC) = C2(IK-1,J)+C2(IK,JC)
            CH2(IK,J) = C2(IK,J)+C2(IK-1,JC)
            CH2(IK,JC) = C2(IK,J)-C2(IK-1,JC)
  119    CONTINUE
  120 CONTINUE
      NAC = 1
      IF (IDO .EQ. 2) RETURN
      NAC = 0
!DIR$ IVDEP
      DO 121 IK=1,IDL1
         C2(IK,1) = CH2(IK,1)
  121 CONTINUE
      DO 123 J=2,IP
!DIR$ IVDEP
         DO 122 K=1,L1
            C1(1,K,J) = CH(1,K,J)
            C1(2,K,J) = CH(2,K,J)
  122    CONTINUE
  123 CONTINUE
      IF (IDOT .GT. L1) GO TO 127
      IDIJ = 0
      DO 126 J=2,IP
         IDIJ = IDIJ+2
         DO 125 I=4,IDO,2
            IDIJ = IDIJ+2
!DIR$ IVDEP
            DO 124 K=1,L1
               C1(I-1,K,J) = WA(IDIJ-1)*CH(I-1,K,J)+WA(IDIJ)*CH(I,K,J)
               C1(I,K,J) = WA(IDIJ-1)*CH(I,K,J)-WA(IDIJ)*CH(I-1,K,J)
  124       CONTINUE
  125    CONTINUE
  126 CONTINUE
      RETURN
  127 IDJ = 2-IDO
      DO 130 J=2,IP
         IDJ = IDJ+IDO
         DO 129 K=1,L1
            IDIJ = IDJ
!DIR$ IVDEP
            DO 128 I=4,IDO,2
               IDIJ = IDIJ+2
               C1(I-1,K,J) = WA(IDIJ-1)*CH(I-1,K,J)+WA(IDIJ)*CH(I,K,J)
               C1(I,K,J) = WA(IDIJ-1)*CH(I,K,J)-WA(IDIJ)*CH(I-1,K,J)
  128       CONTINUE
  129    CONTINUE
  130 CONTINUE
      RETURN
      END SUBROUTINE PASSF
      SUBROUTINE PASSF2(IDO,L1,CC,CH,WA1)
!***BEGIN PROLOGUE  PASSF2
!***REFER TO  CFFTF
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSF2
      DIMENSION       CC(IDO,2,L1)           ,CH(IDO,L1,2)           ,   &
                      WA1(*)
!***FIRST EXECUTABLE STATEMENT  PASSF2
      IF (IDO .GT. 2) GO TO 102
      DO 101 K=1,L1
         CH(1,K,1) = CC(1,1,K)+CC(1,2,K)
         CH(1,K,2) = CC(1,1,K)-CC(1,2,K)
         CH(2,K,1) = CC(2,1,K)+CC(2,2,K)
         CH(2,K,2) = CC(2,1,K)-CC(2,2,K)
  101 CONTINUE
      RETURN
  102 IF(IDO/2.LT.L1) GO TO 105
      DO 104 K=1,L1
!DIR$ IVDEP
         DO 103 I=2,IDO,2
            CH(I-1,K,1) = CC(I-1,1,K)+CC(I-1,2,K)
            TR2 = CC(I-1,1,K)-CC(I-1,2,K)
            CH(I,K,1) = CC(I,1,K)+CC(I,2,K)
            TI2 = CC(I,1,K)-CC(I,2,K)
            CH(I,K,2) = WA1(I-1)*TI2-WA1(I)*TR2
            CH(I-1,K,2) = WA1(I-1)*TR2+WA1(I)*TI2
  103    CONTINUE
  104 CONTINUE
      RETURN
  105 DO 107 I=2,IDO,2
!DIR$ IVDEP
      DO 106 K=1,L1
            CH(I-1,K,1) = CC(I-1,1,K)+CC(I-1,2,K)
            TR2 = CC(I-1,1,K)-CC(I-1,2,K)
            CH(I,K,1) = CC(I,1,K)+CC(I,2,K)
            TI2 = CC(I,1,K)-CC(I,2,K)
            CH(I,K,2) = WA1(I-1)*TI2-WA1(I)*TR2
            CH(I-1,K,2) = WA1(I-1)*TR2+WA1(I)*TI2
  106    CONTINUE
  107 CONTINUE
      RETURN
      END SUBROUTINE PASSF2
      SUBROUTINE PASSF3(IDO,L1,CC,CH,WA1,WA2)
!***BEGIN PROLOGUE  PASSF3
!***REFER TO  CFFTF
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSF3
      DIMENSION       CC(IDO,3,L1)           ,CH(IDO,L1,3)           ,   &
                      WA1(*)     ,WA2(*)
!***FIRST EXECUTABLE STATEMENT  PASSF3
      TAUR = -.5
      TAUI = -.5*SQRT(3.)
      IF (IDO .NE. 2) GO TO 102
      DO 101 K=1,L1
         TR2 = CC(1,2,K)+CC(1,3,K)
         CR2 = CC(1,1,K)+TAUR*TR2
         CH(1,K,1) = CC(1,1,K)+TR2
         TI2 = CC(2,2,K)+CC(2,3,K)
         CI2 = CC(2,1,K)+TAUR*TI2
         CH(2,K,1) = CC(2,1,K)+TI2
         CR3 = TAUI*(CC(1,2,K)-CC(1,3,K))
         CI3 = TAUI*(CC(2,2,K)-CC(2,3,K))
         CH(1,K,2) = CR2-CI3
         CH(1,K,3) = CR2+CI3
         CH(2,K,2) = CI2+CR3
         CH(2,K,3) = CI2-CR3
  101 CONTINUE
      RETURN
  102 IF(IDO/2.LT.L1) GO TO 105
      DO 104 K=1,L1
!DIR$ IVDEP
         DO 103 I=2,IDO,2
            TR2 = CC(I-1,2,K)+CC(I-1,3,K)
            CR2 = CC(I-1,1,K)+TAUR*TR2
            CH(I-1,K,1) = CC(I-1,1,K)+TR2
            TI2 = CC(I,2,K)+CC(I,3,K)
            CI2 = CC(I,1,K)+TAUR*TI2
            CH(I,K,1) = CC(I,1,K)+TI2
            CR3 = TAUI*(CC(I-1,2,K)-CC(I-1,3,K))
            CI3 = TAUI*(CC(I,2,K)-CC(I,3,K))
            DR2 = CR2-CI3
            DR3 = CR2+CI3
            DI2 = CI2+CR3
            DI3 = CI2-CR3
            CH(I,K,2) = WA1(I-1)*DI2-WA1(I)*DR2
            CH(I-1,K,2) = WA1(I-1)*DR2+WA1(I)*DI2
            CH(I,K,3) = WA2(I-1)*DI3-WA2(I)*DR3
            CH(I-1,K,3) = WA2(I-1)*DR3+WA2(I)*DI3
  103    CONTINUE
  104 CONTINUE
      RETURN
  105 DO 107 I=2,IDO,2
!DIR$ IVDEP
         DO 106 K=1,L1
            TR2 = CC(I-1,2,K)+CC(I-1,3,K)
            CR2 = CC(I-1,1,K)+TAUR*TR2
            CH(I-1,K,1) = CC(I-1,1,K)+TR2
            TI2 = CC(I,2,K)+CC(I,3,K)
            CI2 = CC(I,1,K)+TAUR*TI2
            CH(I,K,1) = CC(I,1,K)+TI2
            CR3 = TAUI*(CC(I-1,2,K)-CC(I-1,3,K))
            CI3 = TAUI*(CC(I,2,K)-CC(I,3,K))
            DR2 = CR2-CI3
            DR3 = CR2+CI3
            DI2 = CI2+CR3
            DI3 = CI2-CR3
            CH(I,K,2) = WA1(I-1)*DI2-WA1(I)*DR2
            CH(I-1,K,2) = WA1(I-1)*DR2+WA1(I)*DI2
            CH(I,K,3) = WA2(I-1)*DI3-WA2(I)*DR3
            CH(I-1,K,3) = WA2(I-1)*DR3+WA2(I)*DI3
  106    CONTINUE
  107 CONTINUE
      RETURN
      END SUBROUTINE PASSF3
      SUBROUTINE PASSF4(IDO,L1,CC,CH,WA1,WA2,WA3)
!***BEGIN PROLOGUE  PASSF4
!***REFER TO  CFFTF
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSF4
      DIMENSION       CC(IDO,4,L1)           ,CH(IDO,L1,4)           ,   &
                      WA1(*)     ,WA2(*)     ,WA3(*)
!***FIRST EXECUTABLE STATEMENT  PASSF4
      IF (IDO .NE. 2) GO TO 102
      DO 101 K=1,L1
         TI1 = CC(2,1,K)-CC(2,3,K)
         TI2 = CC(2,1,K)+CC(2,3,K)
         TR4 = CC(2,2,K)-CC(2,4,K)
         TI3 = CC(2,2,K)+CC(2,4,K)
         TR1 = CC(1,1,K)-CC(1,3,K)
         TR2 = CC(1,1,K)+CC(1,3,K)
         TI4 = CC(1,4,K)-CC(1,2,K)
         TR3 = CC(1,2,K)+CC(1,4,K)
         CH(1,K,1) = TR2+TR3
         CH(1,K,3) = TR2-TR3
         CH(2,K,1) = TI2+TI3
         CH(2,K,3) = TI2-TI3
         CH(1,K,2) = TR1+TR4
         CH(1,K,4) = TR1-TR4
         CH(2,K,2) = TI1+TI4
         CH(2,K,4) = TI1-TI4
  101 CONTINUE
      RETURN
  102 IF(IDO/2.LT.L1) GO TO 105
      DO 104 K=1,L1
!DIR$ IVDEP
         DO 103 I=2,IDO,2
            TI1 = CC(I,1,K)-CC(I,3,K)
            TI2 = CC(I,1,K)+CC(I,3,K)
            TI3 = CC(I,2,K)+CC(I,4,K)
            TR4 = CC(I,2,K)-CC(I,4,K)
            TR1 = CC(I-1,1,K)-CC(I-1,3,K)
            TR2 = CC(I-1,1,K)+CC(I-1,3,K)
            TI4 = CC(I-1,4,K)-CC(I-1,2,K)
            TR3 = CC(I-1,2,K)+CC(I-1,4,K)
            CH(I-1,K,1) = TR2+TR3
            CR3 = TR2-TR3
            CH(I,K,1) = TI2+TI3
            CI3 = TI2-TI3
            CR2 = TR1+TR4
            CR4 = TR1-TR4
            CI2 = TI1+TI4
            CI4 = TI1-TI4
            CH(I-1,K,2) = WA1(I-1)*CR2+WA1(I)*CI2
            CH(I,K,2) = WA1(I-1)*CI2-WA1(I)*CR2
            CH(I-1,K,3) = WA2(I-1)*CR3+WA2(I)*CI3
            CH(I,K,3) = WA2(I-1)*CI3-WA2(I)*CR3
            CH(I-1,K,4) = WA3(I-1)*CR4+WA3(I)*CI4
            CH(I,K,4) = WA3(I-1)*CI4-WA3(I)*CR4
  103    CONTINUE
  104 CONTINUE
      RETURN
  105 DO 107 I=2,IDO,2
!DIR$ IVDEP
         DO 106 K=1,L1
            TI1 = CC(I,1,K)-CC(I,3,K)
            TI2 = CC(I,1,K)+CC(I,3,K)
            TI3 = CC(I,2,K)+CC(I,4,K)
            TR4 = CC(I,2,K)-CC(I,4,K)
            TR1 = CC(I-1,1,K)-CC(I-1,3,K)
            TR2 = CC(I-1,1,K)+CC(I-1,3,K)
            TI4 = CC(I-1,4,K)-CC(I-1,2,K)
            TR3 = CC(I-1,2,K)+CC(I-1,4,K)
            CH(I-1,K,1) = TR2+TR3
            CR3 = TR2-TR3
            CH(I,K,1) = TI2+TI3
            CI3 = TI2-TI3
            CR2 = TR1+TR4
            CR4 = TR1-TR4
            CI2 = TI1+TI4
            CI4 = TI1-TI4
            CH(I-1,K,2) = WA1(I-1)*CR2+WA1(I)*CI2
            CH(I,K,2) = WA1(I-1)*CI2-WA1(I)*CR2
            CH(I-1,K,3) = WA2(I-1)*CR3+WA2(I)*CI3
            CH(I,K,3) = WA2(I-1)*CI3-WA2(I)*CR3
            CH(I-1,K,4) = WA3(I-1)*CR4+WA3(I)*CI4
            CH(I,K,4) = WA3(I-1)*CI4-WA3(I)*CR4
  106    CONTINUE
  107 CONTINUE
      RETURN
      END SUBROUTINE PASSF4
      SUBROUTINE PASSF5(IDO,L1,CC,CH,WA1,WA2,WA3,WA4)
!***BEGIN PROLOGUE  PASSF5
!***REFER TO  CFFTF
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PASSF5
      DIMENSION       CC(IDO,5,L1)           ,CH(IDO,L1,5)           ,   &
                      WA1(*)     ,WA2(*)     ,WA3(*)     ,WA4(*)
!***FIRST EXECUTABLE STATEMENT  PASSF5
      PI = 4.*ATAN(1.)
      TR11 = SIN(.1*PI)
      TI11 = -SIN(.4*PI)
      TR12 = -SIN(.3*PI)
      TI12 = -SIN(.2*PI)
      IF (IDO .NE. 2) GO TO 102
      DO 101 K=1,L1
         TI5 = CC(2,2,K)-CC(2,5,K)
         TI2 = CC(2,2,K)+CC(2,5,K)
         TI4 = CC(2,3,K)-CC(2,4,K)
         TI3 = CC(2,3,K)+CC(2,4,K)
         TR5 = CC(1,2,K)-CC(1,5,K)
         TR2 = CC(1,2,K)+CC(1,5,K)
         TR4 = CC(1,3,K)-CC(1,4,K)
         TR3 = CC(1,3,K)+CC(1,4,K)
         CH(1,K,1) = CC(1,1,K)+TR2+TR3
         CH(2,K,1) = CC(2,1,K)+TI2+TI3
         CR2 = CC(1,1,K)+TR11*TR2+TR12*TR3
         CI2 = CC(2,1,K)+TR11*TI2+TR12*TI3
         CR3 = CC(1,1,K)+TR12*TR2+TR11*TR3
         CI3 = CC(2,1,K)+TR12*TI2+TR11*TI3
         CR5 = TI11*TR5+TI12*TR4
         CI5 = TI11*TI5+TI12*TI4
         CR4 = TI12*TR5-TI11*TR4
         CI4 = TI12*TI5-TI11*TI4
         CH(1,K,2) = CR2-CI5
         CH(1,K,5) = CR2+CI5
         CH(2,K,2) = CI2+CR5
         CH(2,K,3) = CI3+CR4
         CH(1,K,3) = CR3-CI4
         CH(1,K,4) = CR3+CI4
         CH(2,K,4) = CI3-CR4
         CH(2,K,5) = CI2-CR5
  101 CONTINUE
      RETURN
  102 IF(IDO/2.LT.L1) GO TO 105
      DO 104 K=1,L1
!DIR$ IVDEP
         DO 103 I=2,IDO,2
            TI5 = CC(I,2,K)-CC(I,5,K)
            TI2 = CC(I,2,K)+CC(I,5,K)
            TI4 = CC(I,3,K)-CC(I,4,K)
            TI3 = CC(I,3,K)+CC(I,4,K)
            TR5 = CC(I-1,2,K)-CC(I-1,5,K)
            TR2 = CC(I-1,2,K)+CC(I-1,5,K)
            TR4 = CC(I-1,3,K)-CC(I-1,4,K)
            TR3 = CC(I-1,3,K)+CC(I-1,4,K)
            CH(I-1,K,1) = CC(I-1,1,K)+TR2+TR3
            CH(I,K,1) = CC(I,1,K)+TI2+TI3
            CR2 = CC(I-1,1,K)+TR11*TR2+TR12*TR3
            CI2 = CC(I,1,K)+TR11*TI2+TR12*TI3
            CR3 = CC(I-1,1,K)+TR12*TR2+TR11*TR3
            CI3 = CC(I,1,K)+TR12*TI2+TR11*TI3
            CR5 = TI11*TR5+TI12*TR4
            CI5 = TI11*TI5+TI12*TI4
            CR4 = TI12*TR5-TI11*TR4
            CI4 = TI12*TI5-TI11*TI4
            DR3 = CR3-CI4
            DR4 = CR3+CI4
            DI3 = CI3+CR4
            DI4 = CI3-CR4
            DR5 = CR2+CI5
            DR2 = CR2-CI5
            DI5 = CI2-CR5
            DI2 = CI2+CR5
            CH(I-1,K,2) = WA1(I-1)*DR2+WA1(I)*DI2
            CH(I,K,2) = WA1(I-1)*DI2-WA1(I)*DR2
            CH(I-1,K,3) = WA2(I-1)*DR3+WA2(I)*DI3
            CH(I,K,3) = WA2(I-1)*DI3-WA2(I)*DR3
            CH(I-1,K,4) = WA3(I-1)*DR4+WA3(I)*DI4
            CH(I,K,4) = WA3(I-1)*DI4-WA3(I)*DR4
            CH(I-1,K,5) = WA4(I-1)*DR5+WA4(I)*DI5
            CH(I,K,5) = WA4(I-1)*DI5-WA4(I)*DR5
  103    CONTINUE
  104 CONTINUE
      RETURN
  105 DO 107 I=2,IDO,2
!DIR$ IVDEP
         DO 106 K=1,L1
            TI5 = CC(I,2,K)-CC(I,5,K)
            TI2 = CC(I,2,K)+CC(I,5,K)
            TI4 = CC(I,3,K)-CC(I,4,K)
            TI3 = CC(I,3,K)+CC(I,4,K)
            TR5 = CC(I-1,2,K)-CC(I-1,5,K)
            TR2 = CC(I-1,2,K)+CC(I-1,5,K)
            TR4 = CC(I-1,3,K)-CC(I-1,4,K)
            TR3 = CC(I-1,3,K)+CC(I-1,4,K)
            CH(I-1,K,1) = CC(I-1,1,K)+TR2+TR3
            CH(I,K,1) = CC(I,1,K)+TI2+TI3
            CR2 = CC(I-1,1,K)+TR11*TR2+TR12*TR3
            CI2 = CC(I,1,K)+TR11*TI2+TR12*TI3
            CR3 = CC(I-1,1,K)+TR12*TR2+TR11*TR3
            CI3 = CC(I,1,K)+TR12*TI2+TR11*TI3
            CR5 = TI11*TR5+TI12*TR4
            CI5 = TI11*TI5+TI12*TI4
            CR4 = TI12*TR5-TI11*TR4
            CI4 = TI12*TI5-TI11*TI4
            DR3 = CR3-CI4
            DR4 = CR3+CI4
            DI3 = CI3+CR4
            DI4 = CI3-CR4
            DR5 = CR2+CI5
            DR2 = CR2-CI5
            DI5 = CI2-CR5
            DI2 = CI2+CR5
            CH(I-1,K,2) = WA1(I-1)*DR2+WA1(I)*DI2
            CH(I,K,2) = WA1(I-1)*DI2-WA1(I)*DR2
            CH(I-1,K,3) = WA2(I-1)*DR3+WA2(I)*DI3
            CH(I,K,3) = WA2(I-1)*DI3-WA2(I)*DR3
            CH(I-1,K,4) = WA3(I-1)*DR4+WA3(I)*DI4
            CH(I,K,4) = WA3(I-1)*DI4-WA3(I)*DR4
            CH(I-1,K,5) = WA4(I-1)*DR5+WA4(I)*DI5
            CH(I,K,5) = WA4(I-1)*DI5-WA4(I)*DR5
  106    CONTINUE
  107 CONTINUE
      RETURN
      END SUBROUTINE PASSF5
      SUBROUTINE PBDV(V,X,DV,DP,PDF,PDD)
!
!       ====================================================
!       Purpose: Compute parabolic cylinder functions Dv(x)
!                and their derivatives
!       Input:   x --- Argument of Dv(x)
!                v --- Order of Dv(x)
!       Output:  DV(na) --- Dn+v0(x)
!                DP(na) --- Dn+v0'(x)
!                ( na = |n|, v0 = v-n, |v0| < 1,
!                  n = 0,ś1,ś2,÷÷÷ )
!                PDF --- Dv(x)
!                PDD --- Dv'(x)
!       Routines called:
!             (1) DVSA for computing Dv(x) for small |x|
!             (2) DVLA for computing Dv(x) for large |x|
!       ====================================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
        DIMENSION DV(0:*),DP(0:*)
!
        XA=DABS(X)
        VH=V
        V=V+DSIGN(1.0D0,V)
        NV=INT(V)
        V0=V-NV
        NA=ABS(NV)
        EP=DEXP(-.25D0*X*X)
        PD0=0.0D0
        PD1=0.0D0
!
        IF (NA.GE.1) JA=1
        IF (V.GE.0.0) THEN
           IF (V0.EQ.0.0) THEN
              PD0=EP
              PD1=X*EP
           ELSE
              DO 10 L=0,JA
                 V1=V0+L
                 IF (XA.LE.5.8) CALL DVSA(V1,X,PD1)
                 IF (XA.GT.5.8) CALL DVLA(V1,X,PD1)
                 IF (L.EQ.0) PD0=PD1
10            CONTINUE
           ENDIF
           DV(0)=PD0
           DV(1)=PD1
           DO 15 K=2,NA
              PDF=X*PD1-(K+V0-1.0D0)*PD0
              DV(K)=PDF
              PD0=PD1
              PD1=PDF
15         CONTINUE
        ELSE
           IF (X.LE.0.0) THEN
              IF (XA.LE.5.8D0)  THEN
                 CALL DVSA(V0,X,PD0)
                 V1=V0-1.0D0
                 CALL DVSA(V1,X,PD1)
              ELSE
                 CALL DVLA(V0,X,PD0)
                 V1=V0-1.0D0
                 CALL DVLA(V1,X,PD1)
              ENDIF
              DV(0)=PD0
              DV(1)=PD1
              DO 20 K=2,NA
                 PD=(-X*PD1+PD0)/(K-1.0D0-V0)
                 DV(K)=PD
                 PD0=PD1
                 PD1=PD
20            CONTINUE
           ELSE IF (X.LE.2.0) THEN
              V2=NV+V0
              IF (NV.EQ.0) V2=V2-1.0D0
              NK=INT(-V2)
              CALL DVSA(V2,X,F1)
              V1=V2+1.0D0
              CALL DVSA(V1,X,F0)
              DV(NK)=F1
              DV(NK-1)=F0
              DO 25 K=NK-2,0,-1
                 F=X*F0+(K-V0+1.0D0)*F1
                 DV(K)=F
                 F1=F0
                 F0=F
25            CONTINUE
           ELSE
              IF (XA.LE.5.8) CALL DVSA(V0,X,PD0)
              IF (XA.GT.5.8) CALL DVLA(V0,X,PD0)
              DV(0)=PD0
              M=100+NA
              F1=0.0D0
              F0=1.0D-30
              DO 30 K=M,0,-1
                 F=X*F0+(K-V0+1.0D0)*F1
                 IF (K.LE.NA) DV(K)=F
                 F1=F0
                 F0=F
30            CONTINUE
              S0=PD0/F
              DO 35 K=0,NA
                 DV(K)=S0*DV(K)
35            CONTINUE
           ENDIF
        ENDIF
        DO 40 K=0,NA-1
           V1=ABS(V0)+K
           IF (V.GE.0.0D0) THEN
              DP(K)=0.5D0*X*DV(K)-DV(K+1)
           ELSE
              DP(K)=-0.5D0*X*DV(K)-V1*DV(K+1)
           ENDIF
40      CONTINUE
        PDF=DV(NA-1)
        PDD=DP(NA-1)
        V=VH
        RETURN
        END
      SUBROUTINE PBNCOR(X,Y,N,IWRITE,XTEMP1,XTEMP2,MAXNXT,PBCORR,BETA,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE PERCENTAGE BEND CORRELATION
!              OF THE DATA IN THE INPUT VECTORS X AND Y.
!              THIS IS A ROBUST MEASURE OF SCALE DESCRIBED IN
!              "INTRODUCTION TO ROBUST ESTIMATION AND HYPOTHESIS
!              TESTING", RAND R. WILCOX, ACADEMIC PRESS, 1997.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--PBCORR = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE PERCENTAGE BEND
!                                CORRELATION.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PERCENTAGE BEND CORRELATION (WITH DENOMINATOR N-1).
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEDIAN AND SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"INTRODUCTION TO ROBUST ESTIMATION AND HYPOTHESIS
!                 TESTING", RAND R. WILCOX, ACADEMIC PRESS, 1997.
!                 COMPUTATIONAL STEPS DESCRIBED IN THIS REFERENCE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/7
!     ORIGINAL VERSION--JULY      2002.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTERM6
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NCOR'
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF PBNCOR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I),Y(I)
   56 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN PBNCOR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE PERCENTAGE BEND CORRELATION IS TO BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      COMPUTED, MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** NON-FATAL DIAGNOSTIC IN PBNCOR--',   &
      'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
      CALL DPWRST('XXX','BUG ')
      PBCORR=0.0
      GO TO 9000
  129 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE PERCENTAGE BEND CORRELATION.   **
!               *************************************************
!
      IWRIT2='OFF'
!
      CALL MEDIAN(X,N,IWRIT2,XTEMP1,MAXNXT,XMED,IBUGA3,IERROR)
      CALL MEDIAN(Y,N,IWRIT2,XTEMP1,MAXNXT,YMED,IBUGA3,IERROR)
!
      DO 300 I=1,N
        XTEMP1(I)=ABS(X(I)-XMED)
        XTEMP2(I)=ABS(Y(I)-YMED)
  300 CONTINUE
!
      IF(BETA.LE.0.01 .OR. BETA.GT.0.99)THEN
        WRITE(ICOUT,321)
  321   FORMAT('***** WARNING IN PBNCOR--THE VALUE OF ',   &
               'BETA OUTSIDE THE (0.01,0.99) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,323)
  323   FORMAT('      DEFAULT VALUE OF 0.1 USED.')
        CALL DPWRST('XXX','BUG ')
        BETA=0.1
      ENDIF
!
      CALL SORT(XTEMP1,N,XTEMP1)
      CALL SORT(XTEMP2,N,XTEMP2)
!
      AN=REAL(N)
      AM=(1.0 - BETA)*AN + 0.5
      M=INT(AM)
      WBETAX=XTEMP1(M)
      WBETAY=XTEMP2(M)
!
      I1=0
      I2=0
      I3=0
      I6=0
      I7=0
      I8=0
      DTERM1=0.0D0
      DTERM6=0.0D0
      DO 400 I=1,N
        IF(ABS((X(I)-XMED)/WBETAX).LE.1.0)THEN
          DTERM1=DTERM1 + X(I)
          I3=I3 + 1
        ELSEIF((X(I)-XMED)/WBETAX.LT.-1.0)THEN
          I1=I1 + 1
        ELSEIF((X(I)-XMED)/WBETAX.GT.1.0)THEN
          I2=I2 + 1
        ENDIF
!
        IF(ABS((Y(I)-YMED)/WBETAY).LE.1.0)THEN
          DTERM6=DTERM6 + Y(I)
          I8=I8+1
        ELSEIF((Y(I)-YMED)/WBETAY.LT.-1.0)THEN
          I6=I6 + 1
        ELSEIF((Y(I)-YMED)/WBETAY.GT.1.0)THEN
          I7=I7 + 1
        ENDIF
  400 CONTINUE
      PHIX=(WBETAX*REAL(I2-I1) + REAL(DTERM1))/REAL(N - I1 - I2)
      PHIY=(WBETAY*REAL(I7-I6) + REAL(DTERM6))/REAL(N - I6 - I7)
!
      DTERM1=0.0D0
      DTERM2=0.0D0
      DTERM3=0.0D0
      DO 500 I=1,N
        UI=(X(I) - PHIX)/WBETAX
        VI=(Y(I) - PHIY)/WBETAY
        DTERM4=MAX(-1.0D0,MIN(1.0D0,DBLE(UI)))
        DTERM5=MAX(-1.0D0,MIN(1.0D0,DBLE(VI)))
        DTERM1=DTERM1 + DTERM4*DTERM4
        DTERM2=DTERM2 + DTERM5*DTERM5
        DTERM3=DTERM3 + DTERM4*DTERM5
  500 CONTINUE
      DTERM4=0.0D0
      IF(DTERM1*DTERM2.GT.0.0D0)DTERM4=DTERM3/DSQRT(DTERM1*DTERM2)
      PBCORR=REAL(DTERM4)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,PBCORR
  811 FORMAT('THE PERCENTAGE BEND CORRELATION OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF PBNCOR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)XMED,WBETAX,YMED,WBETAY
 9014 FORMAT('XMED,WBETAX,YMED,WBETAY = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)PBCORR
 9015 FORMAT('PBCORR = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)DTERM1,DTERM2,DTERM3,DTERM3
 9016 FORMAT('DTERM1,DTERM2,DTERM3,DTERM3 = ',4D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9018)I1,I2,I3,I6,I7,I8
 9018 FORMAT('I1,I2,I3,I6,I7,I8 = ',6I8)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE PBNCOR
      SUBROUTINE PBNMDV(X,N,IWRITE,XTEMP,MAXNXT,PBMDVA,BETA,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE PERCENTAGE BEND MIDVARIANCE
!              OF THE DATA IN THE INPUT VECTOR X.
!              THIS IS A ROBUST MEASURE OF SCALE DESCRIBED IN
!              "INTRODUCTION TO ROBUST ESTIMATION AND HYPOTHESIS
!              TESTING", RAND R. WILCOX, ACADEMIC PRESS, 1997.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--PBMDVA    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE PERCENTAGE BEND MIDVARIANCE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PERCENTAGE BEND MIDVARIANCE (WITH DENOMINATOR N-1).
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEDIAN AND SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"INTRODUCTION TO ROBUST ESTIMATION AND HYPOTHESIS
!                 TESTING", RAND R. WILCOX, ACADEMIC PRESS, 1997.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/7
!     ORIGINAL VERSION--JULY      2002.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NMDV'
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF PBNMDV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN PBNMDV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE PERCENTAGE BEND MIDVARIANCE IS TO BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      COMPUTED, MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** WARNING IN PBNMDV--',   &
      'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
      CALL DPWRST('XXX','BUG ')
      PBMDVA=0.0
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('***** NON-FATAL DIAGNOSTIC IN PBNMDV--',   &
      'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      PBMDVA=0.0
      GO TO 9000
  139 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE PERCENTAGE BEND MIDVARIANCE.   **
!               *************************************************
!
      IWRIT2='OFF'
      CALL MEDIAN(X,N,IWRIT2,XTEMP,MAXNXT,XMED,IBUGA3,IERROR)
!
      DO 300 I=1,N
      XTEMP(I)=ABS(X(I)-XMED)
  300 CONTINUE
!
      IF(BETA.LE.0.01 .OR. BETA.GT.0.99)THEN
        WRITE(ICOUT,321)
  321   FORMAT('***** WARNING IN PBNMDV--THE VALUE OF ',   &
               'BETA OUTSIDE THE (0.01,0.99) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,323)
  323   FORMAT('      DEFAULT VALUE OF 0.1 USED.')
        CALL DPWRST('XXX','BUG ')
        BETA=0.1
      ENDIF
!
      CALL SORT(XTEMP,N,XTEMP)
      AN=REAL(N)
      AM=(1.0 - BETA)*AN + 0.5
      M=INT(AM)
      WBETA=XTEMP(M)
!
      DTERM2=0.0D0
      DO 400 I=1,N
      X(I)=(X(I) - XMED)/WBETA
      IF(ABS(X(I)).LT.1.0)DTERM2=DTERM2+1.0D0
  400 CONTINUE
      DTERM2=DTERM2*DTERM2
!
      DTERM1=DBLE(WBETA)/DTERM2
      DTERM1=DTERM1*DBLE(WBETA)*DBLE(N)
      DTERM3=0.0D0
      DO 500 I=1,N
        DTERM4=MAX(-1.0D0,MIN(1.0D0,DBLE(X(I))))
        DTERM3=DTERM3 + DTERM4*DTERM4
  500 CONTINUE
      PBMDVA=REAL(DTERM1*DTERM3)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,PBMDVA
  811 FORMAT('THE PERCENTAGE BEND MIDVARIANCE OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF PBNMDV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)XMED,WBETA
 9014 FORMAT('XMED,WBETA = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)PBMDVA
 9015 FORMAT('PBMDVA = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)DTERM1,DTERM2,DTERM3,DTERM4
 9016 FORMAT('DTERM1,DTERM2,DTERM3,DTERM4 = ',4D15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE PBNMDV
      SUBROUTINE PBVV(V,X,VV,VP,PVF,PVD)
!
!       ===================================================
!       Purpose: Compute parabolic cylinder functions Vv(x)
!                and their derivatives
!       Input:   x --- Argument of Vv(x)
!                v --- Order of Vv(x)
!       Output:  VV(na) --- Vv(x)
!                VP(na) --- Vv'(x)
!                ( na = |n|, v = n+v0, |v0| < 1
!                  n = 0,ś1,ś2,÷÷÷ )
!                PVF --- Vv(x)
!                PVD --- Vv'(x)
!       Routines called:
!             (1) VVSA for computing Vv(x) for small |x|
!             (2) VVLA for computing Vv(x) for large |x|
!       ===================================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
        DIMENSION VV(0:*),VP(0:*)
!
        PI=3.141592653589793D0
        XA=DABS(X)
        VH=V
        V=V+DSIGN(1.0D0,V)
        NV=INT(V)
        V0=V-NV
        NA=ABS(NV)
        QE=DEXP(0.25D0*X*X)
        Q2P=DSQRT(2.0D0/PI)
        F0=0.0D0
        F1=0.0D0
!
        IF (NA.GE.1) JA=1
        IF (V.LE.0.0) THEN
           IF (V0.EQ.0.0) THEN
              PV0=0.0
              IF (XA.LE.7.5) CALL VVSA(V0,X,PV0)
              IF (XA.GT.7.5) CALL VVLA(V0,X,PV0)
              F0=Q2P*QE
              F1=X*F0
              VV(0)=PV0
              VV(1)=F0
              VV(2)=F1
           ELSE
              DO 10 L=0,JA
                 V1=V0-L
                 IF (XA.LE.7.5) CALL VVSA(V1,X,F1)
                 IF (XA.GT.7.5) CALL VVLA(V1,X,F1)
                 IF (L.EQ.0) F0=F1
10            CONTINUE
              VV(0)=F0
              VV(1)=F1
           ENDIF
           KV=2
           IF (V0.EQ.0.0) KV=3
           DO 15 K=KV,NA
              F=X*F1+(K-V0-2.0D0)*F0
              VV(K)=F
              F0=F1
              F1=F
15         CONTINUE
        ELSE
           IF (X.GE.0.0.AND.X.LE.7.5D0) THEN
              V2=V
              IF (V2.LT.1.0) V2=V2+1.0D0
              CALL VVSA(V2,X,F1)
              V1=V2-1.0D0
              KV=INT(V2)
              CALL VVSA(V1,X,F0)
              VV(KV)=F1
              VV(KV-1)=F0
              DO 20 K=KV-2,0,-1
                 F=X*F0-(K+V0+2.0D0)*F1
                 IF (K.LE.NA) VV(K)=F
                 F1=F0
                 F0=F
20            CONTINUE
           ELSE IF (X.GT.7.5D0) THEN
              CALL VVLA(V0,X,PV0)
              M=100+ABS(NA)
              VV(1)=PV0
              F1=0.0D0
              F0=1.0D-40
              DO 25 K=M,0,-1
                 F=X*F0-(K+V0+2.0D0)*F1
                 IF (K.LE.NA) VV(K)=F
                 F1=F0
                 F0=F
25            CONTINUE
              S0=PV0/F
              DO 30 K=0,NA
                 VV(K)=S0*VV(K)
30            CONTINUE
           ELSE
              IF (XA.LE.7.5D0) THEN
                 CALL VVSA(V0,X,F0)
                 V1=V0+1.0
                 CALL VVSA(V1,X,F1)
              ELSE
                 CALL VVLA(V0,X,F0)
                 V1=V0+1.0D0
                 CALL VVLA(V1,X,F1)
              ENDIF
              VV(0)=F0
              VV(1)=F1
              DO 35 K=2,NA
                 F=(X*F1-F0)/(K+V0)
                 VV(K)=F
                 F0=F1
                 F1=F
35            CONTINUE
           ENDIF
        ENDIF
        DO 40 K=0,NA-1
           V1=V0+K
           IF (V.GE.0.0D0) THEN
              VP(K)=0.5D0*X*VV(K)-(V1+1.0D0)*VV(K+1)
           ELSE
              VP(K)=-0.5D0*X*VV(K)+VV(K+1)
           ENDIF
40      CONTINUE
        PVF=VV(NA-1)
        PVD=VP(NA-1)
        V=VH
        RETURN
        END
        SUBROUTINE PBWA(A,X,W1F,W1D,W2F,W2D)
!
!       ======================================================
!       Purpose: Compute parabolic cylinder functions W(a,śx)
!                and their derivatives
!       Input  : a --- Parameter  ( 0 ü |a| ü 5 )
!                x --- Argument of W(a,śx)  ( 0 ü |x| ü 5 )
!       Output : W1F --- W(a,x)
!                W1D --- W'(a,x)
!                W2F --- W(a,-x)
!                W2D --- W'(a,-x)
!       Routine called:
!               CGAMA for computing complex gamma function
!       ======================================================
!
        IMPLICIT DOUBLE PRECISION (A,B,D-H,O-Y)
!CCCC   IMPLICIT COMPLEX *16 (C,Z)
        DIMENSION H(101),D(101)
        EPS=1.0D-15
        P0=0.59460355750136D0
        IF (A.EQ.0.0D0) THEN
           G1=3.625609908222D0
           G2=1.225416702465D0
        ELSE
           X1=0.25D0
           Y1=0.5D0*A
           CALL CGAMA(X1,Y1,1,UGR,UGI)
           G1=DSQRT(UGR*UGR+UGI*UGI)
           X2=0.75D0
           CALL CGAMA(X2,Y1,1,VGR,VGI)
           G2=DSQRT(VGR*VGR+VGI*VGI)
        ENDIF
        F1=DSQRT(G1/G2)
        F2=DSQRT(2.0D0*G2/G1)
        H0=1.0D0
        H1=A
        H(1)=A
        DO 10 L1=4,200,2
           M=L1/2
           HL=A*H1-0.25D0*(L1-2.0D0)*(L1-3.0D0)*H0
           H(M)=HL
           H0=H1
           H1=HL
10      CONTINUE
        Y1F=1.0D0
        R=1.0D0
        DO 15 K=1,100
           R=0.5D0*R*X*X/(K*(2.0D0*K-1.0D0))
           R1=H(K)*R
           Y1F=Y1F+R1
           IF (DABS(R1/Y1F).LE.EPS.AND.K.GT.30) GO TO 20
15      CONTINUE
20      Y1D=A
        R=1.0D0
        DO 25 K=1,100
           R=0.5D0*R*X*X/(K*(2.0D0*K+1.0D0))
           R1=H(K+1)*R
           Y1D=Y1D+R1
           IF (DABS(R1/Y1D).LE.EPS.AND.K.GT.30) GO TO 30
25      CONTINUE
30      Y1D=X*Y1D
        D1=1.0D0
        D2=A
        D(1)=1.0D0
        D(2)=A
        DO 40 L2=5,160,2
           M=(L2+1)/2
           DL=A*D2-0.25D0*(L2-2.0D0)*(L2-3.0D0)*D1
           D(M)=DL
           D1=D2
           D2=DL
40      CONTINUE
        Y2F=1.0D0
        R=1.0D0
        DO 45 K=1,100
           R=0.5D0*R*X*X/(K*(2.0D0*K+1.0D0))
           R1=D(K+1)*R
           Y2F=Y2F+R1
           IF (DABS(R1/Y2F).LE.EPS.AND.K.GT.30) GO TO 50
45      CONTINUE
50      Y2F=X*Y2F
        Y2D=1.0D0
        R=1.0D0
        DO 55 K=1,100
           R=0.5D0*R*X*X/(K*(2.0D0*K-1.0D0))
           R1=D(K+1)*R
           Y2D=Y2D+R1
           IF (DABS(R1/Y2D).LE.EPS.AND.K.GT.30) GO TO 60
55      CONTINUE
60      W1F=P0*(F1*Y1F-F2*Y2F)
        W2F=P0*(F1*Y1F+F2*Y2F)
        W1D=P0*(F1*Y1D-F2*Y2D)
        W2D=P0*(F1*Y1D+F2*Y2D)
        RETURN
        END
      REAL FUNCTION PCHDF(K,X,S,IERR)
!***BEGIN PROLOGUE  PCHDF
!***REFER TO  PCHCE,PCHSP
!***END PROLOGUE  PCHDF
      INTEGER  K, IERR
      REAL  X(K), S(K)
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER  I, J
      REAL  VALUE, ZERO
!
      INCLUDE 'DPCOP2.INC'
!
      DATA  ZERO /0./
!
!  CHECK FOR LEGAL VALUE OF K.
!
!***FIRST EXECUTABLE STATEMENT  PCHDF
      IF (K .LT. 3)  GO TO 5001
!
!  COMPUTE COEFFICIENTS OF INTERPOLATING POLYNOMIAL.
!
      DO 10  J = 2, K-1
         DO 9  I = 1, K-J
            S(I) = (S(I+1)-S(I))/(X(I+J)-X(I))
    9    CONTINUE
   10 CONTINUE
!
!  EVALUATE DERIVATIVE AT X(K).
!
      VALUE = S(1)
      DO 20  I = 2, K-1
         VALUE = S(I) + VALUE*(X(K)-X(I))
   20 CONTINUE
!
!  NORMAL RETURN.
!
      IERR = 0
      PCHDF = VALUE
      RETURN
!
!  ERROR RETURN.
!
 5001 CONTINUE
!     K.LT.3 RETURN.
      IERR = -1
!NIST CALL XERROR ('PCHDF -- K LESS THAN THREE'
!NIST*           , 26, IERR, 1)
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
 5011 FORMAT('****** ERROR IN PCHDF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5012)
 5012 FORMAT('       K IS LESS THAN THREE.')
      CALL DPWRST('XXX','BUG ')
      PCHDF = ZERO
      RETURN
!------------- LAST LINE OF PCHDF FOLLOWS ------------------------------
      END FUNCTION PCHDF
      SUBROUTINE PCHEV(N,X,F,D,NVAL,XVAL,FVAL,DVAL,IERR)
!***BEGIN PROLOGUE  PCHEV
!***DATE WRITTEN   870828   (YYMMDD)
!***REVISION DATE  870828   (YYMMDD)
!***CATEGORY NO.  E3,H1
!***KEYWORDS  CUBIC HERMITE OR SPLINE DIFFERENTIATION,CUBIC HERMITE
!             EVALUATION,EASY TO USE SPLINE OR CUBIC HERMITE EVALUATOR
!***AUTHOR  KAHANER, D.K., (NBS)
!             SCIENTIFIC COMPUTING DIVISION
!             NATIONAL BUREAU OF STANDARDS
!             ROOM A161, TECHNOLOGY BUILDING
!             GAITHERSBURG, MARYLAND 20899
!             (301) 975-3808
!***PURPOSE  Evaluates the function and first derivative of a piecewise
!            cubic Hermite or spline function at an array of points XVAL,
!            easy to use.
!***DESCRIPTION
!
!          PCHEV:  Piecewise Cubic Hermite or Spline Derivative Evaluator,
!                  Easy to Use.
!
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!                 Prentice Hall 1988
!
!     Evaluates the function and first derivative of the cubic Hermite
!     or spline function defined by  N, X, F, D, at the array of points XVAL.
!
!     This is an easy to use driver for the routines by F.N. Fritsch
!     described in reference (2) below. Those also have other capabilities.
!
! ----------------------------------------------------------------------
!
!  Calling sequence: CALL  PCHEV (N, X, F, D, NVAL, XVAL, FVAL, DVAL, IERR)
!
!     INTEGER  N, NVAL, IERR
!     REAL  X(N), F(N), D(N), XVAL(NVAL), FVAL(NVAL), DVAL(NVAL)
!
!   Parameters:
!
!     N -- (input) number of data points.  (Error return if N.LT.2 .)
!
!     X -- (input) real array of independent variable values.  The
!           elements of X must be strictly increasing:
!             X(I-1) .LT. X(I),  I = 2(1)N. (Error return if not.)
!
!     F -- (input) real array of function values.  F(I) is
!           the value corresponding to X(I).
!
!     D -- (input) real array of derivative values.  D(I) is
!           the value corresponding to X(I).
!
!  NVAL -- (input) number of points at which the functions are to be
!           evaluated. ( Error return if NVAL.LT.1 )
!
!  XVAL -- (input) real array of points at which the functions are to
!           be evaluated.
!
!          NOTES:
!           1. The evaluation will be most efficient if the elements
!              of XVAL are increasing relative to X;
!              that is,   XVAL(J) .GE. X(I)
!              implies    XVAL(K) .GE. X(I),  all K.GE.J .
!           2. If any of the XVAL are outside the interval [X(1),X(N)],
!              values are extrapolated from the nearest extreme cubic,
!              and a warning error is returned.
!
!  FVAL -- (output) real array of values of the cubic Hermite function
!           defined by  N, X, F, D  at the points  XVAL.
!
!  DVAL -- (output) real array of values of the first derivative of
!           the same function at the points  XVAL.
!
!  IERR -- (output) error flag.
!           Normal return:
!              IERR = 0  (no errors).
!           Warning error:
!              IERR.GT.0  means that extrapolation was performed at
!                 IERR points.
!           "Recoverable" errors:
!              IERR = -1  if N.LT.2 .
!              IERR = -3  if the X-array is not strictly increasing.
!              IERR = -4  if NVAL.LT.1 .
!           (Output arrays have not been changed in any of these cases.)
!               NOTE:  The above errors are checked in the order listed,
!                   and following arguments have **NOT** been validated.
!              IERR = -5  if an error has occurred in the lower-level
!                         routine CHFDV.  NB: this should never happen.
!                         Notify the author **IMMEDIATELY** if it does.
!
! ----------------------------------------------------------------------
!***REFERENCES  1. F.N.FRITSCH AND R.E.CARLSON, 'MONOTONE PIECEWISE
!                 CUBIC INTERPOLATION,' SIAM J.NUMER.ANAL. 17, 2 (APRIL
!                 1980), 238-246.
!               2. F.N.FRITSCH, 'PIECEWISE CUBIC HERMITE INTERPOLATION
!                 PACKAGE, FINAL SPECIFICATIONS', LAWRENCE LIVERMORE
!                 NATIONAL LABORATORY, COMPUTER DOCUMENTATION UCID-30194,
!                 AUGUST 1982.
!***ROUTINES CALLED  PCHFD
!***END PROLOGUE  PCHEV
      INTEGER  N, NVAL, IERR
      REAL  X(N), F(N), D(N), XVAL(NVAL), FVAL(NVAL), DVAL(NVAL)
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER INCFD
      LOGICAL SKIP
!
      INCLUDE 'DPCOP2.INC'
!
      DATA SKIP /.TRUE./
      DATA INCFD /1/
                                                                                                                                  
!
!
!***FIRST EXECUTABLE STATEMENT  PCHEV
!
      CALL PCHFD(N,X,F,D,INCFD,SKIP,NVAL,XVAL,FVAL,DVAL,IERR)
!
      RETURN
!
!------------- LAST LINE OF PCHEV FOLLOWS ------------------------------
      END SUBROUTINE PCHEV
      SUBROUTINE PCHEZ(N,X,F,D,SPLINE,WK,LWK,IERR)
!***BEGIN PROLOGUE  PCHEZ
!***DATE WRITTEN   870821   (YYMMDD)
!***REVISION DATE  870908   (YYMMDD)
!***CATEGORY NO.  E1B
!***KEYWORDS  CUBIC HERMITE MONOTONE INTERPOLATION, SPLINE
!             INTERPOLATION, EASY TO USE PIECEWISE CUBIC INTERPOLATION
!***AUTHOR  KAHANER, D.K., (NBS)
!             SCIENTIFIC COMPUTING DIVISION
!             NATIONAL BUREAU OF STANDARDS
!             GAITHERSBURG, MARYLAND 20899
!             (301) 975-3808
!***PURPOSE  Easy to use spline or cubic Hermite interpolation.
!***DESCRIPTION
!
!          PCHEZ:  Piecewise Cubic Interpolation, Easy to Use.
!
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!
!     Sets derivatives for spline (two continuous derivatives) or
!     Hermite cubic (one continuous derivative) interpolation.
!     Spline interpolation is smoother, but may not "look" right if the
!     data contains both "steep" and "flat" sections.  Hermite cubics
!     can produce a "visually pleasing" and monotone interpolant to
!     monotone data. This is an easy to use driver for the routines
!     by F. N. Fritsch in reference (4) below. Various boundary
!     conditions are set to default values by PCHEZ. Many other choices
!     are available in the subroutines PCHIC, PCHIM and PCHSP.
!
!     Use PCHEV to evaluate the resulting function and its derivative.
!
! ----------------------------------------------------------------------
!
!  Calling sequence:   CALL  PCHEZ (N, X, F, D, SPLINE, WK, LWK, IERR)
!
!     INTEGER  N, IERR,  LWK
!     REAL  X(N), F(N), D(N), WK(*)
!     LOGICAL SPLINE
!
!   Parameters:
!
!     N -- (input) number of data points.  (Error return if N.LT.2 .)
!           If N=2, simply does linear interpolation.
!
!     X -- (input) real array of independent variable values.  The
!           elements of X must be strictly increasing:
!                X(I-1) .LT. X(I),  I = 2(1)N.
!           (Error return if not.)
!
!     F -- (input) real array of dependent variable values to be inter-
!           polated.  F(I) is value corresponding to X(I).
!
!     D -- (output) real array of derivative values at the data points.
!
!     SPLINE -- (input) logical variable to specify if the interpolant
!           is to be a spline with two continuous derivaties
!           (set SPLINE=.TRUE.) or a Hermite cubic interpolant with one
!           continuous derivative (set SPLINE=.FALSE.).
!        Note: If SPLINE=.TRUE. the interpolating spline satisfies the
!           default "not-a-knot" boundary condition, with a continuous
!           third derivative at X(2) and X(N-1). See reference (3).
!              If SPLINE=.FALSE. the interpolating Hermite cubic will be
!           monotone if the input data is monotone. Boundary conditions are
!           computed from the derivative of a local quadratic unless this
!           alters monotonicity.
!
!     WK -- (scratch) real work array, which must be declared by the calling
!           program to be at least 2*N if SPLINE is .TRUE. and not used
!           otherwise.
!
!     LWK -- (input) length of work array WK. (Error return if
!           LWK.LT.2*N and SPLINE is .TRUE., not checked otherwise.)
!
!     IERR -- (output) error flag.
!           Normal return:
!              IERR = 0  (no errors).
!           Warning error:
!              IERR.GT.0  (can only occur when SPLINE=.FALSE.) means that
!                 IERR switches in the direction of monotonicity were detected.
!                 When SPLINE=.FALSE.,  PCHEZ guarantees that if the input
!                 data is monotone, the interpolant will be too. This warning
!                 is to alert you to the fact that the input data was not
!                 monotone.
!           "Recoverable" errors:
!              IERR = -1  if N.LT.2 .
!              IERR = -3  if the X-array is not strictly increasing.
!              IERR = -7  if LWK is less than 2*N and SPLINE is .TRUE.
!             (The D-array has not been changed in any of these cases.)
!               NOTE:  The above errors are checked in the order listed,
!                   and following arguments have **NOT** been validated.
!
! ----------------------------------------------------------------------
!***REFERENCES  1. F.N.FRITSCH AND R.E.CARLSON, 'MONOTONE PIECEWISE
!                 CUBIC INTERPOLATION,' SIAM J.NUMER.ANAL. 17, 2 (APRIL
!                 1980), 238-246.
!               2. F.N.FRITSCH AND J.BUTLAND, 'A METHOD FOR CONSTRUCTING
!                 LOCAL MONOTONE PIECEWISE CUBIC INTERPOLANTS,' LLNL
!                 PREPRINT UCRL-87559 (APRIL 1982).
!               3. CARL DE BOOR, A PRACTICAL GUIDE TO SPLINES, SPRINGER-
!                 VERLAG (NEW YORK, 1978).  (ESP. CHAPTER IV, PP.49-62.)
!               4. F.N.FRITSCH, 'PIECEWISE CUBIC HERMITE INTERPOLATION
!                 PACKAGE, FINAL SPECIFICATIONS', LAWRENCE LIVERMORE
!                 NATIONAL LABORATORY, COMPUTER DOCUMENTATION UCID-30194,
!                 AUGUST 1982.
!***ROUTINES CALLED  PCHIM,PCHSP
!***END PROLOGUE  PCHEZ
      INTEGER  N, LWK, IERR
      REAL  X(N), F(N), D(N), WK(LWK)
      LOGICAL SPLINE
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER IC(2), INCFD
      REAL  VC(2)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA IC(1) /0/
      DATA IC(2) /0/
      DATA INCFD /1/
!
!
!***FIRST EXECUTABLE STATEMENT  PCHEZ
!
      IF ( SPLINE ) THEN
        CALL  PCHSP (IC, VC, N, X, F, D, INCFD, WK, LWK, IERR)
      ELSE
        CALL  PCHIM (N, X, F, D, INCFD, IERR)
      ENDIF
!
!  ERROR CONDITIONS ALREADY CHECKED IN PCHSP OR PCHIM
                                                                                                                                  
      RETURN
!------------- LAST LINE OF PCHEZ FOLLOWS ------------------------------
      END SUBROUTINE PCHEZ
      SUBROUTINE PCHFD(N,X,F,D,INCFD,SKIP,NE,XE,FE,DE,IERR)
!***BEGIN PROLOGUE  PCHFD
!     THIS PROLOGUE HAS BEEN REMOVED FOR REASONS OF SPACE
!     FOR A COMPLETE COPY OF THIS ROUTINE CONTACT THE AUTHORS
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!***END PROLOGUE  PCHFD
!
!  DECLARE ARGUMENTS.
!
      INTEGER  N, INCFD, NE, IERR
      REAL  X(N), F(INCFD,N), D(INCFD,N), XE(NE), FE(NE), DE(NE)
      LOGICAL  SKIP
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER  I, IERC, IR, J, JFIRST, NEXT(2), NJ
!
      INCLUDE 'DPCOP2.INC'
!
!
!  VALIDITY-CHECK ARGUMENTS.
!
!***FIRST EXECUTABLE STATEMENT  PCHFD
      IF (SKIP)  GO TO 5
!
      IF ( N.LT.2 )  GO TO 5001
      IF ( INCFD.LT.1 )  GO TO 5002
      DO 1  I = 2, N
         IF ( X(I).LE.X(I-1) )  GO TO 5003
    1 CONTINUE
!
!  FUNCTION DEFINITION IS OK, GO ON.
!
    5 CONTINUE
      IF ( NE.LT.1 )  GO TO 5004
      IERR = 0
      SKIP = .TRUE.
!
!  LOOP OVER INTERVALS.        (   INTERVAL INDEX IS  IL = IR-1  . )
!                              ( INTERVAL IS X(IL).LE.X.LT.X(IR) . )
      JFIRST = 1
      IR = 2
   10 CONTINUE
!
!     SKIP OUT OF LOOP IF HAVE PROCESSED ALL EVALUATION POINTS.
!
         IF (JFIRST .GT. NE)  GO TO 5000
!
!     LOCATE ALL POINTS IN INTERVAL.
!
         DO 20  J = JFIRST, NE
            IF (XE(J) .GE. X(IR))  GO TO 30
   20    CONTINUE
         J = NE + 1
         GO TO 40
!
!     HAVE LOCATED FIRST POINT BEYOND INTERVAL.
!
   30    CONTINUE
         IF (IR .EQ. N)  J = NE + 1
!
   40    CONTINUE
         NJ = J - JFIRST
!
!     SKIP EVALUATION IF NO POINTS IN INTERVAL.
!
         IF (NJ .EQ. 0)  GO TO 50
!
!     EVALUATE CUBIC AT XE(I),  I = JFIRST (1) J-1 .
!
!       ----------------------------------------------------------------
        CALL CHFDV (X(IR-1),X(IR), F(1,IR-1),F(1,IR), D(1,IR-1),D(1,IR),   &
                    NJ, XE(JFIRST), FE(JFIRST), DE(JFIRST), NEXT, IERC)
!       ----------------------------------------------------------------
         IF (IERC .LT. 0)  GO TO 5005
!
         IF (NEXT(2) .EQ. 0)  GO TO 42
!        IF (NEXT(2) .GT. 0)  THEN
!           IN THE CURRENT SET OF XE-POINTS, THERE ARE NEXT(2) TO THE
!           RIGHT OF X(IR).
!
            IF (IR .LT. N)  GO TO 41
!           IF (IR .EQ. N)  THEN
!              THESE ARE ACTUALLY EXTRAPOLATION POINTS.
               IERR = IERR + NEXT(2)
               GO TO 42
   41       CONTINUE
!           ELSE
!              WE SHOULD NEVER HAVE GOTTEN HERE.
               GO TO 5005
!           ENDIF
!        ENDIF
   42    CONTINUE
!
         IF (NEXT(1) .EQ. 0)  GO TO 49
!        IF (NEXT(1) .GT. 0)  THEN
!           IN THE CURRENT SET OF XE-POINTS, THERE ARE NEXT(1) TO THE
!           LEFT OF X(IR-1).
!
            IF (IR .GT. 2)  GO TO 43
!           IF (IR .EQ. 2)  THEN
!              THESE ARE ACTUALLY EXTRAPOLATION POINTS.
               IERR = IERR + NEXT(1)
               GO TO 49
   43       CONTINUE
!           ELSE
!              XE IS NOT ORDERED RELATIVE TO X, SO MUST ADJUST
!              EVALUATION INTERVAL.
!
!              FIRST, LOCATE FIRST POINT TO LEFT OF X(IR-1).
               DO 44  I = JFIRST, J-1
                  IF (XE(I) .LT. X(IR-1))  GO TO 45
   44          CONTINUE
!              NOTE-- CANNOT DROP THROUGH HERE UNLESS THERE IS AN ERROR
!                     IN CHFDV.
               GO TO 5005
!
   45          CONTINUE
!              RESET J.  (THIS WILL BE THE NEW JFIRST.)
               J = I
!
!              NOW FIND OUT HOW FAR TO BACK UP IN THE X-ARRAY.
               DO 46  I = 1, IR-1
                  IF (XE(J) .LT. X(I)) GO TO 47
   46          CONTINUE
!              NB-- CAN NEVER DROP THROUGH HERE, SINCE XE(J).LT.X(IR-1).
!
   47          CONTINUE
!              AT THIS POINT, EITHER  XE(J) .LT. X(1)
!                 OR      X(I-1) .LE. XE(J) .LT. X(I) .
!              RESET IR, RECOGNIZING THAT IT WILL BE INCREMENTED BEFORE
!              CYCLING.
               IR = MAX0(1, I-1)
!           ENDIF
!        ENDIF
   49    CONTINUE
!
         JFIRST = J
!
!     END OF IR-LOOP.
!
   50 CONTINUE
      IR = IR + 1
      IF (IR .LE. N)  GO TO 10
!
!  NORMAL RETURN.
!
 5000 CONTINUE
      RETURN
!
!  ERROR RETURNS.
!
 5001 CONTINUE
!     N.LT.2 RETURN.
      IERR = -1
!NIST CALL XERROR ('PCHFD -- NUMBER OF DATA POINTS LESS THAN TWO'
!NIST*           , 44, IERR, 1)
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
 5011 FORMAT('****** ERROR IN PCHFD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5012)
 5012 FORMAT('       THE NUMBER OF DATA POINTS IS LESS THAN TWO.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5002 CONTINUE
!     INCFD.LT.1 RETURN.
      IERR = -2
!NIST CALL XERROR ('PCHFD -- INCREMENT LESS THAN ONE'
!NIST*           , 32, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5022)
 5022 FORMAT('       THE INCREMENT IS LESS THAN ONE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5003 CONTINUE
!     X-ARRAY NOT STRICTLY INCREASING.
      IERR = -3
!NIST CALL XERROR ('PCHFD -- X-ARRAY NOT STRICTLY INCREASING'
!NIST*           , 40, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5032)
 5032 FORMAT('       THE X-ARRAY IS NOT STRICTLY INCREASING.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5004 CONTINUE
!     NE.LT.1 RETURN.
      IERR = -4
!NIST CALL XERROR ('PCHFD -- NUMBER OF EVALUATION POINTS LESS THAN ONE'
!NIST*           , 50, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5042)
 5042 FORMAT('       THE NUMBER OF EVALUATION POINTS IS LESS THAN ONE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5005 CONTINUE
!     ERROR RETURN FROM CHFDV.
!   *** THIS CASE SHOULD NEVER OCCUR ***
      IERR = -5
!NIST CALL XERROR ('PCHFD -- ERROR RETURN FROM CHFDV -- FATAL'
!NIST*           , 41, IERR, 2)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5052)
 5052 FORMAT('       ERROR RETURN FROM CHFDV.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!------------- LAST LINE OF PCHFD FOLLOWS ------------------------------
      END SUBROUTINE PCHFD
      REAL FUNCTION PCHIA(N,X,F,D,INCFD,SKIP,A,B,IERR)
!***BEGIN PROLOGUE  PCHIA
!     THIS PROLOGUE HAS BEEN REMOVED FOR REASONS OF SPACE
!     FOR A COMPLETE COPY OF THIS ROUTINE CONTACT THE AUTHORS
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!***END PROLOGUE  PCHIA
!
!  DECLARE ARGUMENTS.
!
      INTEGER  N, INCFD, IERR
      REAL  X(N), F(INCFD,N), D(INCFD,N), A, B
      LOGICAL  SKIP
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER  I, IA, IB, IERD, IERV, IL, IR
      REAL  VALUE, XA, XB, ZERO
      REAL  CHFIV, PCHID
!
      INCLUDE 'DPCOP2.INC'
!
!  INITIALIZE.
!
      DATA  ZERO /0./
!
!  VALIDITY-CHECK ARGUMENTS.
!
      PCHIA = CPUMIN
!
!***FIRST EXECUTABLE STATEMENT  PCHIA
      IF (SKIP)  GO TO 5
!
      IF ( N.LT.2 )  GO TO 5001
      IF ( INCFD.LT.1 )  GO TO 5002
      DO 1  I = 2, N
         IF ( X(I).LE.X(I-1) )  GO TO 5003
    1 CONTINUE
!
!  FUNCTION DEFINITION IS OK, GO ON.
!
    5 CONTINUE
      SKIP = .TRUE.
      IERR = 0
      IF ( (A.LT.X(1)) .OR. (A.GT.X(N)) )  IERR = IERR + 1
      IF ( (B.LT.X(1)) .OR. (B.GT.X(N)) )  IERR = IERR + 2
!
!  COMPUTE INTEGRAL VALUE.
!
      IF (A .EQ. B)  THEN
         VALUE = ZERO
      ELSE
         XA = AMIN1 (A, B)
         XB = AMAX1 (A, B)
         IF (XB .LE. X(2))  THEN
!           INTERVAL IS TO LEFT OF X(2), SO USE FIRST CUBIC.
!                   --------------------------------------------
            VALUE = CHFIV (X(1),X(2), F(1,1),F(1,2),   &
                                      D(1,1),D(1,2), A, B, IERV)
!                   --------------------------------------------
            IF (IERV .LT. 0)  GO TO 5004
         ELSE IF (XA .GE. X(N-1))  THEN
!           INTERVAL IS TO RIGHT OF X(N-1), SO USE LAST CUBIC.
!                   -----------------------------------------------
            VALUE = CHFIV(X(N-1),X(N), F(1,N-1),F(1,N),   &
                                       D(1,N-1),D(1,N), A, B, IERV)
!                   -----------------------------------------------
            IF (IERV .LT. 0)  GO TO 5004
         ELSE
!           'NORMAL' CASE -- XA.LT.XB, XA.LT.X(N-1), XB.GT.X(2).
!      ......LOCATE IA AND IB SUCH THAT
!               X(IA-1).LT.XA.LE.X(IA).LE.X(IB).LE.XB.LE.X(IB+1)
            IA = 1
            DO 10  I = 1, N-1
               IF (XA .GT. X(I))  IA = I + 1
   10       CONTINUE
!             IA = 1 IMPLIES XA.LT.X(1) .  OTHERWISE,
!             IA IS LARGEST INDEX SUCH THAT X(IA-1).LT.XA,.
!
            IB = N
            DO 20  I = N, IA, -1
               IF (XB .LT. X(I))  IB = I - 1
   20       CONTINUE
!             IB = N IMPLIES XB.GT.X(N) .  OTHERWISE,
!             IB IS SMALLEST INDEX SUCH THAT XB.LT.X(IB+1) .
!
!     ......COMPUTE THE INTEGRAL.
            IERV = 0
            IF (IB .LT. IA)  THEN
!              THIS MEANS IB = IA-1 AND
!                 (A,B) IS A SUBSET OF (X(IB),X(IA)).
!                      ------------------------------------------------
               VALUE = CHFIV (X(IB),X(IA), F(1,IB),F(1,IA),   &
                                           D(1,IB),D(1,IA), A, B, IERV)
!                      ------------------------------------------------
               IF (IERV .LT. 0)  GO TO 5004
            ELSE
!
!              FIRST COMPUTE INTEGRAL OVER (X(IA),X(IB)).
               IF (IB .EQ. IA)  THEN
                  VALUE = ZERO
               ELSE
!                         ---------------------------------------------
                  VALUE = PCHID (N, X, F, D, INCFD, SKIP, IA, IB, IERD)
!                         ---------------------------------------------
                  IF (IERD .LT. 0)  GO TO 5005
               ENDIF
!
!              THEN ADD ON INTEGRAL OVER (XA,X(IA)).
               IF (XA .LT. X(IA))  THEN
                  IL = MAX0 (1, IA-1)
                  IR = IL + 1
!                                 -------------------------------------
                  VALUE = VALUE + CHFIV (X(IL),X(IR), F(1,IL),F(1,IR),   &
                                      D(1,IL),D(1,IR), XA, X(IA), IERV)
!                                 -------------------------------------
                  IF (IERV .LT. 0)  GO TO 5004
               ENDIF
!
!              THEN ADD ON INTEGRAL OVER (X(IB),XB).
               IF (XB .GT. X(IB))  THEN
                  IR = MIN0 (IB+1, N)
                  IL = IR - 1
!                                 -------------------------------------
                  VALUE = VALUE + CHFIV (X(IL),X(IR), F(1,IL),F(1,IR),   &
                                      D(1,IL),D(1,IR), X(IB), XB, IERV)
!                                 -------------------------------------
                  IF (IERV .LT. 0)  GO TO 5004
               ENDIF
!
!              FINALLY, ADJUST SIGN IF NECESSARY.
               IF (A .GT. B)  VALUE = -VALUE
            ENDIF
         ENDIF
      ENDIF
!
!  NORMAL RETURN.
!
      PCHIA = VALUE
      RETURN
!
!  ERROR RETURNS.
!
 5001 CONTINUE
!     N.LT.2 RETURN.
      IERR = -1
!NIST CALL XERROR ('PCHIA -- NUMBER OF DATA POINTS LESS THAN TWO'
!NIST*           , 44, IERR, 1)
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
 5011 FORMAT('****** ERROR IN PCHIA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5012)
 5012 FORMAT('       THE NUMBER OF DATA POINTS IS LESS THAN TWO.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5002 CONTINUE
!     INCFD.LT.1 RETURN.
      IERR = -2
!NIST CALL XERROR ('PCHIA -- INCREMENT LESS THAN ONE'
!NIST*           , 32, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5022)
 5022 FORMAT('       THE INCREMENT IS LESS THAN ONE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5003 CONTINUE
!     X-ARRAY NOT STRICTLY INCREASING.
      IERR = -3
!NIST CALL XERROR ('PCHIA -- X-ARRAY NOT STRICTLY INCREASING'
!NIST*           , 40, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5032)
 5032 FORMAT('       THE X-ARRAY IS NOT STRICTLY INCREASING.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5004 CONTINUE
!     TROUBLE IN CHFIV.  (SHOULD NEVER OCCUR.)
      IERR = -4
!NIST CALL XERROR ('PCHIA -- TROUBLE IN CHFIV'
!NIST*           , 25, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5042)
 5042 FORMAT('       TROUBLE IN CHFIV.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5005 CONTINUE
!     TROUBLE IN PCHID.  (SHOULD NEVER OCCUR.)
      IERR = -5
!NIST CALL XERROR ('PCHIA -- TROUBLE IN PCHID'
!NIST*           , 25, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5052)
 5052 FORMAT('       TROUBLE IN PCHID.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!------------- LAST LINE OF PCHIA FOLLOWS ------------------------------
      END FUNCTION PCHIA
      REAL FUNCTION PCHID(N,X,F,D,INCFD,SKIP,IA,IB,IERR)
!***BEGIN PROLOGUE  PCHID
!     THIS PROLOGUE HAS BEEN REMOVED FOR REASONS OF SPACE
!     FOR A COMPLETE COPY OF THIS ROUTINE CONTACT THE AUTHORS
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!***END PROLOGUE  PCHID
!
!  DECLARE ARGUMENTS.
!
      INTEGER  N, INCFD, IA, IB, IERR
      REAL  X(N), F(INCFD,N), D(INCFD,N)
      LOGICAL  SKIP
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER  I, IUP, LOW
      REAL  H, HALF, SIX, SUM, VALUE, ZERO
!
      INCLUDE 'DPCOP2.INC'
!
!  INITIALIZE.
!
      DATA  ZERO /0./,  HALF /0.5/,  SIX /6./
!
      PCHID = CPUMIN
!
!  VALIDITY-CHECK ARGUMENTS.
!
!***FIRST EXECUTABLE STATEMENT  PCHID
      IF (SKIP)  GO TO 5
!
      IF ( N.LT.2 )  GO TO 5001
      IF ( INCFD.LT.1 )  GO TO 5002
      DO 1  I = 2, N
         IF ( X(I).LE.X(I-1) )  GO TO 5003
    1 CONTINUE
!
!  FUNCTION DEFINITION IS OK, GO ON.
!
    5 CONTINUE
      SKIP = .TRUE.
      IF ((IA.LT.1) .OR. (IA.GT.N))  GO TO 5004
      IF ((IB.LT.1) .OR. (IB.GT.N))  GO TO 5004
      IERR = 0
!
!  COMPUTE INTEGRAL VALUE.
!
      IF (IA .EQ. IB)  THEN
         VALUE = ZERO
      ELSE
         LOW = MIN0(IA, IB)
         IUP = MAX0(IA, IB) - 1
         SUM = ZERO
         DO 10  I = LOW, IUP
            H = X(I+1) - X(I)
            SUM = SUM + H*( (F(1,I) + F(1,I+1)) +   &
                            (D(1,I) - D(1,I+1))*(H/SIX) )
   10    CONTINUE
         VALUE = HALF * SUM
         IF (IA .GT. IB)  VALUE = -VALUE
      ENDIF
!
!  NORMAL RETURN.
!
      PCHID = VALUE
      RETURN
!
!  ERROR RETURNS.
!
 5001 CONTINUE
!     N.LT.2 RETURN.
      IERR = -1
!NIST CALL XERROR ('PCHID -- NUMBER OF DATA POINTS LESS THAN TWO'
!NIST*           , 44, IERR, 1)
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
 5011 FORMAT('****** ERROR IN PCHID--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5012)
 5012 FORMAT('       THE NUMBER OF DATA POINTS IS LESS THAN TWO.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5002 CONTINUE
!     INCFD.LT.1 RETURN.
      IERR = -2
!NIST CALL XERROR ('PCHID -- INCREMENT LESS THAN ONE'
!NIST*           , 32, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5022)
 5022 FORMAT('       THE INCREMENT IS LESS THAN ONE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5003 CONTINUE
!     X-ARRAY NOT STRICTLY INCREASING.
      IERR = -3
!NIST CALL XERROR ('PCHID -- X-ARRAY NOT STRICTLY INCREASING'
!NIST*           , 40, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5032)
 5032 FORMAT('       THE X-ARRAY IS NOT STRICTLY INCREASING.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5004 CONTINUE
!     IA OR IB OUT OF RANGE RETURN.
      IERR = -4
!NIST CALL XERROR ('PCHID -- IA OR IB OUT OF RANGE'
!NIST*           , 30, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5042)
 5042 FORMAT('       IA OR IB IS OUT OF RANGE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!------------- LAST LINE OF PCHID FOLLOWS ------------------------------
      END FUNCTION PCHID
      SUBROUTINE PCHIM(N,X,F,D,INCFD,IERR)
!***BEGIN PROLOGUE  PCHIM
!     THIS PROLOGUE HAS BEEN REMOVED FOR REASONS OF SPACE
!     FOR A COMPLETE COPY OF THIS ROUTINE CONTACT THE AUTHORS
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!***END PROLOGUE  PCHIM
!
!  DECLARE ARGUMENTS.
!
      INTEGER  N, INCFD, IERR
      REAL  X(N), F(INCFD,N), D(INCFD,N)
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER  I, NLESS1
      REAL  DEL1, DEL2, DMAX, DMIN, DRAT1, DRAT2, DSAVE,   &
            H1, H2, HSUM, HSUMT3, THREE, W1, W2, ZERO
      REAL  PCHST
!
      INCLUDE 'DPCOP2.INC'
!
      DATA  ZERO /0./,  THREE /3./
!
!  VALIDITY-CHECK ARGUMENTS.
!
!***FIRST EXECUTABLE STATEMENT  PCHIM
      IF ( N.LT.2 )  GO TO 5001
      IF ( INCFD.LT.1 )  GO TO 5002
      DO 1  I = 2, N
         IF ( X(I).LE.X(I-1) )  GO TO 5003
    1 CONTINUE
!
!  FUNCTION DEFINITION IS OK, GO ON.
!
      IERR = 0
      NLESS1 = N - 1
      H1 = X(2) - X(1)
      DEL1 = (F(1,2) - F(1,1))/H1
      DSAVE = DEL1
!
!  SPECIAL CASE N=2 -- USE LINEAR INTERPOLATION.
!
      IF (NLESS1 .GT. 1)  GO TO 10
      D(1,1) = DEL1
      D(1,N) = DEL1
      GO TO 5000
!
!  NORMAL CASE  (N .GE. 3).
!
   10 CONTINUE
      H2 = X(3) - X(2)
      DEL2 = (F(1,3) - F(1,2))/H2
!
!  SET D(1) VIA NON-CENTERED THREE-POINT FORMULA, ADJUSTED TO BE
!     SHAPE-PRESERVING.
!
      HSUM = H1 + H2
      W1 = (H1 + HSUM)/HSUM
      W2 = -H1/HSUM
      D(1,1) = W1*DEL1 + W2*DEL2
      IF ( PCHST(D(1,1),DEL1) .LE. ZERO)  THEN
         D(1,1) = ZERO
      ELSE IF ( PCHST(DEL1,DEL2) .LT. ZERO)  THEN
!        NEED DO THIS CHECK ONLY IF MONOTONICITY SWITCHES.
         DMAX = THREE*DEL1
         IF (ABS(D(1,1)) .GT. ABS(DMAX))  D(1,1) = DMAX
      ENDIF
!
!  LOOP THROUGH INTERIOR POINTS.
!
      DO 50  I = 2, NLESS1
         IF (I .EQ. 2)  GO TO 40
!
         H1 = H2
         H2 = X(I+1) - X(I)
         HSUM = H1 + H2
         DEL1 = DEL2
         DEL2 = (F(1,I+1) - F(1,I))/H2
   40    CONTINUE
!
!        SET D(I)=0 UNLESS DATA ARE STRICTLY MONOTONIC.
!
         D(1,I) = ZERO
         IF ( PCHST(DEL1,DEL2) .LT.0.0)THEN
            GO TO 42
         ELSEIF ( PCHST(DEL1,DEL2) .EQ.0.0)THEN
            GO TO 41
         ELSEIF ( PCHST(DEL1,DEL2) .GT.0.0)THEN
            GO TO 45
         ENDIF
!
!        COUNT NUMBER OF CHANGES IN DIRECTION OF MONOTONICITY.
!
   41    CONTINUE
         IF (DEL2 .EQ. ZERO)  GO TO 50
         IF ( PCHST(DSAVE,DEL2) .LT. ZERO)  IERR = IERR + 1
         DSAVE = DEL2
         GO TO 50
!
   42    CONTINUE
         IERR = IERR + 1
         DSAVE = DEL2
         GO TO 50
!
!        USE BRODLIE MODIFICATION OF BUTLAND FORMULA.
!
   45    CONTINUE
         HSUMT3 = HSUM+HSUM+HSUM
         W1 = (HSUM + H1)/HSUMT3
         W2 = (HSUM + H2)/HSUMT3
         DMAX = AMAX1( ABS(DEL1), ABS(DEL2) )
         DMIN = AMIN1( ABS(DEL1), ABS(DEL2) )
         DRAT1 = DEL1/DMAX
         DRAT2 = DEL2/DMAX
         D(1,I) = DMIN/(W1*DRAT1 + W2*DRAT2)
!
   50 CONTINUE
!
!  SET D(N) VIA NON-CENTERED THREE-POINT FORMULA, ADJUSTED TO BE
!     SHAPE-PRESERVING.
!
      W1 = -H2/HSUM
      W2 = (H2 + HSUM)/HSUM
      D(1,N) = W1*DEL1 + W2*DEL2
      IF ( PCHST(D(1,N),DEL2) .LE. ZERO)  THEN
         D(1,N) = ZERO
      ELSE IF ( PCHST(DEL1,DEL2) .LT. ZERO)  THEN
!        NEED DO THIS CHECK ONLY IF MONOTONICITY SWITCHES.
         DMAX = THREE*DEL2
         IF (ABS(D(1,N)) .GT. ABS(DMAX))  D(1,N) = DMAX
      ENDIF
!
!  NORMAL RETURN.
!
 5000 CONTINUE
      RETURN
!
!  ERROR RETURNS.
!
 5001 CONTINUE
!     N.LT.2 RETURN.
      IERR = -1
!NIST CALL XERROR ('PCHIM -- NUMBER OF DATA POINTS LESS THAN TWO'
!NIST*           , 44, IERR, 1)
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
 5011 FORMAT('****** ERROR IN PCHIM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5012)
 5012 FORMAT('       THE NUMBER OF DATA POINTS IS LESS THAN TWO.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5002 CONTINUE
!     INCFD.LT.1 RETURN.
      IERR = -2
!NIST CALL XERROR ('PCHIM -- INCREMENT LESS THAN ONE'
!NIST*           , 32, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5022)
 5022 FORMAT('       THE INCREMENT IS LESS THAN ONE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
      RETURN
!
 5003 CONTINUE
!     X-ARRAY NOT STRICTLY INCREASING.
      IERR = -3
!NIST CALL XERROR ('PCHIM -- X-ARRAY NOT STRICTLY INCREASING'
!NIST*           , 40, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5032)
 5032 FORMAT('       THE X-ARRAY IS NOT STRICTLY INCREASING.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!------------- LAST LINE OF PCHIM FOLLOWS ------------------------------
      END SUBROUTINE PCHIM
      REAL FUNCTION PCHQA(N,X,F,D,A,B,IERR)
!***BEGIN PROLOGUE  PCHQA
!***DATE WRITTEN   870829   (YYMMDD)
!***REVISION DATE  870829   (YYMMDD)
!***CATEGORY NO.  E3,H2A2
!***KEYWORDS  EASY TO USE CUBIC HERMITE OR SPLINE INTEGRATION
!             NUMERICAL INTEGRATION, QUADRATURE
!***AUTHOR  KAHANER, D.K., (NBS)
!             SCIENTIFIC COMPUTING DIVISION
!             NATIONAL BUREAU OF STANDARDS
!             ROOM A161, TECHNOLOGY BUILDING
!             GAITHERSBURG, MARYLAND 20899
!             (301) 975-3808
!***PURPOSE  Evaluates the definite integral of a piecewise cubic Hermite
!            or spline function over an arbitrary interval, easy to use.
!***DESCRIPTION
!
!          PCHQA:  Piecewise Cubic Hermite or Spline Integrator,
!                  Arbitrary limits, Easy to Use.
!
!          From the book "Numerical Methods and Software"
!                  by  D. Kahaner, C. Moler, S. Nash
!                          Prentice Hall 1988
!
!     Evaluates the definite integral of the cubic Hermite or spline
!     function defined by  N, X, F, D  over the interval [A, B].  This
!     is an easy to use driver for the routine PCHIA by F.N. Fritsch
!     described in reference (2) below. That routine also has other
!     capabilities.
! ----------------------------------------------------------------------
!
!  Calling sequence:
!
!           VALUE = PCHQA (N, X, F, D, A, B, IERR)
!
!     INTEGER  N, IERR
!     REAL  X(N), F(N), D(N), A, B
!
!   Parameters:
!
!     VALUE -- (output) VALUE of the requested integral.
!
!     N -- (input) number of data points.  (Error return if N.LT.2 .)
!
!     X -- (input) real array of independent variable values.  The
!           elements of X must be strictly increasing:
!                X(I-1) .LT. X(I),  I = 2(1)N.
!           (Error return if not.)
!
!     F -- (input) real array of function values.  F(I) is
!           the value corresponding to X(I).
!
!     D -- (input) real array of derivative values.  D(I) is
!           the value corresponding to X(I).
!
!     A,B -- (input) the limits of integration.
!           NOTE:  There is no requirement that [A,B] be contained in
!                  [X(1),X(N)].  However, the resulting integral value
!                  will be highly suspect, if not.
!
!     IERR -- (output) error flag.
!           Normal return:
!              IERR = 0  (no errors).
!           Warning errors:
!              IERR = 1  if  A  is outside the interval [X(1),X(N)].
!              IERR = 2  if  B  is outside the interval [X(1),X(N)].
!              IERR = 3  if both of the above are true.  (Note that this
!                        means that either [A,B] contains data interval
!                        or the intervals do not intersect at all.)
!           "Recoverable" errors:
!              IERR = -1  if N.LT.2 .
!              IERR = -3  if the X-array is not strictly increasing.
!                (Value has not been computed in any of these cases.)
!               NOTE:  The above errors are checked in the order listed,
!                   and following arguments have **NOT** been validated.
!
!***REFERENCES  1. F.N.FRITSCH AND R.E.CARLSON, 'MONOTONE PIECEWISE
!                 CUBIC INTERPOLATION,' SIAM J.NUMER.ANAL. 17, 2 (APRIL
!                 1980), 238-246.
!               2. F.N.FRITSCH, 'PIECEWISE CUBIC HERMITE INTERPOLATION
!                 PACKAGE, FINAL SPECIFICATIONS', LAWRENCE LIVERMORE
!                 NATIONAL LABORATORY, COMPUTER DOCUMENTATION UCID-30194,
!                 AUGUST 1982.
!***ROUTINES CALLED  PCHIA
!***END PROLOGUE  PCHQA
      INTEGER  N, IERR
      REAL  X(N), F(N), D(N), A, B
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER  INCFD
      REAL  PCHIA
      LOGICAL SKIP
!
      INCLUDE 'DPCOP2.INC'
!
!  INITIALIZE.
!
      DATA  INCFD /1/
      DATA  SKIP /.TRUE./
!
!
!***FIRST EXECUTABLE STATEMENT  PCHQA
                                                                                                                                  
      PCHQA  =  PCHIA( N, X, F, D, INCFD, SKIP, A, B, IERR )
!
! ERROR MESSAGES ARE FROM LOWER LEVEL ROUTINES
      RETURN
!
!------------- LAST LINE OF PCHQA FOLLOWS ------------------------------
      END FUNCTION PCHQA
      SUBROUTINE PCHSP(IC,VC,N,X,F,D,INCFD,WK,NWK,IERR)
!***BEGIN PROLOGUE  PCHSP
!     THIS PROLOGUE HAS BEEN REMOVED FOR REASONS OF SPACE
!     FOR A COMPLETE COPY OF THIS ROUTINE CONTACT THE AUTHORS
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!***END PROLOGUE  PCHSP
!
!  DECLARE ARGUMENTS.
!
      INTEGER  IC(2), N, INCFD, NWK, IERR
      REAL  VC(2), X(N), F(INCFD,N), D(INCFD,N), WK(2,N)
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER  IBEG, IEND, INDEX, J, NM1
      REAL  G, HALF, ONE, STEMP(3), THREE, TWO, XTEMP(4), ZERO
      REAL  PCHDF
!
      INCLUDE 'DPCOP2.INC'
!
      DATA  ZERO /0./,  HALF /0.5/,  ONE /1./,  TWO /2./,  THREE /3./
!
!  VALIDITY-CHECK ARGUMENTS.
!
!***FIRST EXECUTABLE STATEMENT  PCHSP
      IF ( N.LT.2 )  GO TO 5001
      IF ( INCFD.LT.1 )  GO TO 5002
      DO 1  J = 2, N
         IF ( X(J).LE.X(J-1) )  GO TO 5003
    1 CONTINUE
!
      IBEG = IC(1)
      IEND = IC(2)
      IERR = 0
      IF ( (IBEG.LT.0).OR.(IBEG.GT.4) )  IERR = IERR - 1
      IF ( (IEND.LT.0).OR.(IEND.GT.4) )  IERR = IERR - 2
      IF ( IERR.LT.0 )  GO TO 5004
!
!  FUNCTION DEFINITION IS OK -- GO ON.
!
      IF ( NWK .LT. 2*N )  GO TO 5007
!
!  COMPUTE FIRST DIFFERENCES OF X SEQUENCE AND STORE IN WK(1,.). ALSO,
!  COMPUTE FIRST DIVIDED DIFFERENCE OF DATA AND STORE IN WK(2,.).
      DO 5  J=2,N
         WK(1,J) = X(J) - X(J-1)
         WK(2,J) = (F(1,J) - F(1,J-1))/WK(1,J)
    5 CONTINUE
!
!  SET TO DEFAULT BOUNDARY CONDITIONS IF N IS TOO SMALL.
!
      IF ( IBEG.GT.N )  IBEG = 0
      IF ( IEND.GT.N )  IEND = 0
!
!  SET UP FOR BOUNDARY CONDITIONS.
!
      IF ( (IBEG.EQ.1).OR.(IBEG.EQ.2) )  THEN
         D(1,1) = VC(1)
      ELSE IF (IBEG .GT. 2)  THEN
!        PICK UP FIRST IBEG POINTS, IN REVERSE ORDER.
         DO 10  J = 1, IBEG
            INDEX = IBEG-J+1
!           INDEX RUNS FROM IBEG DOWN TO 1.
            XTEMP(J) = X(INDEX)
            IF (J .LT. IBEG)  STEMP(J) = WK(2,INDEX)
   10    CONTINUE
!                 --------------------------------
         D(1,1) = PCHDF (IBEG, XTEMP, STEMP, IERR)
!                 --------------------------------
         IF (IERR .NE. 0)  GO TO 5009
         IBEG = 1
      ENDIF
!
      IF ( (IEND.EQ.1).OR.(IEND.EQ.2) )  THEN
         D(1,N) = VC(2)
      ELSE IF (IEND .GT. 2)  THEN
!        PICK UP LAST IEND POINTS.
         DO 15  J = 1, IEND
            INDEX = N-IEND+J
!           INDEX RUNS FROM N+1-IEND UP TO N.
            XTEMP(J) = X(INDEX)
            IF (J .LT. IEND)  STEMP(J) = WK(2,INDEX+1)
   15    CONTINUE
!                 --------------------------------
         D(1,N) = PCHDF (IEND, XTEMP, STEMP, IERR)
!                 --------------------------------
         IF (IERR .NE. 0)  GO TO 5009
         IEND = 1
      ENDIF
!
! --------------------( BEGIN CODING FROM CUBSPL )--------------------
!
!  **** A TRIDIAGONAL LINEAR SYSTEM FOR THE UNKNOWN SLOPES S(J) OF
!  F  AT X(J), J=1,...,N, IS GENERATED AND THEN SOLVED BY GAUSS ELIM-
!  INATION, WITH S(J) ENDING UP IN D(1,J), ALL J.
!     WK(1,.) AND WK(2,.) ARE USED FOR TEMPORARY STORAGE.
!
!  CONSTRUCT FIRST EQUATION FROM FIRST BOUNDARY CONDITION, OF THE FORM
!             WK(2,1)*S(1) + WK(1,1)*S(2) = D(1,1)
!
      IF (IBEG .EQ. 0)  THEN
         IF (N .EQ. 2)  THEN
!           NO CONDITION AT LEFT END AND N = 2.
            WK(2,1) = ONE
            WK(1,1) = ONE
            D(1,1) = TWO*WK(2,2)
         ELSE
!           NOT-A-KNOT CONDITION AT LEFT END AND N .GT. 2.
            WK(2,1) = WK(1,3)
            WK(1,1) = WK(1,2) + WK(1,3)
            D(1,1) =((WK(1,2) + TWO*WK(1,1))*WK(2,2)*WK(1,3)   &
                              + WK(1,2)**2*WK(2,3)) / WK(1,1)
         ENDIF
      ELSE IF (IBEG .EQ. 1)  THEN
!        SLOPE PRESCRIBED AT LEFT END.
         WK(2,1) = ONE
         WK(1,1) = ZERO
      ELSE
!        SECOND DERIVATIVE PRESCRIBED AT LEFT END.
         WK(2,1) = TWO
         WK(1,1) = ONE
         D(1,1) = THREE*WK(2,2) - HALF*WK(1,2)*D(1,1)
      ENDIF
!
!  IF THERE ARE INTERIOR KNOTS, GENERATE THE CORRESPONDING EQUATIONS AND
!  CARRY OUT THE FORWARD PASS OF GAUSS ELIMINATION, AFTER WHICH THE J-TH
!  EQUATION READS    WK(2,J)*S(J) + WK(1,J)*S(J+1) = D(1,J).
!
      NM1 = N-1
      IF (NM1 .GT. 1)  THEN
         DO 20 J=2,NM1
            IF (WK(2,J-1) .EQ. ZERO)  GO TO 5008
            G = -WK(1,J+1)/WK(2,J-1)
            D(1,J) = G*D(1,J-1)   &
                        + THREE*(WK(1,J)*WK(2,J+1) + WK(1,J+1)*WK(2,J))
            WK(2,J) = G*WK(1,J-1) + TWO*(WK(1,J) + WK(1,J+1))
   20    CONTINUE
      ENDIF
!
!  CONSTRUCT LAST EQUATION FROM SECOND BOUNDARY CONDITION, OF THE FORM
!           (-G*WK(2,N-1))*S(N-1) + WK(2,N)*S(N) = D(1,N)
!
!     IF SLOPE IS PRESCRIBED AT RIGHT END, ONE CAN GO DIRECTLY TO BACK-
!     SUBSTITUTION, SINCE ARRAYS HAPPEN TO BE SET UP JUST RIGHT FOR IT
!     AT THIS POINT.
      IF (IEND .EQ. 1)  GO TO 30
!
      IF (IEND .EQ. 0)  THEN
         IF (N.EQ.2 .AND. IBEG.EQ.0)  THEN
!           NOT-A-KNOT AT RIGHT ENDPOINT AND AT LEFT ENDPOINT AND N = 2.
            D(1,2) = WK(2,2)
            GO TO 30
         ELSE IF ((N.EQ.2) .OR. (N.EQ.3 .AND. IBEG.EQ.0))  THEN
!           EITHER (N=3 AND NOT-A-KNOT ALSO AT LEFT) OR (N=2 AND *NOT*
!           NOT-A-KNOT AT LEFT END POINT).
            D(1,N) = TWO*WK(2,N)
            WK(2,N) = ONE
            IF (WK(2,N-1) .EQ. ZERO)  GO TO 5008
            G = -ONE/WK(2,N-1)
         ELSE
!           NOT-A-KNOT AND N .GE. 3, AND EITHER N.GT.3 OR  ALSO NOT-A-
!           KNOT AT LEFT END POINT.
            G = WK(1,N-1) + WK(1,N)
!           DO NOT NEED TO CHECK FOLLOWING DENOMINATORS (X-DIFFERENCES).
            D(1,N) = ((WK(1,N)+TWO*G)*WK(2,N)*WK(1,N-1)   &
                        + WK(1,N)**2*(F(1,N-1)-F(1,N-2))/WK(1,N-1))/G
            IF (WK(2,N-1) .EQ. ZERO)  GO TO 5008
            G = -G/WK(2,N-1)
            WK(2,N) = WK(1,N-1)
         ENDIF
      ELSE
!        SECOND DERIVATIVE PRESCRIBED AT RIGHT ENDPOINT.
         D(1,N) = THREE*WK(2,N) + HALF*WK(1,N)*D(1,N)
         WK(2,N) = TWO
         IF (WK(2,N-1) .EQ. ZERO)  GO TO 5008
         G = -ONE/WK(2,N-1)
      ENDIF
!
!  COMPLETE FORWARD PASS OF GAUSS ELIMINATION.
!
      WK(2,N) = G*WK(1,N-1) + WK(2,N)
      IF (WK(2,N) .EQ. ZERO)   GO TO 5008
      D(1,N) = (G*D(1,N-1) + D(1,N))/WK(2,N)
!
!  CARRY OUT BACK SUBSTITUTION
!
   30 CONTINUE
      DO 40 J=NM1,1,-1
         IF (WK(2,J) .EQ. ZERO)  GO TO 5008
         D(1,J) = (D(1,J) - WK(1,J)*D(1,J+1))/WK(2,J)
   40 CONTINUE
! --------------------(  END  CODING FROM CUBSPL )--------------------
!
!  NORMAL RETURN.
!
      RETURN
!
!  ERROR RETURNS.
!
 5001 CONTINUE
!     N.LT.2 RETURN.
      IERR = -1
!NIST CALL XERROR ('PCHSP -- NUMBER OF DATA POINTS LESS THAN TWO'
!NIST*           , 44, IERR, 1)
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
 5011 FORMAT('****** ERROR IN PCHSP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5012)
 5012 FORMAT('       THE NUMBER OF DATA POINTS IS LESS THAN TWO.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5002 CONTINUE
!     INCFD.LT.1 RETURN.
      IERR = -2
!NIST CALL XERROR ('PCHSP -- INCREMENT LESS THAN ONE'
!NIST*           , 32, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5022)
 5022 FORMAT('       THE INCREMENT IS LESS THAN ONE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5003 CONTINUE
!     X-ARRAY NOT STRICTLY INCREASING.
      IERR = -3
!NIST CALL XERROR ('PCHSP -- X-ARRAY NOT STRICTLY INCREASING'
!NIST*           , 40, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5032)
 5032 FORMAT('       THE X-ARRAY IS NOT STRICTLY INCREASING.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5004 CONTINUE
!     IC OUT OF RANGE RETURN.
      IERR = IERR - 3
!NIST CALL XERROR ('PCHSP -- IC OUT OF RANGE'
!NIST*           , 24, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5042)
 5042 FORMAT('       IC IS OUT OF RANGE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5007 CONTINUE
!     NWK TOO SMALL RETURN.
      IERR = -7
!NIST CALL XERROR ('PCHSP -- WORK ARRAY TOO SMALL'
!NIST*           , 29, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5052)
 5052 FORMAT('       THE WORK ARRAY IS TOO SMALL.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5008 CONTINUE
!     SINGULAR SYSTEM.
!   *** THEORETICALLY, THIS CAN ONLY OCCUR IF SUCCESSIVE X-VALUES   ***
!   *** ARE EQUAL, WHICH SHOULD ALREADY HAVE BEEN CAUGHT (IERR=-3). ***
      IERR = -8
!NIST CALL XERROR ('PCHSP -- SINGULAR LINEAR SYSTEM'
!NIST*           , 31, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5062)
 5062 FORMAT('       THE LINEAR SYSTEM IS SINGULAR.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5009 CONTINUE
!     ERROR RETURN FROM PCHDF.
!   *** THIS CASE SHOULD NEVER OCCUR ***
      IERR = -9
!NIST CALL XERROR ('PCHSP -- ERROR RETURN FROM PCHDF'
!NIST*           , 32, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5072)
 5072 FORMAT('       ERROR RETURN FROM PCHDF.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!------------- LAST LINE OF PCHSP FOLLOWS ------------------------------
      END SUBROUTINE PCHSP
      REAL FUNCTION PCHST(ARG1,ARG2)
!***BEGIN PROLOGUE  PCHST
!***REFER TO  PCHCE,PCHCI,PCHCS,PCHIM
!***END PROLOGUE  PCHST
      REAL  ARG1, ARG2
!
!  DECLARE LOCAL VARIABLES.
!
      REAL  ONE, ZERO
      DATA  ZERO /0./,  ONE /1./
!
!  PERFORM THE TEST.
!
!***FIRST EXECUTABLE STATEMENT  PCHST
      PCHST = SIGN(ONE,ARG1) * SIGN(ONE,ARG2)
      IF ((ARG1.EQ.ZERO) .OR. (ARG2.EQ.ZERO))  PCHST = ZERO
!
      RETURN
!------------- LAST LINE OF PCHST FOLLOWS ------------------------------
      END FUNCTION PCHST
      DOUBLE PRECISION FUNCTION PDFWAK(X,PARA)
!
!
!  PROBABILITY DENSITY FUNCTION OF THE WAKEBY DISTRIBUTION
!
!  OTHER ROUTINES USED: CDFWAK
!
!  USE THE RELATION (FROM PAGE 46 OF JOHNSON, KOTZ AND
!  BALAKRISHNAN, "CONTINUOUS UNIVARIATE DISTRIBUTIONS: VOLUME 1",
!  SECOND EDITION, WILE, 1994):
!
!     f(X) = [(1 - F(X))**(DELTA+1)*(ALPHA*T + GAMMA)**(-1)
!
!  WHERE
!
!     T = (1 - F(X))**(BETA+DELTA)
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(5)
!
      INCLUDE 'DPCOP2.INC'
!
!     XI = LOCATION
!     A  = SCALE (ALPHA)
!     B  = BETA
!     C  = GAMMA
!     D  = DELTA
!
      ZERO=0.0D0
      XI=PARA(1)
      A=PARA(2)
      B=PARA(3)
      C=PARA(4)
      D=PARA(5)
!
!         TEST FOR VALID PARAMETERS
!
      IF(B+D.LE.ZERO.AND.(B.NE.ZERO.OR.C.NE.ZERO.OR.D.NE.ZERO))GO TO  1000
      IF(A.EQ.ZERO.AND.B.NE.ZERO)GO TO  1000
      IF(C.EQ.ZERO.AND.D.NE.ZERO)GO TO  1000
      IF(C.LT.ZERO.OR.A+C.LT.ZERO)GO TO  1000
      IF(A.EQ.ZERO.AND.C.EQ.ZERO)GO TO  1000
!
      DTERM1=CDFWAK(X,PARA)
      DT=(1.0D0 - DTERM1)**(B+D)
      DTERM2=(1.0D0 - DTERM1)**(D+1.0D0)
      DTERM3=A*DT + C
      PDFWAK=DTERM2/DTERM3
      GO TO 9000
!
 1000 CONTINUE
      WRITE(ICOUT,7000)
 7000 FORMAT('***** ERROR IN WAKCDF--PARAMETERS INVALID.')
      CALL DPWRST('XXX','WRIT')
      PDFWAK=0.0D0
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION PDFWAK
      SUBROUTINE PE3CDF(DX,DGAMMA,DMU,DSIGMA,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DENSITY
!              FUNCTION VALUE FOR THE PEARSON TYPE 3 DISTRIBUTION
!              WITH SHAPE PARAMETERS GAMMA.
!
!              FOR GAMMA > 0, THE CDF FOR THE DISTRIBUTION IS
!
!                 F(X;GAMMA,MU,SIGMA) = G(ALPHA,(X-XI)/BETA)/G(ALPHA)
!                                       XI <= X < INFINITY
!
!              FOR GAMMA < 0, THE CDF FOR THE DISTRIBUTION IS
!
!                 F(X;GAMMA,MU,SIGMA) = 1 - G(ALPHA,(XI-XI)/BETA)/
!                                       G(ALPHA)
!                                       -INFINITY < X <= XI
!
!              FOR GAMMA = 0, THE PEARSON TYPE 3 IS EQUIVALENT
!              TO THE NORMAL DISTRIBUTION.
!
!              WHERE
!
!                 ALPHA = 4/GAMMA**2
!                 BETA  = 0.5*SIGMA*|GAMMA|
!                 XI    = MU - 2*SIGMA/GAMMA
!                 G(x)  = GAMMA FUNCTION
!                 G(A,X) = INCOMPLETE GAMMA FUNCTION
!
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DGAMMA = THE FIRST SHAPE PARAMETER
!                     --DMU    = THE LOCATION PARAMETER
!                     --DSIGMA = THE SCALE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE PEARSON TYPE 3 DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--RANGE OF X DEPENDENT ON GAMMA
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOSKING AND WALLIS (1997), "REGIONAL FREQUENCY
!                 ANALYSIS: AN APPROACH BASED ON L-MOMENTS",
!                 CAMBRIDGE UNVERSITY PRESS, PP. 200-202.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DXI
      DOUBLE PRECISION CDFPE3
      EXTERNAL CDFPE3
!
      DOUBLE PRECISION PARA(3)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DXI=DMU - 2.0D0*DSIGMA/DGAMMA
!
      DCDF=0.0D0
      IF(DSIGMA.LE.0.0D0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DSIGMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO PE3CDF ',   &
             '(THE SCALE PARAMETER) IS NON-POSITIVE')
!
      ELSEIF(DGAMMA.GT.0.0D0 .AND. DX.LT.DXI)THEN
!CCCC   WRITE(ICOUT,5)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,6)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)DX
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7)DXI
!CCCC   CALL DPWRST('XXX','BUG ')
        GO TO 9999
!CCC5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PE3CDF IS ',
!CCCC1       '< MU - 2*SIGMA/GAMMA')
!CCC6 FORMAT('      WHEN THE SHAPE PARAMETER (GAMMA) IS POSITIVE.')
!CCC7 FORMAT('      THE VALUE OF MU - 2*SIGMA/GAMMA IS ',G15.7)
!
      ELSEIF(DGAMMA.LT.0.0D0 .AND. DX.GT.DXI)THEN
!CCCC   WRITE(ICOUT,15)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,16)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)DX
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,17)DXI
!CCCC   CALL DPWRST('XXX','BUG ')
        DCDF=1.0D0
        GO TO 9999
      ENDIF
!CC15 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PE3CDF IS ',
!CCCC1       '> MU - 2*SIGMA/GAMMA')
!CC16 FORMAT('      WHEN THE SHAPE PARAMETER (GAMMA) IS NEGATIVE.')
!CC17 FORMAT('      THE VALUE OF MU - 2*SIGMA/GAMMA IS ',G15.7)
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      PARA(1)=DMU
      PARA(2)=DSIGMA
      PARA(3)=DGAMMA
      DCDF=CDFPE3(DX,PARA)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PE3CDF
      SUBROUTINE PE3ML1(Y,N,   &
                        DTEMP1,XMOM,NMOM,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALOCML,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE L-MOMENTS ESTIMATES FOR THE
!              PEARSON TYPE 3 DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).  THIS ROUTINE RETURNS ONLY
!              THE POINT ESTIMATES.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLP3 WILL GENERATE THE OUTPUT
!              FOR THE PEARSON TYPE 3 MLE COMMAND).
!
!     REFERENCE--FORTRAN CODE WRITTEN FOR INCLUSION IN IBM
!                RESEARCH REPORT RC20525, 'FORTRAN ROUTINES FOR
!                USE WITH THE METHOD OF L-MOMENTS, VERSION 3',
!                J. R. M. HOSKING, IBM RESEARCH DIVISION,
!                T. J. WATSON RESEARCH CENTER, YORKTOWN HEIGHTS
!                NEW YORK 10598, U.S.A., VERSION 3     AUGUST 1996
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLP3)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION XMOM(*)
      DOUBLE PRECISION XPAR(3)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PE3M'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'3ML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF PE3ML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               *******************************************
!               **  STEP 2--                             **
!               **  CARRY OUT CALCULATIONS               **
!               **  FOR PEARSON TYPE 3 MLE ESTIMATE      **
!               *******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'3ML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='PEARSON TYPE 3'
      ALOCML=CPUMIN
      SCALML=CPUMIN
      SHAPML=CPUMIN
!
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      CALL SORT(Y,N,Y)
      NMOM=3
      DO 2110 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 2110 CONTINUE
      CALL SAMLMU(DTEMP1,N,XMOM,NMOM)
      CALL PELPE3(XMOM,XPAR,IFAIL)
!
      IF(IFAIL.EQ.1)GO TO 9000
!
      ALOCML=REAL(XPAR(1))
      SCALML=REAL(XPAR(2))
      SHAPML=REAL(XPAR(3))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'3ML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF PE3ML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)XMOM(1),XMOM(2),XMOM(3)
 9015   FORMAT('XMOM(1),XMOM(2),XMOM(3) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9016)XPAR(1),XPAR(2),XPAR(3)
 9016   FORMAT('XPAR(1),XPAR(2),XPAR(3) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPML,SCALML,ALOCML
 9017   FORMAT('SHAPML,SCALML,ALOCML =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE PE3ML1
      SUBROUTINE PE3PDF(DX,DGAMMA,DMU,DSIGMA,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE PEARSON TYPE 3 DISTRIBUTION
!              WITH SHAPE PARAMETERS GAMMA.
!
!              FOR GAMMA > 0, THE PDF FOR THE DISTRIBUTION IS
!
!                 f(X;GAMMA,MU,SIGMA) = (X-XI)**(ALPHA-1)*EXP(-(X-XI)/BETA)/
!                                       {BETA**ALPHA*G(ALPHA}
!                                       XI <= X < INFINITY
!
!              FOR GAMMA < 0, THE PDF FOR THE DISTRIBUTION IS
!
!                 f(X;GAMMA,MU,SIGMA) = (XI-X)**(ALPHA-1)*EXP(-(XI-X)/BETA)/
!                                       {BETA**ALPHA*G(ALPHA}
!                                       -INFINITY < X <= XI
!
!              FOR GAMMA = 0, THE PEARSON TYPE 3 IS EQUIVALENT
!              TO THE NORMAL DISTRIBUTION.
!
!              WHERE
!
!                 ALPHA = 4/GAMMA**2
!                 BETA  = 0.5*SIGMA*|GAMMA|
!                 XI    = MU - 2*SIGMA/GAMMA
!                 G(x)  = GAMMA FUNCTION
!                 G(A,X) = INCOMPLETE GAMMA FUNCTION
!
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DGAMMA = THE FIRST SHAPE PARAMETER
!                     --DMU    = THE LOCATION PARAMETER
!                     --DSIGMA = THE SCALE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE PDF FOR THE PEARSON TYPE 3 DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--RANGE OF X DEPENDENT ON GAMMA
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOSKING AND WALLIS (1997), "REGIONAL FREQUENCY
!                 ANALYSIS: AN APPROACH BASED ON L-MOMENTS",
!                 CAMBRIDGE UNVERSITY PRESS, PP. 200-202.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DXI
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!CCCC DOUBLE PRECISION DLGAMA
      DOUBLE PRECISION DLGADP
      DOUBLE PRECISION DEPS
!CCCC EXTERNAL DLGAMA
      EXTERNAL DLGADP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DEPS=1.0D-7
      DXI=DMU - 2.0D0*DSIGMA/DGAMMA
      IF(DGAMMA.GT.0.0D0)THEN
        IF(DABS(DX-DXI).LE.DEPS)DX=DXI+DEPS
      ELSEIF(DGAMMA.LT.0.0D0)THEN
        IF(DABS(DX-DXI).LE.DEPS)DX=DXI-DEPS
      ENDIF
      DBETA=0.5D0*DSIGMA*DABS(DGAMMA)
      DALPHA=4.0D0/DGAMMA**2
      DPDF=0.0D0
!
      IF(DSIGMA.LE.0.0D0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DSIGMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO PE3PDF ',   &
             '(THE SCALE PARAMETER) IS NON-POSITIVE')
!
      ELSEIF(DGAMMA.GT.0.0D0 .AND. DX.LT.DXI)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7)DXI
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO PE3PDF IS ',   &
               '< MU - 2*SIGMA/GAMMA')
    6   FORMAT('      WHEN THE SHAPE PARAMETER (GAMMA) IS POSITIVE.')
    7   FORMAT('      THE VALUE OF MU - 2*SIGMA/GAMMA IS ',G15.7)
!
      ELSEIF(DGAMMA.LT.0.0D0 .AND. DX.GT.DXI)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,17)DXI
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   15 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PE3PDF IS ',   &
             '> MU - 2*SIGMA/GAMMA')
   16 FORMAT('      WHEN THE SHAPE PARAMETER (GAMMA) IS NEGATIVE.')
   17 FORMAT('      THE VALUE OF MU - 2*SIGMA/GAMMA IS ',G15.7)
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      IF(DGAMMA.EQ.0.0D0)THEN
        DTERM1=(DX-DMU)/DSIGMA
        CALL NODPDF(DTERM1,DTERM2)
        DPDF=DTERM2/DSIGMA
      ELSEIF(DGAMMA.GT.0.0D0)THEN
        DTERM1=(DALPHA-1.0D0)*DLOG(DX-DXI)
        DTERM2=-(DX-DXI)/DBETA
        DTERM3=DALPHA*DLOG(DBETA)
!CCCC   DTERM4=DLGAMA(DALPHA)
        DTERM4=DLGADP(DALPHA)
        DPDF=DTERM1 + DTERM2 - DTERM3 - DTERM4
        DPDF=DEXP(DPDF)
      ELSEIF(DGAMMA.LT.0.0D0)THEN
        DTERM1=(DALPHA-1.0D0)*DLOG(DXI-DX)
        DTERM2=-(DXI-DX)/DBETA
        DTERM3=DALPHA*DLOG(DBETA)
!CCCC   DTERM4=DLGAMA(DALPHA)
        DTERM4=DLGADP(DALPHA)
        DPDF=DTERM1 + DTERM2 - DTERM3 - DTERM4
        DPDF=DEXP(DPDF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PE3PDF
      SUBROUTINE PE3PPF(DP,DGAMMA,DMU,DSIGMA,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE PEARSON TYPE 3 DISTRIBUTION
!              WITH SHAPE PARAMETERS GAMMA.
!
!              FOR GAMMA > 0, THE CDF FOR THE DISTRIBUTION IS
!
!                 F(X;GAMMA,MU,SIGMA) = G(ALPHA,(X-XI)/BETA)/G(ALPHA)
!                                       XI <= X < INFINITY
!
!              FOR GAMMA < 0, THE CDF FOR THE DISTRIBUTION IS
!
!                 F(X;GAMMA,MU,SIGMA) = 1 - G(ALPHA,(XI-XI)/BETA)/
!                                       G(ALPHA)
!                                       -INFINITY < X <= XI
!
!              FOR GAMMA = 0, THE PEARSON TYPE 3 IS EQUIVALENT
!              TO THE NORMAL DISTRIBUTION.
!
!              WHERE
!
!                 ALPHA = 4/GAMMA**2
!                 BETA  = 0.5*SIGMA*|GAMMA|
!                 XI    = MU - 2*SIGMA/GAMMA
!                 G(x)  = GAMMA FUNCTION
!                 G(A,X) = INCOMPLETE GAMMA FUNCTION
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DGAMMA = THE SHAPE PARAMETER
!                     --DMU    = THE LOCATION PARAMETER
!                     --DSIGMA = THE SCALE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE
!             PPF FOR THE PEARSON TYPE 3 DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 < P < 1
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOSKING AND WALLIS (1997), "REGIONAL FREQUENCY
!                 ANALYSIS: AN APPROACH BASED ON L-MOMENTS",
!                 CAMBRIDGE UNVERSITY PRESS, PP. 200-202.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION QUAPE3
      EXTERNAL QUAPE3
!
      DOUBLE PRECISION PARA(3)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DGAMMA.GT.0.0D0 .AND.   &
         (DP.LT.0.0D0 .OR. DP.GE.1.0D0))THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        DPPF=0.0D0
        GO TO 9999
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PE3PPF IS ',   &
             'OUTSIDE THE (0,1] INTERVAL')
!
      ELSEIF(DGAMMA.LT.0.0D0 .AND.   &
         (DP.LE.0.0D0 .OR. DP.GT.1.0D0))THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        DPPF=0.0D0
        GO TO 9999
   15 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PE3PPF IS ',   &
             'OUTSIDE THE [0,1) INTERVAL')
!
      ELSEIF(DGAMMA.EQ.0.0D0 .AND.   &
         (DP.LE.0.0D0 .OR. DP.GE.1.0D0))THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        DPPF=0.0D0
        GO TO 9999
   25 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PE3PPF IS ',   &
             'OUTSIDE THE (0,1) INTERVAL')
!
      ELSEIF(DSIGMA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DSIGMA
        CALL DPWRST('XXX','BUG ')
        DPPF=0.0D0
        GO TO 9999
   35 FORMAT('***** ERROR--THE THIRD ARGUMENT TO PE3PPF ',   &
             '(THE SCALE PARAMETER) IS NON-POSITIVE')
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      PARA(1)=DMU
      PARA(2)=DSIGMA
      PARA(3)=DGAMMA
      DPPF=QUAPE3(DP,PARA)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PE3PPF
      SUBROUTINE PE3RAN(N,GAMMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE PEARSON TYPE 3 DISTRIBUTION WITH SHAPE
!              PARAMETER GAMMA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE PEARSON TYPE 3
!             DISTRIBUTION WITH SHAPE PARAMETER GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, QUAPE3.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION QUAPE3
      DOUBLE PRECISION PARA(3)
!
      EXTERNAL QUAPE3
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF PEARSON TYPE 3 ',   &
             'RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N PEARSON TYPE 3 DISTRIBUTION RANDOM NUMBERS USING
!     THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      PARA(1)=0.0D0
      PARA(2)=1.0D0
      PARA(3)=DBLE(GAMMA)
!
      DO 100 I=1,N
        DPPF=QUAPE3(DBLE(X(I)),PARA)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PE3RAN
      SUBROUTINE PEARCC(Y1,Y2,N,IWRITE,XIDTEM,XIDTE2,TEMP1,STAT,   &
                 IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES PEARSON'S CONTINGENCY
!              COEFFICIENT FOR RXC CONTINGENCY TABLES.  THIS IS
!
!                  SQRT(T/(N+T))
!
!              WHERE
!
!                  T = CHI-SQUARE STATISTIC
!                    = SUM[i=1 to r][SUM[j=1 to c]
!                      [(O(ij)-E(ij))**2/E(ij)]]
!
!                      O = OBSERVED COUNT
!                      E = EXPECTED COUNT
!                        = ROW TOTAL*COL TOTAL/GRAND TOTAL
!
!                  N = TOTAL NUMBER OF OBSERVATIONS
!
!     REFERENCE--CONOVER (1999), "PRACTICAL NONPARAMETRIC
!                STATISTICS", THIRD EDITION, WILEY, PP. 231-232.
!     NOTE--THIS SUBROUTINE HANDLES THE RAW DATA CASE.  USE
!           THE COMMAND
!
!               LET A = MATRIX PEARSON CONTINGENCY COEFFICENT M
!
!           IF YOUR DATA CONSISTS OF AN RXC TABLE.
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y2     = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                PEARSON'S CONTINGENCY COEFFICIENT
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PEARSON'S CONTINGENCY COEFFICENT BETWEEN THE
!             2 SETS OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DISTIN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      PARAMETER(MAXLEV=20000)
      PARAMETER(IWORK1=0)
      PARAMETER(IWORK2=20000)
      PARAMETER(IWORK3=40000)
      PARAMETER(IWORK4=60000)
      PARAMETER(IWORK5=80000)
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION TEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CRAM'
      ISUBN2='ER  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PEARCC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('****** ERROR IN PEARSON CONTINGENCY COEFFICIENT--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2101)
 2101   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN 2.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2103)N
 2103   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************************
!               **  STEP 2.2--                                      **
!               **  DETERMINE THE NUMBER OF DISTINCT VALUES         **
!               **  FOR THE GROUP VARIABLES (Y1, Y2).               **
!               ******************************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DISTIN(Y1,N,IWRITE,XIDTEM,NUMSE1,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NUMSE1,XIDTEM)
      CALL DISTIN(Y2,N,IWRITE,XIDTE2,NUMSE2,IBUGA3,IERROR)
      CALL SORT(XIDTE2,NUMSE2,XIDTE2)
!
      IF(NUMSE1.LT.1 .OR. NUMSE1.GT.MAXLEV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2202)MAXLEV
 2202   FORMAT('      NUMBER OF SETS FOR VARIABLE ONE IS OUTSIDE ',   &
               'THE INTERVAL (1,',I8,')')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2204)NUMSE1
 2204   FORMAT('      THE NUMBER OF SET = ',I10)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NUMSE2.LT.1 .OR. NUMSE2.GT.MAXLEV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2212)MAXLEV
 2212   FORMAT('      NUMBER OF SETS FOR VARIABLE TWO IS OUTSIDE ',   &
               'THE INTERVAL (1,',I8,')')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2204)NUMSE2
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***********************************************
!               **  STEP 2.3--                               **
!               **  COMPUTE THE CHI-SQUARE STATISTIC         **
!               ***********************************************
!
      ISTEPN='23'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     COMPUTE COUNTS FOR EACH CELL
!
      J=0
      DO 2310 ISET1=1,NUMSE1
        DO 2320 ISET2=1,NUMSE2
!
          K=0
          DO 2330 I=1,N
            IF(XIDTEM(ISET1).EQ.Y1(I).AND.XIDTE2(ISET2).EQ.Y2(I))THEN
              K=K+1
            ENDIF
 2330     CONTINUE
          NTEMP=K
          J=J+1
          TEMP1(IWORK1+J)=REAL(K)
          TEMP1(IWORK2+J)=XIDTEM(ISET1)
          TEMP1(IWORK3+J)=XIDTE2(ISET2)
!
 2320   CONTINUE
 2310 CONTINUE
      NTEMP2=J
!
!     COMPUTE ROW AND COLUMN TOTALS AND GRAND TOTAL.
!
      J=0
      GTOTAL=0.0
!
      DO 2340 ISET1=1,NUMSE1
        TEMP1(IWORK4+ISET1)=0.0
        DO 2350 ISET2=1,NUMSE2
          J=J+1
          TEMP1(IWORK4+ISET1)=TEMP1(IWORK4+ISET1) + TEMP1(IWORK1+J)
          GTOTAL=GTOTAL + TEMP1(IWORK1+J)
 2350   CONTINUE
!
        IF(IBUGA3.EQ.'ON')THEN
          WRITE(ICOUT,2352)ISET1,TEMP1(IWORK4+ISET1)
 2352     FORMAT('ISET1,ROWTOT(ISET1)=',I5,1X,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 2340 CONTINUE
!
      DO 2360 ISET2=1,NUMSE2
        TEMP1(IWORK5+ISET2)=0.0
        DO 2370 J=1,NTEMP2
          IF(TEMP1(IWORK3+J).EQ.XIDTE2(ISET2))THEN
            TEMP1(IWORK5+ISET2)=TEMP1(IWORK5+ISET2) + TEMP1(IWORK1+J)
          ENDIF
 2370   CONTINUE
!
        IF(IBUGA3.EQ.'ON')THEN
          WRITE(ICOUT,2372)ISET2,TEMP1(IWORK5+ISET2)
 2372     FORMAT('ISET2,COLTOT(ISET2)=',I5,1X,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2360 CONTINUE
!
!     NOW COMPUTE THE CHI-SQUARE TEST STATISTIC
!
      STAT=0.0
      J=0
!
      DO 2380 ISET1=1,NUMSE1
        DO 2390 ISET2=1,NUMSE2
          J=J+1
          EXP=TEMP1(IWORK4+ISET1)*TEMP1(IWORK5+ISET2)/GTOTAL
          STAT=STAT + (TEMP1(IWORK1+J) - EXP)**2/EXP
 2390   CONTINUE
 2380 CONTINUE
      T=STAT
      STAT=STAT/(GTOTAL+T)
      STAT=SQRT(STAT)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE PEARSON CONTINGENCY COEFFICIENT = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF PEARCC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)T,GTOTAL,STAT
 9015   FORMAT('T,GTOTAL,STAT = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PEARCC
      SUBROUTINE PEARC2(XMAT,MAXOBV,NR1,NC1,IWRITE,   &
                 TEMP1,STAT,   &
                 IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES PEARSON'S CONTINGENCY
!              COEFFICIENT FOR RXC CONTINGENCY TABLES.  THIS IS
!
!                  SQRT(T/(N+T))
!
!              WHERE
!
!                  T = CHI-SQUARE STATISTIC
!                    = SUM[i=1 to r][SUM[j=1 to c]
!                      [(O(ij)-E(ij))**2/E(ij)]]
!
!                      O = OBSERVED COUNT
!                      E = EXPECTED COUNT
!                        = ROW TOTAL*COL TOTAL/GRAND TOTAL
!
!                  N = TOTAL NUMBER OF OBSERVATIONS
!
!     REFERENCE--CONOVER (1999), "PRACTICAL NONPARAMETRIC
!                STATISTICS", THIRD EDITION, WILEY, PP. 231-232.
!     NOTE--THIS SUBROUTINE HANDLES THE SUMMARY DATA CASE (I.E..
!           THE DATA IS GIVEN AS AN RXC TABLE).   THE "PEARSON"
!           SUBROUTINE IS USED FOR THE RAW DATA CASE.
!     INPUT  ARGUMENTS--XMAT   = THE SINGLE PRECISION MATRIX OF
!                                OBSERVATIONS (RXC TABLE)
!                     --MAXOBV = THE INTEGER NUMBER THAT SPECIFIES
!                                THE MAXIMUM NUMBER OF ROWS IN THE
!                                MATRIX.
!                     --NR1    = THE INTEGER NUMBER OF ROWS
!                                IN THE MATRIX XMAT.
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS
!                                IN THE MATRIX XMAT.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                PEARSON'S CONTINGENCY COEFFICIENT
!                                OF THE DATA IN THE MATRIX XMAT.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PEARSON'S CONTINGENCY COEFFICENT OF THE DATA
!             IN THE MATRIX XMAT.
!     RESTRICTIONS--THE MAXIMUM NUMBER OF LEVELS IS 50,000.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DISTIN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      PARAMETER(MAXLEV=50000)
      PARAMETER(IWORK1=0)
      PARAMETER(IWORK2=50000)
!
      DIMENSION XMAT(MAXOBV,NC1)
      DIMENSION TEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PEAR'
      ISUBN2='C2  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PEARC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NR1,NC1
   53   FORMAT('N = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NR1
          DO 60 J=1,NC1
            WRITE(ICOUT,56)I,J,XMAT(I,J)
   56       FORMAT('I,J,XMAT(I,J) = ',2I8,G15.7)
            CALL DPWRST('XXX','BUG ')
   60     CONTINUE
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NR1.LT.2 .OR. NR1.GT.MAXLEV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('****** ERROR IN MATRIX PEARSON CONTINGENCY ',   &
               'COEFFICIENT--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2101)
 2101   FORMAT('      THE NUMBER OF ROWS IN THE MATRIX IS LESS ',   &
               'THAN 2')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2102)MAXLEV
 2102   FORMAT('      OR GREATER THAN ',I10,'.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2103)NR1
 2103   FORMAT('NUMBER OF ROWS = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NC1.LT.2 .OR. NC1.GT.MAXLEV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2111)
 2111   FORMAT('      THE NUMBER OF COLUMNS IN THE MATRIX IS LESS ',   &
               'THAN 2')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2102)MAXLEV
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2113)NC1
 2113   FORMAT('NUMBER OF COLUMNS = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      GTOTAL=0.0
      DO 2120 J=1,NC1
        DO 2130 I=1,NR1
          ITEMP=INT(XMAT(I,J)+0.5)
          IF(ITEMP.LT.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1201)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,2131)
 2131       FORMAT('      A NEGATIVE COUNT WAS ENCOUNTERED IN THE ',   &
                   'INPUT MATRIX.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,2133)I,J,ITEMP
 2133       FORMAT('      COUNT FOR ROW ',I8,' COLUMN ',I8,' = ',I8)
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
          XMAT(I,J)=REAL(ITEMP)
          GTOTAL=GTOTAL + XMAT(I,J)
 2130   CONTINUE
 2120 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,2344)GTOTAL
 2344   FORMAT('GTOTAL = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************************************************
!               **  STEP 2.2--                                      **
!               **  COMPUTE THE ROW AND COLUMN TOTALS.              **
!               ******************************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 2340 ISET1=1,NR1
        TEMP1(IWORK1+ISET1)=0.0
        DO 2350 ISET2=1,NC1
          TEMP1(IWORK1+ISET1)=TEMP1(IWORK1+ISET1) + XMAT(ISET1,ISET2)
          IF(IBUGA3.EQ.'ON')THEN
            WRITE(ICOUT,2342)ISET1,ISET2,XMAT(ISET1,ISET2)
 2342       FORMAT('ISET1,ISET2,XMAT(I,J) =',2I8,G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
 2350   CONTINUE
!
        IF(IBUGA3.EQ.'ON')THEN
          WRITE(ICOUT,2352)ISET1,TEMP1(IWORK1+ISET1)
 2352     FORMAT('ISET1,ROWTOT(ISET1)=',I5,1X,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 2340 CONTINUE
!
      DO 2360 ISET2=1,NC1
        TEMP1(IWORK2+ISET2)=0.0
        DO 2370 ISET1=1,NR1
          TEMP1(IWORK2+ISET2)=TEMP1(IWORK2+ISET2) + XMAT(ISET1,ISET2)
 2370   CONTINUE
!
        IF(IBUGA3.EQ.'ON')THEN
          WRITE(ICOUT,2372)ISET2,TEMP1(IWORK2+ISET2)
 2372     FORMAT('ISET2,COLTOT(ISET2)=',I5,1X,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2360 CONTINUE
!
!               ******************************************************
!               **  STEP 2.3--                                      **
!               **  COMPUTE THE CHI-SQUARE STATISTIC.               **
!               ******************************************************
!
      ISTEPN='23'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      STAT=0.0
!
      DO 2380 ISET1=1,NR1
        DO 2390 ISET2=1,NC1
          EXP=TEMP1(IWORK1+ISET1)*TEMP1(IWORK2+ISET2)/GTOTAL
          STAT=STAT + (XMAT(ISET1,ISET2) - EXP)**2/EXP
 2390   CONTINUE
 2380 CONTINUE
      T=STAT
      STAT=STAT/(GTOTAL+STAT)
      STAT=SQRT(STAT)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE PEARSON CONTINGENCY COEFFICIENT = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF PEARC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)T,GTOTAL,STAT
 9015   FORMAT('T,GTOTAL,STAT = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PEARC2
      SUBROUTINE PELGLO(XMOM,PARA)
!===================================================== PELGLO.FOR
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  PARAMETER ESTIMATION VIA L-MOMENTS FOR THE GENERALIZED LOGISTIC
!  DISTRIBUTION
!
!  PARAMETERS OF ROUTINE:
!  XMOM   * INPUT* ARRAY OF LENGTH 3. CONTAINS THE L-MOMENTS LAMBDA-1,
!                  LAMBDA-2, TAU-3.
!  PARA   *OUTPUT* ARRAY OF LENGTH 3. ON EXIT, CONTAINS THE PARAMETERS
!                  IN THE ORDER XI, ALPHA, K (LOCATION, SCALE, SHAPE).
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION XMOM(3),PARA(3)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0.0D0/
      DATA ONE/1.0D0/
      DATA PI/3.141592653589793238D0/
!
!         SMALL IS USED TO TEST WHETHER K IS EFFECTIVELY ZERO
!
      DATA SMALL/1D-6/
!
!         ESTIMATE K
!
      G=-XMOM(3)
      IF(XMOM(2).LE.ZERO.OR.DABS(G).GE.ONE)THEN
        WRITE(ICOUT,7000)
 7000   FORMAT('***** ERROR IN GENERALIZED LOGISTIC L-MOMENTS ',   &
               'ESTIMATION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,7005)
 7005   FORMAT('      L-MOMENTS INVALID')
        CALL DPWRST('XXX','WRIT')
        PARA(3)=ZERO
        PARA(2)=ZERO
        PARA(1)=ZERO
        GO TO 9000
      ENDIF
!
!         ESTIMATED K EFFECTIVELY ZERO (I.E., USE LOGISTIC RATHER THAN
!         GENERALIZED LOGISTIC)
!
      IF(DABS(G).LE.SMALL)THEN
        PARA(3)=ZERO
        PARA(2)=XMOM(2)
        PARA(1)=XMOM(1)
        GO TO 9000
      ENDIF
!
!         ESTIMATE ALPHA, XI
!
      GG=G*PI/DSIN(G*PI)
      A=XMOM(2)/GG
      PARA(1)=XMOM(1)-A*(ONE-GG)/G
      PARA(2)=A
      PARA(3)=G
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PELGLO
!===================================================== PELKAP.FOR
      SUBROUTINE PELKAP(XMOM,PARA,IFAIL)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  PARAMETER ESTIMATION VIA L-MOMENTS FOR THE KAPPA DISTRIBUTION
!
!  PARAMETERS OF ROUTINE:
!  XMOM   * INPUT* ARRAY OF LENGTH 4. CONTAINS THE L-MOMENTS LAMBDA-1,
!                  LAMBDA-2, TAU-3, TAU-4.
!  PARA   *OUTPUT* ARRAY OF LENGTH 4. ON EXIT, CONTAINS THE PARAMETERS
!                  IN THE ORDER XI, ALPHA, K, H.
!  IFAIL  *OUTPUT* FAIL FLAG. ON EXIT, IT IS SET AS FOLLOWS.
!                  0  SUCCESSFUL EXIT
!                  1  L-MOMENTS INVALID
!                  2  (TAU-3, TAU-4) LIES ABOVE THE GENERALIZED-LOGISTIC
!                     LINE (SUGGESTS THAT L-MOMENTS ARE NOT CONSISTENT
!                     WITH ANY KAPPA DISTRIBUTION WITH H.GT.-1)
!                  3  ITERATION FAILED TO CONVERGE
!                  4  UNABLE TO MAKE PROGRESS FROM CURRENT POINT IN
!                     ITERATION
!                  5  ITERATION ENCOUNTERED NUMERICAL DIFFICULTIES -
!                     OVERFLOW WOULD HAVE BEEN LIKELY TO OCCUR
!                  6  ITERATION FOR H AND K CONVERGED, BUT OVERFLOW
!                     WOULD HAVE OCCURRED WHEN CALCULATING XI AND ALPHA
!
!  N.B.  PARAMETERS ARE SOMETIMES NOT UNIQUELY DEFINED BY THE FIRST 4
!  L-MOMENTS. IN SUCH CASES THE ROUTINE GO TO 9000S THE SOLUTION FOR WHICH
!  THE H PARAMETER IS LARGEST.
!
!  OTHER ROUTINES USED: DLGAMA (DLGADP),DIGAMD
!
!  NOTE 6/2008: USE DPSI ROUTINE INSTEAD OF DIGAMD.
!
!  THE SHAPE PARAMETERS K AND H ARE ESTIMATED USING NEWTON-RAPHSON
!  ITERATION ON THE RELATIONSHIP BETWEEN (TAU-3,TAU-4) AND (K,H).
!  THE CONVERGENCE CRITERION IS THAT TAU-3 AND TAU-4 CALCULATED FROM
!  THE ESTIMATED VALUES OF K AND H SHOULD DIFFER BY LESS THAN 'EPS'
!  FROM THE VALUES SUPPLIED IN ARRAY XMOM.
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION XMOM(4),PARA(4)
!
      EXTERNAL DPSI
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,HALF/0.5D0/,ONE/1D0/,TWO/2D0/,THREE/3D0/,FOUR/4D0/
      DATA FIVE/5D0/,SIX/6D0/,TWELVE/12D0/,TWENTY/20D0/,THIRTY/30D0/
      DATA P725/0.725D0/,P8/0.8D0/
!
!         EPS,MAXIT CONTROL THE TEST FOR CONVERGENCE OF N-R ITERATION
!         MAXSR IS THE MAX. NO. OF STEPLENGTH REDUCTIONS PER ITERATION
!         HSTART IS THE STARTING VALUE FOR H
!         BIG IS USED TO INITIALIZE THE CRITERION FUNCTION
!         OFLEXP IS SUCH THAT DEXP(OFLEXP) JUST DOES NOT CAUSE OVERFLOW
!         OFLGAM IS SUCH THAT DEXP(DLGAMA(OFLGAM)) JUST DOES NOT CAUSE
!           OVERFLOW
!
      DATA EPS/1D-6/,MAXIT/20/,MAXSR/10/,HSTART/1.001D0/,BIG/10D0/
      DATA OFLEXP/170D0/,OFLGAM/53D0/
!
      DEL1=1.0D0
      DEL2=1.0D0
      XH=0.0D0
      XG=0.0D0
!
      T3=XMOM(3)
      T4=XMOM(4)
      DO 10 I=1,4
        PARA(I)=ZERO
   10 CONTINUE
!
!         TEST FOR FEASIBILITY
!
      IF(XMOM(2).LE.ZERO)GO TO  1000
      IF(DABS(T3).GE.ONE.OR.DABS(T4).GE.ONE)GO TO  1000
      IF(T4.LE.(FIVE*T3*T3-ONE)/FOUR)GO TO  1000
      IF(T4.GE.(FIVE*T3*T3+ONE)/SIX )GO TO  1010
!
!         SET STARTING VALUES FOR N-R ITERATION:
!         G IS CHOSEN TO GIVE THE CORRECT VALUE OF TAU-3 ON THE
!         ASSUMPTION THAT H=1 (I.E. A GENERALIZED PARETO FIT) -
!         BUT H IS ACTUALLY SET TO 1.001 TO AVOID NUMERICAL
!         DIFFICULTIES WHICH CAN SOMETIMES ARISE WHEN H=1 EXACTLY
!
      G=(ONE-THREE*T3)/(ONE+T3)
      H=HSTART
      Z=G+H*P725
      XDIST=BIG
!
!         START OF NEWTON-RAPHSON ITERATION
!
      DO 100 IT=1,MAXIT
!
!         REDUCE STEPLENGTH UNTIL WE ARE NEARER TO THE REQUIRED
!         VALUES OF TAU-3 AND TAU-4 THAN WE WERE AT THE PREVIOUS STEP
!
      DO 40 I=1,MAXSR
!
!         - CALCULATE CURRENT TAU-3 AND TAU-4
!
!           NOTATION:
!           U.    - RATIOS OF GAMMA FUNCTIONS WHICH OCCUR IN THE PWM'S
!                   BETA-SUB-R
!           ALAM. - L-MOMENTS (APART FROM A LOCATION AND SCALE SHIFT)
!           TAU.  - L-MOMENT RATIOS
!
      IF(G.GT.OFLGAM)GO TO  1020
      IF(H.GT.ZERO)GO TO  20
!CCCC U1=DEXP(DLGAMA(  -ONE/H-G)-DLGAMA(  -ONE/H+ONE))
!CCCC U2=DEXP(DLGAMA(  -TWO/H-G)-DLGAMA(  -TWO/H+ONE))
!CCCC U3=DEXP(DLGAMA(-THREE/H-G)-DLGAMA(-THREE/H+ONE))
!CCCC U4=DEXP(DLGAMA( -FOUR/H-G)-DLGAMA( -FOUR/H+ONE))
      U1=DEXP(DLGADP(  -ONE/H-G)-DLGADP(  -ONE/H+ONE))
      U2=DEXP(DLGADP(  -TWO/H-G)-DLGADP(  -TWO/H+ONE))
      U3=DEXP(DLGADP(-THREE/H-G)-DLGADP(-THREE/H+ONE))
      U4=DEXP(DLGADP( -FOUR/H-G)-DLGADP( -FOUR/H+ONE))
      GO TO  30
   20 CONTINUE
!CCCC U1=DEXP(DLGAMA(  ONE/H)-DLGAMA(  ONE/H+ONE+G))
!CCCC U2=DEXP(DLGAMA(  TWO/H)-DLGAMA(  TWO/H+ONE+G))
!CCCC U3=DEXP(DLGAMA(THREE/H)-DLGAMA(THREE/H+ONE+G))
!CCCC U4=DEXP(DLGAMA( FOUR/H)-DLGAMA( FOUR/H+ONE+G))
      U1=DEXP(DLGADP(  ONE/H)-DLGADP(  ONE/H+ONE+G))
      U2=DEXP(DLGADP(  TWO/H)-DLGADP(  TWO/H+ONE+G))
      U3=DEXP(DLGADP(THREE/H)-DLGADP(THREE/H+ONE+G))
      U4=DEXP(DLGADP( FOUR/H)-DLGADP( FOUR/H+ONE+G))
   30 CONTINUE
      ALAM2=U1-TWO*U2
      ALAM3=-U1+SIX*U2-SIX*U3
      ALAM4=U1-TWELVE*U2+THIRTY*U3-TWENTY*U4
      IF(ALAM2.EQ.ZERO)GO TO  1020
      TAU3=ALAM3/ALAM2
      TAU4=ALAM4/ALAM2
      E1=TAU3-T3
      E2=TAU4-T4
!
!         - IF NEARER THAN BEFORE, EXIT THIS LOOP
!
      DIST=DMAX1(DABS(E1),DABS(E2))
      IF(DIST.LT.XDIST)GO TO  50
!
!         - OTHERWISE, HALVE THE STEPLENGTH AND TRY AGAIN
!
      DEL1=HALF*DEL1
      DEL2=HALF*DEL2
      G=XG-DEL1
      H=XH-DEL2
   40 CONTINUE
!
!         TOO MANY STEPLENGTH REDUCTIONS
!
      GO TO 1050
!
!         TEST FOR CONVERGENCE
!
   50 CONTINUE
      IF(DIST.LT.EPS)GO TO  110
!
!         NOT CONVERGED: CALCULATE NEXT STEP
!
!         NOTATION:
!         U1G  - DERIVATIVE OF U1 W.R.T. G
!         DL2G - DERIVATIVE OF ALAM2 W.R.T. G
!         D..  - MATRIX OF DERIVATIVES OF TAU-3 AND TAU-4 W.R.T. G AND H
!         H..  - INVERSE OF DERIVATIVE MATRIX
!         DEL. - STEPLENGTH
!
      XG=G
      XH=H
      XZ=Z
      XDIST=DIST
      RHH=ONE/(H*H)
      IF(H.GT.ZERO)GO TO  60
      U1G=-U1*DPSI(  -ONE/H-G)
      U2G=-U2*DPSI(  -TWO/H-G)
      U3G=-U3*DPSI(-THREE/H-G)
      U4G=-U4*DPSI( -FOUR/H-G)
      U1H=      RHH*(-U1G-U1*DPSI(  -ONE/H+ONE))
      U2H=  TWO*RHH*(-U2G-U2*DPSI(  -TWO/H+ONE))
      U3H=THREE*RHH*(-U3G-U3*DPSI(-THREE/H+ONE))
      U4H= FOUR*RHH*(-U4G-U4*DPSI( -FOUR/H+ONE))
      GO TO  70
   60 U1G=-U1*DPSI(  ONE/H+ONE+G)
      U2G=-U2*DPSI(  TWO/H+ONE+G)
      U3G=-U3*DPSI(THREE/H+ONE+G)
      U4G=-U4*DPSI( FOUR/H+ONE+G)
      U1H=      RHH*(-U1G-U1*DPSI(  ONE/H))
      U2H=  TWO*RHH*(-U2G-U2*DPSI(  TWO/H))
      U3H=THREE*RHH*(-U3G-U3*DPSI(THREE/H))
      U4H= FOUR*RHH*(-U4G-U4*DPSI( FOUR/H))
   70 CONTINUE
      DL2G=U1G-TWO*U2G
      DL2H=U1H-TWO*U2H
      DL3G=-U1G+SIX*U2G-SIX*U3G
      DL3H=-U1H+SIX*U2H-SIX*U3H
      DL4G=U1G-TWELVE*U2G+THIRTY*U3G-TWENTY*U4G
      DL4H=U1H-TWELVE*U2H+THIRTY*U3H-TWENTY*U4H
      D11=(DL3G-TAU3*DL2G)/ALAM2
      D12=(DL3H-TAU3*DL2H)/ALAM2
      D21=(DL4G-TAU4*DL2G)/ALAM2
      D22=(DL4H-TAU4*DL2H)/ALAM2
      DET=D11*D22-D12*D21
      H11= D22/DET
      H12=-D12/DET
      H21=-D21/DET
      H22= D11/DET
      DEL1=E1*H11+E2*H12
      DEL2=E1*H21+E2*H22
!
!         TAKE NEXT N-R STEP
!
      G=XG-DEL1
      H=XH-DEL2
      Z=G+H*P725
!
!         REDUCE STEP IF G AND H ARE OUTSIDE THE PARAMETER SPACE
!
      FACTOR=ONE
      IF(G.LE.-ONE)FACTOR=P8*(XG+ONE)/DEL1
      IF(H.LE.-ONE)FACTOR=DMIN1(FACTOR,P8*(XH+ONE)/DEL2)
      IF(Z.LE.-ONE)FACTOR=DMIN1(FACTOR,P8*(XZ+ONE)/(XZ-Z))
      IF(H.LE.ZERO.AND.G*H.LE.-ONE)   &
        FACTOR=DMIN1(FACTOR,P8*(XG*XH+ONE)/(XG*XH-G*H))
      IF(FACTOR.EQ.ONE)GO TO  80
      DEL1=DEL1*FACTOR
      DEL2=DEL2*FACTOR
      G=XG-DEL1
      H=XH-DEL2
      Z=G+H*P725
   80 CONTINUE
!
!         END OF NEWTON-RAPHSON ITERATION
!
  100 CONTINUE
!
!         NOT CONVERGED
!
      GO TO 1040
!
!         CONVERGED
!
  110 IFAIL=0
      PARA(4)=H
      PARA(3)=G
!CCCC TEMP=DLGAMA(ONE+G)
      TEMP=DLGADP(ONE+G)
      IF(TEMP.GT.OFLEXP)GO TO  1030
      GAM=DEXP(TEMP)
      TEMP=(ONE+G)*DLOG(DABS(H))
      IF(TEMP.GT.OFLEXP)GO TO  1030
      HH=DEXP(TEMP)
      PARA(2)=XMOM(2)*G*HH/(ALAM2*GAM)
      PARA(1)=XMOM(1)-PARA(2)/G*(ONE-GAM*U1/HH)
      GO TO 9000
!
 1000 CONTINUE
      IFAIL=1
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1001)
 1001 FORMAT('**** ERROR IN KAPPA L-MOMENTS ESTIMATION--')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1003)
 1003 FORMAT('     THE L-MOMENTS ARE INVALID')
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
!
 1010 CONTINUE
      IFAIL=2
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1001)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1013)
 1013 FORMAT('     (TAU-3, TAU-4) LIES ABOVE THE GENERALIZED ',   &
             'LOGISTIC LINE.')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1014)
 1014 FORMAT('     THIS SUGGEST THAT THE L-MOMENTS ARE NOT CONSISTENT',   &
             ' WITH ANY KAPPA')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1015)
 1015 FORMAT('     DISTRIBUTION WITH H GREATER THAN -1.')
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
!
 1020 CONTINUE
      IFAIL=5
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1001)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1023)
 1023 FORMAT('     THE ITERATION ENCOUNTERED NUMERICAL DIFFICULTIIES.')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1024)
 1024 FORMAT('     OVERFLOW WOULD HAVE BEEN LIKELY TO OCCUR.')
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
!
!                  6  ITERATION FOR H AND K CONVERGED, BUT OVERFLOW
!                     WOULD HAVE OCCURRED WHEN CALCULATING XI AND ALPHA
 1030 CONTINUE
      IFAIL=6
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1001)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1033)
 1033 FORMAT('     THE ITERATION FOR H AND K CONVERGED, BUT OVERFLOW')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1034)
 1034 FORMAT('     WOULD HAVE OCCURRED WHEN CALCULATING THE ',   &
             'LOCATION AND SCALE ESTIMATES.')
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
!
 1040 CONTINUE
      IFAIL=3
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1001)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1043)
 1043 FORMAT('     THE L-MOMENTS ESTIMATION FAILED TO CONVERGE.')
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
!
 1050 CONTINUE
      IFAIL=4
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1001)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1053)
 1053 FORMAT('     THE L-MOMENTS ESTIMATION IS UNABLE TO MAKE PROGRESS')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1054)
 1054 FORMAT('     FROM THE CURRENT POINT IN THE ITERATION.')
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PELKAP
!===================================================== PELPE3.FOR
      SUBROUTINE PELPE3(XMOM,PARA,IFAIL)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  PARAMETER ESTIMATION VIA L-MOMENTS FOR THE PEARSON TYPE 3 DISTRIBUTION
!
!  PARAMETERS OF ROUTINE:
!  XMOM   * INPUT* ARRAY OF LENGTH 3. CONTAINS THE L-MOMENTS LAMBDA-1,
!                  LAMBDA-2 AND TAU-3.
!  PARA   *OUTPUT* ARRAY OF LENGTH 3. ON EXIT, CONTAINS THE PARAMETERS
!                  IN THE ORDER MU, SIGMA, GAMMA (MEAN, S.D., SKEWNESS).
!
!  OTHER ROUTINES USED: DLGAMA (DLGADP)
!
!  METHOD: RATIONAL APPROXIMATION IS USED TO EXPRESS ALPHA, THE SHAPE
!  PARAMETER OF THE GAMMA DISTRIBUTION, AS A FUNCTION OF TAU-3.
!  RELATIVE ACCURACY OF THE APPROXIMATION IS BETTER THAN 3E-5.
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION XMOM(3),PARA(3)
!CCCC EXTERNAL DLGAMA
      EXTERNAL DLGADP
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,THIRD/0.33333333D0/,HALF/0.5D0/,ONE/1D0/,TWO/2D0/
!
!         SMALL IS USED TO TEST WHETHER SKEWNESS IS EFFECTIVELY ZERO
!
      DATA SMALL/1D-6/
!
!         CONSTANTS USED IN MINIMAX APPROXIMATIONS
!
      DATA C1,C2,C3/ 0.2906D0,  0.1882D0,  0.0442D0/
      DATA D1,D2,D3/ 0.36067D0,-0.59567D0, 0.25361D0/
      DATA D4,D5,D6/-2.78861D0, 2.56096D0,-0.77045D0/
      DATA PI3,ROOTPI/9.4247780D0,1.7724539D0/
!
      IFAIL=0
      T3=DABS(XMOM(3))
      IF(XMOM(2).LE.ZERO.OR.T3.GE.ONE)THEN
        IFAIL=1
        WRITE(ICOUT,7000)
 7000   FORMAT('****** ERROR IN PEARSON TYPE 3 L-MOMENTS ESTIMATION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,7001)
 7001   FORMAT('       L-MOMENTS ARE INVALID.')
        CALL DPWRST('XXX','WRIT')
        DO 1010 I=1,3
          PARA(I)=ZERO
 1010   CONTINUE
        GO TO 9000
      ELSEIF(T3.LE.SMALL)THEN
!
!       ZERO SKEWNESS
!
        PARA(1)=XMOM(1)
        PARA(2)=XMOM(2)*ROOTPI
        PARA(3)=ZERO
        GO TO 9000
      ELSEIF(T3.GE.THIRD)THEN
        T=ONE-T3
        ALPHA=T*(D1+T*(D2+T*D3))/(ONE+T*(D4+T*(D5+T*D6)))
      ELSE
        T=PI3*T3*T3
        ALPHA=(ONE+C1*T)/(T*(ONE+T*(C2+T*C3)))
      ENDIF
!
      RTALPH=DSQRT(ALPHA)
!CCCC BETA=ROOTPI*XMOM(2)*DEXP(DLGAMA(ALPHA)-DLGAMA(ALPHA+HALF))
      BETA=ROOTPI*XMOM(2)*DEXP(DLGADP(ALPHA)-DLGADP(ALPHA+HALF))
      PARA(1)=XMOM(1)
      PARA(2)=BETA*RTALPH
      PARA(3)=TWO/RTALPH
      IF(XMOM(3).LT.ZERO)PARA(3)=-PARA(3)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PELPE3
      SUBROUTINE PELWAK(XMOM,PARA,IFAIL)
!===================================================== PELWAK.FOR
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  PARAMETER ESTIMATION VIA L-MOMENTS FOR THE WAKEBY DISTRIBUTION
!
!  PARAMETERS OF ROUTINE:
!  XMOM   * INPUT* ARRAY OF LENGTH 5. CONTAINS THE L-MOMENTS LAMBDA-1,
!                  LAMBDA-2, TAU-3, TAU-4, TAU-5.
!  PARA   *OUTPUT* ARRAY OF LENGTH 5. ON EXIT, CONTAINS THE PARAMETERS
!                  IN THE ORDER XI, ALPHA, BETA, GAMMA, DELTA.
!  IFAIL  *OUTPUT* FAIL FLAG. ON EXIT, IT IS SET AS FOLLOWS.
!                  0 SUCCESSFUL EXIT
!                  1 ESTIMATES COULD ONLY BE OBTAINED BY SETTING XI=0
!                  2 ESTIMATES COULD ONLY BE OBTAINED BY FITTING A
!                    GENERALIZED PARETO DISTRIBUTION
!                  3 L-MOMENTS INVALID
!
!  PROCEDURE:
!  1. LOOK FOR A SOLUTION WITH XI UNCONSTRAINED;
!  2. IF NONE FOUND, LOOK FOR A SOLUTION WITH XI=0;
!  3. IF NONE FOUND, FIT A GENERALIZED PARETO DISTRIBUTION TO THE
!     FIRST 3 L-MOMENTS.
!  ESTIMATES ARE CALCULATED USING THE FORMULAS GIVEN BY GREENWOOD ET AL.
!  (1979, WATER RESOUR. RES., TABLE 5), BUT EXPRESSED IN TERMS OF
!  L-MOMENTS RATHER THAN PROBABILITY WEIGHTED MOMENTS.
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION XMOM(5),PARA(5)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,HALF/0.5D0/,ONE/1D0/,TWO/2D0/,THREE/3D0/,FOUR/4D0/
      DATA X2/2D0/,X3/3D0/,X4/4D0/,X5/5D0/,X7/7D0/,X8/8D0/,X9/9D0/,   &
        X10/10D0/,X11/11D0/,X16/16D0/,X25/25D0/,X29/29D0/,X32/32D0/,   &
        X35/35D0/,X85/85D0/,X125/125D0/,X203/203D0/
!
      IF(DABS(XMOM(2)).LE.ZERO)GO TO  1000
      IF(DABS(XMOM(3)).GE.ONE)GO TO  1000
      IF(DABS(XMOM(4)).GE.ONE)GO TO  1000
      IF(DABS(XMOM(5)).GE.ONE)GO TO  1000
      IFAIL=0
!
!         CALCULATE THE L-MOMENTS (LAMBDA'S)
!
      ALAM1=XMOM(1)
      ALAM2=XMOM(2)
      ALAM3=XMOM(3)*ALAM2
      ALAM4=XMOM(4)*ALAM2
      ALAM5=XMOM(5)*ALAM2
!
!         ESTIMATE N1,N2,N3,C1,C2,C3 WHEN XI.NE.0
!
      XN1= X3*ALAM2-X25*ALAM3 +X32*ALAM4
      XN2=-X3*ALAM2 +X5*ALAM3  +X8*ALAM4
      XN3= X3*ALAM2 +X5*ALAM3  +X2*ALAM4
      XC1= X7*ALAM2-X85*ALAM3+X203*ALAM4-X125*ALAM5
      XC2=-X7*ALAM2+X25*ALAM3  +X7*ALAM4 -X25*ALAM5
      XC3= X7*ALAM2 +X5*ALAM3  -X7*ALAM4  -X5*ALAM5
!
!         ESTIMATE B AND D
!
      XA=XN2*XC3-XC2*XN3
      XB=XN1*XC3-XC1*XN3
      XC=XN1*XC2-XC1*XN2
      DISC=XB*XB-FOUR*XA*XC
      IF(DISC.LT.ZERO)GO TO  10
      DISC=DSQRT(DISC)
      ROOT1=HALF*(-XB+DISC)/XA
      ROOT2=HALF*(-XB-DISC)/XA
      B= DMAX1(ROOT1,ROOT2)
      D=-DMIN1(ROOT1,ROOT2)
      IF(D.GE.ONE)GO TO  10
!
!         ESTIMATE A, C AND XI
!
      A=(ONE+B)*(TWO+B)*(THREE+B)/   &
        (FOUR*(B+D))*((ONE+D)*ALAM2-(THREE-D)*ALAM3)
      C=-(ONE-D)*(TWO-D)*(THREE-D)/   &
        (FOUR*(B+D))*((ONE-B)*ALAM2-(THREE+B)*ALAM3)
      XI=ALAM1-A/(ONE+B)-C/(ONE-D)
!
!         CHECK FOR VALID PARAMETERS
!
      IF(C.GE.ZERO.AND.A+C.GE.ZERO)GO TO  30
!
!         CAN'T FIND VALID ESTIMATES FOR XI UNRESTRICTED, SO TRY XI=0
!
!         ESTIMATE B AND D FOR XI=0
!
   10 CONTINUE
      IFAIL=1
      XI=ZERO
      ZN1=X4*ALAM1-X11*ALAM2+X9*ALAM3
      ZN2=-ALAM2+X3*ALAM3
      ZN3=ALAM2+ALAM3
      ZC1=X10*ALAM1-X29*ALAM2+X35*ALAM3-X16*ALAM4
      ZC2=-ALAM2+X5*ALAM3-X4*ALAM4
      ZC3=ALAM2-ALAM4
      ZA=ZN2*ZC3-ZC2*ZN3
      ZB=ZN1*ZC3-ZC1*ZN3
      ZC=ZN1*ZC2-ZC1*ZN2
      DISC=ZB*ZB-FOUR*ZA*ZC
      IF(DISC.LT.ZERO)GO TO  20
      DISC=DSQRT(DISC)
      ROOT1=HALF*(-ZB+DISC)/ZA
      ROOT2=HALF*(-ZB-DISC)/ZA
      B= DMAX1(ROOT1,ROOT2)
      D=-DMIN1(ROOT1,ROOT2)
      IF(D.GE.ONE)GO TO  20
!
!         ESTIMATE A AND C
!
      A= (ONE+B)*(TWO+B)/(B+D)*(ALAM1-(TWO-D)*ALAM2)
      C=-(ONE-D)*(TWO-D)/(B+D)*(ALAM1-(TWO+B)*ALAM2)
      IF(C.GE.ZERO.AND.A+C.GE.ZERO)GO TO  30
!
!         CAN'T FIND VALID ESTIMATES EVEN WITH XI=0 -
!         FIT GENERALIZED PARETO DISTRIBUTION INSTEAD
!
   20 CONTINUE
      IFAIL=2
      D=-(ONE-THREE*XMOM(3))/(ONE+XMOM(3))
      C=(ONE-D)*(TWO-D)*XMOM(2)
      B=ZERO
      A=ZERO
      XI=XMOM(1)-C/(ONE-D)
      IF(D.GT.ZERO)GO TO  30
      A=C
      B=-D
      C=ZERO
      D=ZERO
!
!         COPY RESULTS INTO ARRAY PARA
!
   30 CONTINUE
      PARA(1)=XI
      PARA(2)=A
      PARA(3)=B
      PARA(4)=C
      PARA(5)=D
      GO TO 9000
!
 1000 IFAIL=3
      DO 1010 I=1,5
        PARA(I)=ZERO
 1010 CONTINUE
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PELWAK
      COMPLEX FUNCTION PEQ(Z)
!
!     WEIERSTRASS: P-FUNCTION IN THE EQUIANHARMONIC CASE
!     FOR COMPLEX ARGUMENT WITH UNIT PERIOD PARALLELOGRAM
!
      INCLUDE 'DPCOMC.INC'
      COMPLEX Z, Z2, Z4, Z6
      REAL ZR, ZI
      INTEGER M, N
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!
!     REDUCTION TO FUNDAMENTAL PARALLELOGRAM
!
      ZI = 1.1547005383792515E0*AIMAG(Z) + 0.5E0
      M = INT(ZI)
      IF (ZI.LT.0E0) M = M - 1
      ZR = REAL(Z) - 0.5E0*FLOAT(M) + 0.5E0
      N = INT(ZR)
      IF (ZR.LT.0E0) N = N - 1
      Z2 = Z - FLOAT(N) - (0.5E0,0.86602540378443865E0)*FLOAT(M)
!
!     IF Z2=0 THEN Z COINCIDES WITH A LATTICE POINT.
!     SINCE P HAS POLES AT THE LATTICE POINTS,
!     A DIVISION ERROR WILL OCCUR
!
      IF(REAL(Z2).EQ.0.0.AND.AIMAG(Z2).EQ.0.0)THEN
        PEQ=R1MACH(2)
        WRITE(ICOUT,91)
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
   91 FORMAT('***** ERROR: INPUT POINT CORRESPONDS TO A LATTICE ',   &
      'POINT.  VALUE SET TO LARGEST REAL. *****')
      Z2 = Z2*Z2
      Z4 = Z2*Z2
      Z6 = Z4*Z2
      PEQ = 1E0/Z2 + 6E0*Z4*(5E0+Z6)/(1E0-Z6)**2 + Z4*   &
       (((((-2.6427662E-10*Z6+1.610954818E-8)*Z6+7.38610752879E-6)*   &
       Z6+4.3991444671178E-4)*Z6+7.477288220490697E-2)*   &
       Z6-6.8484153287299201E-1)/(((((6.2252191E-10*Z6+2.553314573E-7)*   &
       Z6-2.619832920421E-5)*Z6-5.6444801847646E-4)*   &
       Z6+4.565553484820106E-2)*Z6+1E0)
      RETURN
      END FUNCTION PEQ
      COMPLEX FUNCTION PEQ1(Z)
!
!     FIRST DERIVATIVE OF WEIERSTRASS: P-FUNCTION IN THE
!     EQUIANHARMONIC CASE FOR COMPLEX ARGUMENT
!     WITH UNIT PERIOD PARALLELOGRAM
!
      INCLUDE 'DPCOMC.INC'
      COMPLEX Z, Z3, Z6
      REAL ZR, ZI
      INTEGER M, N
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!     REDUCTION TO FUNDAMENTAL PARALLELOGRAM
!
      ZI = 1.1547005383792515E0*AIMAG(Z) + 0.5E0
      M = INT(ZI)
      IF (ZI.LT.0E0) M = M - 1
      ZR = REAL(Z) - 0.5E0*FLOAT(M) + 0.5E0
      N = INT(ZR)
      IF (ZR.LT.0E0) N = N - 1
      Z3 = Z - FLOAT(N) - (0.5E0,0.86602540378443865E0)*FLOAT(M)
!
!     IF Z3=0 THEN Z COINCIDES WITH A LATTICE POINT.
!     SINCE P: HAS POLES AT THE LATTICE POINTS,
!     A DIVISION ERROR WILL OCCUR
!
      IF(REAL(Z3).EQ.0.0.AND.AIMAG(Z3).EQ.0.0)THEN
        PEQ1=R1MACH(2)
        WRITE(ICOUT,91)
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
   91 FORMAT('***** ERROR: INPUT POINT CORRESPONDS TO A LATTICE ',   &
      'POINT.  VALUE SET TO LARGEST REAL. *****')
      Z3 = Z3*Z3*Z3
      Z6 = Z3*Z3
      PEQ1 = (((14E0*Z6+294E0)*Z6+126E0)*Z6-2E0)/(Z3*(1E0-Z6)**3) +   &
       Z3*((((((-2.95539175E-9*Z6-2.6764693031E-7)*Z6+2.402192743346E-5)   &
       *Z6+1.9656661451391E-4)*Z6+1.760135529461036E-2)*   &
       Z6+8.1026243498822636E-1)*Z6-2.73936613149196804E0)/   &
       ((((((4.6397763E-10*Z6+5.413482233E-8)*Z6-1.56293298374E-6)*   &
       Z6-1.0393701076352E-4)*Z6+9.5553182532237E-4)*   &
       Z6+9.131106969640212E-2)*Z6+1E0)
      RETURN
      END FUNCTION PEQ1
      SUBROUTINE PERAGR(X,Y,N,IWRITE,RIGHT,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT AGREEMENT
!              BETWEEN THE 2 SETS OF DATA IN THE INPUT VECTORS X AND Y.
!              THIS IS USEFUL IN THE CONTEXT OF DETERMINING WHAT
!              PERCENTAGE OF THE TIME TWO METHODS RESULT IN THE
!              SAME DECISION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF UNSORTED
!                                OBSERVATIONS WHICH CONSTITUTE THE FIRST
!                                SET OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF UNSORTED
!                                OBSERVATIONS WHICH CONSTITUTE THE SECOND
!                                SET OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--RIGHT  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED PERCENTAGE OF AGREEMENT
!                                BETWEEN THE 2 SETS OF DATA IN THE
!                                INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PERCENTAGE AGREEMENT BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/7
!     ORIGINAL VERSION--JULY      2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /1.0E-12/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PERA'
      ISUBN2='GR  '
      IERROR='NO'
      RIGHT=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RAGR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PERAGR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN PERCENTAGE AGREEMENT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLES IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS      = ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE PERCENTAGE AGREEMENT.         **
!               ************************************************
!
      NMATCH=0
      DO 200 I=1,N
        IF(ABS(Y(I) - X(I)).LE.EPS)NMATCH=NMATCH+1
  200 CONTINUE
      RIGHT=REAL(NMATCH)/REAL(N)
      RIGHT=100.0*RIGHT
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,RIGHT
  811   FORMAT('THE PERCENTAGE ARGEEMENT OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RAGR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF PERAGR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)N,NMATCH,RIGHT
 9015   FORMAT('N,NMATCH,RIGHT = ',2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PERAGR
      SUBROUTINE PERCEN(P100,X,N,IWRITE,XTEMP,MAXNXT,   &
                        XPERC,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE PERCENTILE
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--P100   = THE SINGLE PRECISION PERCENTAGE
!                                (BETWEEN 0 AND 100)
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XPERC  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE PERCENTILE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PERCENTILE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HYNDMAN AND FAN (NOVEMBER 1996), "SAMPLE QUANTILES IN
!                 STATISTICAL PACKAGES", THE AMERICAN STATISTICIAN,
!                 VOL. 50, NO. 4, PP. 361-365.
!     WRITTEN BY--JAMES J. FILLIBEN/ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--87.11
!     ORIGINAL VERSION--SEPTEMBER 1987.
!     UPDATED         --FEBRUARY  2015. SUPPORT "R8" AND "R7" METHODS
!     UPDATED         --DECEMBER  2017. SUPPORT "AVERAGE" METHOD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PERCEN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)P100,N,IBUGA3
   53   FORMAT('P100,N,IBUGA3, = ',G15.7,I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      ISUBN1='PERC'
      ISUBN2='EN  '
      IERROR='NO'
!
      NI=0
      NIP1=0
      ANI=0.0
      A2NI=0.0
      REM=0.0
!
!               ******************************
!               **  COMPUTE PERCENTILE      **
!               ******************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(P100.LT.0.0 .OR. P100.GT.100.0)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN PERCENTILE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT PERCENTAGE FOR WHICH THE PERCENTILE ',   &
               'IS TO BE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      COMPUTED MUST BE LARGER THAN 0 AND SMALLER ',   &
               'THAN 100.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)P100
  117   FORMAT('      SUCH WAS NOT THE CASE HERE.  THE INPUT ',   &
               'PERCENTAGE = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS FOR THE ',   &
               'RESPONSE VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,125)MAXNXT
  125   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)N
  127   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XPERC=X(1)
        GO TO 9000
      ENDIF
!
!     CASE WHERE ALL RESPONSE VALUES ARE THE SAME
!
      HOLD=X(1)
      DO 145 I=2,N
        IF(X(I).NE.HOLD)GO TO 149
  145 CONTINUE
      XPERC=HOLD
      GO TO 9000
  149 CONTINUE
!
!               ***********************************
!               **  STEP 2--                     **
!               **  COMPUTE THE PERCENTILE.      **
!               ***********************************
!
      CALL SORT(X,N,XTEMP)
!
      P=P100/100.0
!
!     NOTE 2015/02: THE HYNDMAN AND FAN ARTICLE DISCUSSES EIGHT
!                   DEFINITIONS OF A PERCENTILE IN RELATION TO SIX
!                   DESIRABLE PROPERTIES.  THE DEFAULT DATAPLOT
!                   ALGORITHM USES THE "R6" DEFINITION.  THEIR
!                   RECOMMENDATION FOR A "STANDARD" DEFINITION IS
!                   "R8".  ALLOW THE USER TO REQUEST THE R8
!                   DEFINITION (SPECIFIED IN IQUAME VARIABLE).
!                   THE R7 METHOD IS ALSO SUPPORTED (THIS IS THE
!                   DEFAULT METHOD FOR R AND EXCEL).
!
!                   ALSO, FOR DEFAULT DEFINITION, LOOK FOR MINIMUM
!                   AND MAXIMUM VALUES OF P100 THAT ARE SET TO THE
!                   DATA MINIMUM AND MAXIMUM, RESPECTIVELY.
!
      IF(IQUAME.EQ.'R8')THEN
        AVAL1=2.0/3.0
        AVAL2=1.0/3.0
        ALOW=AVAL1/(AN+AVAL2)
        AHIGH=(AN-AVAL2)/(AN+AVAL2)
        IF(P.LT.ALOW)THEN
          XPERC=XTEMP(1)
        ELSEIF(P.GE.AHIGH)THEN
          XPERC=XTEMP(N)
        ELSE
          ANI=P*(AN+AVAL2) + AVAL2
          NI=INT(ANI)
          A2NI=REAL(NI)
          REM=ANI-A2NI
          NIP1=NI+1
          IF(NI.LE.1)NI=1
          IF(NI.GE.N)NI=N
          IF(NIP1.LE.1)NIP1=1
          IF(NIP1.GE.N)NIP1=N
          XPERC=XTEMP(NI) + REM*(XTEMP(NIP1) - XTEMP(NI))
        ENDIF
      ELSEIF(IQUAME.EQ.'R7')THEN
        AHIGH=1.0
        IF(P.GE.AHIGH)THEN
          XPERC=XTEMP(N)
        ELSE
          AVAL1=1.0
          ANI=P*(AN-AVAL1) + AVAL1
          NI=INT(ANI)
          A2NI=REAL(NI)
          REM=ANI-A2NI
          NIP1=NI+1
          IF(NI.LE.1)NI=1
          IF(NI.GE.N)NI=N
          IF(NIP1.LE.1)NIP1=1
          IF(NIP1.GE.N)NIP1=N
          XPERC=XTEMP(NI) + REM*(XTEMP(NIP1) - XTEMP(NI))
        ENDIF
      ELSEIF(IQUAME.EQ.'AVER')THEN
!
!        AVERAGE METHOD - TAKE AVERAGE OF TWO CLOSEST POINTS, NOT
!        RECOMMENDED, BUT THIS APPEARS TO BE METHOD USED BY BONETT
!        FOR CONFIDENCE INTERVALS FOR COEFFCIENT OF QUARTILE
!        DISPERSION.  INCLUDE SO THAT WE CAN MATCH HIS RESULTS.
!
        AINDX=P*AN
        IINDX=INT(AINDX)
        IF(IINDX.EQ.N)THEN
          XPERC=XTEMP(IINDX)
        ELSEIF(IINDX.LT.1)THEN
          XPERC=XTEMP(1)
        ELSE
          XPERC=(XTEMP(IINDX) + XTEMP(IINDX+1))/2.0
        ENDIF
      ELSE
        ALOW=1.0/(AN+1.0)
        AHIGH=AN/(AN+1.0)
        IF(P.LT.ALOW)THEN
          XPERC=XTEMP(1)
        ELSEIF(P.GE.AHIGH)THEN
          XPERC=XTEMP(N)
        ELSE
          ANI=P*(AN+1.0)
          NI=INT(ANI)
          A2NI=REAL(NI)
          REM=ANI-A2NI
          NIP1=NI+1
          IF(NI.LE.1)NI=1
          IF(NI.GE.N)NI=N
          IF(NIP1.LE.1)NIP1=1
          IF(NIP1.GE.N)NIP1=N
!CCCC     BUG FIX.  WEIGHTS IN WRONG ORDER!  NOVEMBER 1998.
!CCCC     XPERC=REM*XTEMP(NI)+(1.0-REM)*XTEMP(NIP1)
          XPERC=(1.0-REM)*XTEMP(NI)+REM*XTEMP(NIP1)
        ENDIF
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)P100,N,XPERC
  811   FORMAT('THE ',F10.2,'-PERCENTILE OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF PERCEN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N,P100,P,XPERC
 9013   FORMAT('IERROR,N,P100,P,XPERC = ',A4,2X,I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NI,NIP1,ANI,A2NI,REM
 9014   FORMAT('NI,NIP1,ANI,A2NI,REM = ',2I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PERCEN
      SUBROUTINE PERCE2(NPERC,X,N,IWRITE,XTEMP,MAXNXT,XPERC,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE IS SIMILAR TO THE PERCEN SUBROUTINE.
!              THAT ROUTINE COMPUTES A SINGLE SPECIFIED PERCENTILE.
!              IN THIS ROUTINE, WE SPECIFY THE NUMBER OF PERCENTILES
!              WE WANT TO COMPUTE.  FOR EXAMPLE, IF YOU WANT TO
!              GENERATE A Q-Q PLOT FOR VERY LARGE DATA SETS, YOU CAN
!              USE THIS ROUTINE TO GENERATE PERCENTILES AT A SPECIFIED
!              NUMBER OF POINTS AND THEN GENERATE THE Q-Q PLOT ON THESE
!              REDUCED DATA SETS.
!     INPUT  ARGUMENTS--NPERC  = THE INTEGER SPECIFYING THE NUMBER OF
!                                PERCENTILES TO GENERATE.
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XPERC  = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED SAMPLE PERCENTILES.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUES OF THE
!             SAMPLE PERCENTILES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HYNDMAN AND FAN (NOVEMBER 1996), "SAMPLE QUANTILES IN
!                 STATISTICAL PACKAGES", THE AMERICAN STATISTICIAN,
!                 VOL. 50, NO. 4, PP. 361-365.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--2016.06
!     ORIGINAL VERSION--JUNE      2016.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DIMENSION XPERC(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RCE2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PERCE2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NPERC,N,IBUGA3
   53   FORMAT('NPERC,N,IBUGA3, = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      ISUBN1='PERC'
      ISUBN2='E2  '
      IERROR='NO'
!
      NI=0
      NIP1=0
      ANI=0.0
      A2NI=0.0
      REM=0.0
!
!               ******************************
!               **  COMPUTE PERCENTILE      **
!               ******************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(NPERC.LT.1 .OR. NPERC.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN PERCENTILE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)MAXNXT
  112   FORMAT('      THE REQUESTED NUMBER OF PERCENTILES IS LESS ',   &
               'ONE OR GREATER THAN ',I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)NPERC
  117   FORMAT('      THE REQUESTED NUMBER OF PERCENTILES IS ',I10)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,125)MAXNXT
  125   FORMAT('      MUST BE BETWEEN 1 AND ',I10,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)N
  127   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XPERC(1)=X(1)
        GO TO 9000
      ENDIF
!
!     CASE WHERE ALL RESPONSE VALUES ARE THE SAME
!
      HOLD=X(1)
      DO 145 I=2,N
        IF(X(I).NE.HOLD)GO TO 149
  145 CONTINUE
      DO 148 I=1,NPERC
        XPERC(I)=HOLD
  148 CONTINUE
      GO TO 9000
  149 CONTINUE
!
!               ***********************************
!               **  STEP 2--                     **
!               **  COMPUTE THE PERCENTILE.      **
!               ***********************************
!
      CALL SORT(X,N,XTEMP)
!
      DO 1010 I=1,NPERC
!
        P=REAL(I)/REAL(NPERC)
!
!     NOTE 2015/02: THE HYNDMAN AND FAN ARTICLE DISCUSSES EIGHT
!                   DEFINITIONS OF A PERCENTILE IN RELATION TO SIX
!                   DESIRABLE PROPERTIES.  THE DEFAULT DATAPLOT
!                   ALGORITHM USES THE "R6" DEFINITION.  THEIR
!                   RECOMMENDATION FOR A "STANDARD" DEFINITION IS
!                   "R8".  ALLOW THE USER TO REQUEST THE R8
!                   DEFINITION (SPECIFIED IN IQUAME VARIABLE).
!                   THE R7 METHOD IS ALSO SUPPORTED (THIS IS THE
!                   DEFAULT METHOD FOR R AND EXCEL).
!
!                   ALSO, FOR DEFAULT DEFINITION, LOOK FOR MINIMUM
!                   AND MAXIMUM VALUES OF P100 THAT ARE SET TO THE
!                   DATA MINIMUM AND MAXIMUM, RESPECTIVELY.
!
        IF(IQUAME.EQ.'R8')THEN
          AVAL1=2.0/3.0
          AVAL2=1.0/3.0
          ALOW=AVAL1/(AN+AVAL2)
          AHIGH=(AN-AVAL2)/(AN+AVAL2)
          IF(P.LT.ALOW)THEN
            XPERC(I)=XTEMP(1)
          ELSEIF(P.GE.AHIGH)THEN
            XPERC(I)=XTEMP(N)
          ELSE
            ANI=P*(AN+AVAL2) + AVAL2
            NI=INT(ANI)
            A2NI=REAL(NI)
            REM=ANI-A2NI
            NIP1=NI+1
            IF(NI.LE.1)NI=1
            IF(NI.GE.N)NI=N
            IF(NIP1.LE.1)NIP1=1
            IF(NIP1.GE.N)NIP1=N
            XPERC(I)=XTEMP(NI) + REM*(XTEMP(NIP1) - XTEMP(NI))
          ENDIF
        ELSEIF(IQUAME.EQ.'R7')THEN
          AHIGH=1.0
          IF(P.GE.AHIGH)THEN
            XPERC(I)=XTEMP(N)
          ELSE
            AVAL1=1.0
            ANI=P*(AN-AVAL1) + AVAL1
            NI=INT(ANI)
            A2NI=REAL(NI)
            REM=ANI-A2NI
            NIP1=NI+1
            IF(NI.LE.1)NI=1
            IF(NI.GE.N)NI=N
            IF(NIP1.LE.1)NIP1=1
            IF(NIP1.GE.N)NIP1=N
            XPERC(I)=XTEMP(NI) + REM*(XTEMP(NIP1) - XTEMP(NI))
          ENDIF
        ELSE
          ALOW=1.0/(AN+1.0)
          AHIGH=AN/(AN+1.0)
          IF(P.LT.ALOW)THEN
            XPERC(I)=XTEMP(1)
          ELSEIF(P.GE.AHIGH)THEN
            XPERC(I)=XTEMP(N)
          ELSE
            ANI=P*(AN+1.0)
            NI=INT(ANI)
            A2NI=REAL(NI)
            REM=ANI-A2NI
            NIP1=NI+1
            IF(NI.LE.1)NI=1
            IF(NI.GE.N)NI=N
            IF(NIP1.LE.1)NIP1=1
            IF(NIP1.GE.N)NIP1=N
            XPERC(I)=(1.0-REM)*XTEMP(NI)+REM*XTEMP(NIP1)
          ENDIF
        ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RCE2')THEN
        WRITE(ICOUT,1011)I,P,XPERC(I)
 1011   FORMAT('I,P,XPERC(I) = ',I10,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1013)ANI,A2NI,REM
 1013   FORMAT('ANI,A2NI,REM = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 1010 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)NPERC
  811   FORMAT('NUMBER OF PERCENTILES COMPUTED = ',I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,813)XPERC(1)
  813   FORMAT('THE FIRST COMPUTED PERCENTILE = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,815)XPERC(NPERC)
  815   FORMAT('THE LAST COMPUTED PERCENTILE = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RCE2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF PERCE2--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PERCE2
      SUBROUTINE PERCRA(X,N,IWRITE,XR,XS,MAXOBV,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE GENERATES THE PERCENTAGE RANK OF
!              EACH OF THE N ELEMENTS OF THE VECTOR X AND PUTS THE
!              RESULTING N RANKS INTO THE VECTOR XR.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS FOR WHICH THE PERCENTAGE
!                                RANKS WILL BE COMPUTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XR     = THE SINGLE PRECISION VECTOR WHERE THE
!                                PERCNTAGE RANKS WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XR CONTAINING THE RANKS
!             (IN ASCENDING ORDER) OF THE VALUES IN THE VECTOR X.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANK.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--ISO 13528, FIRST EDITION, STATISTICAL METHODS FOR USE
!                 IN PROFICIENCY TESTING BY INTERLABORATORY COMPARISONS,
!                 2005.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.1
!     ORIGINAL VERSION--JANUARY   2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XR(*)
      DIMENSION XS(MAXOBV)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PERC'
      ISUBN2='RA  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RCRA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PERCRA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               *******************************************
!               **  COMPUTE THE PERCENTAGE RANK VALUES.  **
!               *******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN PERCENTAGE RANK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('      THE NUMBER OF OBSERVATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 2--                                     **
!               **  FIRST RANK THE DATA FROM THE INPUT VECTOR X  **
!               **  INTO THE INTERMEDIATE STORAGE VECTOR XR.     **
!               ***************************************************
!
      CALL RANK(X,N,IWRITE,XR,XS,MAXOBV,IBUGA3,IERROR)
!
!               *********************************************************
!               **  STEP 3--                                           **
!               **  NOW COMPUTE THE PERCENTAGE RANKS:                  **
!               **      PERCENTAGE RANK(I) = 100*(RANK(I)-0.5)/N       **
!               **********************************************************
!
      DO 210 I=1,N
        XR(I)=100.0*(XR(I) - 0.5)/AN
  210 CONTINUE
!
!               ******************************
!               **  STEP 4--                **
!               **  WRITE OUT A FEW LINES   **
!               **  OF SUMMARY INFORMATION  **
!               **  ABOUT THE CODING.       **
!               ******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        AI=1
        WRITE(ICOUT,912)XR(1)
  912   FORMAT('THE FIRST ELEMENT HAS PERCENTAGE RANK ',F14.2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,914)XR(N)
  914   FORMAT('THE LAST  ELEMENT HAS PERCENTAGE RANK ',F14.2)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RCRA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF PERCRA--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,X(I),XR(I)
 9016     FORMAT('I,X(I),XR(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE PERCRA
      SUBROUTINE PERDEF(X,N,ENGLSL,ENGUSL,IWRITE,XACTPD,XTHEPD,   &
                        XACTL,XTHEL,XACTU,XTHEU,                  &
                        IFLAG,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              ACTUAL PERCENT DEFECTIVE (XACTPD) AND
!              THOERETICAL PERCENT DEFECTIVE (XTHEPD)
!              FROM THE DATA IN THE INPUT VECTOR X.
!              THIS CALCULATION ASSUMES--
!                 1) A NORMAL DISTRIBUTION
!                 2) WITH MEAN XBAR AND STANDARD DEVIATION S
!                 3) THE TARGET IS MIDWAY BETWEEN ENGUSL AND ENGLSL
!              XTHEPD = 100*(AREA UNDER NORMAL CURVE ABOVE USL AND BELOW LSL)
!     THE FINAL FORM FOR XTHEPD IS QUITE SIMPLE--
!        XTHEPD = 100(1-(NORCDF(ZUPPER)-NORCDF(ZLOWER)))
!     WHERE ZUPPER = (ENGUSL-MU)/SIGMA
!     AND   ZLOWER = (ENGLSL-MU)/SIGMA
!     IN PRACTICE, WE USE XBAR FOR MU AND S FOR SIGMA.
!     NOTE--XTHEPD IS A MEASURE OF PROCESS QUALITY AND IS
!           SENSITIVE TO LOSS OF QUALITY FROM BOTH BIAS AND FROM VARIATION.
!     NOTE--XTHEPD IS A MEASURE WHICH TAKES ON
!           THE VALUES 0% TO 100%
!           A GOOD PROCESS YIELDS VALUES OF
!           PERCENT DEFECTIVE NEAR 0%.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ENGLSL = LOWER (ENGINEERING) SPEC LIMIT
!                     --ENGUSL = UPPER (ENGINEERING) SPEC LIMIT
!                     --IFLAG  = WRITE FLAG (THEO, ACTU, BOTH)
!     OUTPUT ARGUMENTS--PERDEF = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE PERCENT DEFECTIVE
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PERCENT DEFECTIVE (IN XTHEPD)
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION & SINGLE PRECISION
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--R&M 2000 AIR FORCE MANUAL
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89.5
!     ORIGINAL VERSION--MAY       1989.
!     UPDATED         --SEPTEMBER 1990. REVERSE INPUT ARGS
!     UPDATED         --APRIL     2001. ADD XACTL, XTHEL, XACTU, XTHEU
!                                       THESE ARE ONE SIDED LIMITS
!                                       (CAPABILITY ANALYSIS PRINTS
!                                       THEM)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IFLAG
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DVAR
      DOUBLE PRECISION DSD
!
      DOUBLE PRECISION DUSL
      DOUBLE PRECISION DLSL
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PERD'
      ISUBN2='EF  '
      IERROR='NO'
!
      DMEAN=0.0D0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PERDEF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IFLAG,IBUGA3,N,ENGUSL,ENGLSL
   52   FORMAT('IFLAG,IBUGA3,N,ENGUSL.ENGLSL = ',2(A4,2X),I10,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO I=1,N
           WRITE(ICOUT,56)I,X(I)
   56      FORMAT('I,X(I) = ',I8,E15.7)
           CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
!               ********************************************
!               **  COMPUTE PROCESS CAPABILITY INDEX PERDEF  **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN PERDEF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE PERCENT DEFECTIVE IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN PERDEF--',
!CCCC1'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
!CCCC CALL DPWRST('XXX','BUG ')
      XSD=0.0
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN PERDEF--',
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      XSD=0.0
      GO TO 9000
  139 CONTINUE
!
!               ***************************************
!               **  STEP 2--                         **
!               **  COMPUTE THE STANDARD DEVIATION.  **
!               ***************************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
      DX=X(I)
      DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
!
      DSUM=0.0D0
      DO 300 I=1,N
      DX=X(I)
      DSUM=DSUM+(DX-DMEAN)**2
  300 CONTINUE
      DVAR=DSUM/(DN-1.0D0)
      DSD=0.0D0
      IF(DVAR.GT.0.0D0)DSD=DSQRT(DVAR)
      XSD=DSD
!
!               **************************************************
!               **  STEP 3--                                    **
!               **  COMPUTE THE ACTUAL      PERCENT DEFECTIVE   **
!               **  COMPUTE THE THEORETICAL PERCENT DEFECTIVE   **
!               **************************************************
!
      DUSL=ENGUSL
      DLSL=ENGLSL
!
      IF(DSD.EQ.0.0D0)GO TO 410
      GO TO 420
!
  410 CONTINUE
      XTHEPD=0.0
      IF(DMEAN.GT.DUSL)XTHEPD=100.0
      IF(DMEAN.LT.DLSL)XTHEPD=100.0
      GO TO 490
!
  420 CONTINUE
      ZUPPER=(DUSL-DMEAN)/DSD
      ZLOWER=(DLSL-DMEAN)/DSD
      CALL NORCDF(ZUPPER,CDFUPP)
      CALL NORCDF(ZLOWER,CDFLOW)
      XTHEPD=100.0*(1.0-(CDFUPP-CDFLOW))
      XTHEL=100.0*(CDFLOW)
      XTHEU=100.0*(1.0-CDFUPP)
!
  490 CONTINUE
!
      XACTPD=0.0
      XACTL=0.0
      XACTU=0.0
      ICOUNT=0
      DO 510 I=1,N
      IF(X(I).LT.ENGLSL.OR.X(I).GT.ENGUSL)ICOUNT=ICOUNT+1
      IF(X(I).LT.ENGLSL)XACTL=XACTL+1.0
      IF(X(I).GT.ENGUSL)XACTU=XACTU+1.0
  510 CONTINUE
      ACOUNT=ICOUNT
      IF(AN.NE.0.0)XACTPD=100.0*(ACOUNT/AN)
      IF(AN.NE.0.0)XACTL=100.0*(XACTL/AN)
      IF(AN.NE.0.0)XACTU=100.0*(XACTU/AN)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IF(IFLAG.EQ.'THEO'.OR.IFLAG.EQ.'BOTH')   &
      WRITE(ICOUT,811)N,XTHEPD
  811 FORMAT('THE (THEORETICAL) PERCENT DEFECTIVE OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      IF(IFLAG.EQ.'THEO'.OR.IFLAG.EQ.'BOTH')   &
      CALL DPWRST('XXX','BUG ')
      IF(IFLAG.EQ.'ACTU'.OR.IFLAG.EQ.'BOTH')   &
      WRITE(ICOUT,812)N,XACTPD
  812 FORMAT('THE (ACTUAL     ) PERCENT DEFECTIVE OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      IF(IFLAG.EQ.'ACTU'.OR.IFLAG.EQ.'BOTH')   &
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF PERDEF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IFLAG,IBUGA3,IERROR
 9012 FORMAT('IFLAG,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DMEAN
 9014 FORMAT('DMEAN = ',D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)DSD
 9015 FORMAT('DSD = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)DUSL,DLSL
 9016 FORMAT('DUSL,DLSL = ',2D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)ZUPPER,ZLOWER,CDFUPP,CDFLOW,XTHEPD
 9017 FORMAT('ZUPPER,ZLOWER,CDFUPP,CDFLOW,XTHEPD = ',5E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)ENGLSL,ENGUSL,ACOUNT,AN
 9021 FORMAT('ENGLSL,ENGUSL,ACOUNT,AN = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)XACTPD,XTHEPD
 9022 FORMAT('XACTPD,XTHEPD = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE PERDEF
      SUBROUTINE PERDME(Y1,N1,Y2,N2,IWRITE,PERDIF,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENTATE DIFFERENCE
!              BETWEEN THE MEANS OF TWO SAMPLES. SPECIFICALLY,
!
!                 PDIFF = 100*(Y1BAR - Y2BAR)/Y1BAR
!
!              NOTE THAT THE DIFFERENCE IS RELATIVE TO THE FIRST
!              RESPONSE VARIABLE GIVEN.
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS FOR THE FIRST
!                                SET OF DATA.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y1.
!                     --Y2     = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS FOR THE SECOND
!                                SET OF DATA.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y2.
!     OUTPUT ARGUMENTS--PERDIF = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED PERCENTAGE DIFFERENCE BETWEEN
!                                THE MEANS OF THE TWO SETS OF DATA.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PERCENTAGE DIFFERENCE BETWEEN THE MEANS OF THE TWO
!             SETS OF DATA IN THE INPUT VECTORS Y1 AND Y2.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUES OF
!                   N1 AND N2 FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/06
!     ORIGINAL VERSION--JUNE      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IWRISV
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PERD'
      ISUBN2='ME  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RDME')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PERDME--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISUBRO,IBUGA3,N1,N2
   52   FORMAT('ISUBRO,IBUGA3,N1,N2 = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I)
   56     FORMAT('I,Y1(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,Y2(I)
   66     FORMAT('I,Y2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N1.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN PERCENTAGE DIFFERENCE OF THE MEAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N1
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N2.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE     SAMPLE MEANS              **
!               **  AND THEN THE PERCENTAGE DIFFERENCE.       **
!               ************************************************
!
      IWRISV=IWRITE
      IWRITE='OFF'
      CALL MEAN(Y1,N1,IWRITE,Y1MEAN,IBUGA3,IERROR)
      CALL MEAN(Y2,N2,IWRITE,Y2MEAN,IBUGA3,IERROR)
      IWRITE=IWRISV
!
      IF(Y1MEAN.EQ.0.0)THEN
        PERDIF=0.0
        IERROR='YES'
        GO TO 9000
      ELSE
        PERDIF=(Y2MEAN-Y1MEAN)/Y1MEAN
        PERDIF=100.0*PERDIF
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)PERDIF
  811   FORMAT('THE PERCENTAGE DIFFERENCE OF THE TWO MEANS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RDME')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF PERDME--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,Y1MEAN,Y2MEAN,PERDIF
 9012   FORMAT('IERROR,Y1MEAN,Y2MEAN,PERDIF = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PERDME
      SUBROUTINE PEXCDF(DX,DBETA,DCDF)
!CCCC SUBROUTINE PEXCDF(X,ALPHA,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE EXPONENTIAL POWER DISTRIBUTION
!              WITH SHAPE PARAMETER BETA AND SCALE PARAMETER
!              ALPHA.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X, AND HAS THE CUMULATIVE DISTRIBUTION
!              FUNCTION
!
!                 F(X) = 1-EXP(1-EXP((X/ALPHA)**B))
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED ALPHA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            ALPHA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE.
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DBETA  = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALKRISHNAN, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND ED 1994, PAGES 643-644.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--DECEMBER  1995.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
!CCCC DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1, DTERM2
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DCDF=0.0D0
      IF(DX.LT.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!CCCC IF(ALPHA.LE.0.0)THEN
!CCCC   WRITE(ICOUT,14)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,15)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)ALPHA
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
!CCCC ENDIF
      IF(DBETA.LE.0.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DBETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PEXCDF IS NEGATIVE.')
!CC14 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO')
!CC15 FORMAT('      THE PEXCDF SUBROUTINE IS ZERO OR NEGATIVE *****')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PEXCDF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(DX.LE.0.0D0)THEN
        DCDF=0.0D0
        GO TO 9999
      ENDIF
!
      DTERM1=1.0D0 - DEXP(DX**DBETA)
      DTERM2=DEXP(DTERM1)
      DCDF=1.0D0 - DTERM2
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PEXCDF
      SUBROUTINE PEXCHA(DX,DBETA,DHAZ)
!CCCC SUBROUTINE PEXCHA(X,ALPHA,BETA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE EXPONENTIAL POWER DISTRIBUTION
!              WITH SHAPE PARAMETER BETA AND SCALE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!
!              THE CUMULATIVE HAZARD FUNCTION IS:
!
!                 H(X;BETA)=EXP(X**BETA) - 1
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED ALPHA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            ALPHA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE).
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --DBETA  = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--DHAZ   = THE DOUBLE PRECISION CUMULATIVE
!                                HAZARD FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE DHAZ.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALKRISHNAN, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND ED 1994, PAGES 643-644.
!                 SMITH AND BAIN, "AN EXPONENTIAL POWER LIFE-TESTING
!                 DISTRIBUTION", COMMUNICATIONS IN STATISITCS, 1975,
!                 PP. 469-481.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
!CCCC DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DHAZ
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DHAZ=0.0D0
      IF(DX.LT.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!CCCC IF(ALPHA.LE.0.0)THEN
!CCCC   WRITE(ICOUT,14)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,15)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)ALPHA
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
!CCCC ENDIF
      IF(DBETA.LE.0.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DBETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PEXCHAZ IS NEGATIVE.')
!CC14 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO')
!CC15 FORMAT('      THE PEXCHAZ SUBROUTINE IS ZERO OR NEGATIVE *****')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PEXCHAZ IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DHAZ=DEXP(DX**DBETA) - 1.0D0
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PEXCHA
      SUBROUTINE PEXHAZ(DX,DBETA,DHAZ)
!CCCC SUBROUTINE PEXHAZ(X,ALPHA,BETA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE EXPONENTIAL POWER DISTRIBUTION
!              WITH SHAPE PARAMETER BETA AND SCALE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE HAZARD FUNCTION:
!
!              H(X;ALPHA,BETA)=ALPHA*BETA*X**(X-1)*EXP(ALPHA*X**BETA)
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED ALPHA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            ALPHA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE.
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --DBETA  = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--DHAZ   = THE DOUBLE PRECISION
!                                HAZARD FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION HAZARD FUNCTION VALUE DHAZ.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALKRISHNAN, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND ED 1994, PAGES 643-644.
!                 SMITH AND BAIN, "AN EXPONENTIAL POWER LIFE-TESTING
!                 DISTRIBUTION", COMMUNICATIONS IN STATISITCS, 1975,
!                 PP. 469-481.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
!CCCC DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DHAZ=0.0D0
      IF(DBETA.GE.1.0D0)THEN
        IF(DX.LT.0.0D0)THEN
          WRITE(ICOUT,4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DX
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ELSE
        IF(DX.LE.0.0D0)THEN
          WRITE(ICOUT,5)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DX
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ENDIF
!CCCC IF(ALPHA.LE.0.0)THEN
!CCCC   WRITE(ICOUT,14)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,15)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)ALPHA
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
!CCCC ENDIF
      IF(DBETA.LE.0.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DBETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PEXHAZ IS NEGATIVE.')
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PEXPDF IS ',   &
             'NON-POSITIVE.')
!CC14 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO')
!CC15 FORMAT('      THE PEXHAZ SUBROUTINE IS ZERO OR NEGATIVE *****')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PEXHAZ IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DLOG(DBETA)
      DTERM2=(DBETA-1.0D0)*DLOG(DX)
      DTERM3=DX**DBETA
      DTERM4=DTERM1+DTERM2+DTERM3
      DHAZ=DEXP(DTERM4)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PEXHAZ
      SUBROUTINE PEXFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              EXPONENTIAL POWER MAXIMUM LIKELIHOOD EQUATIONS.
!
!                (N/BETA) + N*LOG(ALPHA) + SUM[A(i)] -
!                SUM[B(i)*C(i)*EXP(B(i))] +SUM[B(i)*C(i)] = 0
!
!                (BETA*N/ALPHA) - (BETA/ALPHA)*SUM[B(i)*EXP(B(i))] +
!                (BETA/ALPHA)*SUM[B(i)] = 0
!
!              WHERE
!
!                BETA     = SHAPE PARAMETER
!                ALPHA    = SCALE PARAMETER
!                A(i)     = LOG(X(i)]
!                B(i)     = (ALPHA*X(i))**BETA
!                C(i)     = LOG(ALPHA*X(i))
!
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--EXPONENTIAL POWER MAXIMUM LIKELIHOOD Y
!     REFERENCE--DHILLON (1981), "LIFE DISTRIBUTIONS", IEEE
!                TRANSACTIONS ON RELIABILITY, VOL. R-30, NO. 5,
!                PP. 457-459.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/11
!     ORIGINAL VERSION--NOVEMBER  2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DC
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
      DN=DBLE(NOBS)
      DBETA=DBLE(X(1))
      DALPHA=DBLE(X(2))
!
      DTERM1=(DN/DBETA)  + DN*DLOG(DALPHA)
      DTERM2=(DBETA*DN/DALPHA)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DSUM5=0.0D0
!
      DO 200 I=1,NOBS
!
        DX=DBLE(XDATA(I))
        DA=DLOG(DX)
        DB=(DALPHA*DX)**DBETA
        DC=DLOG(DALPHA*DX)
!
        DSUM1=DSUM1 + DA
        DSUM2=DSUM2 + DB*DC*DEXP(DB)
        DSUM3=DSUM3 + DB*DC
!
        DSUM4=DSUM4 + DB*DEXP(DB)
        DSUM5=DSUM5 + DB
!
  200 CONTINUE
!
      FVEC(1)=DTERM1 + DSUM1 - DSUM2 + DSUM3
      FVEC(2)=DTERM2 - (DBETA/DALPHA)*DSUM4 + (DBETA/DALPHA)*DSUM5
!
      RETURN
      END SUBROUTINE PEXFUN 
      SUBROUTINE PEXML1(Y,N,BETASV,SCALSV,MAXNXT,   &
                        TEMP1,TEMP2,DISPAR,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        BETAML,SCALML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE EXPONENTIAL POWER DISTRIBUTION FOR THE RAW DATA
!              CASE (I.E., NO CENSORING AND NO GROUPING).  THIS ROUTINE
!              RETURNS ONLY THE POINT ESTIMATES.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLPX WILL GENERATE THE OUTPUT
!              FOR THE ALPHA MLE COMMAND).
!
!     NOTE--THE MAXIMIUM LIKELIHOOD ESTIMATES ARE THE SOLUTIONS
!           TO THE FOLLOWING EQUATIONS:
!
!             (N/BETA) + N*LOG(ALPHA) + SUM[A(i)] -
!             SUM[B(i)*C(i)*EXP(B(i))] +SUM[B(i)*C(i)] = 0
!
!             (BETA*N/ALPHA) - (BETA/ALPHA)*SUM[B(i)*EXP(B(i))] +
!             (BETA/ALPHA)*SUM[B(i)] = 0
!
!           WHERE
!
!             BETA     = SHAPE PARAMETER
!             ALPHA    = SCALE PARAMETER
!             A(i)     = LOG(X(i)]
!             B(i)     = (ALPHA*X(i))**BETA
!             C(i)     = LOG(ALPHA*X(i))
!
!     REFERENCE--DHILLON (1981), "LIFE DISTRIBUTIONS", IEEE
!                TRANSACTIONS ON RELIABILITY, VOL. R-30, NO. 5,
!                PP. 457-459.
!              --JOHNSON, KOTZ, AND BALKRISHNAN, CONTINUOUS UNIVARIATE
!                DISTRIBUTIONS--2, 2ND ED 1994, PAGES 643-644.
!             -- SMITH AND BAIN, "AN EXPONENTIAL POWER LIFE-TESTING
!                DISTRIBUTION", COMMUNICATIONS IN STATISITCS, 1975,
!                PP. 469-481.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLAL)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION DISPAR(*)
      DIMENSION DISPA2(1)
      INTEGER   IPPCAP(2)
      DOUBLE PRECISION DTEMP1(*)
!
      EXTERNAL PEXFUN
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PEXM'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GL5ML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  CARRY OUT CALCULATIONS                        **
!               **  FOR ALPHA MLE ESTIMATE                        **
!               ****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='EXPONENTIAL POWER'
      SCALML=CPUMIN
      BETAML=CPUMIN
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               **********************************
!               **  STEP 21--                   **
!               **  CARRY OUT CALCULATIONS      **
!               **  FOR ALPHA MLE               **
!               **  ESTIMATE (FULL SAMPLE CASE) **
!               **********************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLAL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(BETASV.GT.0.0 .AND. SCALSV.GT.0.0)THEN
        XPAR(1)=DBLE(BETASV)
        XPAR(2)=DBLE(SCALSV)
      ELSE
!
!       IF NO STARTING VALUES SPECIFIED, COMPUTE STARTING
!       VALUES BASED ON PPCC METHOD.
!
        CALL UNIMED(N,TEMP1)
        CALL SORT(Y,N,Y)
        ICASP2='PEXP'
        ICASPL='PPCC'
        IPPCAP(1)=100
        IPPCAP(2)=1
!
!       OBTAIN LOWER/UPPER LIMITS FOR SHAPE PARAMETER
!
        CALL EXTPA2(ICASP2,IDIST,A,B,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ISUBRO,IBUGA3,IERROR)
!
!       CREATE ARRAY FOR THE CANDIDATE VALUES OF SHAPE PARAMETER
!
        NUMSHA=1
        CALL DPPPC7(ICASPL,ICASP2,IPPCAP,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                    XMIN,XMAX,A,B,   &
                    DISPAR,DISPA2,NUMDIS,NUMSHA,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,   &
                    ICONDF,IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                    IBUGA3,ISUBRO,IERROR)
!
        CORRMX=-1.0
        IWRITE='OFF'
        SCALE2=1.0
        DO 1010 IDIS=1,NUMDIS
          SHAPE=DISPAR(IDIS)
          DO 1020 I=1,N
            CALL PEXPPF(DBLE(TEMP1(I)),DBLE(SHAPE),DPPF)
            TEMP2(I)=REAL(DPPF)
 1020     CONTINUE
          CALL CORR(Y,TEMP2,N,IWRITE,CC,IBUGA3,IERROR)
          IF(CC.GT.CORRMX)THEN
            SHAPE1=SHAPE
            CALL LINFI2(Y,TEMP2,N,PPA0,PPA1,ISUBRO,IBUGA3,IERROR)
            CORRMX=CC
            SCALE2=PPA1
          ENDIF
 1010   CONTINUE
        XPAR(1)=DBLE(SHAPE1)
        XPAR(2)=DBLE(SCALE2)
      ENDIF
!
      IOPT=2
      TOL=1.0D-5
      NVAR=2
      NPRINT=-1
      INFO=0
      CALL DNSQE(PEXFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      BETAML=REAL(XPAR(1))
      SCALML=1.0/REAL(XPAR(2))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF PEXML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)BETAML,SCALML
 9017   FORMAT('BETAML,SCALML =  ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE PEXML1
      SUBROUTINE PEXPDF(DX,DBETA,DPDF)
!CCCC SUBROUTINE PEXPDF(X,ALPHA,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE EXPONENTIAL POWER DISTRIBUTION
!              WITH SHAPE PARAMETER BETA AND SCALE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!
!              f(X;BETA) = BETA*X**(BETA-1)A*EXP(X**BETA)*
!                          EXP(1 - EXP(X**BETA))
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED ALPHA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            ALPHA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE.
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DBETA  = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE DPDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALKRISHNAN, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND ED 1994, PAGES 643-644.
!                 SMITH AND BAIN, "AN EXPONENTIAL POWER LIFE-TESTING
!                 DISTRIBUTION", COMMUNICATIONS IN STATISITCS, 1975,
!                 PP. 469-481.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--DECEMBER  1995.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
!     NOTE: IF BETA < 1, THEN PDF IS INFINITE AT X = 0.
!
      DPDF=0.0D0
      IF(DBETA.GE.1.0D0)THEN
        IF(DX.LT.0.0D0)THEN
          WRITE(ICOUT,4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DX
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ELSE
        IF(DX.LE.0.0D0)THEN
          WRITE(ICOUT,5)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DX
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ENDIF
!CCCC IF(ALPHA.LE.0.0)THEN
!CCCC   WRITE(ICOUT,14)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,15)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)ALPHA
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
!CCCC ENDIF
      IF(DBETA.LE.0.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DBETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PEXPDF IS NEGATIVE.')
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PEXPDF IS ',   &
             'NON-POSITIVE.')
!CC14 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO')
!CC15 FORMAT('      THE PEXPDF SUBROUTINE IS ZERO OR NEGATIVE *****')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PEXPDF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DLOG(DBETA)
      DTERM2=(DBETA-1.0D0)*DLOG(DX)
      DTERM3=DX**DBETA
      DTERM4=1.0D0 - DEXP(DX**DBETA)
      DTERM5=DTERM1+DTERM2+DTERM3+DTERM4
      DPDF=DEXP(DTERM5)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PEXPDF
      SUBROUTINE PEXPPF(DP,DBETA,DPPF)
!CCCC SUBROUTINE PEXPPF(P,ALPHA,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE EXPONENTIAL POWER DISTRIBUTION
!              WITH SHAPE PARAMETER BETA AND SCALE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PERCENT POINT FUNCTION
!
!              G(P;BETA) = -{LOG[1 - LOG(1-P)]}**(1/BETA)
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED ALPHA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            ALPHA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE.
!
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     -DBETA   = THE DOUBLE PRECISION VALUE OF
!                                THE SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE DPPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALKRISHNAN, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND ED 1994, PAGES 643-644.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--96/1
!     ORIGINAL VERSION--JANUARY   1996.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
!CCCC DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPPF=0.0D0
      IF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!CCCC IF(ALPHA.LE.0.0)THEN
!CCCC   WRITE(ICOUT,14)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,15)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)ALPHA
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
!CCCC ENDIF
      IF(DBETA.LE.0.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DBETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PEXPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1] INTERVAL.')
!CC14 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO')
!CC15 FORMAT('      THE PEXPPF SUBROUTINE IS ZERO OR NEGATIVE *****')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PEXPPF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(DP.LE.0.0D0)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
      DPPF=DLOG(1.0D0-DLOG(1.0D0-DP))**(1.0D0/DBETA)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PEXPPF
      SUBROUTINE PEXRAN(N,BETA,ISEED,X)
!CCCC SUBROUTINE PEXRAN(N,ALPHA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE EXPONENTIAL POWER DISTRIBUTION
!              WITH SHAPE PARAMETER BETA.
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED ALPHA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            ALPHA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE).
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --BETA  = THE SINGLE PRECISION VALUE OF THE SHAPE
!                               PARAMETER.  BETA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE POWER EXPONENTIAL DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --BETA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, PEXPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT, 6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF EXPONENTIAL ',   &
             'POWER')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   24 FORMAT('***** ERROR--THE VALUE OF THE BETA SHAPE PARAMETER ',   &
             'IS NON-POSITIVE.')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N EXPONENTIAL POWER DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL PEXPPF(DBLE(X(I)),DBLE(BETA),DTEMP)
        X(I)=REAL(DTEMP)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PEXRAN
      SUBROUTINE PHASMP(A,ZINV,K,PP,QQ)
! THIS ROUTINE DOES PHASE-AMPLITUDE CALCULATIONS FOR BESSEL FUNCTIONS.
! A IS THE ORDER OF THE FUNCTION, AT MOST 1 IN ABSOLUTE VALUE.  ZINV IS
! 2./Z, WHERE Z IS THE ARGUMENT.  TO ACHIEVE 14 FIGURES ACCURACY, ABS(Z)
! MUST BE AT LEAST 14, OR A MUST BE .5 OR -.5.  IF K=0, PHASMP RETURNS
! PP AND QQ FOR EQUATIONS 9.2.5 TO 9.2.8 OF REFERENCE (1) LISTED IN
! BESJCF.  IF K=1 (-1) PHASMP RETURNS PP FOR EQUATION 9.7.2 (9.7.1).
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      COMPLEX PP,QQ,ZI,ZINV,TERM(25),ZDUMMY
!-----------------------------------------------------------------------
!
!  MACHINE DEPENDENT CONSTANTS.
!  ---------------------------
!
      SAVE ISAVE, DYOUK
      DATA ISAVE /1/
      DATA TERM(1)/(1.,0.)/
!
! Definition of real and imaginary parts of complex number,
! standard Fortran and will work on Convex with -r8 -i8.
      REALP(ZDUMMY) = REAL(ZDUMMY)
      AIMAGP(ZDUMMY) = REAL((0,-1)*ZDUMMY)
!
      IF (ISAVE.GT.0) THEN
        ISAVE = 0
        DYOUK = R1MACH (4)
      ENDIF
!
!-----------------------------------------------------------------------
      ZI=.0625*ZINV
      S=K
      IF(K.EQ.0) S=-1.
      C=(DBLE(2.*A))**2-1.D0
      DO 1 N=1,24
      IF(K.EQ.0) S=-S
      TERM(N+1)=TERM(N)*ZI*(S*(C/REAL(N)+REAL(4-4*N)))
      IF(MAX(ABS(REALP(TERM(N+1))),ABS(AIMAGP(TERM(N+1)))).LE.DYOUK)   &
       GO TO 2
    1 CONTINUE
      N=25
    2 PP = (0.0, 0.0)
      QQ = (0.0, 0.0)
      IF ((K .NE. 0) .OR. (MOD (N, 2) .NE. 0)) GO TO 4
    3 QQ=QQ+TERM(N)
      N=N-1
    4 PP=PP+TERM(N)
      N=N-1
      IF(N.EQ.0) RETURN
!CCCC IF(K) 4,3,4
      IF(K.EQ.0) GO TO 3
      GO TO 4
      END SUBROUTINE PHASMP
      DOUBLE PRECISION FUNCTION PHI(Z)
!
!     Normal distribution probabilities accurate to 1.e-15.
!     Z = no. of standard deviations from the mean.
!
!     Based upon algorithm 5666 for the error function, from:
!     Hart, J.F. et al, 'Computer Approximations', Wiley 1968
!
!     Programmer: Alan Miller
!
!     Latest revision - 30 March 1986
!
      DOUBLE PRECISION P0, P1, P2, P3, P4, P5, P6,   &
           Q0, Q1, Q2, Q3, Q4, Q5, Q6, Q7,   &
           Z, P, EXPNTL, CUTOFF, ROOTPI, ZABS
      PARAMETER(   &
           P0 = 220.2068679123761D0,   &
           P1 = 221.2135961699311D0,   &
           P2 = 112.0792914978709D0,   &
           P3 = 33.91286607838300D0,   &
           P4 = 6.373962203531650D0,   &
           P5 = .7003830644436881D0,   &
           P6 = .03526249659989109D0)
      PARAMETER(   &
           Q0 = 440.4137358247522D0,   &
           Q1 = 793.8265125199484D0,   &
           Q2 = 637.3336333788311D0,   &
           Q3 = 296.5642487796737D0,   &
           Q4 = 86.78073220294608D0,   &
           Q5 = 16.06417757920695D0,   &
           Q6 = 1.755667163182642D0,   &
           Q7 = .08838834764831844D0)
      PARAMETER(ROOTPI = 2.506628274631001D0)
      PARAMETER(CUTOFF = 7.071067811865475D0)
!
      ZABS = ABS(Z)
!
!     |Z| > 37
!
      IF (ZABS .GT. 37) THEN
         P = 0
      ELSE
!
!     |Z| <= 37
!
         EXPNTL = EXP(-ZABS**2/2)
!
!     |Z| < CUTOFF = 10/SQRT(2)
!
         IF (ZABS .LT. CUTOFF) THEN
            P = EXPNTL*((((((P6*ZABS + P5)*ZABS + P4)*ZABS + P3)*ZABS   &
                 + P2)*ZABS + P1)*ZABS + P0)/(((((((Q7*ZABS + Q6)*ZABS   &
                 + Q5)*ZABS + Q4)*ZABS + Q3)*ZABS + Q2)*ZABS + Q1)*ZABS   &
                 + Q0)
!
!     |Z| >= CUTOFF.
!
         ELSE
            P = EXPNTL/(ZABS + 1/(ZABS + 2/(ZABS + 3/(ZABS + 4/   &
                 (ZABS + 0.65D0)))))/ROOTPI
         END IF
      END IF
      IF (Z .GT. 0) P = 1 - P
      PHI = P
!
      RETURN
      END FUNCTION PHI
      DOUBLE PRECISION FUNCTION PHINV(P)
!
!	ALGORITHM AS241  APPL. STATIST. (1988) VOL. 37, NO. 3
!
!	Produces the normal deviate Z corresponding to a given lower
!	tail area of P.
!
!	The hash sums below are the sums of the mantissas of the
!	coefficients.   They are included for use in checking
!	transcription.
!
      DOUBLE PRECISION SPLIT1, SPLIT2, CONST1, CONST2,   &
           A0, A1, A2, A3, A4, A5, A6, A7, B1, B2, B3, B4, B5, B6, B7,   &
           C0, C1, C2, C3, C4, C5, C6, C7, D1, D2, D3, D4, D5, D6, D7,   &
           E0, E1, E2, E3, E4, E5, E6, E7, F1, F2, F3, F4, F5, F6, F7,   &
           P, Q, R
      PARAMETER (SPLIT1 = 0.425, SPLIT2 = 5,   &
           CONST1 = 0.180625D0, CONST2 = 1.6D0)
!
!     Coefficients for P close to 0.5
!
      PARAMETER (   &
           A0 = 3.3871328727963666080D0,   &
           A1 = 1.3314166789178437745D+2,   &
           A2 = 1.9715909503065514427D+3,   &
           A3 = 1.3731693765509461125D+4,   &
           A4 = 4.5921953931549871457D+4,   &
           A5 = 6.7265770927008700853D+4,   &
           A6 = 3.3430575583588128105D+4,   &
           A7 = 2.5090809287301226727D+3,   &
           B1 = 4.2313330701600911252D+1,   &
           B2 = 6.8718700749205790830D+2,   &
           B3 = 5.3941960214247511077D+3,   &
           B4 = 2.1213794301586595867D+4,   &
           B5 = 3.9307895800092710610D+4,   &
           B6 = 2.8729085735721942674D+4,   &
           B7 = 5.2264952788528545610D+3)
!     HASH SUM AB    55.8831928806149014439
!
!     Coefficients for P not close to 0, 0.5 or 1.
!
      PARAMETER (   &
           C0 = 1.42343711074968357734D0,   &
           C1 = 4.63033784615654529590D0,   &
           C2 = 5.76949722146069140550D0,   &
           C3 = 3.64784832476320460504D0,   &
           C4 = 1.27045825245236838258D0,   &
           C5 = 2.41780725177450611770D-1,   &
           C6 = 2.27238449892691845833D-2,   &
           C7 = 7.74545014278341407640D-4,   &
           D1 = 2.05319162663775882187D0,   &
           D2 = 1.67638483018380384940D0,   &
           D3 = 6.89767334985100004550D-1,   &
           D4 = 1.48103976427480074590D-1,   &
           D5 = 1.51986665636164571966D-2,   &
           D6 = 5.47593808499534494600D-4,   &
           D7 = 1.05075007164441684324D-9)
!     HASH SUM CD    49.33206503301610289036
!
!   Coefficients for P near 0 or 1.
!
      PARAMETER (   &
           E0 = 6.65790464350110377720D0,   &
           E1 = 5.46378491116411436990D0,   &
           E2 = 1.78482653991729133580D0,   &
           E3 = 2.96560571828504891230D-1,   &
           E4 = 2.65321895265761230930D-2,   &
           E5 = 1.24266094738807843860D-3,   &
           E6 = 2.71155556874348757815D-5,   &
           E7 = 2.01033439929228813265D-7,   &
           F1 = 5.99832206555887937690D-1,   &
           F2 = 1.36929880922735805310D-1,   &
           F3 = 1.48753612908506148525D-2,   &
           F4 = 7.86869131145613259100D-4,   &
           F5 = 1.84631831751005468180D-5,   &
           F6 = 1.42151175831644588870D-7,   &
           F7 = 2.04426310338993978564D-15)
!     HASH SUM EF    47.52583317549289671629
!
      Q = ( 2*P - 1 )/2
      IF ( ABS(Q) .LE. SPLIT1 ) THEN
         R = CONST1 - Q*Q
         PHINV = Q*(((((((A7*R + A6)*R + A5)*R + A4)*R + A3)   &
              *R + A2)*R + A1)*R + A0) /   &
              (((((((B7*R + B6)*R + B5)*R + B4)*R + B3)   &
              *R + B2)*R + B1)*R + 1)
      ELSE
         R = MIN( P, 1 - P )
         IF (R .GT. 0) THEN
            R = SQRT( -LOG(R) )
            IF ( R .LE. SPLIT2 ) THEN
               R = R - CONST2
               PHINV = (((((((C7*R + C6)*R + C5)*R + C4)*R + C3)   &
                    *R + C2)*R + C1)*R + C0) /   &
                    (((((((D7*R + D6)*R + D5)*R + D4)*R + D3)   &
                    *R + D2)*R + D1)*R + 1)
            ELSE
               R = R - SPLIT2
               PHINV = (((((((E7*R + E6)*R + E5)*R + E4)*R + E3)   &
                    *R + E2)*R + E1)*R + E0) /   &
                    (((((((F7*R + F6)*R + F5)*R + F4)*R + F3)   &
                    *R + F2)*R + F1)*R + 1)
            END IF
         ELSE
            PHINV = 9
         END IF
         IF ( Q .LT. 0 ) PHINV = - PHINV
      END IF
!
      RETURN
      END FUNCTION PHINV
      SUBROUTINE PIGPDF(X,THETA,ALPHA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X
!              FOR THE POISSON-INVERSE GAUSSIAN DISTRIBUTION
!              WITH DOUBLE PRECISION SHAPE PARAMETERS ALPHA AND
!              THETA.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X = 0, 1, 2, ...
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;ALPHA,THETA) = SQRT(2*ALPHA/PI)*
!                  EXP(ALPHA*SQRT(1-THETA))*(ALPHA*THETA/2)**X*
!                  K(X-1/2)(ALPHA)/X!
!                  ALPHA > 0; 0 < THETA < 1
!                  K(V) IS THE MODIFIED BESSEL FUNCTION
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --ALPHA  = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --THETA  = THE DOUBLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS
!             FUNCTION VALUE PDF
!             FOR THE POISSON-INVERSE GAUSSIAN DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 < THETA < 1,  AND ALPHA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--LNGAMM, DBESK.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 455-457.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION Y(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      INTX=INT(X+0.5)
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO PIGPDF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO PIGPDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(INTX.LT.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO PIGPDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      DX=DBLE(INTX)
!
      DTERM1=0.5D0*(DLOG(2.0D0) + DLOG(ALPHA) - DLOG(DPI))
      DTERM2=ALPHA*DSQRT(1.0D0 - THETA)
      DTERM3=DX*(DLOG(ALPHA) + DLOG(THETA) - DLOG(2.0D0))
      IF(INTX.EQ.0)THEN
        DTERM4=-ALPHA + 0.5D0*(DLOG(DPI) - DLOG(2.0D0*ALPHA))
      ELSEIF(INTX.EQ.1)THEN
        DTERM4=-ALPHA + 0.5D0*(DLOG(DPI) - DLOG(2.0D0*ALPHA))
      ELSE
        FNU=DX-0.5
        KODE=1
        N=1
        CALL DBESK(ALPHA,FNU,KODE,N,Y,NZ)
        DTERM4=DBLE(Y(1))
        IF(DTERM4.GE.0.0D0)THEN
          DTERM4=DLOG(DTERM4)
        ELSE
          PDF=0.0D0
          GO TO 9999
        ENDIF
      ENDIF
      DTERM5=DLNGAM(DX+1.0D0)
      DPDF=DTERM1 + DTERM2 + DTERM3 + DTERM4 - DTERM5
      PDF=DEXP(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PIGPDF
      REAL FUNCTION PKS2(N, D)
!     ALGORITHM 487 COLLECTED ALGORITHMS FROM ACM.
!     ALGORITHM APPEARED IN COMM. ACM, VOL. 17, NO. 12,
!     P. 703.
      INTEGER N
! N IS THE SAMPLE SIZE USED.
      REAL D
! D IS THE MAXIMUM MAGNITUDE (OF THE DISCREPANCY
! BETWEEN THE EMPIRICAL AND PROPOSED DISTRIBUTIONS)
! IN EITHER THE POSITIVE OR NEGATIVE DIRECTION.
! PKS2 IS THE EXACT PROBABILITY OF OBTAINING A
! DEVIATION NO LARGER THAN D.
! THESE FORMULAS APPEAR AS (23) AND (24) IN
! J. DURBIN.  THE PROBABILITY THAT THE SAMPLE
! DISTRIBUTION FUNCTION LIES BETWEEN TWO PARALLEL
! STRAIGHT LINES. ANNALS OF MATHEMATICAL STATISTICS
! 39, 2(APRIL 1968),398-411.
      DOUBLE PRECISION Q(141), FACT(141), SUM, CI,   &
       FT, FU, FV
      IF (N.EQ.1) GO TO 90
      FN = FLOAT(N)
      FND = FN*D
      NDT = IFIX(2.*FND)
      IF (NDT.LT.1) GO TO 100
      ND = IFIX(FND)
      NDD = MIN0(2*ND,N)
      NDP = ND + 1
      NDDP = NDD + 1
      FACT(1) = 1.
      CI = 1.
      DO 10 I=1,N
        FACT(I+1) = FACT(I)*CI
        CI = CI + 1.
   10 CONTINUE
      Q(1) = 1.
      IF (NDD.EQ.0) GO TO 50
      CI = 1.
      DO 20 I=1,NDD
        Q(I+1) = CI**I/FACT(I+1)
        CI = CI + 1.
   20 CONTINUE
      IF (NDP.GT.N) GO TO 80
      FV = FLOAT(NDP) - FND
      JMAX = IDINT(FV) + 1
      DO 40 I=NDP,NDD
        SUM = 0.
        FT = FND
        K = I
        FU = FV
        DO 30 J=1,JMAX
          SUM = SUM + FT**(J-2)/FACT(J)*FU**K/   &
           FACT(K+1)
          FT = FT + 1.
          FU = FU - 1.
          K = K - 1
   30   CONTINUE
        Q(I+1) = Q(I+1) - 2.*FND*SUM
        JMAX = JMAX + 1
        FV = FV + 1.
   40 CONTINUE
      IF (NDD.EQ.N) GO TO 80
   50 DO 70 I=NDDP,N
        SUM = 0.
        SIGN = 1.
        FT = 2.*FND
        DO 60 J=1,NDT
          FT = FT - 1.
          K = I - J + 1
          SUM = SUM + SIGN*FT**J/FACT(J+1)*Q(K)
          SIGN = -SIGN
   60   CONTINUE
        Q(I+1) = SUM
   70 CONTINUE
   80 PKS2 = Q(N+1)*FACT(N+1)/FN**N
      RETURN
   90 PKS2 = 2.*D - 1.
      RETURN
  100 PKS2 = 0.
      RETURN
      END FUNCTION PKS2
      SUBROUTINE PRFAC
      DIMENSION DXA(4)
      COMMON /KSCOMM/ DX, DXA, J
      DOUBLE PRECISION PF
      COMMON /KSCOM2/ PF(4,40)
      DATA I /1/
      DO 10 J=1,4
        IF (DXA(J).EQ.DX) RETURN
   10 CONTINUE
      J = I
      I = I + 1
      IF (I.EQ.5) I = 1
      DXA(J) = DX
      PF(J,1) = 1.
      DO 20 K=2,38
        PF(J,K) = (PF(J,K-1)*DX)/FLOAT(K-1)
   20 CONTINUE
      RETURN
      END SUBROUTINE PRFAC                  
      FUNCTION CEILDP(X)
      IF (X.GE.0.) GO TO 10
      I = INT(-X)
      CEILDP = -I
      RETURN
   10 I = INT(X + .99999999)
      CEILDP = I
      RETURN
      END FUNCTION CEILDP
      COMPLEX FUNCTION PLEM(Z)
!
!     WEIERSTRASS: P-FUNCTION IN THE LEMNISCATIC CASE
!     FOR COMPLEX ARGUMENT WITH UNIT PERIOD PARALLELOGRAM
!
      INCLUDE 'DPCOMC.INC'
      COMPLEX Z, Z2, Z4, Z6
      REAL ZR, ZI
      INTEGER M, N
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!     REDUCTION TO FUNDAMENTAL PARALLELOGRAM
!
      ZR = REAL(Z) + 0.5E0
      ZI = AIMAG(Z) + 0.5E0
      M = INT(ZR)
      N = INT(ZI)
      IF (ZR.LT.0E0) M = M - 1
      IF (ZI.LT.0E0) N = N - 1
      Z2 = Z - FLOAT(M) - (0E0,1E0)*FLOAT(N)
!
!     IF Z2=0 THEN Z COINCIDES WITH A LATTICE POINT.
!     SINCE P HAS POLES AT THE LATTICE POINTS,
!     A DIVISION ERROR WILL OCCUR
!
      IF(REAL(Z2).EQ.0.0.AND.AIMAG(Z2).EQ.0.0)THEN
        PLEM=R1MACH(2)
        WRITE(ICOUT,91)
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
   91 FORMAT('***** ERROR: INPUT POINT CORRESPONDS TO A LATTICE ',   &
      'POINT.  VALUE SET TO LARGEST REAL. *****')
      Z2 = Z2*Z2
      Z4 = Z2*Z2
      Z6 = Z4*Z2
      PLEM = 1E0/Z2 + 4E0*Z2*(3E0+Z4)/(1E0-Z4)**2 +   &
       Z2*((((((((-7.233108E-11*Z4+1.714197273E-8)*Z4-2.5369036492E-7)*   &
       Z4-7.98710206868E-6)*Z4+6.4850606909737E-4)*Z4+7.39624629362938E-3)   &
       *Z4+2.012382768497244E-2)*Z4+7.1177297543136598E-1)*   &
       Z4-2.54636399353830738E0)/((((((((5.1161516E-10*Z4+6.61289408E-9)   &
       *Z4+4.4618987048E-7)*Z4-8.42694918892E-6)*Z4+4.42886829095E-6)*   &
       Z4-4.22629935217101E-3)*Z4+2.577496871700433E-2)*   &
       Z4+4.2359940482277074E-1)*Z4+1E0)
      RETURN
      END FUNCTION PLEM
      COMPLEX FUNCTION PLEM1(Z)
!
!     FIRST DERIVATIVE OF WEIERSTRASS: P-FUNCTION IN THE
!     LEMNISCATIC CASE FOR COMPLEX ARGUMENT
!     WITH UNIT PERIOD PARALLELOGRAM
!
      INCLUDE 'DPCOMC.INC'
      COMPLEX Z, Z1, Z3, Z4
      REAL ZR, ZI
      INTEGER M, N
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!     REDUCTION TO FUNDAMENTAL PARALLELOGRAM
!
      ZR = REAL(Z) + 0.5E0
      ZI = AIMAG(Z) + 0.5E0
      M = INT(ZR)
      N = INT(ZI)
      IF (ZR.LT.0E0) M = M - 1
      IF (ZI.LT.0E0) N = N - 1
      Z1 = Z - FLOAT(M) - (0E0,1E0)*FLOAT(N)
!
!     IF Z1=0 THEN Z COINCIDES WITH A LATTICE POINT.
!     SINCE P: HAS POLES AT THE LATTICE POINTS,
!     A DIVISION ERROR WILL OCCUR
!
      IF(REAL(Z1).EQ.0.0.AND.AIMAG(Z1).EQ.0.0)THEN
        PLEM1=R1MACH(2)
        WRITE(ICOUT,91)
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
   91 FORMAT('***** ERROR: INPUT POINT CORRESPONDS TO A LATTICE ',   &
      'POINT.  VALUE SET TO LARGEST REAL. *****')
      Z3 = Z1*Z1*Z1
      Z4 = Z3*Z1
      PLEM1 = (((1E1*Z4+9E1)*Z4+3E1)*Z4-2E0)/(Z1*(1E0-Z4))**3 +   &
       Z1*((((((((((-3.9046302E-9*Z4-1.001487137E-8)*Z4+5.9573043092E-7)   &
       *Z4-2.482518130524E-5)*Z4+1.4557266595395E-4)*   &
       Z4+4.56633655643206E-3)*Z4+6.224782572111135E-2)*   &
       Z4+1.038527937794269E-2)*Z4+1.19804620802637942E0)*   &
       Z4+6.42791439683811718E0)*Z4-5.09272798707661477E0)/   &
       ((((((((((4.726888E-11*Z4-3.0667983E-9)*Z4+1.0087596089E-7)*   &
       Z4-8.060683451E-8)*Z4+1.184299251664E-5)*Z4-2.3096723361547E-4)*   &
       Z4-2.90730903142055E-3)*Z4+1.338392411135511E-2)*   &
       Z4+2.3098639320021426E-1)*Z4+8.4719880964554148E-1)*Z4+1E0)
      RETURN
      END FUNCTION PLEM1
      SUBROUTINE PLOTCN(Y,X,D,N,ICHAR,MAXCHA,ICASPL,ICAS3D,   &
      ITITTE,NCTITL,   &
      IX1LTE,NCX1LA,   &
      IX2LTE,NCX2LA,   &
      IX3LTE,NCX3LA,   &
      IY1LTE,NCY1LA,   &
      IY2LTE,NCY2LA,   &
      GX1MIN,GX1MAX,GY1MIN,GY1MAX,   &
      IERASW,IBUGU2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE YIELDS A NARROW-WIDTH (68-CHARACTER)
!              PLOT OF Y(I) VERSUS X(I) WITH SPECIAL CHARACTERS
!              FOR THE VARIOUS SUB-TRACES DICTATED BY THE
!              CONTENTS OF THE DUMMY VARIABLE D(.)
!              AND THE CHARACTER VARIABLE ICHAR(.).
!              ALL(X,Y) PAIRS CORRESPONING
!              TO THE MINIMUM VALUE IN D(.)
!              WILL BE PLOTTED WITH PLOT CHARACTER = ICHAR(1).
!              ALL(X,Y) PAIRS CORRESPONING
!              TO THE NEXT LARGER VALUE IN D(.)
!              WILL BE PLOTTED WITH PLOT CHARACTER = ICHAR(2).
!              ETC.
!     NOTE--THE NARROW WIDTH OF THIS PLOT
!           MAKES IT APPROPRIATE FOR
!           USE ON A (DISCRETE) TERMINAL.
!     INPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS
!                               TO BE PLOTTED VERTICALLY.
!                    --X      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS
!                               TO BE PLOTTED HORIZONTALLY.
!                    --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR X.
!                    --ICHAR  = THE HOLLERITH VECTOR OF
!                               CHARACTERS
!                               (1 CHARACTER PER TRACE)
!                    --MAXCHA = THE INTEGER NUMBER OF
!                               CHARACTERS IN ICHAR(.)
!     OUTPUT--A NARROW-WIDTH (68-CHARACTER) TERMINAL PLOT
!             OF Y(I) VERSUS I.
!             THE BODY OF THE PLOT (NOT COUNTING AXIS VALUES
!             AND MARGINS) IS 17 ROWS (LINES) AND 41 COLUMNS.
!     PRINTING--YES.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT THE STORAGE REQUIREMENTS FOR THIS
!              (AND THE OTHER) TERMINAL PLOT SUBROUTINESS ARE .
!              VERY SMALL.
!              THIS IS DUE TO THE 'ONE LINE AT A TIME' ALGORITHM
!              EMPLOYED FOR THE PLOT.
!     REFERENCES--NONE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--FEBRUARY  1974.
!     UPDATED         --APRIL     1974.
!     UPDATED         --OCTOBER   1974.
!     UPDATED         --OCTOBER   1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1977.
!     UPDATED         --JUNE      1978.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --JANUARY   1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICHAR
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
!
      CHARACTER*4 ITITTE
      CHARACTER*4 IX1LTE
      CHARACTER*4 IX2LTE
      CHARACTER*4 IX3LTE
      CHARACTER*4 IY1LTE
      CHARACTER*4 IY2LTE
!
      CHARACTER*4 IERASW
      CHARACTER*4 IBUGU2
      CHARACTER*4 IERROR
!
      CHARACTER*4 IBLANK
      CHARACTER*4 IHYPHE
      CHARACTER*4 IALPHI
      CHARACTER*4 IALPHX
      CHARACTER*4 ILABT
      CHARACTER*4 ILABY
      CHARACTER*4 ILABX1
      CHARACTER*4 ILABX2
      CHARACTER*4 ILABX3
      CHARACTER*4 JPLOTC
      CHARACTER*4 ICASP2
      CHARACTER*4 ILINE
      CHARACTER*4 IAXISC
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION D(*)
      DIMENSION ICHAR(*)
!
      DIMENSION ITITTE(*)
      DIMENSION IX1LTE(*)
      DIMENSION IX2LTE(*)
      DIMENSION IX3LTE(*)
      DIMENSION IY1LTE(*)
      DIMENSION IY2LTE(*)
!
      DIMENSION ILABT(132)
      DIMENSION ILABY(132)
      DIMENSION ILABX1(132)
      DIMENSION ILABX2(132)
      DIMENSION ILABX3(132)
!
      DIMENSION ILINE(72)
      DIMENSION AILABL(10)
      DIMENSION DISTD(MAXOBV)
!CCCC FOLLOWING LINES ADDED JUNE, 1990
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),DISTD(1))
!CCCC END CHANGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      ISUBN1='PLOT'
      ISUBN2='CN  '
!
      IBLANK=' '
      IHYPHE='-'
      IALPHI='I'
      IALPHX='X'
!
      IMAXT=0
      IMAXX1=0
      IMAXX2=0
      IMAXX3=0
!
      IF(IBUGU2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF PLOTCN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,MAXCHA,NCY1LA,NCY2LA,IBUGU2
   52   FORMAT('N,MAXCHA,NCY1LA,NCY2LA,IBUGU2 = ',4I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)Y(1),X(1),D(1),ICHAR(1)
   53   FORMAT('Y(1),X(1),D(1),ICHAR(1) = ',3E15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)Y(N),X(N),D(N),ICHAR(N)
   54   FORMAT('Y(N),X(N),D(N),ICHAR(N) = ',3E15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ICASPL,ICAS3D
   55   FORMAT('ICASPL,ICAS3D = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)GX1MIN,GX1MAX,GY1MIN,GY1MAX
   73   FORMAT('GX1MIN,GX1MAX,GY1MIN,GY1MAX = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,75)IY1LTE(1),IY2LTE(1)
   75   FORMAT('IY1LTE(1),IY2LTE(1) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!               ***************************************************************
!               **  STEP 2--                                                 **
!               **  DEFINE THE NUMBER OF ROWS AND COLUMNS WITHIN THE PLOT--  **
!               **  THIS HAS BEEN SET TO 21 ROWS AND 41 COLUMNS.             **
!               ***************************************************************
!
!CCCC NUMROW=21
      NUMROW=17
      NUMCOL=41
!
      ANUMR=NUMROW
      ANUMRM=NUMROW-1
      ANUMCM=NUMCOL-1
      NUMR25=(NUMROW/4)+1
      NUMR50=(NUMROW/2)+1
      NUMR75=3*(NUMROW/4)+1
      IXDEL=(NUMCOL-1)/4
!
!               ********************************
!               **  STEP 2.2--                **
!               **  DEFINE THE TYPE OF PLOT.  **
!               ********************************
!
      ICASP2=ICASPL
      IF(ICASPL.EQ.'MDBP')ICASP2='BOXP'
      IF(ICASPL.EQ.'MEBP')ICASP2='BOXP'
      IF(ICASPL.EQ.'VIPL')ICASP2='BOXP'
      IF(ICASPL.EQ.'MDIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MEIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MRIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MMIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MECL')ICASP2='IPLO'
      IF(ICASPL.EQ.'1SE ')ICASP2='IPLO'
      IF(ICASPL.EQ.'2SE ')ICASP2='IPLO'
      IF(ICASPL.EQ.'1SD ')ICASP2='IPLO'
      IF(ICASPL.EQ.'2SD ')ICASP2='IPLO'
      IF(ICASPL.EQ.'MDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'QUCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'TMCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'BWCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'SDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CVCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CRCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CQCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'DPRO')ICASP2='IPLO'
      IF(ICASPL.EQ.'DMEA')ICASP2='IPLO'
      IF(ICASPL.EQ.'NTOL')ICASP2='IPLO'
      IF(ICASPL.EQ.'NPRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'BWRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'TMRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'AGCL')ICASP2='IPLO'
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  PREPARE THE TITLE LINE, THE Y-AXIS LABEL,       **
!               **  AND THE 3 HORIZONTAL AXIS LABELS FOR PRINTING.  **
!               ******************************************************
!
      YMIDL=REAL(NUMROW/2)
      XMIDL=REAL(22+NUMCOL/2)
!
      YFACT=1.0
      XFACT=1.0
!
      ILENT=NCTITL
      ILENY1=NCY1LA
      ILENX1=NCX1LA
      ILENX2=NCX2LA
      ILENX3=NCX3LA
!
      ALENT=ILENT
      ALENY1=ILENY1
      ALENX1=ILENX1
      ALENX2=ILENX2
      ALENX3=ILENX3
!
      IX=INT(XMIDL-XFACT*(ALENT/2.0))
      DO 310 I=1,132
      ILABT(I)=' '
  310 CONTINUE
      J=IX-1
      IF(ILENT.LE.0)GO TO 319
      DO 315 I=1,ILENT
      J=J+1
      ILABT(J)=ITITTE(I)
  315 CONTINUE
      IMAXT=J
  319 CONTINUE
!
      IY=INT(YMIDL-YFACT*(ALENY1/2.0))
      DO 320 I=1,132
      ILABY(I)=' '
  320 CONTINUE
      J=IY-1
      IF(ILENY1.LE.0)GO TO 329
      DO 325 I=1,ILENY1
      J=J+1
      ILABY(J)=ITITTE(I)
  325 CONTINUE
      IMAXY1=J
  329 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX1/2.0))
      DO 330 I=1,132
      ILABX1(I)=' '
  330 CONTINUE
      J=IX-1
      IF(ILENX1.LE.0)GO TO 339
      DO 335 I=1,ILENX1
      J=J+1
      ILABX1(J)=IX1LTE(I)
  335 CONTINUE
      IMAXX1=J
  339 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX2/2.0))
      DO 340 I=1,132
      ILABX2(I)=' '
  340 CONTINUE
      J=IX-1
      IF(ILENX2.LE.0)GO TO 349
      DO 345 I=1,ILENX2
      J=J+1
      ILABX2(J)=IX2LTE(I)
  345 CONTINUE
      IMAXX2=J
  349 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX3/2.0))
      DO 350 I=1,132
      ILABX3(I)=' '
  350 CONTINUE
      J=IX-1
      IF(ILENX3.LE.0)GO TO 359
      DO 355 I=1,ILENX3
      J=J+1
      ILABX3(J)=IX3LTE(I)
  355 CONTINUE
      IMAXX3=J
  359 CONTINUE
!
!               ****************************************************************
!               **  STEP 4--
!               **  SKIP TO A NEW PAGE;
!               **  WRITE OUT THE TITLE (IF ANY);
!               **  WRITE OUT THE TOP HORIZONTAL AXIS OF THE PLOT;
!               ****************************************************************
!
      IF(IERASW.EQ.'ON')WRITE(ICOUT,504)
  504 FORMAT(1H1)
      IF(IERASW.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IF(IERASW.EQ.'OFF')WRITE(ICOUT,999)
      IF(IERASW.EQ.'OFF')CALL DPWRST('XXX','BUG ')
      IF(IMAXT.GE.1)WRITE(ICOUT,505)(ILABT(I),I=1,IMAXT)
  505 FORMAT(240A1)
      IF(IMAXT.GE.1)CALL DPWRST('XXX','BUG ')
!
      DO 500 ICOL=1,NUMCOL
      ILINE(ICOL)=IHYPHE
  500 CONTINUE
      DO 550 ICOL=1,NUMCOL,IXDEL
      ILINE(ICOL)=IALPHI
  550 CONTINUE
      WRITE(ICOUT,555)(ILINE(I),I=1,NUMCOL)
  555 FORMAT(20X,54A1)
      CALL DPWRST('XXX','BUG ')
!
!
!               *******************************************************
!               **  STEP 5--                                         **
!               **  DETERMINE THE MIN AND MAX VALUES OF Y AND OF X.  **
!               *******************************************************
!
      XMIN=X(1)
      XMAX=X(1)
      YMIN=Y(1)
      YMAX=Y(1)
      DO 700 I=1,N
      IF(X(I).LT.XMIN)XMIN=X(I)
      IF(X(I).GT.XMAX)XMAX=X(I)
      IF(Y(I).LT.YMIN)YMIN=Y(I)
      IF(Y(I).GT.YMAX)YMAX=Y(I)
  700 CONTINUE
      IF(GX1MIN.NE.CPUMIN)XMIN=GX1MIN
      IF(GX1MAX.NE.CPUMAX)XMAX=GX1MAX
      IF(GY1MIN.NE.CPUMIN)YMIN=GY1MIN
      IF(GY1MAX.NE.CPUMAX)YMAX=GY1MAX
      DELX=XMAX-XMIN
      DELY=YMAX-YMIN
      XWIDTH=DELX/ANUMCM
      YWIDTH=DELY/ANUMRM
!
!               *************************************
!               **  STEP 6--                       **
!               **  DETERMINE THE DISTINCT VALUES  **
!               **  IN THE VARIABLE D(.)           **
!               *************************************
!
      MAXDIS=1000
!
      NUMDIS=1
      DISTD(1)=D(1)
!
      DO 900 I=2,N
      DO 910 J=1,NUMDIS
      IF(D(I).EQ.DISTD(J))GO TO 900
  910 CONTINUE
      IF(NUMDIS.GE.MAXDIS)GO TO 990
      NUMDIS=NUMDIS+1
      DISTD(NUMDIS)=D(I)
  900 CONTINUE
  990 CONTINUE
!
!               ****************************************************************
!               **  STEP 7--
!               **  DETERMINE AND WRITE OUT THE PLOT POSITIONS ONE LINE AT A TIM
!               ****************************************************************
!
      DO 1100 IROW=1,NUMROW
!
      DO 1200 ICOL=1,NUMCOL
      ILINE(ICOL)=IBLANK
 1200 CONTINUE
!
      AIROW=IROW
      YUPPER=YMAX+(1.5-AIROW)*YWIDTH
      YLABEL=YMAX+(1.0-AIROW)*YWIDTH
      YLOWER=YMAX+(0.5-AIROW)*YWIDTH
      IF(IROW.EQ.NUMROW)YLABEL=YMIN
      DO 1300 I=1,N
      AI=I
      IF(YLOWER.LE.Y(I).AND.Y(I).LT.YUPPER)GO TO 1350
      GO TO 1300
 1350 CONTINUE
      ICOL=INT(((X(I)-XMIN)/XWIDTH)+1.5)
      IF(ICOL.LT.1.OR.ICOL.GT.NUMCOL)GO TO 1300
      DO 1360 K=1,NUMDIS
      K2=K
      IF(D(I).EQ.DISTD(K))GO TO 1370
 1360 CONTINUE
      JPLOTC='X'
      GO TO 1390
 1370 CONTINUE
      JPLOTC='X'
      IF(ICASP2.EQ.'BOXP')K2=K2-((K2-1)/20)*20
      IF(ICASP2.EQ.'IPLO')K2=K2-((K2-1)/5)*5
      IF(K2.LE.MAXCHA)JPLOTC=ICHAR(K2)
      IF(JPLOTC.EQ.'    ')JPLOTC='X'
      IF(JPLOTC.EQ.'BLAN')JPLOTC='X'
      IF(JPLOTC.EQ.'NONE')JPLOTC='X'
      GO TO 1390
 1390 CONTINUE
      ILINE(ICOL)=JPLOTC
 1300 CONTINUE
!
      ICOLMX=1
      DO 1400 ICOL=1,NUMCOL
      ICOLRV=NUMCOL-ICOL+1
      IF(ILINE(ICOLRV).EQ.' ')GO TO 1400
      ICOLMX=ICOLRV
      GO TO 1490
 1400 CONTINUE
 1490 CONTINUE
!
      IAXISC=IALPHI
      IF(IROW.EQ.1.OR.IROW.EQ.NUMROW)IAXISC=IHYPHE
      IF(IROW.EQ.NUMR25.OR.IROW.EQ.NUMR50.OR.IROW.EQ.NUMR75)   &
      IAXISC=IHYPHE
      WRITE(ICOUT,1410)ILABY(IROW),YLABEL,IAXISC,   &
      (ILINE(ICOL),ICOL=1,ICOLMX)
 1410 FORMAT(A1,1X,E14.7,1X,A1,2X,50A1)
      CALL DPWRST('XXX','BUG ')
!
 1100 CONTINUE
!
!               ************************************************************
!               **  STEP 8--                                              **
!               **  WRITE OUT THE BOTTOM HORIZONTAL AXIS OF THE PLOT;     **
!               **  WRITE OUT THE X-AXIS NUMERIC LABELS;                  **
!               **  WRITE OUT THE FIRST  HORIZONTAL AXIS LABEL (IF ANY);  **
!               **  WRITE OUT THE SECOND HORIZONTAL AXIS LABEL (IF ANY);  **
!               **  WRITE OUT THE THIRD  HORIZONTAL AXIS LABEL (IF ANY).  **
!               ************************************************************
!
!
      DO 2200 ICOL=1,NUMCOL
      ILINE(ICOL)=IHYPHE
 2200 CONTINUE
      DO 2300 ICOL=1,NUMCOL,IXDEL
      ILINE(ICOL)=IALPHI
 2300 CONTINUE
      WRITE(ICOUT,2105)(ILINE(ICOL),ICOL=1,NUMCOL)
 2105 FORMAT(20X,54A1)
      CALL DPWRST('XXX','BUG ')
!
      NUMLAB=5
      ANUMLM=NUMLAB-1
      DO 2500 I=1,NUMLAB
      AIM1=I-1
      AILABL(I)=XMIN+(AIM1/ANUMLM)*DELX
 2500 CONTINUE
      WRITE(ICOUT,2310)(AILABL(I),I=1,NUMLAB)
 2310 FORMAT(13X,5E10.4)
      CALL DPWRST('XXX','BUG ')
!
      IF(IMAXX1.GE.1)WRITE(ICOUT,2311)(ILABX1(I),I=1,IMAXX1)
 2311 FORMAT(240A1)
      IF(IMAXX1.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX2.GE.1)WRITE(ICOUT,2311)(ILABX2(I),I=1,IMAXX2)
      IF(IMAXX2.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX3.GE.1)WRITE(ICOUT,2311)(ILABX3(I),I=1,IMAXX3)
      IF(IMAXX3.GE.1)CALL DPWRST('XXX','BUG ')
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      RETURN
      END SUBROUTINE PLOTCN
      SUBROUTINE PLOTCW(Y,X,D,N,ICHAR,MAXCHA,ICASPL,ICAS3D,   &
      ITITTE,NCTITL,   &
      IX1LTE,NCX1LA,   &
      IX2LTE,NCX2LA,   &
      IX3LTE,NCX3LA,   &
      IY1LTE,NCY1LA,   &
      IY2LTE,NCY2LA,   &
      GX1MIN,GX1MAX,GY1MIN,GY1MAX,   &
      IERASW,IBUGU2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE YIELDS A WIDE-WIDTH (130-CHARACTER)
!              PLOT OF Y(I) VERSUS X(I) WITH SPECIAL CHARACTERS
!              FOR THE VARIOUS SUB-TRACES DICTATED BY THE
!              CONTENTS OF THE DUMMY VARIABLE D(.)
!              AND THE CHARACTER VARIABLE ICHAR(.).
!              ALL(X,Y) PAIRS CORRESPONING
!              TO THE MINIMUM VALUE IN D(.)
!              WILL BE PLOTTED WITH PLOT CHARACTER = ICHAR(1).
!              ALL(X,Y) PAIRS CORRESPONING
!              TO THE NEXT LARGER VALUE IN D(.)
!              WILL BE PLOTTED WITH PLOT CHARACTER = ICHAR(2).
!              ETC.
!      NOTE--THE WIDE WIDTH OF THIS PLOT
!            MAKES IT APPROPRIATE FOR
!            USE ON A BATCH PRINTER.
!     INPUT ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS
!                               TO BE PLOTTED VERTICALLY.
!                    --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR X.
!                    --ICHAR  = THE HOLLERITH VECTOR OF
!                               CHARACTERS (ONLY THE
!                               FIRST OF WHICH WILL BE USED)
!                    --MAXCHA = THE INTEGER NUMBER OF
!                               CHARACTERS IN ICHAR(.)
!     OUTPUT--A WIDE-WIDTH (130-CHARACTER) TERMINAL PLOT
!             OF Y(I) VERSUS X(I).
!             THE BODY OF THE PLOT (NOT COUNTING AXIS VALUES
!             AND MARGINS) IS 41 ROWS (LINES) AND 101 COLUMNS.
!     PRINTING--YES.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NONE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --JANUARY   1975.
!     UPDATED         --JULY      1975.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --OCTOBER   1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1976.
!     UPDATED         --FEBRUARY  1977.
!     UPDATED         --JUNE      1978.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --JANUARY   1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICHAR
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
!
      CHARACTER*4 ITITTE
      CHARACTER*4 IX1LTE
      CHARACTER*4 IX2LTE
      CHARACTER*4 IX3LTE
      CHARACTER*4 IY1LTE
      CHARACTER*4 IY2LTE
!
      CHARACTER*4 IERASW
      CHARACTER*4 IBUGU2
      CHARACTER*4 IERROR
!
      CHARACTER*4 IBLANK
      CHARACTER*4 IHYPHE
      CHARACTER*4 IALPHI
      CHARACTER*4 IALPHX
      CHARACTER*4 IALPHM
      CHARACTER*4 IALPHA
      CHARACTER*4 IALPHN
      CHARACTER*4 IALPHD
      CHARACTER*4 IEQUAL
!
      CHARACTER*4 ILABT
      CHARACTER*4 ILABY1
      CHARACTER*4 ILABX1
      CHARACTER*4 ILABX2
      CHARACTER*4 ILABX3
!
      CHARACTER*4 JPLOTC
      CHARACTER*4 IGRAPH
      CHARACTER*4 ICASP2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION D(*)
      DIMENSION ICHAR(*)
      DIMENSION IGRAPH(55,130)
!
      DIMENSION ITITTE(*)
      DIMENSION IX1LTE(*)
      DIMENSION IX2LTE(*)
      DIMENSION IX3LTE(*)
      DIMENSION IY1LTE(*)
      DIMENSION IY2LTE(*)
!
      DIMENSION ILABT(132)
      DIMENSION ILABY1(132)
      DIMENSION ILABX1(132)
      DIMENSION ILABX2(132)
      DIMENSION ILABX3(132)
!
      DIMENSION YLABEL(11)
      DIMENSION DISTD(MAXOBV)
!CCCC FOLLOWING LINES ADDED JUNE, 1990
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),DISTD(1))
!CCCC END CHANGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IBLANK=' '
      IHYPHE='-'
      IALPHI='I'
      IALPHX='X'
      IALPHM='M'
      IALPHA='A'
      IALPHX='X'
      IALPHN='N'
      IALPHD='D'
      IALPHN='N'
      IEQUAL='='
!
      IMAXT=0
      IMAXX1=0
      IMAXX2=0
      IMAXX3=0
!
      IF(IBUGU2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF PLOTCW--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,NCY1LA,NCY2LA,IBUGU2
   52   FORMAT('N,NCY1LA,NCY2LA,IBUGU2 = ',3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)Y(1),X(1),D(1),ICHAR(1)
   53   FORMAT('Y(1),X(1),D(1),ICHAR(1) = ',3E15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)Y(N),X(N),D(N),ICHAR(N)
   54   FORMAT('Y(N),X(N),D(N),ICHAR(N) = ',3E15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ICASPL,ICAS3D
   55   FORMAT('ICASPL,ICAS3D = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)GX1MIN,GX1MAX,GY1MIN,GY1MAX
   73   FORMAT('GX1MIN,GX1MAX,GY1MIN,GY1MAX = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,75)IY2LTE(1)
   75   FORMAT('IY2LTE(1) = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!               *************************************
!               **  STEP 1.5--                     **
!               **  DETERMINE THE DISTINCT VALUES  **
!               **  IN THE VARIABLE D(.)           **
!               *************************************
!
      MAXDIS=1000
!
      NUMDIS=1
      DISTD(1)=D(1)
!
      DO 250 I=2,N
      DO 260 J=1,NUMDIS
      IF(D(I).EQ.DISTD(J))GO TO 250
  260 CONTINUE
      IF(NUMDIS.GE.MAXDIS)GO TO 269
      NUMDIS=NUMDIS+1
      DISTD(NUMDIS)=D(I)
  250 CONTINUE
  269 CONTINUE
!
!
!               ***************************************************************
!               **  STEP 2--                                                 **
!               **  DEFINE THE NUMBER OF ROWS AND COLUMNS WITHIN THE PLOT--  **
!               **  THIS HAS BEEN SET TO 41 ROWS AND  97 COLUMNS.            **
!               ***************************************************************
!
      NUMROW=41
      NUMCOL=97
!
      ANUMR=NUMROW
      ANUMRM=NUMROW-1
      ANUMCM=NUMCOL-1
      NUMR25=(NUMROW/4)+1
      NUMR50=(NUMROW/2)+1
      NUMR75=3*(NUMROW/4)+1
      IXDEL=(NUMCOL-1)/4
!
!               ***************************
!               **  STEP 2.1--           **
!               **  BLANK OUT THE GRAPH  **
!               ***************************
!
      DO 280 I=1,55
      DO 290 J=1,130
      IGRAPH(I,J)=IBLANK
  290 CONTINUE
  280 CONTINUE
!
!               ********************************
!               **  STEP 2.2--                **
!               **  DEFINE THE TYPE OF PLOT.  **
!               ********************************
!
      ICASP2=ICASPL
      IF(ICASPL.EQ.'MDBP')ICASP2='BOXP'
      IF(ICASPL.EQ.'MEBP')ICASP2='BOXP'
      IF(ICASPL.EQ.'VIPL')ICASP2='BOXP'
      IF(ICASPL.EQ.'MDIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MEIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MRIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MMIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'1SE ')ICASP2='IPLO'
      IF(ICASPL.EQ.'2SE ')ICASP2='IPLO'
      IF(ICASPL.EQ.'1SD ')ICASP2='IPLO'
      IF(ICASPL.EQ.'2SD ')ICASP2='IPLO'
      IF(ICASPL.EQ.'MDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'MECL')ICASP2='IPLO'
      IF(ICASPL.EQ.'QUCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'TMCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'BWCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'SDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CVCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CRCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CQCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'DPRO')ICASP2='IPLO'
      IF(ICASPL.EQ.'DMEA')ICASP2='IPLO'
      IF(ICASPL.EQ.'NPRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'BWRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'TMRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'AGCL')ICASP2='IPLO'
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  PREPARE THE TITLE LINE, THE Y-AXIS LABEL,       **
!               **  AND THE 3 HORIZONTAL AXIS LABELS FOR PRINTING.  **
!               ******************************************************
!
      IVAL=INT((55./2.) - 4)
      YMIDL=REAL(IVAL)
      IVAL=29 + INT(REAL(NUMCOL)/2.)
      XMIDL=REAL(IVAL)
!
      YFACT=1.0
      XFACT=1.0
!
      ILENT=NCTITL
      ILENY1=NCY1LA
      ILENX1=NCX1LA
      ILENX2=NCX2LA
      ILENX3=NCX3LA
!
      ALENT=ILENT
      ALENY1=ILENY1
      ALENX1=ILENX1
      ALENX2=ILENX2
      ALENX3=ILENX3
!
      IX=INT(XMIDL-XFACT*(ALENT/2.0))
      DO 310 I=1,132
      ILABT(I)=' '
  310 CONTINUE
      J=IX-1
      IF(ILENT.LE.0)GO TO 319
      DO 315 I=1,ILENT
      J=J+1
      ILABT(J)=ITITTE(I)
  315 CONTINUE
      IMAXT=J
  319 CONTINUE
!
      IY=INT(YMIDL-YFACT*(ALENY1/2.0))
      DO 320 I=1,132
      ILABY1(I)=' '
  320 CONTINUE
      J=IY-1
      IF(ILENY1.LE.0)GO TO 329
      DO 325 I=1,ILENY1
      J=J+1
      ILABY1(J)=IY1LTE(I)
  325 CONTINUE
      IMAXY1=J
  329 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX1/2.0))
      DO 330 I=1,132
      ILABX1(I)=' '
  330 CONTINUE
      J=IX-1
      IF(ILENX1.LE.0)GO TO 339
      DO 335 I=1,ILENX1
      J=J+1
      ILABX1(J)=IX1LTE(I)
  335 CONTINUE
      IMAXX1=J
  339 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX2/2.0))
      DO 340 I=1,132
      ILABX2(I)=' '
  340 CONTINUE
      J=IX-1
      IF(ILENX2.LE.0)GO TO 349
      DO 345 I=1,ILENX2
      J=J+1
      ILABX2(J)=IX2LTE(I)
  345 CONTINUE
      IMAXX2=J
  349 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX3/2.0))
      DO 350 I=1,132
      ILABX3(I)=' '
  350 CONTINUE
      J=IX-1
      IF(ILENX3.LE.0)GO TO 359
      DO 355 I=1,ILENX3
      J=J+1
      ILABX3(J)=IX3LTE(I)
  355 CONTINUE
      IMAXX3=J
  359 CONTINUE
!
!               *******************************************************
!               **  STEP 5--                                         **
!               **  DETERMINE THE MIN AND MAX VALUES OF Y AND OF X.  **
!               *******************************************************
!
      YMIN=Y(1)
      YMAX=Y(1)
      XMIN=X(1)
      XMAX=X(1)
      DO 700 I=1,N
      IF(Y(I).LT.YMIN)YMIN=Y(I)
      IF(Y(I).GT.YMAX)YMAX=Y(I)
      IF(X(I).LT.XMIN)XMIN=X(I)
      IF(X(I).GT.XMAX)XMAX=X(I)
  700 CONTINUE
      IF(GX1MIN.NE.CPUMIN)XMIN=GX1MIN
      IF(GX1MAX.NE.CPUMAX)XMAX=GX1MAX
      IF(GY1MIN.NE.CPUMIN)YMIN=GY1MIN
      IF(GY1MAX.NE.CPUMAX)YMAX=GY1MAX
      DELY=YMAX-YMIN
      DELX=XMAX-XMIN
      YWIDTH=DELY/ANUMRM
      XWIDTH=DELX/ANUMCM
!
      XMID=(XMIN+XMAX)/2.0
      X25=0.75*XMIN+0.25*XMAX
      X75=0.25*XMIN+0.75*XMAX
!
      DO 800 I=1,9
      AIM1=I-1
      YLABEL(I)=YMAX-(AIM1/8.0)*(YMAX-YMIN)
  800 CONTINUE
!
!               *********************************
!               **  STEP 6--                   **
!               **  PRODUCE THE VERTICAL AXES  **
!               *********************************
!
      DO 1300 I=3,43
      IGRAPH(I,5)=IALPHI
      IGRAPH(I,105)=IALPHI
 1300 CONTINUE
      DO 1400 I=3,43,5
      IGRAPH(I,5)=IHYPHE
      IGRAPH(I,105)=IHYPHE
 1400 CONTINUE
      IGRAPH(3,1)=IEQUAL
      IGRAPH(3,2)=IALPHM
      IGRAPH(3,3)=IALPHA
      IGRAPH(3,4)=IALPHX
      IGRAPH(23,1)=IEQUAL
      IGRAPH(23,2)=IALPHM
      IGRAPH(23,3)=IALPHI
      IGRAPH(23,4)=IALPHD
      IGRAPH(43,1)=IEQUAL
      IGRAPH(43,2)=IALPHM
      IGRAPH(43,3)=IALPHI
      IGRAPH(43,4)=IALPHN
!
!               ***********************************
!               **  STEP 7--                     **
!               **  PRODUCE THE HORIZONTAL AXES  **
!               ***********************************
!
      DO 1500 J=7,103
      IGRAPH(1,J)=IHYPHE
      IGRAPH(45,J)=IHYPHE
 1500 CONTINUE
      DO 1600 J=7,103,12
      IGRAPH(1,J)=IALPHI
      IGRAPH(45,J)=IALPHI
 1600 CONTINUE
!
!               ******************************************
!               **  STEP 8--                            **
!               **  DETERMINE THE (X,Y) PLOT POSITIONS  **
!               ******************************************
!
      RATIOY=ANUMRM/(YMAX-YMIN)
      RATIOX=ANUMCM/(XMAX-XMIN)
      DO 1800 I=1,N
      XI=X(I)
      MX=INT(RATIOX*(XI-XMIN)+0.5)
      MX=MX+7
      IF(MX.LT.7.OR.MX.GT.103)GO TO 1800
      MY=INT(RATIOY*(Y(I)-YMIN)+0.5)
      MY=43-MY
      IF(MY.LT.3.OR.MY.GT.43)GO TO 1800
      DO 1860 K=1,NUMDIS
      K2=K
      IF(D(I).EQ.DISTD(K))GO TO 1870
 1860 CONTINUE
      JPLOTC='X'
      GO TO 1890
 1870 CONTINUE
      JPLOTC='X'
      IF(ICASP2.EQ.'BOXP')K2=K2-((K2-1)/20)*20
      IF(ICASP2.EQ.'IPLO')K2=K2-((K2-1)/5)*5
      IF(K2.LE.MAXCHA)JPLOTC=ICHAR(K2)
      IF(JPLOTC.EQ.'    ')JPLOTC='X'
      IF(JPLOTC.EQ.'BLAN')JPLOTC='X'
      IF(JPLOTC.EQ.'NONE')JPLOTC='X'
      GO TO 1890
 1890 CONTINUE
      IGRAPH(MY,MX)=JPLOTC
 1800 CONTINUE
!
!               *************************************
!               **  STEP 9--                       **
!               **  SKIP TO A NEW PAGE.            **
!               **  WRITE OUT THE TITLE (IF ANY);  **
!               *************************************
!
      IF(IERASW.EQ.'ON')WRITE(ICOUT,2004)
 2004 FORMAT(1H1)
      IF(IERASW.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IF(IERASW.EQ.'OFF')WRITE(ICOUT,999)
      IF(IERASW.EQ.'OFF')CALL DPWRST('XXX','BUG ')
      IF(IMAXT.GE.1)WRITE(ICOUT,2005)(ILABT(I),I=1,IMAXT)
 2005 FORMAT(240A1)
      IF(IMAXT.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXT.LE.0)WRITE(ICOUT,999)
      IF(IMAXT.LE.0)CALL DPWRST('XXX','BUG ')
!
!               *********************************************
!               **  STEP 10--                              **
!               **  WRITE OUT THE GRAPH                    **
!               **  (INCLUDING THE X-AXIS NUMERIC LABELS)  **
!               *********************************************
!
      DO 2100 I=1,45
      IP2=I+2
      IFLAG=IP2-(IP2/5)*5
      K=IP2/5
      IF(IFLAG.NE.0)WRITE(ICOUT,2105)ILABY1(I),(IGRAPH(I,J),J=1,105)
 2105 FORMAT(A1,20X,105A1)
      IF(IFLAG.NE.0)CALL DPWRST('XXX','BUG ')
      IF(IFLAG.EQ.0)WRITE(ICOUT,2106)ILABY1(I),YLABEL(K),   &
      (IGRAPH(I,J),J=1,105)
 2106 FORMAT(A1,F20.7,105A1)
      IF(IFLAG.EQ.0)CALL DPWRST('XXX','BUG ')
 2100 CONTINUE
      WRITE(ICOUT,2107)XMIN,X25,XMID,X75,XMAX
 2107 FORMAT(14X,F20.7,4X,F20.7,4X,F20.7,4X,F20.7,4X,F20.7)
      CALL DPWRST('XXX','BUG ')
!
!               ************************************************************
!               **  STEP 11--                                             **
!               **  WRITE OUT THE FIRST  HORIZONTAL AXIS LABEL (IF ANY);  **
!               **  WRITE OUT THE SECOND HORIZONTAL AXIS LABEL (IF ANY);  **
!               **  WRITE OUT THE THIRD  HORIZONTAL AXIS LABEL (IF ANY).  **
!               ************************************************************
!
      IF(IMAXX1.GE.1)WRITE(ICOUT,2311)(ILABX1(I),I=1,IMAXX1)
 2311 FORMAT(240A1)
      IF(IMAXX1.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX1.LE.0)WRITE(ICOUT,999)
      IF(IMAXX1.LE.0)CALL DPWRST('XXX','BUG ')
      IF(IMAXX2.GE.1)WRITE(ICOUT,2311)(ILABX2(I),I=1,IMAXX2)
      IF(IMAXX2.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX2.LE.0)WRITE(ICOUT,999)
      IF(IMAXX2.LE.0)CALL DPWRST('XXX','BUG ')
      IF(IMAXX3.GE.1)WRITE(ICOUT,2311)(ILABX3(I),I=1,IMAXX3)
      IF(IMAXX3.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX3.LE.0)WRITE(ICOUT,999)
      IF(IMAXX3.LE.0)CALL DPWRST('XXX','BUG ')
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      RETURN
      END SUBROUTINE PLOTCW
      SUBROUTINE PLOTGE(Y,X,X3D,D,N,XIDC,NUMSET,                  &
                        ICASPL,ICAS3D,ISQUAR,YSAVE,               &
                        IVGMSW,IHGMSW,IFIRST,ILAST,               &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,   &
                        IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,        &
                        DSIZE,DSYMB,DCOLOR,DFILL,                 &
                        ICAPSW,                                   &
                        IBUGU2,IBUGU3,IBUGU4,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A GENERAL (SINGLE OR MULTIPLE TRACE) PLOT
!              ON A GENERAL GRAPHICS DEVICE.
!              THE PLOT WILL CONSIST OF Y VERSUS X
!              WITH EACH DISTINCT VALUE OF THE VARIABLE D
!              RESULTING IN A DISTINCT TRACE ON THE PLOT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--AUGUST 22, 1977.
!     UPDATED         --DECEMBER  1977.
!     UPDATED         --JUNE      1978.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --MARCH     1979.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --MARCH     1981.
!     UPDATED         --APRIL     1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JULY      1983.
!     UPDATED         --SEPTEMBER 1988.  3D HIDDEN LINE ETC.
!     UPDATED         --OCTOBER   1988.  ERROR BAR PLOT
!     UPDATED         --FEBRUARY  1989.  HORIZONTAL SWITCH (ALAN)
!     UPDATED         --MAY       1989.  DES. OF EXP. PLOTS
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --JUNE      1992.  BLOCK PLOTS
!     UPDATED         --AUGUST    1992.  VECTOR PLOT.  ALSO, BUG IF
!                                        NUMSET =101, 201, ETC.
!     UPDATED         --AUGUST    1992.  SYMBOL PLOT
!     UPDATED         --NOVEMBER  1993.  MODIFICATION FOR PIE CHART
!     UPDATED         --AUGUST    1994.  BUG FOR VECTOR PLOT
!     UPDATED         --DECEMBER  1994.  EXACT CHARACTER MAPPING
!     UPDATED         --JUNE      1995.  BLOCK PLOT FIX--KEEP
!     UPDATED                                            ISET3 <= 100
!
!     UPDATED         --MAY       1998.  DUANE PLOTS NEED LOG SCALES
!     UPDATED         --DECEMBER  1999. IMPLEMENT SUB-REGIONS
!     UPDATED         --JANUARY   2000. IMPLEMENT ZVAL CHARACTER TYPE
!     UPDATED         --AUGUST    2001. CONSENSUS MEAN PLOT, SET
!                                       CHAR/LINE TYPES SIMILAR TO
!                                       I-PLOT
!     UPDATED         --FEBRUARY  2003. VIOLIN PLOT (SIMILAR TO BOX
!                                       PLOT, EXTRA TRACE AT
!                                       BEGINNING)
!     UPDATED         --MARCH     2003. PARALLEL COORDINATES PLOT
!                                       (PRE-SORT OFF)
!     UPDATED         --MAY       2003. GROUPED PARALLEL COORDINATES
!                                       PLOT
!     UPDATED         --MARCH     2007. BUG IN BOX PLOT (FENCES)
!     UPDATED         --JUNE      2007. ASSOCIATION PLOT
!     UPDATED         --JUNE      2007. SIEVE PLOT
!     UPDATED         --MARCH     2008. LEVEL PLOT
!     UPDATED         --MARCH     2008. IMAGE PLOT
!     UPDATED         --MAY       2008. FLUCTUATION PLOT
!     UPDATED         --SEPTEMBER 2009. TABULATION PLOT
!     UPDATED         --FEBRUARY  2012. RLP PLOT
!     UPDATED         --JULY      2012. WHEN CHARACTER SETTINGS RESET
!                                       (> 100 TRACES), ALLOW AN OFFSET
!     UPDATED         --JULY      2012. FOR "CHARACTER AUTOMATIC", ALLLOW
!                                       A "DYNAMIC" OPTION THAT WILL
!                                       EXTRACT AN APPROPRIATE CHARACTER
!                                       SETTING IN THIS ROUTINE RATHER
!                                       THAN AT THE TIME
!                                       "CHARACTER AUTOMATIC" COMMAND GIVEN.
!                                       (THIS NOT FULLY IMPLEMENTED AT
!                                       THIS TIME, HOWEVER THERE IS A
!                                       PATCH FOR > 100 TRACES)
!     UPDATED         --DECEMBER  2012. HANDLE BLOCK PLOT WITH
!                                       "BACKGROUND" OPTION AS A
!                                       SPECIAL CASE.
!     UPDATED         --NOVEMBER  2015. ADD IDEVO3 TO CALL LIST
!     UPDATED         --JULY      2019. TWEAK SCRATCH SPACE
!     UPDATED         --APRIL     2025. TWEAK FOR COMMUTABILITY PLOT
!     UPDATED         --JUNE      2025. SETTINGS FOR WATERFALL CHART
!     UPDATED         --JUNE      2025. TWEAKS FOR BULLET PLOT
!     UPDATED         --JUNE      2025. TWEAKS FOR VARIABLE WIDTH BAR PLOT
!     UPDATED         --JULY      2025. TWEAKS FOR CANDLESTICK PLOT
!
!-----NON-COMMON VARIABLES--------------------------------------------
!
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ISQUAR
      CHARACTER*4 IVGMSW
      CHARACTER*4 IHGMSW
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*4 IFIRST
      CHARACTER*4 ILAST
!
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 IFUNC
!
      CHARACTER*1 IREPCH
!
      CHARACTER*4 IBUGU2
      CHARACTER*4 IBUGU3
      CHARACTER*4 IBUGU4
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IMORE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*24 ICH3PA
      CHARACTER*10 IFORMT
!
      CHARACTER*4 IOPGRS
      CHARACTER*4 IOPG2S
      CHARACTER*4 IDELIS
      CHARACTER*4 IDRFRS
      CHARACTER*4 IWRLAS
      CHARACTER*4 IWRLES
      CHARACTER*4 IDRTRS
      CHARACTER*4 ICLG2S
      CHARACTER*4 ICLGRS
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISWTCH
      CHARACTER*4 IX1TMP
      CHARACTER*4 IX2TMP
      CHARACTER*4 IY1TMP
      CHARACTER*4 IY2TMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCO3D.INC'
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION X3D(*)
      DIMENSION D(*)
      DIMENSION DSIZE(*)
      DIMENSION DSYMB(*)
      DIMENSION DCOLOR(*)
      DIMENSION DFILL(*)
      DIMENSION XIDC(*)
!
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
      DIMENSION IVSTAR(*)
      DIMENSION IVSTOP(*)
      DIMENSION IFUNC(*)
!
      DIMENSION X2(MAXPOP)
      DIMENSION Y2(MAXPOP)
      DIMENSION Z2(MAXPOP)
      DIMENSION X3D2(MAXPOP)
!
      DIMENSION X3(MAXPOP)
      DIMENSION Y3(MAXPOP)
      DIMENSION Z3(MAXPOP)
!
      DIMENSION X4(MAXPOP)
      DIMENSION Y4(MAXPOP)
      DIMENSION Z4(MAXPOP)
!
      DIMENSION X5(MAXPOP)
      DIMENSION Y5(MAXPOP)
!
      EQUIVALENCE (GARBAG(IGARB1),X2(1))
      EQUIVALENCE (GARBAG(IGARB3),Y2(1))
      EQUIVALENCE (GARBAG(IGARB5),Z2(1))
      EQUIVALENCE (GARBAG(IGARB7),X3D2(1))
      EQUIVALENCE (GARBAG(IGARB9),X3(1))
      EQUIVALENCE (GARBAG(JGAR11),Y3(1))
      EQUIVALENCE (GARBAG(JGAR13),Z3(1))
      EQUIVALENCE (GARBAG(JGAR15),X4(1))
      EQUIVALENCE (GARBAG(JGAR17),Y4(1))
      EQUIVALENCE (GARBAG(JGAR19),Z4(1))
      EQUIVALENCE (GARBAG(IGAR11),X5(1))
      EQUIVALENCE (GARBAG(IGAR13),Y5(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPC.INC'
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOST.INC'
!
      COMMON/IPLOT/NREPI1,NREPI2
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PLOT'
      ISUBN2='GE  '
      ISWTCH='OFF'
      IWRITE='OFF'
!
      IBUGG4=IBUGU2
      ISUBG4=ISUBRO
      IERRG4=IERROR
!
      IX1TMP='    '
      IX2TMP='    '
      IY1TMP='    '
      IY2TMP='    '
!CCCC IX1TSC='    '
!CCCC IX2TSC='    '
!CCCC IY1TSC='    '
!CCCC IY2TSC='    '
!
!CCCC DECEMBER 1999.  DETERMINE NUMBER OF SUB-REGIONS ON PLOT.
      NUMSBR=0
      DO 20 I=1,MAXSUB
        IF(ISUBSW(I).EQ.'ON')NUMSBR=NUMSBR+1
   20 CONTINUE
!
!CCCC THE FOLLOWING COMMENT AND REPLACEMENT WAS MADE FEBRUARY 1989 (ALAN)
!CCCC MXNPPC=1000
      MXNPPC=MAXPOP
!
      XDELMN=CPUMAX
      YDELMN=CPUMAX
      ZDELMN=CPUMAX
!CCCC FOLLOWING BLOCK ADDED AUGUST 1992.
      ASETSZ=1.0
      ISETSY=1
      ISETCL=1
      ISETFI=0
      PBARBA=0.0
!CCCC ADD FOLLOWING SECTION FOR DUANE PLOTS.   MAY 1998.
      IF(ICASPL.EQ.'DUAN')THEN
        IX1TMP=IX1TSC
        IX2TMP=IX2TSC
        IY1TMP=IY1TSC
        IY2TMP=IY2TSC
        IX1TSC='LOG'
        IX2TSC='LOG'
        IY1TSC='LOG'
        IY2TSC='LOG'
      ENDIF
!
!CCCC ALAN COMMENTED OUT THE FOLLOWING LINE FEBRUARY 1989
!CCCC YSAVE=0.0
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PLOTGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,NUMSET
   52   FORMAT('N,NUMSET = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,ICAS3D,I3DPRO
   53   FORMAT('ICASPL,ICAS3D,I3DPRO,I3DPRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ISQUAR,IFIRST,ILAST
   55   FORMAT('ISQUAR,IFIRST,ILAST = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,58)IBUGG4,ISUBG4,IERRG4
   58   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,59)IBUGU2,IBUGU3,IBUGU4,ISUBRO,IERROR
   59   FORMAT('IBUGU2,IBUGU3,IBUGU4,ISUBRO,IERROR = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ILINPA(1),ILINPA(2),ISPILI(1),ISPILI(2)
   61   FORMAT('ILINPA(1),ILINPA(2),ISPILI(1),ISPILI(2) = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)ICHAPA(1),ICHAPA(2)
   62   FORMAT('ICHAPA(1),ICHAPA(2) = ',A24,2X,A24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IX1JSW,IY1JSW,IX1NSW,IY1NSW
   64   FORMAT('IX1JSW,IY1JSW,IX1NSW,IY1NSW = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,66)ASPIBA(1),ASPIBA(2)
   66   FORMAT('ASPIBA(1),ASPIBA(2) = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO I=1,NUMSET
          WRITE(ICOUT,71)I,XIDC(I)
   71     FORMAT('I,XIDC(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDDO
        DO I=1,N
          WRITE(ICOUT,73)I,X(I),Y(I),D(I)
   73     FORMAT('I,X(I),Y(I),D(I),XIDC(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT PRE-PLOT ACTIVITIES.      **
!               ******************************************
!
      IF(IFIRST.EQ.'YES')THEN
        ISTEPN='1'
        IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IOPGRS='ON'
        IOPG2S='ON'
        IDELIS='ON'
        IF(IGRDOR.EQ.'BEFO')THEN
          IDRFRS='ON'
        ELSE
          IDRFRS='OFF'
        ENDIF
        IWRLAS='OFF'
        IWRLES='OFF'
        IDRTRS='OFF'
        ICLG2S='OFF'
        ICLGRS='OFF'
!
        ISTEP=1
        ISUBST=1
        ISET=1
        ISET3=ISET
        ICH3PA=ICHAPA(ISET3)
!
        IF(ICAS3D.EQ.'OFF')THEN
          CALL PLOTG2(Y,X,Y2,X2,N,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D,    &
                      D,XIDC,                                      &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,   &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,       &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,          &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                 &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,      &
                      ASETSZ,ISETSY,ISETCL,ISETFI,                 &
                      NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,          &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ELSEIF(ICAS3D.EQ.'ON')THEN
          CALL PLOTG3(X,X3D,Y,N,DSIZE,                             &
                      X2,Y2,Z2,X4,Y4,Z4,N4,X5,Y5,N5,NUMSET,        &
                      D,XIDC,                                      &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,          &
                      XDELMN,YDELMN,ZDELMN,                        &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,              &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,          &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                 &
                      ICAPSW,                                      &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,      &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ENDIF
      ENDIF
!
!               ********************************************************
!               **  STEP 2--                                          **
!               **  GENERATE THE TRACES OF THE PLOT.                  **
!               **  LOOP THROUGH THE VARIOUS LEVELS OF D--            **
!               **  ONE LEVEL AT A TIME--SO AS TO INDIVIDUALLY        **
!               **  GENERATE EACH TRACE.                              **
!               **  FOR A GIVEN LEVEL, COLLECT ALL Y AND X            **
!               **  DATA WHICH HAVE THE CORRESPONDING D VALUE         **
!               **  AT THIS LEVEL.  PLACE THESE Y AND X PAIRS         **
!               **  IN THE INTERMEDIATE VECTORS Y2 AND X2             **
!               **  IN ORDER TO BE PLOTTED.                           **
!               **  THE PLOT WILL BE GENERATED 1 'CURVE' AT A TIME--  **
!               **  THAT IS FOR 1 LEVEL OF D AT A TIME.               **
!               **  FOR EFFICIENCY SAKE,                              **
!               **  TREAT EACH OF THE FOLLOWING                       **
!               **  4 CASES SEPARATELY--                              **
!               **     1) ONLY ONE SUBSET AND N NOT EXCEED MXNPPC;    **
!               **     2) ONLY ONE SUBSET BUT N EXCEEDS MXNPPC;       **
!               **     3) MORE THAN ONE SUBSET BUT NI NOT EXCEED MXNPPC;
!               **     4) MORE THAN ONE SUBSET AND NI EXCEEDS MXNPPC; **
!               ********************************************************
!
      ISTEPN='2'
      IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASPL.EQ.'NONE')GO TO 1900
!
      IOPGRS='OFF'
      IOPG2S='OFF'
      IDELIS='OFF'
      IDRFRS='OFF'
      IWRLAS='OFF'
      IWRLES='OFF'
      IDRTRS='ON'
      ICLG2S='OFF'
      ICLGRS='OFF'
!
      IF(NUMSET.LE.0)GO TO 1900
!
!     2012/07: IF "SET CHARACTER AUTOMATIC DYNAMIC ON" WAS ENTERED,
!              EXTRACT THE VARIABLE NAME AND SEE IF IT EXISTS.
!
!
      IFLAGW=0
      ILOCW=-99
      ICOLW=-99
      NWEIGH=-99
      IF(ICHADY.EQ.'ON')THEN
        DO 201 I=1,NUMNAM
          I2=I
          IF(ICHAVN(1:4).EQ.IHNAME(I2).AND.   &
             ICHAVN(5:8).EQ.IHNAM2(I2).AND.   &
             IUSE(I2).EQ.'V')THEN
            ILOCCH=I2
            ICOLCH=IVALUE(ILOCCH)
!CCCC       NCHADY=IN(ILOCCH)
            IFLAGW=1
            GO TO 229
          ENDIF
  201   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,211)
  211   FORMAT('***** ERROR IN PLOTGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,213)
  213   FORMAT('      FOR THE CHARACTER AUTOMATIC DYNAMIC CASE, THE ',   &
               'SPEIFIED VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,215)
  215   FORMAT('      EITHER DOES NOT EXIST, OR IS NOT A VARIABLE,')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,217)
  217   FORMAT('      IN THE CURRENT NAME LIST.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,219)ICHAVN
  219   FORMAT('      NAME OF THE SPECIFIED VARIABLE = ',A8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
  229 CONTINUE
!
!CCCC AUGUST 1992.  HANDLE SYMBOL PLOT CASE SEPARATELY
      IF(ICASPL.EQ.'SYMB')THEN
!
!               *****************************************************
!               **  STEP 2.5--                                     **
!               **  TREAT THE SYMBOL PLOT CASE WHERE               **
!               **  LOOP THROUGH AND PLOT EACH POINT INDIVIUALLY   **
!               **  SET SIZE, FILL, COLOR, SYMBOL FOR EACH POINT   **
!               *****************************************************
!
        ISTEPN='2.5'
        IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ISTEP=2
        ISUBST=5
        ISET3=ISET
        ICH3PA=ICHAPA(ISET3)
!
        N2=1
        DO I=1,N
          I2=I
          Y2(N2)=Y(I2)
          X2(N2)=X(I2)
          X3D2(N2)=X3D(I2)
          ASETSZ=DSIZE(I2)
          ISETSY=INT(DSYMB(I2)+0.5)
          IF(ISETSY.LT.1.OR.ISETSY.GT.MAXCH2)ISETSY=1
          ISETFI=INT(DFILL(I2)+0.5)
          ISETCL=INT(DCOLOR(I2)+0.5)
          IF(ISETCL.LT.1.OR.ISETCL.GT.MAXCH2)ISETCL=1
!
          CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                      D,XIDC,                                         &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,IWRLES,      &
                      IDRTRS,ICLG2S,ICLGRS,                           &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                      ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                      NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ENDDO
        GO TO 1900
!CCCC FEBRUARY 2012.  HANDLE RLP PLOT CASE SEPARATELY IF NUMSET > 2
      ELSEIF(ICASPL.EQ.'RLP' .AND. NUMSET.GT.2)THEN
!
!               *****************************************************
!               **  STEP 2.6--                                     **
!               **  TREAT THE RLP    PLOT CASE WHEN THE PLOT       **
!               **  POINTS WILL BE LABELED WITH THE LAB-ID.        **
!               **  LOOP THROUGH AND PLOT EACH POINT INDIVIUALLY   **
!               **  SET SYMBOL FOR EACH POINT                      **
!               *****************************************************
!
        ISTEPN='2.6'
        IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       DO IN TWO PASSES:
!
!          1. TRACE 1 CONTAINS THE "SUB-REGION" AND TRACE 2 DRAWS
!             ALL POINTS USING A SINGLE SYMBOL
!
!          2. FOR TRACE 2, DRAW EACH POINT SEPARATELY AND TAKE
!             SYMBOL FROM "X3D" ARRAY.
!
!       PASS 1: DRAW ALL POINTS USING SAME CHARACTER
!
        ICH3PA=' '
        ISTEP=2
        ISUBST=6
!
        DO II=1,2
          ISET=II
          ISET3=II
          ASETSZ=1.0
          JSET=INT(XIDC(ISET)+0.5)
          N2=0
!
          DO I=1,N
            I2=I
            IF(D(I2).EQ.XIDC(ISET))THEN
              N2=N2+1
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
              DSYMB(N2)=DSIZE(I2)
            ENDIF
          ENDDO
!
          CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                      D,XIDC,                                         &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                      ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                      NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
!
        ENDDO
!
        ISET=3
        ISET3=3
!
        ASETSZ=1.0
        JSET=INT(XIDC(ISET)+0.5)
        N2=1
!
        DO I=1,N
          I2=I
          IF(D(I2).EQ.XIDC(ISET))THEN
            Y2(N2)=Y(I2)
            X2(N2)=X(I2)
            X3D2(N2)=1.0
            IXTEMP=INT(X3D(I2)+0.5)
            ICH3PA=' '
            NCSTR=0
            IF(IXTEMP.LE.9)THEN
              NCHTOT=1
            ELSEIF(IXTEMP.LE.99)THEN
              NCHTOT=2
            ELSEIF(IXTEMP.LE.999)THEN
              NCHTOT=3
            ELSEIF(IXTEMP.LE.9999)THEN
              NCHTOT=4
            ELSEIF(IXTEMP.LE.99999)THEN
              NCHTOT=5
            ELSEIF(IXTEMP.LE.999999)THEN
              NCHTOT=6
            ELSEIF(IXTEMP.LE.9999999)THEN
              NCHTOT=7
            ELSEIF(IXTEMP.LE.99999999)THEN
              NCHTOT=8
            ELSEIF(IXTEMP.LE.999999999)THEN
              NCHTOT=9
            ENDIF
            IFORMT='(I  )'
            WRITE(IFORMT(3:4),'(I2)')NCHTOT
            WRITE(ICH3PA(1:NCHTOT),IFORMT)IXTEMP
!
            CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                        D,XIDC,                                         &
                        ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                        ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                        IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                        IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                        ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                        NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                        IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
          ENDIF
        ENDDO
        GO TO 1900
!
!CCCC DECEMBER 2012.  HANDLE BLOCK PLOT WITH "BACKGROUND" OPTION SET
!CCCC                 CASE SEPARATELY.
!
      ELSEIF(ICASPL.EQ.'BLPL' .AND. IBPLBG.EQ.'ON')THEN
!
!               *****************************************************
!               **  STEP 2.7--                                     **
!               **  TREAT THE BLOCK PLOT CASE WHEN THE "BACKGROUND"**
!               **  OPTION IS SET. THE "BLOCKS" WILL BE            **
!               **  IDENTIFIED WITH "NEGATIVE TAG VALUES.  DRAW    **
!               **  THESE FIRST.  THEN PLOT THE VALUES WITH THE    **
!               **  POSITIVE TAG VALUES.                           **
!               *****************************************************
!
        ISTEPN='2.7'
        IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       PLOT THE "BLOCKS" FIRST (D(.) NEGATIVE VALUES)
!
        DO 1710 ISET=1,NUMSET
!
          ISTEP=1
          ISUBST=1
          ISET4=INT(XIDC(ISET)-0.1)
          IF(ISET4.GT.0)GO TO 1710
          ISET3=-ISET4
          ASETSZ=1.0
!
          N2=0
          DO I=1,N
            I2=I
            IF(D(I2).EQ.ISET4)THEN
              N2=N2+1
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
            ENDIF
          ENDDO
!
          IF(N2.GE.1)THEN
            ICASPL='BLP2'
            CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                        D,XIDC,                                         &
                        ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                        ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                        IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                        IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                        ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                        NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                        IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
          ENDIF
!
 1710   CONTINUE
!
!       NOW PLOT THE "CHARACTERS" (D(.) POSITIVE VALUES)
!
        DO 1760 ISET=1,NUMSET
!
          ISTEP=1
          ISUBST=1
          ISET3=INT(XIDC(ISET)+0.1)
          IF(ISET3.LT.0)GO TO 1760
          ASETSZ=1.0
!
          N2=0
          DO I=1,N
            I2=I
            IF(D(I2).EQ.ISET3)THEN
              N2=N2+1
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
            ENDIF
          ENDDO
!
          IF(N2.GE.1)THEN
            ICASPL='BLP3'
            CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                        D,XIDC,                                         &
                        ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                        ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                        IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                        IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                        ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                        NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                        IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
          ENDIF
!
 1760   CONTINUE
!
        ICASPL='BLPL'
        GO TO 1900
!
      ELSEIF(ICASPL.EQ.'WAPL')THEN
!
!               *****************************************************
!               **  STEP 2.8--                                     **
!               **  TREAT THE WATERFALL CHART CASE.                **
!               *****************************************************
!
        ISTEPN='2.8'
        IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        DO ISET=1,NUMSET
!
           ISTEP=1
           ISUBST=1
           ISET3=INT(XIDC(ISET)+0.1)
           IVAL=MOD(ISET3,3)
           IF(IVAL.EQ.0)IVAL=3
           ASETSZ=1.0
!
           N2=0
           DO I=1,N
              I2=I
              IF(D(I2).EQ.ISET3)THEN
                N2=N2+1
                Y2(N2)=Y(I2)
                X2(N2)=X(I2)
                X3D2(N2)=X3D(I2)
              ENDIF
           ENDDO
!
           IF(N2.GE.1)THEN
             ISET3T=IVAL
             CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                         D,XIDC,                                         &
                         ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                         ISTEP,ISUBST,ISET,ISET3T,ICH3PA,PBARBA,         &
                         IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                         IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                         IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                         ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                         NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                         IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
           ENDIF
        ENDDO
        GO TO 1900
!
      ELSEIF(ICASPL.EQ.'BUPL')THEN
!
!               *****************************************************
!               **  STEP 2.9--                                     **
!               **  TREAT THE BULLET PLOT     CASE.                **
!               *****************************************************
!
        ISTEPN='2.9'
        IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       FOR BULLET PLOT, DRAW TRACES 3 AND ABOVE FIRST, THEN
!       DO TRACES 1 AND 2.
!
        DO ISET=3,NUMSET
!
           ISTEP=1
           ISUBST=1
           ISET3=INT(XIDC(ISET)+0.1)
           ASETSZ=1.0
!
           N2=0
           DO I=1,N
              I2=I
              IF(D(I2).EQ.ISET3)THEN
                N2=N2+1
                Y2(N2)=Y(I2)
                X2(N2)=X(I2)
                X3D2(N2)=X3D(I2)
              ENDIF
           ENDDO
           PBARBA=X3D2(1)
!
           IF(N2.GE.1)THEN
             CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                         D,XIDC,                                         &
                         ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                         ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                         IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                         IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                         IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                         ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                         NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                         IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
           ENDIF
        ENDDO
!
        DO ISET=1,2
!
           ISTEP=1
           ISUBST=1
           ISET3=INT(XIDC(ISET)+0.1)
           ASETSZ=1.0
!
           N2=0
           DO I=1,N
              I2=I
              IF(D(I2).EQ.ISET3)THEN
                N2=N2+1
                Y2(N2)=Y(I2)
                X2(N2)=X(I2)
                X3D2(N2)=X3D(I2)
              ENDIF
           ENDDO
           PBARBA=0.0
!
           IF(N2.GE.1)THEN
             CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                         D,XIDC,                                         &
                         ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                         ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                         IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                         IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                         IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                         ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                         NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                         IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
           ENDIF
        ENDDO
        GO TO 1900
!
      ELSEIF(ICASPL.EQ.'VWBP')THEN
!
!               *****************************************************
!               **  STEP 2.9--                                     **
!               **  TREAT THE VARIABLE WIDTH BAR PLOT CASE         **
!               *****************************************************
!
        ISTEPN='2.9'
        IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        AWID=1.0
        DO ISET=1,NUMSET
!
           ISTEP=1
           ISUBST=1
           AVAL=XIDC(ISET)
!
           N2=0
           IVAL=1
           DO I=1,N
              I2=I
              IF(D(I2).EQ.AVAL)THEN
                N2=N2+1
                Y2(N2)=Y(I2)
                X2(N2)=X(I2)
                AWID=X3D(I2)
                IF(N2.EQ.1)IVAL=INT(DCOLOR(I2)+0.1)
              ENDIF
           ENDDO
!
           IF(N2.GE.1)THEN
             ISET3T=IVAL
             X3D2(ISET3T)=AWID
             CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                         D,XIDC,                                         &
                         ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                         ISTEP,ISUBST,ISET,ISET3T,ICH3PA,PBARBA,         &
                         IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                         IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                         IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                         ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                         NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                         IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
           ENDIF
        ENDDO
        GO TO 1900
!
      ELSEIF(ICASPL.EQ.'CSPL' .OR. ICASPL.EQ.'OCLH')THEN
!
!               *****************************************************
!               **  STEP 2.10--                                    **
!               **  TREAT THE CANDLESTICK PLOT     CASE.           **
!               *****************************************************
!
        ISTEPN='2.9'
        IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DISTIN(X3D,N,IWRITE,DFILL,NUMSETT,IBUGG4,IERROR)
!
        N2=0
        DO II=1,NUMSETT
!
          ISET=II
          HOLD=DFILL(ISET)
          ISTEP=1
          ISUBST=1
          ASETSZ=1.0
          DO JJ=1,NUMSET
!
            ISET3=JJ
            N2=0
            PBARBA=CPUMAX
            DO KK=1,N
               I2=KK
               IVAL=INT(D(I2)+0.1)
               IF(IVAL.EQ.ISET3 .AND. HOLD.EQ.X3D(I2))THEN
                 N2=N2+1
                 Y2(N2)=Y(I2)
                 X2(N2)=X(I2)
                 IF(Y2(N2).LE.PBARBA)PBARBA=Y2(N2)
              ENDIF
            ENDDO
!
            IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')THEN
              WRITE(ICOUT,2101)ISET,ISET3,IVAL,N2,HOLD,PBARBA
 2101         FORMAT('AT CSPL: ISET,ISET3,IVAL,N2,HOLD,PBARBA = ',4I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
              DO KK=1,N2
                 WRITE(ICOUT,2103)KK,Y2(KK),X2(KK)
 2103            FORMAT('KK,Y2(KK),X2(KK) = ',I8,2G15.7)
                 CALL DPWRST('XXX','BUG ')
              ENDDO
            ENDIF
!
            IF(N2.GE.2)THEN
              CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSETT,X3D2,  &
                          X3D,DFILL,                                      &
                          ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                          ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                          IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,IWRLES,      &
                          IDRTRS,ICLG2S,ICLGRS,                           &
                          IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                          ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                          NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                          IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
            ENDIF
          ENDDO
        ENDDO
!
        GO TO 1900
!
      ENDIF
!
!CCCC AUGUST 1992.  BUG IF NUMSET = 101, 201, (OR MAX TRACES + 1).
!CCCC GOES TO WRONG CASE, USES WRONG VALUE OF N AND GENERATES
!CCCC EXTRA MISCELLANEOUS LINES THAT ARE NOT DESIRED.  CHECK FOR
!CCCC CASE OF FIRST PASS.
      IF(IFIRST.EQ.'NO')THEN
        IF(N.LE.MXNPPC)GO TO 1300
        IF(N.GT.MXNPPC)GO TO 1400
      ENDIF
!CCCC END CHANGE
      IF(NUMSET.LE.1.AND.N.LE.MXNPPC)GO TO 1100
      IF(NUMSET.LE.1.AND.N.GT.MXNPPC)GO TO 1200
      IF(NUMSET.GT.1.AND.N.LE.MXNPPC)GO TO 1300
      IF(NUMSET.GT.1.AND.N.GT.MXNPPC)GO TO 1400
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1106)
 1106 FORMAT('***** INTERNAL ERROR IN PLOTGE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1107)
 1107 FORMAT('      4-WAY BRANCH UNDER STEP 2 NOT SATISFIED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1108)
 1108 FORMAT('      NUMSET,N,MXNPPC = ',3I8)
      CALL DPWRST('XXX','BUG ')
      IERRG4='YES'
      GO TO 9000
!
!               ********************************************************
!               **  STEP 2.1--                                        **
!               **  TREAT THE CASE WHERE                              **
!               **  THE NUMBER OF TRACES = 1 AND                      **
!               **  THE NUMBER OF PLOT POINTS DOES NOT EXCEED MXNPPC  **
!               ********************************************************
!
 1100 CONTINUE
!
      ISTEPN='2.1'
      IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISTEP=2
      ISUBST=1
      ISET=1
      ISET3=ISET
!
      IF(ICASPL.EQ.'TABC')THEN
        ISET3=INT(XIDC(1)+0.1)
      ENDIF
!
!CCCC THE FOLLOWING LINE WAS ADDED JULY 2011
!CCCC TO HAVE AN EXACT    IDENTIFIER => CHARACTER    MAPPING
      IF(ICHMAP.EQ.'EXAC')ISET3=INT(XIDC(1)+0.5)
!
      ICH3PA=ICHAPA(ISET3)
!
      IF(ICASPL.EQ.'IMAG' .OR. ICASPL.EQ.'IMA2')THEN
        DO I=1,N
          Y3(I)=DCOLOR(I)
          X3(I)=DFILL(I)
          Y4(I)=DSYMB(I)
          X4(I)=DSIZE(I)
        ENDDO
      ELSEIF(ICASPL.EQ.'RIPH')THEN
        DO I=1,N
          Y4(I)=DFILL(I)
        ENDDO
      ENDIF
      IF(ICAS3D.EQ.'OFF')THEN
        CALL PLOTG2(Y,X,Y3,X3,N,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D,   &
                    D,XIDC,                                     &
                    ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,  &
                    ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,      &
                    IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,         &
                    IWRLES,IDRTRS,ICLG2S,ICLGRS,                &
                    IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,     &
                    ASETSZ,ISETSY,ISETCL,ISETFI,                &
                    NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,         &
                    IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ELSEIF(ICAS3D.EQ.'ON')THEN
          CALL PLOTG3(X,X3D,Y,N,DSIZE,                        &
                      X3,Y3,Z3,X4,Y4,Z4,N4,X5,Y5,N5,NUMSET,   &
                      D,XIDC,                                 &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,     &
                      XDELMN,YDELMN,ZDELMN,                   &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,         &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,     &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,            &
                      ICAPSW,                                 &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM, &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
      ENDIF
!
      GO TO 1900
!
!               ************************************************
!               **  STEP 2.2--                                **
!               **  TREAT THE CASE WHERE                      **
!               **  THE NUMBER OF TRACES = 1 AND              **
!               **  THE NUMBER OF PLOT POINTS EXCEEDS MXNPPC  **
!               ************************************************
!
 1200 CONTINUE
!
      ISTEPN='2.2'
      IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISTEP=2
      ISUBST=2
      ISET=1
      ISET3=ISET
!
!CCCC THE FOLLOWING LINE WAS ADDED JULY 2011
!CCCC TO HAVE AN EXACT    IDENTIFIER => CHARACTER    MAPPING
      IF(ICHMAP.EQ.'EXAC')ISET3=INT(XIDC(1)+0.5)
!
      IF(ICASPL.EQ.'TABC')THEN
        ISET3=INT(XIDC(1)+0.1)
      ENDIF
!
      ICH3PA=ICHAPA(ISET3)
!
      NUMPAS=(N/MXNPPC)+1
      IF(N.EQ.MXNPPC)NUMPAS=1
!
      IMAX=1
      DO IPASS=1,NUMPAS
        IMIN=IMAX
        IMAX=IMIN+MXNPPC-1
        IF(IMAX.GT.N)IMAX=N
!
        N2=0
        DO I=IMIN,IMAX
          N2=N2+1
          Y2(N2)=Y(I)
          X2(N2)=X(I)
          X3D2(N2)=X3D(I)
          DSYMB(N2)=DSIZE(I)
          IF(ICASPL.EQ.'RIPH')Y4(N2)=DFILL(I)
        ENDDO
!
        IF(ICAS3D.EQ.'OFF')THEN
          CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                      D,XIDC,                                         &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                      ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                      NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ELSEIF(ICAS3D.EQ.'ON')THEN
          CALL PLOTG3(X2,X3D2,Y2,N2,DSYMB,                            &
                      X3,Y3,Z3,X4,Y4,Z4,N4,X5,Y5,N5,NUMSET,           &
                      D,XIDC,                                         &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,             &
                      XDELMN,YDELMN,ZDELMN,                           &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,                 &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                      ICAPSW,                                         &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ENDIF
      ENDDO
!
      GO TO 1900
!
!               ******************************************************
!               **  STEP 2.3--                                      **
!               **  TREAT THE CASE WHERE                            **
!               **  THERE ARE 2 OR MORE TRACES BUT THE TOTAL        **
!               **  NUMBER OF PLOT POINTS DOES NOT EXCEED MXNPPC    **
!               ******************************************************
!
 1300 CONTINUE
!
      ISTEPN='2.3'
      IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'OTGE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1310 ISET=1,NUMSET
!
        ISTEP=2
        ISUBST=3
        ISET3=ISET
!
        IF(ICASPL.EQ.'TABC')ISET3=INT(XIDC(ISET)+0.1)
        IF(ICASPL.EQ.'1352')ISET3=INT(XIDC(ISET)+0.1)
        IF(ICASPL.EQ.'ZSCC')ISET3=INT(XIDC(ISET)+0.1)
        IF(ICASPL.EQ.'JSCC')ISET3=INT(XIDC(ISET)+0.1)
        IF(ICASPL.EQ.'CPLO')THEN
           IVAL=INT(XIDC(ISET)+0.1)
           ISET3=IVAL
           IF(IVAL.GE.6)ISET3=6
        ENDIF
        IF(ICASPL.EQ.'CPLO' .OR. ICASPL.EQ.'CDPL')THEN
           IVAL=INT(XIDC(ISET)+0.1)
           ISET3=IVAL
           IF(IVAL.GE.6)ISET3=6
        ENDIF
!
!       NORMAL KERNEL DENSITY MIXTURE CASE: SETTINGS FOR TRACE 3 AND
!       TRACE 4 WILL REPEAT FOR ALL HIGHER VALUES OF ISET (I.E.,
!       TRACE 5 = TRACE 3, TRACE 6 = TRACE 4).
!
!
!       THIS WILL ALSO BE THE CASE FOR THE DUMBBELL PLOT
!
        IF(ICASPL.EQ.'NMPL' .OR. ICASPL.EQ.'DBPL')THEN
          IF(ISET.GT.4)THEN
            ISETZZ=MOD(ISET,2)
            IF(ISETZZ.EQ.1)THEN
              ISET3=3
            ELSE
              ISET3=4
            ENDIF
          ENDIF
        ENDIF
!
!
!CCCC   THE FOLLOWING LINE WAS ADDED DECEMBER 1994
!CCCC   TO HAVE AN EXACT    IDENTIFIER => CHARACTER    MAPPING
        IF(ICHMAP.EQ.'EXAC')ISET3=INT(XIDC(ISET)+0.5)
!
!CCCC   ICH3PA=ICHAPA(ISET3)
!
        ASETSZ=1.0
!
        JSET=INT(XIDC(ISET)+0.5)
!CCCC   NOVEMBER 1993.  COMMENT OUT FOLLOWING LINE
!CCCC   PIE CHART MODIFED TO HANDLE ATTRIBUTE SETTINGS.
!CCCC   IF(ICASPL.EQ.'PIEC')ISET3=1
!CCCC   AUGUST 1992.  FOLLOWING LINE ADDED FOR VECTOR PLOT
        IF(ICASPL.EQ.'VECT')ISET3=1
        IFACT=20
        IF(IFENSW.EQ.'ON')IFACT=24
!CCCC   FEBRUARY 2003: VIOLIN PLOT
        IF(ICASPL.EQ.'VIPL')IFACT=IFACT+1
        IF(ICASPL.EQ.'MDBP' .AND. IBXPDI.EQ.'ON')THEN
          IFACT=IFACT+6
        ELSEIF(ICASPL.EQ.'MEBP' .AND. IBXPDI.EQ.'ON')THEN
          IFACT=IFACT+6
        ENDIF
        IF(ICASPL.EQ.'MDBP')ISET3=JSET-IFACT*((JSET-1)/IFACT)
        IF(ICASPL.EQ.'MEBP')ISET3=JSET-IFACT*((JSET-1)/IFACT)
!
        IF(ICASPL.EQ.'MEIP' .OR. ICASPL.EQ.'MRIP' .OR.   &
           ICASPL.EQ.'MDIP' .OR. ICASPL.EQ.'MMIP' .OR.   &
           ICASPL.EQ.'1SE ' .OR. ICASPL.EQ.'2SE ' .OR.   &
           ICASPL.EQ.'1SD ' .OR. ICASPL.EQ.'2SD ' .OR.   &
           ICASPL.EQ.'MDCL' .OR. ICASPL.EQ.'MECL' .OR.   &
           ICASPL.EQ.'QUCL' .OR. ICASPL.EQ.'TMCL' .OR.   &
           ICASPL.EQ.'NTOL' .OR. ICASPL.EQ.'NPRE' .OR.   &
           ICASPL.EQ.'TMIP' .OR. ICASPL.EQ.'BWIP' .OR.   &
           ICASPL.EQ.'AGCL' .OR. ICASPL.EQ.'CVCL' .OR.   &
           ICASPL.EQ.'CDCL' .OR. ICASPL.EQ.'CQCL' .OR.   &
           ICASPL.EQ.'CRCL' .OR.   &
           ICASPL.EQ.'DPRO' .OR. ICASPL.EQ.'DMEA' .OR.   &
           ICASPL.EQ.'BWCL' .OR. ICASPL.EQ.'SDCL')THEN
          IF(NREPI1.EQ.0 .OR. NREPI2.EQ.0)THEN
            ISET3=JSET-5*((JSET-1)/5)
          ELSE
            NREPZZ=5*NREPI1
            IF(JSET.LE.NREPZZ)THEN
              ISET3=JSET-5*((JSET-1)/5)
            ELSE
              ISET32=JSET/NREPZZ
              ISET31=MOD(JSET,NREPZZ)
              IF(ISET31.EQ.0)THEN
                ISET31=NREPZZ
                ISET32=ISET32-1
              ENDIF
              ISET3=ISET31-5*((ISET31-1)/5)
              ISET3=5*ISET32 + ISET3
            ENDIF
          ENDIF
        ENDIF
!
        IF(ICASPL.EQ.'ERBA')ISET3=JSET-7*((JSET-1)/7)
        IF(ICASPL.EQ.'VIPL')ISET3=JSET-IFACT*((JSET-1)/IFACT)
!CCCC   AUGUST 2001.  ADD FOLLOWING LINE FOR CONSENSUS MEAN PLOT
!CCCC   IF(ICASPL.EQ.'CMPL')ISET3=JSET-5*((JSET-1)/5)
        IF(ICASPL.EQ.'CMPL')THEN
          ISET3=JSET-2*((JSET-1)/2)
          IF(JSET.LE.100)THEN
            ISET3=JSET
          ELSE
            ISET3=MOD(JSET-1,100) + 2
          ENDIF
        ENDIF
!CCCC   THE FOLLOWING 2 LINES WERE ADDED FOR DES. OF EXP. PLOTS MAY 1989
        IF(ICASPL.EQ.'DEXP'.AND.JSET.NE.NUMSET)ISET3=1
        IF(ICASPL.EQ.'DEXP'.AND.JSET.EQ.NUMSET)ISET3=2
!CCCC   THE FOLLOWING LINE WAS ADDED FOR BLOCK PLOTS  JUNE 1992 (JJF)
!CCCC   THE FOLLOWING LINE WAS ADDED FOR BLOCK PLOT   JUNE 1995
!CCCC   VERTEX JUNK CHARACTER PROBLEM                 JUNE 1995
        IF(ICASPL.EQ.'BLPL')THEN
          IF(IFIRST.EQ.'NO')THEN
            ISET3=JSET
            IF(JSET.GE.100)ISET3=100
          ELSE
            ISET3=JSET
            IF(JSET.GE.100)ISET3=100
           ICH3PA=ICHAPA(ISET3)
          ENDIF
          IF(ISET3.LE.100)THEN
            ICH3PA=ICHAPA(ISET3)
          ENDIF
!CCCC   ENDIF
!
!       NOTE 2012/07: RECODE THIS SECTION A BIT FOR THE CASE
!                     WHEN THERE ARE > 100 CHARACTER TRACES.
!
!                     PARALLEL COORDINATES PLOT IS HANDLED
!                     SEPARATELY.  OTHERWISE, INSTEAD OF PRINTING
!                     ERROR, RESTART THE TRACE COUNTER TO 1.
!                     HOWEVER, ALLOW AN OFFSET (ICHARO) (I.E.,
!                     INSTEAD OF STARTING WITH SETTING 1, START
!                     WITH SETTING ICHARO).
!
!CCCC   IF(ICASPL.EQ.'PCPL'.OR.ICASPL.EQ.'PCPG')THEN
        ELSEIF(ICASPL.EQ.'PCPL'.OR.ICASPL.EQ.'PCPG')THEN
           ISET3=MOD(JSET-1,100)+1
        ELSEIF(ISET3.LE.100)THEN
           ICH3PA=ICHAPA(ISET3)
        ELSE
           IF(ICHARO.LT.0 .OR. ICHARO.GE.100)THEN
             ISET3=JSET
           ELSEIF(ICHARO.EQ.0)THEN
             ISET3=MOD(JSET-1,100)+1
           ELSE
             IF(JSET.LE.100)THEN
               ISET3=JSET
             ELSE
               JSETT=JSET-ICHARO
               IJUNK1=100 - ICHARO
               ISET3=MOD(JSETT-1,IJUNK1)+1
             ENDIF
           ENDIF
        ENDIF
!
        IF(ISET3.GT.100)THEN
           WRITE(ICOUT,1311)
 1311      FORMAT('***** ERROR IN PLOTGE AT STEP 2.3--')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1312)
 1312      FORMAT('      AN ATTEMPT WAS MADE TO REFERENCE')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1313)ISET3
 1313      FORMAT('      ELEMENT ',I8,' OF THE DATAPLOT INTERNAL')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1314)
 1314      FORMAT('      TRACE CHARACTER ARRAY.  THIS IS ILLEGAL.')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1315)
 1315      FORMAT('      THE MAX NUMBER OF TRACE CHARACTERS THAT CAN')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1316)
 1316      FORMAT('      BE SET IS 100')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1317)
 1317      FORMAT('      POSSIBLE CURE--HAS THE ANALYST CHANGED THE')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1318)
 1318      FORMAT('         CHARACTER MAPPING EXACT    COMMAND TO THE')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1319)
 1319      FORMAT('         CHARACTER MAPPING RANK       COMMAND?')
           CALL DPWRST('XXX','BUG ')
           IERRG4='YES'
           GO TO 9000
        ENDIF
!
        N2=0
!CCCC   AUGUST 1992.  HANDLE VECTOR PLOT WITH VARIABLE SIZE ARROW
!CCCC   SEPARATELY.
        IF(ICASPL.EQ.'VVAR')THEN
          DO I=1,N
            I2=I
            IF(D(I2).EQ.XIDC(ISET))THEN
              N2=N2+1
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
              DSYMB(N2)=DSIZE(I2)
            ENDIF
          ENDDO
!
        ELSEIF(ICASPL.EQ.'PCPG')THEN
          DO I=1,N
            I2=I
            IF(D(I2).EQ.XIDC(ISET))THEN
              N2=N2+1
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
              DSYMB(N2)=DSIZE(I2)
              ISET3=INT(DFILL(I2))
            ENDIF
          ENDDO
        ELSEIF(ICASPL.EQ.'ASSO' .OR. ICASPL.EQ.'SIEV' .OR.   &
               ICASPL.EQ.'FLUC' .OR. ICASPL.EQ.'TABU' .OR.   &
               ICASPL.EQ.'FLCP' .OR. ICASPL.EQ.'DFIT')THEN
          DO I=1,N
            I2=I
            IF(D(I2).EQ.XIDC(ISET))THEN
              N2=N2+1
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
              DSYMB(N2)=DSIZE(I2)
              ISETCL=INT(DCOLOR(I2)+0.5)
              IF(ICASPL.EQ.'SIEV')THEN
                ISETFI=INT(DFILL(I2)+0.5)
              ENDIF
            ENDIF
          ENDDO
        ELSEIF(ICASPL.EQ.'LPLO')THEN
          DO I=1,N
            I2=I
            IF(D(I2).EQ.XIDC(ISET))THEN
              N2=N2+1
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
              ISETCL=INT(DCOLOR(I2)+0.5)
              ISETFI=INT(DFILL(I2)+0.5)
            ENDIF
          ENDDO
        ELSE
          DO I=1,N
            I2=I
            IF(D(I2).EQ.XIDC(ISET))THEN
              N2=N2+1
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
              DSYMB(N2)=DSIZE(I2)
              IF(ICASPL.EQ.'RIPH')Y4(N2)=DFILL(I2)
            ENDIF
          ENDDO
        ENDIF
!
        IF(ICASPL.EQ.'MDBP' .OR. ICASPL.EQ.'MEBP')THEN
!CCCC     THE FOLLOWING 5 LINES WERE INSERTED BY ALAN.  FEBRUARY 1989
          IF(IHORSW.EQ.'OFF')THEN
            IF(ISET3.EQ.20)YSAVE=Y2(1)
            IF(ISET3.GT.20.AND.N2.EQ.1.AND.Y2(1).EQ.YSAVE)ICH3PA='BLAN'
          ELSE
            IF(ISET3.EQ.20)YSAVE=X2(1)
            IF(ISET3.GT.20.AND.N2.EQ.1.AND.X2(1).EQ.YSAVE)ICH3PA='BLAN'
          ENDIF
        ELSEIF(ICASPL.EQ.'VIPL')THEN
          IF(IHORSW.EQ.'OFF')THEN
            IF(ISET3.EQ.21)YSAVE=Y2(1)
            IF(ISET3.GT.21.AND.N2.EQ.1.AND.Y2(1).EQ.YSAVE)ICH3PA='BLAN'
          ELSE
            IF(ISET3.EQ.21)YSAVE=X2(1)
            IF(ISET3.GT.21.AND.N2.EQ.1.AND.X2(1).EQ.YSAVE)ICH3PA='BLAN'
          ENDIF
        ENDIF
!
        IF(IBUGG4.EQ.'ON')THEN
          WRITE(ICOUT,1361)N2,ISORSW,ICASPL,ICAS3D,I3DPRO,ICH3PA
 1361     FORMAT('N2,ISORSW,ICASPL,ICAS3D,I3DPRO,ICH3PA = ',I8,5(2X,A4))
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ICAS3D.EQ.'OFF')THEN
          CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                      D,XIDC,                                         &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                      ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                      NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ELSEIF(ICAS3D.EQ.'ON')THEN
          CALL PLOTG3(X2,X3D2,Y2,N2,DSYMB,                            &
                      X3,Y3,Z3,X4,Y4,Z4,N4,X5,Y5,N5,NUMSET,           &
                      D,XIDC,                                         &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,             &
                      XDELMN,YDELMN,ZDELMN,                           &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,                 &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                      ICAPSW,                                         &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ENDIF
!
 1310 CONTINUE
!
      GO TO 1900
!
!               *************************************************
!               **  STEP 2.4--                                 **
!               **  TREAT THE CASE WHERE                       **
!               **  THERE ARE 2 OR MORE TRACES AND             **
!               **  THE TOTAL NUMBER OF POINTS EXCEEDS MXNPPC  **
!               *************************************************
!
 1400 CONTINUE
!
      ISTEPN='2.4'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1410 ISET=1,NUMSET
!
        ISTEP=2
        ISUBST=4
        ISET3=ISET
!CCCC   THE FOLLOWING LINE WAS ADDED DECEMBER 1994
!CCCC   TO HAVE AN EXACT    IDENTIFIER => CHARACTER    MAPPING
        IF(ICHMAP.EQ.'EXAC')ISET3=INT(XIDC(ISET)+0.1)
        IF(ICASPL.EQ.'TABC')ISET3=INT(XIDC(ISET)+0.1)
        IF(ICASPL.EQ.'1352')ISET3=INT(XIDC(ISET)+0.1)
        IF(ICASPL.EQ.'ZSCC')ISET3=INT(XIDC(ISET)+0.1)
        IF(ICASPL.EQ.'JSCC')ISET3=INT(XIDC(ISET)+0.1)
!
!       NORMAL KERNEL DENSITY MIXTURE CASE: SETTINGS FOR TRACE 3 AND
!       TRACE 4 WILL REPEAT FOR ALL HIGHER VALUES OF ISET (I.E.,
!       TRACE 5 = TRACE 3, TRACE 6 = TRACE 4).
!
        IF(ICASPL.EQ.'NMPL')THEN
          IF(ISET.GT.4)THEN
            ISETZZ=MOD(ISET,2)
            IF(ISETZZ.EQ.1)THEN
              ISET3=3
            ELSE
              ISET3=4
            ENDIF
          ENDIF
        ENDIF
!
!CCCC   ICH3PA=ICHAPA(ISET3)
!
        ASETSZ=1.0
!
        JSET=INT(XIDC(ISET)+0.5)
!CCCC   NOVEMBER 1993.  COMMENT OUT FOLLOWING LINE
!CCCC   PIE CHART MODIFED TO HANDLE ATTRIBUTE SETTINGS.
!CCCC   IF(ICASPL.EQ.'PIEC')ISET3=1
!CCCC   AUGUST 1992.  FOLLOWING LINE ADDED FOR VECTOR PLOT
        IF(ICASPL.EQ.'VECT')ISET3=1
        IFACT=20
        IF(IFENSW.EQ.'ON')IFACT=24
        IF(ICASPL.EQ.'VIPL')IFACT=IFACT+1
        IF(ICASPL.EQ.'MDBP' .AND. IBXPDI.EQ.'ON')THEN
          IFACT=IFACT+6
        ELSEIF(ICASPL.EQ.'MEBP' .AND. IBXPDI.EQ.'ON')THEN
          IFACT=IFACT+6
        ENDIF
        IF(ICASPL.EQ.'MDBP')ISET3=JSET-IFACT*((JSET-1)/IFACT)
        IF(ICASPL.EQ.'MEBP')ISET3=JSET-IFACT*((JSET-1)/IFACT)
!
        IF(ICASPL.EQ.'MEIP' .OR. ICASPL.EQ.'MRIP' .OR.   &
           ICASPL.EQ.'MDIP' .OR. ICASPL.EQ.'MMIP' .OR.   &
           ICASPL.EQ.'1SE ' .OR. ICASPL.EQ.'2SE ' .OR.   &
           ICASPL.EQ.'1SD ' .OR. ICASPL.EQ.'2SD ' .OR.   &
           ICASPL.EQ.'MDCL' .OR. ICASPL.EQ.'MECL' .OR.   &
           ICASPL.EQ.'QUCL' .OR. ICASPL.EQ.'TMCL' .OR.   &
           ICASPL.EQ.'NTOL' .OR. ICASPL.EQ.'NPRE' .OR.   &
           ICASPL.EQ.'TMIP' .OR. ICASPL.EQ.'BWIP' .OR.   &
           ICASPL.EQ.'AGCL' .OR. ICASPL.EQ.'CVCL' .OR.   &
           ICASPL.EQ.'CDCL' .OR. ICASPL.EQ.'CQCL' .OR.   &
           ICASPL.EQ.'CRCL' .OR.   &
           ICASPL.EQ.'DPRO' .OR. ICASPL.EQ.'DMEA' .OR.   &
           ICASPL.EQ.'BWCL' .OR. ICASPL.EQ.'SDCL')THEN
          IF(NREPI1.EQ.0)THEN
            ISET3=JSET-5*((JSET-1)/5)
          ELSE
            NREPZZ=5*NREPI1
            IF(JSET.LE.NREPZZ)THEN
              ISET3=JSET-5*((JSET-1)/5)
            ELSE
              ISET32=JSET/NREPZZ
              ISET31=MOD(JSET,NREPZZ)
              IF(ISET31.EQ.0)THEN
                ISET31=NREPZZ
                ISET32=ISET32-1
              ENDIF
              ISET3=ISET31-5*((ISET31-1)/5)
              ISET3=5*ISET32 + ISET3
            ENDIF
          ENDIF
        ENDIF
!
        IF(ICASPL.EQ.'ERBA')ISET3=JSET-7*((JSET-1)/7)
        IF(ICASPL.EQ.'VIPL')ISET3=JSET-IFACT*((JSET-1)/IFACT)
!CCCC   AUGUST 2001.  ADD FOLLOWING LINE FOR CONSENSUS MEAN PLOT
!CCCC   IF(ICASPL.EQ.'CMPL')ISET3=JSET-5*((JSET-1)/5)
        IF(ICASPL.EQ.'CMPL')THEN
          ISET3=JSET-2*((JSET-1)/2)
          IF(JSET.LE.100)THEN
            ISET3=JSET
          ELSE
            ISET3=MOD(JSET-1,100) + 2
          ENDIF
        ENDIF
!CCCC   THE FOLLOWING 2 LINES WERE ADDED FOR DES. OF EXP. PLOTS MAY 1989
        IF(ICASPL.EQ.'DEXP'.AND.JSET.NE.NUMSET)ISET3=1
        IF(ICASPL.EQ.'DEXP'.AND.JSET.EQ.NUMSET)ISET3=2
!CCCC   THE FOLLOWING LINE WAS ADDED FOR BLOCK PLOTS  JUNE 1992 (JJF)
!CCCC   THE FOLLOWING LINE WAS ADDED FOR BLOCK PLOT   JUNE 1995
!CCCC   VERTEX JUNK CHARACTER PROBLEM                 JUNE 1995
        IF(ICASPL.EQ.'BLPL')THEN
          IF(IFIRST.EQ.'NO')THEN
            ISET3=JSET
            IF(JSET.GE.100)ISET3=100
          ELSE
            ISET3=JSET
            IF(JSET.GE.100)ISET3=100
          ENDIF
          IF(ISET3.LE.100)THEN
            ICH3PA=ICHAPA(ISET3)
          ENDIF
!CCCC   ENDIF
!
!CCCC   THE FOLLOWING SECTION WAS ADDED    DECEMBER 1994
!CCCC   ICH3PA=ICHAPA(ISET3)
!CCCC   IF(ISET3.LE.100)THEN
!CCCC     ICH3PA=ICHAPA(ISET3)
!CCCC   ENDIF
!
!       NOTE 2012/07: RECODE THIS SECTION A BIT FOR THE CASE
!                     WHEN THERE ARE > 100 CHARACTER TRACES.
!
!                     PARALLEL COORDINATES PLOT IS HANDLED
!                     SEPARATELY.  OTHERWISE, INSTEAD OF PRINTING
!                     ERROR, RESTART THE TRACE COUNTER TO 1.
!                     HOWEVER, ALLOW AN OFFSET (ICHARO) (I.E.,
!                     INSTEAD OF STARTING WITH SETTING 1, START
!                     WITH SETTING ICHARO).
!
!CCCC   IF(ICASPL.EQ.'PCPL'.OR.ICASPL.EQ.'PCPG')THEN
        ELSEIF(ICASPL.EQ.'PCPL'.OR.ICASPL.EQ.'PCPG')THEN
           ISET3=MOD(JSET-1,100)+1
        ELSEIF(ISET3.LE.100)THEN
           ICH3PA=ICHAPA(ISET3)
        ELSE
           IF(ICHARO.LT.0 .OR. ICHARO.GE.100)THEN
             ISET3=JSET
           ELSEIF(ICHARO.EQ.0)THEN
             ISET3=MOD(JSET-1,100)+1
           ELSE
             IF(JSET.LE.100)THEN
               ISET3=JSET
             ELSE
               JSETT=JSET-ICHARO
               IJUNK1=100 - ICHARO
               ISET3=MOD(JSETT-1,IJUNK1)+1
             ENDIF
           ENDIF
        ENDIF
!
        IF(ISET3.GT.100)THEN
           WRITE(ICOUT,1411)
 1411      FORMAT('***** ERROR IN PLOTGE AT STEP 2.4--')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1412)
 1412      FORMAT('      AN ATTEMPT WAS MADE TO REFERENCE')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1413)ISET3
 1413      FORMAT('      ELEMENT ',I8,' OF THE DATAPLOT INTERNAL')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1414)
 1414      FORMAT('      TRACE CHARACTER ARRAY.  THIS IS ILLEGAL.')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1415)
 1415      FORMAT('      THE MAX NUMBER OF TRACE CHARACTERS THAT CAN')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1416)
 1416      FORMAT('      BE SET IS 100')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1417)
 1417      FORMAT('      POSSIBLE CURE--HAS THE ANALYST CHANGED THE')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1418)
 1418      FORMAT('         CHARACTER MAPPING EXACT    COMMAND TO THE')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1419)
 1419      FORMAT('         CHARACTER MAPPING RANK       COMMAND?')
           CALL DPWRST('XXX','BUG ')
           IERRG4='YES'
           GO TO 9000
        ENDIF
!
        IMIN=1
 1420   CONTINUE
        IMORE='NO'
!
        N2=0
!CCCC   AUGUST 1992.  HANDLE VECTOR PLOT WITH VARIABLE SIZE ARROW
!CCCC   SEPARATELY
        IF(ICASPL.EQ.'VVAR')THEN
          DO 1490 I=IMIN,N
            I2=I
            ASETSZ=DSIZE(I2)
            IF(D(I2).EQ.XIDC(ISET))THEN
              N2=N2+1
              IF(N2.GE.MXNPPC)THEN
                IMIN=I2
                IMORE='YES'
                GO TO 1499
              ENDIF
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
              DSYMB(N2)=DSIZE(I2)
            ENDIF
 1490     CONTINUE
 1499     CONTINUE
        ELSE
          DO 1430 I=IMIN,N
            I2=I
            IF(D(I2).EQ.XIDC(ISET))THEN
              N2=N2+1
              IF(N2.GE.MXNPPC)THEN
                IMIN=I2
                IMORE='YES'
                GO TO 1439
              ENDIF
              Y2(N2)=Y(I2)
              X2(N2)=X(I2)
              X3D2(N2)=X3D(I2)
              IF(ICASPL.EQ.'ASSO' .OR. ICASPL.EQ.'SIEV' .OR.   &
                 ICASPL.EQ.'FLUC' .OR. ICASPL.EQ.'TABU' .OR.   &
                 ICASPL.EQ.'FLCP' .OR. ICASPL.EQ.'DFIT')THEN
                ISETCL=INT(DCOLOR(I2)+0.5)
              ENDIF
            ENDIF
 1430     CONTINUE
 1439     CONTINUE
        ENDIF
!
        IF(ICASPL.EQ.'MDBP' .OR. ICASPL.EQ.'MEBP')THEN
!CCCC     THE FOLLOWING 5 LINES WERE INSERTED BY ALAN.  FEBRUARY 1989
          IF(IHORSW.EQ.'OFF')THEN
            IF(ISET3.EQ.20)YSAVE=Y2(1)
            IF(ISET3.GT.20.AND.N2.EQ.1.AND.Y2(1).EQ.YSAVE)ICH3PA='BLAN'
          ELSE
            IF(ISET3.EQ.20)YSAVE=X2(1)
            IF(ISET3.GT.20.AND.N2.EQ.1.AND.X2(1).EQ.YSAVE)ICH3PA='BLAN'
          ENDIF
        ELSEIF(ICASPL.EQ.'VIPL')THEN
          IF(IHORSW.EQ.'OFF')THEN
            IF(ISET3.EQ.21)YSAVE=Y2(1)
            IF(ISET3.GT.21.AND.N2.EQ.1.AND.Y2(1).EQ.YSAVE)ICH3PA='BLAN'
          ELSE
            IF(ISET3.EQ.21)YSAVE=X2(1)
            IF(ISET3.GT.21.AND.N2.EQ.1.AND.X2(1).EQ.YSAVE)ICH3PA='BLAN'
          ENDIF
        ENDIF
!
        IF(IBUGG4.EQ.'ON')THEN
          WRITE(ICOUT,1461)N,NUMSET,ISET,JSET,ISET3,N2,YSAVE
 1461     FORMAT('N,NUMSET,ISET,JSET,ISET3,N2,YSAVE = ',6I8,E15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1462)N2,ISORSW,ICASPL,ICAS3D,I3DPRO,ICH3PA
 1462     FORMAT('N2,ISORSW,ICASPL,ICAS3D,I3DPRO,ICH3PA=',I8,5(2X,A4))
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ICAS3D.EQ.'OFF')THEN
          CALL PLOTG2(Y2,X2,Y3,X3,N2,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D2,   &
                      D,XIDC,                                         &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,      &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,          &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                      ASETSZ,ISETSY,ISETCL,ISETFI,                    &
                      NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,             &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ELSEIF(ICAS3D.EQ.'ON')THEN
          CALL PLOTG3(X2,X3D2,Y2,N2,DSYMB,                            &
                      X3,Y3,Z3,X4,Y4,Z4,N4,X5,Y5,N5,NUMSET,           &
                      D,XIDC,                                         &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,             &
                      XDELMN,YDELMN,ZDELMN,                           &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,                 &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,             &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,                    &
                      ICAPSW,                                         &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,         &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ENDIF
!
        IF(IMORE.EQ.'YES')GO TO 1420
!
 1410 CONTINUE
!
      GO TO 1900
!
 1900 CONTINUE
!
!               ************************************************
!               **  STEP 3--                                  **
!               **  CARRY OUT POST-PLOT ACTIVITIES--          **
!               **  GENERATE THE FRAME, TITLE, LABELS, ETC.   **
!               **  FINISH UP DETAILS FOR THE PLOT            **
!               **  (E.G., MAKING HARDCOPIES IF CALLED FOR).  **
!               ************************************************
!
      IF(ILAST.EQ.'YES')THEN
!
        ISTEPN='3'
        IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IOPGRS='OFF'
        IOPG2S='OFF'
        IDELIS='OFF'
        IF(IGRDOR.EQ.'BEFO')THEN
          IDRFRS='OFF'
        ELSE
          IDRFRS='ON'
        ENDIF
        IWRLAS='ON'
        IWRLES='ON'
        IDRTRS='OFF'
        ICLG2S='ON'
        ICLGRS='ON'
!
        ISTEP=3
        ISUBST=1
        ISET=1
        ISET3=ISET
        ICH3PA=ICHAPA(ISET3)
!
      IF(ICAS3D.EQ.'OFF')THEN
        CALL PLOTG2(Y,X,Y2,X2,N,Y4,X4,N4,Y5,X5,N5,NUMSET,X3D,    &
                    D,XIDC,                                      &
                    ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,   &
                    ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,       &
                    IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,          &
                    IWRLES,IDRTRS,ICLG2S,ICLGRS,                 &
                    IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,      &
                    ASETSZ,ISETSY,ISETCL,ISETFI,                 &
                    NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,          &
                    IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ELSEIF(ICAS3D.EQ.'ON')THEN
          CALL PLOTG3(X,X3D,Y,N,DSIZE,                           &
                      X2,Y2,Z2,X4,Y4,Z4,N4,X5,Y5,N5,NUMSET,      &
                      D,XIDC,                                    &
                      ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,        &
                      XDELMN,YDELMN,ZDELMN,                      &
                      ISTEP,ISUBST,ISET,ISET3,ICH3PA,            &
                      IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,        &
                      IWRLES,IDRTRS,ICLG2S,ICLGRS,               &
                      ICAPSW,                                    &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,   &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!CCCC ADD FOLLOWING SECTION FOR DUANE PLOTS.   MAY 1998.
      IF(ICASPL.EQ.'DUAN')THEN
        IX1TSC=IX1TMP
        IX2TSC=IX2TMP
        IY1TSC=IY1TMP
        IY2TSC=IY2TMP
      ENDIF
!
!CCCC ADD FOLLOWING SECTION FOR RLP PLOTS.   FEBRUARY 2012.
      IF(ICASPL.EQ.'RLP')THEN
        ISUBNU=ISUBNU-1
        ISUBSW(ISUBNU)='OFF'
        ASUBXL(ISUBNU)=CPUMIN
        ASUBXU(ISUBNU)=CPUMIN
        ASUBYL(ISUBNU)=CPUMIN
        ASUBYU(ISUBNU)=CPUMIN
      ENDIF
!
      IERROR=IERRG4
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTGE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF PLOTGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)N,NUMSET,YSAVE,XDELMN
 9012   FORMAT('N,NUMSET,YSAVE,XDELMN = ',2I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)ICASPL,ICAS3D,I3DPRO,ISQUARE
 9013   FORMAT('ICASPL,ICAS3D,I3DPRO,I3DPRO,ISQUARE = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PLOTGE
      SUBROUTINE PLOTG2(Y,X,PY,PX,NP,PY2,PX2,NP2,PY3,PX3,NP3,NUMSET,X3D,   &
                        D,XIDC,                                            &
                        ICASPL,ICAS3D,ISQUAR,IVGMSW,IHGMSW,XDELMN,         &
                        ISTEP,ISUBST,ISET,ISET3,ICH3PA,PBARBA,             &
                        IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,IWRLES,         &
                        IDRTRS,ICLG2S,ICLGRS,                              &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,            &
                        ASETSZ,ISETSY,ISETCL,ISETFI,                       &
                        NUMSBR,ICAPSW,IDEVO3,IDV2SP,IGRDOR,                &
                        IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
!
!     PURPOSE--GENERATE A COMPLETE 2-D PLOT OF A SINGLE TRACE OF Y VERSUS X
!              (INCLUDING FRAME, TICS, LEGENDS, ETC.)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED         --SEPTEMBER 1988. BIHISTOGRAM
!     UPDATED         --FEBRUARY  1989. HORIZONTAL PLOT SWITCH (ALAN)
!     UPDATED         --FEBRUARY  1989. DEVICE POWER (ALAN)
!     UPDATED         --APRIL     1989. ANIMATION
!     UPDATED         --MAY       1989. HAZARD PLOT
!     UPDATED         --MARCH     1990. X11 PATCH
!     UPDATED         --APRIL     1992. ISET3,ISET3S TO ISET,ISET3
!     UPDATED         --MAY       1992. AUTO CLOSE/OPEN OF DEVICE 3 (JJF)
!     UPDATED         --MAY       1992. DEBUG STATEMENTS
!     UPDATED         --MAY       1992. IBUGXX, ISUBXX, IERRXX
!     UPDATED         --MAY       1992. BUG FOR MAXDEV
!     UPDATED         --AUGUS T   1992. SHADOW FOR BOX
!     UPDATED         --AUGUST    1992. UPDATE FOR SYMBOL PLOT
!     UPDATED         --OCTOBER   1993. UPDATE FOR REGION BASE INTER
!     UPDATED         --FEBRUARY  1994. VECTOR PLOT = PRE-ERASE OFF
!     UPDATED         --MARCH     1994. REGION BASE INTERPOLATE
!     UPDATED         --AUGUST    1995  ARGUMENT LIST TO DPWRLE
!     UPDATED         --JULY      1996  DEVICE FONT
!     UPDATED         --OCTOBER   1996. QWIN PATCH
!     UPDATED         --APRIL     1997. SUPPORT FOR AUTOMATICALLY
!                                       SAVING X11 PIXMAPS
!     UPDATED         --DECEMBER  1997. GENERALIZE PIXMAPS TO OTHER
!                                       DEVICE
!     UPDATED         --NOVEMBER  1999. ARGUMENT TO DPWRLA
!     UPDATED         --DECEMBER  1999. IMPLEMENT SUBREGIONS
!     UPDATED         --DECEMBER  1999. CROSS TABULATE, DEX CONTOUR
!                                       PLOTS AUTOMATICALLY SET CHAR 1
!                                       TO ZVAL
!     UPDATED         --JANUARY   2000. ADD X3D TO ARGUMENT LIST, PASS
!                                       TO DPDRCH
!     UPDATED         --FEBRUARY  2003. SET PRE-SORT OFF FOR VIOLIN
!                                       PLOT
!     UPDATED         --MARCH     2003. SET PRE-SORT OFF FOR PARALLEL
!                                       COORDINATES PLOT
!     UPDATED         --MAY       2003. GROUP PARALLEL COORD PLOT
!                                       HANDLES "TRACES" DIFFERENTLY
!     UPDATED         --FEBRUARY  2006. FOR DEVICE 1 LATEX, IF
!                                       CAPTURE SWITCH ON, SEND OUTPUT
!                                       TO CAPTURE FILE RATHER THAN
!                                       THE SCREEN
!     UPDATED         --APRIL     2007. PRE-SORT OFF FOR BIVARIATE
!                                       NORMAL TOLERANCE REGION PLOT
!     UPDATED         --JUNE      2007. ASSOCIATION PLOT
!     UPDATED         --JUNE      2007. SIEVE PLOT
!     UPDATED         --MARCH     2008. LEVEL PLOT
!     UPDATED         --MARCH     2008. IMAGE PLOT
!     UPDATED         --MAY       2008. FLUCTUATION PLOT
!     UPDATED         --SEPTEMBER 2009. TABULATION PLOT
!     UPDATED         --JANUARY   2010. CALL LIST TO DPDRBA FOR
!                                       UNEQUI-SPACED HISTOGRAM
!     UPDATED         --APRIL     2010. CONTOUR VERSION OF FLUCTUATION
!                                       PLOT
!     UPDATED         --JUNE      2010. "CHARACTER" VERSION OF
!                                        TABULATION PLOT
!     UPDATED         --AUGUST    2010. UPDATE CHARACTER TABULATION
!                                       PLOT FOR CASE WITH
!                                       ROW/COLUMN MIN/MAX
!     UPDATED         --DECEMBER  2010. PRE-SORT OFF FOR
!                                       HOMOSCEDASTICITY PLOT
!     UPDATED         --NOVEMBER  2015. ADD IDEVO3 TO CALL LIST.
!                                       THIS ADDS OPTION FOR HOW
!                                       DEVICE 3 IS HANDLED.
!     UPDATED         --DECEMBER  2015. ADD IDV2SP TO CALL LIST.
!                                       THIS ADDS OPTION FOR HOW
!                                       DEVICE 2 IS HANDLED.
!     UPDATED         --FEBRUARY  2017. PRE-SORT OFF FOR EMPIRICAL
!                                       QUANTILE PLOT
!     UPDATED         --JULY      2017. BLAND ALTMAN AND NORMAL KERNEL
!                                       DENSITY MIXTURE PRE-SORT OFF
!     UPDATED         --JANUARY   2018. ADD CHARATER UNITS AND LINE
!                                       UNITS TO DPDRCH AND DPDRLI
!     UPDATED         --JANUARY   2018. CALL LIST TO DPDELI
!     UPDATED         --OCTOBER   2018. LABEL COORDINATES
!     UPDATED         --DECEMBER  2018. SUPPORT FOR "DEVICE ... SCALE"
!                                       COMMAND
!     UPDATED         --MARCH     2021. SUPPORT FOR "GRID ORDER"
!     UPDATED         --MAY       2022. SUPPORT FOR "DEVICE ...
!                                       HARDWARE CHARACTER OFFSET"
!     UPDATED         --JUNE      2025. TWEAKS FOR WATERFALL CHART
!     UPDATED         --JUNE      2025. TWEAKS FOR BULLET PLOT
!     UPDATED         --JUNE      2025. TWEAKS FOR VARIABLE WIDTH BAR PLOT
!     UPDATED         --JULY      2025. TWEAKS FOR CANDLESTICK PLOT
!     UPDATED         --AUGUST    2025. TWEAKS FOR DOT MATRIX PLOT
!
!-----FOR NON-COMMON VARIABLES-----------------------------------------
!
      CHARACTER*4 ICONT
      CHARACTER*4 ICAPSW
      CHARACTER*4 IDEVO3
      CHARACTER*4 IDV2SP
      CHARACTER*4 ISQUAR
      CHARACTER*4 IVGMSW
      CHARACTER*4 IHGMSW
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*4 IGRDOR
      CHARACTER*24 ICH3PA
!
      CHARACTER*4 ILI2SW
      CHARACTER*4 ILI2PA
      CHARACTER*4 ILI2CO
      CHARACTER*4 ILI2TY
!
      CHARACTER*4 ICH2SW
      CHARACTER*24 ICH2PA
      CHARACTER*4 ICH2FO
      CHARACTER*4 ICH2CA
      CHARACTER*4 ICH2JU
      CHARACTER*4 ICH2DI
      CHARACTER*4 ICH2FI
      CHARACTER*4 ICH2CO
      CHARACTER*4 ICH2TY
!
      CHARACTER*4 IFI2SW
      CHARACTER*4 IFI2PA
      CHARACTER*4 IFI2CO
!
      CHARACTER*4 IPA2SW
      CHARACTER*4 IPA2PA
      CHARACTER*4 IPA2LI
      CHARACTER*4 IPA2CO
!
      CHARACTER*4 ISP2SW
      CHARACTER*4 ISP2LI
      CHARACTER*4 ISP2CO
      CHARACTER*4 ISP2DI
!
      CHARACTER*4 IBA2SW
      CHARACTER*4 IBA2BL
      CHARACTER*4 IBA2BC
      CHARACTER*4 IBA2FS
      CHARACTER*4 IBA2FC
      CHARACTER*4 IBA2PT
      CHARACTER*4 IBA2PL
      CHARACTER*4 IBA2PC
      CHARACTER*4 IBA2TY
      CHARACTER*4 IBA2DI
!
      CHARACTER*4 IRE2SW
      CHARACTER*4 IRE2BL
      CHARACTER*4 IRE2BC
      CHARACTER*4 IRE2FS
      CHARACTER*4 IRE2FC
      CHARACTER*4 IRE2PT
      CHARACTER*4 IRE2PL
      CHARACTER*4 IRE2PC
      CHARACTER*4 IRE2PZ
!
      CHARACTER*4 IMA2SW
      CHARACTER*4 IMA2BL
      CHARACTER*4 IMA2BC
      CHARACTER*4 IMA2FS
      CHARACTER*4 IMA2FC
      CHARACTER*4 IMA2PT
      CHARACTER*4 IMA2PL
      CHARACTER*4 IMA2PC
!
      CHARACTER*4 ITE2SW
      CHARACTER*4 ITE2BL
      CHARACTER*4 ITE2BC
      CHARACTER*4 ITE2FS
      CHARACTER*4 ITE2FC
      CHARACTER*4 ITE2PT
      CHARACTER*4 ITE2PL
