!
      PSAVE=-999.0
!
      ILI2SW='ON'
      ICH2SW='ON'
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PLOTG2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ISTEP,ISUBST,ISET,ISET3,ICH3PA
   53   FORMAT('ISTEP,ISUBST,ISET,ISET3,ICH3PA = ',4I8,2X,A16)
        CALL DPWRST('XXX','BUG ')
!CCCC   THE FOLLOWING 2 LINES WERE ADDED   MAY 1992
        WRITE(ICOUT,54)IPL2CS,NP,NUMSET
   54   FORMAT('IPL2CS,NP,NUMSET = ',A4,2X,I10,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)Y(1),X(1),PY(1),PX(1)
   63   FORMAT('Y(1),X(1),PY(1),PX(1) = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)Y(2),X(2),PY(2),PX(2)
   64   FORMAT('Y(2),X(2),PY(2),PX(2) = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)Y(NP),X(NP),PY(NP),PX(NP)
   65   FORMAT('Y(NP),X(NP),PY(NP),PX(NP) = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,68)ICASPL,ICAS3D,ISQUAR,XDELMN
   68   FORMAT('ICASPL,ICAS3D,ISQUAR,XDELMN = ',3(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS
   71   FORMAT('IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,76)IWRLES,IDRTRS,ICLG2S,ICLGRS
   76   FORMAT('IWRLES,IDRTRS,ICLG2S,ICLGRS = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,80)ITEXSY,ITEXSP,IBACCO,IANISW
   80   FORMAT('ITEXSY,ITEXSP,IBACCO,IANISW = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,81)IMANUF,IMODEL
   81   FORMAT('IMANUF,IMODEL = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,89)IBUGG4,ISUBG4,IERRG4
   89   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **************************************************
!               **  STEP 11--                                   **
!               **  EXTRACT SETTINGS FOR THIS PARTICULAR TRACE  **
!               **************************************************
!
!CCCC IF(IOPGRS.EQ.'ON')GO TO 1109
!CCCC IF(ICLGRS.EQ.'ON')GO TO 1109
!
!CCCC IMPLEMENT SUB-REGIONS DECEMBER 1999.
!CCCC CHAR, LINE, SPIKE, BAR SETTINGS SHOULD BE BLANK UNTIL ALL
!CCCC SUB-REGIONS PLOTTED.  THEN SHOULD START WITH FIRST SETTING.
!CCCC REGION SETTINGS SHOULD START WITH 1 REGARDLESS.
      ISET3T=ISET3-NUMSBR
      IF(ISET3T.LT.1)ISET3T=1
!
      ICH2PA=ICHAPA(ISET3T)
      ICH2FO=ICHAFO(ISET3T)
      ICH2CA=ICHACA(ISET3T)
      ICH2JU=ICHAJU(ISET3T)
      ICH2DI=ICHADI(ISET3T)
      ICH2TY=ICHATY(ISET3T)
      ACH2AN=ACHAAN(ISET3T)
      ICH2FI=ICHAFI(ISET3T)
      ICH2CO=ICHACO(ISET3T)
      ICH2CR=ICHAC2(ISET3T,1)
      ICH2CG=ICHAC2(ISET3T,2)
      ICH2CB=ICHAC2(ISET3T,3)
      PCH2HE=PCHAHE(ISET3T)
      PCH2WI=PCHAWI(ISET3T)
      PCH2TH=PCHATH(ISET3T)
      PCH2HO=PCHAHO(ISET3T)
      PCH2VO=PCHAVO(ISET3T)
      ILI2PA=ILINPA(ISET3T)
      ILI2CO=ILINCO(ISET3T)
      ILI2CR=ILINC2(ISET3T,1)
      ILI2CG=ILINC2(ISET3T,2)
      ILI2CB=ILINC2(ISET3T,3)
      ILI2TY=ILINTY(ISET3T)
      PLI2TH=PLINTH(ISET3T)
      IFI2SW=IFILSW(ISET3T)
      IFI2PA=IFILPA(ISET3T)
      IFI2CO=IFILCO(ISET3T)
      IFI2CR=IFILC2(ISET3T,1)
      IFI2CG=IFILC2(ISET3T,2)
      IFI2CB=IFILC2(ISET3T,3)
      PFI2SP=PFILSP(ISET3T)
      PFI2TH=PFILTH(ISET3T)
      IPA2SW=IPATSW(ISET3T)
      IPA2PA=IPATPA(ISET3T)
      IPA2LI=IPATLI(ISET3T)
      IPA2CO=IPATCO(ISET3T)
      IPA2CR=IPATC2(ISET3T,1)
      IPA2CG=IPATC2(ISET3T,2)
      IPA2CB=IPATC2(ISET3T,3)
      PPA2HE=PPATHE(ISET3T)
      PPA2WI=PPATWI(ISET3T)
      PPA2SP=PPATSP(ISET3T)
      PPA2TH=PPATTH(ISET3T)
      ISP2SW=ISPISW(ISET3T)
      ISP2LI=ISPILI(ISET3T)
      ISP2CO=ISPICO(ISET3T)
      ISP2CR=ISPIC2(ISET3T,1)
      ISP2CG=ISPIC2(ISET3T,2)
      ISP2CB=ISPIC2(ISET3T,3)
      ISP2DI=ISPIDI(ISET3T)
!CCCC THE FOLLOWING LINE WAS ADDED FEBRUARY 1989
      IF(IHORSW.EQ.'ON')ISP2DI='H'
      PSP2TH=PSPITH(ISET3T)
      ASP2BA=ASPIBA(ISET3T)
      PCH2HO=PCHAHO(ISET3T)
      PCH2VO=PCHAVO(ISET3T)
!
      IBA2SW=IBARSW(ISET3T)
      ABA2WI=ABARWI(ISET3T)
      ABA2BA=ABARBA(ISET3T)
      IBA2BL=IBABLI(ISET3T)
      IBA2BC=IBABCO(ISET3T)
      IBA2BR=IBABC2(ISET3T,1)
      IBA2BG=IBABC2(ISET3T,2)
      IBA2BB=IBABC2(ISET3T,3)
      PBA2BT=PBABTH(ISET3T)
      IBA2FS=IBAFSW(ISET3T)
      IBA2FC=IBAFCO(ISET3T)
      IBA2FR=IBAFC2(ISET3T,1)
      IBA2FG=IBAFC2(ISET3T,2)
      IBA2FB=IBAFC2(ISET3T,3)
      IBA2PT=IBAPTY(ISET3T)
      IBA2PL=IBAPLI(ISET3T)
      IBA2PC=IBAPCO(ISET3T)
      IBA2PR=IBAPC2(ISET3T,1)
      IBA2PG=IBAPC2(ISET3T,2)
      IBA2PB=IBAPC2(ISET3T,3)
      IBA2TY=IBARTY(ISET3T)
      IBA2DI=IBARDI(ISET3T)
!CCCC THE FOLLOWING LINE WAS ADDED FEBRUARY 1989
      IF(IHORSW.EQ.'ON')IBA2DI='H'
      PBA2PS=PBAPSP(ISET3T)
      PBA2PT=PBAPTH(ISET3T)
!
!     FOR DUMBELL PLOT, SET BAR BASE TO MINIMUM VALUE
!
!     FOR RIDGELINE PLOT WITH HISTOGRAM OPTION, SET BAR BASE
!     BASED ON DATA.
!
!     FOR DOT MATRIX PLOT, SET LINE, SPIKE, REGION SWITCH TO OFF
!
      IF(ICASPL.EQ.'DBPL')THEN
        IF(ISET3T.GT.2 .AND. IBA2SW.EQ.'ON')THEN
          IF(IHORSW.EQ.'OFF')THEN
            ABA2BA=MIN(Y(1),Y(2))
            Y(1)=MAX(Y(1),Y(2))
          ELSE
            ABA2BA=MIN(X(1),X(2))
            X(1)=MAX(X(1),X(2))
          ENDIF
          NP=1
        ENDIF
      ELSEIF(ICASPL.EQ.'RIPH')THEN
        ILI2PA='BLAN'
        IBA2SW='ON'
        ABA2BA=PY2(1)
      ELSEIF(ICASPL.EQ.'DMPL' .OR. ICASPL.EQ.'DMPP')THEN
        ILI2PA='BLAN'
        IBA2SW='OFF'
        ISP2SW='OFF'
      ENDIF
!
      IRE2SW=IREGSW(ISET3)
      ARE2WI=AREGWI(ISET3)
      ARE2BA=AREGBA(ISET3)
      IRE2BL=IREBLI(ISET3)
      IRE2BC=IREBCO(ISET3)
      IRE2BR=IREBC2(ISET3,1)
      IRE2BG=IREBC2(ISET3,2)
      IRE2BB=IREBC2(ISET3,3)
      PRE2BT=PREBTH(ISET3)
      IRE2FS=IREFSW(ISET3)
      IRE2FC=IREFCO(ISET3)
      IRE2FR=IREFC2(ISET3,1)
      IRE2FG=IREFC2(ISET3,2)
      IRE2FB=IREFC2(ISET3,3)
      IRE2PT=IREPTY(ISET3)
      IRE2PL=IREPLI(ISET3)
      IRE2PC=IREPCO(ISET3)
      IRE2PR=IREPC2(ISET3,1)
      IRE2PG=IREPC2(ISET3,2)
      IRE2PB=IREPC2(ISET3,3)
      PRE2PS=PREPSP(ISET3)
      PRE2PT=PREPTH(ISET3)
      IRE2PZ=IREBPL
!
!     FOR WATERFALL OR BACKGROUND OF BLOCK PLOT, SET REGION
!     BASE TO MINIMUM Y VALUE.  FOR BULLET PLOT, SET BAR BASE
!     BASED ON DATA.
!
      IF(ICASPL.EQ.'WAPL' .OR. ICASPL.EQ.'BLP2')THEN
        IF(Y(2).LE.Y(3))THEN
          ARE2BA=Y(2)
        ELSE
          ARE2BA=Y(3)
        ENDIF
      ELSEIF(ICASPL.EQ.'BUPL')THEN
        ILI2PA='BLAN'
        IBA2SW='ON'
        IF(ISET3T.GE.3)ABA2BA=PBARBA
      ELSEIF(ICASPL.EQ.'CSPL')THEN
        ARE2BA=PBARBA
        IRE2SW='BLAN'
        IRE2FS='OFF'
        IF(ISET3T.LE.2)THEN
          IRE2SW='ON'
          IRE2FS='ON'
        ENDIF
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,91)ISET3T,IRE2SW,ARE2BA
   91     FORMAT('CSPL: ISET3T,IRE2SW,ARE2BA = ',I6,A4,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ENDIF
!
!CCCC OCTOBER 1993.  ADD FOLLOWING SECTION
!
      IF(IREBIN.EQ.'OFF')THEN
        ARE3BA=ARE2BA
      ELSE
        ARE3BA=AREGBA(ISET3+1)
        IF(ARE3BA.EQ.CPUMAX)ARE3BA=ARE2BA
      ENDIF
!
      IF(ISET3.LE.NUMSBR)THEN
        ICH2PA='BLAN'
        ILI2PA=IRE2BL
        ILI2CO=IRE2BC
        ILI2CR=IREBC2(ISET3,1)
        ILI2CG=IREBC2(ISET3,2)
        ILI2CB=IREBC2(ISET3,3)
        PLI2TH=PRE2BT
        ISP2SW='OFF'
        IBA2SW='OFF'
        IFI2SW='OFF'
        IRE2SW='ON'
        IRE2PZ='ON'
        IRE2PC=IRE2FC
        IR2PCR=IRE2FR
        IR2PCG=IRE2FG
        IR2PCB=IRE2FB
      ENDIF
!
!     FOR VARIABLE WIDTH BAR PLOT, SET BAR WIDTH TO VALUE IN X3D.
!     ALSO, BLANK OUT LINE AND SPIKE SWITCHES.
!
      IF(ICASPL.EQ.'VWBP')THEN
        ABA2WI=X3D(ISET3)
        ILI2PA='BLAN'
        ISP2SW='OFF'
        IRE2SW='OFF'
        IBA2SW='ON'
        IBA2FS='ON'
      ENDIF
!
      IMA2SW=IMARSW(ISET3)
      AMA2WI=AMARWI(ISET3)
      AMA2BA=AMARBA(ISET3)
      IMA2BL=IMABLI(ISET3)
      IMA2BC=IMABCO(ISET3)
      IMA2BR=IMABC2(ISET3,1)
      IMA2BG=IMABC2(ISET3,2)
      IMA2BB=IMABC2(ISET3,3)
      PMA2BT=PMABTH(ISET3)
      IMA2FS=IMAFSW(ISET3)
      IMA2FC=IMAFCO(ISET3)
      IMA2FR=IMAFC2(ISET3,1)
      IMA2FG=IMAFC2(ISET3,2)
      IMA2FB=IMAFC2(ISET3,3)
      IMA2PT=IMAPTY(ISET3)
      IMA2PL=IMAPLI(ISET3)
      IMA2PC=IMAPCO(ISET3)
      IMA2PR=IMAPC2(ISET3,1)
      IMA2PG=IMAPC2(ISET3,2)
      IMA2PB=IMAPC2(ISET3,3)
      PMA2PS=PMAPSP(ISET3)
      PMA2PT=PMAPTH(ISET3)
!
      ITE2SW=ITEXSW(ISET3)
      ATE2WI=ATEXWI(ISET3)
      ATE2BA=ATEXBA(ISET3)
      ITE2BL=ITEBLI(ISET3)
      ITE2BC=ITEBCO(ISET3)
      ITE2BR=ITEBC2(ISET3,1)
      ITE2BG=ITEBC2(ISET3,2)
      ITE2BB=ITEBC2(ISET3,3)
      PTE2BT=PTEBTH(ISET3)
      ITE2FS=ITEFSW(ISET3)
      ITE2FC=ITEFCO(ISET3)
      ITE2FR=ITEFC2(ISET3,1)
      ITE2FG=ITEFC2(ISET3,2)
      ITE2FB=ITEFC2(ISET3,3)
      ITE2PT=ITEPTY(ISET3)
      ITE2PL=ITEPLI(ISET3)
      ITE2PC=ITEPCO(ISET3)
      ITE2PR=ITEPC2(ISET3,1)
      ITE2PG=ITEPC2(ISET3,2)
      ITE2PB=ITEPC2(ISET3,3)
      PTE2PS=PTEPSP(ISET3)
      PTE2PT=PTEPTH(ISET3)
!
      IF(ISTEP.EQ.2.AND.ISUBST.EQ.3.AND.NUMSBR.LE.0)THEN
          ICH2PA=ICH3PA
      ELSEIF(ISTEP.EQ.2.AND.ISUBST.EQ.4.AND.NUMSBR.LE.0)THEN
        ICH2PA=ICH3PA
      ELSEIF(ISTEP.EQ.2.AND.ISUBST.EQ.6.AND.ICH3PA.NE.' ')THEN
        ICH2PA=ICH3PA
      ENDIF
!
      IF(ICASPL.EQ.'BLP2' .OR. ICASPL.EQ.'WAPL')THEN
        ICH2PA='BLAN'
        ILI2PA='SOLI'
        IRE2SW='ON'
      ELSEIF(ICASPL.EQ.'BLP3')THEN
        IRE2SW='OFF'
        IRE2FS='OFF'
        ILI2PA='BLAN'
      ENDIF
!
!CCCC AUGUST 1992.  FOLLOWING BLOCK OF CODE ADDED FOR SYMBOL PLOT
!CCCC AND VECTOR PLOTS WITH VARIABLE ARROW LENGTH
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'SYMB'.AND.ISET3.GT.NUMSBR)THEN
        ICH2PA=ICHAPA(ISETSY)
        ICH2FI='OFF'
        IF(ISETFI.NE.0)ICH2FI='ON'
        ICH2CO=ICHACO(ISETCL)
        ICH2CR=ICHAC2(ISETCL,1)
        ICH2CG=ICHAC2(ISETCL,2)
        ICH2CB=ICHAC2(ISETCL,3)
        PCH2HE=ASETSZ*PCH2HE
        PCH2WI=ASETSZ*PCH2WI
      ENDIF
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'VVAR')THEN
        PCH2HE=ASETSZ*PCH2HE
        PCH2WI=ASETSZ*PCH2WI
      ENDIF
!CCCC DECEMBER 1999.  CROSS TABULATE PLOT X1 X2 SETS CHAR TYPE TO
!CCCC ZVAL.
!CCCC JUNE 2010.  "CHARACTER" VERSION OF TABULATION PLOT DOES THE
!CCCC             FOLLOWING:
!CCCC             1) FOR TRACES 1 - NUMSET/2, USE CHARACTER
!CCCC                SETTINGS AS SPECIFIED BY USER.
!CCCC             2) FOR TRACES (NUMSET/2)+1 - NUMSET, USE "ZVAL".
!CCCC             THE FIRST SET ALLOWS THE USER TO PLOT A "BACKGROUND"
!CCCC             ELEMENT WHILE THE SECOND SET DRAWS THE VALUE OF
!CCCC             THE STATISTIC.
!
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'CTCO'.AND.ISET3.GT.NUMSBR)THEN
        ICH2PA='ZVAL'
        ILI2PA='BLAN'
      ENDIF
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'CTA2'.AND.ISET3.GT.NUMSBR)THEN
        ICH2PA='ZVAL'
        ILI2PA='BLAN'
      ENDIF
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'DCON'.AND.   &
        (ISET3.EQ.NUMSBR+1 .OR. ISET3.EQ.NUMSBR+2))THEN
        ICH2PA='ZVAL'
        ILI2PA='BLAN'
      ENDIF
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'TABC')THEN
        IF(IADD.GT.0)THEN
          NTEMP=(NUMSET-IADD)/2
          IF(ISET3.GE.NUMSBR+NTEMP+1 .AND. ISET3.LE.NUMSBR+2*NTEMP)THEN
            ICH2PA='ZVAL'
            ILI2PA='BLAN'
          ENDIF
        ELSE
          NTEMP=NUMSET/2
          IF(ISET3.GE.NUMSBR+NTEMP+1)THEN
            ICH2PA='ZVAL'
            ILI2PA='BLAN'
          ENDIF
        ENDIF
      ENDIF
!
!CCCC JUNE 2007.  ASSOCIATION PLOT SETS LINE AND CHARACTER TO BLANK
!
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'ASSO'.AND.   &
         ISET3.GE.NUMSBR+1)THEN
        ICH2PA='BLAN'
        ILI2PA=ILINPA(1)
        IRE2SW='ON'
        ARE2WI=AREGWI(1)
        ARE2BA=Y(1)
        IRE2BC=IREBCO(ISETCL)
        IRE2BR=IREBC2(ISETCL,1)
        IRE2BG=IREBC2(ISETCL,2)
        IRE2BB=IREBC2(ISETCL,3)
        IRE2BL=IREBLI(1)
        PRE2BT=PREBTH(1)
        IRE2FS='ON'
        IRE2FC=IREFCO(ISETCL)
        IRE2FR=IREFC2(ISETCL,1)
        IRE2FG=IREFC2(ISETCL,2)
        IRE2FB=IREFC2(ISETCL,3)
        IRE2PT=IREPTY(1)
        IRE2PL=IREPLI(1)
        IRE2PC=IREPCO(ISETCL)
        IRE2PR=IREPC2(ISETCL,1)
        IRE2PG=IREPC2(ISETCL,2)
        IRE2PB=IREPC2(ISETCL,3)
        PRE2PS=PREPSP(1)
        PRE2PT=PREPTH(1)
        IRE2PZ=IREBPL
        ARE3BA=ARE2BA
        ILI2CO=IRE2BL
        ILI2CR=IRE2BR
        ILI2CG=IRE2BG
        ILI2CB=IRE2BB
        PLI2TH=PRE2BT
      ELSEIF(ISTEP.EQ.2.AND.   &
            (ICASPL.EQ.'TABU'.OR.ICASPL.EQ.'DFIT') .AND.   &
         ISET3.GE.NUMSBR+1)THEN
        ICH2PA='BLAN'
        ILI2PA='BLAN'
        IRE2SW='ON'
        ARE2WI=AREGWI(1)
        ARE2BA=Y(1)
        IRE2BC=IREBCO(ISETCL)
        IRE2BR=IREBC2(ISETCL,1)
        IRE2BG=IREBC2(ISETCL,2)
        IRE2BB=IREBC2(ISETCL,3)
        IRE2BL=IREBLI(1)
        PRE2BT=PREBTH(1)
        IRE2FS='ON'
        IRE2FC=IREFCO(ISETCL)
        IRE2FR=IREFC2(ISETCL,1)
        IRE2FG=IREFC2(ISETCL,2)
        IRE2FB=IREFC2(ISETCL,3)
        IRE2PT=IREPTY(1)
        IRE2PL=IREPLI(1)
        IRE2PC=IREPCO(ISETCL)
        IRE2PR=IREPC2(ISETCL,1)
        IRE2PG=IREPC2(ISETCL,2)
        IRE2PB=IREPC2(ISETCL,3)
        PRE2PS=PREPSP(1)
        PRE2PT=PREPTH(1)
        PRE2TH=PREBTH(1)
!
        IRE2PT=IREPTY(ISETCL)
        IRE2PL=IREPLI(ISETCL)
        PRE2PS=PREPSP(ISETCL)
        PRE2PT=PREPTH(ISETCL)
!
        IRE2PZ=IREBPL
        ARE3BA=ARE2BA
        ILI2CO=IRE2BL
        ILI2CR=IRE2BR
        ILI2CG=IRE2BG
        ILI2CB=IRE2BB
        PLI2TH=PRE2BT
      ELSEIF(ISTEP.EQ.2.AND.ICASPL.EQ.'FLUC'.AND.ISETCL.LE.4.AND.   &
         ISET3.GE.NUMSBR+1)THEN
!
!       IF REGION COLOR IS SET TO "NULL" OR "NONE", THEN TURN
!       REGION FILL SWITCH OFF.  THIS CAN BE HELPFUL IN CREATING
!       A "STACKED" FLUCTUATION PLOT.
!
        IRE2SW='ON'
        IRE2FS='ON'
        ICH2PA='BLAN'
        ILI2PA=ILINPA(1)
        ARE2WI=AREGWI(1)
        ARE2BA=Y(1)
        IRE2BC=IREBCO(ISETCL)
        IRE2BR=IREBC2(ISETCL,1)
        IRE2BG=IREBC2(ISETCL,2)
        IRE2BB=IREBC2(ISETCL,3)
        IRE2BL=IREBLI(ISETCL)
        IRE2FC=IREFCO(ISETCL)
        IRE2FR=IREFC2(ISETCL,1)
        IRE2FG=IREFC2(ISETCL,2)
        IRE2FB=IREFC2(ISETCL,3)
        IRE2PT=IREPTY(ISETCL)
        IRE2PL=IREPLI(ISETCL)
        IRE2PC=IREPCO(ISETCL)
        IRE2PR=IREPC2(ISETCL,1)
        IRE2PG=IREPC2(ISETCL,2)
        IRE2PB=IREPC2(ISETCL,3)
        PRE2PS=PREPSP(ISETCL)
        PRE2PT=PREPTH(ISETCL)
        PRE2BT=PREBTH(ISETCL)
        PRE2TH=PREBTH(ISETCL)
        PRE2BT=PREBTH(ISETCL)
        IRE2PT=IREPTY(ISETCL)
        IRE2PL=IREPLI(ISETCL)
        IRE2PZ=IREBPL
        ARE3BA=ARE2BA
        ILI2CO=IRE2BL
        ILI2CR=IRE2BR
        ILI2CG=IRE2BG
        ILI2CB=IRE2BB
        PLI2TH=PRE2BT
!CCCC   IF(ISETCL.EQ.1 .AND.
        IF((ISETCL.EQ.1.OR.ISETCL.EQ.2) .AND.   &
           (IRE2FC.EQ.'NONE' .OR. IRE2FC.EQ.'NULL'))THEN
          GO TO 9000
        ENDIF
      ELSEIF(ISTEP.EQ.2.AND.ICASPL.EQ.'FLCP'.AND.   &
         ISET3.GE.NUMSBR+1)THEN
        IRE2SW='ON'
        IRE2FS='ON'
        ICH2PA='BLAN'
        ILI2PA='BLAN'
        ARE2WI=AREGWI(1)
        ARE2BA=Y(1)
        IRE2BC=IREBCO(ISETCL)
        IRE2BR=IREBC2(ISETCL,1)
        IRE2BG=IREBC2(ISETCL,2)
        IRE2BB=IREBC2(ISETCL,3)
        IRE2BL=IREBLI(1)
        PRE2BT=PREBTH(1)
        IRE2FC=IREFCO(ISETCL)
        IRE2FR=IREFC2(ISETCL,1)
        IRE2FG=IREFC2(ISETCL,2)
        IRE2FB=IREFC2(ISETCL,3)
        IRE2PT=IREPTY(ISETCL)
        IRE2PL=IREPLI(ISETCL)
        IRE2PC=IREPCO(ISETCL)
        IRE2PR=IREPC2(ISETCL,1)
        IRE2PG=IREPC2(ISETCL,2)
        IRE2PB=IREPC2(ISETCL,3)
        PRE2PS=PREPSP(ISETCL)
        PRE2PT=PREPTH(ISETCL)
        IRE2PZ=IRE2PL
        ARE3BA=ARE2BA
      ENDIF
!
      IF(ISTEP.EQ.2.AND.   &
         (ICASPL.EQ.'FLUC' .AND. ISETCL.GT.4).AND.   &
         ISET3.GE.NUMSBR+1)THEN
        ICH2PA=ICHAPA(ISETCL)
        ICH2FO=ICHAFO(ISETCL)
        ICH2CA=ICHACA(ISETCL)
        ICH2JU=ICHAJU(ISETCL)
        ICH2DI=ICHADI(ISETCL)
        ICH2TY=ICHATY(ISETCL)
        ACH2AN=ACHAAN(ISETCL)
        ICH2FI=ICHAFI(ISETCL)
        ICH2CO=ICHACO(ISETCL)
        ICH2CR=ICHAC2(ISETCL,1)
        ICH2CG=ICHAC2(ISETCL,2)
        ICH2CB=ICHAC2(ISETCL,3)
        PCH2HE=PCHAHE(ISETCL)
        PCH2WI=PCHAWI(ISETCL)
        PCH2TH=PCHATH(ISETCL)
        PCH2HO=PCHAHO(ISETCL)
        PCH2VO=PCHAVO(ISETCL)
        ILI2PA=ILINPA(ISETCL)
        ILI2CO=ILINCO(ISETCL)
        ILI2CR=ILINC2(ISETCL,1)
        ILI2CG=ILINC2(ISETCL,2)
        ILI2CB=ILINC2(ISETCL,3)
        ILI2TY=ILINTY(ISETCL)
        PLI2TH=PLINTH(ISETCL)
        IRE2BL='BLAN'
        IRE2PT='BLAN'
        IRE2PL='BLAN'
      ENDIF
!
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'SIEV'.AND.   &
         ISET3.GE.NUMSBR+1)THEN
        ICH2PA='BLAN'
!
        IF(ISETFI.EQ.1)THEN
          ILI2PA=ILINPA(1)
          ILI2CO=ILINCO(1)
          ILI2CR=ILINC2(1,1)
          ILI2CG=ILINC2(1,2)
          ILI2CB=ILINC2(1,3)
          PLI2TH=PLINTH(1)
        ELSEIF(ISETFI.EQ.2)THEN
          ILI2PA=ILINPA(ISETFI)
          IF(ISETCL.EQ.1)THEN
            ILI2CO=ILINCO(2)
            ILI2CR=ILINC2(2,1)
            ILI2CG=ILINC2(2,2)
            ILI2CB=ILINC2(2,3)
          ELSEIF(ISETCL.EQ.2)THEN
            ILI2CO=ILINCO(3)
            ILI2CR=ILINC2(3,1)
            ILI2CG=ILINC2(3,2)
            ILI2CB=ILINC2(3,3)
          ENDIF
          PLI2TH=PLINTH(ISETFI)
        ELSEIF(ISETFI.EQ.3)THEN
          ILI2PA=ILINPA(ISETFI)
          IF(ISETCL.EQ.1)THEN
            ILI2CO=ILINCO(2)
            ILI2CR=ILINC2(2,1)
            ILI2CG=ILINC2(2,2)
            ILI2CB=ILINC2(2,3)
          ELSEIF(ISETCL.EQ.2)THEN
            ILI2CO=ILINCO(3)
            ILI2CR=ILINC2(3,1)
            ILI2CG=ILINC2(3,2)
            ILI2CB=ILINC2(3,3)
          ENDIF
          PLI2TH=PLINTH(ISETFI)
        ELSE
          ILI2PA=ILINPA(1)
          ILI2CO=ILINCO(1)
          ILI2CR=ILINC2(1,1)
          ILI2CG=ILINC2(1,2)
          ILI2CB=ILINC2(1,3)
          PLI2TH=PLINTH(1)
        ENDIF
!
      ENDIF
!
      IF(ISTEP.EQ.2.AND.ICASPL.EQ.'LPLO'.AND.   &
         ISET3.GE.NUMSBR+1)THEN
        ICH2PA='BLAN'
        ILI2PA='BLAN'
        ILI2CO=ILINCO(1)
        ILI2CR=ILINC2(1,1)
        ILI2CG=ILINC2(1,2)
        ILI2CB=ILINC2(1,3)
        PLI2TH=PLINTH(1)
        IRE2SW='ON'
        ARE2WI=AREGWI(1)
        ARE2BA=Y(1)
        IRE2BL=IREBLI(1)
        IRE2BC=IREBCO(ISETCL)
        IRE2BR=IREBC2(ISETCL,1)
        IRE2BG=IREBC2(ISETCL,2)
        IRE2BB=IREBC2(ISETCL,3)
        PRE2BT=PREBTH(1)
        IRE2FS='ON'
        IRE2FC=IREFCO(ISETCL)
        IRE2FR=IREFC2(ISETCL,1)
        IRE2FG=IREFC2(ISETCL,2)
        IRE2FB=IREFC2(ISETCL,3)
        IRE2PT=IREPTY(1)
        IRE2PL=IREPLI(1)
        IRE2PC=IREPCO(ISETCL)
        IRE2PR=IREPC2(ISETCL,1)
        IRE2PG=IREPC2(ISETCL,2)
        IRE2PB=IREPC2(ISETCL,3)
        PRE2PS=PREPSP(1)
        PRE2PT=PREPTH(1)
        IRE2PZ=IREBPL
        ARE3BA=ARE2BA
      ENDIF
!
      IF(ISTEP.EQ.2.AND.   &
        (ICASPL.EQ.'IMAG'.OR.ICASPL.EQ.'IMA2').AND.   &
         ISET3.GE.NUMSBR+1)THEN
        ICASCO='RGB'
        IF(ICASPL.EQ.'IMA2')ICASCO='GREY'
        ICH2PA='BLAN'
        ILI2PA='BLAN'
        IRE2SW='OFF'
        IRE2FS='OFF'
        IBA2SW='OFF'
        ISP2SW='OFF'
      ENDIF
!
!CCCC THE FOLLOWING CHUNK OF CODE WAS ADDED FEBRUARY 1989 (ALAN).
!CCCC SEPTEMBER, 1987: ADD "HORIZONTAL SWITCH ON" CASE, I.E. PLOT
!CCCC THE CHART HORIZONTALLY RATHER THAN VERTICALLY.  NOTE THAT
!CCCC "DPDRBA" AND "DPDRSP" ALREADY HANDLE THIS CASE (SPIKE DIRECTION
!CCCC AND BAR DIRECTION COMMANDS).  OTHER CASES SIMPLY REVERSE VALUE
!CCCC OF X AND Y COORDINATES.  HORIZONTAL ON WILL SET THE SPIKE AND
!CCCC BAR DIRECTIONS TO HORIZONTAL.
!CCCC ONE COMPLICATION IS IF THE BAR OR SPIKE SWITCH IS "ON" AND THE
!CCCC LINE OR CHARACTER SWITCH IS ON AS WELL.  THEN ONE CASE REQUIRES
!CCCC A X AND Y TO SWITCH WHILE THE OTHER DOES NOT.  IN THIS CASE, MAY
!CCCC NEED TO SWITCH X AND Y BACK TO ORIGINAL WAY BEFORE DRAW SPIKE OR
!CCCC BAR (VARIABLE ISWTCH KEEPS TRACK)
!CCCC ISWTCH='OFF'
      IF(IHORSW.EQ.'OFF')GO TO 1119
      IF(IDELIS.EQ.'OFF'.AND.IDRTRS.EQ.'OFF')GO TO 1119
      IF(ISWTCH.EQ.'ON')GO TO 1119
!CCCC IF(ICASPL.EQ.'HIST')GO TO 1119
!CCCC IF(ICASPL.EQ.'CUMH')GO TO 1119
!CCCC IF(ICASPL.EQ.'BARP')GO TO 1119
!CCCC IF(ICASPL.EQ.'ROOT')GO TO 1119
!CCCC IF(ICASPL.EQ.'CUMR')GO TO 1119
!CCCC IF(ICASPL.EQ.'BIHI')GO TO 1119
      DO 1115 I=1,MAXPOP
        XTEMP=X(I)
        X(I)=Y(I)
        Y(I)=XTEMP
 1115 CONTINUE
      ISWTCH='ON'
 1119 CONTINUE
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'OTG2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1121)
 1121   FORMAT('***** FROM THE MIDDLE OF PLOTG2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1131)ILI2PA,ILI2CO,ILI2TY,PLI2TH
 1131   FORMAT('ILI2PA,ILI2CO,ILI2TY,PLI2TH = ',3(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1132)ICH2PA,ICH2FO,ICH2CA,ICH2JU
 1132   FORMAT('ICH2PA,ICH2FO,ICH2CA,ICH2JU = ',A16,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1133)ICH2DI,ICH2FI,ICH2CO,ICH2TY,ACH2AN
 1133   FORMAT('ICH2DI,ICH2FI,ICH2CO,ICH2TY,ACH2AN, = ',4(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1134)PCH2HE,PCH2WI,PCH2TH,PCH2HO,PCH2VO
 1134   FORMAT('PCH2HE,PCH2WI,PCH2TH,PCH2HO,PCH2VO = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1135)IFI2SW,IFI2PA,IFI2CO,PFI2SP,PFI2TH
 1135   FORMAT('IFI2SW,IFI2PA,IFI2CO,PFI2SP,PFI2TH = ',3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1136)IPA2SW,IPA2PA,IPA2LI,IPA2CO
 1136   FORMAT('IPA2SW,IPA2PA,IPA2LI,IPA2CO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1138)ISP2SW,ISP2LI,ISP2CO,PSP2TH,ASP2BA
 1138   FORMAT('ISP2SW,ISP2LI,ISP2CO,PSP2TH,ASP2BA = ',3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1141)IBA2SW,ABA2WI,ABA2BA
 1141   FORMAT('IBA2SW,ABA2WI,ABA2BA = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1142)IBA2BL,IBA2BC,PBA2BT
 1142   FORMAT('IBA2BL,IBA2BC,PBA2BT = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1143)IBA2FS,IBA2FC
 1143   FORMAT('IBA2FS,IBA2FC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1144)IBA2PT,IBA2PL,IBA2PC,IBA2TY,PBA2PS,PBA2PT
 1144   FORMAT('IBA2PT,IBA2PL,IBA2PC,IBA2TY,PBA2PS,PBA2PT = ',   &
               4(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1151)IRE2SW,ARE2WI,ARE2BA
 1151   FORMAT('IRE2SW,ARE2WI,ARE2BA = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1152)IRE2BL,IRE2BC,PRE2BT
 1152   FORMAT('IRE2BL,IRE2BC,PRE2BT = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1153)IRE2FS,IRE2FC,IR2FCR,IR2FCG,IR2FCB
 1153   FORMAT('IRE2FS,IRE2FC,IR2FCR,IR2FCG,IR2FCB = ',2(A4,2X),3I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1154)IRE2PT,IRE2PL,IRE2PC,IR2PCR,IR2PCG,IR2PCB,   &
                         PRE2PS,PRE2PT
 1154   FORMAT('IRE2PT,IRE2PL,IRE2PC,IR2PCR,IR2PCG,IR2PCB,',   &
               'PRE2PS,PRE2PT = ',3(A4,2X),3I5,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1161)IMA2SW,AMA2WI,AMA2BA
 1161   FORMAT('IMA2SW,AMA2WI,AMA2BA = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1162)IMA2BL,IMA2BC,PMA2BT
 1162   FORMAT('IMA2BL,IMA2BC,PMA2BT = ',2(A4,2X,A4),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1163)IMA2FS,IMA2FC
 1163   FORMAT('IMA2FS,IMA2FC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1164)IMA2PT,IMA2PL,IMA2PC,PMA2PS,PMA2PT
 1164   FORMAT('IMA2PT,IMA2PL,IMA2PC,PMA2PS,PMA2PT = ',3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1171)ITE2SW,ATE2WI,ATE2BA
 1171   FORMAT('ITE2SW,ATE2WI,ATE2BA = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1172)ITE2BL,ITE2BC,PTE2BT
 1172   FORMAT('ITE2BL,ITE2BC,PTE2BT = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1173)ITE2FS,ITE2FC
 1173   FORMAT('ITE2FS,ITE2FC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1174)ITE2PT,ITE2PL,ITE2PC,PTE2PS,PTE2PT
 1174   FORMAT('ITE2PT,ITE2PL,ITE2PC,PTE2PS,PTE2PT = ',3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1181)IHORSW,ISWTCH
 1181   FORMAT('IHORSW,ISWTCH=',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 1182 I=1,10
          WRITE(ICOUT,1183)I,X(I),Y(I)
 1183     FORMAT('I,X(I),Y(I)=',I4,2(2X,G15.7))
          CALL DPWRST('XXX','BUG ')
 1182   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************************************
!               **  STEP 21--                          **
!               **  STEP THROUGH EACH GRAPHICS DEVICE  **
!               *****************************************
!
      ISYMBL=ITEXSY
      ISPAC=ITEXSP
!
!CCCC THE FOLLOWING 6 LINES WERE ADDED           MAY 1992 (JJF)
!CCCC TO AUTOMATICALLY CLOSE/OPEN DEVICE 3    MAY 1992
!CCCC WHENEVER AN INITIALIZATION/ERASE IS DONE   MAY 1992
!CCCC (SEE ALSO DPERAS AND MAINOD)               MAY 1992
!CCCC
!CCCC AUGMENTED TO AUTOMATICALLY SAVE THE CURRENT X11 PIXMAP TO
!CCCC A FILE.  APRIL 1997.
!
      IF(IERASW.EQ.'ON')THEN
         IF(IOPG2S.EQ.'ON')THEN
            IF(IDEVO3.EQ.'AUTO')THEN
              IBUGXX=IBUGG4
              ISUBXX=ISUBG4
              IERRXX=IERRG4
              IF(IPL2CS.EQ.'OPEN')THEN
                CALL DPDEV(3,'CLOS','POST',ICAPSW,IBUGXX,ISUBXX,IERRXX)
              ENDIF
              IF(IPL2CS.EQ.'CLOSED')THEN
                CALL DPDEV(3,'OPEN','POST',ICAPSW,IBUGXX,ISUBXX,IERRXX)
              ENDIF
            ENDIF
!
            IF(IDV2SP.EQ.'ON')THEN
              IBUGXX=IBUGG4
              ISUBXX=ISUBG4
              IERRXX=IERRG4
              IF(IPL1CS.EQ.'OPEN')THEN
                CALL DPDEV(2,'CLOS','POST',ICAPSW,   &
                           IBUGXX,ISUBXX,IERRXX)
              ENDIF
              IF(IPL1CS.EQ.'CLOSED')THEN
                CALL DPDEV(2,'OPEN','POST',ICAPSW,   &
                           IBUGXX,ISUBXX,IERRXX)
              ENDIF
            ENDIF
!
            IF(IPXMFL.EQ.'ON' .OR. IPXMFL.EQ.'YES')THEN
              NUMPXM=NUMPXM+1
              IF(NUMPXM.GT.MAXPM)THEN
                WRITE(ICOUT,999)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,2011)MAXPM
                GO TO 2099
              ENDIF
 2011 FORMAT('***** ERROR FROM PLOTG2.  MAXIMUM NUMBER OF PIXMAPS (',   &
      I5,') EXCEEDED.')
              IPXMFN(NUMPXM)(1:IPXMNC)=IPXMFB(1:IPXMNC)
              NCSTR=IPXMNC+1
              IF(NUMPXM.LE.9)THEN
                WRITE(IPXMFN(NUMPXM)(NCSTR:NCSTR),'(I1)')NUMPXM
              ELSEIF(NUMPXM.LE.99)THEN
                WRITE(IPXMFN(NUMPXM)(NCSTR:NCSTR+1),'(I2)')NUMPXM
                NCSTR=NCSTR+1
              ELSEIF(NUMPXM.LE.999)THEN
                WRITE(IPXMFN(NUMPXM)(NCSTR:NCSTR+2),'(I3)')NUMPXM
                NCSTR=NCSTR+2
              ENDIF
!CCCC DECEMBER 1997.  FOR DEVICE GENERALITY, GO THROUGH GRSAGR.
              ICODE='SAVE'
              CTEMP=' '
              NCTEMP=0
              ISTRI2=' '
              ISTRI2(1:NCSTR)=IPXMFN(NUMPXM)(1:NCSTR)
              CALL GRSAGR(ICODE,ISTRI2,NCSTR,CTEMP,NCTEMP)
            ENDIF
!
!CCCC         DO2030I=1,NCSTR
!CCCC           CALL DPCOAN(IPXMFN(NUMPXM)(I:I),IADE(I))
!2030         CONTINUE
!CCCC         IERR=0
!CCCC         CALL XSAVEG(IADE,IERR)
!CCCC         IF(IERR.EQ.1)THEN
!CCCC           WRITE(ICOUT,999)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC           WRITE(ICOUT,2041)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC           GO TO 2099
!2041 FORMAT('***** ERROR IN PLOTG2--WRITING BIT MAP UNSUCCESSFUL.')
!CCCC         ELSEIF(IERR.EQ.2)THEN
!CCCC           NUMPXM=NUMPXM-1
!CCCC           WRITE(ICOUT,999)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC           WRITE(ICOUT,2043)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC           GO TO 2099
!2043 FORMAT('***** ERROR IN PLOTG2--NO CURRENT PIXMAP TO SAVE.')
!CCCC         ELSEIF(IERR.EQ.3)THEN
!CCCC           WRITE(ICOUT,999)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC           WRITE(ICOUT,2045)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC           GO TO 2099
!2045 FORMAT('***** ERROR IN PLOTG2--X11 HAS NOT BEEN OPENED.')
!CCCC         ELSEIF(IERR.EQ.4)THEN
!CCCC           WRITE(ICOUT,999)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC           WRITE(ICOUT,2047)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC           GO TO 2099
!2047 FORMAT('***** ERROR IN PLOTG2--X11 NOT INSTALLED ON THIS ',
!CCCC1'IMPLEMENTATION.')
!CCCC         ELSE
!CCCC           IF(IPXMCM(NUMPXM).EQ.' ')THEN
!CCCC             IPXMCM(NUMPXM)(1:128)=IPXMFN(NUMPXM)(1:128)
!CCCC           ENDIF
!CCCC           GO TO 2099
!CCCC         ENDIF
!CCCC      ENDIF
         ENDIF
      ENDIF
 2099 CONTINUE
!
!     2015/11: IN CASE ALL DEVICES ARE TURNED OFF (E.G., IN
!              10-STEP MACROS WE OFTEN GENERATE A PLOT IN THE
!              BACKGROUND TO OBTAIN PLOT LIMITS).  HOWEVER, TO
!              AVOID PROBLEMS FOR CASE WHERE ONE OR MORE DEVICES
!              ACTUALLY ARE ON, CHECK TO SEE IF ANY DEVICES ARE
!              ON FIRST.
!
      IF(NUMSET.NE.0)THEN
        IFLAG=0
        DO 2066 IDEV=1,NUMDEV
          IF(IDCONT(IDEV).EQ.'ON' .AND. IDPOWE(IDEV).EQ.'ON')IFLAG=1
 2066   CONTINUE
        IF(IFLAG.EQ.0)THEN
          CALL DPDELI(Y,X,X3D,PX,NP,NUMSET,   &
                      ICASPL,ICAS3D,XDELMN,D,XIDC)
        ENDIF
      ENDIF
!
      DO 2100 IDEV=1,NUMDEV
!
        ICONT=IDCONT(IDEV)
!CCCC   THE FOLLOWING LINE WAS INSERTED FEBRUARY 1989. (ALAN)
        IPOWER=IDPOWE(IDEV)
        IMANUF=IDMANU(IDEV)
        IMODEL=IDMODE(IDEV)
        IMODE2=IDMOD2(IDEV)
        IMODE3=IDMOD3(IDEV)
        IGCODE=IDCODE(IDEV)
        IGUNIT=IDUNIT(IDEV)
!
!       2022/05: CHECK IF "DEVICE <1/2/3> HARDWARE CHARACTER OFFSET"
!                HAS BEEN ENTERED.  BUT ONLY APPLY IF HARDWARE
!                CHARACTERS ARE IN EFFECT.
!
        IF(ICH2FO.EQ.'TEKT')THEN
          PHOROF=PCHOSH(IDEV)
          PVEROF=PCHOSV(IDEV)
          IF(PHOROF.GT.0.0 .OR. PVEROF.GT.0.0)THEN
            IFLAGS=0
!
!           CHECK FOR CHARACTERS THAT WILL BE DRAWN IS SOFTWARE,
!           CONVERT CHARACTER PATTERN TO UPPER CASE.
!
            ICH2ST=ICH2PA(1:4)
            DO 80111 KK=1,4
              ICH2ST(KK:KK)=ICH2PA(KK:KK)
              CALL DPCOAN(ICH2ST(KK:KK),IVALT)
              IF(IVALT.GE.97 .AND. IVALT.LE.122)THEN
                IVAM32=IVALT-32
                CALL DPCONA(IVAM32,ICH2ST(KK:KK))
              ENDIF
80111       CONTINUE
!
            IF(ICH2ST(1:4).EQ.'TRIA' .OR. ICH2ST(1:4).EQ.'TR  ')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'SQUA' .OR. ICH2ST(1:4).EQ.'SQ  ')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'DIAM' .OR. ICH2ST(1:4).EQ.'DI  ')IFLAGS=1
