            IF(ICH2ST(1:4).EQ.'DAGG')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'DDAG')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'VBAR')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'DVBA')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'LVBA')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'LHBA')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'BAR ')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'DEL ')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'PIXE')IFLAGS=1
            IF(ICH2ST(1:4).EQ.'DEL ')IFLAGS=1
!
!
!           ADD THE DEVICE OFFSET TO CHARACTER OFFSET
!
            IF(IFLAGS.EQ.0)THEN
              PCH2HO=PCH2HO + PHOROF
              PCH2VO=PCH2VO + PVEROF
            ENDIF
!
          ENDIF
        ENDIF
!
!CCCC   FEBRUARY 2006: DEVICE 1 LATEX TO CAPTURE FILE
!
        IF(IDEV.EQ.1 .AND. IMANUF.EQ.'LATE' .AND.   &
           IPR.EQ.ICAPNU)THEN
          IGUNIT=ICAPNU
        ENDIF
!
        NUMHPP=IDNHPP(IDEV)
        ANUMHP=NUMHPP
        NUMVPP=IDNVPP(IDEV)
        ANUMVP=NUMVPP
        IOFFSV=IDNVOF(IDEV)
        IOFFSH=IDNHOF(IDEV)
        IGCOLO=IDCOLO(IDEV)
        IGBAUD=IDBAUD(IDEV)
        ISOFT=IDSOFT(IDEV)
        ISOFT2=IDSOF2(IDEV)
        ISOFT3=IDSOF3(IDEV)
        IGFONT=IDFONT(IDEV)
        PCHSCA=PDSCAL(IDEV)
!
        IF(ICONT.EQ.'OFF')GO TO 2100
!
!CCCC   THE FOLLOWING LINE WAS INSERTED FEBRUARY 1989. (ALAN)
!CCCC   IF HAVE   DEVICE 2 OFF    COMMAND,
!CCCC   DO NOT SET DEFAULT DEVICE.
!CCCC   SET POWER OFF, WHEN POWER OFF DON'T DO PLOT.  DEVICE 2 ON  ???
!CCCC   WILL TURN ON WHATEVER CURRENT DEVICE IS.
!CCCC   THIS ALLOWS PLOT FILE TO BE TOGGLED ON AND OFF CONVIENTLY.
        IF(IPOWER.EQ.'OFF')GO TO 2100
!
        IF(ISQUAR.EQ.'ON' .OR. ICASPL.EQ.'PIEC' .OR.   &
           ICASPL.EQ.'ROSE')THEN
          PSAVE=PXMAX
          PYDEL=PYMAX-PYMIN
          PXDEL=PYDEL*(ANUMVP/ANUMHP)
          PXMAX=PXMIN+PXDEL
        ENDIF
!
!               ***************************************************
!               **  STEP 31--                                    **
!               **  CARRY OUT OPENING OPERATIONS                 **
!               **  ON THE DEVICES AND ON THE GRAPHICS SOFTWARE  **
!               ***************************************************
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90001)
90001     FORMAT('BEFORE CALL DPOPDE')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IOPGRS.EQ.'ON')CALL DPOPDE
!
!               ****************************************************************
!               **  STEP 32--
!               **  CARRY OUT MINOR PRE-PLOT ACTIVITIES--
!               **  ERASE THE SCREEN, FILL  THE BACKGROUND, RING THE BELL, ETC.
!               ****************************************************************
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90002)
90002     FORMAT('BEFORE CALL DPOPPL')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IOPG2S.EQ.'ON')   &
           CALL DPOPPL(IGRASW,IBELSW,NUMRIN,IERASW,IBACCO,IBACC2)
!CCCC   FOLLOWING LINES ADDED MARCH, 1990 FOR X11 DEVICE.  X11 CAN
!CCCC   DYNAMICALLY MODIFY THE PICTURE POINTS (ERASE SCREEN GETS UPDATED
!CCCC   VALUES).  ALSO CHECK FOR CAIRO X11 DRIVER.
        IF(IMANUF.EQ.'X11')THEN
          NUMVPP=INT(ANUMVP+0.5)
          NUMHPP=INT(ANUMHP+0.5)
          IDNVPP(IDEV)=NUMVPP
          IDNHPP(IDEV)=NUMHPP
        ELSEIF(IMANUF.EQ.'CAIR' .AND. IMODEL.EQ.'X11 ')THEN
          NUMVPP=INT(ANUMVP+0.5)
          NUMHPP=INT(ANUMHP+0.5)
          IDNVPP(IDEV)=NUMVPP
          IDNHPP(IDEV)=NUMHPP
!CCCC   FOLLOWING LINES ADDED OCTOBER, 1996 FOR QWIN DEVICE.  QWIN CAN
!CCCC   DYNAMICALLY MODIFY THE PICTURE POINTS (ERASE SCREEN GETS UPDATED
!CCCC   VALUES).
        ELSEIF(IMANUF.EQ.'QWIN')THEN
          NUMVPP=INT(ANUMVP+0.5)
          NUMHPP=INT(ANUMHP+0.5)
          IDNVPP(IDEV)=NUMVPP
          IDNHPP(IDEV)=NUMHPP
        ENDIF
!CCCC   END CHANGES
!
!               ************************************************
!               **  STEP 33--                                 **
!               **  IF HAVE NO POINTS BEING PLOTTED           **
!               **  (AND THEREFORE ONLY INTERESTED IN SEEING  **
!               **  THE TITLES, LABELS, LEGENDS, ETC.)        **
!               **  THEN SKIP DOWN TO THOSE SECTIONS.         **
!               ************************************************
!
        IF(NP.LE.0)GO TO 5700
!
!               ********************************************
!               **  STEP 34--                             **
!               **  DETERMINE DATA LIMITS, FRAME LIMITS,  **
!               **  AND TIC COORDINATES.                  **
!               ********************************************
!
        IF(IDELIS.EQ.'ON')THEN
!
!CCCC     THE FOLLOWING LINE WAS INSERTED FEBRUARY 1989
!CCCC     TO HANDLE THE CASE OF AN EMPTY SUBSET
!
          IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
            WRITE(ICOUT,90003)
90003       FORMAT('BEFORE CALL DPDELI')
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(NUMSET.GT.0)THEN
            CALL DPDELI(Y,X,X3D,PX,NP,NUMSET,ICASPL,ICAS3D,XDELMN,   &
                        D,XIDC)
            IF(IERRG4.EQ.'YES')GO TO 9000
          ENDIF
        ENDIF
!
        IF(IGRDOR.EQ.'BEFO')THEN
          IF(IDRFRS.EQ.'ON')   &
            CALL DPDRFR(ICASPL,ICAS3D,IVGMSW,IHGMSW)
          IF(IERRG4.EQ.'YES')GO TO 9000
        ENDIF
!
!               *********************************************
!               **  STEP 41--                              **
!               **  DRAW A DATA-DEFINED GENERALIZED TRACE. **
!               **  THE TRACE MAY CONSIST OF ANY OR ALL    **
!               **  OF THE FOLLOWING--                     **
!               **     1. CHARACTERS                       **
!               **     2. LINES                            **
!               **     3. BARS                             **
!               **     4. SPIKES                           **
!               *********************************************
!
        IF(IDRTRS.EQ.'ON')GO TO 4100
        GO TO 4190
!
 4100   CONTINUE
!
        IFLGTR=1
        IF(ICASPL.EQ.'HIST')IFLGTR=0
        IF(ICASPL.EQ.'RIPH')IFLGTR=0
        IF(ICASPL.EQ.'HISO' .AND. ISET3.EQ.1)IFLGTR=0
        IF(ICASPL.EQ.'CUMH')IFLGTR=0
        IF(ICASPL.EQ.'BARP')IFLGTR=0
        IF(ICASPL.EQ.'ROOT')IFLGTR=0
        IF(ICASPL.EQ.'CUMR')IFLGTR=0
        IF(ICASPL.EQ.'BIHI')IFLGTR=0
        IF(ICASPL.EQ.'BIRO')IFLGTR=0
        IF(ICASPL.EQ.'CBIR')IFLGTR=0
        IF(ICASPL.EQ.'BIAS')IFLGTR=0
        IF(ICASPL.EQ.'IMAG')IFLGTR=0
        IF(ICASPL.EQ.'IMA2')IFLGTR=0
!
        IF(IFLGTR.EQ.1)THEN
          ICH2SW='ON'
          IF(ICH2PA.EQ.'OFF')ICH2SW='OFF'
          IF(ICH2PA.EQ.'BLAN')ICH2SW='OFF'
          IF(ICH2PA.EQ.'BL')ICH2SW='OFF'
          IF(ICH2PA.EQ.'    ')ICH2SW='OFF'
          IF(ICH2PA.EQ.'NONE')ICH2SW='OFF'
          IF(ICH2PA.EQ.'NO')ICH2SW='OFF'
!CCCC     THE FOLLOWING 2 LINES WAS ADDED FOR VECTOR PLOT AUGUST 1992
          IF(ICASPL.EQ.'VECT')ICH2PA='VECT'
          IF(ICASPL.EQ.'VVAR')ICH2PA='VECT'
!CCCC     THE FOLLOWING BLOCK WAS ADDED FOR VECTOR PLOTS TO AUTOMATICALLY
!CCCC     SET THE PRE-SORT OFF.   FEBRUARY 1994.
!CCCC     SET THE PRE-SORT OFF FOR VIOLIN PLOT.   FEBRUARY 2003.
!CCCC     SET THE PRE-SORT OFF FOR PARALLEL COORDINATES PLOT.  APRIL 2003.
!CCCC     SET THE PRE-SORT OFF FOR BIVARIATE NORMAL TOLERANCE REGION
!CCCC     SET THE PRE-SORT OFF FOR HOMOSCEDASTICITY PLOT
!CCCC     SET THE PRE-SORT OFF FOR EMPIRICAL QUANTILE PLOT
!CCCC     SET THE PRE-SORT OFF FOR NORMAL KERNEL DENSITY MIXTURE PLOT
!CCCC     SET THE PRE-SORT OFF FOR RIDGELINE PLOT
!CCCC         PLOT.  APRIL 2007.
          IF(ICASPL.EQ.'VECT'.OR.ICASPL.EQ.'VVAR'.OR.   &
             ICASPL.EQ.'DCON'.OR.ICASPL.EQ.'YCUB'.OR.   &
             ICASPL.EQ.'VIPL'.OR.ICASPL.EQ.'PCPL'.OR.   &
             ICASPL.EQ.'PCPG'.OR.ICASPL.EQ.'BNTR'.OR.   &
             ICASPL.EQ.'ASSO'.OR.ICASPL.EQ.'BNCR'.OR.   &
             ICASPL.EQ.'POIN'.OR.ICASPL.EQ.'SIEV'.OR.   &
             ICASPL.EQ.'LPLO'.OR.ICASPL.EQ.'FLUC'.OR.   &
             ICASPL.EQ.'HOMO'.OR.ICASPL.EQ.'EQFU'.OR.   &
             ICASPL.EQ.'NMPL'.OR.ICASPL.EQ.'BLP2'.OR.   &
             ICASPL.EQ.'BLP3'.OR.ICASPL.EQ.'DFIT'.OR.   &
             ICASPL.EQ.'RIPL'.OR.ICASPL.EQ.'RIPH'.OR.   &
             ICASPL.EQ.'TABU'.OR.ICASPL.EQ.'FLCP'.OR.   &
             ICASPL.EQ.'CSPL'.OR.ICASPL.EQ.'OCLH'.OR.   &
             ICASPL.EQ.'TABC'.OR.ICASPL.EQ.'WAPL')THEN
            ISORZZ='OFF'
          ELSE
            ISORZZ=ISORSW
          END IF
!
          IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
            WRITE(ICOUT,90004)
90004       FORMAT('BEFORE CALL DPDRCH')
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(ICH2SW.EQ.'ON')   &
          CALL DPDRCH(Y,X,PY,PX,NP,PY2,PX2,NP2,X3D,   &
                      ICASPL,ICAS3D,ISORZZ,ARE2BA,   &
                      ICH2PA,ICH2FO,ICH2CA,ICH2JU,ICH2DI,   &
                      ACH2AN,ICH2FI,ICH2CO,ICH2CR,ICH2CG,ICH2CB,   &
                      ICH2TY,PCH2HE,PCH2WI,PCH2TH,PCH2HO,PCH2VO,   &
                      ITEXSP,   &
                      PXMIN,PXMAX,PYMIN,PYMAX,   &
                      FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                      IX1TSC,IY1TSC,   &
                      IMPSW2,AMPSCH,AMPSCW)
!
!CCCC     THE FOLLOWING ANIMATION CHUNK WAS ADDED APRIL 1989
!
          IF(IANISW.EQ.'ON')THEN
            ICH2CO=IBACCO
            IF(ICH2SW.EQ.'ON')   &
              CALL DPDRCH(Y,X,PY,PX,NP,PY2,PX2,NP2,X3D,   &
                          ICASPL,ICAS3D,ISORZZ,ARE2BA,   &
                          ICH2PA,ICH2FO,ICH2CA,ICH2JU,ICH2DI,   &
                          ACH2AN,ICH2FI,ICH2CO,ICH2CR,ICH2CG,ICH2CB,   &
                          ICH2TY,PCH2HE,PCH2WI,PCH2TH,PCH2HO,PCH2VO,   &
                          ITEXSP,   &
                          PXMIN,PXMAX,PYMIN,PYMAX,   &
                          FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                          IX1TSC,IY1TSC,   &
                          IMPSW2,AMPSCH,AMPSCW)
          ENDIF
        ENDIF
!
        IF(ICASPL.EQ.'DCON'.OR.ICASPL.EQ.'VIPL'.OR.ICASPL.EQ.'PCPL'.OR.   &
           ICASPL.EQ.'PCPG'.OR.ICASPL.EQ.'BNTR'.OR.ICASPL.EQ.'ASSO'.OR.   &
           ICASPL.EQ.'BNCR'.OR.ICASPL.EQ.'POIN'.OR.                       &
           ICASPL.EQ.'SIEV'.OR.ICASPL.EQ.'LPLO'.OR.ICASPL.EQ.'FLUC'.OR.   &
           ICASPL.EQ.'HOMO'.OR.ICASPL.EQ.'EQFU'.OR.ICASPL.EQ.'NMPL'.OR.   &
           ICASPL.EQ.'BLP2'.OR.ICASPL.EQ.'BLP3'.OR.ICASPL.EQ.'DFIT'.OR.   &
           ICASPL.EQ.'RIPL'.OR.ICASPL.EQ.'WAPL'.OR.ICASPL.EQ.'RIPH'.OR.   &
           ICASPL.EQ.'CSPL'.OR.ICASPL.EQ.'OCLH'.OR.                       &
           ICASPL.EQ.'TABU'.OR.ICASPL.EQ.'FLCP'.OR.ICASPL.EQ.'TABC')THEN
          ISORZZ='OFF'
        ELSE
          ISORZZ=ISORSW
        END IF
        ILI2SW='ON'
        IF(ILI2PA.EQ.'OFF')ILI2SW='OFF'
        IF(ILI2PA.EQ.'BLAN')ILI2SW='OFF'
        IF(ILI2PA.EQ.'BL')ILI2SW='OFF'
        IF(ILI2PA.EQ.'    ')ILI2SW='OFF'
        IF(ILI2PA.EQ.'NONE')ILI2SW='OFF'
        IF(ILI2PA.EQ.'NO')ILI2SW='OFF'
!CCCC   THE FOLLOWING LINE WAS ADDED FOR HAZARD PLOT MAY 1989
        IF(ICASPL.EQ.'HAZA')ILI2SW='ON'
!CCCC   THE FOLLOWING LINE WAS ADDED FOR SYMBOL PLOT AUGUST 1992
        IF(ICASPL.EQ.'SYMB')ILI2SW='OFF'
        IF(IFLGTR.EQ.0)ILI2SW='OFF'
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90005)
90005     FORMAT('BEFORE CALL DPDRTR')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ILI2SW.EQ.'ON' .OR. ICASPL.EQ.'LPLO' .OR.   &
           ICASPL.EQ.'TABU' .OR. ICASPL.EQ.'FLUC' .OR.   &
           ICASPL.EQ.'FLCP' .OR. ICASPL.EQ.'DFIT' .OR.   &
           IRE2SW.EQ.'ON' .OR. IRE2FS.EQ.'ON' .OR.   &
          (IFLGTR.EQ.0 .AND. ISET3.LE.NUMSBR))   &
        CALL DPDRTR(Y,X,PY,PX,NP,PY2,PX2,NP2,PY3,PX3,NP3,X3D,   &
                    ICASPL,ICAS3D,ISORZZ,   &
                    ILI2PA,ILI2CO,ILI2CR,ILI2CG,ILI2CB,   &
                    ILI2TY,PLI2TH,   &
                    ARE2BA,ARE3BA,   &
                    IRE2FS,IRE2FC,IRE2FR,IRE2FG,IRE2FB,   &
                    IRE2PT,IRE2PL,IRE2PC,IRE2PR,IRE2PG,IRE2PB,   &
                    PRE2PT,PRE2PS,IRE2PZ,   &
                    PXMIN,PXMAX,PYMIN,PYMAX,   &
                    FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                    IX1TSC,IY1TSC)
!
!CCCC   THE FOLLOWING ANIMATION CHUNK WAS ADDED APRIL 1989
!
        IF(IANISW.EQ.'ON')THEN
          ILI2CO=IBACCO
          IRE2FC=IBACCO
          IRE2PC=IBACCO
          IF(ILI2SW.EQ.'ON' .OR. ICASPL.EQ.'LPLO' .OR.   &
             ICASPL.EQ.'TABU' .OR. ICASPL.EQ.'FLUC' .OR.   &
             ICASPL.EQ.'FLCP' .OR. ICASPL.EQ.'DFIT' .OR.   &
            (IFLGTR.EQ.0 .AND. ISET3.LE.NUMSBR) .OR.   &
             IRE2SW.EQ.'ON' .OR. IRE2FS.EQ.'ON')   &
             CALL DPDRTR(Y,X,PY,PX,NP,PY2,PX2,NP2,PY3,PX3,NP3,X3D,   &
                         ICASPL,ICAS3D,ISORZZ,   &
                         ILI2PA,ILI2CO,ILI2CR,ILI2CG,ILI2CB,   &
                         ILI2TY,PLI2TH,   &
                         ARE2BA,ARE3BA,   &
                         IRE2FS,IRE2FC,IRE2FR,IRE2FG,IRE2FB,   &
                         IRE2PT,IRE2PL,IRE2PC,IRE2PR,IRE2PG,IRE2PB,   &
                         PRE2PT,PRE2PS,IRE2PZ,   &
                         PXMIN,PXMAX,PYMIN,PYMAX,   &
                         FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                         IX1TSC,IY1TSC)
        ENDIF
!
!4119   CONTINUE
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90006)
90006     FORMAT('BEFORE CALL DPDRBA')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IBA2SW.EQ.'ON'.OR.   &
          (ICASPL.EQ.'HIST'.AND.ISET3.GT.NUMSBR).OR.                    &
          (ICASPL.EQ.'HISO'.AND.ISET3.EQ.1).OR.                         &
           ICASPL.EQ.'CUMH' .OR. ICASPL.EQ.'BARP' .OR.                  &
           ICASPL.EQ.'ROOT' .OR. ICASPL.EQ.'CUMR' .OR.                  &
           ICASPL.EQ.'BIRO' .OR. ICASPL.EQ.'CBIR' .OR.                  &
           ICASPL.EQ.'RIPH' .OR.                                        &
           ICASPL.EQ.'BIAS' .OR. ICASPL.EQ.'BIHI')                      &
        CALL DPDRBA(Y,X,X3D,PY,PX,PX3,NP,                               &
                    ICASPL,ICAS3D,ISORSW,                               &
                    IBA2SW,ABA2WI,ABA2BA,                               &
                    IBA2BL,IBA2BC,IBA2BR,IBA2BG,IBA2BB,PBA2BT,          &
                    IBA2FS,IBA2FC,IBA2FR,IBA2FG,IBA2FB,                 &
                    IBA2PT,IBA2PL,IBA2PC,IBA2PR,IBA2PG,IBA2PB,IBA2TY,   &
                    IBA2DI,PBA2PS,PBA2PT,                               &
                    XDELMN,                                             &
                    PXMIN,PXMAX,PYMIN,PYMAX,                            &
                    FX1MIN,FX1MAX,FY1MIN,FY1MAX,                        &
                    IX1TSC,IY1TSC)
!
!CCCC   THE FOLLOWING ANIMATION CHUNK WAS ADDED APRIL 1989
!
        IF(IANISW.EQ.'ON')THEN
          IBA2BC=IBACCO
          IBA2FC=IBACCO
          IBA2PC=IBACCO
          IF(IBA2SW.EQ.'ON'.OR.                                           &
            (ICASPL.EQ.'HIST'.AND.ISET3.GT.NUMSBR).OR.                    &
            (ICASPL.EQ.'HISO'.AND.ISET3.EQ.1).OR.                         &
             ICASPL.EQ.'CUMH' .OR. ICASPL.EQ.'BARP' .OR.                  &
             ICASPL.EQ.'ROOT' .OR. ICASPL.EQ.'CUMR' .OR.                  &
             ICASPL.EQ.'BIRO' .OR. ICASPL.EQ.'CBIR' .OR.                  &
             ICASPL.EQ.'RIPH' .OR.                                        &
             ICASPL.EQ.'BIAS' .OR. ICASPL.EQ.'BIHI')                      &
          CALL DPDRBA(Y,X,X3D,PY,PX,PX3,NP,                               &
                      ICASPL,ICAS3D,ISORSW,                               &
                      IBA2SW,ABA2WI,ABA2BA,                               &
                      IBA2BL,IBA2BC,IBA2BR,IBA2BG,IBA2BB,PBA2BT,          &
                      IBA2FS,IBA2FC,IBA2FR,IBA2FG,IBA2FB,                 &
                      IBA2PT,IBA2PL,IBA2PC,IBA2PR,IBA2PG,IBA2PB,IBA2TY,   &
                      IBA2DI,PBA2PS,PBA2PT,                               &
                      XDELMN,                                             &
                      PXMIN,PXMAX,PYMIN,PYMAX,                            &
                      FX1MIN,FX1MAX,FY1MIN,FY1MAX,                        &
                      IX1TSC,IY1TSC)
        ENDIF
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90007)
90007     FORMAT('BEFORE CALL DPDRSP')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ISP2SW.EQ.'ON')   &
          CALL DPDRSP(Y,X,PY,PX,NP,   &
                      ICASPL,ICAS3D,ISORSW,   &
                      ISP2LI,ISP2CO,ISP2CR,ISP2CG,ISP2CB,   &
                      ISP2DI,PSP2TH,ASP2BA,   &
                      PXMIN,PXMAX,PYMIN,PYMAX,   &
                      FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                      IX1TSC,IY1TSC)
!
!CCCC   THE FOLLOWING ANIMATION CHUNK WAS ADDED APRIL 1989
!
        IF(IANISW.EQ.'ON')THEN
          ISP2CO=IBACCO
          IF(ISP2SW.EQ.'ON')   &
            CALL DPDRSP(Y,X,PY,PX,NP,   &
                        ICASPL,ICAS3D,ISORSW,   &
                        ISP2LI,ISP2CO,ISP2CR,ISP2CG,ISP2CB,   &
                        ISP2DI,PSP2TH,ASP2BA,   &
                        PXMIN,PXMAX,PYMIN,PYMAX,   &
                        FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                        IX1TSC,IY1TSC)
!
        ENDIF
!
!       MARCH 2008: FOLLOWING CODE GENERATES "IMAGE" PLOTS
!
        IF(ICASPL.EQ.'IMAG' .OR. ICASPL.EQ.'IMA2')THEN
          CALL DPDRIM(X,Y,PY,PX,PY2,PX2,NP,ICASCO,PCH2HE)
        ENDIF
!
 4190   CONTINUE
!
!               ********************************************************
!               **  STEP 56--                                         **
!               **  DRAW THE FRAME, TICS, TIC LABELS, AND GRID LINES  **
!               ********************************************************
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90008)
90008     FORMAT('BEFORE CALL DPDRFR')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IGRDOR.EQ.'AFTE')THEN
          IF(IDRFRS.EQ.'ON')   &
            CALL DPDRFR(ICASPL,ICAS3D,IVGMSW,IHGMSW)
          IF(IERRG4.EQ.'YES')GO TO 9000
        ENDIF
!
!               *********************************
!               **  STEP 57--                  **
!               **  DRAW THE LABELS AND TITLE  **
!               *********************************
!
 5700   CONTINUE
!
        IF(IWRLAS.EQ.'ON')THEN
          ITITCV(1)=ITITFO
          ITITCV(2)=ITITCA
          ITITCV(3)=ITITFI
          ITITCV(4)=ITITCO
          PTITRV(1)=PTITHE
          PTITRV(2)=PTITWI
          PTITRV(3)=PTITVG
          PTITRV(4)=PTITHG
          PTITRV(5)=PTITTH
          PTITRV(6)=PTITDS
          PTITRV(7)=REAL(ITITC2(1))
          PTITRV(8)=REAL(ITITC2(2))
          PTITRV(9)=REAL(ITITC2(3))
!
          IX1LCV(1)=IX1LFO
          IX1LCV(2)=IX1LCA
          IX1LCV(3)=IX1LFI
          IX1LCV(4)=IX1LCO
          IX1LCV(5)=IX1LJU
          IX1LCV(6)=IX1LDI
          PX1LRV(1)=PX1LHE
          PX1LRV(2)=PX1LWI
          PX1LRV(3)=PX1LVG
          PX1LRV(4)=PX1LHG
          PX1LRV(5)=PX1LTH
          PX1LRV(6)=PX1LDS
          PX1LRV(7)=PX1LOF
          PX1LRV(8)=PX1LAN
          PX1LRV(9)=PX1LXC
          PX1LRV(10)=PX1LYC
          PX1LRV(11)=REAL(IX1LC2(1))
          PX1LRV(12)=REAL(IX1LC2(2))
          PX1LRV(13)=REAL(IX1LC2(3))
!
          IX2LCV(1)=IX2LFO
          IX2LCV(2)=IX2LCA
          IX2LCV(3)=IX2LFI
          IX2LCV(4)=IX2LCO
          IX2LCV(5)=IX2LJU
          IX2LCV(6)=IX2LDI
          PX2LRV(1)=PX2LHE
          PX2LRV(2)=PX2LWI
          PX2LRV(3)=PX2LVG
          PX2LRV(4)=PX2LHG
          PX2LRV(5)=PX2LTH
          PX2LRV(6)=PX2LDS
          PX2LRV(7)=PX2LOF
          PX2LRV(8)=PX2LAN
          PX2LRV(9)=PX2LXC
          PX2LRV(10)=PX2LYC
          PX2LRV(11)=REAL(IX2LC2(1))
          PX2LRV(12)=REAL(IX2LC2(2))
          PX2LRV(13)=REAL(IX2LC2(3))
!
          IX3LCV(1)=IX3LFO
          IX3LCV(2)=IX3LCA
          IX3LCV(3)=IX3LFI
          IX3LCV(4)=IX3LCO
          IX3LCV(5)=IX3LJU
          IX3LCV(6)=IX3LDI
          PX3LRV(1)=PX3LHE
          PX3LRV(2)=PX3LWI
          PX3LRV(3)=PX3LVG
          PX3LRV(4)=PX3LHG
          PX3LRV(5)=PX3LTH
          PX3LRV(6)=PX3LDS
          PX3LRV(7)=PX3LOF
          PX3LRV(8)=PX3LAN
          PX3LRV(9)=PX3LXC
          PX3LRV(10)=PX3LYC
          PX3LRV(11)=REAL(IX3LC2(1))
          PX3LRV(12)=REAL(IX3LC2(2))
          PX3LRV(13)=REAL(IX3LC2(3))
!
          IY1LCV(1)=IY1LFO
          IY1LCV(2)=IY1LCA
          IY1LCV(3)=IY1LFI
          IY1LCV(4)=IY1LCO
          IY1LCV(5)=IY1LJU
          IY1LCV(6)=IY1LDI
          PY1LRV(1)=PY1LHE
          PY1LRV(2)=PY1LWI
          PY1LRV(3)=PY1LVG
          PY1LRV(4)=PY1LHG
          PY1LRV(5)=PY1LTH
          PY1LRV(6)=PY1LDS
          PY1LRV(7)=PY1LOF
          PY1LRV(8)=PY1LAN
          PY1LRV(9)=PY1LXC
          PY1LRV(10)=PY1LYC
          PY1LRV(11)=REAL(IY1LC2(1))
          PY1LRV(12)=REAL(IY1LC2(2))
          PY1LRV(13)=REAL(IY1LC2(3))
!
          IY2LCV(1)=IY2LFO
          IY2LCV(2)=IY2LCA
          IY2LCV(3)=IY2LFI
          IY2LCV(4)=IY2LCO
          IY2LCV(5)=IY2LJU
          IY2LCV(6)=IY2LDI
          PY2LRV(1)=PY2LHE
          PY2LRV(2)=PY2LWI
          PY2LRV(3)=PY2LVG
          PY2LRV(4)=PY2LHG
          PY2LRV(5)=PY2LTH
          PY2LRV(6)=PY2LDS
          PY2LRV(7)=PY2LOF
          PY2LRV(8)=PY2LAN
          PY2LRV(9)=PY2LXC
          PY2LRV(10)=PY2LYC
          PY2LRV(11)=REAL(IY2LC2(1))
          PY2LRV(12)=REAL(IY2LC2(2))
          PY2LRV(13)=REAL(IY2LC2(3))
!
          IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
            WRITE(ICOUT,90009)
90009       FORMAT('BEFORE CALL DPWRLA')
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          CALL DPWRLA(PXMIN,PYMIN,PXMAX,PYMAX,   &
                      ITITTE,NCTITL,ITITCV,PTITRV,   &
                      IX1LTE,NCX1LA,IX1LCV,PX1LRV,   &
                      IX2LTE,NCX2LA,IX2LCV,PX2LRV,   &
                      IX3LTE,NCX3LA,IX3LCV,PX3LRV,   &
                      IY1LTE,NCY1LA,IY1LCV,PY1LRV,   &
                      IY2LTE,NCY2LA,IY2LCV,PY2LRV,   &
                      ISYMBL,ISPAC,   &
                      IMPSW2,AMPSCH,AMPSCW,   &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,   &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISEQSW,NUMSEQ)
!
        ENDIF
!
!               ***********************************************************
!               **  STEP 58--                                            **
!               **  DRAW THE LEGENDS, LEGEND BOXES, SEGMENTS AND ARROWS  **
!               ***********************************************************
!
!CCCC   THE PLEGTH ARGUMENT WAS ADDED FEBRUARY 1989 (ALAN)
!CCCC   AUGUST 1995.  ADD ILGENA TO LIST
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90010)
90010     FORMAT('BEFORE CALL DPWRLE')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IWRLES.EQ.'ON')   &
          CALL DPWRLE(ILEGTE,ILEGST,ILEGSP,   &
                      ILEGNA,PLEGXC,PLEGYC,ILEGFO,ILEGCA,ILEGJU,   &
                      ILEGDI,ALEGAN,ILEGFI,ILEGCO,ILEGC2,ILEGUN,   &
                      PLEGHE,PLEGWI,PLEGVG,PLEGHG,PLEGTH,NUMLEG,   &
                      PBOXXC,PBOXYC,IBOBCO,IBOBC2,   &
                      IBOPPA,IBOBPA,PBOPTH,PBOPGA,IBOFPA,   &
                      IBOFCO,IBOFC2,   &
                      PBOFTH,PBOSHE,PBOSWI,NUMBOX,   &
                      PARRXC,PARRYC,IARRPA,IARRCO,IARRC2,PARRTH,   &
                      PARHLE,PARHWI,NUMARR,   &
                      PSEGXC,PSEGYC,ISEGPA,ISEGCO,ISEGC2,   &
                      PSEGTH,NUMSEG,   &
                      IMPSW2,AMPSCH,AMPSCW,   &
                      IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,   &
                      IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISYMBL,ISPAC)
!
!               ****************************************************************
!               **  STEP 61--                                                 **
!               **  CARRY OUT POST-PLOT OPERATIONS--                          **
!               **  COPYING THE SCREEN, MOVING CURSOR TO HOME POSITION, ETC.  **
!               ****************************************************************
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90011)
90011     FORMAT('BEFORE CALL DPCLPL')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ICLG2S.EQ.'ON')   &
          CALL DPCLPL(ICOPSW,NUMCOP,   &
                      PGRAXF,PGRAYF,   &
                      IGRASW,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                      PDIAHE,PDIAWI,PDIAVG,PDIAHG)
!
!               ***************************************************
!               **  STEP 62--                                    **
!               **  CARRY OUT CLOSING OPERATIONS                 **
!               **  ON THE DEVICES AND ON THE GRAPHICS SOFTWARE  **
!               ***************************************************
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90012)ICLGRS
90012     FORMAT('BEFORE CALL DPCLDE: ICLGRS = ',A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ICLGRS.EQ.'ON')CALL DPCLDE
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'OTG2')THEN
          WRITE(ICOUT,90014)ISQUAR,ICASPL,PSAVE
90014     FORMAT('AFTER CALL DPCLDE: ISQUAR,ICASPL,PSAVE = ',   &
                 2(A4,2X),G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ISQUAR.EQ.'ON' .OR. ICASPL.EQ.'PIEC' .OR.   &
           ICASPL.EQ.'ROSE')THEN
          PXMAX=PSAVE
        ENDIF
!
 2100 CONTINUE
      IF(IWRLAS.EQ.'ON'.AND.ISEQSW.EQ.'ON')NUMSEQ=NUMSEQ+1
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'OTG2')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF PLOTG2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IMANUF,IMODEL
 9012 FORMAT('IMANUF,IMODEL = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IBUGG4,ISUBG4,IERRG4
 9015 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
!CCCC THE FOLLOWING 2 LINES WERE ADDED   MAY 1992
      WRITE(ICOUT,9016)IPL2CS
 9016 FORMAT('IPL2CS = ',A4)
      CALL DPWRST('XXX','BUG ')
!  APRIL 1992.  FIX TYPO IN FOLLOWING 2 LINES
!CCCC WRITE(ICOUT,9017)NUMSET,ISET3,ISET3S
!9017 FORMAT('NUMSET,ISET3,ISET3S = ',3I8)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)NUMSET,ISET,ISET3
 9017 FORMAT('NUMSET,ISET,ISET3 = ',3I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9018)ICASPL,ICAS3D
 9018 FORMAT('ICASPL,ICAS3D = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9019)ISQUAR,XDELMN
 9019 FORMAT('ISQUAR,XDELMN = ',A4,2X,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)ILI2PA,ILI2SW
 9021 FORMAT('ILI2PA,ILI2SW = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)ICH2PA,ICH2SW
 9022 FORMAT('ICH2PA,ICH2SW = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9031)IBA2SW,ABA2WI,ABA2BA
 9031 FORMAT('IBA2SW,ABA2WI,ABA2BA = ',A4,2X,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9032)IBA2BL,IBA2BC,PBA2BT
 9032 FORMAT('IBA2BL,IBA2BC,PBA2BT = ',A4,2X,A4,2X,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9033)IBA2FS,IBA2FC
 9033 FORMAT('IBA2FS,IBA2FC = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9034)IBA2PT,IBA2PL,IBA2PC,IBA2TY,PBA2PS,PBA2PT
 9034 FORMAT('IBA2PT,IBA2PL,IBA2PC,IBA2TY,PBA2PS,PBA2PT = ',   &
      A4,2X,A4,2X,A4,2X,A4,2X,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9035)ITEXSY,ITEXSP
 9035 FORMAT('ITEXSY,ITEXSP = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9036)ISYMBL,ISPAC
 9036 FORMAT('ISYMBL,ISPAC = ',A16,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9041)IREPCH
 9041 FORMAT('IREPCH = ',A1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9043)IBACCO,IANISW
 9043 FORMAT('IBACCO,IANISW = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE PLOTG2
      SUBROUTINE PLOTG3(XRAW,YRAW,ZRAW,NP,DSIZE,   &
                        PX,PY,PZ,PX2,PY2,PZ2,NP2,PX3,PY3,NP3,NUMSET,   &
                        D,XIDC,   &
                        ICASPL,ICAS3D,ISQUAR,   &
                        IVGMSW,IHGMSW,   &
                        XDELMN,YDELMN,ZDELMN,   &
                        ISTEP,ISUBST,ISET,ISET3,ICH3PA,   &
                        IOPGRS,IOPG2S,IDELIS,IDRFRS,IWRLAS,IWRLES,   &
                        IDRTRS,ICLG2S,ICLGRS,ICAPSW,   &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,   &
                        IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,ISWTCH)
!
!     PURPOSE--GENERATE A COMPLETE 3-D PLOT OF A SINGLE TRACE OF Y VERSUS X
!              (INCLUDING FRAME, TICS, LEGENDS, ETC.)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED         --SEPTEMBER 1988  BIHISTOGRAM
!     UPDATED         --MARCH     1990  X11 PATCH
!     UPDATED         --AUGUST    1992  DPWRLE PARAMETERS, BOX NAMES
!     UPDATED         --AUGUST    1992  SOME PLOTG2 BUG FIXES INCORPORATED
!     UPDATED         --SEPTEMBER 1993  3-D FRAMES
!     UPDATED         --AUGUST    1995  ARGUMENT LIST TO DPWRLE
!     UPDATED         --MAY       1996  DIMENSION FOR XT, ZT
!     UPDATED         --JULY      1996  ADD IDFONT
!     UPDATED         --OCTOBER   1996  QWIN PATCH
!     UPDATED         --APRIL     1997. SUPPORT FOR AUTOMATICALLY
!                                       SAVING X11 PIXMAPS
!     UPDATED         --DECEMBER  1997. GENERALIZE PIXMAPS TO OTHER
!                                       DEVICE
!     UPDATED         --NOVEMBER  1999. ARGUMENT TO DPWRLA
!     UPDATED         --FEBRUARY  2006. DEVICE 1 LATEX OUTPUT TO
!                                       CAPTURE FILE
!     UPDATED         --JANUARY   2018. CALL LIST TO DPDELI
!     UPDATED         --DECEMBER  2018. SUPPORT FOR "DEVICE ... SCALE"
!                                       COMMAND
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----FOR NON-COMMON VARIABLES-----------------------------------------
!
      CHARACTER*4 ICONT
      CHARACTER*4 ISQUAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 IVGMSW
      CHARACTER*4 IHGMSW
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*24 ICH3PA
!
      CHARACTER*4 ILI2SW
      CHARACTER*4 ILI2PA
      CHARACTER*4 ILI2CO
      CHARACTER*4 ILI2TY
!
      CHARACTER*4 ICH2SW
      CHARACTER*24 ICH2PA
      CHARACTER*4 ICH2FO
      CHARACTER*4 ICH2CA
      CHARACTER*4 ICH2JU
      CHARACTER*4 ICH2DI
      CHARACTER*4 ICH2FI
      CHARACTER*4 ICH2CO
      CHARACTER*4 ICH2TY
!
      CHARACTER*4 IFI2SW
      CHARACTER*4 IFI2PA
      CHARACTER*4 IFI2CO
!
      CHARACTER*4 IPA2SW
      CHARACTER*4 IPA2PA
      CHARACTER*4 IPA2LI
      CHARACTER*4 IPA2CO
!
      CHARACTER*4 ISP2SW
      CHARACTER*4 ISP2LI
      CHARACTER*4 ISP2CO
      CHARACTER*4 ISP2DI
!
      CHARACTER*4 IBA2SW
      CHARACTER*4 IBA2BL
      CHARACTER*4 IBA2BC
      CHARACTER*4 IBA2FS
      CHARACTER*4 IBA2FC
      CHARACTER*4 IBA2PT
      CHARACTER*4 IBA2PL
      CHARACTER*4 IBA2PC
      CHARACTER*4 IBA2TY
      CHARACTER*4 IBA2DI
!
      CHARACTER*4 IRE2SW
      CHARACTER*4 IRE2BL
      CHARACTER*4 IRE2BC
      CHARACTER*4 IRE2FS
      CHARACTER*4 IRE2FC
      CHARACTER*4 IRE2PT
      CHARACTER*4 IRE2PL
      CHARACTER*4 IRE2PC
!
      CHARACTER*4 IMA2SW
      CHARACTER*4 IMA2BL
      CHARACTER*4 IMA2BC
      CHARACTER*4 IMA2FS
      CHARACTER*4 IMA2FC
      CHARACTER*4 IMA2PT
      CHARACTER*4 IMA2PL
      CHARACTER*4 IMA2PC
!
      CHARACTER*4 ITE2SW
      CHARACTER*4 ITE2BL
      CHARACTER*4 ITE2BC
      CHARACTER*4 ITE2FS
      CHARACTER*4 ITE2FC
      CHARACTER*4 ITE2PT
      CHARACTER*4 ITE2PL
      CHARACTER*4 ITE2PC
!
      CHARACTER*4 IOPGRS
      CHARACTER*4 IOPG2S
      CHARACTER*4 IDELIS
      CHARACTER*4 IDRFRS
      CHARACTER*4 IWRLAS
      CHARACTER*4 IWRLES
