!CCCC           IF(IPXMCM(NUMPXM).EQ.' ')THEN
!CCCC             IPXMCM(NUMPXM)(1:128)=IPXMFN(NUMPXM)(1:128)
!CCCC           ENDIF
!CCCC           GO TO 2099
!CCCC         ENDIF
!CCCC      ENDIF
         ENDIF
      ENDIF
 2099 CONTINUE
!
      DO 2100 IDEV=1,NUMDEV
!
      ICONT=IDCONT(IDEV)
!CCCC THE FOLLOWING LINE WAS INSERTED AUGUST 1992. (ALAN)
      IPOWER=IDPOWE(IDEV)
      IMANUF=IDMANU(IDEV)
      IMODEL=IDMODE(IDEV)
      IMODE2=IDMOD2(IDEV)
      IMODE3=IDMOD3(IDEV)
      IGCODE=IDCODE(IDEV)
      IGUNIT=IDUNIT(IDEV)
!
!CCCC FEBRUARY 2006: DEVICE 1 LATEX TO CAPTURE FILE
!
!     APRIL 2006: COMMENT OUT THIS SECTION FOR NOW, HANDLED
!                 ELSEWHERE (IMACNU NOT PASSED TO THIS ROUTINE)
!
!CCCC IF(IDEV.EQ.1 .AND. IMANUF.EQ.'LATE' .AND.
!CCCC1   IGUNIT.EQ.IMACNU)THEN
!CCCC   IGUNIT=IMACNU
!CCCC ENDIF
!
      NUMHPP=IDNHPP(IDEV)
      ANUMHP=NUMHPP
      NUMVPP=IDNVPP(IDEV)
      ANUMVP=NUMVPP
!CCCC THE FOLLOWING 2 LINES WERE INSERTED AUGUST 1992. (ALAN)
      IOFFSV=IDNVOF(IDEV)
      IOFFSH=IDNHOF(IDEV)
      IGCOLO=IDCOLO(IDEV)
      IGBAUD=IDBAUD(IDEV)
      ISOFT=IDSOFT(IDEV)
      ISOFT2=IDSOF2(IDEV)
      ISOFT3=IDSOF3(IDEV)
!CCCC THE FOLLOWING LINE WAS INSERTED JULY 1996. (ALAN)
      IGFONT=IDFONT(IDEV)
      PCHSCA=PDSCAL(IDEV)
!
      IF(ICONT.EQ.'OFF')GO TO 2100
!
!CCCC THE FOLLOWING LINE WAS INSERTED AUGUST 1992. (ALAN)
!CCCC IF HAVE   DEVICE 2 OFF    COMMAND,
!CCCC DO NOT SET DEFAULT DEVICE.
!CCCC SET POWER OFF, WHEN POWER OFF DON'T DO PLOT.  DEVICE 2 ON  ???
!CCCC WILL TURN ON WHATEVER CURRENT DEVICE IS.
!CCCC THIS ALLOWS PLOT FILE TO BE TOGGLED ON AND OFF CONVIENTLY.
      IF(IPOWER.EQ.'OFF')GO TO 2100
      IF(ISQUAR.EQ.'ON')GO TO 2110
      IF(ICASPL.EQ.'PIEC')GO TO 2110
      IF(ICASPL.EQ.'ROSE')GO TO 2110
      GO TO 2190
 2110 CONTINUE
      PSAVE=PXMAX
      PYDEL=PYMAX-PYMIN
      PXDEL=PYDEL*(ANUMVP/ANUMHP)
      PXMAX=PXMIN+PXDEL
 2190 CONTINUE
!
!               ***************************************************
!               **  STEP 31--                                    **
!               **  CARRY OUT OPENING OPERATIONS                 **
!               **  ON THE DEVICES AND ON THE GRAPHICS SOFTWARE  **
!               ***************************************************
!
      IF(IOPGRS.EQ.'ON')CALL DPOPDE
!
!               ****************************************************************
!               **  STEP 32--
!               **  CARRY OUT MINOR PRE-PLOT ACTIVITIES--
!               **  ERASE THE SCREEN, FILL  THE BACKGROUND, RING THE BELL, ETC.
!               ****************************************************************
!
      IF(IOPG2S.EQ.'ON')   &
      CALL DPOPPL(IGRASW,IBELSW,NUMRIN,IERASW,IBACCO,IBACC2)
!CCCC FOLLOWING LINES ADDED MARCH, 1990 FOR X11.  X11 LIBRARY CAN
!CCCC DYNAMICALLY MODIFY THE PICTURE POINTS.  THE ERASE SCREEN ROUTINE
!CCCC GETS THE UPDATED VALUES.
      IF(IMANUF.EQ.'X11')THEN
        NUMVPP=INT(ANUMVP+0.5)
        NUMHPP=INT(ANUMHP+0.5)
        IDNVPP(IDEV)=NUMVPP
        IDNHPP(IDEV)=NUMHPP
      ELSEIF(IMANUF.EQ.'CAIR' .AND. IMODEL.EQ.'X11 ')THEN
!CCCC END CHANGES
!CCCC FOLLOWING LINES ADDED OCTOBER, 1996 FOR QWIN.  QWIN LIBRARY CAN
!CCCC DYNAMICALLY MODIFY THE PICTURE POINTS.  THE ERASE SCREEN ROUTINE
!CCCC GETS THE UPDATED VALUES.
      ELSEIF(IMANUF.EQ.'QWIN')THEN
        NUMVPP=INT(ANUMVP+0.5)
        NUMHPP=INT(ANUMHP+0.5)
        IDNVPP(IDEV)=NUMVPP
        IDNHPP(IDEV)=NUMHPP
      ENDIF
!CCCC END CHANGES
