      IF(NP.LE.0)GO TO 5700
!
!               **************************************************
!               **  STEP 34--                                   **
!               **  FOR 3-D PLOTS,                              **
!               **  FOR THE FIRST TIME THROUGH,                 **
!               **  COMPUTE MIN'S, MAX'S, MID'S, AND RANGES.    **
!               **  COMPUTE EYE COORDINATES AND ORIGINS.        **
!               **************************************************
!
      IF(IDELIS.EQ.'ON')GO TO 3400
      GO TO 3790
