      CALL D3DELI(XRAW,YRAW,ZRAW,NP,   &
                  XEYE0,YEYE0,ZEYE0,   &
                  XORIG,YORIG,ZORIG,   &
                  X3DMIN,Y3DMIN,Z3DMIN,   &
                  X3DMAX,Y3DMAX,Z3DMAX,   &
                  X3DMID,Y3DMID,Z3DMID,   &
