        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9033)IBA2FS,IBA2FC
 9033   FORMAT('IBA2FS,IBA2FC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9034)IBA2PT,IBA2PL,IBA2PC,IBA2TY,PBA2PS,PBA2PT
 9034   FORMAT('IBA2PT,IBA2PL,IBA2PC,IBA2TY,PBA2PS,PBA2PT = ',   &
              4( A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PLOTG3
      SUBROUTINE PLOTN(Y,X,N,ICHAR,MAXCHA,ICASPL,ICAS3D,   &
      ITITTE,NCTITL,   &
      IX1LTE,NCX1LA,   &
      IX2LTE,NCX2LA,   &
      IX3LTE,NCX3LA,   &
      IY1LTE,NCY1LA,   &
      IY2LTE,NCY2LA,   &
      GX1MIN,GX1MAX,GY1MIN,GY1MAX,   &
      IERASW,IBUGU2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE YIELDS A NARROW-WIDTH (68-CHARACTER)
!              PLOT OF Y(I) VERSUS X(I).
!     NOTE--THE NARROW WIDTH OF THIS PLOT
!           MAKES IT APPROPRIATE FOR
!           USE ON A (DISCRETE) TERMINAL.
!     INPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS
!                               TO BE PLOTTED VERTICALLY.
!                    --X      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS
!                               TO BE PLOTTED HORIZONTALLY.
!                    --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR X.
!                    --ICHAR  = THE HOLLERITH VECTOR OF
!                               CHARACTERS (ONLY THE
!                               FIRST OF WHICH WILL BE USED)
!                    --MAXCHA = THE INTEGER NUMBER OF
!                               CHARACTERS IN ICHAR(.)
!     OUTPUT--A NARROW-WIDTH (68-CHARACTER) TERMINAL PLOT
!             OF Y(I) VERSUS I.
!             THE BODY OF THE PLOT (NOT COUNTING AXIS VALUES
!             AND MARGINS) IS 17 ROWS (LINES) AND 41 COLUMNS.
!     PRINTING--YES.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT THE STORAGE REQUIREMENTS FOR THIS
!              (AND THE OTHER) TERMINAL PLOT SUBROUTINESS ARE .
!              VERY SMALL.
!              THIS IS DUE TO THE 'ONE LINE AT A TIME' ALGORITHM
!              EMPLOYED FOR THE PLOT.
!     REFERENCES--NONE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--FEBRUARY  1974.
!     UPDATED         --APRIL     1974.
!     UPDATED         --OCTOBER   1974.
!     UPDATED         --OCTOBER   1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1977.
!     UPDATED         --JUNE      1978.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --JANUARY   1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICHAR
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
!
      CHARACTER*4 ITITTE
      CHARACTER*4 IX1LTE
      CHARACTER*4 IX2LTE
      CHARACTER*4 IX3LTE
      CHARACTER*4 IY1LTE
      CHARACTER*4 IY2LTE
!
      CHARACTER*4 IERASW
      CHARACTER*4 IBUGU2
      CHARACTER*4 IERROR
!
      CHARACTER*4 IBLANK
      CHARACTER*4 IHYPHE
      CHARACTER*4 IALPHI
      CHARACTER*4 IALPHX
      CHARACTER*4 ILABT
      CHARACTER*4 ILABY1
      CHARACTER*4 ILABX1
      CHARACTER*4 ILABX2
      CHARACTER*4 ILABX3
      CHARACTER*4 JPLOTC
      CHARACTER*4 ILINE
      CHARACTER*4 ICASP2
      CHARACTER*4 IAXISC
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION ICHAR(*)
!
      DIMENSION ITITTE(*)
      DIMENSION IX1LTE(*)
      DIMENSION IX2LTE(*)
      DIMENSION IX3LTE(*)
      DIMENSION IY1LTE(*)
      DIMENSION IY2LTE(*)
!
      DIMENSION ILABT(132)
      DIMENSION ILABY1(132)
      DIMENSION ILABX1(132)
      DIMENSION ILABX2(132)
      DIMENSION ILABX3(132)
!
      DIMENSION ILINE(72)
      DIMENSION AILABL(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PLOT'
      ISUBN2='N   '
      IERROR='NO'
!
      IBLANK=' '
      IHYPHE='-'
      IALPHI='I'
      IALPHX='X'
!
      IMAXT=0
      IMAXX1=0
      IMAXX2=0
      IMAXX3=0
!
      IF(IBUGU2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF PLOTN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,MAXCHA,NCY2LA,IBUGU2,IBUGU3,IBUGU4
   52   FORMAT('N,MAXCHA,NCY2LA,IBUGU2,IBUGU3,IBUGU4 = ',   &
               3I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)Y(1),X(1)
   53   FORMAT('Y(1),X(1) = ',2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)Y(N),X(N)
   54   FORMAT('Y(N),X(N) = ',2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ICASPL,ICAS3D
   55   FORMAT('ICASPL,ICAS3D = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)GX1MIN,GX1MAX,GY1MIN,GY1MAX
   73   FORMAT('GX1MIN,GX1MAX,GY1MIN,GY1MAX = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,75)IY2LTE(1)
   75   FORMAT('IY2LTE(1) = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!               ***************************************************************
!               **  STEP 2--                                                 **
!               **  DEFINE THE NUMBER OF ROWS AND COLUMNS WITHIN THE PLOT--  **
!               **  THIS HAS BEEN SET TO 21 ROWS AND 41 COLUMNS.             **
!               ***************************************************************
!
!CCCC NUMROW=21
      NUMROW=17
      NUMCOL=41
!
      ANUMR=NUMROW
      ANUMRM=NUMROW-1
      ANUMCM=NUMCOL-1
                                                                                                                                  
      NUMR25=(NUMROW/4)+1
      NUMR50=(NUMROW/2)+1
      NUMR75=3*(NUMROW/4)+1
      IXDEL=(NUMCOL-1)/4
!
!               ********************************
!               **  STEP 2.2--                **
!               **  DEFINE THE TYPE OF PLOT.  **
!               ********************************
!
      ICASP2=ICASPL
      IF(ICASPL.EQ.'MDBP')ICASP2='BOXP'
      IF(ICASPL.EQ.'MEBP')ICASP2='BOXP'
      IF(ICASPL.EQ.'VIPL')ICASP2='BOXP'
      IF(ICASPL.EQ.'MDIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MEIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MRIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MMIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'1SE ')ICASP2='IPLO'
      IF(ICASPL.EQ.'2SE ')ICASP2='IPLO'
      IF(ICASPL.EQ.'1SD ')ICASP2='IPLO'
      IF(ICASPL.EQ.'2SD ')ICASP2='IPLO'
      IF(ICASPL.EQ.'MDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'MECL')ICASP2='IPLO'
      IF(ICASPL.EQ.'TMCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'BWCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'SDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CVCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CRCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CQCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'DMEA')ICASP2='IPLO'
      IF(ICASPL.EQ.'DPRO')ICASP2='IPLO'
      IF(ICASPL.EQ.'NTOL')ICASP2='IPLO'
      IF(ICASPL.EQ.'NPRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'BWRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'TMRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'AGCL')ICASP2='IPLO'
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  PREPARE THE TITLE LINE, THE Y-AXIS LABEL,       **
!               **  AND THE 3 HORIZONTAL AXIS LABELS FOR PRINTING.  **
!               ******************************************************
!
      YMIDL=NUMROW/2
      XMIDL=22+NUMCOL/2
!
      YFACT=1.0
      XFACT=1.0
!
      ILENT=NCTITL
      ILENY1=NCY1LA
      ILENX1=NCX1LA
      ILENX2=NCX2LA
      ILENX3=NCX3LA
!
      ALENT=ILENT
      ALENY1=ILENY1
      ALENX1=ILENX1
      ALENX2=ILENX2
      ALENX3=ILENX3
!
      IX=INT(XMIDL-XFACT*(ALENT/2.0))
      DO 310 I=1,132
      ILABT(I)=' '
  310 CONTINUE
      J=IX-1
      IF(ILENT.LE.0)GO TO 319
      DO 315 I=1,ILENT
      J=J+1
      ILABT(J)=ITITTE(I)
  315 CONTINUE
      IMAXT=J
  319 CONTINUE
!
      IY=INT(YMIDL-YFACT*(ALENY1/2.0))
      DO 320 I=1,132
      ILABY1(I)=' '
  320 CONTINUE
      J=IY-1
      IF(ILENY1.LE.0)GO TO 329
!CCCC WRITE(6,777)I,J,ILENY1,IY,YMIDL,YFACT,ALENY1
!C777 FORMAT('I,J,ILENY1,IY,YMIDL,YFACT,ALENY1 = ',4I8,3E15.7)
      DO 325 I=1,ILENY1
      J=J+1
      ILABY1(J)=IY1LTE(I)
  325 CONTINUE
      IMAXY1=J
  329 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX1/2.0))
      DO 330 I=1,132
      ILABX1(I)=' '
  330 CONTINUE
      J=IX-1
      IF(ILENX1.LE.0)GO TO 339
      DO 335 I=1,ILENX1
      J=J+1
      ILABX1(J)=IX1LTE(I)
  335 CONTINUE
      IMAXX1=J
  339 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX2/2.0))
      DO 340 I=1,132
      ILABX2(I)=' '
  340 CONTINUE
      J=IX-1
      IF(ILENX2.LE.0)GO TO 349
      DO 345 I=1,ILENX2
      J=J+1
      ILABX2(J)=IX2LTE(I)
  345 CONTINUE
      IMAXX2=J
  349 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX3/2.0))
      DO 350 I=1,132
      ILABX3(I)=' '
  350 CONTINUE
      J=IX-1
      IF(ILENX3.LE.0)GO TO 359
      DO 355 I=1,ILENX3
      J=J+1
      ILABX3(J)=IX3LTE(I)
  355 CONTINUE
      IMAXX3=J
  359 CONTINUE
!
!               ****************************************************************
!               **  STEP 4--
!               **  SKIP TO NEW PAGE;
!               **  WRITE OUT THE TITLE (IF ANY);
!               **  WRITE OUT THE TOP HORIZONTAL AXIS OF THE PLOT;
!               ****************************************************************
!
      IF(IERASW.EQ.'ON')WRITE(ICOUT,504)
  504 FORMAT(1H1)
      IF(IERASW.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IF(IERASW.EQ.'OFF')WRITE(ICOUT,999)
      IF(IERASW.EQ.'OFF')CALL DPWRST('XXX','BUG ')
      IF(IMAXT.GE.1)WRITE(ICOUT,505)(ILABT(I),I=1,IMAXT)
  505 FORMAT(240A1)
      IF(IMAXT.GE.1)CALL DPWRST('XXX','BUG ')
!
      DO 500 ICOL=1,NUMCOL
      ILINE(ICOL)=IHYPHE
  500 CONTINUE
      DO 550 ICOL=1,NUMCOL,IXDEL
      ILINE(ICOL)=IALPHI
  550 CONTINUE
      WRITE(ICOUT,555)(ILINE(I),I=1,NUMCOL)
  555 FORMAT(20X,54A1)
      CALL DPWRST('XXX','BUG ')
!
!
!               *******************************************************
!               **  STEP 5--                                         **
!               **  DETERMINE THE MIN AND MAX VALUES OF Y AND OF X.  **
!               *******************************************************
!
      XMIN=X(1)
      XMAX=X(1)
      YMIN=Y(1)
      YMAX=Y(1)
      DO 700 I=1,N
      IF(X(I).LT.XMIN)XMIN=X(I)
      IF(X(I).GT.XMAX)XMAX=X(I)
      IF(Y(I).LT.YMIN)YMIN=Y(I)
      IF(Y(I).GT.YMAX)YMAX=Y(I)
  700 CONTINUE
      IF(GX1MIN.NE.CPUMIN)XMIN=GX1MIN
      IF(GX1MAX.NE.CPUMAX)XMAX=GX1MAX
      IF(GY1MIN.NE.CPUMIN)YMIN=GY1MIN
      IF(GY1MAX.NE.CPUMAX)YMAX=GY1MAX
      DELX=XMAX-XMIN
      DELY=YMAX-YMIN
      XWIDTH=DELX/ANUMCM
      YWIDTH=DELY/ANUMRM
!
!               ****************************************************************
!               **  STEP 6--
!               **  DETERMINE AND WRITE OUT THE PLOT POSITIONS ONE LINE AT A TIM
!               ****************************************************************
!
      DO 1100 IROW=1,NUMROW
!
      DO 1200 ICOL=1,NUMCOL
      ILINE(ICOL)=IBLANK
 1200 CONTINUE
!
      AIROW=IROW
      YUPPER=YMAX+(1.5-AIROW)*YWIDTH
      YLABEL=YMAX+(1.0-AIROW)*YWIDTH
      YLOWER=YMAX+(0.5-AIROW)*YWIDTH
      IF(IROW.EQ.NUMROW)YLABEL=YMIN
      DO 1300 I=1,N
      AI=I
      IF(YLOWER.LE.Y(I).AND.Y(I).LT.YUPPER)GO TO 1350
      GO TO 1300
 1350 CONTINUE
      ICOL=INT(((X(I)-XMIN)/XWIDTH)+1.5)
      IF(ICOL.LT.1.OR.ICOL.GT.NUMCOL)GO TO 1300
      JPLOTC=ICHAR(1)
      IF(JPLOTC.EQ.'    ')JPLOTC='X'
      IF(JPLOTC.EQ.'BLAN')JPLOTC='X'
      IF(JPLOTC.EQ.'NONE')JPLOTC='X'
      ILINE(ICOL)=JPLOTC
 1300 CONTINUE
!
      ICOLMX=1
      DO 1400 ICOL=1,NUMCOL
      ICOLRV=NUMCOL-ICOL+1
      IF(ILINE(ICOLRV).EQ.' ')GO TO 1400
      ICOLMX=ICOLRV
      GO TO 1490
 1400 CONTINUE
 1490 CONTINUE
!
      IAXISC=IALPHI
      IF(IROW.EQ.1.OR.IROW.EQ.NUMROW)IAXISC=IHYPHE
      IF(IROW.EQ.NUMR25.OR.IROW.EQ.NUMR50.OR.IROW.EQ.NUMR75)   &
      IAXISC=IHYPHE
      WRITE(ICOUT,1410)ILABY1(IROW),YLABEL,IAXISC,   &
      (ILINE(ICOL),ICOL=1,ICOLMX)
 1410 FORMAT(A1,1X,E14.7,1X,A1,2X,50A1)
      CALL DPWRST('XXX','BUG ')
!
 1100 CONTINUE
!
!               ************************************************************
!               **  STEP 7--                                              **
!               **  WRITE OUT THE BOTTOM HORIZONTAL AXIS OF THE PLOT;     **
!               **  WRITE OUT THE X-AXIS NUMERIC LABELS;                  **
!               **  WRITE OUT THE FIRST  HORIZONTAL AXIS LABEL (IF ANY);  **
!               **  WRITE OUT THE SECOND HORIZONTAL AXIS LABEL (IF ANY);  **
!               **  WRITE OUT THE THIRD  HORIZONTAL AXIS LABEL (IF ANY).  **
!               ************************************************************
!
!
      DO 2200 ICOL=1,NUMCOL
      ILINE(ICOL)=IHYPHE
 2200 CONTINUE
      DO 2300 ICOL=1,NUMCOL,IXDEL
      ILINE(ICOL)=IALPHI
 2300 CONTINUE
      WRITE(ICOUT,2105)(ILINE(ICOL),ICOL=1,NUMCOL)
 2105 FORMAT(20X,54A1)
      CALL DPWRST('XXX','BUG ')
!
      NUMLAB=5
      ANUMLM=NUMLAB-1
      DO 2500 I=1,NUMLAB
      AIM1=I-1
      AILABL(I)=XMIN+(AIM1/ANUMLM)*DELX
 2500 CONTINUE
      WRITE(ICOUT,2310)(AILABL(I),I=1,NUMLAB)
 2310 FORMAT(13X,5E10.4)
      CALL DPWRST('XXX','BUG ')
!
      IF(IMAXX1.GE.1)WRITE(ICOUT,2311)(ILABX1(I),I=1,IMAXX1)
 2311 FORMAT(240A1)
      IF(IMAXX1.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX2.GE.1)WRITE(ICOUT,2311)(ILABX2(I),I=1,IMAXX2)
      IF(IMAXX2.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX3.GE.1)WRITE(ICOUT,2311)(ILABX3(I),I=1,IMAXX3)
      IF(IMAXX3.GE.1)CALL DPWRST('XXX','BUG ')
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      RETURN
      END SUBROUTINE PLOTN
      SUBROUTINE PLOTW(Y,X,N,ICHAR,MAXCHA,ICASPL,ICAS3D,   &
      ITITTE,NCTITL,   &
      IX1LTE,NCX1LA,   &
      IX2LTE,NCX2LA,   &
      IX3LTE,NCX3LA,   &
      IY1LTE,NCY1LA,   &
      IY2LTE,NCY2LA,   &
      GX1MIN,GX1MAX,GY1MIN,GY1MAX,   &
      IERASW,IBUGU2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE YIELDS A WIDE-WIDTH (130-CHARACTER)
!              PLOT OF Y(I) VERSUS X(I).
!     NOTE--THE WIDE WIDTH OF THIS PLOT
!            MAKES IT APPROPRIATE FOR
!            USE ON A BATCH PRINTER.
!     INPUT ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS
!                               TO BE PLOTTED VERTICALLY.
!                    --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR X.
!                    --ICHAR  = THE HOLLERITH VECTOR OF
!                               CHARACTERS (ONLY THE
!                               FIRST OF WHICH WILL BE USED)
!                    --MAXCHA = THE INTEGER NUMBER OF
!                               CHARACTERS IN ICHAR(.)
!     OUTPUT--A WIDE-WIDTH (130-CHARACTER) TERMINAL PLOT
!             OF X(I) VERSUS I.
!             THE BODY OF THE PLOT (NOT COUNTING AXIS VALUES
!             AND MARGINS) IS 41 ROWS (LINES) AND 101 COLUMNS.
!     PRINTING--YES.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NONE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --JANUARY   1975.
!     UPDATED         --JULY      1975.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --OCTOBER   1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1976.
!     UPDATED         --FEBRUARY  1977.
!     UPDATED         --JUNE      1978.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --JANUARY   1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICHAR
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
!
      CHARACTER*4 ITITTE
      CHARACTER*4 IX1LTE
      CHARACTER*4 IX2LTE
      CHARACTER*4 IX3LTE
      CHARACTER*4 IY1LTE
      CHARACTER*4 IY2LTE
!
      CHARACTER*4 IERASW
      CHARACTER*4 IBUGU2
      CHARACTER*4 IERROR
!
      CHARACTER*4 IBLANK
      CHARACTER*4 IHYPHE
      CHARACTER*4 IALPHI
      CHARACTER*4 IALPHX
      CHARACTER*4 IALPHM
      CHARACTER*4 IALPHA
      CHARACTER*4 IALPHN
      CHARACTER*4 IALPHD
      CHARACTER*4 IEQUAL
!
      CHARACTER*4 ILABT
      CHARACTER*4 ILABX1
      CHARACTER*4 ILABX2
      CHARACTER*4 ILABX3
      CHARACTER*4 ILABY1
      CHARACTER*4 JPLOTC
      CHARACTER*4 IGRAPH
      CHARACTER*4 ICASP2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION ICHAR(*)
      DIMENSION IGRAPH(55,130)
!
      DIMENSION ITITTE(*)
      DIMENSION IX1LTE(*)
      DIMENSION IX2LTE(*)
      DIMENSION IX3LTE(*)
      DIMENSION IY1LTE(*)
      DIMENSION IY2LTE(*)
!
      DIMENSION ILABT(132)
      DIMENSION ILABY1(132)
      DIMENSION ILABX1(132)
      DIMENSION ILABX2(132)
      DIMENSION ILABX3(132)
!
      DIMENSION YLABEL(11)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      IBLANK=' '
      IHYPHE='-'
      IALPHI='I'
      IALPHX='X'
      IALPHM='M'
      IALPHA='A'
      IALPHX='X'
      IALPHN='N'
      IALPHD='D'
      IALPHN='N'
      IEQUAL='='
!
      IMAXT=0
      IMAXX1=0
      IMAXX2=0
      IMAXX3=0
!
      IF(IBUGU2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF PLOTW--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,MAXCHA,NCTITL,IBUGU2
   52   FORMAT('N,MAXCHA,NCTITL,IBUGU2 = ',3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)Y(1),X(1)
   53   FORMAT('Y(1),X(1) = ',2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)Y(N),X(N)
   54   FORMAT('Y(N),X(N) = ',2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ICASPL,ICAS3D
   55   FORMAT('ICASPL,ICAS3D = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)GX1MIN,GX1MAX,GY1MIN,GY1MAX
   73   FORMAT('GX1MIN,GX1MAX,GY1MIN,GY1MAX = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,75)IY2LTE(1)
   75   FORMAT('IY2TLE(1) = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!               ***************************************************************
!               **  STEP 2--                                                 **
!               **  DEFINE THE NUMBER OF ROWS AND COLUMNS WITHIN THE PLOT--  **
!               **  THIS HAS BEEN SET TO 41 ROWS AND  97 COLUMNS.            **
!               ***************************************************************
!
      NUMROW=41
      NUMCOL=97
!
      ANUMR=NUMROW
      ANUMRM=NUMROW-1
      ANUMCM=NUMCOL-1
                                                                                                                                  
      NUMR25=(NUMROW/4)+1
      NUMR50=(NUMROW/2)+1
      NUMR75=3*(NUMROW/4)+1
      IXDEL=(NUMCOL-1)/4
!
!               ***************************
!               **  STEP 2.1--           **
!               **  BLANK OUT THE GRAPH  **
!               ***************************
!
      DO 280 I=1,55
      DO 290 J=1,130
      IGRAPH(I,J)=IBLANK
  290 CONTINUE
  280 CONTINUE
!
!               ********************************
!               **  STEP 2.2--                **
!               **  DEFINE THE TYPE OF PLOT.  **
!               ********************************
!
      ICASP2=ICASPL
      IF(ICASPL.EQ.'MDBP')ICASP2='BOXP'
      IF(ICASPL.EQ.'MEBP')ICASP2='BOXP'
      IF(ICASPL.EQ.'VIPL')ICASP2='BOXP'
      IF(ICASPL.EQ.'MDIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MEIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MRIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'MMIP')ICASP2='IPLO'
      IF(ICASPL.EQ.'1SE ')ICASP2='IPLO'
      IF(ICASPL.EQ.'2SE ')ICASP2='IPLO'
      IF(ICASPL.EQ.'1SD ')ICASP2='IPLO'
      IF(ICASPL.EQ.'2SD ')ICASP2='IPLO'
      IF(ICASPL.EQ.'MDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'MECL')ICASP2='IPLO'
      IF(ICASPL.EQ.'TMCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'BWCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'SDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CVCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CDCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CRCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'CQCL')ICASP2='IPLO'
      IF(ICASPL.EQ.'DPRO')ICASP2='IPLO'
      IF(ICASPL.EQ.'DMEA')ICASP2='IPLO'
      IF(ICASPL.EQ.'NTOL')ICASP2='IPLO'
      IF(ICASPL.EQ.'NPRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'BWRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'TMRE')ICASP2='IPLO'
      IF(ICASPL.EQ.'AGCL')ICASP2='IPLO'
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  PREPARE THE TITLE LINE, THE Y-AXIS LABEL,       **
!               **  AND THE 3 HORIZONTAL AXIS LABELS FOR PRINTING.  **
!               ******************************************************
!
      IVAL=INT((55./2.) - 4)
      YMIDL=REAL(IVAL)
      IVAL=29 + INT(REAL(NUMCOL)/2.)
      XMIDL=REAL(IVAL)
!
      YFACT=1.0
      XFACT=1.0
!
      ILENT=NCTITL
      ILENY1=NCY1LA
      ILENY2=NCY2LA
      ILENX1=NCX1LA
      ILENX2=NCX2LA
      ILENX3=NCX3LA
!
      ALENT=ILENT
      ALENY1=ILENY1
      ALENX1=ILENX1
      ALENX2=ILENX2
      ALENX3=ILENX3
!
      IX=INT(XMIDL-XFACT*(ALENT/2.0))
      DO 310 I=1,132
      ILABT(I)=' '
  310 CONTINUE
      J=IX-1
      IF(ILENT.LE.0)GO TO 319
      DO 315 I=1,ILENT
      J=J+1
      ILABT(J)=ITITTE(I)
  315 CONTINUE
      IMAXT=J
  319 CONTINUE
!
      IY=INT(YMIDL-YFACT*(ALENY1/2.0))
      DO 320 I=1,132
      ILABY1(I)=' '
  320 CONTINUE
      J=IY-1
      IF(ILENY1.LE.0)GO TO 329
      DO 325 I=1,ILENY1
      J=J+1
      ILABY1(J)=IY1LTE(I)
  325 CONTINUE
      IMAXY1=J
  329 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX1/2.0))
      DO 330 I=1,132
      ILABX1(I)=' '
  330 CONTINUE
      J=IX-1
      IF(ILENX1.LE.0)GO TO 339
      DO 335 I=1,ILENX1
      J=J+1
      ILABX1(J)=IX1LTE(I)
  335 CONTINUE
      IMAXX1=J
  339 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX2/2.0))
      DO 340 I=1,132
      ILABX2(I)=' '
  340 CONTINUE
      J=IX-1
      IF(ILENX2.LE.0)GO TO 349
      DO 345 I=1,ILENX2
                                                                                                                                  
      J=J+1
      ILABX2(J)=IX2LTE(I)
  345 CONTINUE
      IMAXX2=J
  349 CONTINUE
!
      IX=INT(XMIDL-XFACT*(ALENX3/2.0))
      DO 350 I=1,132
      ILABX3(I)=' '
  350 CONTINUE
      J=IX-1
      IF(ILENX3.LE.0)GO TO 359
      DO 355 I=1,ILENX3
      J=J+1
      ILABX3(J)=IX3LTE(I)
  355 CONTINUE
      IMAXX3=J
  359 CONTINUE
!
!               *******************************************************
!               **  STEP 5--                                         **
!               **  DETERMINE THE MIN AND MAX VALUES OF Y AND OF X.  **
!               *******************************************************
!
      YMIN=Y(1)
      YMAX=Y(1)
      XMIN=X(1)
      XMAX=X(1)
      DO 700 I=1,N
      IF(Y(I).LT.YMIN)YMIN=Y(I)
      IF(Y(I).GT.YMAX)YMAX=Y(I)
      IF(X(I).LT.XMIN)XMIN=X(I)
      IF(X(I).GT.XMAX)XMAX=X(I)
  700 CONTINUE
      IF(GX1MIN.NE.CPUMIN)XMIN=GX1MIN
      IF(GX1MAX.NE.CPUMAX)XMAX=GX1MAX
      IF(GY1MIN.NE.CPUMIN)YMIN=GY1MIN
      IF(GY1MAX.NE.CPUMAX)YMAX=GY1MAX
      DELY=YMAX-YMIN
      DELX=XMAX-XMIN
      YWIDTH=DELY/ANUMRM
      XWIDTH=DELX/ANUMCM
!
      XMID=(XMIN+XMAX)/2.0
      X25=0.75*XMIN+0.25*XMAX
      X75=0.25*XMIN+0.75*XMAX
!
      DO 800 I=1,9
      AIM1=I-1
      YLABEL(I)=YMAX-(AIM1/8.0)*(YMAX-YMIN)
  800 CONTINUE
!
!               *********************************
!               **  STEP 6--                   **
!               **  PRODUCE THE VERTICAL AXES  **
!               *********************************
!
      DO 1300 I=3,43
      IGRAPH(I,5)=IALPHI
      IGRAPH(I,105)=IALPHI
 1300 CONTINUE
      DO 1400 I=3,43,5
      IGRAPH(I,5)=IHYPHE
      IGRAPH(I,105)=IHYPHE
 1400 CONTINUE
      IGRAPH(3,1)=IEQUAL
      IGRAPH(3,2)=IALPHM
      IGRAPH(3,3)=IALPHA
      IGRAPH(3,4)=IALPHX
      IGRAPH(23,1)=IEQUAL
      IGRAPH(23,2)=IALPHM
      IGRAPH(23,3)=IALPHI
      IGRAPH(23,4)=IALPHD
      IGRAPH(43,1)=IEQUAL
      IGRAPH(43,2)=IALPHM
      IGRAPH(43,3)=IALPHI
      IGRAPH(43,4)=IALPHN
!
!               ***********************************
!               **  STEP 7--                     **
!               **  PRODUCE THE HORIZONTAL AXES  **
!               ***********************************
!
      DO 1500 J=7,103
      IGRAPH(1,J)=IHYPHE
      IGRAPH(45,J)=IHYPHE
 1500 CONTINUE
      DO 1600 J=7,103,12
      IGRAPH(1,J)=IALPHI
      IGRAPH(45,J)=IALPHI
 1600 CONTINUE
!
!               ******************************************
!               **  STEP 8--                            **
!               **  DETERMINE THE (X,Y) PLOT POSITIONS  **
!               ******************************************
!
      RATIOY=ANUMRM/(YMAX-YMIN)
      RATIOX=ANUMCM/(XMAX-XMIN)
      DO 1800 I=1,N
      XI=X(I)
      MX=INT(RATIOX*(XI-XMIN)+0.5)
      MX=MX+7
      IF(MX.LT.7.OR.MX.GT.103)GO TO 1800
      MY=INT(RATIOY*(Y(I)-YMIN)+0.5)
      MY=43-MY
      IF(MY.LT.3.OR.MY.GT.43)GO TO 1800
      JPLOTC=ICHAR(1)
      IF(JPLOTC.EQ.'    ')JPLOTC='X'
      IF(JPLOTC.EQ.'BLAN')JPLOTC='X'
      IF(JPLOTC.EQ.'NONE')JPLOTC='X'
      IGRAPH(MY,MX)=JPLOTC
 1800 CONTINUE
!
!               *************************************
!               **  STEP 9--                       **
!               **  SKIP TO A NEW PAGE.            **
!               **  WRITE OUT THE TITLE (IF ANY);  **
!               *************************************
!
      IF(IERASW.EQ.'ON')WRITE(ICOUT,2004)
 2004 FORMAT(1H1)
      IF(IERASW.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IF(IERASW.EQ.'OFF')WRITE(ICOUT,999)
      IF(IERASW.EQ.'OFF')CALL DPWRST('XXX','BUG ')
      IF(IMAXT.GE.1)WRITE(ICOUT,2005)(ILABT(I),I=1,IMAXT)
 2005 FORMAT(240A1)
      IF(IMAXT.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXT.LE.0)WRITE(ICOUT,999)
      IF(IMAXT.LE.0)CALL DPWRST('XXX','BUG ')
!
!               *********************************************
!               **  STEP 10--                              **
!               **  WRITE OUT THE GRAPH                    **
!               **  (INCLUDING THE X-AXIS NUMERIC LABELS)  **
!               *********************************************
!
      DO 2100 I=1,45
      IP2=I+2
      IFLAG=IP2-(IP2/5)*5
      K=IP2/5
      IF(IFLAG.NE.0)WRITE(ICOUT,2105)ILABY1(I),(IGRAPH(I,J),J=1,105)
 2105 FORMAT(A1,20X,105A1)
      IF(IFLAG.NE.0)CALL DPWRST('XXX','BUG ')
      IF(IFLAG.EQ.0)WRITE(ICOUT,2106)ILABY1(I),YLABEL(K),   &
      (IGRAPH(I,J),J=1,105)
 2106 FORMAT(A1,F20.7,105A1)
      IF(IFLAG.EQ.0)CALL DPWRST('XXX','BUG ')
 2100 CONTINUE
      WRITE(ICOUT,2107)XMIN,X25,XMID,X75,XMAX
 2107 FORMAT(14X,F20.7,4X,F20.7,4X,F20.7,4X,F20.7,4X,F20.7)
      CALL DPWRST('XXX','BUG ')
!
!               ************************************************************
!               **  STEP 11--                                             **
!               **  WRITE OUT THE FIRST  HORIZONTAL AXIS LABEL (IF ANY);  **
!               **  WRITE OUT THE SECOND HORIZONTAL AXIS LABEL (IF ANY);  **
!               **  WRITE OUT THE THIRD  HORIZONTAL AXIS LABEL (IF ANY).  **
!               ************************************************************
!
      IF(IMAXX1.GE.1)WRITE(ICOUT,2311)(ILABX1(I),I=1,IMAXX1)
 2311 FORMAT(240A1)
      IF(IMAXX1.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX1.LE.0)WRITE(ICOUT,999)
      IF(IMAXX1.LE.0)CALL DPWRST('XXX','BUG ')
      IF(IMAXX2.GE.1)WRITE(ICOUT,2311)(ILABX2(I),I=1,IMAXX2)
      IF(IMAXX2.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX2.LE.0)WRITE(ICOUT,999)
      IF(IMAXX2.LE.0)CALL DPWRST('XXX','BUG ')
      IF(IMAXX3.GE.1)WRITE(ICOUT,2311)(ILABX3(I),I=1,IMAXX3)
      IF(IMAXX3.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IMAXX3.LE.0)WRITE(ICOUT,999)
      IF(IMAXX3.LE.0)CALL DPWRST('XXX','BUG ')
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      RETURN
      END SUBROUTINE PLOTW
      SUBROUTINE PLYSRT(XC,YC,NMX,NSEG,NSGE,NSGCL,NSGCH,NPTS,NTPE,   &
                        NTPCL,NTPCH,SNSE,CLSD,NSGX,X,Y,IMX,JMX,   &
                        IB,JB,NBX,PRMTR,NS,D,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--XX
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!     UPDATED         --JANUARY   1989.  MORE CHANGES TO STANDARD FORTRAN 77--
!                                        CHANGED DO WHILE/END DO (ALAN HECKERT).
!     UPDATED         --JULY      1996.  EXPLICITLY INITIALIZE SOME
!                                        ARRAYS (BOMBED ON SGI WHICH
!                                        DOESN'T PRESET TO 0)
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOCP.INC'
!
!---------------------------------------------------------------------
!
!CCCC INTEGER NPTS(NSGX,3),SNSE(NSGX,3),CLSD(NSGX,3),NSEG(3),
!CCCC1 LC(4),NSGE(3),NSGCL(3),NSGCH(3),NTPE(3),NTPCL(3),NTPCH(3),
!CCCC2 ESTR
!
!CCCC DIMENSION XC(NMX,3),YC(NMX,3),D(2,NSGX,3),X(IMX),Y(JMX),
!CCCC1 IB(NBX),JB(NBX),NS(2,NSGX,3)
!
      INTEGER NPTS
      INTEGER SNSE
      INTEGER CLSD
      INTEGER NSEG
!CCCC INTEGER LC
      INTEGER NSGE
      INTEGER NSGCL
      INTEGER NSGCH
      INTEGER NTPE
      INTEGER NTPCL
      INTEGER NTPCH
      INTEGER ESTR
!
      DIMENSION NPTS(MAXNSG,3)
      DIMENSION SNSE(MAXNSG,3)
      DIMENSION CLSD(MAXNSG,3)
      DIMENSION NSEG(3)
!CCCC DIMENSION LC(4)
      DIMENSION NSGE(3)
      DIMENSION NSGCL(3)
      DIMENSION NSGCH(3)
      DIMENSION NTPE(3)
      DIMENSION NTPCL(3)
      DIMENSION NTPCH(3)
!
      DIMENSION XC(MAXNMX,3)
      DIMENSION YC(MAXNMX,3)
      DIMENSION D(2,MAXNSG,3)
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION IB(*)
      DIMENSION JB(*)
      DIMENSION NS(2,MAXNSG,3)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
        WRITE(ICOUT,101)MAXNSG,MAXNMX,IMX,JMX,NMX,NSGX
  101   FORMAT('PLYSRT: MAXNSG,MAXNMS,IMX,JMX,NMX,NSGX = ',6I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCC JULY 1996.  ADD FOLLOING 9 LINES FOR SGI BUG.
      NSGE(1)=0
      NSGE(2)=0
      NSGE(3)=0
      NSGCH(1)=0
      NSGCH(2)=0
      NSGCH(3)=0
      NSGCL(1)=0
      NSGCL(2)=0
      NSGCL(3)=0
!
      IF (NSEG(1).EQ.0) THEN
        NSGE(1)=0
        NSGCL(1)=0
        NSGCH(1)=0
        NTPE(1)=0
        NTPCL(1)=0
        NTPCH(1)=0
      END IF
      IF (NSEG(2).EQ.0) THEN
        NSGE(2)=0
        NSGCL(2)=0
        NSGCH(2)=0
        NTPE(2)=0
        NTPCL(2)=0
        NTPCH(2)=0
      ELSE
!   BEGIN SORTING THE *(*,2) ARRAYS
        NSG=NSEG(2)
        NTP=0
        NTPE(2)=0
        NTPCL(2)=0
        NTPCH(2)=0
        NSGE(2)=0
        NSGCL(2)=0
        NSGCH(2)=0
        DO 100 N=1,NSG
          NTP=NTP+NPTS(N,2)
          IF (CLSD(N,2).EQ.0) THEN
            NSGE(2)=NSGE(2)+1
            NTPE(2)=NTPE(2)+NPTS(N,2)
          ELSE IF (CLSD(N,2).LT.0) THEN
            NSGCL(2)=NSGCL(2)+1
            NTPCL(2)=NTPCL(2)+NPTS(N,2)
          ELSE
            NSGCH(2)=NSGCH(2)+1
            NTPCH(2)=NTPCH(2)+NPTS(N,2)
          END IF
  100   CONTINUE
!   MAKE SURE EACH CONTOUR SEGMENT PROCEEDS IN THE CORRECT SENSE
!    WHICH IS WITH LOW VALUES TO THE RIGHT OF THE CONTOUR
        LN=0
        DO 200 N=1,NSG
          LS=LN+1
          LN=LN+NPTS(N,2)
          IF (SNSE(N,2).LT.0) THEN
            LN2=(LS+LN-1)/2
            DO 210 L=LS,LN2
              LL=LN-L+LS
              H=XC(LL,2)
              XC(LL,2)=XC(L,2)
              XC(L,2)=H
              H=YC(LL,2)
              YC(LL,2)=YC(L,2)
              YC(L,2)=H
  210       CONTINUE
            SNSE(N,2)=1
          END IF
  200   CONTINUE
!   SEPARATE THE EDGE-TO-EDGE SEGMENTS FROM THE CLOSED SEGMENTS
        IF (NSGE(2).GT.0) THEN
          NSGM=NSG-1
          DO 300 N=1,NSGM
            L1=1
            DO 310 M=1,NSGM
              IF (CLSD(M,2).NE.0.AND.CLSD(M+1,2).EQ.0) THEN
                IH=CLSD(M,2)
                CLSD(M,2)=CLSD(M+1,2)
                CLSD(M+1,2)=IH
                L2=L1+NPTS(M,2)
                L3=L2+NPTS(M+1,2)
                CALL STRSWP(XC(1,2),L1,L2,L3)
                CALL STRSWP(YC(1,2),L1,L2,L3)
                IH=NPTS(M,2)
                NPTS(M,2)=NPTS(M+1,2)
                NPTS(M+1,2)=IH
              END IF
              L1=L1+NPTS(M,2)
  310       CONTINUE
  300     CONTINUE
!   DETERMINE THE BOUNDARY POINTS FOR EACH EDGE-TO-EDGE SEGMENT'S ENTRY & EXIT
!    AND THE DISTANCE OF THESE POINTS FROM THE LOWER LEFT CORNER
          NBM=NBX-1
          LN=0
          NSG=NSGE(2)
          DO 400 N=1,NSG
            LS=LN+1
            LN=LN+NPTS(N,2)
            L=LS
!
            IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
              WRITE(ICOUT,401)
  401         FORMAT('BEFORE FIRST CALL TO SIDEDI')
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            DO 410 K=1,2
              CALL SIDEDI(XC(L,2),YC(L,2),NS(K,N,2),D(K,N,2),   &
                          IB,JB,X,Y,   &
                          IBUGG3,ISUBRO,IERROR)
               L=LN
  410       CONTINUE
  400     CONTINUE
        END IF
!   SEPARATE CLOSED LOW SEGMENTS FROM CLOSED HIGH SEGMENTS
        IF (NSGCL(2).GT.0.AND.NSGCH(2).GT.0) THEN
          NSGM=NSEG(2)-1
          DO 500 N=NSGE(2)+1,NSGM
            L1=NTPE(2)+1
            DO 510 M=NSGE(2)+1,NSGM
              IF (CLSD(M,2).GT.0.AND.CLSD(M+1,2).LT.0) THEN
                IH=CLSD(M,2)
                CLSD(M,2)=CLSD(M+1,2)
                CLSD(M+1,2)=IH
                L2=L1+NPTS(M,2)
                L3=L2+NPTS(M+1,2)
                CALL STRSWP(XC(1,2),L1,L2,L3)
                CALL STRSWP(YC(1,2),L1,L2,L3)
                IH=NPTS(M,2)
                NPTS(M,2)=NPTS(M+1,2)
                NPTS(M+1,2)=IH
              END IF
              L1=L1+NPTS(M,2)
  510       CONTINUE
  500     CONTINUE
        END IF
!   DETERMINE AREA OF CLOSED SEGMENTS AND STORE IN D(1,*,*)
        IF (NSGCL(2).GT.0.OR.NSGCH(2).GT.0) THEN
          N1=NSGE(2)+1
          NSG=N1+NSGCL(2)+NSGCH(2)-1
          LE=NTPE(2)
          DO 600 N=N1,NSG
            LS=LE+1
            LE=LE+NPTS(N,2)
            D(1,N,2)=0.
            DO 610 L=LS+1,LE
              D(1,N,2)=D(1,N,2)+0.5*(XC(L,2)-XC(L-1,2))*   &
                                 (YC(L,2)+YC(L-1,2))
  610       CONTINUE
            D(1,N,2)=ABS(D(1,N,2))
  600     CONTINUE
        END IF
      END IF
!     WRITE(9,'(''  EDGE CONTOURS'')')
!     CALL PRT_STR(9,XC(1,2),YC(1,2),NSGE(2),NPTS(1,2))
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
        WRITE(ICOUT,611)
  611   FORMAT('EDGE CONTOURS 1')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,612)XC(1,2),YC(1,2),NSGE(2),NPTS(1,2)
  612   FORMAT('XC(1,2),YC(1,2),NSGE(2),NPTS(1,2) = ',2G15.7,2I6)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     SORT BOTH 1 AND 2 EDGE-TO-EDGE SEGMENTS BY DISTANCE OF
!     ENTRY POINTS FROM LOWER LEFT CORNER.
!
      DO 700 K=1,2
        IF (NSGE(K).GT.0) THEN
          NSGM=NSGE(K)-1
          DO 710 N=1,NSGM
            L1=1
            DO 720 M=1,NSGM
              IF (D(1,M,K).GT.D(1,M+1,K)) THEN
                DO 730 L=1,2
                  H=D(L,M,K)
                  D(L,M,K)=D(L,M+1,K)
                  D(L,M+1,K)=H
                  IH=NS(L,M,K)
                  NS(L,M,K)=NS(L,M+1,K)
                  NS(L,M+1,K)=IH
  730           CONTINUE
                IH=CLSD(M,K)
                CLSD(M,K)=CLSD(M+1,K)
                CLSD(M+1,K)=IH
                L2=L1+NPTS(M,K)
                L3=L2+NPTS(M+1,K)
                CALL STRSWP(XC(1,K),L1,L2,L3)
                CALL STRSWP(YC(1,K),L1,L2,L3)
                IH=NPTS(M,K)
                NPTS(M,K)=NPTS(M+1,K)
                NPTS(M+1,K)=IH
              END IF
              L1=L1+NPTS(M,K)
  720       CONTINUE
  710     CONTINUE
        END IF
  700 CONTINUE
!     WRITE(9,'(''  SORTED EDGE CONTOURS 1'')')
!     CALL PRT_STR(9,XC(1,1),YC(1,1),NSGE(1),NPTS(1,1))
!     WRITE(9,'(''  SORTED EDGE CONTOURS 2'')')
!     CALL PRT_STR(9,XC(1,2),YC(1,2),NSGE(2),NPTS(1,2))
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
        WRITE(ICOUT,711)
  711   FORMAT('SORTED EDGE CONTOURS 1')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,712)XC(1,1),YC(1,1),NSGE(1),NPTS(1,1)
  712   FORMAT('XC(1,1),YC(1,1),NSGE(1),NPTS(1,1) = ',2G15.7,2I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,716)
  716   FORMAT('SORTED EDGE CONTOURS 2')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,717)XC(1,2),YC(1,2),NSGE(2),NPTS(1,2)
  717   FORMAT('XC(1,2),YC(1,2),NSGE(2),NPTS(1,2) = ',2G15.7,2I6)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!   BEGIN CONVERTING EDGE-TO-EDGE SEGMENTS TO CLOSED SEGMENTS
      L3=0
      N3=0
      IF (NSGE(2).GT.0.OR.NSGE(1).GT.0) THEN
        DO 800 K=2,1,-1
          NSG=NSGE(K)
          LE=0
          DO 810 N=1,NSG
            LS=LE+1
            LE=LE+IABS(NPTS(N,K))
            IF (NPTS(N,K).GT.0) THEN
              N3=N3+1
              DO 820 L=LS,LE
                LL=L3+L-LS+1
                XC(LL,3)=XC(L,K)
                YC(LL,3)=YC(L,K)
  820         CONTINUE
              NPTS(N3,3)=NPTS(N,K)
              NPTS(N,K)=-NPTS(N,K)
              NS(1,N3,3)=NS(1,N,K)
              NS(2,N3,3)=NS(2,N,K)
              D(1,N3,3)=D(1,N,K)
              D(2,N3,3)=D(2,N,K)
              ESTR=0
  900         CONTINUE
              IF(ESTR.EQ.1)GO TO 999
!
!     WRITE(9,'('' PRMTR'',F10.2)') PRMTR
!
              IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
                WRITE(ICOUT,907)PRMTR
  907           FORMAT('PRMTR = ',F10.2)
                CALL DPWRST('XXX','BUG ')
              ENDIF
!
              DD=D(1,N3,3)-D(2,N3,3)
              SGNDD=SIGN(1.0,DD)
              IF (DD.LT.0.) DD=DD+PRMTR
              KE=K
              NE=N
!     WRITE(9,'('' D1 D2 DD SGNDD KE NE'',4F8.2,2I6)')
!     1               D(1,N3,3),D(2,N3,3),DD,SGNDD,KE,NE
              DO 910 KK=1,2
                NNSG=NSGE(KK)
                DO 920 NN=1,NNSG
!     WRITE(9,'('' KK NN NPTS'',3I6)') KK,NN,NPTS(KK,NN)
                  IF (NPTS(NN,KK).GT.0) THEN
                    D0=D(1,NN,KK)-D(2,N3,3)
                    SGND0=SIGN(1.0,D0)
                    IF (D0.LT.0.) D0=D0+PRMTR
!     WRITE(9,'('' D1 D2 D0 SGND0'',4F8.2)')
!     1               D(1,NN,KK),D(2,N3,3),D0,SGND0
                    IF (D0.LT.DD) THEN
                      DD=D0
                      SGNDD=SGND0
                      KE=KK
                      NE=NN
                    END IF
                  END IF
  920           CONTINUE
  910         CONTINUE
!     WRITE(9,'('' KE NE'',2I6)') KE,NE
!     WRITE(9,'('' NS2 NS1 SGNDD'',2I6,F6.0)')
!     1               NS(2,N3,3),NS(1,NE,KE),SGNDD
!
              IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
                WRITE(ICOUT,917)KE,NE
  917           FORMAT('KE,NE = ',2I6)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,918)NS2,NS1,SDGND
  918           FORMAT('NS2,NS1,SDGND = ',2I6,F6.0)
                CALL DPWRST('XXX','BUG ')
              ENDIF
!
              IF (NS(2,N3,3).NE.NS(1,NE,KE).OR.SGNDD.LT.0.) THEN
                NB1=NS(2,N3,3)+1
                NB2=NS(1,NE,KE)
                LL=L3+NPTS(N3,3)
!     WRITE(9,'('' NB1 NB2'',2I6)') NB1,NB2
!
                IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
                  WRITE(ICOUT,921)NB1,NB2
  921             FORMAT('NB1,NB2 = ',2I6)
                  CALL DPWRST('XXX','BUG ')
                ENDIF
!
                IF (NS(2,N3,3).LT.NS(1,NE,KE)) THEN
                  DO 930 NB=NB1,NB2
                    LL=LL+1
                    XC(LL,3)=X(IB(NB))
                    YC(LL,3)=Y(JB(NB))
  930             CONTINUE
                  NPTS(N3,3)=NPTS(N3,3)+NB2-NB1+1
                ELSE
                  DO 940 NB=NB1,NBX
                    LL=LL+1
                    XC(LL,3)=X(IB(NB))
                    YC(LL,3)=Y(JB(NB))
  940             CONTINUE
                  DO 950 NB=2,NB2
                    LL=LL+1
                    XC(LL,3)=X(IB(NB))
                    YC(LL,3)=Y(JB(NB))
  950             CONTINUE
                  NPTS(N3,3)=NPTS(N3,3)+NB2-NB1+NBX
                END IF
!
                IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
                  WRITE(ICOUT,951)
  951             FORMAT('BEFORE SECOND CALL TO SIDEDI')
                  CALL DPWRST('XXX','BUG ')
                ENDIF
!
                CALL SIDEDI(XC(LL,3),YC(LL,3),NS(2,N3,3),   &
                            D(2,N3,3),IB,JB,X,Y,   &
                            IBUGG3,ISUBRO,IERROR)
                DD=D(1,NE,KE)-D(2,N3,3)
                SGNDD=SIGN(1.0,DD)
                IF (DD.LT.0.) DD=DD+PRMTR
              END IF
              IF (KE.EQ.K.AND.NE.EQ.N) THEN
                ESTR=1
                NPTS(N3,3)=NPTS(N3,3)+1
                LL=L3+NPTS(N3,3)
                XC(LL,3)=XC(L3+1,3)
                YC(LL,3)=YC(L3+1,3)
              ELSE
                LLE=0
                DO 960 NN=1,NE
                  LLS=LLE+1
                  LLE=LLE+IABS(NPTS(NN,KE))
  960           CONTINUE
                LL3=L3+NPTS(N3,3)
                DO 970 LL=LLS,LLE
                  LLL=LL3+LL-LLS+1
                  XC(LLL,3)=XC(LL,KE)
                  YC(LLL,3)=YC(LL,KE)
  970           CONTINUE
                NPTS(N3,3)=NPTS(N3,3)+NPTS(NE,KE)
                NPTS(NE,KE)=-NPTS(NE,KE)
                NS(2,N3,3)=NS(2,NE,KE)
                D(2,N3,3)=D(2,NE,KE)
              END IF
              GO TO 900
  999         CONTINUE
!
!
!
              IF (NSGCH(1).GT.0.OR.NSGCH(2).GT.0) THEN
                LLL=L3+1
                ESTR=0
 2000           CONTINUE
                IF(ESTR.EQ.1)GO TO 2099
                  A=0.
                  KE=0
                  DO 2010 KK=1,2
                    LL=1+NTPE(KK)+NTPCL(KK)
                    NN1=1+NSGE(KK)+NSGCL(KK)
                    NNSG=NN1+NSGCH(KK)-1
                    DO 2020 NN=NN1,NNSG
                      IF (NPTS(NN,KK).GT.0) THEN
                        CALL INOUT(XC(LL,KK),YC(LL,KK),XC(LLL,3),   &
                          YC(LLL,3),NPTS(N3,3),IO)
                        IF (IO.EQ.1.AND.D(1,NN,KK).GT.A) THEN
                          A=D(1,NN,KK)
                          NE=NN
                          KE=KK
                        END IF
                      END IF
                      LL=LL+IABS(NPTS(NN,KK))
 2020               CONTINUE
 2010             CONTINUE
                  IF (KE.EQ.0) THEN
                    ESTR=1
                  ELSE
                    LL=1+NTPE(KE)+NTPCL(KE)
                    NN1=1+NSGE(KE)+NSGCL(KE)
                    DO 2030 NN=NN1,NE-1
                      LL=LL+IABS(NPTS(NN,KE))
 2030               CONTINUE
                    CALL CONINS(XC(LLL,3),YC(LLL,3),NPTS(N3,3),   &
                      XC(LL,KE),YC(LL,KE),NPTS(NE,KE))
                    NPTS(NE,KE)=-NPTS(NE,KE)
                  END IF
                  GO TO 2000
 2099           CONTINUE
              END IF
              L3=L3+NPTS(N3,3)
            END IF
  810     CONTINUE
  800   CONTINUE
      END IF
!   BEGIN COMBINING CLOSED SEGMENTS
      IF (NSGCL(2).GT.0.OR.NSGCL(1).GT.0) THEN
        DO 3000 K=2,1,-1
          N1=NSGE(K)+1
          NSG=N1+NSGCL(K)-1
          LE=NTPE(K)
          DO 3010 N=N1,NSG
            LS=LE+1
            LE=LE+IABS(NPTS(N,K))
            N3=N3+1
            DO 3020 L=LS,LE
              LL=L3+L-LS+1
              XC(LL,3)=XC(L,K)
              YC(LL,3)=YC(L,K)
 3020       CONTINUE
            NPTS(N3,3)=NPTS(N,K)
            IF (NSGCH(1).GT.0.OR.NSGCH(2).GT.0) THEN
              LLL=L3+1
              ESTR=0
 4000         CONTINUE
              IF(ESTR.EQ.1)GO TO 4099
                A=0.
                KE=0
                DO 4010 KK=1,2
                  LL=1+NTPE(KK)+NTPCL(KK)
                  NN1=1+NSGE(KK)+NSGCL(KK)
                  NNSG=NN1+NSGCH(KK)-1
                  DO 4020 NN=NN1,NNSG
                    IF (NPTS(NN,KK).GT.0) THEN
                      CALL INOUT(XC(LL,KK),YC(LL,KK),XC(LLL,3),   &
                          YC(LLL,3),NPTS(N3,3),IO)
                      IF (IO.EQ.1.AND.D(1,NN,KK).GT.A) THEN
                        A=D(1,NN,KK)
                        NE=NN
                        KE=KK
                      END IF
                    END IF
                    LL=LL+IABS(NPTS(NN,KK))
 4020             CONTINUE
 4010           CONTINUE
                IF (KE.EQ.0) THEN
                  ESTR=1
                ELSE
                  LL=1+NTPE(KE)+NTPCL(KE)
                  NN1=1+NSGE(KE)+NSGCL(KE)
                  DO 4030 NN=NN1,NE-1
                    LL=LL+IABS(NPTS(NN,KE))
 4030             CONTINUE
                  CALL CONINS(XC(LLL,3),YC(LLL,3),NPTS(N3,3),   &
                      XC(LL,KE),YC(LL,KE),NPTS(NE,KE))
                  NPTS(NE,KE)=-NPTS(NE,KE)
                END IF
                GO TO 4000
 4099         CONTINUE
            END IF
            L3=L3+NPTS(N3,3)
 3010     CONTINUE
 3000   CONTINUE
      END IF
!   HANDLE SITUATION WHERE THERE ARE ONLY CLOSED HIGH SEGMENTS
      IF ((NSGE(1)+NSGE(2)+NSGCL(1)+NSGCL(2)).EQ.0) THEN
        N3=N3+1
        DO 5000 NB=1,NBX
          XC(L3+NB,3)=X(IB(NB))
          YC(L3+NB,3)=Y(JB(NB))
 5000   CONTINUE
        NPTS(N3,3)=NBX
        IF (NSGCH(1).GT.0.OR.NSGCH(2).GT.0) THEN
          LLL=L3+1
          ESTR=0
 5100     CONTINUE
          IF(ESTR.EQ.1)GO TO 5199
            A=0.
            KE=0
            DO 5110 KK=1,2
              LL=1
              NNSG=NSGCH(KK)
              DO 5120 NN=1,NNSG
                IF (NPTS(NN,KK).GT.0) THEN
                  CALL INOUT(XC(LL,KK),YC(LL,KK),XC(LLL,3),   &
                          YC(LLL,3),NPTS(N3,3),IO)
                  IF (IO.EQ.1.AND.D(1,NN,KK).GT.A) THEN
                    A=D(1,NN,KK)
                    NE=NN
                    KE=KK
                  END IF
                END IF
                LL=LL+IABS(NPTS(NN,KK))
 5120         CONTINUE
 5110       CONTINUE
            IF (KE.EQ.0) THEN
              ESTR=1
            ELSE
              LL=1
              DO 5130 NN=1,NE-1
                LL=LL+IABS(NPTS(NN,KE))
 5130         CONTINUE
              CALL CONINS(XC(LLL,3),YC(LLL,3),NPTS(N3,3),   &
                      XC(LL,KE),YC(LL,KE),NPTS(NE,KE))
              NPTS(NE,KE)=-NPTS(NE,KE)
            END IF
            GO TO 5100
 5199     CONTINUE
        END IF
        L3=L3+NPTS(N3,3)
      END IF
      NSEG(3)=N3
!     WRITE(9,'(''  TOTAL CONTOURS'')')
!     CALL PRT_STR(9,XC(1,3),YC(1,3),NSEG(3),NPTS(1,3))
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'YSRT')THEN
        WRITE(ICOUT,9001)
 9001   FORMAT('AT THE END OF PLYSRT: TOTAL CONTOURS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9003)XC(1,3),YC(1,3),NSEG(3),NPTS(1,3)
 9003   FORMAT('XC(1,3),YC(1,3),NSEG(3),NPTS(1,3) = ',2G15.7,2I6)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PLYSRT
      SUBROUTINE PLNCDF(X,P,SD,CDF)
!
!     NOTE--POWER-LOGNORMAL CDF IS:
!              PLNCDF(X,U,SD,P) = 1 - [NORCDF(-(LN(X)-U)/SD)]**P
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PLNCDF(X,P) = 1 - [NORCDF(-LN(X))]**P
!           FOR CONSISTENCY WITH PLNPDF ROUTINE, ALLOW SD AS
!           OPTIONAL PARAMETER.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS/0.1D-100/
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE FIRST ARGUMENT TO PLNCDF IS ',   &
               '      NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(P.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE POWER PARAMETER P IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR--THE STANDARD DEVIATION PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  203 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      TERM1=-LOG(X)/SD
      CALL NODCDF(DBLE(TERM1),DTERM1)
      IF(DTERM1.LE.DEPS)DTERM1=DEPS
      DTERM2=DBLE(P)*DLOG(DTERM1)
      DTERM3=DEXP(DTERM2)
      DTERM4=1.0D0-DTERM3
      CDF=REAL(DTERM4)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PLNCDF
      SUBROUTINE PLNCHA(X,P,SD,HAZ)
!
!     NOTE--POWER-LOGNORMAL PDF IS:
!              PLNPDF(X,U,S,P) = (P/(X*SD))*NORPDF((LN(X)-U)/SD)*
!                                   NORCDF(-(LN(X)-U)/SD))**(P-1)
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PLNPDF(X,S,P) = (P/(X*SD))*NORPDF(LN(X))*
!                                NORCDF(-LN(X)/SD)**(P-1)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE FIRST ARGUMENT TO PLNCHA IS ',   &
               '      NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(X.EQ.0.0)THEN
        GO TO 9999
      ELSEIF(P.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE POWER PARAMETER P IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR--THE STANDARD DEVIATION PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  203 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      CALL PLNCDF(X,SD,P,CDF)
      CDF=1.0-CDF
      IF(CDF.GT.0.0)THEN
        HAZ=-LOG(CDF)
      ELSE
        HAZ=0.0
        WRITE(ICOUT,901)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
  901 FORMAT('**** ERROR: FOR X = ',E15.7,' THE CDF IS ',   &
      'ESSENTIALLY 1.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PLNCHA
      SUBROUTINE PLNHAZ(X,P,SD,HAZ)
!
!     NOTE--POWER-LOGNORMAL PDF IS:
!              PLNPDF(X,U,S,P) = (P/(X*SD))*NORPDF((LN(X)-U)/SD)*
!                                   NORCDF(-(LN(X)-U)/SD))**(P-1)
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PLNPDF(X,S,P) = (P/(X*SD))*NORPDF(LN(X))*
!                                NORCDF(-LN(X)/SD)**(P-1)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE FIRST ARGUMENT TO PLNHAZ IS ',   &
               '      NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(X.EQ.0.0)THEN
        GO TO 9999
      ELSEIF(P.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE POWER PARAMETER P IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR--THE STANDARD DEVIATION PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  203 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      CALL LGNHAZ(X,SD,ALGCDF)
      HAZ=P*ALGCDF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PLNHAZ
      SUBROUTINE PLNPDF(X,P,SD,PDF)
!
!     NOTE--POWER-LOGNORMAL PDF IS:
!              PLNPDF(X,U,S,P) = (P/(X*SD))*NORPDF((LN(X)-U)/SD)*
!                                   NORCDF(-(LN(X)-U)/SD))**(P-1)
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PLNPDF(X,S,P) = (P/(X*SD))*NORPDF(LN(X))*
!                                NORCDF(-LN(X)/SD)**(P-1)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --JULY      1999. FIXED THIS ROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!CCCC JULY 1999.  ADD FOLLOWING LINES.
      DOUBLE PRECISION DX
      DOUBLE PRECISION DXLOG
      DOUBLE PRECISION DP
      DOUBLE PRECISION DSD
!
!CCCC JULY 1995.  ADD FOLLOWING LINE.
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      DPDF=0.0D0
      DEPS=D1MACH(1)
!
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(P.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('***** ERROR--THE POWER PARAMETER, P, IS ',   &
             '      NON-POSITIVE.')
  103 FORMAT('      THE VALUE OF P IS ',G15.7)
  201 FORMAT('***** ERROR--THE STANDARD DEVIATION ',   &
             'PARAMETER IS NON-POSITIVE.')
  203 FORMAT('      THE VALUE IS ',G15.7)
  301 FORMAT('***** ERROR--THE INPUT ARGUMENT IS ',   &
             '      NON-POSITIVE.')
!
      DX=DBLE(X)
      DSD=DBLE(SD)
      DP=DBLE(P)
      DXLOG=DLOG(DX)
!
      DTERM1=DLOG(DP) - DLOG(DSD) - DXLOG
      CALL NODPDF(DXLOG/DSD,DTERM2)
      IF(DTERM2.LT.DEPS)DTERM2=DEPS
      DTERM2=DLOG(DTERM2)
      CALL NODCDF(-DXLOG/DSD,DTERM3)
      IF(DTERM3.LT.DEPS)DTERM3=DEPS
      DTERM4=(DP-1.0D0)*DLOG(DTERM3)
      DTERM5=DTERM1 + DTERM2 + DTERM4
      IF(DTERM5.LE.DBLE(I1MACH(12)))THEN
        PDF=0.0
      ELSEIF(DTERM5.GT.DBLE(I1MACH(13)))THEN
        PDF=0.0
        WRITE(ICOUT,503)X,P,SD
        CALL DPWRST('XXX','BUG ')
      ELSE
        DPDF=DEXP(DTERM5)
        PDF=REAL(DPDF)
      ENDIF
  503 FORMAT('**** FROM PLNPDF: COMPUTATION OVERFLOWS FOR ',   &
             'ARGUMENTS ',3G16.7)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PLNPDF
      SUBROUTINE PLNPPF(P,POWER,SD,PPF)
!
!     NOTE--POWER-LOGNORMAL PPF IS:
!              PLNPPF(P,U,SD,POWER) = EXP(U+Zf*SD)
!           WHERE Zf = NORPPF(1-(1-P)**(1/POWER))
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PLNPPF(P,U,SD,POWER) = EXP(Zf)
!           FOR CONSISTENCY WITH PLNPDF ROUTINE, ALLOW SD AS
!           OPTIONAL PARAMETER.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     MODIFIED        --JUNE      1995. CHECK FOR MAXIMUM VALUE
!     MODIFIED        --SEPTEMBER 1995. BETTER HANDLING OF CASE WHEN
!                                       NORPPF CALLED WITH VALUE CLOSE
!                                       TO 1.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTERM6
      DOUBLE PRECISION DTMIN
!CCCC DOUBLE PRECISION DTMAX
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS / 1.0D-16/
!
!-----START POINT-----------------------------------------------------
!
      PPF=0.0
!
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(P.EQ.0.0)THEN
        GO TO 9999
      ELSEIF(POWER.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)POWER
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PLNPPF ',   &
             ' IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
  101 FORMAT('***** ERROR--THE POWER PARAMETER IS NON-POSITIVE.')
  201 FORMAT('***** ERROR--THE STANDARD DEVIATION PARAMETER IS ',   &
             'NON-POSITIVE.')
!
      DTMIN=D1MACH(1)
      DTERM1= 1.0D0 - DBLE(P)
      DTERM2=1.0D0/DBLE(POWER)
!CCCC SEPTEMBER 1995.  HANDLE CASE WHERE NORPPF CALLED WITH ARGUMENT
!CCCC CLOSE TO 1 BETTER.
!CCCC DTERM3=1.0D0 - DTERM1**DTERM2
      DTERM3=DTERM1**DTERM2
      IF(DTERM3.LT.DEPS)THEN
        IF(DTERM3.LE.DTMIN)DTERM3=DTMIN
        CALL NODPPF(DTERM3,DTERM4)
        DTERM4=-DTERM4
      ELSE
        DTERM3=1.0D0 - DTERM3
        IF(DTERM3.LE.DTMIN)DTERM3=DTMIN
!CCCC JUNE 1995.  ADD FOLLOWING 2 LINES
!CCCC DTMAX=1.0D0-DEPS
!CCCC IF(DTERM3.GE.DTMAX)DTERM3=DTMAX
        CALL NODPPF(DTERM3,DTERM4)
      ENDIF
!
      DTERM5=DBLE(SD)*DTERM4
      DTERM6=DEXP(DTERM5)
      PPF=REAL(DTERM6)
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PLNPPF
      SUBROUTINE PLNRAN(N,P,SD,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE POWER LOGNORMAL DISTRIBUTION
!              WITH SHAPE PARAMETER VALUES = P AND SD.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                                P SHOULD BE POSITIVE.
!                     --SD = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                                SD SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE POWER LOGNORMAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUES = P AND SD.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --P SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.11
!     ORIGINAL VERSION--NOVEMBER  2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(P.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO PLNRAN IS ',   &
             'NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO PLNRAN IS ',   &
             'NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO PLNRAN IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N POWER LOGNORMAL DISTRIBUTION RANDOM NUMBERS
!     USING PERCENT POINT FUNCTION
!
      SD=1.0
      DO 100 I=1,N
        CALL PLNPPF(X(I),P,SD,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PLNRAN
      DOUBLE PRECISION FUNCTION PPND16 (P, IFAULT)
!
!      ALGORITHM AS241  APPL. STATIST. (1988) VOL. 37, NO. 3
!
!      Produces the normal deviate Z corresponding to a given lower
!      tail area of P; Z is accurate to about 1 part in 10**16.
!
!      The hash sums below are the sums of the mantissas of the
!      coefficients.   They are included for use in checking
!      transcription.
!
      DOUBLE PRECISION ZERO, ONE, HALF, SPLIT1, SPLIT2, CONST1,   &
               CONST2, A0, A1,   A2, A3, A4, A5, A6, A7, B1, B2, B3,   &
                B4, B5, B6, B7,   &
               C0, C1, C2, C3, C4, C5, C6, C7,   D1, D2, D3, D4, D5,   &
               D6, D7, E0, E1, E2, E3, E4, E5, E6, E7, F1, F2, F3,   &
               F4, F5, F6, F7, P, Q, R
      PARAMETER (ZERO = 0.D0, ONE = 1.D0, HALF = 0.5D0,   &
               SPLIT1 = 0.425D0, SPLIT2 = 5.D0,   &
               CONST1 = 0.180625D0, CONST2 = 1.6D0)
!
!      Coefficients for P close to 0.5
!
      PARAMETER (A0 = 3.3871328727963666080D0,   &
                 A1 = 1.3314166789178437745D+2,   &
                 A2 = 1.9715909503065514427D+3,   &
                 A3 = 1.3731693765509461125D+4,   &
                 A4 = 4.5921953931549871457D+4,   &
                 A5 = 6.7265770927008700853D+4,   &
                 A6 = 3.3430575583588128105D+4,   &
                 A7 = 2.5090809287301226727D+3,   &
                 B1 = 4.2313330701600911252D+1,   &
                 B2 = 6.8718700749205790830D+2,   &
                 B3 = 5.3941960214247511077D+3,   &
                 B4 = 2.1213794301586595867D+4,   &
                 B5 = 3.9307895800092710610D+4,   &
                 B6 = 2.8729085735721942674D+4,   &
                 B7 = 5.2264952788528545610D+3)
!      HASH SUM AB    55.8831928806149014439
!
!      Coefficients for P not close to 0, 0.5 or 1.
!
      PARAMETER (C0 = 1.42343711074968357734D0,   &
                 C1 = 4.63033784615654529590D0,   &
                 C2 = 5.76949722146069140550D0,   &
                 C3 = 3.64784832476320460504D0,   &
                 C4 = 1.27045825245236838258D0,   &
                 C5 = 2.41780725177450611770D-1,   &
                 C6 = 2.27238449892691845833D-2,   &
                 C7 = 7.74545014278341407640D-4,   &
                 D1 = 2.05319162663775882187D0,   &
                 D2 = 1.67638483018380384940D0,   &
                 D3 = 6.89767334985100004550D-1,   &
                 D4 = 1.48103976427480074590D-1,   &
                 D5 = 1.51986665636164571966D-2,   &
                 D6 = 5.47593808499534494600D-4,   &
                 D7 = 1.05075007164441684324D-9)
!      HASH SUM CD    49.33206503301610289036
!
!      Coefficients for P near 0 or 1.
!
      PARAMETER (E0 = 6.65790464350110377720D0,   &
                 E1 = 5.46378491116411436990D0,   &
                 E2 = 1.78482653991729133580D0,   &
                 E3 = 2.96560571828504891230D-1,   &
                 E4 = 2.65321895265761230930D-2,   &
                 E5 = 1.24266094738807843860D-3,   &
                 E6 = 2.71155556874348757815D-5,   &
                 E7 = 2.01033439929228813265D-7,   &
                 F1 = 5.99832206555887937690D-1,   &
                 F2 = 1.36929880922735805310D-1,   &
                 F3 = 1.48753612908506148525D-2,   &
                 F4 = 7.86869131145613259100D-4,   &
                 F5 = 1.84631831751005468180D-5,   &
                 F6 = 1.42151175831644588870D-7,   &
                 F7 = 2.04426310338993978564D-15)
!      HASH SUM EF    47.52583317549289671629
!
      IFAULT = 0
      Q = P - HALF
      IF (ABS(Q) .LE. SPLIT1) THEN
        R = CONST1 - Q * Q
        PPND16 = Q * (((((((A7 * R + A6) * R + A5) * R + A4) * R + A3)   &
                  * R + A2) * R + A1) * R + A0) /   &
                     (((((((B7 * R + B6) * R + B5) * R + B4) * R + B3)   &
                  * R + B2) * R + B1) * R + ONE)
        RETURN
      ELSE
        IF (Q .LT. ZERO) THEN
          R = P
        ELSE
          R = ONE - P
        END IF
        IF (R .LE. ZERO) THEN
          IFAULT = 1
          PPND16 = ZERO
          RETURN
        END IF
        R = SQRT(-LOG(R))
        IF (R .LE. SPLIT2) THEN
          R = R - CONST2
          PPND16 = (((((((C7 * R + C6) * R + C5) * R + C4) * R + C3)   &
                  * R + C2) * R + C1) * R + C0) /   &
                    (((((((D7 * R + D6) * R + D5) * R + D4) * R + D3)   &
                  * R + D2) * R + D1) * R + ONE)
        ELSE
          R = R - SPLIT2
          PPND16 = (((((((E7 * R + E6) * R + E5) * R + E4) * R + E3)   &
                  * R + E2) * R + E1) * R + E0) /   &
                    (((((((F7 * R + F6) * R + F5) * R + F4) * R + F3)   &
                  * R + F2) * R + F1) * R + ONE)
        END IF
        IF (Q .LT. ZERO) PPND16 = - PPND16
        RETURN
      END IF
!
      RETURN
      END FUNCTION PPND16 
      SUBROUTINE PNRCDF(X,P,CDF)
!CCCC SUBROUTINE PNRCDF(X,P,SD,CDF)
!
!     NOTE--POWER-NORMAL CDF IS:
!              PNRCDF(X,U,SD,P) = 1 - [NORCDF(-(X-U)/SD)]**P
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PNRCDF(X,P) = 1 - [NORCDF(X)]**P
!           FOR CONSISTENCY WITH PNRPDF ROUTINE, ALLOW SD AS
!           OPTIONAL PARAMETER.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --OCTOBER   2001.  ALGORITHM UPDATED
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!CCCC DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA DEPS/0.1D-20/
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
      XMAXVL=38.0
!
      IF(P.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE POWER PARAMETER P IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
!CCCC ELSEIF(SD.LE.0.0)THEN
!CCCC   WRITE(ICOUT,201)
!C201   FORMAT('***** ERROR--THE STANDARD DEVIATION ',
!CCCC1         'PARAMETER IS NON-POSITIVE.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,103)SD
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
      ELSEIF(ABS(X).GT.XMAXVL)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--FOR THE PNRCDF FUNCTION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)-XMAXVL,XMAXVL
  303   FORMAT('      DATAPLOT IS UNABLE TO COMPUTE NORCDF FOR VALUES',   &
             ' OUTSIDE THE RANGE (',E15.7,',',E15.7,')')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)X
        CALL DPWRST('XXX','BUG ')
        IF(X.GT.XMAXVL)CDF=1.0
        GO TO 9999
      ENDIF
  103 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      CALL NODCDF(DBLE(-X),DTERM1)
      DTERM2=DBLE(P)*DLOG(DTERM1)
      DTERM3=DEXP(DTERM2)
      DTERM4=1.0D0-DTERM3
      CDF=REAL(DTERM4)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PNRCDF
      SUBROUTINE PNRCHA(X,P,S,HAZ)
!
!     NOTE--POWER-NORMAL PDF IS:
!              PNRPDF(X,U,S,P) = (P/S)*NORPDF((X-U)/S)*
!                                   NORCDF(-(X-U)/S))**(P-1)
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PNRPDF(X,S,P) = (P/S)*NORPDF(X)*NORCDF(-X/S)**(P-1)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --NOVEMBER  2001. FORCE SD PARAMETER TO BE 1
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0
      SD=1.0
      S=1.0
!
      IF(P.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE POWER PARAMETER P IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)P
  103   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR--THE STANDARD DEVIATION PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      Z=-X/SD
      CALL NODCDF(DBLE(Z),DCDF)
      IF(DCDF.GT.0.0D0)THEN
        HAZ=-REAL(DLOG(DCDF**DBLE(P)))
      ELSE
        HAZ=0.0
        WRITE(ICOUT,901)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
  901 FORMAT('***** ERROR: FOR X = ',E15.7,' THE POWER NORMAL CDF ',   &
      'IS ESSENTIALLY 1.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PNRCHA
      subroutine pnrerr(icode,number)
!
! *   AUTHORS: Necip Doganaksoy and Wayne Nelson
! *   PURPOSE: Maximum likelihood fitting of the power-normal and
! *            -lognormal models to censored life or strength data
! *            from specimens of various sizes
! *   DOCUMENTATION: Wayne Nelson and Necip Doganaksoy, "A Computer
! *                  Program POWNOR for Fitting the Power-Normal and
! *                  -Lognormal Models to Life or Strength Data from
! *                  Specimens of Various Sizes", NISTIR 4760, 3/1992.
