      SUBROUTINE PNRHAZ(X,P,S,HAZ)
!
!     NOTE--POWER-NORMAL PDF IS:
!              PNRPDF(X,U,S,P) = (P/S)*NORPDF((X-U)/S)*
!                                   NORCDF(-(X-U)/S))**(P-1)
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PNRPDF(X,S,P) = (P/S)*NORPDF(X)*NORCDF(-X/S)**(P-1)
!           HAZARD FUNCTION IS:
!              H(X,S,P) = P*NORHAZ(Z)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --NOVEMBER  2001. FORCE SD PARAMETER TO BE 1
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DNORHZ
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0
      SD=1.0
      S=1.0
!
      IF(P.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE POWER PARAMETER P IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)P
  103   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR--THE STANDARD DEVIATION ',   &
               'PARAMETER IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      Z=X/SD
      CALL NODPDF(DBLE(Z),DPDF)
      CALL NODCDF(DBLE(-Z),DCDF)
      IF(DCDF.GT.0.0D0)THEN
        DNORHZ=(DPDF/DCDF)/DBLE(SD)
        DHAZ=DBLE(P)*DNORHZ
        HAZ=REAL(DHAZ)
      ELSE
        HAZ=0.0
        WRITE(ICOUT,901)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
  901 FORMAT('***** ERROR: FOR X = ',E15.7,' THE NORMAL CDF IS ',   &
      'ESSENTIALLY 0.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PNRHAZ
      DOUBLE PRECISION FUNCTION PNRFUN(x,npar,timel,timeu,rlengt)
!
! *   AUTHORS: Necip Doganaksoy and Wayne Nelson
! *   PURPOSE: Maximum likelihood fitting of the power-normal and
! *            -lognormal models to censored life or strength data
! *            from specimens of various sizes
! *   DOCUMENTATION: Wayne Nelson and Necip Doganaksoy, "A Computer
! *                  Program POWNOR for Fitting the Power-Normal and
! *                  -Lognormal Models to Life or Strength Data from
! *                  Specimens of Various Sizes", NISTIR 4760, 3/1992.
! *   PROJECT: 1990-91 ASA/NIST/NSF Fellowship
!
! LOGLIKELIHOOD FUNCTION
!
      implicit DOUBLE PRECISION (a-h,o-z)
!
      DOUBLE PRECISION x(npar)
      DOUBLE PRECISION timel(*)
      DOUBLE PRECISION timeu(*)
      DOUBLE PRECISION rlengt(*)
!
      common /PNRDAT/ iss
      common /PNRFVA/ rmufix,rlnsig,rlnfix
      common /PNRVAR/ mutype,lnsigt,lntype
!
!CCCC external dnordf
      external alnorm
!
      rlogli=0.0d0
      ipar=0
      if (mutype.eq.0) then
         ipar=ipar+1
         rmu=x(ipar)
      else
         rmu=rmufix
      endif
                                                                                                                                  
      if (lnsigt.eq.0) then
         ipar=ipar+1
         rlnsig=x(ipar)
      else
         rlnsig=rlnsig
      endif
                                                                                                                                  
      if (lntype.eq.0) then
         ipar=ipar+1
         rlnlno=x(ipar)
      else
         rlnlno=rlnfix
      endif
                                                                                                                                  
      zero=0.0d0
      pi=4.d0*(datan(.5d0)+datan(1.d0/3.d0))
      accum=0.d0
                                                                                                                                  
      do 100 i=1,iss
                                                                                                                                  
! complete data
         if (timel(i).eq.timeu(i))then
            z=(timel(i)-rmu)/exp(rlnsig)
            z=ztran(z)
            phiz=((2.d0*pi)**(-.5d0))*exp(-.5d0*z*z)
            relphi=alnorm(-z,.false.)
            rho=rlengt(i)/exp(rlnlno)
            rlogli=-log(rlengt(i))+rlnlno+rlnsig+(z*z)/2.d0-   &
                    (rho-1.d0)*log(relphi)
!
! right censored data
!
         elseif (timeu(i).eq.1e10)then
            z=(timel(i)-rmu)/exp(rlnsig)
            z=ztran(z)
            relphi=alnorm(-z,.false.)
            rho=rlengt(i)/exp(rlnlno)
            rlogli=-rho*log(relphi)
!
! left censored data
!
         elseif (timel(i).eq.-1e10)then
            z=(timeu(i)-rmu)/exp(rlnsig)
            z=ztran(z)
            relphi=alnorm(-z,.false.)
            rho=rlengt(i)/exp(rlnlno)
            rlogli=-log(1.d0-(relphi**rho))
!
! interval data
!
         elseif (timeu(i).gt.timel(i))then
            zl=(timel(i)-rmu)/exp(rlnsig)
            zl=ztran(zl)
            zu=(timeu(i)-rmu)/exp(rlnsig)
            zu=ztran(zu)
            relphl=alnorm(-zl,.false.)
            relphu=alnorm(-zu,.false.)
            rho=rlengt(i)/exp(rlnlno)
            rlogli=-log((relphl**rho)-(relphu**rho))
         endif
!
         accum=accum+rlogli
100   continue
!
      pnrfun=accum
!
      return
      end
      SUBROUTINE PNRPDF(X,P,PDF)
!CCCC SUBROUTINE PNRPDF(X,P,SD,PDF)
!CCCC SD IS ACTUALLY A SCALE PARAMETER IN THIS CASE.  DON'T USE
!CCCC IT COMPUTATION OF STANDARD FORM OF DISTRIBUTION.
!
!     NOTE--POWER-NORMAL PDF IS:
!              PNRPDF(X,U,S,P) = (P/S)*NORPDF((X-U)/S)*
!                                   NORCDF(-(X-U)/S))**(P-1)
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PNRPDF(X,P) = P*NORPDF(X)*NORCDF(-X)**(P-1)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --NOVEMBER  2001.  MODIFY TO NOT USE SD, SOME
!                                        OTHER COMPUTATIONAL
!                                        MODIFICATIONS.
!
!CCCC NOTE: THE NODCDF ROUTINE (BASED ON ALNORM FROM APPLIED
!CCCC       STATISTICS) RETURNS 0 FOR X < -18.66 WHICH IN TURN
!CCCC       MAKES THIS PDF=0.
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      DOUBLE PRECISION DTERM1
!CCCC DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!CCCC JULY 1995.  ADD FOLLOWING LINE.
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DEPS2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS/0.1D-300/
      DATA DEPS2/-0.1D35/
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      XMAXVL=38.0
!
      IF(P.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE POWER PARAMETER P IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)P
  203   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ABS(X).GT.XMAXVL)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--FOR THE PNRPDF FUNCTION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)-XMAXVL,XMAXVL
  303   FORMAT('      DATAPLOT IS UNABLE TO COMPUTE NORCDF FOR VALUES',   &
               ' OUTSIDE THE RANGE (',E15.7,',',E15.7,')')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!CCCC DEPS=D1MACH(1)
!
      DTERM1=DLOG(DBLE(P))
!CCCC DTERM2=DLOG(DBLE(SD))
!CCCC TERM1=X/SD
!
      IF(ABS(X).GT.38.D0)THEN
        DTERM3=DEPS
      ELSE
        CALL NODPDF(DBLE(X),DTERM3)
      ENDIF
      IF(DTERM3.LE.DEPS)DTERM3=DEPS
      DTERM3=DLOG(DTERM3)
!CCCC TERM3=-TERM1
      IF(X.GT.DBLE(XMAXVL))THEN
        CALL NODCDF(DBLE(-XMAXVL),DTERM4)
      ELSEIF(X.LT.-DBLE(XMAXVL))THEN
        CALL NODCDF(DBLE(XMAXVL),DTERM4)
      ELSE
        CALL NODCDF(DBLE(-X),DTERM4)
      ENDIF
      IF(DTERM4.LE.DEPS)DTERM4=DEPS
      DTERM4=DBLE(P-1.0)*DLOG(DTERM4)
      DTERM5=DTERM1 + DTERM3 + DTERM4
      IF(DTERM5.LT.DEPS2)THEN
        PDF=0.0
      ELSEIF(DTERM5.GT.-DEPS2)THEN
        PDF=0.0
      ELSE
        DPDF=DEXP(DTERM5)
        PDF=REAL(DPDF)
      ENDIF
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PNRPDF
      subroutine pnrper(p1,tp2,tp3,vp1,vtp2,vtp3,cp1tp2,cp1tp3,ctp2tp3,   &
            slengt,noleng,allfix,   &
            icapty,icapsw)
!
! *   AUTHORS: Necip Doganaksoy and Wayne Nelson
! *   PURPOSE: Maximum likelihood fitting of the power-normal and
! *            -lognormal models to censored life or strength data
! *            from specimens of various sizes
! *   DOCUMENTATION: Wayne Nelson and Necip Doganaksoy, "A Computer
! *                  Program POWNOR for Fitting the Power-Normal and
! *                  -Lognormal Models to Life or Strength Data from
! *                  Specimens of Various Sizes", NISTIR 4760, 3/1992.
! *   PROJECT: 1990-91 ASA/NIST/NSF Fellowship
!
! ML ESTIMATES OF PERCENTILES AND THEIR CONFIDENCE LIMITS
!
      implicit double precision (a-h,o-z)
      double precision f(16),slengt(15)
      dimension pctpri(16)
      character*4 pctpri
      logical allfix
!CCCC external dnorin
!
      character*4 ICAPSW
      character*4 ICAPTY
!
      INCLUDE 'DPCOP2.INC'
!
      data f /.001d0, .002d0, .005d0, .01d0, .02d0, .05d0,.1d0,   &
           .3d0, .5d0, .7d0, .9d0, .95d0, .98d0, .99d0, .995d0,   &
           .999d0/
      data pctpri /'0.1','0.2','0.5','1','2','5','10','30','50','70',   &
                      '90', '95','98','99','99.5','99.9'/
      p2=exp(tp2)
      p3=exp(tp3)
      pinum=4.d0*(datan(.5d0)+datan(1.d0/3.d0))
      const=(2.d0*pinum)**(-.5d0)
      if(icapsw.eq.'ON' .and. icapty.eq.'HTML')then
      elseif(icapsw.eq.'ON' .and. icapty.eq.'LATE')then
      elseif(icapsw.eq.'ON' .and. icapty.eq.'RTF ')then
      else
        write(icout,999)
  999   format(1x)
        CALL DPWRST('XXX','WRIT')
        write(icout,999)
        CALL DPWRST('XXX','WRIT')
        if(noleng.ne.0)then
          if (allfix) then
            write(icout,4201)
 4201       format('PERCENTILE ESTIMATES')
            CALL DPWRST('XXX','WRIT')
          else
            write(icout,4203)
 4203       format('MAXIMUM LIKELIHOOD ESTIMATES FOR DISTRIBUTION ',   &
                  'PERCENTILES')
            CALL DPWRST('XXX','WRIT')
            write(icout,4205)
 4205       format('WITH APPROXIMATE 95% CONFIDENCE LIMITS')
            CALL DPWRST('XXX','WRIT')
          endif
        endif
        do 177 maini=1,noleng
          write(icout,999)
          CALL DPWRST('XXX','WRIT')
          write(icout,4211)SLENGT(MAINI)
 4211     format('LENGTH = ',F15.4)
          CALL DPWRST('XXX','WRIT')
          write(icout,999)
          CALL DPWRST('XXX','WRIT')
          if(allfix)then
            write(icout,4221)
 4221       format('PCT.       ESTIMATE')
            CALL DPWRST('XXX','WRIT')
          else
            write(icout,4223)
 4223       format('PCT.    ML ESTIMATE    LOWER LIMIT     ',   &
                   'UPPER LIMIT     STD. ERROR')
            CALL DPWRST('XXX','WRIT')
          endif
          do 100 i=1,16,1
            fhp=1.d0-((1.d0-f(i))**(p3/slengt(maini)))
!NIST       zfhp=dnorin(fhp)
            CALL NODPPF(FHP,ZFHP)
            rmlper=p1+zfhp*p2
            if (allfix) then
              write(icout,4231)pctpri(i),rmlper
 4231         format(1X,A4,3X,F12.4)
              CALL DPWRST('XXX','WRIT')
            else
              phiz=const*exp(-.5d0*zfhp*zfhp)
              term=-(p2*(1.d0-fhp)*p3*   &
                   log(1.d0-f(i)))/(slengt(maini)*phiz)
              varper=vp1+((zfhp*p2)**2.d0)*vtp2+   &
                     (term*term*vtp3)+2.d0*zfhp*p2*cp1tp2   &
                     +2.d0*term*cp1tp3+2.d0*zfhp*p2*term*ctp2tp3
              rstd=varper**.5d0
              rlow=rmlper-1.96d0*rstd
              rup=rmlper+1.96d0*rstd
              write(icout,4236)pctpri(i),rmlper,rlow,rup,rstd
 4236         format(1x,a4,3x,f12.4,3x,f12.4,3x,f12.4,3x,f12.4)
              CALL DPWRST('XXX','WRIT')
            endif
  100     continue
  177   continue
      endif
!
      return
      end
      SUBROUTINE PNRPPF(P,POWER,PPF)
!CCCC SUBROUTINE PNRPPF(P,POWER,S,PPF)
!
!CCCC SD IS ACTUALLY A SCALE PARAMETER IN THIS CASE.  DON'T USE
!CCCC IT COMPUTATION OF STANDARD FORM OF DISTRIBUTION.
!     NOTE--POWER-NORMAL PPF IS:
!              PNRPPF(P,U,SD,POWER) = U+Zf*SD
!           WHERE Zf = NORPPF(1-(1-P)**(1/POWER))
!           STANDARD FORM OF THIS DISTRIBUTION IS:
!              PNRPPF(P,U,SD,POWER) = Zf
!           FOR CONSISTENCY WITH PNRPDF ROUTINE, ALLOW SD AS
!           OPTIONAL PARAMETER.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     MODIFIED        --JUNE      1995. CHECK FOR MAXIMUM VALUE
!     MODIFIED        --SEPTEMBER 1995. BETTER HANDLING OF CASE WHEN
!                                       NORPPF CALLED WITH VALUE CLOSE
!                                       TO 1.
!     MODIFIED        --NOVEMBER  2001. ALGORITHM UPDATES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTMIN, DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS/1.0D-16/
!
!-----START POINT-----------------------------------------------------
!
      PPF=0.0
!
!CCCC NOVEMBER 2001: FORCE SD TO BE 1 (THIS IS ACTUALLY A SCALE
!CCCC PARAMETER, SO HANDLE IN THE STANDARD WAY).
!
      PPF=0.0
      SD=1.0
      DTMIN=D1MACH(1)
!
      IF(P.LE.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
               'PNRPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(POWER.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE POWER PARAMETER IS ',   &
               '      NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)POWER
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      DTERM1= 1.0D0 - DBLE(P)
      DTERM2=1.0D0/DBLE(POWER)
      DTERM3=DTERM1**DTERM2
!CCCC SEPTEMBER 1995.  HANDLE CASE WHERE NORPPF CALLED WITH ARGUMENT
!CCCC CLOSE TO 1 BETTER.
      IF(DTERM3.LT.DEPS)THEN
        IF(DTERM3.LE.DTMIN)DTERM3=DTMIN
        CALL NODPPF(DTERM3,DTERM4)
        DTERM4=-DTERM4
      ELSE
        DTERM3=1.0D0 - DTERM3
        IF(DTERM3.LE.DTMIN)DTERM3=DTMIN
!CCCC JUNE 1995.  ADD FOLLOWING 2 LINES
!CCCC DTMAX=1.0D0-DEPS
!CCCC IF(DTERM3.GE.DTMAX)DTERM3=DTMAX
        CALL NODPPF(DTERM3,DTERM4)
      ENDIF
!
      DTERM5=DBLE(SD)*DTERM4
      PPF=REAL(DTERM5)
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PNRPPF
      SUBROUTINE PNRRAN(N,P,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE POWER NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = P.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P  = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER.
!                                P SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE POWER NORMAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = P.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --P SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO PNRRAN ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(P.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO PNRRAN ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N POWER NORMAL DISTRIBUTION RANDOM NUMBERS
!     USING PERCENT POINT FUNCTION
!
!CCCC SD=1.0
      DO 100 I=1,N
!CCCC   CALL PNRPPF(X(I),P,SD,XTEMP)
        CALL PNRPPF(X(I),P,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PNRRAN
      SUBROUTINE PNRWMA(ITITLE,NPAR,X,ICAPSW,ICAPTY)
!
! *   AUTHORS: Necip Doganaksoy and Wayne Nelson
! *   PURPOSE: Maximum likelihood fitting of the power-normal and
! *            -lognormal models to censored life or strength data
! *            from specimens of various sizes
! *   DOCUMENTATION: Wayne Nelson and Necip Doganaksoy, "A Computer
! *                  Program POWNOR for Fitting the Power-Normal and
! *                  -Lognormal Models to Life or Strength Data from
! *                  Specimens of Various Sizes", NISTIR 4760, 3/1992.
! *   PROJECT: 1990-91 ASA/NIST/NSF Fellowship
!
!     Declarations
!
      DOUBLE PRECISION X(NPAR,NPAR)
!
      CHARACTER*40 ITITLE
      CHARACTER*4  ICAPSW
      CHARACTER*4  ICAPTY
!
      CHARACTER*10 IFORMT
!
      REAL R1MACH
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      IF(IPRINT.EQ.'ON')THEN
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'HTML')THEN
      ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'LATE')THEN
      ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF')THEN
      ELSE
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
!
        IFORMT='( G15.7)'
        WRITE(IFORMT(2:2),'(I1)')NPAR
        WRITE(ICOUT,4001)ITITLE
 4001   FORMAT(10X,A40)
        CALL DPWRST('XXX','WRIT')
        DO 4010 I=1,NPAR
          WRITE(ICOUT,IFORMT) (X(I,J),J=1,NPAR)
          CALL DPWRST('XXX','WRIT')
 4010   CONTINUE
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE PNRWMA
      SUBROUTINE POICDF(X,ALAMBA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE POISSON DISTRIBUTION
!              WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = ALAMBA.
!              THE POISSON DISTRIBUTION USED
!              HEREIN HAS MEAN = ALAMBA
!              AND STANDARD DEVIATION = SQRT(ALAMBA).
!              THIS DISTRIBUTION IS DEFINED FOR
!              ALL DISCRETE NON-NEGATIVE INTEGER  X--X = 0, 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = EXP(-ALAMBA) * ALAMBA**X / X!.
!              THE POISSON DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF EVENTS
!              IN THE INTERVAL (0,ALAMBA) WHEN
!              THE WAITING TIME BETWEEN EVENTS
!              IS EXPONENTIALLY DISTRIBUTED
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE AND
!                                INTEGRAL-VALUED.
!                     --ALAMBA = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                ALAMBA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF
!             FOR THE POISSON DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = ALAMBA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE AND INTEGRAL-VALUED.
!                 --ALAMBA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DATAN.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SINGLE PRECISION TAIL LENGTH
!              PARAMETER ALAMBA IS     NOT     RESTRICTED
!              TO ONLY INTEGER VALUES.
!              ALAMBA CAN BE SET TO ANY POSITIVE REAL
!              VALUE--INTEGER OR NON-INTEGER.
!            --NOTE THAT EVEN THOUGH THE INPUT
!              TO THIS CUMULATIVE
!              DISTRIBUTION FUNCTION SUBROUTINE
!              FOR THIS DISCRETE DISTRIBUTION
!              SHOULD (UNDER NORMAL CIRCUMSTANCES) BE A
!              DISCRETE INTEGER VALUE,
!              THE INPUT VARIABLE X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL INPUT ****DATA****
!              (AS OPPOSED TO SAMPLE SIZE, FOR EXAMPLE)
!              VARIABLES TO ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 87-121,
!                 ESPECIALLY PAGE 114, FORMULA 93.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 112.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 941, FORMULAE 26.4.4 AND 26.4.5,
!                 AND PAGE 929.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 146-154.
!               --COX AND MILLER, THE THEORY OF STOCHASTIC
!                 PROCESSES, 1965, PAGE 7.
!               --GENERAL ELECTRIC COMPANY, TABLES OF THE
!                 INDIVIDUAL AND CUMULATIVE TERMS OF POISSON
!                 DISTRIBUTION, 1962.
!               --OWEN, HANDBOOK OF STATISTICAL
!                 TABLES, 1962, PAGES 259-261.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       2006. USE NORMAL APPROXIMATION
!                                       FOR LARGE LAMBDA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX,PI,CHI,SUM,TERM,AI,DGCDF
      DOUBLE PRECISION DSQRT,DEXP,DCDF,DMU,DSD
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265358979D0/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(ALAMBA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('*****ERROR--THE SECOND ARGUMENT TO POICDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAMBA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('*****WARNING--THE FIRST ARGUMENT TO POICDF ',   &
               'IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      INTX=INT(X+0.0001)
      FINTX=REAL(INTX)
      DEL=X-FINTX
      IF(DEL.LT.0.0)DEL=-DEL
      IF(DEL.GT.0.001)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** WARNING--THE FIRST ARGUMENT TO POICDF ',   &
               'IS NON-INTEGRAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!     EXPRESS THE POISSON CUMULATIVE DISTRIBUTION
!     FUNCTION IN TERMS OF THE EQUIVALENT CHI-SQUARED
!     CUMULATIVE DISTRIBUTION FUNCTION,
!     AND THEN EVALUATE THE LATTER.
!
!     MAY 2006: FOR LARGE LAMBDA, THE CHI-SQUARE APPROACH CAN
!               RESULT IN A SUM > LARGEST MACHINE DOOBLE PRECISION
!               NUMBER.  SO FOR LAMBDA >= 500, USE THE NORMAL
!               APPROXIMATION WITH MU = LAMBDA, SD=SQRT(LAMBDA).
!
      IF(ALAMBA.GE.500.0)THEN
        NU=INT(X+0.0001)
        DX=DBLE(NU)
        DMU=DBLE(ALAMBA)
        DSD=DSQRT(DBLE(ALAMBA))
        DX=(DX-DMU)/DSD
        CALL NODCDF(DX,DCDF)
        CDF=REAL(DCDF)
        GO TO 9000
      ENDIF
!
      DX=ALAMBA
      DX=2.0D0*DX
      NU=INT(X+0.0001)
      NU=2*(1+NU)
!
      CHI=DSQRT(DX)
      IEVODD=NU-2*(NU/2)
      IF(IEVODD.EQ.0)GO TO 120
!
      SUM=0.0D0
      TERM=1.0/CHI
      IMIN=1
      IMAX=NU-1
      GO TO 130
!
  120 CONTINUE
      SUM=1.0D0
      TERM=1.0D0
      IMIN=2
      IMAX=NU-2
!
  130 CONTINUE
      IF(IMIN.GT.IMAX)GO TO 160
      DO 100 I=IMIN,IMAX,2
      AI=I
      TERM=TERM*(DX/AI)
      SUM=SUM+TERM
  100 CONTINUE
!
  160 CONTINUE
      SUM=SUM*DEXP(-DX/2.0D0)
      IF(IEVODD.EQ.0)GO TO 170
      SUM=(DSQRT(2.0D0/PI))*SUM
      SPCHI=CHI
      CALL NORCDF(SPCHI,GCDF)
      DGCDF=GCDF
      SUM=SUM+2.0D0*(1.0D0-DGCDF)
  170 CONTINUE
      CDF=SUM
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE POICDF
      SUBROUTINE PODCDF(X,ALAMBA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X
!              FOR THE POISSON DISTRIBUTION
!              WITH DOUBLE PRECISION
!              TAIL LENGTH PARAMETER = ALAMBA.
!              THE POISSON DISTRIBUTION USED
!              HEREIN HAS MEAN = ALAMBA
!              AND STANDARD DEVIATION = SQRT(ALAMBA).
!              THIS DISTRIBUTION IS DEFINED FOR
!              ALL DISCRETE NON-NEGATIVE INTEGER  X--X = 0, 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = EXP(-ALAMBA) * ALAMBA**X / X!.
!              THE POISSON DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF EVENTS
!              IN THE INTERVAL (0,ALAMBA) WHEN
!              THE WAITING TIME BETWEEN EVENTS
!              IS EXPONENTIALLY DISTRIBUTED
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!
!              NOTE: THIS IS A COPY OF POICDF.  DOUBLE PRECISION
!                    MAY BE HELPFUL FOR LARGE VALUES OF LAMBDA.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE AND
!                                INTEGRAL-VALUED.
!                     --ALAMBA = THE DOUBLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                ALAMBA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF
!             FOR THE POISSON DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = ALAMBA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE AND INTEGRAL-VALUED.
!                 --ALAMBA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DATAN.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE DOUBLE PRECISION TAIL LENGTH
!              PARAMETER ALAMBA IS     NOT     RESTRICTED
!              TO ONLY INTEGER VALUES.
!              ALAMBA CAN BE SET TO ANY POSITIVE REAL
!              VALUE--INTEGER OR NON-INTEGER.
!            --NOTE THAT EVEN THOUGH THE INPUT
!              TO THIS CUMULATIVE
!              DISTRIBUTION FUNCTION SUBROUTINE
!              FOR THIS DISCRETE DISTRIBUTION
!              SHOULD (UNDER NORMAL CIRCUMSTANCES) BE A
!              DISCRETE INTEGER VALUE,
!              THE INPUT VARIABLE X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL INPUT ****DATA****
!              (AS OPPOSED TO SAMPLE SIZE, FOR EXAMPLE)
!              VARIABLES TO ALL
!              DATAPAC SUBROUTINES ARE DOUBLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 87-121,
!                 ESPECIALLY PAGE 114, FORMULA 93.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 112.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 941, FORMULAE 26.4.4 AND 26.4.5,
!                 AND PAGE 929.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 146-154.
!               --COX AND MILLER, THE THEORY OF STOCHASTIC
!                 PROCESSES, 1965, PAGE 7.
!               --GENERAL ELECTRIC COMPANY, TABLES OF THE
!                 INDIVIDUAL AND CUMULATIVE TERMS OF POISSON
!                 DISTRIBUTION, 1962.
!               --OWEN, HANDBOOK OF STATISTICAL
!                 TABLES, 1962, PAGES 259-261.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       2006. USE NORMAL APPROXIMATION
!                                       FOR LARGE LAMBDA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265358979D0/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
      IF(ALAMBA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('*****ERROR--THE SECOND ARGUMENT TO POICDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAMBA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('*****WARNING--THE FIRST ARGUMENT ',   &
               'TO POICDF IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      INTX=INT(X+0.0001D0)
      FINTX=REAL(INTX)
      DEL=X-FINTX
      IF(DEL.LT.0.0)DEL=-DEL
      IF(DEL.GT.0.001)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** WARNING--THE FIRST ARGUMENT ',   &
               'TO THE POICDF SUBROUTINE IS NON-INTEGRAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.8,'.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     EXPRESS THE POISSON CUMULATIVE DISTRIBUTION
!     FUNCTION IN TERMS OF THE EQUIVALENT CHI-SQUARED
!     CUMULATIVE DISTRIBUTION FUNCTION,
!     AND THEN EVALUATE THE LATTER.
!
!     MAY 2006: FOR LARGE LAMBDA, THE CHI-SQUARE APPROACH CAN
!               RESULT IN A SUM > LARGEST MACHINE DOOBLE PRECISION
!               NUMBER.  SO FOR LAMBDA >= 500, USE THE NORMAL
!               APPROXIMATION WITH MU = LAMBDA, SD=SQRT(LAMBDA).
!
      IF(ALAMBA.GE.500.0D0)THEN
        NU=INT(X+0.0001D0)
        DX=DBLE(NU)
        DMU=DBLE(ALAMBA)
        DSD=DSQRT(DBLE(ALAMBA))
        DX=(DX-DMU)/DSD
        CALL NODCDF(DX,DCDF)
        CDF=DCDF
        GO TO 9000
      ENDIF
!
      DX=ALAMBA
      DX=2.0D0*DX
      NU=INT(X+0.0001D0)
      NU=2*(1+NU)
!
      CHI=DSQRT(DX)
      IEVODD=NU-2*(NU/2)
      IF(IEVODD.EQ.0)GO TO 120
!
      SUM=0.0D0
      TERM=1.0D0/CHI
      IMIN=1
      IMAX=NU-1
      GO TO 130
!
  120 CONTINUE
      SUM=1.0D0
      TERM=1.0D0
      IMIN=2
      IMAX=NU-2
!
  130 CONTINUE
      IF(IMIN.GT.IMAX)GO TO 160
      DO 100 I=IMIN,IMAX,2
      AI=I
      TERM=TERM*(DX/AI)
      SUM=SUM+TERM
  100 CONTINUE
!
  160 CONTINUE
      SUM=SUM*DEXP(-DX/2.0D0)
      IF(IEVODD.EQ.0)GO TO 170
      SUM=(DSQRT(2.0D0/PI))*SUM
      SPCHI=CHI
      CALL NODCDF(SPCHI,GCDF)
      DGCDF=GCDF
      SUM=SUM+2.0D0*(1.0D0-DGCDF)
  170 CONTINUE
      CDF=SUM
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PODCDF
      REAL FUNCTION POIFUN(ALAMB)
!
!     PURPOSE--DPMLPO CALLS FZERO TO FIND A ROOT FOR ONE OF
!              THE FOLLOWING FUNCTIONS:
!
!                 POICDF(S;N*LAMBDAL) - (1 - ALPHA/2) = 0
!                 POICDF(S;N*LAMBDAU) - (ALPHA/2)     = 0
!
!              WITH
!
!                  S        = SUM[i=1 to n][X(i)]
!                  N        = SAMPLE SIZE
!                  LAMBDAL  = LOWER CONFIDENCE LEVEL FOR LAMBDA
!                  LAMBDAU  = UPPER CONFIDENCE LEVEL FOR LAMBDA
!                  ALPHA    = DESIRED SIGNIFICANCE LEVEL
!
!              DPMLPO IS TRYING TO DETERMINE AN CONFIDENCE INTERVAL
!              FOR LAMBDA.  THE VALUES FOR S, N, (1-ALPHA/2),
!              (OR ALPHA/2) ARE PASSED IN VIA A COMMON BLOCK.
!
!     INPUT  ARGUMENTS--ALAMB  = THE SINGLE PRECISION VALUE THAT
!                                SPECIFIES THE SHAPE PARAMETER FOR
!                                THE POISSON DISTRIBUTION.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE POIFUN.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--POICDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KARL BURY (1999). "STATISTICAL DISTRIBUTIONS IN
!                 ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                 PP. 105-106.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.8
!     ORIGINAL VERSION--SEPTEMBER 2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      COMMON/POICOM/S,CONST,N
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL POICDF(S,REAL(N)*ALAMB,CDF)
      POIFUN=CDF - CONST
!
      RETURN
      END FUNCTION POIFUN
      SUBROUTINE POIPPF(P,ALAMBA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE P
!              FOR THE POISSON DISTRIBUTION
!              WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = ALAMBA.
!              THE POISSON DISTRIBUTION USED
!              HEREIN HAS MEAN = ALAMBA
!              AND STANDARD DEVIATION = SQRT(ALAMBA).
!              THIS DISTRIBUTION IS DEFINED FOR
!              ALL DISCRETE NON-NEGATIVE INTEGER  X--X = 0, 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = EXP(-ALAMBA) * ALAMBA**X / X!.
!              THE POISSON DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF EVENTS
!              IN THE INTERVAL (0,ALAMBA) WHEN
!              THE WAITING TIME BETWEEN EVENTS
!              IS EXPONENTIALLY DISTRIBUTED
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALAMBA = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                ALAMBA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT  .
!             FUNCTION VALUE PPF
!             FOR THE POISSON DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = ALAMBA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALAMBA SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPPF, POICDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT, DEXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION AND DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SINGLE PRECISION TAIL LENGTH
!              PARAMETER ALAMBA IS     NOT     RESTRICTED
!              TO ONLY INTEGER VALUES.
!              ALAMBA CAN BE SET TO ANY POSITIVE REAL
!              VALUE--INTEGER OR NON-INTEGER.
!            --NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE DISTRIBUTION
!              PERCENT POINT FUNCTION
!              SUBROUTINE MUST NECESSARILY BE A
!              DISCRETE INTEGER VALUE,
!              THE OUTPUT VARIABLE PPF IS SINGLE
!              PRECISION IN MODE.
!              PPF HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VARIABLES FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 87-121,
!                 ESPECIALLY PAGE 102, FORMULA 36.1.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 108-113.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 146-154.
!               --COX AND MILLER, THE THEORY OF STOCHASTIC
!                 PROCESSES, 1965, PAGE 7.
!               --GENERAL ELECTRIC COMPANY, TABLES OF THE
!                 INDIVIDUAL AND CUMULATIVE TERMS OF POISSON
!                 DISTRIBUTION, 1962.
!               --OWEN, HANDBOOK OF STATISTICAL
!                 TABLES, 1962, PAGES 259-261.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DLAMBA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO POIPPF ',   &
               'POIPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALAMBA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO POIPPF ',   &
               'POIPPF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAMBA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DLAMBA=ALAMBA
      PPF=0.0
      IX0=0
      IX1=0
      IX2=0
      P0=0.0
      P1=0.0
      P2=0.0
!
!     TREAT CERTAIN SPECIAL CASES IMMEDIATELY--
!     1) P = 0.0
!     2) PPF = 0
!
      IF(P.EQ.0.0)GO TO 110
      PF0=DEXP(-DLAMBA)
      IF(P.LE.PF0)GO TO 110
      GO TO 190
  110 PPF=0.0
      RETURN
  190 CONTINUE
!
!     DETERMINE AN INITIAL APPROXIMATION TO THE POISSON
!     PERCENT POINT BY USE OF THE NORMAL APPROXIMATION
!     TO THE POISSON.
!     (SEE JOHNSON AND KOTZ, DISCRETE DISTRIBUTIONS,
!     PAGE 102, FORMULA 36.1).
!
      AMEAN=ALAMBA
      SD=SQRT(ALAMBA)
      CALL NORPPF(P,ZPPF)
      X2=AMEAN-1.0+ZPPF*SD
      IX2=INT(X2)
!
!     CHECK AND MODIFY (IF NECESSARY) THIS INITIAL
!     ESTIMATE OF THE PERCENT POINT
!     TO ASSURE THAT IT BE NON-NEGATIVE.
!
      IF(IX2.LT.0)IX2=0
!
!     DETERMINE UPPER AND LOWER BOUNDS ON THE DESIRED
!     PERCENT POINT BY ITERATING OUT (BOTH BELOW AND ABOVE)
!     FROM THE ORIGINAL APPROXIMATION AT STEPS
!     OF 1 STANDARD DEVIATION.
!     THE RESULTING BOUNDS WILL BE AT MOST
!     1 STANDARD DEVIATION APART.
!
      IX0=0
      IX1=INT(10.0**7 + 0.01)
      ISD=INT(SD+1.0)
      X2=REAL(IX2)
      CALL POICDF(X2,ALAMBA,P2)
!
      IF(P2.LT.P)GO TO 210
      GO TO 250
!
  210 CONTINUE
      IX0=IX2
      I=1
  215 CONTINUE
      IX2=IX0+ISD
      IF(IX2.GE.IX1)GO TO 275
      X2=IX2
      CALL POICDF(X2,ALAMBA,P2)
      IF(P2.GE.P)GO TO 230
      IX0=IX2
      I=I+1
      IF(I.LE.1000000)GO TO 215
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,222)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  230 IX1=IX2
      GO TO 275
!
  250 CONTINUE
      IX1=IX2
      I=1
  255 CONTINUE
      IX2=IX1-ISD
      IF(IX2.LE.IX0)GO TO 275
      X2=IX2
      CALL POICDF(X2,ALAMBA,P2)
      IF(P2.LT.P)GO TO 270
      IX1=IX2
      I=I+1
      IF(I.LE.1000000)GO TO 255
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,262)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  270 IX0=IX2
!
  275 IF(IX0.EQ.IX1)GO TO 280
      GO TO 295
  280 IF(IX0.EQ.0)GO TO 285
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,282)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  285 IX1=IX1+1
      GO TO 295
  295 CONTINUE
!
!     COMPUTE POISSON PROBABILITIES FOR THE
!     DERIVED LOWER AND UPPER BOUNDS.
!
      X0=IX0
      X1=IX1
      CALL POICDF(X0,ALAMBA,P0)
      CALL POICDF(X1,ALAMBA,P1)
!
!     CHECK THE PROBABILITIES FOR PROPER ORDERING
!
      IF(P0.LT.P.AND.P.LE.P1)GO TO 490
      IF(P0.EQ.P)GO TO 410
      IF(P1.EQ.P)GO TO 420
      IF(P0.GT.P1)GO TO 430
      IF(P0.GT.P)GO TO 440
      IF(P1.LT.P)GO TO 450
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,401)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  410 PPF=IX0
      RETURN
  420 PPF=IX1
      RETURN
  430 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,431)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  440 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,441)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  450 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,451)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  490 CONTINUE
!
!     THE STOPPING CRITERION IS THAT THE LOWER BOUND
!     AND UPPER BOUND ARE EXACTLY 1 UNIT APART.
!     CHECK TO SEE IF IX1 = IX0 + 1;
!     IF SO, THE ITERATIONS ARE COMPLETE;
!     IF NOT, THEN BISECT, COMPUTE PROBABILIIES,
!     CHECK PROBABILITIES, AND CONTINUE ITERATING
!     UNTIL IX1 = IX0 + 1.
!
  300 IX0P1=IX0+1
      IF(IX1.EQ.IX0P1)GO TO 690
      IX2=(IX0+IX1)/2
      IF(IX2.EQ.IX0)GO TO 610
      IF(IX2.EQ.IX1)GO TO 620
      X2=IX2
      CALL POICDF(X2,ALAMBA,P2)
      IF(P0.LT.P2.AND.P2.LT.P1)GO TO 630
      IF(P2.LE.P0)GO TO 640
      IF(P2.GE.P1)GO TO 650
  610 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,611)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  620 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,611)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  630 IF(P2.LE.P)GO TO 635
      IX1=IX2
      P1=P2
      GO TO 300
  635 IX0=IX2
      P0=P2
      GO TO 300
  640 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,641)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  650 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,651)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  690 PPF=IX1
      IF(P0.EQ.P)PPF=IX0
      RETURN
!
  950 WRITE(ICOUT,240)IX0,P0
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,241)IX1,P1
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,242)IX2,P2
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,244)P
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,245)ALAMBA
      CALL DPWRST('XXX','BUG ')
!
 9000 CONTINUE
      RETURN
!
  222 FORMAT('NO UPPER BOUND FOUND AFTER 10**7 ITERATIONS')
  240 FORMAT('IX0    = ',I8,10X,'P0 = ',F14.7)
  241 FORMAT('IX1    = ',I8,10X,'P1 = ',F14.7)
  242 FORMAT('IX2    = ',I8,10X,'P2 = ',F14.7)
  244 FORMAT('P      = ',F14.7)
  245 FORMAT('ALAMBA = ',F14.7)
  249 FORMAT('***** INTERNAL ERROR IN POIPPF SUBROUTINE.')
  262 FORMAT('NO LOWER BOUND FOUND AFTER 10**7 ITERATIONS')
  282 FORMAT('LOWER AND UPPER BOUND IDENTICAL')
  401 FORMAT('IMPOSSIBLE BRANCH CONDITION ENCOUNTERED')
  431 FORMAT('LOWER BOUND PROBABILITY (P0) GREATER THAN ',   &
             'UPPER BOUND PROBABILITY (P1)')
  441 FORMAT('LOWER BOUND PROBABILITY (P0) GREATER THAN ',   &
             'INPUT PROBABILITY (P)')
  451 FORMAT('UPPER BOUND PROBABILITY (P1) LESS    THAN ',   &
             'INPUT PROBABILITY (P)')
  611 FORMAT('BISECTION VALUE (X2) = LOWER BOUND (X0)')
!C621 FORMAT('BISECTION VALUE (X2) = UPPER BOUND (X1)')
  641 FORMAT('BISECTION VALUE PROBABILITY (P2) ',   &
             'LESS THAN LOWER BOUND PROBABILITY (P0)')
  651 FORMAT('BISECTION VALUE PROBABILITY (P2) ',   &
             'GREATER THAN UPPER BOUND PROBABILITY (P1)')
!
      END SUBROUTINE POIPPF
      SUBROUTINE POIRAN(N,ALAMBA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE POISSON DISTRIBUTION
!              WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = ALAMBA.
!              THE POISSON DISTRIBUTION USED
!              HEREIN HAS MEAN = ALAMBA
!              AND STANDARD DEVIATION = SQRT(ALAMBA).
!              THIS DISTRIBUTION IS DEFINED FOR
!              ALL DISCRETE NON-NEGATIVE INTEGER  X--X = 0, 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = EXP(-ALAMBA) * ALAMBA**X / X!.
!              THE POISSON DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF EVENTS
!              IN THE INTERVAL (0,ALAMBA) WHEN
!              THE WAITING TIME BETWEEN EVENTS
!              IS EXPONENTIALLY DISTRIBUTED
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALAMBA = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                ALAMBA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE POISSON DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = ALAMBA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALAMBA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THE SINGLE PRECISION TAIL LENGTH
!              PARAMETER ALAMBA IS     NOT     RESTRICTED
!              TO ONLY INTEGER VALUES.
!              ALAMBA CAN BE SET TO ANY POSITIVE REAL
!              VALUE--INTEGER OR NON-INTEGER.
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE RANDOM NUMBER
!              GENERATOR MUST NECESSARILY BE A
!              SEQUENCE OF ***INTEGER*** VALUES,
!              THE OUTPUT VECTOR X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VECTORS FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--COX AND MILLER, THE THEORY OF STOCHASTIC
!                 PROCESSES, 1965, PAGE 7.
!               --TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 36-37.
!               --JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 87-121.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 108-113.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 146-154.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DIMENSION U(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO POIRAN ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALAMBA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO POIRAN ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAMBA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N POISSON RANDOM NUMBERS
!     USING THE FACT THAT THE DISTRIBUTION
!     OF EXPONENTIAL WAITING TIMES IS POISSON.
!
      DO 100 I=1,N
      SUM=0.0
      J=1
  150 CALL UNIRAN(1,ISEED,U)
      E=-LOG(1.0-U(1))
      SUM=SUM+E
      IF(SUM.GT.ALAMBA)GO TO 250
      J=J+1
      GO TO 150
  250 X(I)=J-1
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE POIRAN
      SUBROUTINE POISSF(ALAMB,EPS,L,NSPAN,V,NV,IFLAG)
!
!--- COMPUTE THE POISSON(ALAMB) PROBABILITIES OVER THE RANGE [L,K]
!--- WHERE THE TOTAL TAIL PROBABILITY IS LESS THAN EPS/2, SUM THE
!--- PROBABILITIES IN DOUBLE PRECISION, AND SHIFT THEM TO THE
!--- BEGINNING OF VECTOR V.
!
      DIMENSION V(*)
      DOUBLE PRECISION DAL,DK,DLIMIT,DSUM,DLNGAM
      DLIMIT = 1.0D0-0.5D0*DBLE(EPS)
      K = INT(ALAMB)
      L = K+1
      IF (ALAMB.EQ.0.0) THEN
         PL = 1.0
      ELSE
         DAL = DBLE(ALAMB)
         DK = DBLE(K)
         PL = REAL(DEXP(DK*DLOG(DAL)-DAL-DLNGAM(DBLE(K+1))))
      ENDIF
      PK = ALAMB*PL/REAL(L)
      NK = NV/2
      NL = NK+1
      DSUM = 0.0
   10 IF (PL.LT.PK) THEN
         NK = NK+1
         IF (NK.GT.NV) THEN
            IFLAG = 6
            RETURN
         ENDIF
         V(NK) = PK
         DSUM = DSUM+DBLE(PK)
         K = K+1
         IF (DSUM.GE.DLIMIT) GO TO 20
         PK = ALAMB*PK/REAL(K+1)
      ELSE
         NL = NL-1
         V(NL) = PL
         DSUM = DSUM+DBLE(PL)
         L = L-1
         IF (DSUM.GE.DLIMIT) GO TO 20
         PL = REAL(L)*PL/ALAMB
      ENDIF
      GO TO 10
   20 INC = NL-1
      DO 30 I = NL, NK
         V(I-INC) = V(I)
   30 CONTINUE
      NSPAN = NK-INC
      RETURN
      END SUBROUTINE POISSF
      SUBROUTINE POISST(ALAMB,EPS,L,NSPAN,V,NV,IFLAG)
!CCCC CONVERT TO DOUBLE PRECISION.  SINGLE PRECISION ON 32-BIT
!CCCC MACHINES DOES NOT GIVE ACCURATE RESULTS.
!
!--- COMPUTE THE POISSON(ALAMB) PROBABILITIES OVER THE RANGE [L,K]
!--- WHERE THE TOTAL TAIL PROBABILITY IS LESS THAN EPS/3, SUM THE
!--- PROBABILITIES IN DOUBLE PRECISION, AND SHIFT THEM TO THE
!--- BEGINNING OF VECTOR V.
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      DIMENSION V(*)
!CCCC DOUBLE PRECISION DAL,DK,DLIMIT,DSUM,DLNGAM
!
      DLIMIT = 1.0D0-2.0D0*EPS/3.0D0
      K = INT(ALAMB)
      L = K+1
      IF (ALAMB.EQ.0.0D0) THEN
         PL = 1.0D0
      ELSE
         DAL = ALAMB
         DK = DBLE(K)
!CCCC    PL = SNGL(DEXP(DK*DLOG(DAL)-DAL-DLNGAM(DBLE(K+1))))
         PL = DEXP(DK*DLOG(DAL)-DAL-DLNGAM(DBLE(K+1)))
      ENDIF
      PK = ALAMB*PL/DBLE(L)
      NK = NV/2
      NL = NK+1
      DSUM = 0.0D0
   10 IF (PL.LT.PK) THEN
         NK = NK+1
         IF (NK.GT.NV) THEN
            IFLAG = 6
            RETURN
         ENDIF
         V(NK) = PK
         DSUM = DSUM+PK
         K = K+1
         IF (DSUM.GE.DLIMIT) GO TO 20
         PK = ALAMB*PK/DBLE(K+1)
      ELSE
         NL = NL-1
         IF (NL.LT.1) THEN
            IFLAG = 6
            RETURN
         ENDIF
         V(NL) = PL
         DSUM = DSUM+PL
         L = L-1
         IF (DSUM.GE.DLIMIT) GO TO 20
         PL = DBLE(L)*PL/ALAMB
      ENDIF
      GO TO 10
   20 INC = NL-1
      DO 30 I = NL, NK
         V(I-INC) = V(I)
   30 CONTINUE
      NSPAN = NK-INC
      RETURN
      END SUBROUTINE POISST
      SUBROUTINE POLARI(Y1,Y2,Y3,Y4,N1,N3,IACASE,IWRITE,   &
      Y5,Y6,N5,N6,SCAL3,ITYP3,   &
      DTOP,DBOT,DMID,   &
      IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CARRY OUT POLYNOMIAL ARITHMETIC OPERATIONS
!              OF THE REAL DATA IN Y1 AND Y3.
!
!     OPERATIONS--ADDITION
!                 SUBTRACTION
!                 MULTIPLICATION
!                 DIVISION                      (FUTURE--NOT YET IMPLEMENTED)
!                 SQUARE
!                 SQUARE ROOT                   (FUTURE--NOT YET IMPLEMENTED)
!                 GCD (GREATEST COMMON DIVISOR) (FUTURE--NOT YET IMPLEMENTED)
!                 LCM (LEAST COMMON MULTIPLE)   (FUTURE--NOT YET IMPLEMENTED)
!                 EVALUATION
!
!     INPUT  ARGUMENTS--Y1 (REAL PART)       Y2 (IMAGINARY PART)
!                     --Y3 (REAL PART)       Y4 (IMAGINARY PART)
!     OUTPUT ARGUMENTS--Y5 (REAL PART)       Y6 (IMAGINARY PART)
!
!     NOTE--IT IS NOT PERMISSIBLE TO HAVE THE OUTPUT VECTORS Y5(.) AND Y6(.)
!           BEING IDENTICAL TO THE INPUT VECTORS Y1(.) AND Y2(.), OR
!           Y3(.) AND Y4(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/9
!     ORIGINAL VERSION--AUGUST   1987.
!     UPDATED         --JUNE     1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --JANUARY  2006. PASS DOUBLE PRECISION ARRAYS
!                                      FROM DPMATC
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IACASE
      CHARACTER*4 IWRITE
      CHARACTER*4 ITYP3
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!-----DOUBLE PRECISION STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DY1
!CCCC DOUBLE PRECISION DY2
      DOUBLE PRECISION DY3
!CCC  DOUBLE PRECISION DY4
      DOUBLE PRECISION DY5
!CCCC DOUBLE PRECISION DY6
      DOUBLE PRECISION DSUM5
!CCCC DOUBLE PRECISION DSUM6
!
      DOUBLE PRECISION DTOP
      DOUBLE PRECISION DMID
      DOUBLE PRECISION DBOT
      DOUBLE PRECISION DRATIO
!
      DOUBLE PRECISION DCUM
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION Y4(*)
      DIMENSION Y5(*)
      DIMENSION Y6(*)
!
      DIMENSION DTOP(*)
      DIMENSION DMID(*)
      DIMENSION DBOT(*)
!CCCC DIMENSION DTOP(MAXOBV)
!CCCC DIMENSION DMID(MAXOBV)
!CCCC DIMENSION DBOT(MAXOBV)
!CCCC FOLLOWING LINES ADDED JUNE, 1990
!CCCC INCLUDE 'DPCOZD.INC'
!CCCC EQUIVALENCE (DGARBG(IDGAR1),DTOP(1))
!CCCC EQUIVALENCE (DGARBG(IDGAR2),DMID(1))
!CCCC EQUIVALENCE (DGARBG(IDGAR3),DBOT(1))
!CCCC END CHANGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='POLA'
      ISUBN2='RI  '
      IERROR='NO'
!
      SCAL3=(-999.0)
      ITYP3='VECT'
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'PARI')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF POLARI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3,ISUBRO,IACASE,IWRITE
   52 FORMAT('IBUGA3,ISUBRO,IACASE,IWRITE = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N1,N3
   53 FORMAT('N1,N3 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N1
      WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56 FORMAT('I,Y1(I),Y2(I) = ',I8,2E13.5)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
      DO 65 I=1,N3
      WRITE(ICOUT,66)I,Y3(I),Y4(I)
   66 FORMAT('I,Y3(I),Y4(I) = ',I8,2E13.5)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
   90 CONTINUE
!
!               **************************************************
!               **  CARRY OUT POLYNOMIAL ARITHMETIC OPERATIONS  **
!               **************************************************
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N1.LT.1)GO TO 1100
      IF(IACASE.EQ.'POSQ')GO TO 1190
      IF(IACASE.EQ.'POSR')GO TO 1190
      IF(N3.LT.1)GO TO 1100
      GO TO 1190
!
 1100 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN POLARI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'POAD')WRITE(ICOUT,1161)
 1161 FORMAT('      THE POLYNOMIAL ADDITION IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'POAD')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'POSU')WRITE(ICOUT,1162)
 1162 FORMAT('      THE POLYNOMIAL SUBTRACTION IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'POSU')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'POMU')WRITE(ICOUT,1163)
 1163 FORMAT('      THE POLYNOMIAL MULTIPLICATION IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'POMU')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'PODI')WRITE(ICOUT,1164)
 1164 FORMAT('      THE POLYNOMIAL DIVISION IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'PODI')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'POSQ')WRITE(ICOUT,1165)
 1165 FORMAT('      THE POLYNOMIAL SQUARE IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'POSQ')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'POSR')WRITE(ICOUT,1166)
 1166 FORMAT('      THE POLYNOMIAL SQUARE ROOT IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'POSR')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'POGC')WRITE(ICOUT,1167)
 1167 FORMAT('      THE POLYNOMIAL GCD IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'POGC')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'POLC')WRITE(ICOUT,1168)
 1168 FORMAT('      THE POLYNOMIAL LCM IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'POLC')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'POEV')WRITE(ICOUT,1169)
 1169 FORMAT('      THE POLYNOMIAL EVALUATION IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'POEV')CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)
 1182 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1183)N1,N3
 1183 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',2I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1190 CONTINUE
!
!               *********************************
!               **  STEP 12--                  **
!               **  BRANCH TO THE PROPER CASE  **
!               *********************************
!
      IF(IACASE.EQ.'POAD')GO TO 2100
      IF(IACASE.EQ.'POSU')GO TO 2200
      IF(IACASE.EQ.'POMU')GO TO 2300
      IF(IACASE.EQ.'PODI')GO TO 2400
      IF(IACASE.EQ.'POSQ')GO TO 2500
      IF(IACASE.EQ.'POSR')GO TO 2600
      IF(IACASE.EQ.'POGC')GO TO 2700
      IF(IACASE.EQ.'POLC')GO TO 2800
      IF(IACASE.EQ.'POEV')GO TO 2900
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1211)
 1211 FORMAT('***** INTERNAL ERROR IN POLARI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1212)
 1212 FORMAT('      IACASE NOT EQUAL TO')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1213)
 1213 FORMAT('      POAD, POSU, POMU, PODI, ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1214)
 1214 FORMAT('      POSQ, POSR, POGC, POLC, OR POEV')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('      IACASE = ',A4)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!               *********************************************
!               **  STEP 21--                              **
!               **  TREAT THE POLYNOMIAL ADDITION    CASE  **
!               *********************************************
!
 2100 CONTINUE
      N13MAX=N1
      IF(N3.GT.N1)N13MAX=N3
      DO 2110 I=1,N13MAX
      DY1=0.0D0
!CCCC DY2=0.0D0
      DY3=0.0D0
!CCCC DY4=0.0D0
      IF(I.LE.N1)DY1=Y1(I)
!CCCC IF(I.LE.N1)DY2=Y2(I)
      IF(I.LE.N3)DY3=Y3(I)
!CCCC IF(I.LE.N3)DY4=Y4(I)
      DY5=DY1+DY3
!CCCC DY6=DY2+DY4
      Y5(I)=DY5
!CCCC Y6(I)=DY6
 2110 CONTINUE
!
      ITYP3='VECT'
      N5=N13MAX
      N6=N5
      GO TO 9000
!
!               *********************************************
!               **  STEP 22--                              **
!               **  TREAT THE POLYNOMIAL SUBTRACTION CASE  **
!               *********************************************
!
 2200 CONTINUE
      N13MAX=N1
      IF(N3.GT.N1)N13MAX=N3
      DO 2210 I=1,N13MAX
      DY1=0.0D0
!CCCC DY2=0.0D0
      DY3=0.0D0
!CCCC DY4=0.0D0
      IF(I.LE.N1)DY1=Y1(I)
!CCCC IF(I.LE.N1)DY2=Y2(I)
      IF(I.LE.N3)DY3=Y3(I)
!CCCC IF(I.LE.N3)DY4=Y4(I)
      DY5=DY1-DY3
!CCCC DY6=DY2-DY4
      Y5(I)=DY5
!CCCC Y6(I)=DY6
 2210 CONTINUE
!
      ITYP3='VECT'
      N5=N13MAX
      N6=N5
      GO TO 9000
!
!               ************************************************
!               **  STEP 23--                                 **
!               **  TREAT THE POLYNOMIAL MULTIPLICATION CASE  **
!               ************************************************
!
 2300 CONTINUE
      N1PN3M=N1+N3-1
      DO 2310 I=1,N1PN3M
      DSUM5=0.0D0
!CCCC DSUM6=0.0D0
      DO 2320 J=1,N1
      K=I-J+1
      IF(K.LT.1.OR.K.GT.N3)GO TO 2320
      DY1=Y1(J)
!CCCC DY2=Y2(J)
      DY3=Y3(K)
!CCCC DY4=Y4(K)
!CCCC DY5=DY1*DY3-DY2*DY4
      DY5=DY1*DY3
!CCCC DY6=DY1*DY4+DY2*DY3
      DSUM5=DSUM5+DY5
!CCCC DSUM6=DSUM6+DY6
 2320 CONTINUE
      Y5(I)=DSUM5
!CCCC Y6(I)=DSUM6
 2310 CONTINUE
!
      ITYP3='VECT'
      N5=N1PN3M
      N6=N5
      GO TO 9000
!
!               ************************************************
!               **  STEP 24--                                 **
!               **  TREAT THE POLYNOMIAL DIVISION       CASE  **
!               ************************************************
!
 2400 CONTINUE
!
      DO 2410 I=1,N1
      DBOT(I)=Y1(I)
 2410 CONTINUE
!
      NLOOP=N1-N3+1
      NTOP=N1+1
      IF(NLOOP.LE.0)GO TO 2455
      DO 2420 ILOOP=1,NLOOP
      NTOP=NTOP-1
!
      DO 2430 I=1,NTOP
      DTOP(I)=DBOT(I)
      DMID(I)=0.0D0
 2430 CONTINUE
!
      IDEL=NTOP-N3
      DO 2440 I=1,N3
      J=I+IDEL
      DMID(J)=Y3(I)
 2440 CONTINUE
!
      DRATIO=DTOP(NTOP)/DMID(NTOP)
      ILOOPR=NLOOP-ILOOP+1
      Y5(ILOOPR)=DRATIO
!
      DO 2450 I=1,NTOP
      DMID(I)=DMID(I)*DRATIO
      DBOT(I)=DTOP(I)-DMID(I)
 2450 CONTINUE
!
 2420 CONTINUE
      N5=NLOOP
!
 2455 CONTINUE
      NTOP=NTOP-1
      DO 2460 I=1,NTOP
      Y6(I)=DBOT(I)
 2460 CONTINUE
      N6=NTOP
!
      IF(NLOOP.GE.1)GO TO 2479
      DO 2470 I=1,N6
      Y5(I)=0.0
 2470 CONTINUE
      N5=N6
 2479 CONTINUE
!
      ITYP3='VECT'
      GO TO 9000
!
!               ***************************************************
!               **  STEP 25--                                    **
!               **  TREAT THE POLYNOMIAL SQUARE (SQUARING) CASE  **
!               ***************************************************
!
 2500 CONTINUE
      N1PN1M=N1+N1-1
      DO 2510 I=1,N1PN1M
      DSUM5=0.0D0
!CCCC DSUM6=0.0D0
      DO 2520 J=1,N1
      K=I-J+1
      IF(K.LT.1.OR.K.GT.N1)GO TO 2520
      DY1=Y1(J)
!CCCC DY2=Y2(J)
      DY3=Y1(K)
!CCCC DY4=Y2(K)
!CCCC DY5=DY1*DY3-DY2*DY4
      DY5=DY1*DY3
!CCCC DY6=DY1*DY4+DY2*DY3
      DSUM5=DSUM5+DY5
!CCCC DSUM6=DSUM6+DY6
 2520 CONTINUE
      Y5(I)=DSUM5
!CCCC Y6(I)=DSUM6
 2510 CONTINUE
!
      ITYP3='VECT'
      N5=N1PN1M
      N6=N5
      GO TO 9000
!
!               ************************************************
!               **  STEP 26--                                 **
!               **  TREAT THE POLYNOMIAL SQUARE ROOT    CASE  **
!               ************************************************
!
 2600 CONTINUE
!
!     NOTE YET DONE
!
      GO TO 9000
!
!               *********************************************************
!               **  STEP 27--                                          **
!               **  TREAT THE POLYNOMIAL GREATEST COMMON DIVISOR CASE  **
!               *********************************************************
!
 2700 CONTINUE
!
!     NOTE YET DONE
!
      GO TO 9000
!
!               *******************************************************
!               **  STEP 28--                                        **
!               **  TREAT THE POLYNOMIAL LEAST COMMON MULTIPLE CASE  **
!               *******************************************************
!
 2800 CONTINUE
!
!     NOTE YET DONE
!
      GO TO 9000
!
!               *********************************************
!               **  STEP 29--                              **
!               **  TREAT THE POLYNOMIAL EVALUATION  CASE  **
!               *********************************************
!
 2900 CONTINUE
      N1M1=N1-1
      DO 2910 I=1,N3
      DX=Y3(I)
      DCUM=Y1(N1)
      IF(N1M1.LE.0)GO TO 2925
      DO 2920 J=1,N1M1
      JREV=N1-J+1
      JREVM=JREV-1
      DC=Y1(JREVM)
      DCUM=DX*DCUM+DC
 2920 CONTINUE
 2925 CONTINUE
      Y5(I)=DCUM
 2910 CONTINUE
!
      ITYP3='VECT'
      N5=N3
      N6=N5
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'PARI')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF POLARI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,ISUBRO,IACASE,IWRITE
 9012 FORMAT('IBUGA3,ISUBRO,IACASE,IWRITE = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IERROR
 9013 FORMAT('IERROR = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)N1,N3,N5,N6
 9017 FORMAT('N1,N3,N5,N6 = ',4I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9018)SCAL3,ITYP3
 9018 FORMAT('SCAL3,ITYP3 = ',E15.7,2X,A4)
      CALL DPWRST('XXX','BUG ')
      IF(ITYP3.EQ.'SCAL')GO TO 9090
      DO 9021 I=1,N1
      WRITE(ICOUT,9022)I,Y1(I),Y2(I)
 9022 FORMAT('I,Y1(I),Y2(I) = ',I8,2E13.5)
      CALL DPWRST('XXX','BUG ')
 9021 CONTINUE
      DO 9031 I=1,N3
      WRITE(ICOUT,9032)I,Y3(I),Y4(I)
 9032 FORMAT('I,Y3(I),Y4(I) = ',I8,2E13.5)
      CALL DPWRST('XXX','BUG ')
 9031 CONTINUE
      DO 9041 I=1,N5
      WRITE(ICOUT,9042)I,Y5(I),Y6(I)
 9042 FORMAT('I,Y5(I),Y6(I) = ',I8,2E13.5)
      CALL DPWRST('XXX','BUG ')
 9041 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE POLARI
      SUBROUTINE POLCDF(X,V,W,N,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE POLYA DISTRIBUTION
!              WITH SINGLE PRECISION PARAMETERS V AND W
!              AND INTEGER 'NUMBER OF BERNOULLI TRIALS'
!              PARAMETER = N.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              P(X) = (N X)*B(X+V,N+X+W)/B(V,W)
!              WITH B(.,.) DENOTING THE BETA FUNCTION AND (N X)
!              DENOTING THE BINOMIAL COEFFICIENT.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE INTEGRAL-VALUED,
!                                AND BETWEEN 0.0 (INCLUSIVELY)
!                                AND N (INCLUSIVELY).
!                     --V      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --W      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --N      = THE INTEGER VALUE
!                                OF THE 'NUMBER OF BERNOULLI TRIALS'
!                                PARAMETER.
!                                N SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF
!             FOR THE BINOMIAL DISTRIBUTION
!             WITH 'BERNOULLI PROBABILITY' PARAMETER = P
!             AND 'NUMBER OF BERNOULLI TRIALS' PARAMETER = N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE INTEGRAL-VALUED,
!                   AND BETWEEN 0.0 (INCLUSIVELY)
!                   AND N (INCLUSIVELY).
!                 --V AND W SHOULD BOTH BE POSITIVE.
!                 --N SHOULD BE A POSITIVE INTEGER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DBINOM, DLBETA
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD ED., CHAPTER 5
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX, DV, DW, DN, DCDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM4
      DOUBLE PRECISION DLBETA, DBINOM
      DOUBLE PRECISION DSUM1, DSUM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      AN=N
      IF(V.LE.0.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)V
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(W.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)V
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(N.LE.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      INTX=INT(X+0.0001)
      FINTX=REAL(INTX)
      DEL=X-FINTX
      IF(DEL.LT.0.0)DEL=-DEL
      IF(DEL.GT.0.001)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)INT(FINTX)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IF(FINTX.LT.0.0 .OR. FINTX.GT.AN)THEN
        WRITE(ICOUT,4)N
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO POLCDF IS ',   &
             'OUTSIDE THE (0,N) = (0,',I8,') INTERVAL.')
    5 FORMAT('***** WARNING--THE FIRST INPUT ',   &
      'ARGUMENT TO POLCDF IS NON-INTEGRAL.')
    6 FORMAT('      IT HAS BEEN SET TO ',I8,'.')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
      ' POLCDF IS NON-POSITIVE.')
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
      ' POLCDF IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO ',   &
      ' POLCDF IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
      DV=DBLE(V)
      DW=DBLE(W)
      DN=DBLE(N)
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DMEAN=DN*DW/(DV+DW)
      ICUT=INT(DMEAN)+1
!
!  SUM TERMS UP TO AND INCLUDING MEAN
!
      DO 1000 I=0,MIN(ICUT,INTX),1
        DX=DBLE(I)
        DTERM1=DLOG(DBINOM(N,I))
        DTERM2=DLBETA(DX+DV,DN+DW-DX)
        DTERM4=DLBETA(DV,DW)
        DCDF=DEXP(DTERM1 + DTERM2 - DTERM4)
        DSUM1=DSUM1+DCDF
 1000 CONTINUE
!
!  SUM TERMS FROM X DOWN TO MEAN MEAN
!
      IF(INTX.GT.ICUT)THEN
        DO 2000 I=INTX,ICUT+1,-1
          DX=DBLE(I)
          DTERM1=DLOG(DBINOM(N,I))
          DTERM2=DLBETA(DX+DV,DN+DW-DX)
          DTERM4=DLBETA(DV,DW)
          DCDF=DEXP(DTERM1 + DTERM2 - DTERM4)
          DSUM2=DSUM2+DCDF
 2000   CONTINUE
      ENDIF
      DCDF=DSUM1+DSUM2
      CDF=REAL(DCDF)
!C101 FORMAT('****** ERROR--OVERFLOW IN POLCDF ROUTINE.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE POLCDF
      SUBROUTINE POLPDF(X,W,B,C,N,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE POLYA DISTRIBUTION
!              WITH SINGLE PRECISION PARAMETERS W, B, AND C
!              AND INTEGER PARAMETER N.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              DISCRETE INTEGER X BETWEEN 0 (INCLUSIVELY)
!              AND N (INCLUSIVELY).
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!                 P(X) = (N X)*B(X+ALPHA,N+X+BETA)/B(ALPHA,BETA)
!                        X = 0, 1, 2, ..., N.
!              WITH ALPHA = W/C AND BETA = B/C,
!              B(.,.) DENOTING THE BETA FUNCTION, AND (N X)
!              DENOTING THE BINOMIAL COEFFICIENT.
!              THIS FORM OF THE OF THE PDF IS ONLY USEFUL FOR
!              ALPHA AND BETA POSITIVE.
!              AN ALTERNATIVE FORM THAT CAN BE USED FOR NEGATIVE
!              VALUES FOR W, B, AND C IS:
!                 P(X) = (-W/C  X)*(-B/C  N-X)/(-(W+B)/C  N)
!              FOR NEGATIVE VALUES OF W, B, AND C, USE THE
!              FORMULA:
!              (-N  R) = (-1)**R*(N+R-1  R)
!              NOTE THAT IF C = 0, THEN POLYA DEGENERATES TO
!              BINOMIAL WITH P = W/(W+B) AND N.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE INTEGRAL-VALUED,
!                                AND BETWEEN 0.0 (INCLUSIVELY)
!                                AND N (INCLUSIVELY).
!                     --W      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --B      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --C      = THE SINGLE PRECISION VALUE
!                                OF THE THURD SHAPE PARAMETER.
!                     --N      = THE INTEGER VALUE
!                                OF THE 'NUMBER OF BERNOULLI TRIALS'
!                                PARAMETER.
!                                N SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE POLYA DISTRIBUTION
!             WITH SHAPE PARAMETERS W, B, C, AD N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE INTEGRAL-VALUED,
!                   AND BETWEEN 0.0 (INCLUSIVELY)
!                   AND N (INCLUSIVELY).
!                 --N SHOULD BE A POSITIVE INTEGER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLBETA, DBINOM, DLNGAM
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP, "UNIVARIATE DISCRETE
!                 DISTRIBUTIONS--SECOND EDITION, WILEY, 1992,
!                 PP. 244-249.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2004/4
!     ORIGINAL VERSION--APRIL     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL W
      REAL B
      REAL C
      REAL ALPHA
      REAL BETA
      REAL P
      DOUBLE PRECISION DX, DV, DW, DN, DPDF
      DOUBLE PRECISION DA, DR, DWC, DBC, DWBC
      DOUBLE PRECISION DCONST
      DOUBLE PRECISION D1, D2, D3
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4
      DOUBLE PRECISION DLBETA, DBINOM
      DOUBLE PRECISION DLNGAM
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      AN=N
      ALPHA=W/C
      BETA=B/C
      P=W/(W+B)
!CCCC IF(V.LE.0.0)THEN
!CCCC   WRITE(ICOUT,11)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)V
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   PDF=0.0
!CCCC   GO TO 9999
!CCCC ENDIF
!CCCC IF(W.LE.0.0)THEN
!CCCC   WRITE(ICOUT,12)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)V
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   PDF=0.0
!CCCC   GO TO 9999
!CCCC ENDIF
      IF(N.LE.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      INTX=INT(X+0.0001)
      FINTX=REAL(INTX)
      DEL=X-FINTX
      IF(DEL.LT.0.0)DEL=-DEL
      IF(DEL.GT.0.001)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)INT(FINTX)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IF(FINTX.LT.0.0 .OR. FINTX.GT.AN)THEN
        WRITE(ICOUT,4)N
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
    4 FORMAT('***** ERROR--THE FIRST INPUT ',   &
      'ARGUMENT TO THE POLPDF SUBROUTINE IS OUTSIDE THE USUAL ',   &
      '(0,N) = (0,',I8,') INTERVAL')
    5 FORMAT('***** WARNING--THE FIRST INPUT ',   &
      'ARGUMENT TO THE POLPDF SUBROUTINE IS NON-INTEGRAL *****')
    6 FORMAT('      IT HAS BEEN SET TO ',I8)
!CC11 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',
!CCCC1' POLPDF SUBROUTINE IS NON-POSITIVE')
!CC12 FORMAT('***** FATAL ERROR--THE THIRD INPUT ARGUMENT TO THE ',
!CCCC1' POLPDF SUBROUTINE IS NON-POSITIVE')
   25 FORMAT('***** ERROR--THE FIFTH INPUT ARGUMENT TO THE ',   &
      ' POLPDF SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!
      IF(C.EQ.0.0)THEN
!
!  CASE 1: C = 0 DEGENERATES TO A BINOMIAL DISTRIBUTION
!
        CALL BINCDF(DBLE(X),DBLE(P),N,DCDF)
        CDF1=REAL(DCDF)
        IF(X.LE.0.1)THEN
          PDF=CDF1
        ELSE
          ARG1=X-1.0
          CALL BINCDF(DBLE(ARG1),DBLE(P),N,DCDF)
          CDF2=REAL(DCDF)
          PDF=CDF1-CDF2
        ENDIF
      ELSEIF(ALPHA.GT.0.0 .AND. BETA.GT.0)THEN
!
!  CASE 2: W/C AND B/C BOTH POSITIVE, USE DEFINITION BASED ON
!          BETA FUNCTIONS (THIS CASE IS EQUIVALENT TO
!          BETA-BINOMIAL WITH ALPHA AND BETA ARGUMENTS REVERSED).
!
        DX=DBLE(FINTX)
        DV=DBLE(ALPHA)
        DW=DBLE(BETA)
        DN=DBLE(N)
        DTERM1=DLOG(DBINOM(N,INTX))
        DTERM2=DLBETA(DX+DV,DN+DW-DX)
        DTERM4=DLBETA(DV,DW)
        DPDF=DTERM1 + DTERM2 - DTERM4
        IF(DPDF.LE.-80.D0)THEN
          PDF=0.0
        ELSEIF(DPDF.GT.80.D0)THEN
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
        ELSE
          DPDF=DEXP(DPDF)
          PDF=SNGL(DPDF)
        ENDIF
      ELSE
!
!  CASE 3: W/C OR B/C OR BOTH ARE NEGATIVE.  USE DEFINTION BASED
!          ON BINOMIAL COEFFICIENT WHERE SOME OF THE TERMS MAY
!          HAVE NEGATIVE ARGUMENTS FOR TOP COEFFICIENT.
!
!          (-N  R) = (-1)**R*(N+R-1  R)
!                  = (-1)**R*(N+R-1)!/[R!*(N+R-1-R)!]
!                  = (-1)**R*(N+R-1)!/[R!*(N-1)!]
!                  = (-1)**R*GAMMA(N+R)/[GAMMA(R+1)*GAMMA(N)]
!
!          IF TERM IS POSITIVE, USE
!          (N  R) = N!/(R!*(N-R)!)
!                 = GAMMA(N+1)/[GAMMA(R+1)*GAMMA(N-R+1)]
!          USE LOG GAMMA FUNCTION FOR BETTER NUMERICAL STABILITY
!
        DX=DBLE(FINTX)
        DWC=DBLE(W)/DBLE(C)
        DBC=DBLE(B)/DBLE(C)
        DWBC=DBLE(W+B)/DBLE(C)
        DN=DBLE(N)
!
!  FIRST TERM: (-DWC  X)
!
        DA=-DWC
        DR=DX
        IF(DA.GE.0.0)THEN
          D1=DLNGAM(DA+1.0D0)
          D2=DLNGAM(DR+1.0)
          D3=DLNGAM(DA-DR+1.0)
          DTERM1=DEXP(D1 - D2 - D3)
        ELSE
          DCONST=(-1.0D0)**INT(DR+0.01)
          DA=DABS(DA)
          D1=DLNGAM(DA+DR)
          D2=DLNGAM(DR+1)
          D3=DLNGAM(DA)
          DTERM1=DCONST*DEXP(D1 - D2 - D3)
        ENDIF
!
!  SECOND TERM: (-DBC  N-X)
!
        DA=-DBC
        DR=DN-DX
        IF(DA.GE.0.0)THEN
          D1=DLNGAM(DA+1.0D0)
          D2=DLNGAM(DR+1.0)
          D3=DLNGAM(DA-DR+1.0)
          DTERM2=DEXP(D1 - D2 - D3)
        ELSE
          DCONST=(-1.0D0)**INT(DR+0.01)
          DA=DABS(DA)
          D1=DLNGAM(DA+DR)
          D2=DLNGAM(DR+1)
          D3=DLNGAM(DA)
          DTERM2=DCONST*DEXP(D1 - D2 - D3)
        ENDIF
!
!  THIRD TERM: (-(W+B)/C  N)
!
        DA=-DWBC
        DR=DN
        IF(DA.GE.0.0)THEN
          D1=DLNGAM(DA+1.0D0)
          D2=DLNGAM(DR+1.0)
          D3=DLNGAM(DA-DR+1.0)
          DTERM3=DEXP(D1 - D2 - D3)
        ELSE
          DCONST=(-1.0D0)**INT(DR+0.01)
          DA=DABS(DA)
          D1=DLNGAM(DA+DR)
          D2=DLNGAM(DR+1)
          D3=DLNGAM(DA)
          DTERM3=DCONST*DEXP(D1 - D2 - D3)
        ENDIF
        DPDF=(DTERM1*DTERM2)/DTERM3
        PDF=REAL(DPDF)
      ENDIF
  101 FORMAT('****** FATAL ERROR--OVERFLOW IN POLPDF ROUTINE.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE POLPDF
      SUBROUTINE POLPPF(P,V,W,N,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE P
!              FOR THE POLYA DISTRIBUTION
!              WITH SINGLE PRECISION PARAMETERS V AND W
!              AND INTEGER 'NUMBER OF BERNOULLI TRIALS'
!              PARAMETER = N.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              P(X) = (N X)*B(X+V,N+X+W)/B(V,W)
!              WITH B(.,.) DENOTING THE BETA FUNCTION AND (N X)
!              DENOTING THE BINOMIAL COEFFICIENT.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (INCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --V      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --W      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --N      = THE INTEGER VALUE
!                                OF THE 'NUMBER OF BERNOULLI TRIALS'
!                                PARAMETER.
!                                N SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT  .
!             FUNCTION VALUE PPF
!             FOR THE POLYA DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--N SHOULD BE A POSITIVE INTEGER.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (INCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--BBNCDF
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION AND DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE DISTRIBUTION
!              PERCENT POINT FUNCTION
!              SUBROUTINE MUST NECESSARILY BE A
!              DISCRETE INTEGER VALUE,
!              THE OUTPUT VARIABLE PPF IS SINGLE
!              PRECISION IN MODE.
!              PPF HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VARIABLES FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD ED., CHAPTER 5
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX, DV, DW, DN, DCDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM4
      DOUBLE PRECISION DLBETA, DBINOM
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GT.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO POLPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(V.LE.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO POLPPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)V
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(W.LE.0.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO POLPPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)V
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(N.LE.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO POLPPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      AN=N
      PPF=0.0
!
!     TREAT CERTAIN SPECIAL CASES IMMEDIATELY--
!     1) P = 0.0
!     2) P = 1.0
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
      IF(P.EQ.1.0)THEN
        PPF=REAL(N)
        GO TO 9999
      ENDIF
!
!     COMPUTE THE POLCDF, TERMINATE WHEN CDF IS GREATER THAN OR
!     EQUAL TO P.
!
      DP=DBLE(P)
      DN=DBLE(N)
      DV=DBLE(V)
      DW=DBLE(W)
      DSUM1=0.0D0
      DO 1000 I=0,N
        DX=DBLE(I)
        DTERM1=DLOG(DBINOM(N,I))
        DTERM2=DLBETA(DX+DV,DN+DW-DX)
        DTERM4=DLBETA(DV,DW)
        DCDF=DEXP(DTERM1 + DTERM2 - DTERM4)
        DSUM1=DSUM1+DCDF
        IF(DSUM1.GE.DP)THEN
          PPF=REAL(I)
          GO TO 9999
        ENDIF
 1000 CONTINUE
      PPF=REAL(N)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE POLPPF
      function poly(c, nord, x)
!
!
!        Algorithm AS 181.2   Appl. Statist.  (1982) Vol. 31, No. 2
!
!        Calculates the algebraic polynomial of order nored-1 with
!        array of coefficients c.  Zero order coefficient is c(1)
!
      real c(nord)
      poly = c(1)
      if(nord.eq.1) return
      p = x*c(nord)
      if(nord.eq.2) go to 20
      n2 = nord-2
      j = n2+1
      do 10 i = 1,n2
      p = (p+c(j))*x
      j = j-1
   10 continue
   20 poly = poly+p
      return
      end function poly
      SUBROUTINE POOLSD(Y,X,N,XIDTEM,TEMP,ICASE1,ICASE2,IWRITE,   &
                        XVARP,XSDP,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES ONE OF THE FOLLOWING:
!
!                 1. POOLED VARIANCE FROM RAW DATA
!                 2. POOLED VARIANCE FROM SUMMARY DATA
!                 3. POOLED STANDARD DEVIATION FROM RAW DATA
!                 4. POOLED STANDARD DEVIATION FROM SUMMARY DATA
!
!              THE FORMULA FOR THE POOLED VARIANCE IS:
!
!                V(pooled) = {n1*s1**2 + n2*s2**2 + .. + nk*sk**2}/
!                            (n1 + n2 + ... + nk - k)
!
!              WHERE k IS THE NUMBER OF GROUPS, n1, n2, ...,  Nk
!              DENOTE THE SAMPLE SIZES FOR THE GROUPS AND s1, s2, ..., sk
!              DENOTE THE VARIANCES FOR THE GROUPS.
!
!              IF THE SAMPLE SIZES ARE EQUAL, THEN THE POOLED VARIANCE
!              IS SIMPLY THE MEAN OF THE INDIIVIDUAL VARIANCES.
!
!              THE POOLED STANDARD DEVIATION IS SIMPLY THE SQUARE
!              ROOT OF THE POOLED VARIANCE.
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                                FOR SUMMARY DATA, THIS WILL BE THE
!                                GROUP VARIANCES (OR STANDARD
!                                DEVIATIONS)
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                GROUP ID's.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!                     --ICASE1  = SPECIFY WHETHER RAW DATA OR SUMMARY
!                                 DATA IS GIVEN
!                     --ICASE2  = SPECIFY WHETHER SUMMARY DATA HAS
!                                 VARIANCES OR STANDARD DEVIATIONS
!     OUTPUT ARGUMENTS--XVARP  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE POOLED VARIANCE
!                     --XSDP   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE POOLED STANDARD
!                                DEVIATION
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE POOLED VARIANCE AND POOLED STANDARD DEVIATION.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DISTIN, MEAN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2024.09
!     ORIGINAL VERSION--SEPTEMBER 2024.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASE1
      CHARACTER*4 ICASE2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITET
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='POOL'
      ISUBN2='VA  '
      IERROR='NO'
      IWRITET='NO'
      NUMSET=0
      XVARP=CPUMIN
      XSDP=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'OLSD')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF REPEAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASE1,ICASE2,IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,1X,A4,1X,I8)
        CALL DPWRST('XXX','BUG ')
        DO I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(ICASE1.EQ.'SUMM')THEN
        NMIN=2
      ELSE
        NMIN=4
      ENDIF
!
      IF(N.LT.NMIN)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPUTING VARIANCE (SD)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)NMIN
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN ',I1,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ICASE1.EQ.'SUMM')THEN
        DO II=1,N
          NI=INT(X(II)+0.5)
          IF(Y(II).LT.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            IF(ICASE2.EQ.'VARI')THEN
              WRITE(ICOUT,122)II
  122         FORMAT('      GROUP ',I8,' HAS A NEGATIVE VARIANCE.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,127)Y(II)
  127         FORMAT('      THE VARIANCE = ',G15.7)
              CALL DPWRST('XXX','BUG ')
            ELSE
              WRITE(ICOUT,132)II
  132         FORMAT('      GROUP ',I8,' HAS A NEGATIVE STANDARD ',   &
                     'DEVIATION.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,137)Y(II)
  137         FORMAT('      THE STANDARD DEVIATION = ',G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
            IERROR='YES'
            GO TO 9000
          ELSEIF(NI.LT.1)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,142)II
  142       FORMAT('      GROUP ',I8,' HAS A NON-POSITIVE SAMPLE SIZE.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,147)NI
  147       FORMAT('      THE SAMPLE SIZE = ',I6)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDDO
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  COMPUTE THE POOLED VARIANCE                   **
!               ****************************************************
!
      IF(ICASE1.EQ.'SUMM')THEN
        SUM1=0.0D0
        SUM2=0.0D0
        IF(ICASE2.EQ.'VAR')THEN
          DO II=1,N
             SVAL=Y(II)
             NI=INT(X(II) + 0.5)
             SUM1=SUM1 + DBLE(NI-1)*SVAL
             SUM2=SUM2 + DBLE(NI)
          ENDDO
        ELSE
          DO II=1,N
             SVAL=Y(II)**2
             NI=INT(X(II) + 0.5)
             SUM1=SUM1 + DBLE(NI-1)*SVAL
             SUM2=SUM2 + DBLE(NI)
          ENDDO
          XVARP=SUM1/(SUM2 - REAL(N))
          XSDP=SQRT(XVARP)
        ENDIF
      ELSE
        CALL DISTIN(X,N,IWRITET,XIDTEM,NUMSET,IBUGA3,IERROR)
        CALL SORT(XIDTEM,NUMSET,XIDTEM)
!
        IF(NUMSET.LT.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,192)
  192     FORMAT('      THE NUMBER OF GROUPS IS LESS THAN 1')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        ANUMSE=NUMSET
        SUM1=0.0D0
        SUM2=0.0D0
        J=0
        DO ISET1=1,NUMSET
           K=0
           DO I=1,N
              IF(XIDTEM(ISET1).EQ.X(I))THEN
                K=K+1
                TEMP(K)=Y(I)
              ENDIF
           ENDDO
           NTEMP=K
           CALL VAR(TEMP,NTEMP,IWRITET,XVAR,IBUGA3,IERROR)
           SUM1=SUM1 + REAL(NTEMP-1)*XVAR
           SUM2=SUM2 + REAL(NTEMP)
!
           IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'OLSD')THEN
             WRITE(ICOUT,1131)ISET1,NTEMP,XVAR,SUM1,SUM2
 1131        FORMAT('GROUP ',I8,': N,XVAR,SUM1,SUM2 = ',I8,2X,3G15.7)
             CALL DPWRST('XXX','BUG ')
           ENDIF
!
        ENDDO
!
        XVARP=SUM1/(SUM2 - ANUMSE)
        XSDP=SQRT(XVARP)
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(ICASE2.EQ.'VARI')THEN
          WRITE(ICOUT,811)XVARP
  811     FORMAT('THE POOLED VARIANCE = ',E15.7)
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,821)XSDP
  821     FORMAT('THE POOLED STANDARD DEVIATION = ',E15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'OLSD')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF POOLED VARIANCE/SD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,NUMSET,XVARP,XSDP
 9012   FORMAT('IERROR,NUMSET,XVARP,XSDP = ',A4,2X,I6,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE POOLSD
      SUBROUTINE POSSD(Y,POSID,XIDTEM,N,TEMP,TEMPME,TEMPSD,TEMPN,IWRITE, &
                       SPOS,SPOSMN,SE,NUMSET,AK,                         &
                       FSTAT,IDF1,IDF2,FCDFVAL,PVAL,                     &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE STANDARD DEVIATION OF
!              POSITION EFFECTS FOR COMMUTABILITY STUDIES.  THIS IS
!              COMPUTED FOR THE REFERENCE MATERIALS.  THIS IS FOR THE
!              CASE OF A SINGLE REFERENCE MATERIAL AND A SINGLE MEASUREMENT
!              PROCESS. SPECIFICALLY THE FORMULA IS:
!
!                 s(pos) = SQRT(s(pos-mean)**2 - s(e)**2/k)
!
!              WHERE
!
!                 k            = NUMBER OF REPLICATIONS
!                 s(e)         = THE POOLED STANDARD DEVIATION OF THE
!                                STANDARD DEVIATIONS WITHIN POSITIONS
!                 s(pos-mean)  = THE STANDARD DEVIATION OF THE POSITION
!                                MEANS
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF RESPONSE
!                                VALUES
!                     --POSID  = THE SINGLE PRECISION VECTOR OF POSITION ID's.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS IN Y.
!     OUTPUT ARGUMENTS--SPOS   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE POSITION SD.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE POSITION SD.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DISTIN, SD, POOLSD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NILSSON, et. al. (2018), "IFCC Working Group Recommendations
!                 for Assessing Commutability Part 2: Using the
!                 Difference in Bias Between a Reference Material and
!                 Clinical Samples," Clinical Chemistry, 64(3),
!                 pp. 455-464.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2024.11
!     ORIGINAL VERSION--NOVEMBER  2024.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION POSID(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPME(*)
      DIMENSION TEMPSD(*)
      DIMENSION TEMPN(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='POSS'
      ISUBN2='D   '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'OSSD')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF POSSD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,1X,A4,1X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),POSID(I)
   56     FORMAT('I,Y(I),POSID(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPUTING POSITION SD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  COMPUTE THE POSITION     STANDARD DEVIATION.  **
!               ****************************************************
!
      IWRITE='OFF'
      CALL MEAN(Y,N,IWRITE,POSMEANY,IBUGA3,IERROR)
!
      CALL DISTIN(POSID,N,IWRITE,XIDTEM,NUMSET,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NUMSET,XIDTEM)
!
      IF(NUMSET.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,192)
  192   FORMAT('      THE NUMBER OF DISTINCT POSITIONS IS LESS THAN 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,197)NUMSET
  197   FORMAT('      THE NUMBER OF DISTINCT POSITIONS = ',I6)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      AN=N
      ANUMSE=NUMSET
!
      J=0
      IFLAGE=0
      SUM1=0.0
      SUM2=0.0
      DO ISET1=1,NUMSET
        K=0
        DO I=1,N
          IF(XIDTEM(ISET1).EQ.POSID(I))THEN
            K=K+1
            TEMP(K)=Y(I)
          ENDIF
        ENDDO
        NTEMP=K
        IF(ISET1.EQ.1)THEN
          KSAVE=NTEMP
        ELSE
          IF(NTEMP.NE.KSAVE .AND. IFLAGE.EQ.0)THEN
            IFLAGE=1
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1121)
 1121       FORMAT('****** WARNING-- AN UNEQUAL NUMBER OF REPLICATIONS ',  &
                   'WAS DETECTED.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1122)KSAVE
 1122       FORMAT('      NUMBER OF REPLICATIONS EXPECTED: ',I6)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1124)NTEMP
 1124       FORMAT('      NUMBER OF REPLICATIONS FOUND:    ',I6)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
        CALL MEAN(TEMP,NTEMP,IWRITE,XMEAN,IBUGA3,IERROR)
        CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
        XVAR=XSD**2
        SUM1=SUM1 + REAL(NTEMP-1)*XVAR
        SUM2=SUM2 + REAL(NTEMP)
        TEMPME(ISET1)=XMEAN
        TEMPSD(ISET1)=XSD
        TEMPN(ISET1)=REAL(K)
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'OSSD')THEN
          WRITE(ICOUT,1131)ISET1,TEMPME(ISET1),TEMPSD(ISET1),TEMPN(ISET1)
 1131     FORMAT('ISET1,TEMPME(ISET1),TEMPSD(ISET1),TEMPN(ISET1) = ',I8,2G15.7,G15.1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1133)XVAR,SUM1,SUM2
 1133     FORMAT('XVAR,SUM1,SUM2 = ',3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ENDDO
!
      CALL SD(TEMPME,NUMSET,IWRITE,SPOSMN,IBUGA3,IERROR)
      XVARP=SUM1/(SUM2 - ANUMSE)
      SE=SQRT(XVARP)
      IF(IFLAGE.EQ.0)THEN
        AK=REAL(KSAVE)
      ELSE
        CALL MEAN(TEMPN,NUMSET,IWRITE,AK,IBUGA3,IERROR)
      ENDIF
!
      AVAL=SPOSMN**2 - (SE**2/AK)
      SPOS=0.0
      IF(AVAL.GT.0.0) SPOS=SQRT(SPOSMN**2 - (SE**2/AK))
      FSTAT=AK*SPOSMN**2/(SE**2)
      IDF1=NUMSET-1
      IDF2=(INT(AK+0.01)-1)*NUMSET
      CALL FCDF(FSTAT,IDF1,IDF2,FCDFVAL)
      PVAL=1.0 - FCDFVAL
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'OSSD')THEN
        WRITE(ICOUT,1141)XVARP,SE,SPOSMN,XVARP,SE,SPOS
 1141   FORMAT('XVARP,SE,SPOSMN,XVARP,SE,SPOS = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1143)FSTAT,FCDFVAL,PVAL
 1143   FORMAT('FSTAT,FCDFVAL,PVAL = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)SPOS
  811   FORMAT('THE POSITION STANDARD DEVIATION = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'OSSD')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF POSSD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,NUMSET,SPOSMN,SE,SPOS,AMEAN
 9012   FORMAT('IERROR,NUMSET,SPOSMN,SE,SPOS,AMEAN = ',A4,2X,I6,4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE POSSD
      SUBROUTINE POSTTR(ICTEXT,NCTEXT,ICASE,MAXSYM,   &
      ISTART,ISTOP,IFONT,SIZE,OFFSET,NSTRIN,NSPEC,   &
      IFLAGG,   &
      ISUBRO,IBUGG3)
!
!     PURPOSE--FOR POSTSCRIPT OUTPUT, WE WOULD LIKE TO BE ABLE
!              MAINTAIN THE HIGH QUALITY TYPE SET FONTS WHEN THE
!              TEXT CONTAINS SPECIAL CHARACTERS (E.G., SUBSCRIPTS,
!              SUPER SCRIPTS, GREEK CHARACTERS).  NORMALLY, THESE
!              REQUIRE THAT WE USE A SOFTWARE FONT.  WHEN WE ARE
!              USING A HARDWARE FONT, THIS ROUTINE WILL SCAN THE
!              TEXT STRING AND CHECK FOR:
!
!                 1) SUBSCRIPTS
!                 2) SUPERSCRIPTS
!                 3) GREEK CHARACTERS
!
!             WE MAY ADD ADDITIONAL SPECIAL CHARACTERS AT A LATER
!             DATE, BUT THESE WILL ALLOW MANY GRAPHS INTENDED FOR
!             PUBLICATION TO USE THE POSTSCRIPT FONTS THAT WOULD
!             OTHERWISE REQUIRE THE USE OF SOFTWARE FONTS.
!
!             THE BASIC ALGORITHM IS TO SPLIT THE FULL STRING INTO
!             A NUMBER OF SUBSTRINGS.  SPECIFICALLY, THIS ROUTINE WILL
!             RETURN:
!
!                  1) NSPEC = 0 => NO SPECIAL CHARACTERS DETECTED
!                           = 1 => SPECIAL CHARACTERS DETECTED
!
!                  2) NSTRIN = NUMBER OF SUBSTRINGS RETURNED
!
!                  3) ISTART = ARRAY CONTAINING THE STARTING
!                              POSITIONS OF THE SUBSTRINGS
!
!                  4) ISTOP  = ARRAY CONTAINING THE STOPPING
!                              POSITIONS OF THE SUBSTRINGS
!                  5) IFONT  = ARRAY CONTAINING THE FONT OF THE
!                              SUBSTRINGS (0 => DEFAULT, 1 => SYMBOL)
!
!                  6) SIZE   = ARRAY CONTAINING THE CHARACTER HEIGHT
!                              OF THE SUBSTRINGS (SPECIFIED AS A
!                              SCALE FACTOR)
!
!                  7) OFFSET = ARRAY CONTAINING THE VERTICAL OFFSET
!                              OF THE SUBSTRINGS
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.2
!     ORIGINAL VERSION--FEBRUARY  2009.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG3
!
      CHARACTER*4 ICTEXT(*)
!
      CHARACTER*1 IC1
      CHARACTER*1 IC2
      CHARACTER*1 IC3
      CHARACTER*1 IC4
      CHARACTER*1 IC5
      CHARACTER*1 IC6
!
      DIMENSION ISTART(*)
      DIMENSION ISTOP(*)
      DIMENSION IFONT(*)
      DIMENSION SIZE(*)
      DIMENSION OFFSET(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'STTR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF POSTTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)NCTEXT,MAXSYM
   55   FORMAT('NCTEXT,MAXSYM = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)(ICTEXT(I),I=1,MIN(NCTEXT,25))
   56   FORMAT('(ICTEXT(I),I=1,NCTEXT) = ',25A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,79)ICASE,IBUGG3,ISUBRO
   79   FORMAT('ICASE,IBUGG3,ISUBRO = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      NSTRIN=0
      NSPEC=0
      DO 100 I=1,MAXSYM
        ISTART(I)=-99
        ISTOP(I)=-99
        IFONT(I)=0
        SIZE(I)=0.0
        OFFSET(I)=0.0
  100 CONTINUE
      IF(NCTEXT.LE.5)GO TO 9000
      NSKIP=0
!
      DO 1000 I=1,NCTEXT-4
!
        IF(NSKIP.GT.0)THEN
          NSKIP=NSKIP-1
          GO TO 1000
        ENDIF
!
        IC5=' '
        IC6=' '
        IF(I.LE.NCTEXT)IC1=ICTEXT(I)(1:1)
        IF(I+1.LE.NCTEXT)IC2=ICTEXT(I+1)(1:1)
        IF(I+2.LE.NCTEXT)IC3=ICTEXT(I+2)(1:1)
        IF(I+3.LE.NCTEXT)IC4=ICTEXT(I+3)(1:1)
        IF(I+4.LE.NCTEXT)IC5=ICTEXT(I+4)(1:1)
        IF(I+5.LE.NCTEXT)IC6=ICTEXT(I+5)(1:1)
        CALL DPCOAN(IC1,IJUNK)
        IF(IJUNK.GE.97 .AND. IJUNK.LE.122)CALL DPCONA(IJUNK-32,IC1)
        CALL DPCOAN(IC2,IJUNK)
        IF(IJUNK.GE.97 .AND. IJUNK.LE.122)CALL DPCONA(IJUNK-32,IC2)
        CALL DPCOAN(IC3,IJUNK)
