!
!       STEP 5: SUBSCRIPT/SUPERSCRIPT SPECIAL CHARACTERS FOUND
!
!               CASE 5A: MAXIMUM NUMBER OF SPECIAL CHARACTERS
!                        EXCEEDED
!               CASE 5B: FIRST OCCURENCE
!               CASE 5C: AT END OF STRING
!               CASE 5D: NOT FIRST OCCURENCE AND NOT END OF STRING
!
 1090   CONTINUE
        IF(NSTRIN.GT.MAXSYM)THEN
          ISTOP(NSTRIN)=NCTEXT
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1091)
 1091     FORMAT('***** ERROR IN POSTTR--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1092)
 1092     FORMAT('      MAXIMUM NUMBER OF SPECIAL CHARACTERS EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1093)
 1093     FORMAT('      REMAINING SPECIAL CHARACTERS WILL NOT BE ',   &
                 'PROCESSED.')
          CALL DPWRST('XXX','BUG ')
          GO TO 1999
        ELSEIF(NSTRIN.EQ.MAXSYM)THEN
          ISTOP(NSTRIN)=NCTEXT
          GO TO 1999
        ELSEIF(NSPEC.EQ.0)THEN
          NSPEC=1
          IF(I.GT.1)THEN
            NSTRIN=NSTRIN+1
            ISTART(NSTRIN)=1
            ISTOP(NSTRIN)=I-1
            IFONT(NSTRIN)=0
            SIZE(NSTRIN)=0.0
            OFFSET(NSTRIN)=0.0
          ENDIF
          IF(ILASTT+1.GT.NCTEXT)GO TO 1999
          NSTRIN=NSTRIN+1
          ISTART(NSTRIN)=ILASTT+1
          IFONT(NSTRIN)=IFONTT
          SIZE(NSTRIN)=ASIZET
          OFFSET(NSTRIN)=OFFT
        ELSE
!
!         STEP 1: CLOSE PREVIOUS STRING
!         STEP 2: STRING FOR CURRENT CHARACTER
!         STEP 3: START NEXT STRING
!
          IF(ISTART(NSTRIN).EQ.I)THEN
            IF(ILASTT+1.GT.NCTEXT)THEN
              NSTRIN=NSTRIN-1
              GO TO 1999
            ENDIF
            ISTART(NSTRIN)=ILASTT+1
            IFONT(NSTRIN)=IFONTT
            SIZE(NSTRIN)=ASIZET
            OFFSET(NSTRIN)=OFFT
          ELSE
            IF(NSTRIN.EQ.0)NSTRIN=1
            ISTOP(NSTRIN)=I-1
            IF(ILASTT+1.GT.NCTEXT)GO TO 1999
            NSTRIN=NSTRIN+1
            ISTART(NSTRIN)=ILASTT+1
            IFONT(NSTRIN)=IFONTT
            SIZE(NSTRIN)=ASIZET
            OFFSET(NSTRIN)=OFFT
          ENDIF
        ENDIF
        GO TO 1000
!
!       STEP 6: GREEK SPECIAL CHARACTERS FOUND
!
!               CASE 6A: MAXIMUM NUMBER OF SPECIAL CHARACTERS
!                        EXCEEDED
!               CASE 6B: FIRST OCCURENCE
!               CASE 6C: AT END OF STRING
!               CASE 6D: NOT FIRST OCCURENCE AND NOT END OF STRING
!
 1190   CONTINUE
        IF(NSTRIN.GT.MAXSYM)THEN
          ISTOP(NSTRIN)=NCTEXT
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1191)
 1191     FORMAT('***** ERROR IN POSTTR--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1192)
 1192     FORMAT('      MAXIMUM NUMBER OF SPECIAL CHARACTERS EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1193)
 1193     FORMAT('      REMAINING SPECIAL CHARACTERS WILL NOT BE ',   &
                 'PROCESSED.')
          CALL DPWRST('XXX','BUG ')
          GO TO 1999
        ELSEIF(NSTRIN.EQ.MAXSYM)THEN
          ISTOP(NSTRIN)=NCTEXT
          GO TO 1999
        ELSEIF(NSPEC.EQ.0)THEN
          NSPEC=1
          IF(I.GT.1)THEN
            NSTRIN=NSTRIN+1
            ISTART(NSTRIN)=1
            ISTOP(NSTRIN)=I-1
            IFONT(NSTRIN)=0
            SIZE(NSTRIN)=0.0
            OFFSET(NSTRIN)=0.0
          ENDIF
          NSTRIN=NSTRIN+1
          ISTART(NSTRIN)=I
          ISTOP(NSTRIN)=I
          IFONT(NSTRIN)=IFONTT
          SIZE(NSTRIN)=ASIZET
          OFFSET(NSTRIN)=OFFT
          IF(ILASTT+1.GT.NCTEXT)GO TO 1999
          NSTRIN=NSTRIN+1
          ISTART(NSTRIN)=ILASTT+1
          IFONT(NSTRIN)=0
          SIZE(NSTRIN)=0.0
          OFFSET(NSTRIN)=0.0
        ELSE
!
!         STEP 1: CLOSE PREVIOUS STRING
!                 NOTE: IF PREVIOUS STRING IS EMPTY (E.G., SOMETHING
!                       LIKE SUP()ALPH() ), THEN WE NEED TO PRESERVE
!                       THE FONT, SIZE, AND OFFSET INFO.
!         STEP 2: STRING FOR CURRENT CHARACTER
!         STEP 3: START NEXT STRING
!
          IF(ISTART(NSTRIN).EQ.I)THEN
            IF(NSTRIN.EQ.0)NSTRIN=1
            ISTOP(NSTRIN)=I
!CCCC       IFONT(NSTRIN)=IFONTT
!CCCC       SIZE(NSTRIN)=ASIZET
!CCCC       OFFSET(NSTRIN)=OFFT
          ELSE
            IF(NSTRIN.EQ.0)NSTRIN=1
            ISTOP(NSTRIN)=I-1
            NSTRIN=NSTRIN+1
            ISTART(NSTRIN)=I
            ISTOP(NSTRIN)=I
            IFONT(NSTRIN)=IFONTT
            SIZE(NSTRIN)=ASIZET
            OFFSET(NSTRIN)=OFFT
          ENDIF
          IF(ILASTT+1.GT.NCTEXT)GO TO 1999
          NSTRIN=NSTRIN+1
          ISTART(NSTRIN)=ILASTT+1
          IFONT(NSTRIN)=0
          SIZE(NSTRIN)=0.0
          OFFSET(NSTRIN)=0.0
        ENDIF
        GO TO 1000
!
 1000 CONTINUE
 1999 CONTINUE
!
!CCCC IF(NSTRIN.GE.1 .AND. ISTOP(NSTRIN).LE.0)ISTOP(NSTRIN)=NCTEXT
      IF(NSTRIN.GE.1)THEN
        IF(ISTOP(NSTRIN).LE.0)ISTOP(NSTRIN)=NCTEXT
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'STTR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF POSTTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NSPEC,NSTRIN
 9013   FORMAT('NSPEC,NSTRIN = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NSPEC.GE.1 .AND. NSTRIN.GE.1)THEN
          DO 9021 I=1,NSTRIN
            WRITE(ICOUT,9023)I,ISTART(I),ISTOP(I),IFONT(I),SIZE(I),   &
                             OFFSET(I)
 9023       FORMAT('I,ISTART(I),ISTOP(I),IFONT(I),SIZE(I),OFFSET(I)=',   &
                   4I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
 9021     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE POSTTR
      SUBROUTINE POWCDF(X,C,CDF)
!
!     NOTE--THE STANDARD POWER FUNCTION CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              POWCDF(X,C) = X**C        0 <= X <= 1, C > 0
!
!           WITH C DENOTING THE SCALE PARAMETER.
!     REFERENCE --EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, WILEY, CHAPTER 33.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --RDECEMBER 2007. RECODED A BIT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(X.LE.0.0)THEN
        CDF=0.0
        GO TO 9999
      ELSEIF(X.GE.1.0)THEN
        CDF=1.0
        GO TO 9999
      ENDIF
!
      IF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
  311 FORMAT('***** ERROR IN POWCDF--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(X)
      DC=DBLE(C)
      DCDF=DX**DC
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE POWCDF
      SUBROUTINE POWELD(X,E,N,F,ESCALE,IPRNT,ICON,MAXITF,PNRFUN,   &
                        TIMEL,TIMEU,RLENGT)
!
! *   AUTHORS: Necip Doganaksoy and Wayne Nelson
! *   PURPOSE: Maximum likelihood fitting of the power-normal and
! *            -lognormal models to censored life or strength data
! *            from specimens of various sizes
! *   DOCUMENTATION: Wayne Nelson and Necip Doganaksoy, "A Computer
! *                  Program POWNOR for Fitting the Power-Normal and
! *                  -Lognormal Models to Life or Strength Data from
! *                  Specimens of Various Sizes", NISTIR 4760, 3/1992.
! *   PROJECT: 1990-91 ASA/NIST/NSF Fellowship
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      DOUBLE PRECISION TIMEL(*)
      DOUBLE PRECISION TIMEU(*)
      DOUBLE PRECISION RLENGT(*)
!
      LOGICAL LTP
      LOGICAL LDUMP
!
      COMMON/PNRLST/LTP
      COMMON/PNRIO/INPUT,IOUT
      COMMON/PNRSSS/SCRAT(300)
!
      DIMENSION X(N),E(N)
      DIMENSION W(100)
!
      EXTERNAL PNRFUN
!
      REAL R1MACH
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA FOUR/4.0D00/
!CCCC DATA ZERO,PZ3,PZ5,P1,P4,HALF,ONE,TWO,FIVE,TEN,TWENTY/
!CCCC@0.0D00,0.03D00,0.05D00,0.1D00,0.4D00,0.5D00,1.0D00,2.0D00,5.0D00,
!CCCC@10.0D00,20.0D00/
      DATA ZERO,PZ3,PZ5,P1,HALF,ONE,TWO,FIVE,TEN,TWENTY/   &
      0.0D00,0.03D00,0.05D00,0.1D00,0.5D00,1.0D00,2.0D00,5.0D00,   &
      10.0D00,20.0D00/
!
!     POWELL ALGORTHIM FOR MINIMIZING A FUNCTION OF N VARIABLES
!     WITHOUT THE USE OF DERIVATIVES.
!
      MAXIT=MAXITF
      D=0.0
      DB=0.0
      DC=0.0
      FPREV=0.0
      FHOLD=0.0
      FC=0.0
      FB=0.0
      JTL=0
!
      LDUMP=.FALSE.
      NM1=N-1
      LTP=.TRUE.
      FSAVQ=1.0D35
      IPRNT2=IPRNT
      KTO=0
      IF(IPRNT.EQ.5)THEN
         KTO=1
         IPRNT2=1
      ENDIF
      DDMAG=P1*ESCALE
      SCER=PZ5/ESCALE
      JJ=N*N+N
      JJJ=JJ+N
      K=N+1
      NFCC=1
      IND=1
      INN=1
!
      DO 1 I=1,N
         DO 2 J=1,N
            W(K)=ZERO
            IF(I.EQ.J)THEN
               W(K)=DABS(E(I))
               W(I)=ESCALE
            ENDIF
            K=K+1
2        CONTINUE
1     CONTINUE
!
      ITERC=1
      ISGRAD=2
      F=PNRFUN(X,N,TIMEL,TIMEU,RLENGT)
      FKEEP=DABS(F)+DABS(F)
!
 5    CONTINUE
!
      ITONE=1
      FP=F
      SUM=ZERO
      IXP=JJ
      DO 6 I=1,N
         IXP=IXP+1
         W(IXP)=X(I)
 6    CONTINUE
      IDIRN=N+1
      ILINE=1
!
 7    CONTINUE
!
      DMAX=W(ILINE)
      DACC=DMAX*SCER
      DMAG=DMIN1(DDMAG, P1*DMAX)
      DMAG=DMAX1(DMAG,TWENTY*DACC)
      DDMAX=TEN*DMAG
      IF(ITONE.EQ.3)GO TO 71
      DL=ZERO
      D=DMAG
      FPREV=F
      IS=5
      FA=F
      DA=DL
!
 8    CONTINUE
!
      DD=D-DL
      DL=D
!
 58   CONTINUE
      K=IDIRN
      DO 9 I=1,N
         X(I)=X(I)+DD*W(K)
         K=K+1
9     CONTINUE
      F=PNRFUN(X,N,TIMEL,TIMEU,RLENGT)
      NFCC=NFCC+1
      GO TO(10,11,12,13,14,96),IS
14    CONTINUE
      IF(F.LT.FA)THEN
         FB=F
         DB=D
         GO TO 21
      ELSEIF(F.EQ.FA)THEN
         IF(DABS(D).LE.DMAX)THEN
            D=D+D
            GO TO 8
         ELSE
            WRITE(ICOUT,19)
19          FORMAT(5X,'MAXIMUM CHANGE DOES NOT ALTER FUNCTION')
            CALL DPWRST('XXX','WRIT')
            RETURN
         ENDIF
      ENDIF
      FB=FA
      DB=DA
      FA=F
      DA=D
!
21    CONTINUE
      IF(ISGRAD.NE.1)GO TO 921
         D=HALF*(DA+DB-(FA-FB)/(DA-DB))
         IS=4
         IF((DA-D)*(D-DB).GE.0.0D0)GO TO 8
25       CONTINUE
         IS=1
         IF(DABS(D-DB)-DDMAX.LE.0.0D0)GO TO 8
26       CONTINUE
         D=DB+DSIGN(DDMAX,DB-DA)
         IS=1
         DDMAX=DDMAX+DDMAX
         DDMAG=DDMAG+DDMAG
         IF(DDMAX.LE.DMAX)GO TO 8
         DDMAX=DMAX
         GO TO 8
921   CONTINUE
!
23    CONTINUE
      D=DB+DB-DA
      IS=1
      GO TO 8
!
 13   IF(F.GE.FA)GO TO 23
 28   CONTINUE
      FC=FB
      DC=DB
29    CONTINUE
      FB=F
      DB=D
      GO TO 30
!
12    IF(F.LE.FB)GO TO 28
      FA=F
      DA=D
      GO TO 30
!
11    CONTINUE
      IF(F.GE.FB)GO TO 10
      FA=FB
      DA=DB
      GO TO 29
!
71    DL=ONE
      DDMAX=FIVE
      FA=FP
      DA=-ONE
      FB=FHOLD
      DB=ZERO
      D=ONE
!
10    CONTINUE
      FC=F
      DC=D
!
30    CONTINUE
      A=(DB-DC)*(FA-FC)
      B=(DC-DA)*(FB-FC)
      IF((A+B)*(DA-DC).LE.0.0D0)THEN
         FA=FB
         DA=DB
         FB=FC
         DB=DC
         GO TO 26
      ELSE
         D=HALF*(A*(DB+DC)+B*(DA+DC))/(A+B)
         DI=DB
         FI=FB
         IF(FB.GT.FC)THEN
            DI=DC
            FI=FC
         ENDIF
         IF(ITONE.EQ.2)THEN
            ITONE=2
            GO TO 45
         ENDIF
      ENDIF
      IF(DABS(D-DI)-DACC.LE.0.0D0)GO TO 41
      IF(DABS(D-DI)- PZ3*DABS(D).LE.0.0D0)GO TO 41
45    CONTINUE
      IF((DA-DC)*(DC-D).GE.0.0D0)THEN
         FA=FB
         DA=DB
         FB=FC
         DB=DC
         GO TO 25
      ELSE
        IS=2
        IF((DB-D)*(D-DC).GE.0.0D0)GO TO 8
        IS=3
        GO TO 8
      ENDIF
41    CONTINUE
      F=FI
      D=DI-DL
      DD=DSQRT((DC-DB)*(DC-DA)*(DA-DB)/(A+B))
      DO 49 I=1,N
         X(I)=X(I)+D*W(IDIRN)
         W(IDIRN)=DD*W(IDIRN)
         IDIRN=IDIRN+1
49    CONTINUE
      W(ILINE)=W(ILINE)/DD
      ILINE=ILINE+1
      IF(IPRNT2.EQ.1)THEN
         IF(KTO.EQ.1) THEN
            FMVAL=-F
            WRITE(ICOUT,555)ITERC,NFCC,FMVAL,(X(I),I=1,N)
555         FORMAT(2X,I4,12X,I5,8X,D16.5,2X,6D13.5)
            CALL DPWRST('XXX','WRIT')
         ELSE
            WRITE(ICOUT,52)ITERC,NFCC
52          FORMAT(' ITERATION ',I5,I10,' FUNCT. EVAL.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,952)F
952         FORMAT(' F =',E18.8)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,953)(X(I),I=1,N)
953         FORMAT(8F14.8)
            CALL DPWRST('XXX','WRIT')
         ENDIF
         IF(IPRNT2.EQ.2)GO TO 53
      ENDIF
      IF(ITONE.EQ.2)GO TO 38
      IF(FPREV-F-SUM.GE.0.0D0)THEN
         SUM=FPREV-F
         JTL=ILINE
      ENDIF
      IF(IDIRN.LE.JJ)GO TO 7
      IF(IND.EQ.2)GO TO 72
!
 92   CONTINUE
      FHOLD=F
      IS=6
      IXP=JJ
      DO 59 I=1,N
         IXP=IXP+1
         W(IXP)=X(I)-W(IXP)
59    CONTINUE
      DD=ONE
      GO TO 58
!
 96   CONTINUE
      IF(IND.EQ.1)THEN
         IF(FP-F.LE.0.0D0)GO TO 37
         D=TWO*(FP+F-TWO*FHOLD)/(FP-F)**2
         IF(D*(FP-FHOLD-SUM)**2-SUM.GE.0.0D0)GO TO 37
      ENDIF
      J=JTL*N+1
      IF(J.GT.JJ)THEN
         DO 62 I=J,JJ
            K=I-N
            W(K)=W(I)
62       CONTINUE
         DO 97 I=JTL,N
            W(I-1)=W(I)
97       CONTINUE
      ENDIF
      IDIRN=IDIRN-N
      ITONE=3
      K=IDIRN
      IXP=JJ
      AAA=ZERO
      DO 65 I=1,N
         IXP=IXP+1
         W(K)=W(IXP)
         IF(AAA-DABS(W(K)/E(I)).LE.0.0D0)THEN
            AAA=DABS(W(K)/E(I))
         ENDIF
         K=K+1
65    CONTINUE
      DDMAG=ONE
      W(N)=ESCALE/AAA
      ILINE=N
      GO TO 7
!
 37   IXP=JJ
      AAA=ZERO
      F=FHOLD
      DO 99 I=1,N
         IXP=IXP+1
         X(I)=X(I)-W(IXP)
         IF(AAA*DABS(E(I))-DABS(W(IXP)).LE.0.0D0)THEN
            AAA=DABS(W(IXP)/E(I))
         ENDIF
99    CONTINUE
      GO TO 72
!
 38   CONTINUE
      AAA=AAA*(ONE+DI)
      IF(IND.EQ.2)GO TO 106
!
72    CONTINUE
!
      IF(IPRNT2.LT.2)THEN
         IF(KTO.EQ.1) THEN
            FMVAL=-F
            WRITE(ICOUT,555)ITERC,NFCC,FMVAL,(X(I),I=1,N)
            CALL DPWRST('XXX','WRIT')
         ELSE
            WRITE(ICOUT,52)ITERC,NFCC
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,952)F
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,953)(X(I),I=1,N)
            CALL DPWRST('XXX','WRIT')
         ENDIF
      ENDIF
!
 53   CONTINUE
      IF(IND.EQ.2)GO TO 88
      IF(AAA.GT.P1)GO TO 76
      IF(ICON.EQ.1)RETURN
      IND=2
      IF(INN.EQ.2)GO TO 101
      INN=2
      K=JJJ
      DO 102 I=1,N
         K=K+1
         W(K)=X(I)
         X(I)=X(I)+TEN*E(I)
102   CONTINUE
      FKEEP=F
      F=PNRFUN(X,N,TIMEL,TIMEU,RLENGT)
      NFCC=NFCC+1
      DDMAG=ZERO
      GO TO 108
!
 76   CONTINUE
      IF(F.LT.FP)GO TO 35
!
 78   CONTINUE
      WRITE(ICOUT,80)
80    FORMAT('ACCURACY LIMITED BY ERRORS IN FUNCTION')
      CALL DPWRST('XXX','WRIT')
      RETURN
!
 88   CONTINUE
      IND=1
!
 35   CONTINUE
      DDMAG=FOUR*DSQRT(FP-F)
      ISGRAD=1
108   CONTINUE
      ITERC=ITERC+1
!
!        CHECK TO SEE IF THE LIKELIHOOD IS CHANGING SLOWLY
!
      IF(.NOT.LTP) GO TO 2002
      IF(DABS(F-FSAVQ).GT.ONE) GO TO 2001
      IF(LDUMP)THEN
         WRITE(ICOUT,4998)
4998     FORMAT('***LOGLIKELIHOOD CHANGED BY LESS THAN ONE IN THIS')
         CALL DPWRST('XXX','WRIT')
         WRITE(ICOUT,4999)
4999     FORMAT('ITERATION.  CHANGING TO UNTRANSFORMED OBSERVATIONS')
         CALL DPWRST('XXX','WRIT')
      ENDIF
      LTP=.FALSE.
2001  FSAVQ=F
2002  CONTINUE
      IF(ITERC.LE.MAXIT)GO TO 5
      WRITE(ICOUT,82)MAXIT
82    FORMAT(1X,I4,' ITERATIONS COMPLETED WITHOUT MEETING ',   &
             'SPECIFICATIONS')
      CALL DPWRST('XXX','WRIT')
      IF(F.LE.FKEEP)RETURN
      F=FKEEP
      DO 111 I=1,N
         JJJ=JJJ+1
         X(I)=W(JJJ)
111   CONTINUE
      RETURN
!
101   JTL=1
      FP=FKEEP
      IF(F.EQ.FKEEP)THEN
         GO TO 78
      ELSEIF(F.GT.FKEEP)THEN
         JTL=2
         FP=F
         F=FKEEP
      ENDIF
      IXP=JJ
      DO 113 I=1,N
         IXP=IXP+1
         K=IXP+N
         IF(JTL.EQ.1)THEN
            W(IXP)=W(K)
         ELSE
            W(IXP)=X(I)
            X(I)=W(K)
         ENDIF
113   CONTINUE
      JTL=2
      GO TO 92
!
106   CONTINUE
      IF(AAA.LE.P1)THEN
         RETURN
      ELSE
         INN=1
         GO TO 35
      ENDIF
!
      END SUBROUTINE POWELD
      SUBROUTINE POWCHA(X,C,HAZ)
!
!     NOTE--THE STANDARD POWER FUNCTION CUMULATIVE HAZARD FUNCTION IS:
!
!              H(X;C) = -LOG(1 - X**C)       0 <= X <= 1, C > 0
!
!           WHERE C IS THE SHAPE PARAMETER.
!     REFERENCE --EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, CHAPTER 33.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DHAZ
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0
      IF(X.LT.0.0 .OR. X.GT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR IN POWCHAZ--THE FIRST ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (0,1).')
  311 FORMAT('***** ERROR IN POWCHAZ--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(X)
      DC=DBLE(C)
      DTERM1=1.0D0 - DX**DC
      IF(DTERM1.GT.0.0D0)THEN
        DHAZ=-DLOG(DTERM1)
        HAZ=REAL(DHAZ)
      ELSE
        WRITE(ICOUT,401)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,402)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
  401 FORMAT('***** ERROR IN POWCHAZ')
  402 FORMAT('      THE COMPUTED VALUE OF THE HAZARD FUNCTION ',   &
             'OVERFLOWS.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE POWCHA
      SUBROUTINE POWHAZ(X,C,HAZ)
!
!     NOTE--THE STANDARD POWER FUNCTION HAZARD FUNCTION IS:
!
!              h(X;C) = C*X**(C-1)/(1 - X**C)     0 <= X <= 1, C > 0
!
!           WHERE C IS THE SHAPE PARAMETER.
!     REFERENCE --EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, CHAPTER 33.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DHAZ
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0
      IF(X.LT.0.0 .OR. X.GT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR IN POWHAZ--THE FIRST ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (0,1).')
  311 FORMAT('***** ERROR IN POWHAZ--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(X)
      DC=DBLE(C)
      DTERM1=DC*DX**(DC-1.0D0)
      DTERM2=1.0D0 - DX**DC
      IF(DTERM2.GT.0.0D0)THEN
        DHAZ=DTERM1/DTERM2
        HAZ=REAL(DHAZ)
      ELSE
        WRITE(ICOUT,401)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,402)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
  401 FORMAT('***** ERROR IN POWHAZ')
  402 FORMAT('      THE COMPUTED VALUE OF THE HAZARD FUNCTION ',   &
             'OVERFLOWS.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE POWHAZ
      SUBROUTINE POWLI1(Y,N,TEMP1,C,XMIN,XMAX,ICASPL,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LOG-LIKELIHOOD FUNCTION FOR
!              THE POWER OR THE REFLECTED POWER DISTRIBUTION.  THIS
!              IS FOR THE RAW DATA CASE (I.E., NO GROUPING AND NO
!              CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                DISTRIBUTIONS", THIRD EDITION, WILEY, CHAPTER 33.
!     REFERENCE --KOTZ AND VAN DORP (2004), "BEYOND BETA: OTHER
!                 CONTINUOUS FAMILIES OF DISTRIBUTIONS WITH BOUNDED
!                 SUPPORT AND APPLICATION", WORLD SCIENTIFIC, PP. 199-201.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/9
!     ORIGINAL VERSION--JULY      2010.
!     UPDATED         --JUNE      2013. ACCOMODATE LOWER/UPPER LIMIT
!                                       PARAMETERS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='POWL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF POWLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)ICASPL,IBUGA3,ISUBRO
   52   FORMAT('ICASPL,IBUGA3,ISUBRO = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,XMIN,XMAX
   55   FORMAT('N,XMIN,XMAX = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     NOTE: WE ARE COMPUTING THE LOG-LIKELIHOOD FUNCTION FOR THE
!           STANDARD CASE (I.E., DATA ASSUMED TO BE IN (0,1)
!           INTERVAL).  IF DATA IS NOT IN THIS INTERVAL, THEN
!           WE NEED TO SCALE IT BASED ON THE VALUES OF XMIN AND
!           XMAX.
!
!     NOTE 2013/06: IN ORDER TO KEEP LIKELIHOOD ON SAME SCALE AS
!                   ORIGINAL DATA, ACCOMODATE LOWER/UPPER LIMIT
!                   PARAMETERS.  USE
!
!                   f(x;shape,loc,scale) = f((x-loc)/scale;shape,0,1)/scale
!
!                   SO CAN COMPUTE THE LOG LIKELIHOOD ON THE TRANSFORMED
!                   DATA, BUT SUBTRACT THE TERM
!
!                   N*LOG(SCALE)
!
      ZLOC=XMIN
      ZSCALE=XMAX - XMIN
      DO 2110 I=1,N
        TEMP1(I)=(Y(I) - ZLOC)/ZSCALE
 2110 CONTINUE
!
!     FOR THE POWER FUNCTION, THE LOG-LIKLIHOOD FUNCTION IS:
!
!     N*LOG(C) - N*LOG(UL - LL) + (C-1)*SUM[i=1 to N][LOG((X(i) - )]
!
!     FOR THE REFLECTED POWER FUNCTION, THE LOG-LIKLIHOOD FUNCTION IS:
!
!     N*LOG(C) + (C-1)*SUM[i=1 to N][LOG(1 - X(i))]
!
      DEPS=1.0D-12
      DN=DBLE(N)
      DC=DBLE(C)
      DTERM1=DN*DLOG(DC) - DN*DLOG(DBLE(ZSCALE))
      DTERM2=DC - 1.0D0
      DSUM1=0.0D0
      IF(ICASPL.EQ.'POWE')THEN
        DO 1000 I=1,N
          DX=DBLE(TEMP1(I))
          IF(DX.LE.0.0D0)DX=DEPS
          DSUM1=DSUM1 + DLOG(DX)
 1000   CONTINUE
      ELSE
        DO 1010 I=1,N
          DX=1.0D0 - DBLE(TEMP1(I))
          IF(DX.LE.0.0D0)DX=DEPS
          DSUM1=DSUM1 + DLOG(DX)
 1010   CONTINUE
      ENDIF
!
      DLIK=DTERM1 + DTERM2*DSUM1
      ALIK=REAL(DLIK)
      DNP=1.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF POWLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE POWLI1
      SUBROUTINE POWML1(Y,N,ICASPL,   &
                        XMIN,XMAX,XMEAN,XSD,   &
                        SHAPMO,SHAPML,ZMIN,ZMAX,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF THE SHAPE PARAMETER FOR THE
!              POWER OR REFLECTED POWER DISTRIBUTION.
!     EXAMPLE--POWER MAXIMUM LIKELIHOOD Y
!     REFERENCE--EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                DISTRIBUTIONS", THIRD EDITION, WILEY, CHAPTER 33.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLPW)
!     UPDATED         --JUNE      2013. ALLOW USER-SETTABLE LOWER/UPPER
!                                       LIMITS
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
!
      DOUBLE PRECISION DTEMP
      DOUBLE PRECISION DSUM
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='POWM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
      EPS=0.000001
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF POWML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,ZMIN,ZMAX
   52   FORMAT('IBUGA3,ISUBRO,N,ZMIN,ZMAX = ',2(A4,2X),I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               **********************************************
!               **  STEP 1--                                **
!               **  CARRY OUT CALCULATIONS                  **
!               **  FOR POWER/REFLECTED POWER MLE ESTIMATE  **
!               **********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='POWER'
      IF(ICASPL.NE.'POWE')IDIST='REFLECTED POWER'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(ZMIN.NE.CPUMIN .AND. ZMAX.NE.CPUMAX .AND.   &
         ZMIN.LT.XMIN .AND. ZMAX.GT.XMAX)THEN
        ZLOC=ZMIN
        ZSCALE=ZMAX-ZMIN
        DO 2108 I=1,N
          Y(I)=(Y(I) - ZLOC)/ZSCALE
 2108   CONTINUE
      ELSEIF(XMIN.LE.0.0 .OR. XMAX.GE.1.0)THEN
        ZMIN=XMIN-EPS
        ZMAX=XMAX+EPS
        EPS=(ZMAX - ZMIN)*0.01
        ZMIN=ZMIN - EPS
        ZMAX=ZMAX + EPS
        ZLOC=ZMIN
        ZSCALE=ZMAX-ZMIN
        DO 2110 I=1,N
          Y(I)=(Y(I) - ZLOC)/ZSCALE
          IF(Y(I).LE.0.0)Y(I)=EPS
 2110   CONTINUE
      ELSE
        ZMIN=0.0
        ZMAX=1.0
      ENDIF
      CALL MEAN(Y,N,IWRITE,ZMEAN,IBUGA3,IERROR)
!
      IF(ICASPL.EQ.'POWE')THEN
        SHAPMO=ZMEAN/(1.0 - ZMEAN)
        DSUM=0.0D0
        DO 2120 I=1,N
          DTEMP=DBLE(Y(I))
          IF(DTEMP.LE.0.0D0)GO TO 2120
          DSUM=DSUM + DLOG(DTEMP)
 2120   CONTINUE
        SHAPML=-REAL(DBLE(N)/DSUM)
      ELSE
        SHAPMO=(1.0 - ZMEAN)/ZMEAN
        DSUM=0.0D0
        DO 2130 I=1,N
          DTEMP=DBLE(Y(I))
          IF(DTEMP.GE.1.0D0)GO TO 2130
          DSUM=DSUM + DLOG(1.0D0 - DTEMP)
 2130   CONTINUE
        SHAPML=-REAL(DBLE(N)/DSUM)
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF POWML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9057)SHAPML
 9057   FORMAT('SHAPML = ',G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE POWML1
      SUBROUTINE POWML2(Y,X1,X2,N,NUMV2,ICASPL,   &
                        TEMP1,TEMP2,TEMP3,   &
                        XMIN,XMAX,XMEAN,XSD,NTOT,   &
                        SHAPMO,SHAPML,ZMIN,ZMAX,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF THE SHAPE PARAMETER FOR THE
!              POWER OR REFLECTED POWER DISTRIBUTION.
!              THIS HANDLES THE CAS WHEN THE DATA IS GROUPED.
!     EXAMPLE--POWER MAXIMUM LIKELIHOOD Y
!     REFERENCE--EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                DISTRIBUTIONS", THIRD EDITION, WILEY, CHAPTER 33.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLPW)
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DTEMP
      DOUBLE PRECISION DSUM
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='POWM'
      ISUBN2='L2  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF POWML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),X1(I),X2(I)
   57     FORMAT('I,Y(I),X1(I),X2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR TOPP AND LEONE MLE ESTIMATE     **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='POWER'
      IF(ICASPL.NE.'POWE')IDIST='REFLECTED POWER'
      IFLAG1=0
      IFLAG2=0
      IF(NUMV2.EQ.2)THEN
        CALL SUMGRP(Y,X1,N,IDIST,IFLAG1,IFLAG2,   &
                    TEMP1,TEMP2,TEMP3,MAXNXT,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,NTOT,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ELSEIF(NUMV2.EQ.3)THEN
        CALL SUMGR2(Y,X1,X2,N,IDIST,IFLAG1,IFLAG2,   &
                    TEMP1,TEMP2,TEMP3,MAXNXT,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,NTOT,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ELSE
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NUMV2.EQ.2)THEN
        IF(XMIN.LE.0.0 .OR. XMAX.GE.1.0)THEN
          EPS=1.0E-12
          ZMIN=XMIN-EPS
          ZMAX=XMAX+EPS
          ZLOC=ZMIN
          ZSCALE=ZMAX-ZMIN
          DO 2210 I=1,N
            X1(I)=(X1(I) - ZLOC)/ZSCALE
 2210     CONTINUE
        ELSE
          ZMIN=0.0
          ZMAX=1.0
        ENDIF
        CALL WEMEAN(X1,Y,N,IWRITE,ZMEAN,IBUGA3,IERROR)
        IF(ICASPL.EQ.'POWE')THEN
          SHAPMO=ZMEAN/(1.0 - ZMEAN)
          DSUM=0.0D0
          DO 2320 I=1,N
            DTEMP=DBLE(X1(I))
            IF(DTEMP.LE.0.0D0)GO TO 2320
            DSUM=DSUM + DBLE(Y(I))*DLOG(DTEMP)
 2320     CONTINUE
          SHAPML=-REAL(DBLE(NTOT)/DSUM)
        ELSE
          SHAPMO=(1.0 - ZMEAN)/ZMEAN
          DSUM=0.0D0
          DO 2430 I=1,N
            DTEMP=DBLE(X1(I))
            IF(DTEMP.GE.1.0D0)GO TO 2430
            DSUM=DSUM + DBLE(Y(I))*DLOG(1.0D0 - DTEMP)
 2430     CONTINUE
          SHAPML=-REAL(DBLE(NTOT)/DSUM)
        ENDIF
      ELSEIF(NUMV2.EQ.3)THEN
        IF(XMIN.LE.0.0 .OR. XMAX.GE.1.0)THEN
          EPS=1.0E-12
          ZMIN=XMIN-EPS
          ZMAX=XMAX+EPS
          ZLOC=ZMIN
          ZSCALE=ZMAX-ZMIN
          DO 3210 I=1,N
            X1(I)=(X1(I) - ZLOC)/ZSCALE
            X2(I)=(X2(I) - ZLOC)/ZSCALE
 3210     CONTINUE
        ELSE
          ZMIN=0.0
          ZMAX=1.0
        ENDIF
        IFLAG1=0
        IFLAG2=0
        CALL SUMGR2(Y,X1,X2,N,IDIST,IFLAG1,IFLAG2,   &
                    TEMP1,TEMP2,TEMP3,MAXNXT,   &
                    ZMEAN,ZVAR,ZSD,ZMIN,ZMAX,NTOTZ,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(ICASPL.EQ.'POWE')THEN
          SHAPMO=ZMEAN/(1.0 - ZMEAN)
          DSUM=0.0D0
          DO 3320 I=1,N
            DTEMP=DBLE((X1(I) + X2(I))/2.0)
            IF(DTEMP.LE.0.0D0)GO TO 3320
            DSUM=DSUM + DBLE(Y(I))*DLOG(DTEMP)
 3320     CONTINUE
          SHAPML=-REAL(DBLE(NTOT)/DSUM)
        ELSE
          SHAPMO=(1.0 - ZMEAN)/ZMEAN
          DSUM=0.0D0
          DO 3430 I=1,N
            DTEMP=DBLE((X1(I) + X2(I))/2.0)
            IF(DTEMP.GE.1.0D0)GO TO 3430
            DSUM=DSUM + DBLE(Y(I))*DLOG(1.0D0 - DTEMP)
 3430     CONTINUE
          SHAPML=-REAL(DBLE(NTOT)/DSUM)
        ENDIF
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF POWML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9057)SHAPML,SHAPMO
 9057   FORMAT('SHAPML,SHAPMO = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE POWML2
      SUBROUTINE POWPDF(X,C,PDF)
!
!     NOTE--THE STANDARD POWER FUNCTION PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;C) = C*X**(C-1)      0 <= X <= 1, C > 0
!
!           WITH C DENOTING THE SHAPE PARAMETER.
!     REFERENCE --EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, WILEY, CHAPTER 33.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --DECEMBER  2007. RECODED
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      IF(X.LT.0.0 .OR. X.GT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(X.LE.0.0 .AND. C.LT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR IN POWPDF--THE FIRST ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (0,1).')
  311 FORMAT('***** ERROR IN POWPDF--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(X)
      DC=DBLE(C)
      DPDF=DC*DX**(DC-1.0D0)
      PDF=REAL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE POWPDF
      SUBROUTINE POWRAN(N,C,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE THE POWER FUNCTION
!              DISTRIBUTION WITH SCALE PARAMETER = 1
!              THIS DISTRIBUTION IS DEFINED FOR 0 <= X <= 1
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = C*X**(C-1)/(B**C)
!              WHERE C IS THE SHAPE PARAMETER AND B IS THE SCALE
!              PARAMETER.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE NORMAL DISTRIBUTION
!             WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE --EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, WILEY, CHAPTER 33.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95.4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,312)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF POWER FUNCTION ',   &
             'RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
  311 FORMAT('***** ERROR IN POWER FUNCTION RANDOM NUMBERS.')
  312 FORMAT('      THE VALUE OF THE SHAPE PARAMETER IS NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!     THEN GENERATE 2 ADDITIONAL UNIFORM (0,1) RANDOM NUMBERS
!     (TO BE USED BELOW IN FORMING THE N-TH NORMAL
!     RANDOM NUMBER WHEN THE DESIRED SAMPLE SIZE N
!     HAPPENS TO BE ODD).
!
      CALL UNIRAN(N,ISEED,X)
!
!     POWER FUNCTION RANDOM NUMBERS = (UNIFORM)**(1/C)
!
      DC=DBLE(C)
      DO 200 I=1,N
        DX=DBLE(X(I))
        DTEMP=DX**(1.0D0/DC)
        X(I)=REAL(DTEMP)
  200 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE POWRAN
      SUBROUTINE POWPPF(P,C,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE POWER FUNCTION
!              DISTRIBUTION FROM 0 TO 1
!     NOTE--THE STANDARD POWER FUNCTION PPF IS:
!
!              G(P;C) = P**(1/C)    0 <= P <= 1, C > 0
!
!           WITH C DENOTING THE SHAPE PARAMETER.
!     REFERENCE --EVANS, HASTINGS, AND PEACOCK (2000), "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, WILEY, CHAPTER 33.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --C      = THE SINGLE PRECISION VALUE OF THE SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95.4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --DECEMBER  2007. RECODED
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DC
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR IN POWPPF--THE FIRST ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (0,1).')
  311 FORMAT('***** ERROR IN POWPPF--THE SECOND ARGUMENT IS ',   &
             'NON-POSITIVE.')
  302 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
      ELSEIF(P.EQ.1.0)THEN
        PPF=1.0
      ELSE
        DP=DBLE(P)
        DC=DBLE(C)
        DPPF=DP**(1.0D0/DC)
        PPF=REAL(DPPF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE POWPPF
      REAL FUNCTION PPND(P, IFAULT)
!
!  ALGORITHM AS 111  APPL. STATIST. (1977), VOL.26, NO.1
!
!  PRODUCES NORMAL DEVIATE CORRESPONDING TO LOWER TAIL AREA OF P
!  REAL VERSION FOR EPS = 2 **(-31)
!  THE HASH SUMS ARE THE SUMS OF THE MODULI OF THE COEFFICIENTS
!  THEY HAVE NO INHERENT MEANINGS BUT ARE INCLUDED FOR USE IN
!  CHECKING TRANSCRIPTIONS
!  STANDARD FUNCTIONS ABS, LOG AND SQRT ARE USED
!
!  NOTE: WE COULD USE DATAPLOT NORPPF, BUT VARIOUS APPLIED
!        STATISTICS ALGORITHMS USE THIS.  SO WE PROVIDE IT TO
!        MAKE USE OF APPLIED STATISTICS ALGORITHMS EASIER.
!
      REAL ZERO, SPLIT, HALF, ONE
      REAL A0, A1, A2, A3, B1, B2, B3, B4, C0, C1, C2, C3, D1, D2
      REAL P, Q, R
      INTEGER IFAULT
      DATA ZERO /0.0E0/, HALF/0.5E0/, ONE/1.0E0/
      DATA SPLIT /0.42E0/
      DATA A0 / 2.50662823884E0/
      DATA A1 / -18.61500062529E0/
      DATA A2 / 41.39119773534E0/
      DATA A3 / -25.44106049637E0/
      DATA B1 / -8.47351093090E0/
      DATA B2 / 23.08336743743E0/
      DATA B3 / -21.06224101826E0/
      DATA B4 / 3.13082909833E0/
      DATA C0 / -2.78718931138E0/
      DATA C1 / -2.29796479134E0/
      DATA C2 / 4.85014127135E0/
      DATA C3 / 2.32121276858E0/
      DATA D1 / 3.54388924762E0/
      DATA D2 / 1.63706781897E0/
!
      IFAULT = 0
      Q = P - HALF
      IF (ABS(Q) .GT. SPLIT) GO TO  1
      R = Q*Q
      PPND = Q * (((A3*R + A2)*R + A1) * R + A0) /   &
        ((((B4*R + B3)*R + B2) * R + B1) * R + ONE)
      RETURN
1     R = P
      IF (Q .GT. ZERO)R = ONE - P
      IF (R .LE. ZERO) GO TO  2
      R = SQRT(-LOG(R))
      PPND = (((C3 * R + C2) * R + C1) * R + C0)/   &
        ((D2*R + D1) * R + ONE)
      IF (Q .LT. ZERO) PPND = -PPND
      RETURN
2     IFAULT = 1
      PPND = ZERO
      RETURN
      END FUNCTION PPND
      SUBROUTINE PPV(X,Y,N,IWRITE,XIDTEM,STAT,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE TRUE PREDICTIVE VALUE
!              BETWEEN TWO VARIABLES.
!
!              THIS IS SPECIFICALLY FOR THE 2X2 CASE.  THAT IS,
!              EACH VARIABLE HAS TWO MUTUALLY EXCLUSIVE
!              CHOICES CODED AS 1 (FOR SUCCESS) OR 0 (FOR
!              FAILURE).  TRUE PREDICTIVE VALUE IS DEFINED AS THE
!              CONDITIONAL PROBABILITY OF A POSITIVE TEST GiVEN
!              THAT THE DISEASE IS PRESENT.
!
!              A TYPICAL EXAMPLE WOULD BE WHERE VARIABLE ONE
!              DENOTES THE GROUND TRUTH AND A VALUE OF 1
!              INDICATES "PRESENT" AND A VALUE OF 0 INDICATES
!              "NOT PRESENT".  VARIABLE TWO REPRESENTS SOME TYPE
!              OF DETECTION DEVICE WHERE A VALUE OF 1 INDICATES
!              THE DEVICE DETECTED THE SPECIFIED OBJECT WHILE A
!              VALUE OF 0 INDICATES THAT THE OBJECT WAS NOT
!              DETECTED.  TRUE PREDICTIVE VALUE IS THEN DEFINED AS
!              (TRUE POSITIVE)/(TRUE POSITIVE + FALSE POSIIVE).
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED TRUE PREDICTIVE VALUE
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE TRUE PREDICTIVE VALUE BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PPV '
      ISUBN2='    '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PPV--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE TRUE PREDICTIVE VALUE')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        STAT=AN11/(AN11+AN21)
        GO TO 3000
      ENDIF
!
 1349 CONTINUE
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2202 I=1,N
          X(I)=1.0
 2202   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2203 I=1,N
            IF(X(I).NE.1.0)X(I)=0.0
 2203     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2208 I=1,N
            IF(X(I).EQ.ATEMP1)X(I)=0.0
            IF(X(I).EQ.ATEMP2)X(I)=1.0
 2208     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2211)
 2211   FORMAT('      RESPONSE VARIABLE ONE SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2213)
 2213   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2215)NDIST
 2215   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL DISTIN(Y,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,N
          Y(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,N
            IF(Y(I).NE.1.0)Y(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,N
            IF(Y(I).EQ.ATEMP1)Y(I)=0.0
            IF(Y(I).EQ.ATEMP2)Y(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2311)
 2311   FORMAT('      RESPONSE VARIABLE TWO SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2313)
 2313   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2315)NDIST
 2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      N11=0
      N12=0
      N21=0
      N22=0
      DO 2410 I=1,N
        IF(X(I).EQ.1.0 .AND. Y(I).EQ.1.0)THEN
          N11=N11+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.0.0)THEN
          N22=N22+1
        ELSEIF(X(I).EQ.1.0 .AND. Y(I).EQ.0.0)THEN
          N12=N12+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.1.0)THEN
          N21=N21+1
        ENDIF
 2410 CONTINUE
!
      STAT=REAL(N11)/REAL(N11+N21)
!
 3000 CONTINUE
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE TRUE PREDICTIVE VALUE PROPORTION = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF PPV--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PPV
      SUBROUTINE PRCOMP(AMAT,NR1,NC1,PCCASE,   &
                        DMEAN,COV,EVECT,EVAL,TEMP1,TEMP3,TEMP4,   &
                        PC1,PC2,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE RETURNS THE FIRST TWO PRINCIPAL
!              COMPONENTS OF A MATRIX.  MULTIVARIATE ANALYSES
!              SOMETIMES PLOT RESULTS BASED ON THE FIRST TWO
!              PRINCIPAL COMPONENTS.  THIS IS A UTILITY ROUTINE
!              TO RETURN THE FIRST TWO PRINCIPAL COMPONENTS.
!     INPUT  ARGUMENTS--AMAT   = THE SINGLE PRECISION MATRIX
!                     --NR1    = THE INTEGER NUMBER OF ROWS OF AMAT
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS OF AMAT
!     OUTPUT ARGUMENTS--PC1    = THE SINGLE PRECISION OUTPUT VECTOR
!                                CONTAINING THE FIRST PRINCIPAL COMPONENT
!                     --PC2    = THE SINGLE PRECISION OUTPUT VECTOR
!                                CONTAINING THE SECOND PRINCIPAL COMPONENT
!     OUTPUT--THE COMPUTED FIRST AND SECOND PRINCIPAL COMPONENT VECTORSS
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SSIEV.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2024.07
!     ORIGINAL VERSION--JULY      2024.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 PCCASE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION AMAT(NR1,NC1)
      DIMENSION EVAL(*)
      DIMENSION PC1(*)
      DIMENSION PC2(*)
      DIMENSION DMEAN(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION COV(NC1,NC1)
      DIMENSION EVECT(NC1,NC1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PRCO'
      ISUBN2='MP  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PRCOMP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,NR1,NC1
   52   FORMAT('IBUGA3,ISUBRO = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NR1
          DO 59 J=1,NC1
            WRITE(ICOUT,56)I,J,AMAT(I,J)
   56       FORMAT('I,J,AMAT(I) = ',2I8,G15.7)
            CALL DPWRST('XXX','BUG ')
   59     CONTINUE
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1: COMPUTE THE COVARIANCE MATRIX **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 101 J=1,NC1
        SUM1=0.0
        DO 102 I=1,NR1
          YM1=AMAT(I,J)
          SUM1=SUM1+YM1
  102   CONTINUE
        DMEAN(J)=CPUMIN
        DENOM=REAL(NR1)
        IF(DENOM.NE.0.0)DMEAN(J)=SUM1/DENOM
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')THEN
          WRITE(ICOUT,103)J,DMEAN(J)
  103     FORMAT('J,DMEAN(J) = ',I6,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
  101 CONTINUE
!
      DO 121 J=1,NC1
        DO 122 K=J,NC1
          SUM1=0.0
          DO 123 I=1,NR1
            YM1=AMAT(I,J)
            YM2=AMAT(I,K)
            DEL1=YM1-DMEAN(J)
            DEL2=YM2-DMEAN(K)
            SUM1=SUM1+DEL1*DEL2
  123     CONTINUE
          DCOV=CPUMIN
          DENOM=REAL(NR1)-1.0
          IF(DENOM.NE.0.0)DCOV=SUM1/DENOM
          COV(J,K)=DCOV
          COV(K,J)=COV(J,K)
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')THEN
            WRITE(ICOUT,128)J,K,COV(J,K)
  128       FORMAT('J,K,COV(J,K) = ',2I6,G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
  122   CONTINUE
  121 CONTINUE
!
!     USE CORRELATION MATRIX IF REQUESTED
!
      ISTEPN='1A'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(PCCASE.EQ.'DACR')THEN
        DO 141 I=1,NC1
          S1=SQRT(COV(I,I))
          DO 142 J=1,NC1
            S2=SQRT(COV(J,J))
            IF(I.NE.J)THEN
              S1S2=S1*S2
              IF(S1S2.LE.0.0)COV(I,J)=-999.99
              IF(S1S2.GT.0.0)COV(I,J)=COV(I,J)/S1S2
            ENDIF
  142     CONTINUE
  141   CONTINUE
        DO 143 I=1,NC1
          COV(I,I)=1.0
  143   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')THEN
        WRITE(ICOUT,131)
  131   FORMAT('COVARIANCE MATRIX:')
        CALL DPWRST('XXX','BUG ')
        DO 135 II=1,NC1
          DO 138 JJ=1,NC1
            WRITE(ICOUT,137)II,JJ,COV(II,JJ)
  137       FORMAT('II,JJ,COV(II,JJ) = ',2I6,G15.7)
            CALL DPWRST('XXX','BUG ')
  138     CONTINUE
  135   CONTINUE
      ENDIF
!
!               ***************************************************
!               **  STEP 2: COMPUTE THE EIGENVECTORS/EIGENVALUES **
!               ***************************************************
!
!     USE EISPACK ROUTINES (NOTE THAT CORRELATION OR COVARIANCE MATRIX
!     IS SYMMETRIC).
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERR2=0
      IJOB=1
      DO 250 J=1,NC1
        DO 251 I=1,NC1
          EVECT(I,J)=COV(I,J)
  251   CONTINUE
  250 CONTINUE
      CALL SSIEV(EVECT,NR1,NC1,EVAL,TEMP1,IJOB,IERR2)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')THEN
        DO 256 I=1,NC1
          DO 257 J=1,NC1
            WRITE(ICOUT,258)I,J,EVECT(J,K)
  258       FORMAT('I,J,EVECT(J,K) = ',2I6,G15.7)
            CALL DPWRST('XXX','BUG ')
  257     CONTINUE
  256   CONTINUE
      ENDIF
!
      IF(IERR2.NE.0)THEN
        IERROR='YES'
        WRITE(ICOUT,261)
  261   FORMAT('******** ERROR FROM PRINCIPAL COMPONENTS (PRCOMP)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,262)
  262   FORMAT('         UNABLE TO CALCULATE THE EIGENVALUES OF THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,263)
        CALL DPWRST('XXX','BUG ')
  263   FORMAT('         COVARIANCE (OR CORRELATION) MATRIX.')
        IERROR='YES'
        GO TO 9000
      END IF
!
      ISTEPN='2A'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     SORT THE EIGENVALUES IN DESCENDING ORDER
!
      DO 280 I=1,NC1
        TEMP1(I)=I
  280 CONTINUE
!
      CALL SORTC(EVAL,TEMP1,NC1,TEMP3,TEMP4)
!
      DO 290 J=1,NC1
        JREV=NC1-J+1
        INDEX3=INT(TEMP4(JREV)+0.5)
        EVAL(J)=TEMP3(INDEX3)
  290 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')THEN
        WRITE(ICOUT,293)
  293   FORMAT('SORTED EIGENVALUES')
        CALL DPWRST('XXX','BUG ')
        DO 294 I=1,NC1
          WRITE(ICOUT,295)I,EVAL(I)
  295     FORMAT('I,EVAL(I) = ',I6,G15.7)
          CALL DPWRST('XXX','BUG ')
  294   CONTINUE
      ENDIF
!
!     NOW SORT THE EIGENVECTOR MATRIX IN THE SAME ORDER
!
      DO 291 J=1,NC1
        JREV=NC1-J+1
        INDEX3=INT(TEMP4(JREV)+0.5)
        DO 292 I=1,NC1
          COV(I,J)=EVECT(I,INDEX3)
  292   CONTINUE
  291 CONTINUE
!
      DO 296 I=1,NC1
        DO 297 J=1,NC1
          EVECT(I,J)=COV(I,J)
  297   CONTINUE
  296 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')THEN
        WRITE(ICOUT,301)
  301   FORMAT('SORTED EIGENVECTORS')
        CALL DPWRST('XXX','BUG ')
        DO 302 I=1,NC1
          DO 303 J=1,NC1
            WRITE(ICOUT,258)I,J,EVECT(J,K)
            CALL DPWRST('XXX','BUG ')
  303     CONTINUE
  302   CONTINUE
      ENDIF
!
!               ***************************************************
!               **  STEP 3: COMPUTE THE PRINCIPAL COMPONENTS     **
!               ***************************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 311 I=1,NR1
        DSUM1=0.0
        DSUM2=0.0
        DO 313 K=1,NC1
          DYM1=AMAT(I,K)
          DDEL=DYM1-DMEAN(K)
!
          DYM2=EVECT(K,1)
          DYM9=DDEL*DYM2
          DSUM1=DSUM1+DYM9
!
          DYM2=EVECT(K,2)
          DYM9=DDEL*DYM2
          DSUM2=DSUM2+DYM9
!
  313   CONTINUE
        PC1(I)=DSUM1
        PC2(I)=DSUM2
  311 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COMP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF PRCOMP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 II=1,NR1
          WRITE(ICOUT,9022)II,PC1(II),PC2(II)
 9022     FORMAT('II,PC1(II),PC2(II) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE PRCOMP
      SUBROUTINE PRIMES(N,X,IERROR)
!
!     PURPOSE--THIS SUBROUTINE GENERATES THE FIRST N PRIME NUMBERS--
!              2, 3, 5, 7, 11, ...
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF PRIME NUMBERS
!                                TO BE GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                PRIME NUMBERS
!                                WILL BE PLACED.
!     OUTPUT--THE FIRST N PRIME NUMBERS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87.10
!     ORIGINAL VERSION--SEPTEMBER 1987.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ******************************************
!               **  TREAT THE PRIMES NUMBERS CASE       **
!               ******************************************
!
!               *******************************************
!               **  STEP 1--                             **
!               **  TEST THE INPUT ARGUMENTS FOR ERRORS  **
!               *******************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN GENMS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
  102   FORMAT('      THE LENGTH OF THE DESIRED SEQUENCE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      OF PRIME NUMBERS MUST BE 1 OR LARGER;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)
  104   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)N
  105   FORMAT('      N = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************
!               **  STEP 2--                **
!               **  GENERATE THE SEQUENCE   **
!               ******************************
!
      X(1)=2
      X(2)=3
      X(3)=5
!
      NP=3
      DO 1100 I=7,100000,2
        ANP=NP
        JMAX=INT(SQRT(ANP)+1.5)
!
        DO 1200 J=2,JMAX
          IXJ=INT(X(J)+0.5)
          K=MOD(I,IXJ)
          IF(K.EQ.0)GO TO 1100
 1200   CONTINUE
!
        NP=NP+1
        X(NP)=I
        IF(NP.GE.N)GO TO 1190
!
 1100 CONTINUE
 1190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE PRIMES
      SUBROUTINE PROD(X,N,IWRITE,XPROD,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE PRODUCT
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE PRODUCT = PRODUCT OF ALL OBSERVATIONS IN X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XPROD   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE PRODUCT.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE PRODUCT.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       2008. SAMPLE SIZE = 1 AND ALL
!                                       RESPONSE VALUES EQUAL SHOULD
!                                       NOT BE CONSIDERED AN ERROR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPROD
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PROD'
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF PROD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ***********************
!               **  COMPUTE PRODUCT  **
!               ***********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN PROD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE PRODUCT IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
!CCCC  IF(N.EQ.1)GO TO 120
!CCCC  GO TO 129
!C120 CONTINUE
!CCCC  WRITE(ICOUT,999)
!CCCC  CALL DPWRST('XXX','BUG ')
!CCCC  WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN PROD--',
!CCCC 1'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
!CCCC  CALL DPWRST('XXX','BUG ')
!CCCC  XPROD=X(1)
!CCCC  GO TO 9000
!C129 CONTINUE
!
!CCCC  HOLD=X(1)
!CCCC  DO135I=2,N
!CCCC  IF(X(I).NE.HOLD)GO TO 139
!C135 CONTINUE
!CCCC  WRITE(ICOUT,999)
!CCCC  CALL DPWRST('XXX','BUG ')
!CCCC  WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN PROD--',
!CCCC 1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC  CALL DPWRST('XXX','BUG ')
!CCCC  XPROD=HOLD**N
!CCCC  GO TO 9000
!C139 CONTINUE
!
!               ****************************
!               **  STEP 2--              **
!               **  COMPUTE THE PRODUCT.  **
!               ****************************
!
      DPROD=1.0D0
      DO 200 I=1,N
      DX=X(I)
      DPROD=DPROD*DX
  200 CONTINUE
      XPROD=DPROD
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XPROD
  811 FORMAT('THE PRODUCT OF THE ',I8,' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF PROD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XPROD
 9015 FORMAT('XPROD = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE PROD
      SUBROUTINE PROP(X,N,ANOPL1,ANOPL2,IWRITE,XPROP,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              PROPORTION (0 TO 100%) OF DATA
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ANOPL1 = UPPER (ENGINEERING) SPEC LIMIT
!                     --ANOPL2 = LOWER (ENGINEERING) SPEC LIMIT
!     OUTPUT ARGUMENTS--PROP = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE EXPECTED LOSS
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE EXPECTED LOSS (IN XPROP)
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89.5
!     ORIGINAL VERSION--MAY       1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PROP'
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF PROP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)ANOPL1,ANOPL2
   54 FORMAT('ANOPL1,ANOPL2 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  COMPUTE THE PROPORTION STATISTIC      **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN PROP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE PROPORTION IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN PROP--',
!CCCC1'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
!CCCC CALL DPWRST('XXX','BUG ')
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN PROP--',
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      GO TO 9000
  139 CONTINUE
!
!               *******************************
!               **  STEP 2--                 **
!               **  COMPUTE THE PROPORTION.  **
!               *******************************
!
      ANOPL3=ANOPL1
      IF(ANOPL1.GT.ANOPL2)ANOPL3=ANOPL2
!
      ANOPL4=ANOPL2
      IF(ANOPL1.GT.ANOPL2)ANOPL4=ANOPL1
!
      XPROP=0.0
      ICOUNT=0
      DO 200 I=1,N
      IF(ANOPL3.LE.X(I).AND.X(I).LE.ANOPL4)ICOUNT=ICOUNT+1
  200 CONTINUE
      COUNT=ICOUNT
!
      P=COUNT/AN
      XPROP=100.0*P
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XPROP
  811 FORMAT('THE PROPORTION OF THE ',I8,' OBSERVATIONS = ',   &
      E15.7,' %')
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF PROP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)ANOPL1,ANOPL2
 9015 FORMAT('ANOPL1,ANOPL2 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)ANOPL3,ANOPL4
 9016 FORMAT('ANOPL3,ANOPL4 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)N,ICOUNT,AN,COUNT
 9017 FORMAT('N,ICOUNT,AN,COUNT = ',2I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9018)P,XPROP
 9018 FORMAT('P,XPROP = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE PROP
      double precision function prtrng(q, v, r, ifault)
      implicit double precision (a-h, o-z)
!
!        Algorithm AS 190  Appl. Statist. (1983) Vol.32, No. 2
!       Incorporates corrections from Appl. Statist. (1985) Vol.34 (1)
!
!        Evaluates the probability from 0 to q for a studentized
!        range having v degrees of freedom and r samples.
!
!        Uses subroutine ALNORM = algorithm AS66.
!
!        Arrays vw and qw store transient values used in the
!        quadrature summation.  Node spacing is controlled by
!        step.  pcutj and pcutk control truncation.
!        Minimum and maximum number of steps are controlled by
!        jmin, jmax, kmin and kmax.  Accuracy can be increased
!        by use of a finer grid - Increase sizes of arrays vw
!        and qw, and jmin, jmax, kmin, kmax and 1/step proportionally.
!
      double precision q,v,r,vw(30), qw(30), pcutj, pcutk, step,   &
          vmax,zero,fifth,half,one,two,cv1,cv2,cvmax,cv(4)
      double precision g, gmid, r1, c, h, v2, gstep, pk1, pk2, gk, pk
      double precision w0, pz, x, hj, ehj, pj
      double precision alnorm
      external alnorm
      data pcutj, pcutk, step, vmax /0.00003d0, 0.0001d0, 0.45d0,   &
         120.0d0/, zero, fifth, half, one, two /0.0d0, 0.2d0, 0.5d0,   &
         1.0d0, 2.0d0/, cv1, cv2, cvmax /0.193064705d0, 0.293525326d0,   &
         0.39894228d0/, cv(1), cv(2), cv(3), cv(4) /0.318309886d0,   &
         -0.268132716d-2, 0.347222222d-2, 0.833333333d-1/
      data jmin, jmax, kmin, kmax/3, 15, 7, 15/
!
!        Check initial values
!
      h=0.0d0
      prtrng = zero
      ifault = 0
      if (v .lt. one .or. r .lt. two) ifault = 1
      if (q .le. zero .or. ifault .eq. 1) go to 99
!
!        Computing constants, local midpoint, adjusting steps.
!
      g = step * r ** (-fifth)
      gmid = half * log(r)
      r1 = r - one
      c = log(r * g * cvmax)
      if(v.gt.vmax) go to 20
!
      h = step * v ** (-half)
      v2 = v * half
      if (v .eq. one) c = cv1
      if (v .eq. two) c = cv2
      if (.not. (v .eq. one .or. v .eq. two)) c = sqrt(v2)   &
          * cv(1) / (one + ((cv(2) / v2 + cv(3)) / v2 + cv(4)) / v2)
      c = log(c * r * g * h)
!
!        Computing integral
!        Given a row k, the procedure starts at the midpoint and works
!        outward (index j) in calculating the probability at nodes
!        symmetric about the midpoint.  The rows (index k) are also
!        processed outwards symmetrically about the midpoint.  The
!        centre row is unpaired.
!
   20 gstep = g
      qw(1) = -one
      qw(jmax + 1) = -one
      pk1 = one
      pk2 = one
      do 28 k = 1, kmax
      gstep = gstep - g
   21   gstep = -gstep
      gk = gmid + gstep
      pk = zero
      if (pk2 .le. pcutk .and. k .gt. kmin) go to 26
      w0 = c - gk * gk * half
        pz = alnorm(gk, .true.)
        x = alnorm(gk - q, .true.) - pz
      if (x .gt. zero) pk = exp(w0 + r1 * log(x))
      if (v .gt. vmax) go to 26
!
      jump = -jmax
   22   jump = jump + jmax
      do 24 j = 1, jmax
        jj = j + jump
        if (qw(jj) .gt. zero) go to 23
        hj = h * j
        if (j .lt. jmax) qw(jj + 1) = -one
        ehj = exp(hj)
        qw(jj) = q * ehj
        vw(jj) = v * (hj + half - ehj * ehj * half)
!
   23     pj = zero
          x = alnorm(gk - qw(jj), .true.) - pz
        if (x .gt. zero) pj = exp(w0 + vw(jj) + r1 * log(x))
        pk = pk + pj
        if (pj .gt. pcutj) go to 24
        if (jj .gt. jmin .or. k .gt. kmin) go to 25
   24   continue
   25   h = -h
      if (h .lt. zero) go to 22
!
   26   prtrng = prtrng + pk
      if (k .gt. kmin .and. pk .le. pcutk .and. pk1 .le. pcutk)go to 99
      pk2 = pk1
      pk1 = pk
      if (gstep .gt. zero) go to 21
   28 continue
!
   99 return
      end
      SUBROUTINE PSCORE(X,N1,Y,N2,IWRITE,XSCORE,YSCORE,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PLACEMENT SCORES
!              OF THE N1 ELEMENTS OF THE SINGLE PRECISION VECTOR X AND
!              THE N2 ELEMENTS OF THE SINGLE PRECISION VECTOR Y, AND
!              PUTS THE RESULTING SCORES INTO THE SINGLE PRECISION
!              VECTORS XSCORE AND YSCORE.  THESE ARE USED TO COMPUTE
!              THE FLIGNER-POLICELLO TWO SAMPLE LOCATION TEST.
!
!              THE PLACEMENT SCORE FOR X(i) IS DEFINED AS THE NUMBER
!              OF OBSERVATIONS IN Y THAT ARE LESS THAN X(i).  VALUES
!              IN Y THAT ARE EQUAL TO X(i) ADD (1/2) RATHER THAN 1.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SCORED.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SCORED.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XSCORE = THE SINGLE PRECISION VECTOR INTO WHICH
!                                THE SCORES FROM X WILL BE PLACED.
!                     --YSCORE = THE SINGLE PRECISION VECTOR INTO WHICH
!                                THE SCORES FROM Y WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTORS XSCORE AND YSCORE CONTAINING
!             THE PLACEMENT SCORES.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--ORBAN AND WOLFE (1979), "A CLASS OF DISTRIBUTION-FREE
!                 TWO-SAMPLE TESTS BASED ON PLACEMENTS," TECHNICAL
!                 REPORT 178, DEPARTMENT OF STATISTICS, OHIO STATE
!                 UNIVERSITY.
!               --FLIGNER AND POLICELLO (1981), "ROBUST RANK
!                 PROCEDURES FOR THE BEHRENS-FISHER PROBLEM," JOURNAL
!                 OF THE AMERICAN STATISTICAL ASSOCIATION, VOL. 76,
!                 PP. 162-168.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023.07
!     ORIGINAL VERSION--JULY      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XSCORE(*)
      DIMENSION YSCORE(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='PSCO'
      ISUBN2='RE  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N1,N2,IBUGA3,ISUBRO
   53   FORMAT('N1,N2,IBUGA3,ISUBRO = ',2I8,(2X,A4))
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,Y(I)
   66     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N1.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN PLACEMENT SCORES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N1
  118   FORMAT('      THE NUMBER OF OBSERVATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N2.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  GENERATE THE PLACEMENT   SCORES       **
!               **  FOR THE FIRST RESPONSE VARIABLE.      **
!               ********************************************
!
        DO 211 I=1,N1
          SUM=0.0
          DO 213 J=1,N2
            IF(Y(J).LT.X(I))THEN
              SUM=SUM + 1.0
            ELSEIF(Y(J).EQ.X(I))THEN
              SUM=SUM + 0.5
            ENDIF
  213     CONTINUE
          XSCORE(I)=SUM
  211   CONTINUE
!
!               ********************************************
!               **  STEP 3--                              **
!               **  GENERATE THE PLACEMENT   SCORES       **
!               **  FOR THE SECOND RESPONSE VARIABLE.     **
!               ********************************************
!
        DO 311 I=1,N2
          SUM=0.0
          DO 313 J=1,N1
            IF(X(J).LT.Y(I))THEN
              SUM=SUM + 1.0
            ELSEIF(X(J).EQ.Y(I))THEN
              SUM=SUM + 0.5
            ENDIF
  313     CONTINUE
          YSCORE(I)=SUM
  311   CONTINUE
!
!               ******************************
!               **  STEP 4--                **
!               **  WRITE OUT A FEW LINES   **
!               **  OF SUMMARY INFORMATION  **
!               **  ABOUT THE CODING.       **
!               ******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IINDX=1
        WRITE(ICOUT,912)IINDX,XSCORE(IINDX)
  912   FORMAT('THE PLACEMENT SCORE OF ROW ',I10,   &
               ' FOR THE FIRST RESPONE VARIABLE = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,922)IINDX,YSCORE(IINDX)
  922   FORMAT('THE PLACEMENT SCORE OF ROW ',I10,   &
               ' FOR THE SECOND RESPONE VARIABLE = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IINDX=N1
        WRITE(ICOUT,912)IINDX,XSCORE(IINDX)
        CALL DPWRST('XXX','BUG ')
        IINDX=N2
        WRITE(ICOUT,922)IINDX,YSCORE(IINDX)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF PSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N1
          WRITE(ICOUT,9016)I,X(I),XSCORE(I)
 9016     FORMAT('I,X(I),XSCORE(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        DO 9025 I=1,N2
          WRITE(ICOUT,9026)I,Y(I),YSCORE(I)
 9026     FORMAT('I,Y(I),YSCORE(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9025   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE PSCORE
      DOUBLE PRECISION FUNCTION psi(xx)
!---------------------------------------------------------------------
!
!                 EVALUATION OF THE DIGAMMA FUNCTION
!
!                           -----------
!
!     PSI(XX) IS ASSIGNED THE VALUE 0 WHEN THE DIGAMMA FUNCTION CANNOT
!     BE COMPUTED.
!
!     THE MAIN COMPUTATION INVOLVES EVALUATION OF RATIONAL CHEBYSHEV
!     APPROXIMATIONS PUBLISHED IN MATH. COMP. 27, 123-127(1973) BY
!     CODY, STRECOK AND THACHER.
!
!---------------------------------------------------------------------
!     PSI WAS WRITTEN AT ARGONNE NATIONAL LABORATORY FOR THE FUNPACK
!     PACKAGE OF SPECIAL FUNCTION SUBROUTINES. PSI WAS MODIFIED BY
!     A.H. MORRIS (NSWC).
!---------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION xx
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION aug,den,dx0,piov4,sgn,upper,w,x,xmax1,xmx0,   &
                       xsmall,z
      INTEGER i,m,n,nq
!     ..
!     .. Local Arrays ..
      DOUBLE PRECISION p1(7),p2(4),q1(6),q2(4)
!     ..
!     .. External Functions ..
      DOUBLE PRECISION spmpar
!CCCC INTEGER ipmpar
!CCCC EXTERNAL spmpar,ipmpar
      EXTERNAL spmpar
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,cos,dble,dlog,dmin1,int,sin
!
      INCLUDE 'DPCOMC.INC'
!
!     ..
!     .. Data statements ..
!---------------------------------------------------------------------
!
!     PIOV4 = PI/4
!     DX0 = ZERO OF PSI TO EXTENDED PRECISION
!
!---------------------------------------------------------------------
!---------------------------------------------------------------------
!
!     COEFFICIENTS FOR RATIONAL APPROXIMATION OF
!     PSI(X) / (X - X0),  0.5 .LE. X .LE. 3.0
!
!---------------------------------------------------------------------
!---------------------------------------------------------------------
!
!     COEFFICIENTS FOR RATIONAL APPROXIMATION OF
!     PSI(X) - LN(X) + 1 / (2*X),  X .GT. 3.0
!
!---------------------------------------------------------------------
      DATA piov4/.785398163397448D0/
      DATA dx0/1.461632144968362341262659542325721325D0/
      DATA p1(1)/.895385022981970D-02/,p1(2)/.477762828042627D+01/,   &
           p1(3)/.142441585084029D+03/,p1(4)/.118645200713425D+04/,   &
           p1(5)/.363351846806499D+04/,p1(6)/.413810161269013D+04/,   &
           p1(7)/.130560269827897D+04/
      DATA q1(1)/.448452573429826D+02/,q1(2)/.520752771467162D+03/,   &
           q1(3)/.221000799247830D+04/,q1(4)/.364127349079381D+04/,   &
           q1(5)/.190831076596300D+04/,q1(6)/.691091682714533D-05/
      DATA p2(1)/-.212940445131011D+01/,p2(2)/-.701677227766759D+01/,   &
           p2(3)/-.448616543918019D+01/,p2(4)/-.648157123766197D+00/
      DATA q2(1)/.322703493791143D+02/,q2(2)/.892920700481861D+02/,   &
           q2(3)/.546117738103215D+02/,q2(4)/.777788548522962D+01/
!     ..
!     .. Executable Statements ..
!---------------------------------------------------------------------
!
!     MACHINE DEPENDENT CONSTANTS ...
!
!        XMAX1  = THE SMALLEST POSITIVE FLOATING POINT CONSTANT
!                 WITH ENTIRELY INTEGER REPRESENTATION.  ALSO USED
!                 AS NEGATIVE OF LOWER BOUND ON ACCEPTABLE NEGATIVE
!                 ARGUMENTS AND AS THE POSITIVE ARGUMENT BEYOND WHICH
!                 PSI MAY BE REPRESENTED AS ALOG(X).
!
!        XSMALL = ABSOLUTE ARGUMENT BELOW WHICH PI*COTAN(PI*X)
!                 MAY BE REPRESENTED BY 1/X.
!
!---------------------------------------------------------------------
!CCCC xmax1 = ipmpar(3)
      xmax1 = i1mach(9)
      xmax1 = dmin1(xmax1,1.0D0/spmpar(1))
      xsmall = 1.D-9
!---------------------------------------------------------------------
      x = xx
      aug = 0.0D0
      IF (x.GE.0.5D0) GO TO 50
!---------------------------------------------------------------------
!     X .LT. 0.5,  USE REFLECTION FORMULA
!     PSI(1-X) = PSI(X) + PI * COTAN(PI*X)
!---------------------------------------------------------------------
      IF (abs(x).GT.xsmall) GO TO 10
      IF (x.EQ.0.0D0) GO TO 100
!---------------------------------------------------------------------
!     0 .LT. ABS(X) .LE. XSMALL.  USE 1/X AS A SUBSTITUTE
!     FOR  PI*COTAN(PI*X)
!---------------------------------------------------------------------
      aug = -1.0D0/x
      GO TO 40
!---------------------------------------------------------------------
!     REDUCTION OF ARGUMENT FOR COTAN
!---------------------------------------------------------------------
   10 w = -x
      sgn = piov4
      IF (w.GT.0.0D0) GO TO 20
      w = -w
      sgn = -sgn
!---------------------------------------------------------------------
!     MAKE AN ERROR EXIT IF X .LE. -XMAX1
!---------------------------------------------------------------------
   20 IF (w.GE.xmax1) GO TO 100
      nq = int(w)
      w = w - dble(nq)
      nq = int(w*4.0D0)
      w = 4.0D0* (w-dble(nq)*.25D0)
!---------------------------------------------------------------------
!     W IS NOW RELATED TO THE FRACTIONAL PART OF  4.0 * X.
!     ADJUST ARGUMENT TO CORRESPOND TO VALUES IN FIRST
!     QUADRANT AND DETERMINE SIGN
!---------------------------------------------------------------------
      n = nq/2
      IF ((n+n).NE.nq) w = 1.0D0 - w
      z = piov4*w
      m = n/2
      IF ((m+m).NE.n) sgn = -sgn
!---------------------------------------------------------------------
!     DETERMINE FINAL VALUE FOR  -PI*COTAN(PI*X)
!---------------------------------------------------------------------
      n = (nq+1)/2
      m = n/2
      m = m + m
      IF (m.NE.n) GO TO 30
!---------------------------------------------------------------------
!     CHECK FOR SINGULARITY
!---------------------------------------------------------------------
      IF (z.EQ.0.0D0) GO TO 100
!---------------------------------------------------------------------
!     USE COS/SIN AS A SUBSTITUTE FOR COTAN, AND
!     SIN/COS AS A SUBSTITUTE FOR TAN
!---------------------------------------------------------------------
      aug = sgn* ((cos(z)/sin(z))*4.0D0)
      GO TO 40
                                                                                                                                  
   30 aug = sgn* ((sin(z)/cos(z))*4.0D0)
   40 x = 1.0D0 - x
   50 IF (x.GT.3.0D0) GO TO 70
!---------------------------------------------------------------------
!     0.5 .LE. X .LE. 3.0
!---------------------------------------------------------------------
      den = x
      upper = p1(1)*x
!
      DO 60 i = 1,5
          den = (den+q1(i))*x
          upper = (upper+p1(i+1))*x
   60 CONTINUE
!
      den = (upper+p1(7))/ (den+q1(6))
      xmx0 = dble(x) - dx0
      psi = den*xmx0 + aug
      RETURN
!---------------------------------------------------------------------
!     IF X .GE. XMAX1, PSI = LN(X)
!---------------------------------------------------------------------
   70 IF (x.GE.xmax1) GO TO 90
!---------------------------------------------------------------------
!     3.0 .LT. X .LT. XMAX1
!---------------------------------------------------------------------
      w = 1.0D0/ (x*x)
      den = w
      upper = p2(1)*w
!
      DO 80 i = 1,3
          den = (den+q2(i))*w
          upper = (upper+p2(i+1))*w
   80 CONTINUE
!
      aug = upper/ (den+q2(4)) - 0.5D0/x + aug
   90 psi = aug + dlog(x)
      RETURN
!---------------------------------------------------------------------
!     ERROR RETURN
!---------------------------------------------------------------------
  100 psi = 0.0D0
      RETURN
                                                                                                                                  
      END FUNCTION psi
      FUNCTION PSIXN (N)
!***BEGIN PROLOGUE  PSIXN
!***SUBSIDIARY
!***PURPOSE  Subsidiary to EXINT
!***LIBRARY   SLATEC
!***TYPE      SINGLE PRECISION (PSIXN-S, DPSIXN-D)
!***AUTHOR  Amos, D. E., (SNLA)
!***DESCRIPTION
!
!     This subroutine returns values of PSI(X)=derivative of log
!     GAMMA(X), X .GT. 0.0 at integer arguments. A table look-up is
!     performed for N .LE. 100, and the asymptotic expansion is
!     evaluated for N .GT. 100.
!
!***SEE ALSO  EXINT
!***ROUTINES CALLED  R1MACH
!***REVISION HISTORY  (YYMMDD)
!   800501  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900328  Added TYPE section.  (WRB)
!   910722  Updated AUTHOR section.  (ALS)
!***END PROLOGUE  PSIXN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      INTEGER N, K
      REAL             AX, B, C, FN, RFN2, TRM, S, WDTOL
      DIMENSION B(6), C(100)
!-----------------------------------------------------------------------
!             PSIXN(N), N = 1,100
!-----------------------------------------------------------------------
      DATA C(1), C(2), C(3), C(4), C(5), C(6), C(7), C(8), C(9), C(10),   &
           C(11), C(12), C(13), C(14), C(15), C(16), C(17), C(18),   &
           C(19), C(20), C(21), C(22), C(23), C(24)/   &
          -5.77215664901532861E-01,     4.22784335098467139E-01,   &
           9.22784335098467139E-01,     1.25611766843180047E+00,   &
           1.50611766843180047E+00,     1.70611766843180047E+00,   &
           1.87278433509846714E+00,     2.01564147795561000E+00,   &
           2.14064147795561000E+00,     2.25175258906672111E+00,   &
           2.35175258906672111E+00,     2.44266167997581202E+00,   &
           2.52599501330914535E+00,     2.60291809023222227E+00,   &
           2.67434666166079370E+00,     2.74101332832746037E+00,   &
           2.80351332832746037E+00,     2.86233685773922507E+00,   &
           2.91789241329478063E+00,     2.97052399224214905E+00,   &
           3.02052399224214905E+00,     3.06814303986119667E+00,   &
           3.11359758531574212E+00,     3.15707584618530734E+00/
      DATA C(25), C(26), C(27), C(28), C(29), C(30), C(31), C(32),   &
           C(33), C(34), C(35), C(36), C(37), C(38), C(39), C(40),   &
           C(41), C(42), C(43), C(44), C(45), C(46), C(47), C(48)/   &
           3.19874251285197401E+00,     3.23874251285197401E+00,   &
