           4.56954748265390877E+00,     4.57985676100442424E+00,   &
           4.59006084263707730E+00,     4.60016185273808740E+00/
!-----------------------------------------------------------------------
!             COEFFICIENTS OF ASYMPTOTIC EXPANSION
!-----------------------------------------------------------------------
      DATA B(1), B(2), B(3), B(4), B(5), B(6)/   &
           8.33333333333333333E-02,    -8.33333333333333333E-03,   &
           3.96825396825396825E-03,    -4.16666666666666666E-03,   &
           7.57575757575757576E-03,    -2.10927960927960928E-02/
!
!***FIRST EXECUTABLE STATEMENT  PSIXN
      IF (N.GT.100) GO TO 10
      PSIXN = C(N)
      RETURN
   10 CONTINUE
      WDTOL = MAX(R1MACH(4),1.0E-18)
      FN = N
      AX = 1.0E0
      S = -0.5E0/FN
      IF (ABS(S).LE.WDTOL) GO TO 30
      RFN2 = 1.0E0/(FN*FN)
      DO 20 K=1,6
        AX = AX*RFN2
        TRM = -B(K)*AX
        IF (ABS(TRM).LT.WDTOL) GO TO 30
        S = S + TRM
   20 CONTINUE
   30 CONTINUE
      PSIXN = S + LOG(FN)
      RETURN
      END FUNCTION PSIXN 
      subroutine psort(a,n,ind,ni)
!
!  This routine is part of the Bill Cleveland seasonal loess
!  program.
!
      real a(n)
      integer n,ind(ni),ni
      integer indu(16),indl(16),iu(16),il(16),p,jl,ju,i,j,m,k,ij,l
      real t,tt
      if(.not.(n .lt. 0 .or. ni .lt. 0))go to 23157
      return
23157 continue
      if(.not.(n .lt. 2  .or.  ni .eq. 0))go to 23159
      return
23159 continue
      jl = 1
      ju = ni
      indl(1) = 1
      indu(1) = ni
      i = 1
      j = n
      m = 1
23161 continue
      if(.not.(i .lt. j))go to 23164
      go to 10
23164 continue
23166 continue
      m = m-1
      if(.not.(m .eq. 0))go to 23169
      go to 23163
23169 continue
      i = il(m)
      j = iu(m)
      jl = indl(m)
      ju = indu(m)
      if(.not.(jl .le. ju))go to 23171
23173 if(.not.(j-i .gt. 10))go to 23174
10    k = i
      ij = (i+j)/2
      t = a(ij)
      if(.not.(a(i) .gt. t))go to 23175
      a(ij) = a(i)
      a(i) = t
      t = a(ij)
23175 continue
      l = j
      if(.not.(a(j) .lt. t))go to 23177
      a(ij) = a(j)
      a(j) = t
      t = a(ij)
      if(.not.(a(i) .gt. t))go to 23179
      a(ij) = a(i)
      a(i) = t
      t = a(ij)
23179 continue
23177 continue
23181 continue
      l = l-1
      if(.not.(a(l) .le. t))go to 23184
      tt = a(l)
23186 continue
      k = k+1
      if(.not.(a(k) .ge. t))go to 23186
      if(.not.(k .gt. l))go to 23189
      go to 23183
23189 continue
      a(l) = a(k)
      a(k) = tt
23184 continue
      go to 23181
23183 continue
      indl(m) = jl
      indu(m) = ju
      p = m
      m = m+1
      if(.not.(l-i .le. j-k))go to 23191
      il(p) = k
      iu(p) = j
      j = l
23193 continue
      if(.not.(jl .gt. ju))go to 23196
      go to 23167
23196 continue
      if(.not.(ind(ju) .le. j))go to 23198
      go to 23195
23198 continue
      ju = ju-1
      go to 23193
23195 continue
      indl(p) = ju+1
      go to 23192
23191 continue
      il(p) = i
      iu(p) = l
      i = k
23200 continue
      if(.not.(jl .gt. ju))go to 23203
      go to 23167
23203 continue
      if(.not.(ind(jl) .ge. i))go to 23205
      go to 23202
23205 continue
      jl = jl+1
      go to 23200
23202 continue
      indu(p) = jl-1
23192 continue
      go to 23173
23174 continue
      if(.not.(i .eq. 1))go to 23207
      go to 23168
23207 continue
      i = i-1
23209 continue
      i = i+1
      if(.not.(i .eq. j))go to 23212
      go to 23211
23212 continue
      t = a(i+1)
      if(.not.(a(i) .gt. t))go to 23214
      k = i
23216 continue
      a(k+1) = a(k)
      k = k-1
      if(.not.(t .ge. a(k)))go to 23216
      a(k+1) = t
23214 continue
      go to 23209
23211 continue
23171 continue
23167 go to 23166
23168 continue
      go to 23161
23163 continue
      return
      end
      function pull(a,n,k,b)
!c  Finds the kth order statistic of an array a of length n<=1000
      dimension a(*),b(*)
!
      do 15 j=1,n
        b(j)=a(j)
15    continue
!
      l=1
      lr=n
!
20    continue
      if (l.ge.lr)then
        pull=b(k)
        go to 9999
      endif
      ax=b(k)
      jnc=l
      j=lr
!
30    continue
      if(jnc.gt.j)then
        if(j.lt.k)l=jnc
        if(k.lt.jnc)lr=j
        go to 20
      endif
!
40    continue
      if (b(jnc).ge.ax)then
50      continue
        if (b(j).le.ax)then
          if(jnc.gt.j)go to 30
          buffer=b(jnc)
          b(jnc)=b(j)
          b(j)=buffer
          jnc=jnc+1
          j=j-1
          go to 30
        endif
        j=j-1
        go to 50
      endif
      jnc=jnc+1
      go to 40
!
 9999 CONTINUE
      return
      end
      SUBROUTINE PWLRAN(N,ALPHA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FOR THE POWER LAW FAILURTE TIMES.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE POWER LAW DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--98.6
!     ORIGINAL VERSION--JUNE      1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'PWLRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     POWER LAW RANDOM NUMBERS
!
      C2=(1.0/BETA)
      X(1)=((-1.0/ALPHA)*LOG(X(1)))**C2
      IF(N.EQ.1)GO TO 9999
!
      DO 200 I=2,N
        C3=X(I-1)
        C4=(-1.0/ALPHA)*LOG(X(I))
        X(I)=(C3**BETA + C4)**C2
  200 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE PWLRAN
      REAL FUNCTION PYTHAG(A,B)
!***BEGIN PROLOGUE  PYTHAG
!***REFER TO  EISDOC
!
!     Finds sqrt(A**2+B**2) without overflow or destructive underflow
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  PYTHAG
      REAL A,B
!
      REAL P,Q,R,S,T
!***FIRST EXECUTABLE STATEMENT  PYTHAG
      P = AMAX1(ABS(A),ABS(B))
      Q = AMIN1(ABS(A),ABS(B))
      IF (Q .EQ. 0.0E0) GO TO 20
   10 CONTINUE
         R = (Q/P)**2
         T = 4.0E0 + R
         IF (T .EQ. 4.0E0) GO TO 20
         S = R/T
         P = P + 2.0E0*P*S
         Q = Q*S
      GO TO 10
   20 PYTHAG = P
      RETURN
      END FUNCTION PYTHAG
      function Qn(x,n,y,work,work2,   &
                  left,right,weight,q,p,iwork)
!
!c#####################################################################
!c######################  file Qn.for :  ##############################
!c#####################################################################
!c
!c   This file contains a Fortran function for a new robust estimator
!c   of scale denoted as Qn, proposed in Rousseeuw and Croux (1993).
!c   The estimator has a high breakdown point and a smooth and bounded
!c   influence function. The algorithm given here is very fast (running
!c   in O(nlogn) time) and needs only O(n) storage space.
!c
!c   Rousseeuw, P.J. and Croux, C. (1993), "Alternatives to the
!c      Median Absolute Deviation," Journal of the American
!c      Statistical Association, Vol. 88, 1273-1283.
!c
!c   A Fortran function for the estimator Sn, described in the same
!c   paper, is attached above. For both estimators, implementations
!c   in the Pascal language can be obtained from the authors.
!c
!c   This software may be used and copied freely, provided
!c   reference is made to the abovementioned paper.
!c
!c   For questions, problems or comments contact:
!c
!c              Peter Rousseeuw (rousse@wins.uia.ac.be)
!c              Christophe Croux (croux@wins.uia.ac.be)
!c              Department of Mathematics and Computing
!c              Universitaire Instelling Antwerpen
!c              Universiteitsplein 1
!c              B-2610 Wilrijk (Antwerp)
!c              Belgium
!c
!c--------------------------------------------------------------------
!c
!c   Efficient algorithm for the scale estimator:
!c
!c       Qn = dn * 2.2219 * {|x_i-x_j|; i<j}_(k)
!c
!c   Parameters of the function Qn :
!c       x  : real array containing the observations
!c       n  : number of observations (n >=2)
!c
!c   The function Qn uses the procedures:
!c      whimed(a,iw,n): finds the weighted high median of an array
!c                      a of length n, using the array iw (also of
!c                      length n) with positive integer weights.
!c      sort(x,n,y) : sorts an array x of length n, and stores the
!c                    result in an array y (of size at least n)
!c      pull(a,n,k) : finds the k-th order statistic of an
!c                    array a of length n
!c
      dimension x(*)
      dimension y(*),work(*),work2(*)
      integer left(*),right(*),weight(*),Q(*),P(*),iwork(*)
!cccc dimension y(500),work(500)
!cccc integer left(500),right(500),weight(500),Q(500),P(500)
      integer h,k,knew,jhelp,nL,nR,sumQ,sumP
      logical found
      qn = 0.0
      dn = 0.0
      h=n/2+1
      k=h*(h-1)/2
      call sort(x,n,y)
      do 20 i=1,n
          left(i)=n-i+2
          right(i)=n
20    continue
      jhelp=n*(n+1)/2
      knew=k+jhelp
      nL=jhelp
      nR=n*n
      found=.false.
200   continue
      if ( (nR-nL.gt.n).and.(.not.found) ) then
          j=1
          do 30 i=2,n
          if (left(i).le.right(i)) then
              weight(j)=right(i)-left(i)+1
              jhelp=left(i)+weight(j)/2
              work(j)=y(i)-y(n+1-jhelp)
              j=j+1
          endif
30        continue
          trial=whimed(work,weight,j-1,work2,iwork)
          j=0
          do 40 i=n,1,-1
45            continue
              if ((j.lt.n).and.((y(i)-y(n-j)).lt.trial)) then
                  j=j+1
                  go to 45
              endif
              P(i)=j
40        continue
          j=n+1
          do 50 i=1,n
55            continue
              if ((y(i)-y(n-j+2)).gt.trial) then
                  j=j-1
                  go to 55
              endif
              Q(i)=j
50        continue
          sumP=0
          sumQ=0
          do 60 i=1,n
              sumP=sumP+P(i)
              sumQ=sumQ+Q(i)-1
60        continue
          if (knew.le.sumP) then
              do 70 i=1,n
                  right(i)=P(i)
70            continue
              nR=sumP
          else
              if (knew.gt.sumQ) then
                  do 80 i=1,n
                      left(i)=Q(i)
80                continue
                  nL=sumQ
              else
                  Qn=trial
                  found=.true.
              endif
          endif
      go to 200
      endif
      if (.not.found) then
          j=1
          do 90 i=2,n
          if (left(i).le.right(i)) then
              do 100 jj=left(i),right(i)
                  work(j)=y(i)-y(n-jj+1)
                  j=j+1
100           continue
          endif
90        continue
          Qn=pull(work,j-1,knew-nL,work2)
      endif
      if (n.le.9) then
          if (n.eq.2) dn=0.399
          if (n.eq.3) dn=0.994
          if (n.eq.4) dn=0.512
          if (n.eq.5) dn=0.844
          if (n.eq.6) dn=0.611
          if (n.eq.7) dn=0.857
          if (n.eq.8) dn=0.669
          if (n.eq.9) dn=0.872
      else
          if (mod(n,2).eq.1) dn=n/(n+1.4)
          if (mod(n,2).eq.0) dn=n/(n+3.8)
      endif
      Qn=dn*2.2219*Qn
      return
      end
!DPLT SUBROUTINE QAGI(F,BOUND,INF,EPSABS,EPSREL,RESULT,ABSERR,NEVAL,
      SUBROUTINE QAGI(BOUND,INF,EPSABS,EPSREL,RESULT,ABSERR,NEVAL,   &
         IER,LIMIT,LENW,LAST,IWORK,WORK)
!
!   2013/06: MODIFIED FOR DATAPLOT BY ALAN HECKERT.  CHANGES INCLUDE:
!
!            1) MODIFY TO USE DATAPLOT "DPWRST" FOR PRINTING OUTPUT.
!            2) MODIFY TO USE DATAPLOT FUNCTION DEFINITIONS (I.E.,
!               CALL COMPIM TO EVALUATE FUNCTION).
!
!***BEGIN PROLOGUE  QAGI
!***DATE WRITTEN   800101   (YYMMDD)
!***REVISION DATE  830518   (YYMMDD)
!***CATEGORY NO.  H2A3A1,H2A4A1
!***KEYWORDS  AUTOMATIC INTEGRATOR,EXTRAPOLATION,GENERAL-PURPOSE,
!             GLOBALLY ADAPTIVE,INFINITE INTERVALS,TRANSFORMATION
!***AUTHOR  PIESSENS, ROBERT, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!           DE DONCKER, ELISE, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!***PURPOSE  The routine calculates an approximation result to a given
!            INTEGRAL   I = Integral of F over (BOUND,+INFINITY)
!                    OR I = Integral of F over (-INFINITY,BOUND)
!                    OR I = Integral of F over (-INFINITY,+INFINITY)
!            Hopefully satisfying following claim for accuracy
!            ABS(I-RESULT).LE.MAX(EPSABS,EPSREL*ABS(I)).
!***DESCRIPTION
!
!        Integration over infinite intervals
!        Standard fortran subroutine
!
!        PARAMETERS
!         ON ENTRY
!            F      - Real
!                     Function subprogram defining the integrand
!                     function F(X). The actual name for F needs to be
!                     declared E X T E R N A L in the driver program.
!
!            BOUND  - Real
!                     Finite bound of integration range
!                     (has no meaning if interval is doubly-infinite)
!
!            INF    - Integer
!                     indicating the kind of integration range involved
!                     INF = 1 corresponds to  (BOUND,+INFINITY),
!                     INF = -1            to  (-INFINITY,BOUND),
!                     INF = 2             to (-INFINITY,+INFINITY).
!
!            EPSABS - Real
!                     Absolute accuracy requested
!            EPSREL - Real
!                     Relative accuracy requested
!                     If  EPSABS.LE.0
!                     and EPSREL.LT.MAX(50*REL.MACH.ACC.,0.5D-28),
!                     the routine will end with IER = 6.
!
!
!         ON RETURN
!            RESULT - Real
!                     Approximation to the integral
!
!            ABSERR - Real
!                     Estimate of the modulus of the absolute error,
!                     which should equal or exceed ABS(I-RESULT)
!
!            NEVAL  - Integer
!                     Number of integrand evaluations
!
!            IER    - Integer
!                     IER = 0 normal and reliable termination of the
!                             routine. It is assumed that the requested
!                             accuracy has been achieved.
!                   - IER.GT.0 abnormal termination of the routine. The
!                             estimates for result and error are less
!                             reliable. It is assumed that the requested
!                             accuracy has not been achieved.
!            ERROR MESSAGES
!                     IER = 1 Maximum number of subdivisions allowed
!                             has been achieved. One can allow more
!                             subdivisions by increasing the value of
!                             LIMIT (and taking the according dimension
!                             adjustments into account). However, if
!                             this yields no improvement it is advised
!                             to analyze the integrand in order to
!                             determine the integration difficulties. If
!                             the position of a local difficulty can be
!                             determined (e.g. SINGULARITY,
!                             DISCONTINUITY within the interval) one
!                             will probably gain from splitting up the
!                             interval at this point and calling the
!                             integrator on the subranges. If possible,
!                             an appropriate special-purpose integrator
!                             should be used, which is designed for
!                             handling the type of difficulty involved.
!                         = 2 The occurrence of roundoff error is
!                             detected, which prevents the requested
!                             tolerance from being achieved.
!                             The error may be under-estimated.
!                         = 3 Extremely bad integrand behaviour occurs
!                             at some points of the integration
!                             interval.
!                         = 4 The algorithm does not converge.
!                             Roundoff error is detected in the
!                             extrapolation table.
!                             It is assumed that the requested tolerance
!                             cannot be achieved, and that the returned
!                             RESULT is the best which can be obtained.
!                         = 5 The integral is probably divergent, or
!                             slowly convergent. It must be noted that
!                             divergence can occur with any other value
!                             of IER.
!                         = 6 The input is invalid, because
!                             (EPSABS.LE.0 and
!                              EPSREL.LT.MAX(50*REL.MACH.ACC.,0.5D-28))
!                              or LIMIT.LT.1 or LENIW.LT.LIMIT*4.
!                             RESULT, ABSERR, NEVAL, LAST are set to
!                             zero. Exept when LIMIT or LENIW is
!                             invalid, IWORK(1), WORK(LIMIT*2+1) and
!                             WORK(LIMIT*3+1) are set to ZERO, WORK(1)
!                             is set to A and WORK(LIMIT+1) to B.
!
!         DIMENSIONING PARAMETERS
!            LIMIT - Integer
!                    Dimensioning parameter for IWORK
!                    LIMIT determines the maximum number of subintervals
!                    in the partition of the given integration interval
!                    (A,B), LIMIT.GE.1.
!                    If LIMIT.LT.1, the routine will end with IER = 6.
!
!            LENW  - Integer
!                    Dimensioning parameter for WORK
!                    LENW must be at least LIMIT*4.
!                    If LENW.LT.LIMIT*4, the routine will end
!                    with IER = 6.
!
!            LAST  - Integer
!                    On return, LAST equals the number of subintervals
!                    produced in the subdivision process, which
!                    determines the number of significant elements
!                    actually in the WORK ARRAYS.
!
!         WORK ARRAYS
!            IWORK - Integer
!                    Vector of dimension at least LIMIT, the first
!                    K elements of which contain pointers
!                    to the error estimates over the subintervals,
!                    such that WORK(LIMIT*3+IWORK(1)),... ,
!                    WORK(LIMIT*3+IWORK(K)) form a decreasing
!                    sequence, with K = LAST if LAST.LE.(LIMIT/2+2), and
!                    K = LIMIT+1-LAST otherwise
!
!            WORK  - Real
!                    Vector of dimension at least LENW
!                    on return
!                    WORK(1), ..., WORK(LAST) contain the left
!                     end points of the subintervals in the
!                     partition of (A,B),
!                    WORK(LIMIT+1), ..., WORK(LIMIT+LAST) Contain
!                     the right end points,
!                    WORK(LIMIT*2+1), ...,WORK(LIMIT*2+LAST) contain the
!                     integral approximations over the subintervals,
!                    WORK(LIMIT*3+1), ..., WORK(LIMIT*3)
!                     contain the error estimates.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  QAGIE,XERROR
!***END PROLOGUE  QAGI
!
!DPLT REAL   ABSERR,  EPSABS,EPSREL,F,RESULT,WORK
      REAL   ABSERR,  EPSABS,EPSREL,RESULT,WORK
      INTEGER IER,IWORK,    LENW,LIMIT,LVL,L1,L2,L3,NEVAL
!
      DIMENSION IWORK(LIMIT),WORK(LENW)
!
!DPLT EXTERNAL F
!
      INCLUDE 'DPCOP2.INC'
!
!         CHECK VALIDITY OF LIMIT AND LENW.
!
!***FIRST EXECUTABLE STATEMENT  QAGI
      IER = 6
      NEVAL = 0
      LAST = 0
      RESULT = 0.0E+00
      ABSERR = 0.0E+00
      IF(LIMIT.LT.1.OR.LENW.LT.LIMIT*4) GO TO 10
!
!         PREPARE CALL FOR QAGIE.
!
      L1 = LIMIT+1
      L2 = LIMIT+L1
      L3 = LIMIT+L2
!
!DPLT CALL QAGIE(F,BOUND,INF,EPSABS,EPSREL,LIMIT,RESULT,ABSERR,
      CALL QAGIE(BOUND,INF,EPSABS,EPSREL,LIMIT,RESULT,ABSERR,   &
        NEVAL,IER,WORK(1),WORK(L1),WORK(L2),WORK(L3),IWORK,LAST)
!
!         CALL ERROR HANDLER IF NECESSARY.
!
      LVL = 0
10    IF(IER.EQ.6) LVL = 1
!DPLT IF(IER.NE.0) CALL XERROR( 'ABNORMAL RETURN FROM  QAGI',
!DPLT1  26,IER,LVL)
      IF(IER.NE.0)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,991)
  991   FORMAT('****** ERROR IN INTEGRAL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,993)IER,LVL
  993   FORMAT('       ABNORMAL RETURN FROM QAGI, IER, LVL = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE QAGI
!DPLT SUBROUTINE QAGIE(F,BOUND,INF,EPSABS,EPSREL,LIMIT,RESULT,ABSERR,
      SUBROUTINE QAGIE(BOUND,INF,EPSABS,EPSREL,LIMIT,RESULT,ABSERR,   &
         NEVAL,IER,ALIST,BLIST,RLIST,ELIST,IORD,LAST)
!
!   2013/06: MODIFIED FOR DATAPLOT BY ALAN HECKERT.  CHANGES INCLUDE:
!
!            1) MODIFY TO USE DATAPLOT "DPWRST" FOR PRINTING OUTPUT.
!            2) MODIFY TO USE DATAPLOT FUNCTION DEFINITIONS (I.E.,
!               CALL COMPIM TO EVALUATE FUNCTION).
!
!***BEGIN PROLOGUE  QAGIE
!***DATE WRITTEN   800101   (YYMMDD)
!***REVISION DATE  830518   (YYMMDD)
!***CATEGORY NO.  H2A3A1,H2A4A1
!***KEYWORDS  AUTOMATIC INTEGRATOR,EXTRAPOLATION,GENERAL-PURPOSE,
!             GLOBALLY ADAPTIVE,INFINITE INTERVALS,TRANSFORMATION
!***AUTHOR  PIESSENS, ROBERT, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!           DE DONCKER, ELISE, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!***PURPOSE  The routine calculates an approximation result to a given
!            integral   I = Integral of F over (BOUND,+INFINITY)
!                    or I = Integral of F over (-INFINITY,BOUND)
!                    or I = Integral of F over (-INFINITY,+INFINITY),
!                    hopefully satisfying following claim for accuracy
!                    ABS(I-RESULT).LE.MAX(EPSABS,EPSREL*ABS(I))
!***DESCRIPTION
!
! Integration over infinite intervals
! Standard fortran subroutine
!
!            F      - Real
!                     Function subprogram defining the integrand
!                     function F(X). The actual name for F needs to be
!                     declared E X T E R N A L in the driver program.
!
!            BOUND  - Real
!                     Finite bound of integration range
!                     (has no meaning if interval is doubly-infinite)
!
!            INF    - Real
!                     Indicating the kind of integration range involved
!                     INF = 1 corresponds to  (BOUND,+INFINITY),
!                     INF = -1            to  (-INFINITY,BOUND),
!                     INF = 2             to (-INFINITY,+INFINITY).
!
!            EPSABS - Real
!                     Absolute accuracy requested
!            EPSREL - Real
!                     Relative accuracy requested
!                     If  EPSABS.LE.0
!                     and EPSREL.LT.MAX(50*REL.MACH.ACC.,0.5D-28),
!                     the routine will end with IER = 6.
!
!            LIMIT  - Integer
!                     Gives an upper bound on the number of subintervals
!                     in the partition of (A,B), LIMIT.GE.1
!
!         ON RETURN
!            RESULT - Real
!                     Approximation to the integral
!
!            ABSERR - Real
!                     Estimate of the modulus of the absolute error,
!                     which should equal or exceed ABS(I-RESULT)
!
!            NEVAL  - Integer
!                     Number of integrand evaluations
!
!            IER    - Integer
!                     IER = 0 Normal and reliable termination of the
!                             routine. It is assumed that the requested
!                             accuracy has been achieved.
!                   - IER.GT.0 Abnormal termination of the routine. The
!                             estimates for result and error are less
!                             reliable. It is assumed that the requested
!                             accuracy has not been achieved.
!            ERROR MESSAGES
!                     IER = 1 Maximum number of subdivisions allowed
!                             has been achieved. One can allow more
!                             subdivisions by increasing the value of
!                             LIMIT (and taking the according dimension
!                             adjustments into account). However,if
!                             this yields no improvement it is advised
!                             to analyze the integrand in order to
!                             determine the integration difficulties.
!                             If the position of a local difficulty can
!                             be determined (e.g. SINGULARITY,
!                             DISCONTINUITY within the interval) one
!                             will probably gain from splitting up the
!                             interval at this point and calling the
!                             integrator on the subranges. If possible,
!                             an appropriate special-purpose integrator
!                             should be used, which is designed for
!                             handling the type of difficulty involved.
!                         = 2 The occurrence of roundoff error is
!                             detected, which prevents the requested
!                             tolerance from being achieved.
!                             The error may be under-estimated.
!                         = 3 Extremely bad integrand behaviour occurs
!                             at some points of the integration
!                             interval.
!                         = 4 The algorithm does not converge.
!                             Roundoff error is detected in the
!                             extrapolation table.
!                             It is assumed that the requested tolerance
!                             cannot be achieved, and that the returned
!                             result is the best which can be obtained.
!                         = 5 The integral is probably divergent, or
!                             slowly convergent. It must be noted that
!                             divergence can occur with any other value
!                             of IER.
!                         = 6 The input is invalid, because
!                             (EPSABS.LE.0 and
!                              EPSREL.LT.MAX(50*REL.MACH.ACC.,0.5D-28),
!                             RESULT, ABSERR, NEVAL, LAST, RLIST(1),
!                             ELIST(1) and IORD(1) are set to zero.
!                             ALIST(1) and BLIST(1) are set to 0
!                             and 1 respectively.
!
!            ALIST  - Real
!                     Vector of dimension at least LIMIT, the first
!                      LAST  elements of which are the left
!                     end points of the subintervals in the partition
!                     of the transformed integration range (0,1).
!
!            BLIST  - Real
!                     Vector of dimension at least LIMIT, the first
!                      LAST  elements of which are the right
!                     end points of the subintervals in the partition
!                     of the transformed integration range (0,1).
!
!            RLIST  - Real
!                     Vector of dimension at least LIMIT, the first
!                      LAST  elements of which are the integral
!                     approximations on the subintervals
!
!            ELIST  - Real
!                     Vector of dimension at least LIMIT,  the first
!                     LAST elements of which are the moduli of the
!                     absolute error estimates on the subintervals
!
!            IORD   - Integer
!                     Vector of dimension LIMIT, the first K
!                     elements of which are pointers to the
!                     error estimates over the subintervals,
!                     such that ELIST(IORD(1)), ..., ELIST(IORD(K))
!                     form a decreasing sequence, with K = LAST
!                     If LAST.LE.(LIMIT/2+2), and K = LIMIT+1-LAST
!                     otherwise
!
!            LAST   - Integer
!                     Number of subintervals actually produced
!                     in the subdivision process
!***REFERENCES  (NONE)
!***ROUTINES CALLED  QELG,QK15I,QPSRT,R1MACH
!***END PROLOGUE  QAGIE
!
      REAL ABSEPS,ABSERR,ALIST,AREA,AREA1,AREA12,AREA2,A1,   &
        A2,BLIST,BOUN,BOUND,B1,B2,CORREC,DEFABS,DEFAB1,DEFAB2,   &
        DRES,R1MACH,ELIST,EPMACH,EPSABS,EPSREL,ERLARG,ERLAST,   &
        ERRBND,ERRMAX,ERROR1,ERROR2,ERRO12,ERRSUM,ERTEST,OFLOW,RESABS,   &
        RESEPS,RESULT,RES3LA,RLIST,RLIST2,SMALL,UFLOW
      INTEGER ID,IER,IERRO,INF,IORD,IROFF1,IROFF2,IROFF3,JUPBND,K,KSGN,   &
        KTMIN,LAST,LIMIT,MAXERR,NEVAL,NRES,NRMAX,NUMRL2
      LOGICAL EXTRAP,NOEXT
!
      DIMENSION ALIST(LIMIT),BLIST(LIMIT),ELIST(LIMIT),IORD(LIMIT),   &
        RES3LA(3),RLIST(LIMIT),RLIST2(52)
!
!DPLT EXTERNAL F
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!            THE DIMENSION OF RLIST2 IS DETERMINED BY THE VALUE OF
!            LIMEXP IN SUBROUTINE QELG.
!
!
!            LIST OF MAJOR VARIABLES
!            -----------------------
!
!           ALIST     - LIST OF LEFT END POINTS OF ALL SUBINTERVALS
!                       CONSIDERED UP TO NOW
!           BLIST     - LIST OF RIGHT END POINTS OF ALL SUBINTERVALS
!                       CONSIDERED UP TO NOW
!           RLIST(I)  - APPROXIMATION TO THE INTEGRAL OVER
!                       (ALIST(I),BLIST(I))
!           RLIST2    - ARRAY OF DIMENSION AT LEAST (LIMEXP+2),
!                       CONTAINING THE PART OF THE EPSILON TABLE
!                       WICH IS STILL NEEDED FOR FURTHER COMPUTATIONS
!           ELIST(I)  - ERROR ESTIMATE APPLYING TO RLIST(I)
!           MAXERR    - POINTER TO THE INTERVAL WITH LARGEST ERROR
!                       ESTIMATE
!           ERRMAX    - ELIST(MAXERR)
!           ERLAST    - ERROR ON THE INTERVAL CURRENTLY SUBDIVIDED
!                       (BEFORE THAT SUBDIVISION HAS TAKEN PLACE)
!           AREA      - SUM OF THE INTEGRALS OVER THE SUBINTERVALS
!           ERRSUM    - SUM OF THE ERRORS OVER THE SUBINTERVALS
!           ERRBND    - REQUESTED ACCURACY MAX(EPSABS,EPSREL*
!                       ABS(RESULT))
!           *****1    - VARIABLE FOR THE LEFT SUBINTERVAL
!           *****2    - VARIABLE FOR THE RIGHT SUBINTERVAL
!           LAST      - INDEX FOR SUBDIVISION
!           NRES      - NUMBER OF CALLS TO THE EXTRAPOLATION ROUTINE
!           NUMRL2    - NUMBER OF ELEMENTS CURRENTLY IN RLIST2. IF AN
!                       APPROPRIATE APPROXIMATION TO THE COMPOUNDED
!                       INTEGRAL HAS BEEN OBTAINED, IT IS PUT IN
!                       RLIST2(NUMRL2) AFTER NUMRL2 HAS BEEN INCREASED
!                       BY ONE.
!           SMALL     - LENGTH OF THE SMALLEST INTERVAL CONSIDERED UP
!                       TO NOW, MULTIPLIED BY 1.5
!           ERLARG    - SUM OF THE ERRORS OVER THE INTERVALS LARGER
!                       THAN THE SMALLEST INTERVAL CONSIDERED UP TO NOW
!           EXTRAP    - LOGICAL VARIABLE DENOTING THAT THE ROUTINE
!                       IS ATTEMPTING TO PERFORM EXTRAPOLATION. I.E.
!                       BEFORE SUBDIVIDING THE SMALLEST INTERVAL WE
!                       TRY TO DECREASE THE VALUE OF ERLARG.
!           NOEXT     - LOGICAL VARIABLE DENOTING THAT EXTRAPOLATION
!                       IS NO LONGER ALLOWED (TRUE-VALUE)
!
!            MACHINE DEPENDENT CONSTANTS
!            ---------------------------
!
!           EPMACH IS THE LARGEST RELATIVE SPACING.
!           UFLOW IS THE SMALLEST POSITIVE MAGNITUDE.
!           OFLOW IS THE LARGEST POSITIVE MAGNITUDE.
!
!***FIRST EXECUTABLE STATEMENT  QAGIE
       EPMACH = R1MACH(4)
!
!           TEST ON VALIDITY OF PARAMETERS
!           -----------------------------
!
      IER = 0
      NEVAL = 0
      LAST = 0
      RESULT = 0.0E+00
      ABSERR = 0.0E+00
      CORREC = 0.0E+00
      ERLARG = 0.0E+00
      ERTEST = 0.0E+00
      SMALL = 0.0E+00
      ALIST(1) = 0.0E+00
      BLIST(1) = 0.1E+01
      RLIST(1) = 0.0E+00
      ELIST(1) = 0.0E+00
      IORD(1) = 0
      IF(EPSABS.LE.0.0E+00.AND.EPSREL.LT.AMAX1(0.5E+02*EPMACH,0.5E-14))   &
        IER = 6
      IF(IER.EQ.6) GO TO 999
!
!
!           FIRST APPROXIMATION TO THE INTEGRAL
!           -----------------------------------
!
!           DETERMINE THE INTERVAL TO BE MAPPED ONTO (0,1).
!           IF INF = 2 THE INTEGRAL IS COMPUTED AS I = I1+I2, WHERE
!           I1 = INTEGRAL OF F OVER (-INFINITY,0),
!           I2 = INTEGRAL OF F OVER (0,+INFINITY).
!
      BOUN = BOUND
      IF(INF.EQ.2) BOUN = 0.0E+00
!DPLT CALL QK15I(F,BOUN,INF,0.0E+00,0.1E+01,RESULT,ABSERR,
      CALL QK15I(BOUN,INF,0.0E+00,0.1E+01,RESULT,ABSERR,   &
        DEFABS,RESABS)
!
!           TEST ON ACCURACY
!
      LAST = 1
      RLIST(1) = RESULT
      ELIST(1) = ABSERR
      IORD(1) = 1
      DRES = ABS(RESULT)
      ERRBND = AMAX1(EPSABS,EPSREL*DRES)
      IF(ABSERR.LE.1.0E+02*EPMACH*DEFABS.AND.ABSERR.GT.   &
        ERRBND) IER = 2
      IF(LIMIT.EQ.1) IER = 1
      IF(IER.NE.0.OR.(ABSERR.LE.ERRBND.AND.ABSERR.NE.RESABS).OR.   &
        ABSERR.EQ.0.0E+00) GO TO 130
!
!           INITIALIZATION
!           --------------
!
      UFLOW = R1MACH(1)
      OFLOW = R1MACH(2)
      RLIST2(1) = RESULT
      ERRMAX = ABSERR
      MAXERR = 1
      AREA = RESULT
      ERRSUM = ABSERR
      ABSERR = OFLOW
      NRMAX = 1
      NRES = 0
      KTMIN = 0
      NUMRL2 = 2
      EXTRAP = .FALSE.
      NOEXT = .FALSE.
      IERRO = 0
      IROFF1 = 0
      IROFF2 = 0
      IROFF3 = 0
      KSGN = -1
      IF(DRES.GE.(0.1E+01-0.5E+02*EPMACH)*DEFABS) KSGN = 1
!
!           MAIN DO-LOOP
!           ------------
!
      DO 90 LAST = 2,LIMIT
!
!           BISECT THE SUBINTERVAL WITH NRMAX-TH LARGEST
!           ERROR ESTIMATE.
!
        A1 = ALIST(MAXERR)
        B1 = 0.5E+00*(ALIST(MAXERR)+BLIST(MAXERR))
        A2 = B1
        B2 = BLIST(MAXERR)
        ERLAST = ERRMAX
!CCCC   CALL QK15I(F,BOUN,INF,A1,B1,AREA1,ERROR1,RESABS,DEFAB1)
!CCCC   CALL QK15I(F,BOUN,INF,A2,B2,AREA2,ERROR2,RESABS,DEFAB2)
        CALL QK15I(BOUN,INF,A1,B1,AREA1,ERROR1,RESABS,DEFAB1)
        CALL QK15I(BOUN,INF,A2,B2,AREA2,ERROR2,RESABS,DEFAB2)
!
!           IMPROVE PREVIOUS APPROXIMATIONS TO INTEGRAL
!           AND ERROR AND TEST FOR ACCURACY.
!
        AREA12 = AREA1+AREA2
        ERRO12 = ERROR1+ERROR2
        ERRSUM = ERRSUM+ERRO12-ERRMAX
        AREA = AREA+AREA12-RLIST(MAXERR)
        IF(DEFAB1.EQ.ERROR1.OR.DEFAB2.EQ.ERROR2)GO TO 15
        IF(ABS(RLIST(MAXERR)-AREA12).GT.0.1E-04*ABS(AREA12)   &
        .OR.ERRO12.LT.0.99E+00*ERRMAX) GO TO 10
        IF(EXTRAP) IROFF2 = IROFF2+1
        IF(.NOT.EXTRAP) IROFF1 = IROFF1+1
   10   IF(LAST.GT.10.AND.ERRO12.GT.ERRMAX) IROFF3 = IROFF3+1
   15   RLIST(MAXERR) = AREA1
        RLIST(LAST) = AREA2
        ERRBND = AMAX1(EPSABS,EPSREL*ABS(AREA))
!
!           TEST FOR ROUNDOFF ERROR AND EVENTUALLY
!           SET ERROR FLAG.
!
        IF(IROFF1+IROFF2.GE.10.OR.IROFF3.GE.20) IER = 2
        IF(IROFF2.GE.5) IERRO = 3
!
!           SET ERROR FLAG IN THE CASE THAT THE NUMBER OF
!           SUBINTERVALS EQUALS LIMIT.
!
        IF(LAST.EQ.LIMIT) IER = 1
!
!           SET ERROR FLAG IN THE CASE OF BAD INTEGRAND BEHAVIOUR
!           AT SOME POINTS OF THE INTEGRATION RANGE.
!
        IF(AMAX1(ABS(A1),ABS(B2)).LE.(0.1E+01+0.1E+03*EPMACH)*   &
        (ABS(A2)+0.1E+04*UFLOW)) IER = 4
!
!           APPEND THE NEWLY-CREATED INTERVALS TO THE LIST.
!
        IF(ERROR2.GT.ERROR1) GO TO 20
        ALIST(LAST) = A2
        BLIST(MAXERR) = B1
        BLIST(LAST) = B2
        ELIST(MAXERR) = ERROR1
        ELIST(LAST) = ERROR2
        GO TO 30
   20   ALIST(MAXERR) = A2
        ALIST(LAST) = A1
        BLIST(LAST) = B1
        RLIST(MAXERR) = AREA2
        RLIST(LAST) = AREA1
        ELIST(MAXERR) = ERROR2
        ELIST(LAST) = ERROR1
!
!           CALL SUBROUTINE QPSRT TO MAINTAIN THE DESCENDING ORDERING
!           IN THE LIST OF ERROR ESTIMATES AND SELECT THE
!           SUBINTERVAL WITH NRMAX-TH LARGEST ERROR ESTIMATE (TO BE
!           BISECTED NEXT).
!
   30   CALL QPSRT(LIMIT,LAST,MAXERR,ERRMAX,ELIST,IORD,NRMAX)
        IF(ERRSUM.LE.ERRBND) GO TO 115
        IF(IER.NE.0) GO TO 100
        IF(LAST.EQ.2) GO TO 80
        IF(NOEXT) GO TO 90
        ERLARG = ERLARG-ERLAST
        IF(ABS(B1-A1).GT.SMALL) ERLARG = ERLARG+ERRO12
        IF(EXTRAP) GO TO 40
!
!           TEST WHETHER THE INTERVAL TO BE BISECTED NEXT IS THE
!           SMALLEST INTERVAL.
!
        IF(ABS(BLIST(MAXERR)-ALIST(MAXERR)).GT.SMALL) GO TO 90
        EXTRAP = .TRUE.
        NRMAX = 2
   40   IF(IERRO.EQ.3.OR.ERLARG.LE.ERTEST) GO TO 60
!
!           THE SMALLEST INTERVAL HAS THE LARGEST ERROR.
!           BEFORE BISECTING DECREASE THE SUM OF THE ERRORS
!           OVER THE LARGER INTERVALS (ERLARG) AND PERFORM
!           EXTRAPOLATION.
!
        ID = NRMAX
        JUPBND = LAST
        IF(LAST.GT.(2+LIMIT/2)) JUPBND = LIMIT+3-LAST
        DO 50 K = ID,JUPBND
          MAXERR = IORD(NRMAX)
          ERRMAX = ELIST(MAXERR)
          IF(ABS(BLIST(MAXERR)-ALIST(MAXERR)).GT.SMALL) GO TO 90
          NRMAX = NRMAX+1
   50   CONTINUE
!
!           PERFORM EXTRAPOLATION.
!
   60   NUMRL2 = NUMRL2+1
        RLIST2(NUMRL2) = AREA
        CALL QELG(NUMRL2,RLIST2,RESEPS,ABSEPS,RES3LA,NRES)
        KTMIN = KTMIN+1
        IF(KTMIN.GT.5.AND.ABSERR.LT.0.1E-02*ERRSUM) IER = 5
        IF(ABSEPS.GE.ABSERR) GO TO 70
        KTMIN = 0
        ABSERR = ABSEPS
        RESULT = RESEPS
        CORREC = ERLARG
        ERTEST = AMAX1(EPSABS,EPSREL*ABS(RESEPS))
        IF(ABSERR.LE.ERTEST) GO TO 100
!
!            PREPARE BISECTION OF THE SMALLEST INTERVAL.
!
   70   IF(NUMRL2.EQ.1) NOEXT = .TRUE.
        IF(IER.EQ.5) GO TO 100
        MAXERR = IORD(1)
        ERRMAX = ELIST(MAXERR)
        NRMAX = 1
        EXTRAP = .FALSE.
        SMALL = SMALL*0.5E+00
        ERLARG = ERRSUM
        GO TO 90
   80   SMALL = 0.375E+00
        ERLARG = ERRSUM
        ERTEST = ERRBND
        RLIST2(2) = AREA
   90 CONTINUE
!
!           SET FINAL RESULT AND ERROR ESTIMATE.
!           ------------------------------------
!
  100 IF(ABSERR.EQ.OFLOW) GO TO 115
      IF((IER+IERRO).EQ.0) GO TO 110
      IF(IERRO.EQ.3) ABSERR = ABSERR+CORREC
      IF(IER.EQ.0) IER = 3
      IF(RESULT.NE.0.0E+00.AND.AREA.NE.0.0E+00)GO TO 105
      IF(ABSERR.GT.ERRSUM)GO TO 115
      IF(AREA.EQ.0.0E+00) GO TO 130
      GO TO 110
  105 IF(ABSERR/ABS(RESULT).GT.ERRSUM/ABS(AREA))GO TO 115
!
!           TEST ON DIVERGENCE
!
  110 IF(KSGN.EQ.(-1).AND.AMAX1(ABS(RESULT),ABS(AREA)).LE.   &
       DEFABS*0.1E-01) GO TO 130
      IF(0.1E-01.GT.(RESULT/AREA) .OR. (RESULT/AREA).GT.0.1E+03   &
         .OR. ERRSUM.GT.ABS(AREA)) IER = 6
      GO TO 130
!
!           COMPUTE GLOBAL INTEGRAL SUM.
!
  115 RESULT = 0.0E+00
      DO 120 K = 1,LAST
        RESULT = RESULT+RLIST(K)
  120 CONTINUE
      ABSERR = ERRSUM
  130 NEVAL = 30*LAST-15
      IF(INF.EQ.2) NEVAL = 2*NEVAL
      IF(IER.GT.2) IER=IER-1
  999 RETURN
      END SUBROUTINE QAGIE
      SUBROUTINE QBICDF(X,P,PHI,M,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE QUASI BINOMIAL-I
!              DISTRIBUTION WITH SHAPE PARAMETERS P, PHI, AND M.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;P,PHI,M)=
!                  (M  X)*P*(P+X*PHI)**(X-1)*(1-P-X*PHI)**(M-X)
!                  X = 0, 1, 2, 3, ,..., M;
!                  0 <= P <= 1; -P/M < PHI < (1-P)/M;
!
!              THE CUMULATIVE DISTRIBUTION PROBABILITIES CAN BE
!              COMPUTED WITH THE FOLLOWING RECURRENCE RELATION:
!
!              p(x+1) = {(m-x)*(p+x*phi)/((x+1)*(1-p-x*phi))}*
!                       (1 + phi/(p+x*phi))**x*
!                       (1 - phi/(1-p-X*PHI))**(m-x-1)*p(x)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --P      = THE FIRST SHAPE PARAMETER
!                     --PHI    = THE SECOND SHAPE PARAMETER
!                     --M      = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE QUASI BINOMIAL-I
!             DISTRIBUTION WITH SHAPE PARAMETERS P, PHI AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 <- P <= 1; -P/M < PHI < (1-P)/M
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, PP. 70-80.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL M
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPHI
      DOUBLE PRECISION DM
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5)
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO QBICDF IS LESS ',   &
      'THAN 0')
!
      IF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO QBICDF IS NOT IN ',   &
      'THE INTERVAL (0,1)')
!
      IM=INT(M+0.5)
      M=REAL(IM)
      ALOWLM=-P/M
      AUPPLM=(1.0-P)/M
      IF(PHI.LE.ALOWLM .OR. PHI.GE.AUPPLM)THEN
        WRITE(ICOUT,25)ALOWLM,AUPPLM
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PHI
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO QBICDF IS NOT IN ',   &
      'THE INTERVAL (',G15.7,',',G15.7,')')
!
      IF(IM.LT.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)IM
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   35 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO QBICDF IS ',   &
      'NON-POSITIVE')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(IX.GE.IM)THEN
        CDF=1.0
        GO TO 9000
      ENDIF
!
      DP=DBLE(P)
      DPHI=DBLE(PHI)
      DM=DBLE(M)
!
      DPDFSV=(1.0D0 - DP)**DM
      IF(IX.EQ.0)THEN
        CDF=REAL(DPDFSV)
        GO TO 9000
      ENDIF
!
      DCDF=DPDFSV
      DO 100 I=1,IX
        DX=DBLE(I-1)
        DTERM1=DLOG(DM-DX) + DLOG(DP+DX*DPHI) - DLOG(DX+1.0D0) -   &
               DLOG(1.0D0 - DP - DX*DPHI)
        DTERM2=DX*DLOG(1.0D0 + DPHI/(DP+DX*DPHI))
        DTERM3=(DM-DX-1.0D0)*DLOG(1.0D0 - DPHI/(1.0D0 - DP - DX*DPHI))
        IF(DPDFSV.GT.0.0D0)THEN
          DTERM4=DLOG(DPDFSV)
          DPDF=DEXP(DTERM1+DTERM2+DTERM3+DTERM4)
        ELSE
          CDF=REAL(DCDF)
          GO TO 9000
        ENDIF
        DCDF=DCDF + DPDF
        DPDFSV=DPDF
  100 CONTINUE
!
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE QBICDF
      SUBROUTINE QBIFUN(N,XPAR,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              QUASI BINOMIAL TYPE I MAXIMUM LIKELIHOOD
!              EQUATIONS.
!
!              THE MAXIMUM LIKELIHOOD ESTIMATES ARE THE SOLUTIONS
!              TO THE EQUATIONS:
!
!                 SUM[i=1 to N][(m-X(i))/(1 - P - X9i)*PHI] - M*N = 0
!
!                 SUM[i=1 to N][(X(i)*(X(i) - 1)/(p + X(i)*PHI) -
!                 SUM[i=1 to N][(M - X(i))/(1 - P - X(i)*PHI)] = 0
!
!              NOTE THAT M IS ASSUMED FIXED AND KNOWN AND WE ARE
!              SOLVING FOR P AND PHI.
!
!              WHEN THE DATA IS BINNED, THE MAXIMUM LIKELIHOOD
!              EQUATIONS BECOME
!
!                  SUM[i=1 to k][N(i)*(i-1)*i/(p+i*PHI)] -
!                  SUM[i=1 to k][N(i)*(M-i)*i/(1-p-i*PHI)] = 0
!
!                  (N/P) - SUM[i=1 to k][N(i)*(i-1)/(p+i*PHI)] -
!                  SUM[i=1 to k][N(i)*(i-1)/(P+i*PHI) -
!                  SUM[i=1 to k][N(i)*(M-i)/(1-P-i*PHI)] = 0
!
!              ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--QUASI BINOMIAL TYPE I MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, PP. 70 - 80.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPHI
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
!
      DOUBLE PRECISION DM
      DOUBLE PRECISION F0FREQ
      COMMON/QBICOM/DM,F0FREQ,MAXROW,NTOT2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      IINDX=MAXROW/2
      N=2
      IFLAG=0
!
      DP=XPAR(1)
      DPHI=XPAR(2)
      DN=DBLE(NTOT2)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
!
      DO 100 I=1,K
        DX=DBLE(Y(IINDX+I))
        DFREQ=DBLE(Y(I))
        IF(DFREQ.EQ.0.0D0)GO TO 100
        DSUM1=DSUM1 + DFREQ*(DX-1.0D0)*DX/(DP+DX*DPHI)
        DSUM2=DSUM2 + DFREQ*(DM-DX)*DX/(1.0D0-DP-DX*DPHI)
        DSUM3=DSUM3 + DFREQ*(DX-1.0D0)/(DP+DX*DPHI)
        DSUM4=DSUM4 + DFREQ*(DM-DX)/(1.0D0-DP-DX*DPHI)
  100 CONTINUE
!
      FVEC(1)=DSUM1 - DSUM2
      FVEC(2)=(DN/DP) + DSUM3 - DSUM4
!
      RETURN
      END SUBROUTINE QBIFUN
      SUBROUTINE QBIPDF(X,P,PHI,M,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE FOR THE QUASI BINOMIAL-I
!              DISTRIBUTION WITH SHAPE PARAMETERS P, PHI, AND M.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;P,PHI,M)=
!                  (M  X)*P*(P+X*PHI)**(X-1)*(1-P-X*PHI)**(M-X)
!                  X = 0, 1, 2, 3, ,..., M;
!                  0 <= P <= 1; -P/M < PHI < (1-P)/M;
!
!              THIS DISTRIBUTION IS USED TO MODEL BERNOULLI TRIALS
!              WHERE THE PROBABILITY OF SUCCESS PARAMETER IS
!              INCREASING (OR DECREASING) FOR SUCCESSIVE TRIALS.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --P      = THE FIRST SHAPE PARAMETER
!                     --PHI    = THE SECOND SHAPE PARAMETER
!                     --M      = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY MASS FUNCTION
!             VALUE PDF FOR THE QUASI BINOMIAL-I
!             DISTRIBUTION WITH SHAPE PARAMETERS P, PHI AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 <- P <= 1; -P/M < PHI < (1-P)/M
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, PP. 70-80.
!     WRITTEN BY--ALAN HECKER
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL M
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPHI
      DOUBLE PRECISION DM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DBINLN
      EXTERNAL DBINLN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5)
      PDF=0.0
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO QBIPDF IS LESS ',   &
               'THAN 0')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO QBIPDF IS NOT IN ',   &
               'THE INTERVAL (0,1)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IM=INT(M+0.5)
      M=REAL(IM)
      ALOWLM=-P/M
      AUPPLM=(1.0-P)/M
      IF(PHI.LE.ALOWLM .OR. PHI.GE.AUPPLM)THEN
        WRITE(ICOUT,25)ALOWLM,AUPPLM
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO QBIPDF IS NOT IN ',   &
               'THE INTERVAL (',G15.7,',',G15.7,')')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PHI
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(IM.LT.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO QBIPDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)IM
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      DP=DBLE(P)
      DPHI=DBLE(PHI)
      DM=DBLE(M)
      DX=DBLE(IX)
!
      DTERM1=DBINLN(IM,IX)
      DTERM2=DLOG(DP)
      DTERM3=(DX-1.0D0)*DLOG(DP + DX*DPHI)
      DTERM4=(DM-DX)*DLOG(1.0D0 - DP - DX*DPHI)
      DPDF=DEXP(DTERM1+DTERM2+DTERM3+DTERM4)
!
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE QBIPDF
      SUBROUTINE QBIPPF(P,PPAR,PHI,M,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE QUASI BINOMIAL-I
!              DISTRIBUTION WITH SHAPE PARAMETERS P, PHI, AND M.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;P,PHI,M)=
!                  (M  X)*P*(P+X*PHI)**(X-1)*(1-P-X*PHI)**(M-X)
!                  X = 0, 1, 2, 3, ,..., M;
!                  0 <= P <= 1; -P/M < PHI < (1-P)/M;
!
!              THE CUMULATIVE DISTRIBUTION PROBABILITIES CAN BE
!              COMPUTED WITH THE FOLLOWING RECURRENCE RELATION:
!
!              p(x+1) = {(m-x)*(p+x*phi)/((x+1)*(1-p-x*phi))}*
!                       (1 + phi/(p+x*phi))**x*
!                       (1 - phi/(1-p-X*PHI))**(m-x-1)*p(x)
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY SUMMING
!              THESE CUMULATIVE PROBABILITIES UNTIL AN
!              APPROPRIATE PROBABILITY HAS BEEN OBTAINED.
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --PPAR   = THE FIRST SHAPE PARAMETER
!                     --PHI    = THE SECOND SHAPE PARAMETER
!                     --M      = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE QUASI BINOMIAL-I
!             DISTRIBUTION WITH SHAPE PARAMETERS P, PHI AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P <= 1
!                 --0 <- P <= 1; -P/M < PHI < (1-P)/M
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, PP. 70-80.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL M
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPAR
      DOUBLE PRECISION DPHI
      DOUBLE PRECISION DM
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO QBIPPF IS OUTSIDE ',   &
      'THE (0,1) INTERVAL')
!
      IF(PPAR.LT.0.0 .OR. PPAR.GT.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO QBIPPF IS NOT IN ',   &
      'THE INTERVAL (0,1)')
!
      IM=INT(M+0.5)
      M=REAL(IM)
      ALOWLM=-PPAR/M
      AUPPLM=(1.0-PPAR)/M
      IF(PHI.LE.ALOWLM .OR. PHI.GE.AUPPLM)THEN
        WRITE(ICOUT,25)ALOWLM,AUPPLM
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PHI
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO QBIPPF IS NOT IN ',   &
      'THE INTERVAL (',G15.7,',',G15.7,')')
!
      IF(IM.LT.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)IM
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
   35 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO QBIPPF IS ',   &
      'NON-POSITIVE')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     HANDLE THE P = 0 AND P = 1 CASES IMMEDIATELY
!
      IF(P.LE.0.0)THEN
        PPF=0.0
        GO TO 9000
      ELSEIF(P.GE.1.0)THEN
        PPF=M
        GO TO 9000
      ENDIF
!
      DP=DBLE(P)
      DPPAR=DBLE(PPAR)
      DPHI=DBLE(PHI)
      DM=DBLE(M)
      DEPS=1.0D-7
!
      DCDF=(1.0D0 - DPPAR)**DM
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=0.0
        GO TO 9000
      ENDIF
      DPDFSV=DCDF
!
      I=0
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9000
        ENDIF
        DX=DBLE(I-1)
        DTERM1=DLOG(DM-DX) + DLOG(DPPAR+DX*DPHI) - DLOG(DX+1.0D0) -   &
               DLOG(1.0D0 - DPPAR - DX*DPHI)
        DTERM2=DX*DLOG(1.0D0 + DPHI/(DPPAR+DX*DPHI))
        DTERM3=(DM-DX-1.0D0)*DLOG(1.0D0-DPHI/(1.0D0-DPPAR-DX*DPHI))
        IF(DPDFSV.GT.0.0D0)THEN
          DTERM4=DLOG(DPDFSV)
          DPDF=DEXP(DTERM1+DTERM2+DTERM3+DTERM4)
        ELSE
          DPDF=0.0D0
          GO TO 1000
        ENDIF
 1000   CONTINUE
        DCDF=DCDF + DPDF
        DPDFSV=DPDF
        IF(DCDF.GE.DP-DEPS)THEN
          PPF=REAL(I)
          GO TO 9000
        ENDIF
      GO TO 100
!
      PPF=REAL(DPPF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE QBIPPF
      SUBROUTINE QBIRAN(N,P,PHI,AM,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE QUASI BINOMIAL TYPE I DISTRIBUTION
!              WITH SHAPE PARAMETERS P, PHI, AND M.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;P,PHI,M)=
!                  (M  X)*P*(P+X*PHI)**(X-1)*(1-P-X*PHI)**(M-X)
!                  X = 0, 1, 2, 3, ,..., M;
!                  0 <= P <= 1; -P/M < PHI < (1-P)/M;
!
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --PHI    = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --AM     = THE SINGLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE QUASI BINOMIAL TYPE I DISTRIBUTION
!             WITH SHAPE PARAMETERS P, PHI, AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 <= P <= 1, -P/M < PHI < (1-P)/M; M >= 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, QBIPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, PP. 70-80.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL P
      REAL PHI
      REAL AM
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
      'QUASI BINOMIAL TYPE I')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE')
!
      IM=INT(AM+0.5)
      AM=REAL(IM)
      ALOWLM=-P/AM
      AUPPLM=(1.0-P)/AM
      IF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE P PARAMETER FOR THE ',   &
      'QUASI BINOMIAL TYPE I')
   12 FORMAT('      RANDOM NUMBERS IS OUTSIDE THE (0,1) INTERVAL')
!
      IM=INT(AM+0.5)
      AM=REAL(IM)
      ALOWLM=-P/AM
      AUPPLM=(1.0-P)/AM
      IF(PHI.LE.ALOWLM .OR. PHI.GE.AUPPLM)THEN
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22)ALOWLM,AUPPLM
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PHI
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   21 FORMAT('***** ERROR--THE PHI PARAMETER FOR THE ',   &
      'QUASI BINOMIAL TYPE I')
   22 FORMAT('      RANDOM NUMBERS IS OUTSIDE THE (',G15.7,   &
             ',',G15.7,') INTERVAL')
!
      IF(AM.LT.0.0)THEN
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AM
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   31 FORMAT('***** ERROR--THE M PARAMETER FOR THE ',   &
      'QUASI BINOMIAL TYPE I')
   32 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N QUASI BINOMIAL TYPE I DISTRIBUTION
!     RANDOM NUMBERS.  FOLLOWING RECOMMENDATION OF CONSUL AND
!     FAYMOE, USE INVERSION METHOD FOR P*PHI <= 0.60 AND
!     BRANCHING METHOD OTHERWISE.
!
!     BRANCHING ALGORITHM DOESN'T SEEM TO RETURN AS ACCURATE
!     A RESULT AS THE INVERSION METHOD, SO USE THE INVERSION
!     METHOD EVEN IF SOMEWHAT SLOWER.
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        ZTEMP=X(I)
        CALL QBIPPF(ZTEMP,P,PHI,AM,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE QBIRAN
      SUBROUTINE QELG(N,EPSTAB,RESULT,ABSERR,RES3LA,NRES)
!
!   2013/06: MODIFIED FOR DATAPLOT BY ALAN HECKERT.
!
!***BEGIN PROLOGUE  QELG
!***REFER TO  QAGIE,QAGOE,QAGPE,QAGSE
!***ROUTINES CALLED  R1MACH
!***REVISION DATE  830518   (YYMMDD)
!***KEYWORDS  CONVERGENCE ACCELERATION,EPSILON ALGORITHM,EXTRAPOLATION
!***AUTHOR  PIESSENS, ROBERT, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!           DE DONCKER, ELISE, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!***PURPOSE  The routine determines the limit of a given sequence of
!            approximations, by means of the Epsilon algorithm of
!            P. Wynn. An estimate of the absolute error is also given.
!            The condensed Epsilon table is computed. Only those
!            elements needed for the computation of the next diagonal
!            are preserved.
!***DESCRIPTION
!
!           Epsilon algorithm
!           Standard fortran subroutine
!           Real version
!
!           PARAMETERS
!              N      - Integer
!                       EPSTAB(N) contains the new element in the
!                       first column of the epsilon table.
!
!              EPSTAB - Real
!                       Vector of dimension 52 containing the elements
!                       of the two lower diagonals of the triangular
!                       epsilon table. The elements are numbered
!                       starting at the right-hand corner of the
!                       triangle.
!
!              RESULT - Real
!                       Resulting approximation to the integral
!
!              ABSERR - Real
!                       Estimate of the absolute error computed from
!                       RESULT and the 3 previous results
!
!              RES3LA - Real
!                       Vector of dimension 3 containing the last 3
!                       results
!
!              NRES   - Integer
!                       Number of calls to the routine
!                       (should be zero at first call)
!***END PROLOGUE  QELG
!
      REAL ABSERR,DELTA1,DELTA2,DELTA3,R1MACH,   &
        EPMACH,EPSINF,EPSTAB,ERROR,ERR1,ERR2,ERR3,E0,E1,E1ABS,E2,E3,   &
        OFLOW,RES,RESULT,RES3LA,SS,TOL1,TOL2,TOL3
      INTEGER I,IB,IB2,IE,INDX,K1,K2,K3,LIMEXP,N,NEWELM,NRES,NUM
      DIMENSION EPSTAB(52),RES3LA(3)
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!           LIST OF MAJOR VARIABLES
!           -----------------------
!
!           E0     - THE 4 ELEMENTS ON WHICH THE
!           E1       COMPUTATION OF A NEW ELEMENT IN
!           E2       THE EPSILON TABLE IS BASED
!           E3                 E0
!                        E3    E1    NEW
!                              E2
!           NEWELM - NUMBER OF ELEMENTS TO BE COMPUTED IN THE NEW
!                    DIAGONAL
!           ERROR  - ERROR = ABS(E1-E0)+ABS(E2-E1)+ABS(NEW-E2)
!           RESULT - THE ELEMENT IN THE NEW DIAGONAL WITH LEAST VALUE
!                    OF ERROR
!
!           MACHINE DEPENDENT CONSTANTS
!           ---------------------------
!
!           EPMACH IS THE LARGEST RELATIVE SPACING.
!           OFLOW IS THE LARGEST POSITIVE MAGNITUDE.
!           LIMEXP IS THE MAXIMUM NUMBER OF ELEMENTS THE EPSILON
!           TABLE CAN CONTAIN. IF THIS NUMBER IS REACHED, THE UPPER
!           DIAGONAL OF THE EPSILON TABLE IS DELETED.
!
!***FIRST EXECUTABLE STATEMENT  QELG
      EPMACH = R1MACH(4)
      OFLOW = R1MACH(2)
      NRES = NRES+1
      ABSERR = OFLOW
      RESULT = EPSTAB(N)
      IF(N.LT.3) GO TO 100
      LIMEXP = 50
      EPSTAB(N+2) = EPSTAB(N)
      NEWELM = (N-1)/2
      EPSTAB(N) = OFLOW
      NUM = N
      K1 = N
      DO 40 I = 1,NEWELM
        K2 = K1-1
        K3 = K1-2
        RES = EPSTAB(K1+2)
        E0 = EPSTAB(K3)
        E1 = EPSTAB(K2)
        E2 = RES
        E1ABS = ABS(E1)
        DELTA2 = E2-E1
        ERR2 = ABS(DELTA2)
        TOL2 = AMAX1(ABS(E2),E1ABS)*EPMACH
        DELTA3 = E1-E0
        ERR3 = ABS(DELTA3)
        TOL3 = AMAX1(E1ABS,ABS(E0))*EPMACH
        IF(ERR2.GT.TOL2.OR.ERR3.GT.TOL3) GO TO 10
!
!           IF E0, E1 AND E2 ARE EQUAL TO WITHIN MACHINE
!           ACCURACY, CONVERGENCE IS ASSUMED.
!           RESULT = E2
!           ABSERR = ABS(E1-E0)+ABS(E2-E1)
!
        RESULT = RES
        ABSERR = ERR2+ERR3
! ***JUMP OUT OF DO-LOOP
        GO TO 100
   10   E3 = EPSTAB(K1)
        EPSTAB(K1) = E1
        DELTA1 = E1-E3
        ERR1 = ABS(DELTA1)
        TOL1 = AMAX1(E1ABS,ABS(E3))*EPMACH
!
!           IF TWO ELEMENTS ARE VERY CLOSE TO EACH OTHER, OMIT
!           A PART OF THE TABLE BY ADJUSTING THE VALUE OF N
!
        IF(ERR1.LE.TOL1.OR.ERR2.LE.TOL2.OR.ERR3.LE.TOL3) GO TO 20
        SS = 0.1E+01/DELTA1+0.1E+01/DELTA2-0.1E+01/DELTA3
        EPSINF = ABS(SS*E1)
!
!           TEST TO DETECT IRREGULAR BEHAVIOUR IN THE TABLE, AND
!           EVENTUALLY OMIT A PART OF THE TABLE ADJUSTING THE VALUE
!           OF N.
!
        IF(EPSINF.GT.0.1E-03) GO TO 30
   20   N = I+I-1
! ***JUMP OUT OF DO-LOOP
        GO TO 50
!
!           COMPUTE A NEW ELEMENT AND EVENTUALLY ADJUST
!           THE VALUE OF RESULT.
!
   30   RES = E1+0.1E+01/SS
        EPSTAB(K1) = RES
        K1 = K1-2
        ERROR = ERR2+ABS(RES-E2)+ERR3
        IF(ERROR.GT.ABSERR) GO TO 40
        ABSERR = ERROR
        RESULT = RES
   40 CONTINUE
!
!           SHIFT THE TABLE.
!
   50 IF(N.EQ.LIMEXP) N = 2*(LIMEXP/2)-1
      IB = 1
      IF((NUM/2)*2.EQ.NUM) IB = 2
      IE = NEWELM+1
      DO 60 I=1,IE
        IB2 = IB+2
        EPSTAB(IB) = EPSTAB(IB2)
        IB = IB2
   60 CONTINUE
      IF(NUM.EQ.N) GO TO 80
      INDX = NUM-N+1
      DO 70 I = 1,N
        EPSTAB(I)= EPSTAB(INDX)
        INDX = INDX+1
   70 CONTINUE
   80 IF(NRES.GE.4) GO TO 90
      RES3LA(NRES) = RESULT
      ABSERR = OFLOW
      GO TO 100
!
!           COMPUTE ERROR ESTIMATE
!
   90 ABSERR = ABS(RESULT-RES3LA(3))+ABS(RESULT-RES3LA(2))   &
        +ABS(RESULT-RES3LA(1))
      RES3LA(1) = RES3LA(2)
      RES3LA(2) = RES3LA(3)
      RES3LA(3) = RESULT
  100 ABSERR = AMAX1(ABSERR,0.5E+01*EPMACH*ABS(RESULT))
      RETURN
      END SUBROUTINE QELG
!DPLT SUBROUTINE QK15I(F,BOUN,INF,A,B,RESULT,ABSERR,RESABS,RESASC)
      SUBROUTINE QK15I(BOUN,INF,A,B,RESULT,ABSERR,RESABS,RESASC)
!
!   2013/06: MODIFIED FOR DATAPLOT BY ALAN HECKERT.  CHANGES INCLUDE:
!
!            1) MODIFY TO USE DATAPLOT "DPWRST" FOR PRINTING OUTPUT.
!            2) MODIFY TO USE DATAPLOT FUNCTION DEFINITIONS (I.E.,
!               CALL COMPIM TO EVALUATE FUNCTION).
!
!***BEGIN PROLOGUE  QK15I
!***DATE WRITTEN   800101   (YYMMDD)
!***REVISION DATE  830518   (YYMMDD)
!***CATEGORY NO.  H2A3A2,H2A4A2
!***KEYWORDS  15-POINT TRANSFORMED GAUSS-KRONROD RULES
!***AUTHOR  PIESSENS, ROBERT, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!           DE DONCKER, ELISE, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!***PURPOSE  The original (infinite integration range is mapped
!            onto the interval (0,1) and (A,B) is a part of (0,1).
!            it is the purpose to compute
!            I = Integral of transformed integrand over (A,B),
!            J = Integral of ABS(Transformed Integrand) over (A,B).
!***DESCRIPTION
!
!           Integration Rule
!           Standard Fortran subroutine
!           Real version
!
!           PARAMETERS
!            ON ENTRY
!              F      - Real
!                       Fuction subprogram defining the integrand
!                       FUNCTION F(X). The actual name for F needs to be
!                       Declared E X T E R N A L in the calling program.
!
!              BOUN   - Real
!                       Finite bound of original integration
!                       Range (SET TO ZERO IF INF = +2)
!
!              INF    - Integer
!                       If INF = -1, the original interval is
!                                   (-INFINITY,BOUND),
!                       If INF = +1, the original interval is
!                                   (BOUND,+INFINITY),
!                       If INF = +2, the original interval is
!                                   (-INFINITY,+INFINITY) AND
!                       The integral is computed as the sum of two
!                       integrals, one over (-INFINITY,0) and one over
!                       (0,+INFINITY).
!
!              A      - Real
!                       Lower limit for integration over subrange
!                       of (0,1)
!
!              B      - Real
!                       Upper limit for integration over subrange
!                       of (0,1)
!
!            ON RETURN
!              RESULT - Real
!                       Approximation to the integral I
!                       Result is computed by applying the 15-POINT
!                       KRONROD RULE(RESK) obtained by optimal addition
!                       of abscissae to the 7-POINT GAUSS RULE(RESG).
!
!              ABSERR - Real
!                       Estimate of the modulus of the absolute error,
!                       WHICH SHOULD EQUAL or EXCEED ABS(I-RESULT)
!
!              RESABS - Real
!                       Approximation to the integral J
!
!              RESASC - Real
!                       Approximation to the integral of
!                       ABS((TRANSFORMED INTEGRAND)-I/(B-A)) over (A,B)
!***REFERENCES  (NONE)
!***ROUTINES CALLED  R1MACH
!***END PROLOGUE  QK15I
!
      REAL A,ABSC,ABSC1,ABSC2,ABSERR,B,BOUN,CENTR,   &
        DINF,R1MACH,EPMACH,FC,FSUM,FVAL1,FVAL2,FV1,   &
        FV2,HLGTH,RESABS,RESASC,RESG,RESK,RESKH,RESULT,TABSC1,TABSC2,   &
        UFLOW,WG,WGK,XGK
      INTEGER INF,J,MIN0
!DPLT EXTERNAL F
!
      DIMENSION FV1(7),FV2(7),XGK(8),WGK(8),WG(8)
!
!           THE ABSCISSAE AND WEIGHTS ARE SUPPLIED FOR THE INTERVAL
!           (-1,1).  BECAUSE OF SYMMETRY ONLY THE POSITIVE ABSCISSAE AND
!           THEIR CORRESPONDING WEIGHTS ARE GIVEN.
!
!           XGK    - ABSCISSAE OF THE 15-POINT KRONROD RULE
!                    XGK(2), XGK(4), ... ABSCISSAE OF THE 7-POINT
!                    GAUSS RULE
!                    XGK(1), XGK(3), ...  ABSCISSAE WHICH ARE OPTIMALLY
!                    ADDED TO THE 7-POINT GAUSS RULE
!
!           WGK    - WEIGHTS OF THE 15-POINT KRONROD RULE
!
!           WG     - WEIGHTS OF THE 7-POINT GAUSS RULE, CORRESPONDING
!                    TO THE ABSCISSAE XGK(2), XGK(4), ...
!                    WG(1), WG(3), ... ARE SET TO ZERO.
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA XGK(1),XGK(2),XGK(3),XGK(4),XGK(5),XGK(6),XGK(7),   &
        XGK(8)/   &
           0.9914553711208126E+00,     0.9491079123427585E+00,   &
           0.8648644233597691E+00,     0.7415311855993944E+00,   &
           0.5860872354676911E+00,     0.4058451513773972E+00,   &
           0.2077849550078985E+00,     0.0000000000000000E+00/
!
      DATA WGK(1),WGK(2),WGK(3),WGK(4),WGK(5),WGK(6),WGK(7),   &
        WGK(8)/   &
           0.2293532201052922E-01,     0.6309209262997855E-01,   &
           0.1047900103222502E+00,     0.1406532597155259E+00,   &
           0.1690047266392679E+00,     0.1903505780647854E+00,   &
           0.2044329400752989E+00,     0.2094821410847278E+00/
!
      DATA WG(1),WG(2),WG(3),WG(4),WG(5),WG(6),WG(7),WG(8)/   &
           0.0000000000000000E+00,     0.1294849661688697E+00,   &
           0.0000000000000000E+00,     0.2797053914892767E+00,   &
           0.0000000000000000E+00,     0.3818300505051189E+00,   &
           0.0000000000000000E+00,     0.4179591836734694E+00/
!
!
!           LIST OF MAJOR VARIABLES
!           -----------------------
!
!           CENTR  - MID POINT OF THE INTERVAL
!           HLGTH  - HALF-LENGTH OF THE INTERVAL
!           ABSC*  - ABSCISSA
!           TABSC* - TRANSFORMED ABSCISSA
!           FVAL*  - FUNCTION VALUE
!           RESG   - RESULT OF THE 7-POINT GAUSS FORMULA
!           RESK   - RESULT OF THE 15-POINT KRONROD FORMULA
!           RESKH  - APPROXIMATION TO THE MEAN VALUE OF THE TRANSFORMED
!                    INTEGRAND OVER (A,B), I.E. TO I/(B-A)
!
!           MACHINE DEPENDENT CONSTANTS
!           ---------------------------
!
!           EPMACH IS THE LARGEST RELATIVE SPACING.
!           UFLOW IS THE SMALLEST POSITIVE MAGNITUDE.
!
!***FIRST EXECUTABLE STATEMENT  QK15I
      EPMACH = R1MACH(4)
      UFLOW = R1MACH(1)
      DINF = MIN0(1,INF)
!
      CENTR = 0.5E+00*(A+B)
      HLGTH = 0.5E+00*(B-A)
      TABSC1 = BOUN+DINF*(0.1E+01-CENTR)/CENTR
!DPLT FVAL1 = F(TABSC1)
!DPLT IF(INF.EQ.2) FVAL1 = FVAL1+F(-TABSC1)
      CALL INTFCN(TABSC1,FVAL1)
      IF(INF.EQ.2)THEN
        ATEMP=-TABSC1
        CALL INTFCN(ATEMP,FVALT)
        FVAL1=FVAL1 + FVALT
      ENDIF
!
      FC = (FVAL1/CENTR)/CENTR
!
!           COMPUTE THE 15-POINT KRONROD APPROXIMATION TO
!           THE INTEGRAL, AND ESTIMATE THE ERROR.
!
      RESG = WG(8)*FC
      RESK = WGK(8)*FC
      RESABS = ABS(RESK)
      DO 10 J=1,7
        ABSC = HLGTH*XGK(J)
        ABSC1 = CENTR-ABSC
        ABSC2 = CENTR+ABSC
        TABSC1 = BOUN+DINF*(0.1E+01-ABSC1)/ABSC1
        TABSC2 = BOUN+DINF*(0.1E+01-ABSC2)/ABSC2
!DPLT   FVAL1 = F(TABSC1)
!DPLT   FVAL2 = F(TABSC2)
!DPLT   IF(INF.EQ.2) FVAL1 = FVAL1+F(-TABSC1)
!DPLT   IF(INF.EQ.2) FVAL2 = FVAL2+F(-TABSC2)
        CALL INTFCN(TABSC1,FVAL1)
        CALL INTFCN(TABSC2,FVAL2)
        IF(INF.EQ.2)THEN
          ATEMP=-TABSC1
          CALL INTFCN(ATEMP,FVALT)
          FVAL1=FVAL1 + FVALT
          ATEMP=-TABSC2
          CALL INTFCN(ATEMP,FVALT)
          FVAL2=FVAL2 + FVALT
        ENDIF
!
        FVAL1 = (FVAL1/ABSC1)/ABSC1
        FVAL2 = (FVAL2/ABSC2)/ABSC2
        FV1(J) = FVAL1
        FV2(J) = FVAL2
        FSUM = FVAL1+FVAL2
        RESG = RESG+WG(J)*FSUM
        RESK = RESK+WGK(J)*FSUM
        RESABS = RESABS+WGK(J)*(ABS(FVAL1)+ABS(FVAL2))
   10 CONTINUE
      RESKH = RESK*0.5E+00
      RESASC = WGK(8)*ABS(FC-RESKH)
      DO 20 J=1,7
        RESASC = RESASC+WGK(J)*(ABS(FV1(J)-RESKH)+ABS(FV2(J)-RESKH))
   20 CONTINUE
      RESULT = RESK*HLGTH
      RESASC = RESASC*HLGTH
      RESABS = RESABS*HLGTH
      ABSERR = ABS((RESK-RESG)*HLGTH)
      IF(RESASC.NE.0.0E+00.AND.ABSERR.NE.0.E0) ABSERR = RESASC*   &
       AMIN1(0.1E+01,(0.2E+03*ABSERR/RESASC)**1.5E+00)
      IF(RESABS.GT.UFLOW/(0.5E+02*EPMACH)) ABSERR = AMAX1   &
       ((EPMACH*0.5E+02)*RESABS,ABSERR)
      RETURN
      END SUBROUTINE QK15I
      SUBROUTINE QPSRT(LIMIT,LAST,MAXERR,ERMAX,ELIST,IORD,NRMAX)
!***BEGIN PROLOGUE  QPSRT
!   PART OF QAGI CODE.
!     THIS PROLOGUE HAS BEEN REMOVED FOR REASONS OF SPACE
!     FOR A COMPLETE COPY OF THIS ROUTINE CONTACT THE AUTHORS
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!***END PROLOGUE  QPSRT
!
      REAL ELIST,ERMAX,ERRMAX,ERRMIN
      INTEGER I,IBEG,IDO,IORD,ISUCC,J,JBND,JUPBN,K,LAST,LIMIT,MAXERR,   &
        NRMAX
      DIMENSION ELIST(LAST),IORD(LAST)
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!           CHECK WHETHER THE LIST CONTAINS MORE THAN
!           TWO ERROR ESTIMATES.
!
!***FIRST EXECUTABLE STATEMENT  QPSRT
      IF(LAST.GT.2) GO TO 10
      IORD(1) = 1
      IORD(2) = 2
      GO TO 90
!
!           THIS PART OF THE ROUTINE IS ONLY EXECUTED
!           IF, DUE TO A DIFFICULT INTEGRAND, SUBDIVISION
!           INCREASED THE ERROR ESTIMATE. IN THE NORMAL CASE
!           THE INSERT PROCEDURE SHOULD START AFTER THE
!           NRMAX-TH LARGEST ERROR ESTIMATE.
!
   10 ERRMAX = ELIST(MAXERR)
      IF(NRMAX.EQ.1) GO TO 30
      IDO = NRMAX-1
      DO 20 I = 1,IDO
        ISUCC = IORD(NRMAX-1)
! ***JUMP OUT OF DO-LOOP
        IF(ERRMAX.LE.ELIST(ISUCC)) GO TO 30
        IORD(NRMAX) = ISUCC
        NRMAX = NRMAX-1
   20    CONTINUE
!
!           COMPUTE THE NUMBER OF ELEMENTS IN THE LIST TO
!           BE MAINTAINED IN DESCENDING ORDER. THIS NUMBER
!           DEPENDS ON THE NUMBER OF SUBDIVISIONS STILL
!           ALLOWED.
!
   30 JUPBN = LAST
      IF(LAST.GT.(LIMIT/2+2)) JUPBN = LIMIT+3-LAST
      ERRMIN = ELIST(LAST)
!
!           INSERT ERRMAX BY TRAVERSING THE LIST TOP-DOWN,
!           STARTING COMPARISON FROM THE ELEMENT ELIST(IORD(NRMAX+1)).
!
      JBND = JUPBN-1
      IBEG = NRMAX+1
      IF(IBEG.GT.JBND) GO TO 50
      DO 40 I=IBEG,JBND
        ISUCC = IORD(I)
! ***JUMP OUT OF DO-LOOP
        IF(ERRMAX.GE.ELIST(ISUCC)) GO TO 60
        IORD(I-1) = ISUCC
   40 CONTINUE
   50 IORD(JBND) = MAXERR
      IORD(JUPBN) = LAST
      GO TO 90
!
!           INSERT ERRMIN BY TRAVERSING THE LIST BOTTOM-UP.
!
   60 IORD(I-1) = MAXERR
      K = JBND
      DO 70 J=I,JBND
        ISUCC = IORD(K)
! ***JUMP OUT OF DO-LOOP
        IF(ERRMIN.LT.ELIST(ISUCC)) GO TO 80
        IORD(K+1) = ISUCC
        K = K-1
   70 CONTINUE
      IORD(I) = LAST
      GO TO 90
   80 IORD(K+1) = LAST
!
!           SET MAXERR AND ERMAX.
!
   90 MAXERR = IORD(NRMAX)
      ERMAX = ELIST(MAXERR)
      RETURN
      END SUBROUTINE QPSRT
      SUBROUTINE QQRANG(X,N,IWRITE,XTEMP,MAXNXT,QUANT,XQRANG,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE Q-QUANTILE RANGE
!              OF THE DATA IN THE INPUT VECTOR X.  THIS IS DEFINED AS
!
!                 X(1-q) - X(q)
!
!              WHERE X(q) IS THE q-TH QUANTILE OF THE DATA.  THIS
!              IS A MORE GENERAL FORM OF THE INTERQUARTILE RANGE.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --QUANT  = THE DESIRED QUANTILE
!     OUTPUT ARGUMENTS--XQRANG = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE Q-QUANTILE RANGE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE Q-QUANTILE RANGE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--RAND WILCOX (1997), "INTRODUCTION TO ROBUST
!                 ESTIMATION AND HYPOTHESIS TESTING", ACADEMIC PRESS,
!                 PP. 24-25.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.9
!     ORIGINAL VERSION--SEPTEMBER 2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPQR'
      ISUBN2='AN  '
      IERROR='NO'
!
      NI=0
      NIP1=0
      ANI=0.0
      A2NI=0.0
      REM=0.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RANG')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF QQRANG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,IBUGA3
   53   FORMAT('N,IBUGA3 = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               *******************************
!               **  COMPUTE Q-QUANTILE RANGE **
!               *******************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(QUANT.GT.1.0 .AND. QUANT.LT.100.0)THEN
        QUANT=QUANT/100.
      ENDIF
      IF(QUANT.GT.0.5 .AND. QUANT.LT.1.0)THEN
        QUANT=1.0 - QUANT
      ENDIF
      IF(QUANT.LE.0.0 .OR. QUANT.GE.0.5)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
  102   FORMAT('      THE SPECIFIED QUANTILE IS OUTSIDE THE ',   &
               '(0,0.5) RANGE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,107)QUANT
  107   FORMAT('      THE SPECIFIED VALUE OF THE QUANTILE  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN Q-QUANTILE RANGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XLOWQU=0.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XLOWQU=0.0
      GO TO 9000
  139 CONTINUE
!
!               ***********************************
!               **  STEP 2--                     **
!               **  COMPUTE THE Q-QUANTILE RANGE **
!               ***********************************
!
      CALL SORT(X,N,XTEMP)
!
      P=QUANT
      ANI=P*(AN+1.0)
      NI=INT(ANI)
      A2NI=REAL(NI)
      REM=ANI-A2NI
      NIP1=NI+1
      IF(NI.LE.1)NI=1
      IF(NI.GE.N)NI=N
      IF(NIP1.LE.1)NIP1=1
      IF(NIP1.GE.N)NIP1=N
      XLOW=(1.0-REM)*XTEMP(NI)+REM*XTEMP(NIP1)
!
      P=1.0 - QUANT
      ANI=P*(AN+1.0)
      NI=INT(ANI)
      A2NI=REAL(NI)
      REM=ANI-A2NI
      NIP1=NI+1
      IF(NI.LE.1)NI=1
      IF(NI.GE.N)NI=N
      IF(NIP1.LE.1)NIP1=1
      IF(NIP1.GE.N)NIP1=N
      XUPP=(1.0-REM)*XTEMP(NI)+REM*XTEMP(NIP1)
!
      XQRANG=XUPP - XLOW
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND.IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XLOWQU
  811   FORMAT('THE Q-QUANTILE RANGE OF THE ',I8,' OBSERVATIONS = ',   &
               G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF QQRANG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)ANI,NI,A2NI,REM,NIP1
 9014   FORMAT('ANI,NI,A2NI,REM,NIP1 = ',G15.7,I8,2G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IERROR,XLOW,XUPP,XQRANG
 9015   FORMAT('IERROR,XLOW,XUPP,XQRANG = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE QQRANG
      SUBROUTINE QRAUX1(NR,N,R,I)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! INTERCHANGE ROWS I,I+1 OF THE UPPER HESSENBERG MATRIX R,
! COLUMNS I TO N
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF MATRIX
! R(N,N)      <--> UPPER HESSENBERG MATRIX
! I            --> INDEX OF ROW TO INTERCHANGE (I.LT.N)
!
      DIMENSION R(NR,1)
      DO 10 J=I,N
        TMP=R(I,J)
        R(I,J)=R(I+1,J)
        R(I+1,J)=TMP
   10 CONTINUE
      RETURN
      END SUBROUTINE QRAUX1
      SUBROUTINE QRAUX2(NR,N,R,I,A,B)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! PRE-MULTIPLY R BY THE JACOBI ROTATION J(I,I+1,A,B)
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF MATRIX
! R(N,N)      <--> UPPER HESSENBERG MATRIX
! I            --> INDEX OF ROW
! A            --> SCALAR
! B            --> SCALAR
!
      DIMENSION R(NR,1)
      DEN=SQRT(A*A + B*B)
      C=A/DEN
      S=B/DEN
      DO 10 J=I,N
        Y=R(I,J)
        Z=R(I+1,J)
        R(I,J)=C*Y - S*Z
        R(I+1,J)=S*Y + C*Z
   10 CONTINUE
      RETURN
      END SUBROUTINE QRAUX2
      SUBROUTINE QRUPDT(NR,N,A,U,V)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! FIND AN ORTHOGONAL (N*N) MATRIX (Q*) AND AN UPPER TRIANGULAR (N*N)
! MATRIX (R*) SUCH THAT (Q*)(R*)=R+U(V+)
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(N,N)      <--> ON INPUT:  CONTAINS R
!                  ON OUTPUT: CONTAINS (R*)
! U(N)         --> VECTOR
! V(N)         --> VECTOR
!
      DIMENSION A(NR,1)
      DIMENSION U(N),V(N)
!
! DETERMINE LAST NON-ZERO IN U(.)
!
      K=N
   10 IF(U(K).NE.0. .OR. K.EQ.1) GO TO 20
!     IF(U(K).EQ.0. .AND. K.GT.1)
!     THEN
        K=K-1
        GO TO 10
!     ENDIF
!
! (K-1) JACOBI ROTATIONS TRANSFORM
!     R + U(V+) --> (R*) + (U(1)*E1)(V+)
! WHICH IS UPPER HESSENBERG
!
   20 IF(K.LE.1) GO TO 40
        KM1=K-1
        DO 30 II=1,KM1
          I=KM1-II+1
          IF(U(I).NE.0.) GO TO 25
!         IF(U(I).EQ.0.)
!         THEN
            CALL QRAUX1(NR,N,A,I)
            U(I)=U(I+1)
            GO TO 30
!         ELSE
   25       CALL QRAUX2(NR,N,A,I,U(I),-U(I+1))
            U(I)=SQRT(U(I)*U(I) + U(I+1)*U(I+1))
!         ENDIF
   30   CONTINUE
!     ENDIF
!
! R <-- R + (U(1)*E1)(V+)
!
   40 DO 50 J=1,N
        A(1,J)=A(1,J) +U(1)*V(J)
   50 CONTINUE
!
! (K-1) JACOBI ROTATIONS TRANSFORM UPPER HESSENBERG R
! TO UPPER TRIANGULAR (R*)
!
      IF(K.LE.1) GO TO 100
        KM1=K-1
        DO 80 I=1,KM1
          IF(A(I,I).NE.0.) GO TO 70
!         IF(A(I,I).EQ.0.)
!         THEN
            CALL QRAUX1(NR,N,A,I)
            GO TO 80
!         ELSE
   70       T1=A(I,I)
            T2=-A(I+1,I)
            CALL QRAUX2(NR,N,A,I,T1,T2)
!         ENDIF
   80   CONTINUE
!     ENDIF
  100 RETURN
      END SUBROUTINE QRUPDT
      double precision function qtrng(p, v, r, ifault)
      implicit double precision (a-h, o-z)
!
!        Algorithm AS 190.1  Appl. Statist. (1983) Vol.32, No. 2
!
!        Approximates the quantile p for a studentized range
!        distribution having v degrees of freedom and r samples
!        for probability p, p.ge.0.90 .and. p.le.0.99.
!
!        Uses functions  alnorm, ppnd, prtrng and qtrng0 -
!        Algorithms AS 66, AS 111, AS 190 and AS 190.2
!
      double precision p, v, r, pcut, p75, p80, p90, p99, p995
      double precision p175, one, two, five
      double precision q1, p1, q2, p2, e1, e2
      double precision eps
      data jmax, pcut, p75, p80, p90, p99, p995, p175, one, two, five   &
        /8, 0.001d0, 0.75d0, 0.80d0, 0.90d0, 0.99d0, 0.995d0, 1.75d0,   &
        1.0d0, 2.0d0, 5.0d0/
      data eps/1.0d-4/
!
!        Check input parameters
!
      qtrng = 0.0d0
      p2=0.0d0
      ifault = 0
      nfault = 0
      if (v .lt. one .or. r.lt. two) ifault = 1
      if (p .lt. p90 .or. p .gt. p99) ifault = 2
      if (ifault .ne. 0) go to 99
!
!        Obtain initial values
!
      q1 = qtrng0(p, v, r, nfault)
      if (nfault .ne. 0) go to 99
      p1 = prtrng(q1, v, r, nfault)
      if (nfault .ne. 0) go to 99
      qtrng = q1
      if (abs(p1-p) .lt. pcut) go to 99
      if (p1 .gt. p) p1 = p175 * p - p75 * p1
      if (p1 .lt. p) p2 = p + (p - p1) * (one - p) / (one - p1) * p75
      if (p2 .lt. p80) p2 = p80
      if (p2 .gt. p995) p2 = p995
      q2 = qtrng0(p2, v, r, nfault)
      if (nfault .ne. 0) go to 99
!
!        Refine approximation
!
      do 14 j = 2, jmax
      p2 = prtrng(q2, v, r, nfault)
      if (nfault .ne. 0) go to 99
      e1 = p1 - p
      e2 = p2 - p
      qtrng = (q1 + q2) / two
      d = e2 - e1
      if (abs(d) .gt. eps) qtrng = (e2 * q1 - e1 * q2) / d
      if(abs(e1) .lt. abs(e2)) go to 12
      q1 = q2
      p1 = p2
   12   if (abs(p1 - p) .lt. pcut * five) go to 99
      q2 = qtrng
   14 continue
!
   99 if (nfault .ne. 0) ifault = 9
      return
      end
      double precision function qtrng0(p, v, r, ifault)
      implicit double precision (a-h, o-z)
!
!        Algorithm AS 190.2  Appl. Statist. (1983) Vol.32, No.2
!
!        Calculates an initial quantile p for a studentized range
!        distribution having v degrees of freedom and r samples
!        for probability p, p.gt.0.80 .and. p.lt.0.995.
!
!        Uses function ppnd - Algorithm AS 111
!
      double precision p, v, r, q, t, vmax, half, one, four, c1, c2, c3
      double precision c4, c5
      real ppnd
      data vmax, half, one, four, c1, c2, c3, c4, c5 / 120.0d0, 0.5d0,   &
        1.0d0, 4.0d0, 0.8843d0, 0.2368d0, 1.214d0, 1.208d0, 1.4142d0/
!
      t=dble(ppnd(real(half + half * p),ifault))
      if (v .lt. vmax) t = t + (t * t* t + t) / v / four
      q = c1 - c2 * t
      if (v .lt. vmax) q = q - c3 / v + c4 * t / v
      qtrng0 = t * (q * log(r - one) + c5)
      return
      end
      SUBROUTINE QUAFIT(IT,I1,I2,XS,YS,WH,WV,N,XMAXHF,I3,I4,   &
      ALPHA,BETA1,BETA2,PRED,RES,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--CARRY OUT A LEAST SQUARES WEIGHTED QUARADITIC FIT
!              OF THE DATA IN LOCATIONS I1 TO I2
!              OF THE HORIZONTALLY SORTED DATA
!              IN VARIABLES XS(.) AND YS(.).
!              AFTER THE FIT IS DONE, COMPUTE PREDICTED VALUES
!              AND RESIDUALS FOR ELEMENTS I3 TO I4 OF XS(.).
!              THIS ROUTINE IS USED FOR UNIVARIATE LOWESS OF DEGREE 2.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/4
!     ORIGINAL VERSION--MARCH      1994
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
      DOUBLE PRECISION DSUM6
      DOUBLE PRECISION DSUM7
      DOUBLE PRECISION DSUM8
!
!---------------------------------------------------------------------
!
      DIMENSION XMAT(3,3)
      DIMENSION IPVT(3)
      DIMENSION RHS(3)
      DIMENSION XS(*)
      DIMENSION YS(*)
      DIMENSION WH(*)
      DIMENSION WV(*)
      DIMENSION PRED(*)
      DIMENSION RES(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='QUAF'
      ISUBN2='IT  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'AFIT')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF QUAFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBRO,IBUGA3,IERROR
   52 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IT,I1,I2,N,I3,I4
   53 FORMAT('IT,I1,I2,N,I3,I4 = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)XMAXHF
   54 FORMAT('XMAXHF = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 63
      DO 61 I=1,N
      WRITE(ICOUT,62)I,XS(I),YS(I),WH(I),WV(I)
   62 FORMAT('I,XS(I),YS(I),WH(I),WV(I) = ',I8,4E15.7)
      CALL DPWRST('XXX','BUG ')
   61 CONTINUE
   63 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.GE.1)GO TO 119
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN QUAFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT FULL SAMPLE SIZE,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      FOR WHICH LOWESS HORIZONTAL WEIGHTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      ARE TO BE COMPUTED, MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)N
  116 FORMAT('      THE FULL SAMPLE SIZE N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  119 CONTINUE
!
      IF(IT.GE.1)GO TO 129
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** ERROR IN QUAFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,122)
  122 FORMAT('      THE INPUT TARGET OBSERVATION INDEX')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,123)
  123 FORMAT('      FOR WHICH A LOWESS IS TO BE CARRIED OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,124)N
  124 FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVE).')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,125)
  125 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,126)IT
  126 FORMAT('      THE TARGET OBSERVATION INDEX IT = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  129 CONTINUE
!
      IF(I1.LE.I2)GO TO 139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,131)
  131 FORMAT('***** ERROR IN QUAFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,132)
  132 FORMAT('      THE  NEIGHBORHOOD LOWER INDEX')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,133)
  133 FORMAT('      FOR WHICH A LOWESS IS TO BE CARRIED OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,134)
  134 FORMAT('      MUST NOT EXCEED THE NEIGHBORHOOD UPPER INDEX.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,135)
  135 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)IT
  136 FORMAT('      THE NEIGHBORHOOD INDICES I1 AND I2 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  139 CONTINUE
!
      IF(I3.LE.I4)GO TO 149
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,141)
  141 FORMAT('***** ERROR IN QUAFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,142)
  142 FORMAT('      THE  DESIRED LOWER INDEX FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,143)
  143 FORMAT('      LOWESS PREDICTED VALUES ARE TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,144)
  144 FORMAT('      MUST NOT EXCEED THE DESIRED UPPER INDEX.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,145)
  145 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,146)I3,I4
  146 FORMAT('      THE DESIRED INDICES I3 AND I4 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  149 CONTINUE
!
!               ***********************************************
!               **  STEP 11--                                **
!               **  CARRY OUT A LEAST SQUARES WEIGHTED       **
!               **  QUAFIT FIT                               **
!               ***********************************************
!
      IF(XMAXHF.LE.0.0)GO TO 1200
      GO TO 1300
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  TREAT THE CASE WHEN ALL HORIXONTAL AXIS  **
!               **  VALUES ARE IDENTICAL                     **
!               ***********************************************
!
 1200 CONTINUE
      NN=I2-I1+1
      ANN=NN
!
      SUMY=0.0
      SUMW=0.0
      DO 1210 I=I1,I2
      W=WH(I)*WV(I)
      SUMY=SUMY+W*YS(I)
      SUMW=SUMW+W
 1210 CONTINUE
      YBAR=SUMY/SUMW
!
      ALPHA=YBAR
      BETA1=0.0
      BETA2=0.0
!
      DO 1220 I=I3,I4
      PRED(I)=ALPHA
      RES(I)=YS(I)-PRED(I)
 1220 CONTINUE
!
      GO TO 9000
!               *********************************************
!               **  STEP 13--                              **
!               **  TREAT THE CASE WHEN AT LEAST 1         **
!               **  HORIZONTAL AXIS VALUE IS DIFFERENT     **
!               *********************************************
!
 1300 CONTINUE
      NN=I2-I1+1
      ANN=NN
!
      SUMW=0.0
      DO 1310 I=I1,I2
      W=WH(I)*WV(I)
      SUMW=SUMW+W
 1310 CONTINUE
!
      IF(SUMW.GT.0.0)GO TO 1319
      WRITE(ICOUT,1311)
 1311 FORMAT('***** ERROR IN QUAFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1312)
 1312 FORMAT('      SUM OF WEIGHTS = 0')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1313)IT,I1,I2,N
 1313 FORMAT('IT,I1,I2,N = ',4I8)
      CALL DPWRST('XXX','BUG ')
      DO 1314 I=I1,I2
      WPROD=WH(I)*WV(I)
      WRITE(ICOUT,1315)I,WH(I),WV(I),WPROD
 1315 FORMAT('I,WH(I),WV(I),WPROD = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 1314 CONTINUE
      IERROR='YES'
      GO TO 9000
 1319 CONTINUE
!
!  FOR A QUADRATIC, WEIGHTED FIT, THE NORMAL EQUATIONS ARE:
!  [SUM(W)      SUM(W*X)      SUM(W*X**2)]  [ALPHA]   [SUM(W*Y)  ]
!  [SUM(W*X)    SUM(W*X**2)   SUM(W*X**3)]  [BETA1] = [SUM(W*X*Y]
!  [SUM(W*X**2) SUM(W*X**3)   SUM(W*X**4)]  [BETA2]   [SUM(W*X**2*Y]
!
!  FORM THE FOLLOWING SUMS (IN DOUBLE PRECISION):
!  1) W
!  2) W*X
!  3) W*X**2
!  4) W*X**3
!  5) W*X**4
!  6) W*Y
!  7) W*Y*X
!  8) W*Y*X**2
!
      DSUM1=0.0
      DSUM2=0.0
      DSUM3=0.0
      DSUM4=0.0
      DSUM5=0.0
      DSUM6=0.0
      DSUM7=0.0
      DSUM8=0.0
      DO 1320 I=I1,I2
        W=WH(I)*WV(I)
        DSUM1=DSUM1+W
        DSUM2=DSUM2+W*XS(I)
        DSUM3=DSUM3+W*XS(I)*XS(I)
        DSUM4=DSUM4+W*XS(I)**3
        DSUM5=DSUM5+W*XS(I)**4
        DSUM6=DSUM6+W*YS(I)
        DSUM7=DSUM7+W*YS(I)*XS(I)
        DSUM8=DSUM8+W*YS(I)*XS(I)*XS(I)
 1320 CONTINUE
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'AFIT')GO TO 1390
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1351)
 1351 FORMAT('***** IN THE MIDDLE OF QUAFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1352)DSUM1,DSUM2,DSUM3,DSUM4
 1352 FORMAT('DSUM1,DSUM2,DSUM3,DSUM4 = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1353)DSUM5,DSUM6,DSUM7,DSUM8
 1353 FORMAT('DSUM5,DSUM6,DSUM7,DSUM8 = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
 1390 CONTINUE
!
      XMAT(1,1)=DSUM1
      XMAT(2,1)=DSUM2
      XMAT(3,1)=DSUM3
      XMAT(1,2)=DSUM2
      XMAT(2,2)=DSUM3
      XMAT(2,3)=DSUM4
      XMAT(1,3)=DSUM3
      XMAT(2,3)=DSUM4
      XMAT(3,3)=DSUM5
      RHS(1)=DSUM6
      RHS(2)=DSUM7
      RHS(3)=DSUM8
      IPVT(1)=0
      IPVT(2)=0
      IPVT(3)=0
!
!  USE LINPACK TO SOLVE 3X3 EQUATION
!
      INFO=0
      NP=3
      CALL SGEFA(XMAT,NP,NP,IPVT,INFO)
      IF(INFO.NE.0)THEN
        ALPHA=0.0
        BETA1=0.0
        BETA2=0.0
        IERROR='YES'
      ELSE
        IJOB=0
        CALL SGESL(XMAT,NP,NP,IPVT,RHS,IJOB)
        ALPHA=RHS(1)
        BETA1=RHS(2)
        BETA2=RHS(3)
      END IF
!
      DO 1340 I=I3,I4
      PRED(I)=ALPHA+BETA1*XS(I)+BETA2*XS(I)*XS(I)
      RES(I)=YS(I)-PRED(I)
 1340 CONTINUE
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'AFIT')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF QUAFIT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ISUBRO,IBUGA3,IERROR
 9012 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IT,I1,I2,N,I3,I4
 9013 FORMAT('IT,I1,I2,N,I3,I4 = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)XMAXHF
 9014 FORMAT('XMAXHF = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 9033
      DO 9031 I=I1,I2
      WRITE(ICOUT,9032)I,XS(I),YS(I),WH(I),WV(I)
 9032 FORMAT('I,XS(I),YS(I),WH(I),WV(I) = ',I8,4E15.7)
      CALL DPWRST('XXX','BUG ')
 9031 CONTINUE
 9033 CONTINUE
      WRITE(ICOUT,9040)ALPHA,BETA1,BETA2
 9040 FORMAT('ALPHA,BETA1,BETA2 = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 9043
      DO 9041 I=I3,I4
      WRITE(ICOUT,9042)I,PRED(I),RES(I)
 9042 FORMAT('I,PRED(I),RES(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9041 CONTINUE
 9043 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE QUAFIT
      SUBROUTINE QUAFI2(XS,YS,N,   &
      XTEMP,   &
      ALPHA,BETA1,BETA2,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--CARRY OUT A LEAST SQUARES NON-WEIGHTED QUARADITIC FIT
!              OF THE VARIABLES XS(.) AND YS(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/7
!     ORIGINAL VERSION--JULY       2002
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DOUBLE PRECISION DMEANX
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
      DOUBLE PRECISION DSUM6
!
!---------------------------------------------------------------------
!
      DIMENSION XMAT(3,3)
      DIMENSION IPVT(3)
      DIMENSION RHS(3)
      DIMENSION XS(*)
      DIMENSION YS(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='QUAF'
      ISUBN2='I2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'AFI2')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF QUAFI2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBRO,IBUGA3,IERROR
   52 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 63
      DO 61 I=1,N
      WRITE(ICOUT,62)I,XS(I),YS(I)
   62 FORMAT('I,XS(I),YS(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   61 CONTINUE
   63 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.GE.1)GO TO 119
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN QUAFI2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT SAMPLE SIZE MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)N
  115 FORMAT('      SUCH WAS NOT THE CASE HERE.  THE SAMPLE SIZE N = ',   &
             I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  119 CONTINUE
!
!               ***********************************************
!               **  STEP 11--                                **
!               **  CARRY OUT A LEAST SQUARES QUADRATIC FIT  **
!               ***********************************************
!
      AN=N
!
!  SCALE THE DATA: SUBTRACT MEAN FROM X ARRAY
!
      DSUM1=0.0D0
      DO 1310 I=1,N
        DSUM1=DSUM1 + DBLE(XS(I))
 1310 CONTINUE
      DMEANX=DSUM1/DBLE(N)
!
      AMEANX=REAL(DMEANX)
      DO 1320 I=1,N
        XTEMP(I)=XS(I) - AMEANX
 1320 CONTINUE
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DSUM5=0.0D0
      DSUM6=0.0D0
      DO 1330 I=1,N
        DSUM1=DSUM1 + DBLE(YS(I))
        DSUM2=DSUM2 + DBLE(XTEMP(I))**2
        DSUM3=DSUM3 + DBLE(XTEMP(I))**3
        DSUM4=DSUM4 + DBLE(XTEMP(I))**4
        DSUM5=DSUM5 + DBLE(YS(I))*DBLE(XTEMP(I))
        DSUM6=DSUM6 + DBLE(YS(I))*DBLE(XTEMP(I))**2
 1330 CONTINUE
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'AFI2')GO TO 1390
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1351)
 1351 FORMAT('***** IN THE MIDDLE OF QUAFI2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1352)DSUM1,DSUM2,DSUM3,DSUM4
 1352 FORMAT('DSUM1,DSUM2,DSUM3,DSUM4 = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1353)DSUM5,DSUM6,DMEANX
 1353 FORMAT('DSUM5,DSUM6,DMEANX = ',3D15.7)
      CALL DPWRST('XXX','BUG ')
 1390 CONTINUE
!
      XMAT(1,1)=AN
      XMAT(1,2)=0.0
      XMAT(1,3)=REAL(DSUM2)
      XMAT(2,1)=0.0
      XMAT(2,2)=REAL(DSUM2)
      XMAT(2,3)=REAL(DSUM3)
      XMAT(3,1)=REAL(DSUM2)
      XMAT(3,2)=REAL(DSUM3)
      XMAT(3,3)=REAL(DSUM4)
      RHS(1)=REAL(DSUM1)
      RHS(2)=REAL(DSUM5)
      RHS(3)=REAL(DSUM6)
      IPVT(1)=0
      IPVT(2)=0
      IPVT(3)=0
!
!  USE LINPACK TO SOLVE 2X2 EQUATION
!
      INFO=0
      NP=3
      CALL SGEFA(XMAT,NP,NP,IPVT,INFO)
      IF(INFO.NE.0)THEN
        ALPHA=0.0
        BETA1=0.0
        BETA2=0.0
        IERROR='YES'
      ELSE
        IJOB=0
        CALL SGESL(XMAT,NP,NP,IPVT,RHS,IJOB)
        B0=RHS(1)
        B1=RHS(2)
        B2=RHS(3)
        ALPHA=B0 - B1*AMEANX + B2*AMEANX*AMEANX
        BETA1=B1 - 2*B2*AMEANX
        BETA2=B2
      END IF
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'AFI2')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF QUAFI2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ISUBRO,IBUGA3,IERROR
 9012 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 9033
      DO 9031 I=1,N
      WRITE(ICOUT,9032)I,XS(I),YS(I)
 9032 FORMAT('I,XS(I),YS(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9031 CONTINUE
 9033 CONTINUE
      WRITE(ICOUT,9040)ALPHA,BETA1,BETA2
 9040 FORMAT('ALPHA,BETA1,BETA2 = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE QUAFI2
      DOUBLE PRECISION FUNCTION QUAGLO(F,PARA)
!===================================================== QUAGLO.FOR
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  QUANTILE FUNCTION OF THE GENERALIZED LOGISTIC DISTRIBUTION
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(3)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0.0D0/,ONE/1.0D0/
!
      U=PARA(1)
      A=PARA(2)
      G=PARA(3)
!
      IF(A.LE.ZERO)THEN
        QUAGLO=ZERO
        WRITE(ICOUT,7010)
 7010   FORMAT('***** ERROR IN GL5PPF--NON-POSITIVE SCALE ',   &
               'PARAMETER.')
        CALL DPWRST('XXX','WRIT')
!
      ELSEIF(F.LE.ZERO.OR.F.GE.ONE)THEN
        IF((F.EQ.ZERO.AND.G.LT.ZERO) .OR. (F.EQ.ONE .AND.G.GT.ZERO))   &
          THEN
          QUAGLO=U+A/G
        ELSE
          WRITE(ICOUT,7000)
 7000     FORMAT('***** ERROR IN GL5PPF--ARGUMENT IS INVALID.')
          CALL DPWRST('XXX','WRIT')
          QUAGLO=ZERO
        ENDIF
      ELSE
        Y=DLOG(F/(ONE-F))
        IF(G.NE.ZERO)Y=(ONE-DEXP(-G*Y))/G
        QUAGLO=U+A*Y
      ENDIF
!
      RETURN
      END FUNCTION QUAGLO
!===================================================== QUAGAM.FOR
      DOUBLE PRECISION FUNCTION QUAGAM(F,PARA)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  QUANTILE FUNCTION OF THE GAMMA DISTRIBUTION
!
!  OTHER ROUTINES USED: DERF,DLGAMA (DLGADP,GAMIND,QUASTN
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(2)
      DOUBLE PRECISION NINE
!
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA ZERO/0D0/,P01/0.01D0/,ONE/1D0/,NINE/9D0/
      DATA ZERO/0.0D0/,P01/0.01D0/,ONE/1.0D0/,NINE/9.0D0/
!
!         EPS,MAXIT CONTROL THE TEST FOR CONVERGENCE OF N-R ITERATION
!
      DATA EPS/1D-10/,MAXIT/30/
!
      QUAGAM=ZERO
      ALPHA=PARA(1)
      BETA=PARA(2)
      IF(ALPHA.LE.ZERO)THEN
        WRITE(ICOUT,7000)
 7000   FORMAT('****** ERROR FROM ROUTINE QUAGAM: SHAPE PARAMETER ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LE.ZERO)THEN
        WRITE(ICOUT,7001)
 7001   FORMAT('****** ERROR FROM ROUTINE QUAGAM: SCALE PARAMETER ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(F.LT.ZERO.OR.F.GE.ONE)THEN
        WRITE(ICOUT,7010)
 7010   FORMAT('****** ERROR FROM ROUTINE QUAGAM: ARGUMENT OF ',   &
             'FUNCTION IS OUTSIDE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)F
 7002   FORMAT('       VALUE OF THE ARGUMENT IS ',D24.16)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(F.EQ.ZERO)GO TO 9000
      AM1=ALPHA-ONE
      IF(AM1.NE.ZERO)GO TO  10
!
!         CASE ALPHA.EQ.1 - GAMMA IS EXPONENTIAL
!
      QUAGAM=(-DLOG(ONE-F))*BETA
      GO TO 9000
!
!         INITIAL ESTIMATE OF ROOT OF EQUATION GAMIND(X)=F:
!         - IF ALPHA.GT.1, USE WILSON-HILFERTY APPROXIMATION IF IT'S
!           POSITIVE AND NOT TOO CLOSE TO ZERO;
!         - IF ALPHA.LT.1, OR IF W-H APPROX. ISN'T POSITIVE ENOUGH,
!           USE THE SMALL-X APPROXIMATION OF IGNORING THE EXP(-T) TERM
!           IN THE INTEGRAL DEFINING GAMIND(X)
!
!CC10 DLOGG=DLGAMA(ALPHA)
   10 DLOGG=DLGADP(ALPHA)
      IF(AM1.LE.ZERO)GO TO  20
      ROOT=ALPHA*(ONE-ONE/(NINE*ALPHA)+QUASTN(F)/DSQRT(NINE*ALPHA))**3
      IF(ROOT.GT.P01*ALPHA)GO TO  30
   20 ROOT=DEXP((DLOG(ALPHA*F)+DLOGG)/ALPHA)
   30 CONTINUE
!
!         REFINE INITIAL ESTIMATE BY NEWTON-RAPHSON ITERATION
!
      DO 40 IT=1,MAXIT
        FUNC=GAMIND(ROOT,ALPHA,DLOGG)-F
        RINC=FUNC*DEXP(DLOGG+ROOT-AM1*DLOG(ROOT))
        ROOT=ROOT-RINC
        IF(DABS(FUNC).LE.EPS)GO TO  50
   40 CONTINUE
!
      WRITE(ICOUT,7020)
 7020 FORMAT('**** WARNING FROM ROUTINE QUAGAM:',   &
             ' ITERATION HAS NOT CONVERGED. RESULT MAY BE UNRELIABLE')
!
!         SCALE SOLUTION
!
   50 QUAGAM=ROOT*BETA
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION QUAGAM
!===================================================== QUAKAP.FOR
      DOUBLE PRECISION FUNCTION QUAKAP(F,PARA)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  QUANTILE FUNCTION OF THE KAPPA DISTRIBUTION
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(4)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,ONE/1D0/
!
      QUAKAP=0.0D0
      U=PARA(1)
      A=PARA(2)
      G=PARA(3)
      H=PARA(4)
      IF(A.LE.ZERO)THEN
        WRITE(ICOUT,7000)
 7000   FORMAT('****** ERROR FROM ROUTINE QUAKAP: SCALE PARAMETER ',   &
               'INVALID')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)A
        CALL DPWRST('XXX','BUG ')
        QUAKAP=ZERO
        GO TO 9000
      ENDIF
!
      IF(F.LE.ZERO.OR.F.GE.ONE)GO TO  10
      Y=-DLOG(F)
      IF(H.NE.ZERO)Y=(ONE-DEXP(-H*Y))/H
      Y=-DLOG(Y)
      IF(G.NE.ZERO)Y=(ONE-DEXP(-G*Y))/G
      QUAKAP=U+A*Y
      GO TO 9000
!
   10 IF(F.EQ.ZERO)GO TO  20
      IF(F.EQ.ONE)GO TO  30
!
      WRITE(ICOUT,7010)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7002)F
      CALL DPWRST('XXX','BUG ')
      QUAKAP=ZERO
      GO TO  9000
!
   20 IF(H.LE.ZERO.AND.G.LT.ZERO)QUAKAP=U+A/G
!
      IF(H.LE.ZERO.AND.G.GE.ZERO)THEN
        WRITE(ICOUT,7010)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)F
        CALL DPWRST('XXX','BUG ')
        QUAKAP=ZERO
        GO TO  9000
      ENDIF
!
      IF(H.GT.ZERO.AND.G.NE.ZERO)QUAKAP=U+A/G*(ONE-H**(-G))
      IF(H.GT.ZERO.AND.G.EQ.ZERO)QUAKAP=U+A*DLOG(H)
      GO TO 9000
!
   30 CONTINUE
      IF(G.LE.ZERO)THEN
        WRITE(ICOUT,7010)
 7010   FORMAT('****** ERROR FROM ROUTINE QUAKAP: ARGUMENT OF ',   &
               'FUNCTION IS OUTSIDE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)F
 7002   FORMAT('       VALUE OF THE ARGUMENT IS ',D24.16)
        CALL DPWRST('XXX','BUG ')
        QUAKAP=ZERO
        GO TO  9000
      ENDIF
      QUAKAP=U+A/G
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION QUAKAP
!===================================================== QUAPE3.FOR
      DOUBLE PRECISION FUNCTION QUAPE3(F,PARA)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  QUANTILE FUNCTION OF THE PEARSON TYPE 3 DISTRIBUTION
!
!  OTHER ROUTINES USED: DERF,DLGAMA (DLGADP),GAMIND,QUAGAM,QUASTN
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(3),PAR(2)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,HALF/0.5D0/,ONE/1D0/,TWO/2D0/,FOUR/4D0/
!
!         SMALL IS USED TO TEST WHETHER SKEWNESS IS EFFECTIVELY ZERO
!
      DATA SMALL/1D-6/
!
      QUAPE3=CPUMIN
!
      IF(PARA(2).LE.ZERO)THEN
        WRITE(ICOUT,7010)
 7010   FORMAT('****** ERROR FROM ROUTINE QUAPE3: SCALE PARAMETER ',   &
               'INVALID')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)PARA(2)
        CALL DPWRST('XXX','BUG ')
        QUAPE3=ZERO
        GO TO  9000
      ENDIF
!
      GAMMA=PARA(3)
      IF(F.LE.ZERO.OR.F.GE.ONE)GO TO  20
      IF(DABS(GAMMA).LT.SMALL)GO TO  10
      ALPHA=FOUR/(GAMMA*GAMMA)
      BETA=DABS(HALF*PARA(2)*GAMMA)
      PAR(1)=ALPHA
      PAR(2)=BETA
      IF(GAMMA.GT.ZERO)QUAPE3=PARA(1)-ALPHA*BETA+QUAGAM(F,PAR)
      IF(GAMMA.LT.ZERO)QUAPE3=PARA(1)+ALPHA*BETA-QUAGAM(ONE-F,PAR)
      GO TO 9000
!
!         ZERO SKEWNESS
!
   10 CONTINUE
      QUAPE3=PARA(1)+PARA(2)*QUASTN(F)
      GO TO 9000
!
   20 CONTINUE
      IF(F.EQ.ZERO.AND.GAMMA.GT.ZERO)GO TO  30
      IF(F.EQ.ONE .AND.GAMMA.LT.ZERO)GO TO  30
      WRITE(ICOUT,7000)
 7000 FORMAT('****** ERROR FROM ROUTINE QUAPE3: ARGUMENT OF ',   &
             'FUNCTION INVALID')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7002)F
 7002 FORMAT('       VALUE OF THE ARGUMENT IS ',D24.16)
      CALL DPWRST('XXX','BUG ')
      QUAPE3=ZERO
      GO TO 9000
!
   30 CONTINUE
      QUAPE3=PARA(1)-TWO*PARA(2)/GAMMA
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION QUAPE3
!===================================================== QUASTN.FOR
      DOUBLE PRECISION FUNCTION QUASTN(F)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!*  VERSION 3.03  JUNE 2000                                            *
!*  * Fixed: WRITE(6,7000) and FORMAT statement 7000 incompatible      *
!*                                                                     *
!***********************************************************************
!
!  QUANTILE FUNCTION OF THE STANDARD NORMAL DISTRIBUTION
!
!  BASED ON ALGORITHM AS241, APPL. STATIST. (1988) VOL.37 NO.3
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,HALF/0.5D0/,ONE/1D0/
      DATA SPLIT1/0.425D0/,SPLIT2/5D0/,CONST1/0.180625D0/,CONST2/1.6D0/
!
!         COEFFICIENTS OF RATIONAL-FUNCTION APPROXIMATIONS
!
      DATA A0,A1,A2,A3,A4,A5,A6,A7,B1,B2,B3,B4,B5,B6,B7/   &
                                      0.338713287279636661D1,   &
        0.133141667891784377D3,  0.197159095030655144D4,   &
        0.137316937655094611D5,  0.459219539315498715D5,   &
        0.672657709270087009D5,  0.334305755835881281D5,   &
        0.250908092873012267D4,  0.423133307016009113D2,   &
        0.687187007492057908D3,  0.539419602142475111D4,   &
        0.212137943015865959D5,  0.393078958000927106D5,   &
        0.287290857357219427D5,  0.522649527885285456D4/
      DATA C0,C1,C2,C3,C4,C5,C6,C7,D1,D2,D3,D4,D5,D6,D7/   &
                                      0.142343711074968358D1,   &
        0.463033784615654530D1,  0.576949722146069141D1,   &
        0.364784832476320461D1,  0.127045825245236838D1,   &
        0.241780725177450612D0,  0.227238449892691846D-1,   &
        0.774545014278341408D-3,  0.205319162663775882D1,   &
        0.167638483018380385D1,  0.689767334985100005D0,   &
        0.148103976427480075D0,  0.151986665636164572D-1,   &
        0.547593808499534495D-3,  0.105075007164441684D-8/
      DATA E0,E1,E2,E3,E4,E5,E6,E7,F1,F2,F3,F4,F5,F6,F7/   &
                                 0.665790464350110378D1,   &
        0.546378491116411437D1,  0.178482653991729133D1,   &
        0.296560571828504891D0,  0.265321895265761230D-1,   &
        0.124266094738807844D-2,  0.271155556874348758D-4,   &
        0.201033439929228813D-6,  0.599832206555887938D0,   &
        0.136929880922735805D0,  0.148753612908506149D-1,   &
        0.786869131145613259D-3,  0.184631831751005468D-4,   &
        0.142151175831644589D-6,  0.204426310338993979D-14/
!
      Q=F-HALF
      IF(DABS(Q).GT.SPLIT1)GO TO  10
      R=CONST1-Q*Q
      QUASTN=Q*(((((((A7*R+A6)*R+A5)*R+A4)*R+A3)*R+A2)*R+A1)*R+A0)   &
              /(((((((B7*R+B6)*R+B5)*R+B4)*R+B3)*R+B2)*R+B1)*R+ONE)
      GO TO 9000
!
   10 R=F
      IF(Q.GE.ZERO)R=ONE-F
      IF(R.LE.ZERO)GO TO  1000
      R=DSQRT(-DLOG(R))
      IF(R.GT.SPLIT2)GO TO  20
      R=R-CONST2
      QUASTN=(((((((C7*R+C6)*R+C5)*R+C4)*R+C3)*R+C2)*R+C1)*R+C0)   &
            /(((((((D7*R+D6)*R+D5)*R+D4)*R+D3)*R+D2)*R+D1)*R+ONE)
      GO TO  30
   20 R=R-SPLIT2
      QUASTN=(((((((E7*R+E6)*R+E5)*R+E4)*R+E3)*R+E2)*R+E1)*R+E0)   &
            /(((((((F7*R+F6)*R+F5)*R+F4)*R+F3)*R+F2)*R+F1)*R+ONE)
   30 IF(Q.LT.ZERO)QUASTN=-QUASTN
      GO TO 9000
!
 1000 CONTINUE
      WRITE(ICOUT,7000)
 7000 FORMAT('***** ERROR FROM ROUTINE QUASTN:  ARGUMENT OF ',   &
             'FUNCTION INVALID')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7002)F
 7002 FORMAT('       VALUE OF THE ARGUMENT IS ',D24.16)
      CALL DPWRST('XXX','BUG ')
      QUASTN=ZERO
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION QUASTN
      DOUBLE PRECISION FUNCTION QUAWAK(F,PARA)
!===================================================== QUAWAK.FOR
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  QUANTILE FUNCTION OF THE WAKEBY DISTRIBUTION
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(5)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0.0D0/,ONE/1.0D0/
!
!         UFL SHOULD BE CHOSEN SO THAT EXP(UFL) JUST DOES NOT CAUSE
!         UNDERFLOW
!
      DATA UFL/-170.0D0/
!
      QUAWAK=0.0D0
      XI=PARA(1)
      A=PARA(2)
      B=PARA(3)
      C=PARA(4)
      D=PARA(5)
!
!         TEST FOR VALID PARAMETERS
!
      IF(B+D.LE.ZERO.AND.(B.NE.ZERO.OR.C.NE.ZERO.OR.D.NE.ZERO))GO TO  1000
      IF(A.EQ.ZERO.AND.B.NE.ZERO)GO TO  1000
      IF(C.EQ.ZERO.AND.D.NE.ZERO)GO TO  1000
      IF(C.LT.ZERO.OR.A+C.LT.ZERO)GO TO  1000
      IF(A.EQ.ZERO.AND.C.EQ.ZERO)GO TO  1000
!
      IF(F.LE.ZERO.OR.F.GE.ONE)GO TO  10
      Z=-DLOG(ONE-F)
      Y1=Z
      IF(B.NE.ZERO)THEN
        TEMP=-B*Z
        IF(TEMP.LT.UFL)Y1=ONE/B
        IF(TEMP.GE.UFL)Y1=(ONE-DEXP(TEMP))/B
      ENDIF
      Y2=Z
      IF(D.NE.ZERO)Y2=(ONE-DEXP(D*Y2))/(-D)
      QUAWAK=XI+A*Y1+C*Y2
      GO TO 9000
!
   10 CONTINUE
      IF(F.EQ.ZERO)THEN
        QUAWAK=XI
        GO TO 9000
      ELSEIF(F.EQ.ONE)THEN
        IF(D.GT.ZERO)GO TO  1010
        IF(D.LT.ZERO)QUAWAK=XI+A/B-C/D
        IF(D.EQ.ZERO.AND.C.GT.ZERO)GO TO  1010
        IF(D.EQ.ZERO.AND.C.EQ.ZERO.AND.B.EQ.ZERO)GO TO  1010
        IF(D.EQ.ZERO.AND.C.EQ.ZERO.AND.B.GT.ZERO)QUAWAK=XI+A/B
        GO TO 9000
      ELSE
        GO TO  1010
      ENDIF
!
 1000 CONTINUE
      WRITE(ICOUT,7000)
 7000 FORMAT('***** ERROR IN WAKPPF--PARAMETERS INVALID.')
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
!
 1010 CONTINUE
      WRITE(ICOUT,7010)
 7010 FORMAT('***** ERROR IN WAKPPF--ARGUMENT INVALID.')
      CALL DPWRST('XXX','WRIT')
      QUAWAK=ZERO
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION QUAWAK
      SUBROUTINE QUICH1(ICTEXT,NCTEXT,PLEC,PLECG,ANUMPP)
!
!     PURPOSE--FOR THE QMS GRAPHICS DEVICE,
!              FOR THE "104" (STANDARD ROMAN MEDIUM FONT)
!              10 POINT PROPORTIONAL FONT (TABLE ON APPENDIX B-4 OF
!              QUIC PROGRAMMERS MANUAL FROM QMS)
!              AND FOR THE HORIZONTAL DIRECTION,
!              DETERMINE THE LENGTH OF THE TEXT STRING IN THE
!              CHARACTER VECTOR ICTEXT(.),
!              WHICH CONSISTS OF NTEXT CHARACTERS.
!     NOTE--THE LENGTH IS IN STANDARDIZED COORDINATES
!           THAT IS, 0.0 TO 100.0
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89.2
!     ORIGINAL VERSION--JANUARY   1989.
!     UPDATED         --APRIL     1992. IIVALUE TO IVALUE
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ICTEXT
      CHARACTER*4 ICTEMP
      CHARACTER*1 IC
!
      DIMENSION ICTEXT(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCODV.INC'
      INCLUDE 'DPCOP2.INC'
!
!     WIDTH TABLE, NOTE THAT ASCII CHARACTER 1-31 ARE CONTROL
!     CHARACTERS WITH ZERO WIDTH, CHARACTERS 127-255 ARE UNDEFINED.
!     THERFORE TABLE GOES FROM 32 TO 126.
!
      DIMENSION WIDTAB(95)
!
      DATA WIDTAB( 1) /25./
      DATA WIDTAB( 2) / 8./
      DATA WIDTAB( 3) /20./
      DATA WIDTAB( 4) /26./
      DATA WIDTAB( 5) /19./
      DATA WIDTAB( 6) /32./
      DATA WIDTAB( 7) /34./
      DATA WIDTAB( 8) / 9./
      DATA WIDTAB( 9) /15./
      DATA WIDTAB(10) /15./
      DATA WIDTAB(11) /17./
      DATA WIDTAB(12) /24./
      DATA WIDTAB(13) / 9./
      DATA WIDTAB(14) /15./
      DATA WIDTAB(15) / 9./
      DATA WIDTAB(16) /19./
      DATA WIDTAB(17) /23./
      DATA WIDTAB(18) /23./
      DATA WIDTAB(19) /23./
      DATA WIDTAB(20) /23./
      DATA WIDTAB(21) /23./
      DATA WIDTAB(22) /23./
      DATA WIDTAB(23) /23./
      DATA WIDTAB(24) /23./
      DATA WIDTAB(25) /23./
      DATA WIDTAB(26) /23./
      DATA WIDTAB(27) / 9./
      DATA WIDTAB(28) / 9./
      DATA WIDTAB(29) /19./
      DATA WIDTAB(30) /24./
      DATA WIDTAB(31) /19./
      DATA WIDTAB(32) /18./
      DATA WIDTAB(33) /25./
      DATA WIDTAB(34) /34./
      DATA WIDTAB(35) /26./
      DATA WIDTAB(36) /29./
      DATA WIDTAB(37) /31./
      DATA WIDTAB(38) /26./
      DATA WIDTAB(39) /25./
      DATA WIDTAB(40) /30./
      DATA WIDTAB(41) /32./
      DATA WIDTAB(42) /14./
      DATA WIDTAB(43) /18./
      DATA WIDTAB(44) /32./
      DATA WIDTAB(45) /27./
      DATA WIDTAB(46) /37./
      DATA WIDTAB(47) /29./
      DATA WIDTAB(48) /30./
      DATA WIDTAB(49) /24./
      DATA WIDTAB(50) /30./
      DATA WIDTAB(51) /28./
      DATA WIDTAB(52) /22./
      DATA WIDTAB(53) /28./
      DATA WIDTAB(54) /33./
      DATA WIDTAB(55) /34./
      DATA WIDTAB(56) /45./
      DATA WIDTAB(57) /31./
      DATA WIDTAB(58) /31./
      DATA WIDTAB(59) /27./
      DATA WIDTAB(60) /11./
      DATA WIDTAB(61) /20./
      DATA WIDTAB(62) /11./
      DATA WIDTAB(63) /20./
      DATA WIDTAB(64) /40./
      DATA WIDTAB(65) / 9./
      DATA WIDTAB(66) /20./
      DATA WIDTAB(67) /22./
      DATA WIDTAB(68) /18./
      DATA WIDTAB(69) /23./
      DATA WIDTAB(70) /18./
      DATA WIDTAB(71) /19./
      DATA WIDTAB(72) /21./
      DATA WIDTAB(73) /25./
      DATA WIDTAB(74) /13./
      DATA WIDTAB(75) /13./
      DATA WIDTAB(76) /26./
      DATA WIDTAB(77) /15./
      DATA WIDTAB(78) /37./
      DATA WIDTAB(79) /25./
      DATA WIDTAB(80) /20./
      DATA WIDTAB(81) /23./
      DATA WIDTAB(82) /23./
      DATA WIDTAB(83) /18./
      DATA WIDTAB(84) /16./
      DATA WIDTAB(85) /16./
      DATA WIDTAB(86) /25./
      DATA WIDTAB(87) /26./
      DATA WIDTAB(88) /39./
      DATA WIDTAB(89) /23./
      DATA WIDTAB(90) /26./
      DATA WIDTAB(91) /19./
      DATA WIDTAB(92) /15./
      DATA WIDTAB(93) / 5./
      DATA WIDTAB(94) /15./
      DATA WIDTAB(95) /18./
!
!-----START POINT-----------------------------------------------------
!
!
!     **************************************************************
!     **    STEP 1 - SUM UP THE LENGTH OF THE STRING (IN "DOTS")  **
!     **************************************************************
!
      SUM=0.
      DO 100 I=1,NCTEXT
      ICTEMP=ICTEXT(I)
      IC=ICTEMP(1:1)
      CALL DPCOAN(IC,IVALUE)
!CCCC THE FOLLOWING LINE WAS FIXED   APRIL 1992
!CCCC IF(IVALUE.LT.32..OR.IIVALUE.GT.126)GO TO 100
      IF(IVALUE.LT.32.OR.IVALUE.GT.126)GO TO 100
      IVALUE=IVALUE-31
      SUM=SUM+WIDTAB(IVALUE)
 100  CONTINUE
!
!     **************************************************************
!     **    STEP 2 - CONVERT DOTS TO DATAPLOT PERCENT UNITS       **
!     **************************************************************
!
      PLEC=100.*(SUM/ANUMPP)
      PLECG=PLEC
!
!     **************************************************************
!     **    RETURN                                                **
!     **************************************************************
!
      RETURN
      END SUBROUTINE QUICH1
