      SUBROUTINE QUICPT(PX1,PY1,IX1,IY1,ISUBN0)
!
!     THIS ROUTINE IS A MODIFIED VERSION OF GRTRSD.  IT IS USED
!     ONLY BY THE "QUIC" DEVICES (QMS LASER PRINTER).
!     QUICPT CONVERTS FROM DATAPLOT
!     UNITS TO DEVICE INTEGER UNITS, BUT IT ALSO APPLIES "WINDOW"
!     TRANSFORMATIONS NEEDED BY THE "MULTI-PLOT" AND "WINDOW
!     COORDINATE" COMMANDS.  THE QUIC COORDINATES NEED TO BE TRANSLATED
!     TO INCHES IN THE FORM (XXXXX) WHERE THERE IS AN IMPLIED DECIMAL
!     POINT BETWEEN THE SECOND AND THIRD "X".
!
!     QUIC USES 300 DOT PER INCH RESOLUTION.  THE DIMENSIONS OF THE
!     PAGE ARE DETERMINED BY USING (PICTURE POINTS/DOTS PER INCH).
!
!     PURPOSE--TRANSLATE THE STANDARDIZED (0.0 TO 100.0) COORDINATES (PX1,PY1)
!              INTO (INTEGER PICTURE POINT) DEVICE COORDINATES (AX1,AY1)
!     ISUBN0 = NAME OF SUBROUTINE WHICH CALLED GRWRST.
!              (AND THEREBY HAVE WALKBACK INFORMATION).
!     NOTE--THE ONLY VARIABLES IN THE    PLOT CONTROL COMMON
!           THAT ARE USED HEREIN ARE THE ONES IN /RWIND/
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88.6
!     ORIGINAL VERSION--JANUARY   1989.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ISUBN0
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOPC.INC'
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCODV.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERRG4='NO'
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'ICPT')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF QUICPT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBN0
   52 FORMAT('ISUBN0 (NAME OF THE CALLING SUBROUTINE) = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IMANUF,IMODEL
   53 FORMAT('IMANUF,IMODEL = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMHPP,NUMVPP
   54 FORMAT('NUMHPP,NUMVPP = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)ANUMHP,ANUMVP
   55 FORMAT('ANUMHP,ANUMVP = ',E15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,56)PX1,PY1
   56 FORMAT('PX1,PY1 = ',E15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,57)IOFFSH,IOFFSV
   57 FORMAT('IOFFSH,IOFFSV = ',I10,I10)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)PWXMIN,PWXMAX,PWYMIN,PWYMAX
   61 FORMAT('PWXMIN,PWXMAX,PWYMIN,PWYMAX = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,69)IBUGG4
   69 FORMAT('IBUGG4 = ',A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!              **************************************
!              **  STEP 0--                        **
!              **  DETERMINE THE DIMENSION OF THE  **
!              **  IN INCHES                       **
!              **************************************
!
      DOTPPI=QUIPPI
      XPAGE=ANUMHP/DOTPPI
      YPAGE=ANUMVP/DOTPPI
!
!               *************************************
!               **  STEP 1--                       **
!               **  CARRY OUT THE TRANSFORMATION.  **
!               *************************************
!
!  NOTE: QMS POSITIONS FROM TOP TO BOTTOM RATHER THAN BOTTOM TO
!        TOP AS DATAPLOT ASSUMES.  CONVERT PWYMIN AND PWYMAX TO
!        REFLECT THIS.
!
      PWYMNT=100.-PWYMAX
      PWYMXT=100.-PWYMIN
!
      AX1=PWXMIN+(PX1/100.0)*(PWXMAX-PWXMIN)
      IF(AX1.LE.0.0)AX1=0.0
      IF(AX1.GE.100.)AX1=100.
!
      AY1=PWYMNT+(PY1/100.0)*(PWYMXT-PWYMNT)
      IF(AY1.LE.0.0)AY1=0.0
      IF(AY1.GE.100.)AY1=100.
!
!              **************************************
!              **  STEP 2--                        **
!              **  CONVERT TO INCH FORMAT "XXXXX"  **
!              **  WITH IMPLIED DECIMAL AFTER      **
!              **  SECOND "X"                      **
!              **  INCH = PAGE SIZE * VALUE/100    **
!              **  QMS FORMAT=INT(INCH*1000.)      **
!              **  NOTE: THE LEFT AND TOP MARGINS  **
!              **        NEED TO BE ADDED IN SINCE **
!              **        THE "ABSOLUTE" POSITIONING**
!              **        COMMANDS ARE FROM PAGE    **
!              **        RATHER THAN MARGIN BOUNDARY*
!              **************************************
!
      ALMRG=1000.*REAL(IOFFSH)/DOTPPI
      ATPMRG=1000.*REAL(IOFFSV)/DOTPPI
      AXINCH=XPAGE*AX1*10.+ALMRG
      AYINCH=YPAGE*AY1*10.+ATPMRG
      IX1=INT(AXINCH+0.5)
      IY1=INT(AYINCH+0.5)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'ICPT')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF QUICPT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)PX1,PY1
 9015 FORMAT('PX1,PY1   = ',E15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9018)IX1,IY1
 9018 FORMAT('IX1,IY1   = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE QUICPT
      SUBROUTINE QUAFRM(AMAT,MAXROM,MAXCOM,NR1,NC1,X,IWRITE,   &
                        XQUAD,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              QUADRATIC FORM OF A VECTOR AND A SQUARE MATRIX,
!              I.E., x'Mx
!              THE RESULT IS A SCALAR.
!     INPUT  ARGUMENTS--AMAT   = THE SINGLE PRECISION MATRIX
!                     --X      = THE SINGLE PRECISION VECTOR
!                     --MAXROM = THE INTEGER ROW DIMENSION OF AMAT
!                     --MAXCOM = THE INTEGER COUMN DIMENSION OF AMAT
!                     --NR1    = THE INTEGER NUMBER OF ROWS OF AMAT
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS OF AMAT
!     OUTPUT ARGUMENTS--XQUAD    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE QUADRATIC FORM.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             QUADRATIC FORM.
!     NOTE--THIS ROUTINE ASSUMES THE ERROR CHECKING (FOR EQUAL
!           ROWS AND COLUMNS, MATCHING DIMENSIONS FOR X AND AMAT)
!           IS DONE BT THE CALLING SUBROUTINE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.6
!     ORIGINAL VERSION--JUNE      1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DYM1
      DOUBLE PRECISION DYM2
      DOUBLE PRECISION DYM3
!
      DIMENSION AMAT(MAXROM,MAXCOM)
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='QUAF'
      ISUBN2='RM  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF QUAFRM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NR1,NC1
   53 FORMAT('NR1, NC1 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NR1
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ******************************
!               **  COMPUTE QUADRATIC FORM  **
!               ******************************
!
      DSUM=0.0D0
      DO 5861 I=1,NR1
        DO 5863 J=1,NC1
          DYM1=AMAT(I,J)
          DYM2=X(I)
          DYM3=X(J)
          DSUM=DSUM+DYM2*DYM1*DYM3
 5863   CONTINUE
 5861 CONTINUE
!
      XQUAD=REAL(DSUM)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF'.OR.IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)XQUAD
  811 FORMAT('THE QUADRATIC FORM  = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF QUAFRM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)NR1,NC1
 9013 FORMAT('NR1,NC1 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XQUAD
 9015 FORMAT('XQUAFRM = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE QUAFRM
      SUBROUTINE QUANT(QNT,X,N,IWRITE,XTEMP,MAXNXT,   &
                       IQUAME,   &
                       XQUANT,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE QUANTTILE
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--QNT   = THE SINGLE PRECISION QUANTILE
!                                (BETWEEN 0 AND 1)
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --IQUAME = METHOD:
!                                1. ORDER STATISTIC (IQUAME=ORDE)
!                                2. HERRELL-DAVIS   (IQUAME=HD)
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XQUANT = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE QUANTTILE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE QUANTTILE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HYNDMAN AND FAN (NOVEMBER 1996), "SAMPLE QUANTILES IN
!                 STATISTICAL PACKAGES", THE AMERICAN STATISTICIAN,
!                 VOL. 50, NO. 4, PP. 361-365.
!     WRITTEN BY--JAMES J. FILLIBEN/ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002.7
!     ORIGINAL VERSION--JULY      2002.
!     UPDATED         --FEBRUARY  2015. SUPPORT FOR R8 AND R7 METHODS
!     UPDATED         --DECEMBER  2017. SUPPORT FOR "AVERAGE" METHOD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      CHARACTER*4 IQUAME
!
      CHARACTER*16 IMETH
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
      DOUBLE PRECISION DTEMP1
      DOUBLE PRECISION DTEMP2
      DOUBLE PRECISION WTEMP
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DBETAI
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF QUANT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA3,IQUAME,QNT,N
   53   FORMAT('IBUGA3,IQUAME,QNT,N = ',2(A4,2X),G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      ISUBN1='QUAN'
      ISUBN2='T   '
      IERROR='NO'
!
      NI=0
      NIP1=0
      ANI=0.0
      A2NI=0.0
      REM=0.0
!
!               ******************************
!               **  COMPUTE QUANTTILE      **
!               ******************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(QNT.LT.0.0 .OR. QNT.GT.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN QUANTILE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT QUANTILE TO BE COMPUTED')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      MUST BE LARGER THAN 0 AND SMALLER THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)QNT
  117   FORMAT('      THE INPUT QUANTILE = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,125)MAXNXT
  125   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)N
  127   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XQUANT=X(1)
        GO TO 9000
      ENDIF
!
!     CASE WHERE ALL RESPONSE VALUES ARE THE SAME
      HOLD=X(1)
      DO 145 I=2,N
        IF(X(I).NE.HOLD)GO TO 149
  145 CONTINUE
      XQUANT=HOLD
      GO TO 9000
  149 CONTINUE
!
!               ***********************************
!               **  STEP 2--                     **
!               **  COMPUTE THE QUANTTILE.       **
!               ***********************************
!
      CALL SORT(X,N,XTEMP)
      AN=N
!
!     NOTE 2015/02: THE HYNDMAN AND FAN ARTICLE DISCUSSES EIGHT
!                   DEFINITIONS OF A QUANTILE IN RELATION TO SIX
!                   DESIRABLE PROPERTIES.  THE DEFAULT DATAPLOT
!                   ALGORITHM USES THE "R6" DEFINITION.  THEIR
!                   RECOMMENDATION FOR A "STANDARD" DEFINITION IS
!                   "R8".  ALLOW THE USER TO REQUEST THE R8
!                   DEFINITION (SPECIFIED IN IQUAME VARIABLE).
!                   ALSO SUPPORT THE R7 METHOD (THIS IS THE DEFAULT
!                   METHOD FOR R AND EXCEL).
!
!                   ALSO, FOR DEFAULT DEFINITION, LOOK FOR MINIMUM
!                   AND MAXIMUM VALUES OF P100 THAT ARE SET TO THE
!                   DATA MINIMUM AND MAXIMUM, RESPECTIVELY.
!
      IF(IQUAME.EQ.'HD')THEN
!
!        HERRELL-DAVIS METHOD
!
        P=QNT
        A=(AN+1.0)*P
        B=(AN+1.0)*(1.0-P)
        DA=DBLE(A)
        DB=DBLE(B)
        IF(A.EQ.0.0)DA=0.1D-15
        IF(B.EQ.0.0)DB=0.1D-15
!
        DSUM1=0.0D0
        DO 500 I=1,N
          ATEMP1=REAL(I)/AN
          DTEMP1=DBETAI(DBLE(ATEMP1),DA,DB)
          ATEMP2=REAL(I-1)/AN
          DTEMP2=DBETAI(DBLE(ATEMP2),DA,DB)
          WTEMP=DTEMP1-DTEMP2
          DSUM1=DSUM1 + WTEMP*DBLE(XTEMP(I))
  500   CONTINUE
!
        XQUANT=REAL(DSUM1)
        IMETH='HERRELL-DAVIS'
      ELSEIF(IQUAME.EQ.'R8')THEN
!
!        R8 METHOD
!
        P=QNT
        AVAL1=2.0/3.0
        AVAL2=1.0/3.0
        ALOW=AVAL1/(AN+AVAL2)
        AHIGH=(AN-AVAL2)/(AN+AVAL2)
        IF(P.LT.ALOW)THEN
          XQUANT=XTEMP(1)
        ELSEIF(P.GE.AHIGH)THEN
          XQAUNT=XTEMP(N)
        ELSE
          ANI=P*(AN+AVAL2) + AVAL2
          NI=INT(ANI)
          A2NI=REAL(NI)
          REM=ANI-A2NI
          NIP1=NI+1
          IF(NI.LE.1)NI=1
          IF(NI.GE.N)NI=N
          IF(NIP1.LE.1)NIP1=1
          IF(NIP1.GE.N)NIP1=N
          XQUANT=XTEMP(NI) + REM*(XTEMP(NIP1) - XTEMP(NI))
        ENDIF
        IMETH='R8'
      ELSEIF(IQUAME.EQ.'R7')THEN
!
!        R7 METHOD
!
        P=QNT
        AVAL1=1.0
        AHIGH=1.0
        IF(P.GE.AHIGH)THEN
          XQAUNT=XTEMP(N)
        ELSE
          ANI=P*(AN-AVAL1) + AVAL1
          NI=INT(ANI)
          A2NI=REAL(NI)
          REM=ANI-A2NI
          NIP1=NI+1
          IF(NI.LE.1)NI=1
          IF(NI.GE.N)NI=N
          IF(NIP1.LE.1)NIP1=1
          IF(NIP1.GE.N)NIP1=N
          XQUANT=XTEMP(NI) + REM*(XTEMP(NIP1) - XTEMP(NI))
        ENDIF
        IMETH='R7'
      ELSEIF(IQUAME.EQ.'AVER')THEN
!
!        AVERAGE METHOD - TAKE AVERAGE OF TWO CLOSEST POINTS, NOT
!        RECOMMENDED, BUT THIS APPEARS TO BE METHOD USED BY BONETT
!        FOR CONFIDENCE INTERVALS FOR COEFFCIENT OF QUARTILE
!        DISPERSION.  INCLUDE SO THAT WE CAN MATCH HIS RESULTS.
!
        P=QNT
        AINDX=P*AN
        IINDX=INT(AINDX)
        IF(IINDX.EQ.N)THEN
          XQUANT=XTEMP(IINDX)
        ELSEIF(IINDX.LT.1)THEN
          XQUANT=XTEMP(1)
        ELSE
          XQUANT=(XTEMP(IINDX) + XTEMP(IINDX+1))/2.0
        ENDIF
      ELSE
        P=QNT
        ALOW=1.0/(AN+1.0)
        AHIGH=AN/(AN+1.0)
        IF(P.LT.ALOW)THEN
          XQUANT=XTEMP(1)
        ELSEIF(P.GE.AHIGH)THEN
          XQUANT=XTEMP(N)
        ELSE
          ANI=P*(AN+1.0)
          NI=INT(ANI)
          A2NI=REAL(NI)
          REM=ANI-A2NI
          NIP1=NI+1
          IF(NI.LE.1)NI=1
          IF(NI.GE.N)NI=N
          IF(NIP1.LE.1)NIP1=1
          IF(NIP1.GE.N)NIP1=N
          XQUANT=(1.0-REM)*XTEMP(NI)+REM*XTEMP(NIP1)
          IMETH='ORDER STATISTIC'
        END IF
      END IF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)QNT,IMETH,N,XQUANT
  811   FORMAT('THE ',F10.2,'-QUANTTILE (',A16,' METHOD) OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF QUANT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,QNT,P,N
 9012   FORMAT('IERROR,QNT,P,N = ',A4,2X,2G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NI,NIP1,ANI,A2NI,REM
 9014   FORMAT('NI,NIP1,ANI,A2NI,REM = ',2I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XQUANT
 9015   FORMAT('XQUANT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE QUANT
      SUBROUTINE QUANSE(QNT,X,N,IWRITE,XTEMP,MAXNXT,IQUASE,   &
                        XQUASE,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE STANDARD ERROR OF A
!              SAMPLE QUANTTILE, USING EITHER A MARITZ-JARRETT OR
!              A KERNEL DENSITY BASED METHOD,
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--QNT   = THE SINGLE PRECISION QUANTILE
!                                (BETWEEN 0 AND 1)
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --IQUASE = METHOD:
!                                1. MARITZ-JARRETT  (IQUASE=MJ)
!                                2. KERNEL DENSITY  (IQUASE=KD)
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XQUASE = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE QUANTTILE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE QUANTTILE STANDARD ERROR.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002.7
!     ORIGINAL VERSION--JULY      2002.
!     UPDATED         --JUNE      2010. FIX BUG IN MARITZ-JARRETT
!     UPDATED         --JUNE      2010. NEED TO SORT DATA (THIS
!                                       ROUTINE ASSUMED XQUANT SORTED
!                                       THE DATA, HOWEVER XQUANT WAS
!                                       MODIFIED TO SORT TO A TEMPORARY
!                                       VARIABLE)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IWRIT2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IQUAME
      CHARACTER*4 IQUASE
!
      CHARACTER*16 IMETH
!
!---------------------------------------------------------------------
!
      REAL IQRANG
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
      DOUBLE PRECISION DTEMP1
      DOUBLE PRECISION DTEMP2
      DOUBLE PRECISION WTEMP
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DBETAI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='QUAN'
      ISUBN2='SE  '
      IQUAME='ORDE'
      IERROR='NO'
!
      NI=0
      NIP1=0
!
      ANI=0.0
      A2NI=0.0
      REM=0.0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF QUANSE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)QNT,N,IBUGA3
   53   FORMAT('QNT,N,IBUGA3 = ',G15.7,I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,E15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ******************************
!               **  COMPUTE QUANTTILE      **
!               ******************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(QNT.LE.0.0 .OR. QNT.GE.1.0)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN QUANTILE STANDARD ERROR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT QUANTILE FOR WHICH THE STANDARD ',   &
               'ERROR IS TO BE COMPUTED')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      MUST BE LARGER THAN 0 AND SMALLER THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)QNT
  117   FORMAT('      THE INPUT QUANTILE      = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.LT.1 .OR. N.GE.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,124)
  124   FORMAT('      FOR WHICH THE QUANTTILE STANDARD ERROR IS TO ',   &
               'BE COMPUTED')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,125)MAXNXT
  125   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,126)
  126   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)N
  127   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               *******************************************
!               **  STEP 2--                             **
!               **  COMPUTE THE QUANTTILE STANDARD ERROR **
!               *******************************************
!
      IWRIT2='OFF'
      CALL SORT(X,N,X)
      CALL QUANT(QNT,X,N,IWRIT2,XTEMP,MAXNXT,   &
                 IQUAME,   &
                 XQUANT,IBUGA3,IERROR)
!
      IF(IQUASE.EQ.'KERD')THEN
        CALL SORT(X,N,XTEMP)
        IUPP=INT(AN*0.75 + 0.5)
        RIGH1=XTEMP(IUPP)
        ILOW=INT(AN*0.25 + 0.5)
        RIGH2=XTEMP(ILOW)
        IQRANG=RIGH1-RIGH2
        ATEMP=AN**0.2
        AH=1.2*IQRANG/ATEMP
        XLOW=XQUANT - AH
        XHIGH=XQUANT + AH
        ICOUNT=0
        DO 400 I=1,N
          IF(X(I).GE.XLOW .AND. X(I).LE.XHIGH)ICOUNT=ICOUNT+1
  400   CONTINUE
        FX=REAL(ICOUNT)/(2.0*AN*AH)
        XQUASE=AN*AH/(SQRT(AN)*REAL(ICOUNT))
        IMETH='KERNEL DENSITY'
      ELSEIF(IQUASE.EQ.'MJ')THEN
        P=QNT
        IM=INT(P*AN + 0.5)
        IA=IM - 1
        IB=N - IM
!
        DSUM1=0.0D0
        DSUM2=0.0D0
        DO 500 I=1,N
          ATEMP1=REAL(I)/AN
          DTEMP1=DBETAI(DBLE(ATEMP1),DBLE(IA),DBLE(IB))
          ATEMP2=REAL(I-1)/AN
          DTEMP2=DBETAI(DBLE(ATEMP2),DBLE(IA),DBLE(IB))
          WTEMP=DTEMP1-DTEMP2
          DSUM1=DSUM1 + WTEMP*DBLE(X(I))
          DSUM2=DSUM2 + WTEMP*DBLE(X(I))*DBLE(X(I))
  500   CONTINUE
!
        XQUASE=REAL(DSQRT(DSUM2 - DSUM1*DSUM1))
        IMETH='MARITZ-JARRETT'
      ELSE
        WRITE(ICOUT,600)
  600   FORMAT('***** FROM QUANTILE STANDARD ERROR: METHOD ',A4,' IS ',   &
               'UNKNOWN.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      END IF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)QNT,XQUANT
  811   FORMAT('THE ',F6.2,'-QUANTTILE (ORDER STATISTIC METHOD) = ',   &
               G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,813)XQUASE
  813   FORMAT('THE STANDARD ERROR = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF QUANSE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N,QNT,P,XQUASE
 9013   FORMAT('IERROR,N,QNT,P,XQUASE = ',A4,2X,I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE QUANSE
